% ========================================================================
% TSUNAMI VORTEX SIMULATION - UNIFIED USER INTERFACE (CLASS-BASED)
% ========================================================================
% Purpose:
%   Comprehensive GUI for configuring and launching numerical simulations
%   Self-contained interface with integrated monitoring and visualization
%
% Features:
%   Method Selection (Finite Difference, Finite Volume, Spectral)
%   Mode Configuration (Evolution, Convergence, Sweep, Animation, Experimentation)
%   Initial Condition Designer (Default presets + custom configuration)
%   Live Execution Monitor (CPU, Memory, Iteration tracking)
%   Convergence Monitor (Real-time error decay, mesh refinement tracking)
%   Parameter Validation & Export to Tsunami_Vorticity_Emulator
%
% Usage:
%   >> app = UIController();
%   % Configure settings in GUI, then click "Launch Simulation"
%
% Architecture:
%   Class-based UI with internal state management
%   All monitors are embedded in the UI (no separate windows)
%   Clean encapsulation with properties and methods
%   Grid-based layout (uigridlayout) for intuitive editing
%
% Layout Editing (How to Safely Modify UI):
%   1. Edit layout parameters in UI_Layout_Config.m (NOT this file)
%   2. All sizing, spacing, placement defined in UI_Layout_Config.m
%   3. Use "Validate All Layouts" tool to check for obvious layout errors
%
% Adding New Components:
%   1. Add entry to UI_Layout_Config.m placement map
%   2. Create component in appropriate create_*_tab method
%   3. Set Layout.Row and Layout.Column from config
%   4. DO NOT use Position property (use grid layout only)
%
% Callback Signatures (DO NOT CHANGE):
%   - launch_simulation(app)
%   - on_method_changed(app)
%   - on_mode_changed(app)
%   - update_ic_preview(app)
%
%
% ========================================================================
classdef UIController < handle
    
    properties (Access = public)
        fig                    % Main figure
        root_grid              % Root grid layout (replaces manual positioning)
        tab_group              % Tab group container
        tabs                   % Structure of tab handles
        handles                % All UI component handles
        config                 % Configuration structure
        terminal_log           % Cell array of terminal output
        terminal_type_log      % Message type tags aligned with terminal_log
        figures_list           % Storage for generated figures (legacy screenshot mode)
        session_figures        % Session-wide figure registry: struct array with analysis data
        diary_file             % MATLAB diary file for terminal capture
        diary_timer            % Timer for terminal refresh
        diary_last_size        % Last diary file size
        layout_cfg             % Centralized layout configuration
        current_executor       % ParallelSimulationExecutor for background simulation
    end
    
    properties (Access = private)
        % Terminal color scheme (RGB triplets)
        color_success          % Success messages: bright green
        color_warning          % Warnings: yellow/orange
        color_error            % Errors: red
        color_info             % Info messages: cyan
        color_debug            % Debug messages: light gray
        time_video_timer       % Timer driving in-app triplet playback
        time_video_state       % Cached media streams and playback cursors
        report_html_cache = '' % Cached HTML string for Report tab export
        planner_host_probe = struct() % Cached host probe for planner preview responsiveness
        run_lifecycle_state = 'idle' % idle | starting | running | finalizing | tearing_down
        collector_launch_session_id = ''
        collector_launch_root_dir = ''
        collector_launch_session_dir = ''
        collector_launch_csv_path = ''
        collector_launch_csv_file = ''
        published_completion_keys % Idempotent completion-publication registry
        deferred_live_monitor_payloads = {} % Buffered executor payloads for UI-thread flushing
        is_flushing_live_monitor_payloads = false
        cached_completion_report_payload = struct()
        startup_collector_probe_timer = []
        startup_pool_warm_timer = []
        post_publication_timer = []
        executor_completion_timer = []
        pending_post_publication_jobs = {}
        is_draining_post_publication_jobs = false
        active_post_publication_worker_job = []
        active_post_publication_worker_payload = struct()
        defer_result_autosave = false
        published_completion_entry_indices
        pending_launch_request = struct()
        active_launch_context = struct()
    end
    
    methods
        function app = UIController(varargin)
            % Constructor - creates and initializes the UI
            % UI mode is now the only supported mode

            % ---- PATH SETUP -----------------------------------------------
            % Bootstrap: if PathSetup is not yet on the path (i.e. UIController
            % was launched directly without running the driver first), resolve
            % the project root from UIController.m's own location and attach
            % all Scripts/ subdirectories.  Then verify the full manifest.
            if exist('PathSetup', 'class') ~= 8
                ui_dir      = fileparts(mfilename('fullpath'));  % Scripts/UI
                scripts_dir = fileparts(ui_dir);                % Scripts
                addpath(genpath(scripts_dir));
                utilities_dir = fullfile(fileparts(scripts_dir), 'utilities');
                if exist(utilities_dir, 'dir') == 7
                    addpath(utilities_dir);
                end
            end
            PathSetup.attach_and_verify();
            % ---------------------------------------------------------------

            close all;

            % The UI uses uifigure for its own chrome.  Do not persistently
            % change DefaultFigureVisible here: users may open exported FIG
            % files while the UI is still running.
            set(groot, ...
                'defaultFigureColor', [0.09 0.10 0.13], ...
                'defaultAxesColor', [0.09 0.10 0.13], ...
                'defaultAxesXColor', [0.90 0.92 0.95], ...
                'defaultAxesYColor', [0.90 0.92 0.95], ...
                'defaultAxesZColor', [0.90 0.92 0.95], ...
                'defaultAxesGridColor', [0.40 0.43 0.47], ...
                'defaultTextColor', [0.90 0.92 0.95], ...
                'defaultLegendTextColor', [0.90 0.92 0.95], ...
                'defaultLegendColor', [0.12 0.13 0.16], ...
                'defaultLegendEdgeColor', [0.40 0.43 0.47]);

            % Initialize properties
            app.config = app.initialize_default_config();
            app.handles = struct();
            app.terminal_log = {};
            app.terminal_type_log = {};
            app.figures_list = {};  % Cell array of figure data structs (legacy)
            app.session_figures = struct('name', {}, 'analysis', {}, 'results', {}, 'parameters', {}, ...
                'run_config', {}, 'metadata', {}, 'tab_handle', {}, ...
                'run_color', {}, 'run_badge', {}, 'plot_tabs', {}, ...
                'monitor_series', {}, 'artifacts', {}, ...
                'workflow', {}, 'workflow_kind', {}, ...
                'launch_origin', {}, 'result_layout_kind', {}, ...
                'publication_key', {}, 'publication_state', {}, ...
                'hydration_state', {}, 'post_publication_state', {});
            app.time_video_timer = [];
            if exist('ExecutionResourcePlanner', 'class') == 8 || exist('ExecutionResourcePlanner', 'file') == 2
                try
                    app.planner_host_probe = ExecutionResourcePlanner.probe_host();
                catch
                    app.planner_host_probe = struct();
                end
            end
            app.time_video_state = struct();
            app.published_completion_keys = containers.Map('KeyType', 'char', 'ValueType', 'logical');
            app.published_completion_entry_indices = containers.Map('KeyType', 'char', 'ValueType', 'double');
            app.pending_launch_request = struct();
            app.active_launch_context = struct();

            % Load centralized layout configuration
            app.layout_cfg = UI_Layout_Config(app);

            % Initialize terminal color scheme (RGB triplets)
            app.color_success = [0.3 1.0 0.3];     % Bright green
            app.color_warning = [1.0 0.8 0.2];     % Yellow/orange
            app.color_error = [1.0 0.3 0.3];       % Red
            app.color_info = [0.3 0.8 1.0];        % Cyan
            app.color_debug = [0.7 0.7 0.7];       % Light gray

            % Create full UI interface
            % Create main figure (maximized, dark mode)
            app.fig = uifigure('Name', app.layout_cfg.ui_text.window.main_title, ...
                'WindowState', 'maximized', ...
                'Color', app.layout_cfg.colors.bg_dark, ...
                'AutoResizeChildren', 'off', ...
                'SizeChangedFcn', @(~,~) app.apply_responsive_breakpoint(), ...
                'CloseRequestFcn', @(~,~) app.cleanup());
            % Global dark theme: cascades to all child uiaxes, legends,
            % labels, titles.  style_axes() adds a few extras (grid colour)
            % for versions that lack the Theme property.
            if isprop(app.fig, 'Theme')
                app.fig.Theme = 'dark';
            end
            
            % Create root grid layout (replaces manual Position sizing)
            app.root_grid = uigridlayout(app.fig, app.layout_cfg.root_grid.rows_cols);
            app.root_grid.RowHeight = app.layout_cfg.root_grid.row_heights;
            app.root_grid.ColumnWidth = app.layout_cfg.root_grid.col_widths;
            app.root_grid.Padding = app.layout_cfg.root_grid.padding;
            app.root_grid.RowSpacing = app.layout_cfg.root_grid.row_spacing;
            app.root_grid.ColumnSpacing = app.layout_cfg.root_grid.col_spacing;

            % Create tab group in main content area
            app.tab_group = uitabgroup(app.root_grid, ...
                'FontSize', 12, 'FontWeight', 'bold');
            app.tab_group.Layout.Row = app.layout_cfg.tab_group.parent_row;
            app.tab_group.Layout.Column = app.layout_cfg.tab_group.parent_col;
            
            % Create all tabs
            app.create_all_tabs();
            app.enforce_dark_theme();
            app.apply_responsive_breakpoint();
            app.enforce_container_content_margins(app.tab_group);

            % Show the completed tab layout before slower housekeeping.
            % Do not force drawnow here: on some MATLAB releases a fresh
            % uifigure can still have an uninitialized graphics communicator,
            % which raises a graphics-timeout warning during startup.
            app.fig.Visible = 'on';

            app.start_terminal_capture();
            app.schedule_startup_parallel_pool_warmup();
        end
        
        function create_all_tabs(app)
            % Create tabs from configurable tab order while preserving required handles.
            app.tabs = struct();
            tab_order = {'config', 'monitoring', 'results'};
            if isfield(app.layout_cfg, 'tab_group') && isfield(app.layout_cfg.tab_group, 'order') && ...
                    ~isempty(app.layout_cfg.tab_group.order)
                tab_order = cellstr(string(app.layout_cfg.tab_group.order));
            end

            for i = 1:numel(tab_order)
                key = lower(strtrim(tab_order{i}));
                switch key
                    case 'config'
                        if ~isfield(app.tabs, 'config')
                            app.tabs.config = uitab(app.tab_group, ...
                                'Title', app.tab_title_from_layout('config', 'Simulation Configuration'), ...
                                'BackgroundColor', app.layout_cfg.colors.bg_panel_alt);
                            app.create_config_tab();
                        end
                    case {'monitor', 'monitoring', 'live_monitor'}
                        if ~isfield(app.tabs, 'monitoring')
                            app.tabs.monitoring = uitab(app.tab_group, ...
                                'Title', app.tab_title_from_layout('monitoring', 'Simulation Monitor'), ...
                                'BackgroundColor', app.layout_cfg.colors.bg_panel_alt);
                            app.create_monitoring_tab();
                        end
                    case {'results', 'results_and_figures'}
                        if ~isfield(app.tabs, 'results')
                            app.tabs.results = uitab(app.tab_group, ...
                                'Title', app.tab_title_from_layout('results', 'Figure Viewer'), ...
                                'BackgroundColor', app.layout_cfg.colors.bg_panel_alt);
                            app.create_results_tab();
                        end
                    case 'report'
                        if ~isfield(app.tabs, 'report')
                            app.tabs.report = uitab(app.tab_group, ...
                                'Title', app.tab_title_from_layout('report', 'Report'), ...
                                'BackgroundColor', app.layout_cfg.colors.bg_panel_alt);
                            app.create_report_tab();
                        end
                end
            end

            % Defensive fallback: always create required tabs if omitted in tab_order.
            if ~isfield(app.tabs, 'config')
                app.tabs.config = uitab(app.tab_group, ...
                    'Title', app.tab_title_from_layout('config', 'Configuration'), ...
                    'BackgroundColor', app.layout_cfg.colors.bg_panel_alt);
                app.create_config_tab();
            end
            if ~isfield(app.tabs, 'monitoring')
                app.tabs.monitoring = uitab(app.tab_group, ...
                    'Title', app.tab_title_from_layout('monitoring', 'Live Monitor'), ...
                    'BackgroundColor', app.layout_cfg.colors.bg_panel_alt);
                app.create_monitoring_tab();
            end
            if ~isfield(app.tabs, 'results')
                app.tabs.results = uitab(app.tab_group, ...
                    'Title', app.tab_title_from_layout('results', 'Results and Figures'), ...
                    'BackgroundColor', app.layout_cfg.colors.bg_panel_alt);
                app.create_results_tab();
            end
        end

        function title_txt = tab_title_from_layout(app, key, fallback)
            title_txt = fallback;
            if isfield(app.layout_cfg, 'tab_layout') && isfield(app.layout_cfg.tab_layout, key)
                block = app.layout_cfg.tab_layout.(key);
                if isstruct(block) && isfield(block, 'tab_name') && ~isempty(block.tab_name)
                    title_txt = char(string(block.tab_name));
                    return;
                end
            end
            if isfield(app.layout_cfg, 'text') && isfield(app.layout_cfg.text, 'tabs') && ...
                    isfield(app.layout_cfg.text.tabs, key)
                title_txt = char(string(app.layout_cfg.text.tabs.(key)));
            end
        end

        function cfg = get_layout_config(app)
            % Public bridge used by UI_Layout_Config.m.
            cfg = app.UI_Layout_Config_Internal();
        end
        
        % Tab creation methods
        function create_config_tab(app)
            % Build configuration tab using explicit coordinates and text/options/defaults
            % from UI_Layout_Config.m.
            %
            % Debugging map:
            % - Position/sizing comes from app.layout_cfg.config_tab.* and app.layout_cfg.coords.config.*
            % - Display names/labels/button text come from app.layout_cfg.ui_text.config.*
            % - Dropdown items come from app.layout_cfg.ui_options.*
            % - Initial control values come from app.layout_cfg.ui_defaults.*
            C = app.layout_cfg.colors;
            T = app.layout_cfg.ui_text;
            O = app.layout_cfg.ui_options;
            D = app.layout_cfg.ui_defaults;

            parent = app.tabs.config;
            parent.BackgroundColor = C.bg_dark;
            if isprop(parent, 'Scrollable')
                parent.Scrollable = 'on';
            end

            cfg_root = app.layout_cfg.config_tab.root;
            root = uigridlayout(parent, cfg_root.rows_cols);
            root.ColumnWidth = cfg_root.col_widths;
            root.RowHeight = cfg_root.row_heights;
            root.Padding = cfg_root.padding;
            root.RowSpacing = cfg_root.row_spacing;
            root.ColumnSpacing = cfg_root.col_spacing;
            app.handles.config_root_grid = root;

            left = uipanel(root, 'Title', T.config.root.left_panel_title, 'FontWeight', 'bold', ...
                'BackgroundColor', C.bg_panel, ...
                'Scrollable', 'on');
            left.Layout.Row = app.layout_cfg.coords.config.left(1);
            left.Layout.Column = app.layout_cfg.coords.config.left(2);
            app.handles.config_left_panel = left;

            right = uipanel(root, 'Title', T.config.root.right_panel_title, 'FontWeight', 'bold', ...
                'BackgroundColor', C.bg_panel, ...
                'Scrollable', 'on');
            right.Layout.Row = app.layout_cfg.coords.config.right(1);
            right.Layout.Column = app.layout_cfg.coords.config.right(2);
            app.handles.config_right_panel = right;

            cfg_left = app.layout_cfg.config_tab.left;
            left_layout = uigridlayout(left, cfg_left.rows_cols);
            left_layout.RowHeight = cfg_left.row_heights;
            left_layout.Padding = cfg_left.padding;
            left_layout.RowSpacing = cfg_left.row_spacing;
            if isfield(cfg_left, 'col_widths')
                left_layout.ColumnWidth = cfg_left.col_widths;
            end

            % Left column now uses explicit subtabs for each configuration cluster.
            left_subtabs_cfg = app.layout_cfg.config_tab.left_subtabs;
            left_subtab_group = uitabgroup(left_layout);
            left_subtab_group.Layout.Row = 1;
            left_subtab_group.Layout.Column = 1;
            app.handles.config_left_subtab_group = left_subtab_group;

            subtabs = struct();
            subtab_hosts = struct();
            for idx = 1:numel(left_subtabs_cfg.order)
                key = char(lower(string(left_subtabs_cfg.order{idx})));
                if isfield(left_subtabs_cfg.titles, key)
                    title_txt = char(string(left_subtabs_cfg.titles.(key)));
                else
                    title_txt = app.humanize_token(key);
                end
                subtabs.(key) = uitab(left_subtab_group, 'Title', title_txt);

                host_cfg = left_subtabs_cfg.root;
                host = uigridlayout(subtabs.(key), host_cfg.rows_cols);
                row_heights = host_cfg.row_heights;
                if ischar(row_heights) || isstring(row_heights)
                    row_heights = {char(string(row_heights))};
                end
                col_widths = host_cfg.col_widths;
                if ischar(col_widths) || isstring(col_widths)
                    col_widths = {char(string(col_widths))};
                end
                host.RowHeight = row_heights;
                host.ColumnWidth = col_widths;
                host.Padding = host_cfg.padding;
                host.RowSpacing = host_cfg.row_spacing;
                host.ColumnSpacing = host_cfg.col_spacing;
                subtab_hosts.(key) = host;
            end
            app.handles.config_subtabs = subtabs;
            app.handles.config_subtab_hosts = subtab_hosts;

            % Phase settings panel
            if isfield(subtab_hosts, 'phase')
                panel_phase = uipanel(subtab_hosts.phase, 'Title', 'Phase Settings', ...
                    'BackgroundColor', C.bg_panel_alt);
                if isprop(panel_phase, 'Scrollable')
                    panel_phase.Scrollable = 'on';
                end
                panel_phase.Layout.Row = 1;
                panel_phase.Layout.Column = 1;
                app.handles.config_phase_panel = panel_phase;
                app.handles.phase_settings_panel = panel_phase;
                app.create_phase_settings_tabs(panel_phase, D, C);
            end

            % Method and mode panel
            panel_method = uipanel(subtab_hosts.method, 'Title', T.config.method.panel_title, ...
                'BackgroundColor', C.bg_panel_alt);
            if isprop(panel_method, 'Scrollable')
                panel_method.Scrollable = 'on';
            end
            panel_method.Layout.Row = 1;
            panel_method.Layout.Column = 1;
            app.handles.config_method_panel = panel_method;
            cfg_method = app.layout_cfg.config_tab.method_grid;
            method_grid = uigridlayout(panel_method, cfg_method.rows_cols);
            method_grid.ColumnWidth = cfg_method.col_widths;
            method_grid.RowHeight = cfg_method.row_heights;
            method_grid.RowSpacing = cfg_method.row_spacing;
            method_grid.Padding = cfg_method.padding;
            method_grid.RowHeight = {54, 54, 'fit', '1x', 'fit', 'fit', 'fit', 'fit', 'fit', 'fit'};
            app.handles.config_method_grid = method_grid;

            top_row = uigridlayout(method_grid, [2, 3]);
            top_row.Layout.Row = 1;
            top_row.Layout.Column = [1 4];
            top_row.RowHeight = {18, max(app.layout_cfg.heights.dropdown, 32)};
            top_row.ColumnWidth = {'1x', '1x', '1x'};
            top_row.Padding = [0 0 0 0];
            top_row.ColumnSpacing = 8;
            top_row.RowSpacing = 2;

            app.handles.method_label = uilabel(top_row, 'Text', T.config.method.method_label, ...
                'FontColor', C.fg_text, 'FontWeight', 'bold');
            app.handles.method_label.Layout.Row = 1;
            app.handles.method_label.Layout.Column = 1;
            app.handles.mode_label = uilabel(top_row, 'Text', T.config.method.mode_label, ...
                'FontColor', C.fg_text, 'FontWeight', 'bold');
            app.handles.mode_label.Layout.Row = 1;
            app.handles.mode_label.Layout.Column = 2;
            app.handles.simulation_scenario_label = uilabel(top_row, ...
                'Text', T.config.method.simulation_scenario_label, ...
                'FontColor', C.fg_text, 'FontWeight', 'bold');
            app.handles.simulation_scenario_label.Layout.Row = 1;
            app.handles.simulation_scenario_label.Layout.Column = 3;

            app.handles.method_dropdown = uidropdown(top_row, ...
                'Items', O.method_items, ...
                'Value', D.method, ...
                'ValueChangedFcn', @(~,~) app.on_method_changed());
            app.handles.method_dropdown.Layout.Row = 2;
            app.handles.method_dropdown.Layout.Column = 1;

            app.handles.mode_dropdown = uidropdown(top_row, ...
                'Items', O.mode_items, ...
                'Value', D.mode, ...
                'ValueChangedFcn', @(~,~) app.on_mode_changed());
            app.handles.mode_dropdown.Layout.Row = 2;
            app.handles.mode_dropdown.Layout.Column = 2;

            app.handles.simulation_scenario = uidropdown(top_row, ...
                'Items', O.simulation_scenario_items, ...
                'Value', D.simulation_scenario, ...
                'ValueChangedFcn', @(~,~) app.on_simulation_scenario_changed());
            app.handles.simulation_scenario.Layout.Row = 2;
            app.handles.simulation_scenario.Layout.Column = 3;

            bathy_row = uigridlayout(method_grid, [2, 2]);
            bathy_row.Layout.Row = 2;
            bathy_row.Layout.Column = [1 4];
            bathy_row.RowHeight = {18, max(app.layout_cfg.heights.dropdown, 32)};
            bathy_row.ColumnWidth = {'2x', 'fit'};
            bathy_row.Padding = [0 0 0 0];
            bathy_row.ColumnSpacing = 8;
            bathy_row.RowSpacing = 2;

            app.handles.bathymetry_scenario_label = uilabel(bathy_row, ...
                'Text', T.config.method.bathymetry_scenario_label, ...
                'FontColor', C.fg_text, 'FontWeight', 'bold');
            app.handles.bathymetry_scenario_label.Layout.Row = 1;
            app.handles.bathymetry_scenario_label.Layout.Column = 1;

            app.handles.bathymetry_points_label = uilabel(bathy_row, ...
                'Text', T.config.method.bathymetry_points_label, ...
                'FontColor', C.fg_text, 'FontWeight', 'bold');
            app.handles.bathymetry_points_label.Layout.Row = 1;
            app.handles.bathymetry_points_label.Layout.Column = 2;

            app.handles.bathymetry_scenario = uidropdown(bathy_row, ...
                'Items', O.bathymetry_scenario_items_2d, ...
                'Value', D.bathymetry_scenario, ...
                'ValueChangedFcn', @(~,~) app.on_bathymetry_scenario_changed());
            app.handles.bathymetry_scenario.Layout.Row = 2;
            app.handles.bathymetry_scenario.Layout.Column = 1;

            app.handles.btn_bathymetry_points = uibutton(bathy_row, ...
                'Text', T.config.method.bathymetry_points_button, ...
                'ButtonPushedFcn', @(~,~) app.open_bathymetry_point_editor());
            app.handles.btn_bathymetry_points.Layout.Row = 2;
            app.handles.btn_bathymetry_points.Layout.Column = 2;

            app.handles.bathymetry_dynamic_box = uipanel(method_grid, ...
                'BorderType', 'line', ...
                'BackgroundColor', C.bg_panel_alt, ...
                'ForegroundColor', C.accent_gray);
            if isprop(app.handles.bathymetry_dynamic_box, 'Scrollable')
                app.handles.bathymetry_dynamic_box.Scrollable = 'on';
            end
            app.handles.bathymetry_dynamic_box.Layout.Row = 3;
            app.handles.bathymetry_dynamic_box.Layout.Column = [1 4];
            app.handles.bathymetry_dynamic_grid = [];
            app.handles.bathymetry_dynamic_inputs = struct();
            app.handles.bathymetry_dynamic_labels = struct();
            app.handles.bathymetry_active_entry = struct();
            app.handles.bathymetry_bed_slope_label = [];
            app.handles.bathymetry_bed_slope = [];
            app.handles.bathymetry_depth_offset_label = [];
            app.handles.bathymetry_depth_offset = [];
            app.handles.bathymetry_relief_amplitude_label = [];
            app.handles.bathymetry_relief_amplitude = [];
            app.handles.bathymetry_resolution_label = [];
            app.handles.bathymetry_resolution = [];

            bathy_preview_panel = uipanel(method_grid, ...
                'Title', T.config.method.bathymetry_preview_title, ...
                'BackgroundColor', C.bg_panel, ...
                'ForegroundColor', C.accent_gray);
            if isprop(bathy_preview_panel, 'Scrollable')
                bathy_preview_panel.Scrollable = 'on';
            end
            bathy_preview_panel.Layout.Row = [4 10];
            bathy_preview_panel.Layout.Column = [1 4];
            app.handles.bathymetry_preview_panel = bathy_preview_panel;
            bathy_preview_grid = uigridlayout(bathy_preview_panel, [3, 1]);
            bathy_preview_grid.RowHeight = {'1x', 'fit', 'fit'};
            bathy_preview_grid.ColumnWidth = {'1x'};
            bathy_preview_grid.Padding = [6 6 6 6];
            bathy_preview_grid.RowSpacing = 6;
            bathy_preview_grid.ColumnSpacing = 0;

