            app.handles.launch_progress_status.Layout.Column = [1 2];

            app.handles.launch_progress_gauge = uigauge(progress_strip_grid, 'linear');
            app.handles.launch_progress_gauge.Layout.Row = 2;
            app.handles.launch_progress_gauge.Layout.Column = 1;
            app.handles.launch_progress_gauge.Limits = [0 100];
            app.handles.launch_progress_gauge.Value = 0;
            app.handles.launch_progress_gauge.ScaleColors = [C.accent_cyan; C.accent_green];
            app.handles.launch_progress_gauge.ScaleColorLimits = [0 100];
            app.handles.launch_progress_gauge.MajorTicks = 0:20:100;

            app.handles.launch_progress_value = uilabel(progress_strip_grid, ...
                'Text', '--', ...
                'FontColor', C.fg_muted, ...
                'HorizontalAlignment', 'right');
            app.handles.launch_progress_value.Layout.Row = 2;
            app.handles.launch_progress_value.Layout.Column = 2;

            % === Row 3: IC configuration (fine-grid 12x24 editor) ===
            ic_editor = uigridlayout(right_layout, [12, 24]);
            ic_editor.Layout.Row = 3;
            ic_editor.Layout.Column = 1;
            ic_editor.Padding = [4 4 4 4];
            ic_editor.RowSpacing = 4;
            ic_editor.ColumnSpacing = 4;
            ic_editor.BackgroundColor = C.bg_panel_alt;
            app.handles.ic_top_row_px = max(app.layout_cfg.heights.form_row + 10, 44);
            app.handles.ic_form_row_px = app.layout_cfg.heights.form_row;
            app.handles.ic_eq_row_px = 72;
            app.handles.ic_status_row_px = 20;
            app.handles.ic_editor_grid = ic_editor;
            app.handles.ic_editor_row_classes = {'single', 'single', 'double', 'single', 'single', 'single', ...
                'double', 'fit', 'fit', 'fit', 'single', 'single'};
            app.handles.ic_editor_base_column_widths = app.build_ic_editor_column_widths('standard');
            app.handles.ic_editor_grid.ColumnWidth = app.handles.ic_editor_base_column_widths;
            app.handles.ic_editor_grid.RowHeight = app.build_ic_editor_row_heights();

            top_row_height = max(app.layout_cfg.heights.dropdown, 30);

            type_group = uigridlayout(ic_editor, [2, 1]);
            type_group.Layout.Row = 1;
            type_group.Layout.Column = [1 6];
            type_group.RowHeight = {16, top_row_height, 20};
            type_group.ColumnWidth = {'1x'};
            type_group.Padding = [0 0 0 0];
            type_group.RowSpacing = 2;
            app.handles.ic_type_label = uilabel(type_group, ...
                'Text', 'Initial Condition Model', 'FontColor', C.fg_text, 'FontSize', 12, 'FontWeight', 'bold');
            app.handles.ic_type_label.Layout.Row = 1;
            app.handles.ic_type_label.Layout.Column = 1;
            app.handles.ic_dropdown = uidropdown(type_group, ...
                'Items', O.ic_type_items, ...
                'Value', D.ic_type, ...
                'ValueChangedFcn', @(~,~) app.on_ic_changed());
            app.handles.ic_dropdown.Layout.Row = 2;
            app.handles.ic_dropdown.Layout.Column = 1;
            app.handles.ic_gaussian_model_toggle = uicheckbox(type_group, ...
                'Text', 'Use Elliptic Gaussian', ...
                'Value', strcmpi(app.map_ic_display_to_type(D.ic_type), 'elliptical_vortex'), ...
                'Tooltip', 'Unchecked uses Stretched Gaussian. Checked uses Elliptical Vortex.', ...
                'FontColor', C.fg_text, ...
                'ValueChangedFcn', @(~,~) app.on_ic_gaussian_model_toggle_changed());
            app.handles.ic_gaussian_model_toggle.Layout.Row = 3;
            app.handles.ic_gaussian_model_toggle.Layout.Column = 1;

            scenario_group = uigridlayout(ic_editor, [2, 1]);
            scenario_group.Layout.Row = 1;
            scenario_group.Layout.Column = [7 12];
            scenario_group.RowHeight = {16, top_row_height};
            scenario_group.ColumnWidth = {'1x'};
            scenario_group.Padding = [0 0 0 0];
            scenario_group.RowSpacing = 2;
            app.handles.ic_scenario_label = uilabel(scenario_group, ...
                'Text', 'Scenario', 'FontColor', C.fg_text, 'FontSize', 12, 'FontWeight', 'bold');
            app.handles.ic_scenario_label.Layout.Row = 1;
            app.handles.ic_scenario_label.Layout.Column = 1;
            app.handles.ic_scenario = uidropdown(scenario_group, ...
                'Items', O.ic_scenario_items, ...
                'Value', D.ic_scenario, ...
                'ValueChangedFcn', @(~,~) app.on_ic_scenario_changed());
            app.handles.ic_scenario.Layout.Row = 2;
            app.handles.ic_scenario.Layout.Column = 1;

            multi_group = uigridlayout(ic_editor, [2, 1]);
            multi_group.Layout.Row = 1;
            multi_group.Layout.Column = [13 18];
            multi_group.RowHeight = {16, top_row_height};
            multi_group.ColumnWidth = {'1x'};
            multi_group.Padding = [0 0 0 0];
            multi_group.RowSpacing = 2;
            app.handles.ic_multi_vortex_label = uilabel(multi_group, ...
                'Text', 'Multivortex', 'FontColor', C.fg_text, 'FontSize', 12, 'FontWeight', 'bold');
            app.handles.ic_multi_vortex_label.Layout.Row = 1;
            app.handles.ic_multi_vortex_label.Layout.Column = 1;
            app.handles.btn_multi_vortex_settings = uibutton(multi_group, 'Text', 'Open Editor', ...
                'ButtonPushedFcn', @(~,~) app.open_multi_vortex_settings_dialog());
            app.handles.btn_multi_vortex_settings.Layout.Row = 2;
            app.handles.btn_multi_vortex_settings.Layout.Column = 1;

            bands_group = uigridlayout(ic_editor, [2, 1]);
            bands_group.Layout.Row = 1;
            bands_group.Layout.Column = [19 24];
            bands_group.RowHeight = {16, top_row_height};
            bands_group.ColumnWidth = {'1x'};
            bands_group.Padding = [0 0 0 0];
            bands_group.RowSpacing = 2;
            app.handles.ic_contour_bands_label = uilabel(bands_group, ...
                'Text', 'Bands', 'FontColor', C.fg_text, 'FontSize', 12, 'FontWeight', 'bold');
            app.handles.ic_contour_bands_label.Layout.Row = 1;
            app.handles.ic_contour_bands_label.Layout.Column = 1;
            app.handles.ic_contour_bands_btn = uibutton(bands_group, 'state', ...
                'Text', 'Bands: Off', ...
                'Value', logical(D.ic_contour_bands), ...
                'ValueChangedFcn', @(~,~) app.on_ic_contour_bands_toggled());
            app.handles.ic_contour_bands_btn.Layout.Row = 2;
            app.handles.ic_contour_bands_btn.Layout.Column = 1;

            try
                app.handles.ic_equation = uiimage(ic_editor, ...
                    'ImageSource', app.render_equation_image('Stretched Gaussian', '\omega(x,y)=\exp(-a(x-x_0)^2-b(y-y_0)^2)'), ...
                    'ScaleMethod', 'fit');
            catch
                app.handles.ic_equation = uilabel(ic_editor, ...
                    'Text', 'Initial Condition Equation', ...
                    'FontColor', C.fg_text, 'FontSize', 12);
            end
            app.handles.ic_equation.Layout.Row = 2;
            app.handles.ic_equation.Layout.Column = [1 16];

            app.handles.ic_where = uipanel(ic_editor, ...
                'Title', 'where:', ...
                'FontWeight', 'bold', ...
                'BackgroundColor', C.bg_panel_alt, ...
                'ForegroundColor', C.accent_gray);
            app.handles.ic_where.Layout.Row = [2 10];
            app.handles.ic_where.Layout.Column = [17 24];
            if isprop(app.handles.ic_where, 'Scrollable')
                app.handles.ic_where.Scrollable = 'on';
            end
            where_grid = uigridlayout(app.handles.ic_where, [1, 1]);
            where_grid.Padding = [4 4 4 4];
            where_grid.RowSpacing = 0;
            where_grid.ColumnSpacing = 0;
            app.handles.ic_where_axes = uiaxes(where_grid);
            app.handles.ic_where_axes.Layout.Row = 1;
            app.handles.ic_where_axes.Layout.Column = 1;
            app.style_axes(app.handles.ic_where_axes);

            app.handles.ic_dynamic_box = uipanel(ic_editor, ...
                'BorderType', 'line', ...
                'BackgroundColor', C.bg_panel_alt, ...
                'ForegroundColor', C.accent_gray);
            app.handles.ic_dynamic_box.Layout.Row = [3 10];
            app.handles.ic_dynamic_box.Layout.Column = [1 16];
            app.handles.ic_dynamic_grid = [];
            app.handles.ic_dynamic_inputs = struct();
            app.handles.ic_dynamic_labels = struct();
            app.handles.ic_center_x_label = [];
            app.handles.ic_center_x = [];
            app.handles.ic_center_y_label = [];
            app.handles.ic_center_y = [];
            app.handles.ic_scale_label = [];
            app.handles.ic_scale = [];
            app.handles.ic_count_label = [];
            app.handles.ic_count = [];
            app.handles.ic_amplitude_label = [];
            app.handles.ic_amplitude = [];

            app.handles.ic_status = uilabel(ic_editor, 'Text', '', ...
                'FontColor', C.fg_muted, 'FontSize', 11, 'HorizontalAlignment', 'left');
            app.handles.ic_status.Layout.Row = [11 12];
            app.handles.ic_status.Layout.Column = [1 16];
            app.handles.ic_status.Visible = 'off';
            if isprop(app.handles.ic_status, 'WordWrap')
                app.handles.ic_status.WordWrap = 'on';
            end

            % === Row 4: IC Preview (full-width plot) ===
            panel_preview = uipanel(right_layout, 'Title', 'IC Preview', ...
                'BackgroundColor', C.bg_panel_alt);
            if isprop(panel_preview, 'Scrollable')
                panel_preview.Scrollable = 'on';
            end
            panel_preview.Layout.Row = 4; panel_preview.Layout.Column = 1;
            app.handles.config_ic_preview_panel = panel_preview;
            preview_inner = uigridlayout(panel_preview, [1 1]);
            preview_inner.RowHeight = {'1x'};
            preview_inner.ColumnWidth = {'1x'};
            preview_inner.Padding = [4 4 4 4];
            preview_inner.RowSpacing = 6;
            app.handles.ic_preview_action_row = buttons_row;

            app.handles.ic_preview_axes = uiaxes(preview_inner);
            app.handles.ic_preview_axes.Layout.Row = 1;
            app.handles.ic_preview_axes.Layout.Column = 1;
            app.style_axes(app.handles.ic_preview_axes);

            % Create dummy checklist handles for backward compatibility
            app.handles.check_grid = uilabel(buttons_row, 'Text', '', 'Visible', 'off');
            app.handles.check_grid.Layout.Row = 1; app.handles.check_grid.Layout.Column = 7;
            app.handles.check_domain = app.handles.check_grid;
            app.handles.check_time = app.handles.check_grid;
            app.handles.check_ic = app.handles.check_grid;
            app.handles.check_conv = app.handles.check_grid;
            app.handles.check_monitor = app.handles.check_grid;
            app.handles.check_collectors = app.handles.check_grid;
            app.handles.check_outputs = app.handles.check_grid;
            app.handles.defaults_source_info = app.handles.check_grid;

            % Initialize display
            app.sync_ic_contour_bands_button();
            app.apply_bc_case_to_dropdowns();
            app.update_ic_fields();
            app.on_method_changed();
            app.sync_gpu_toggle_state(false);
            app.update_mode_control_visibility();
            app.update_convergence_control_state();
            app.update_ic_preview();
            app.update_checklist();
            app.apply_tooltips();
            app.enforce_container_content_margins(parent);
        end
        function create_monitoring_tab(app)
            % 3x3 dashboard contract: 8 ranked plots + 1 numeric table tile.
            % Data-flow reference for debugging:
            % - Incoming runtime payloads are consumed in handle_live_monitor_progress().
            % - Plot/numeric tile vectors are assembled in resolve_monitor_series().
            % - This method only creates components and performs initial bind/setup.
            C = app.layout_cfg.colors;
            cfg = app.layout_cfg.monitor_tab;
            T = app.layout_cfg.ui_text.monitor;

            parent = app.tabs.monitoring;
            parent.BackgroundColor = C.bg_dark;

            root = uigridlayout(parent, cfg.root.rows_cols);
            root.ColumnWidth = cfg.root.col_widths;
            root.RowHeight = cfg.root.row_heights;
            root.Padding = cfg.root.padding;
            root.ColumnSpacing = cfg.root.col_spacing;
            app.handles.monitor_root_grid = root;

            dashboard_panel = uipanel(root, ...
                'Title', app.layout_cfg.text.monitor_panels.dashboard, ...
                'BackgroundColor', C.bg_panel_alt);
            dashboard_panel.Layout.Row = app.layout_cfg.coords.monitor.left_panel(1);
            dashboard_panel.Layout.Column = app.layout_cfg.coords.monitor.left_panel(2);

            dash_grid = uigridlayout(dashboard_panel, [cfg.plot_grid_rows, cfg.plot_grid_cols]);
            dash_grid.RowHeight = {'1x', '1x', '1x'};
            dash_grid.ColumnWidth = {'1x', '1x', '1x'};
            dash_grid.Padding = cfg.left.padding;
            dash_grid.RowSpacing = cfg.left.row_spacing;
            dash_grid.ColumnSpacing = cfg.left.col_spacing;
            dash_grid.BackgroundColor = C.bg_dark;

            % Metric title/xlabel/ylabel/rank are owned by cfg.monitor_tab.metric_catalog.
            app.handles.monitor_metric_catalog = app.build_monitor_metric_catalog();
            app.handles.monitor_ranked_selection = 1:8;
            app.handles.monitor_axes = gobjects(1, 8);
            app.handles.monitor_line_handles = cell(1, 8);
            app.handles.monitor_slot_metric_ids = repmat({''}, 1, 8);

            plot_slot = 0;
            for tile_idx = 1:cfg.plot_tile_count
                row_idx = ceil(tile_idx / cfg.plot_grid_cols);
                col_idx = mod(tile_idx - 1, cfg.plot_grid_cols) + 1;

                if tile_idx == cfg.numeric_tile_index
                    numeric_panel = uipanel(dash_grid, ...
                        'Title', 'Metrics', ...
                        'BackgroundColor', C.bg_panel_alt);
                    numeric_panel.Layout.Row = row_idx;
                    numeric_panel.Layout.Column = col_idx;
                    % 2-column metrics grid instead of scrollable table
                    metrics_grid = uigridlayout(numeric_panel, [11 4]);
                    metrics_grid.Padding = [4 4 4 4];
                    metrics_grid.RowSpacing = 2;
                    metrics_grid.ColumnSpacing = 4;
                    metrics_grid.ColumnWidth = {80, '1x', 80, '1x'};
                    metrics_grid.RowHeight = repmat({20}, 1, 11);
                    app.handles.monitor_metrics_grid = metrics_grid;
                    app.handles.monitor_metric_labels = gobjects(0);
                    app.handles.monitor_metric_values = gobjects(0);
                    % Backward-compatibility alias for tests/helpers that still
                    % expect a numeric monitor table handle.
                    app.handles.monitor_numeric_table = uitable(numeric_panel, ...
                        'Data', cell(0, 1), ...
                        'ColumnName', {'Summary'}, ...
                        'Visible', 'off');
                    % Pre-create 22 label pairs (11 rows x 2 columns)
                    for mi = 1:11
                        lbl_l = uilabel(metrics_grid, 'Text', '--', 'FontColor', C.fg_muted, 'FontSize', 11);
                        lbl_l.Layout.Row = mi; lbl_l.Layout.Column = 1;
                        val_l = uilabel(metrics_grid, 'Text', '--', 'FontColor', C.fg_text, 'FontSize', 11, 'FontName', 'Consolas');
                        val_l.Layout.Row = mi; val_l.Layout.Column = 2;
                        lbl_r = uilabel(metrics_grid, 'Text', '--', 'FontColor', C.fg_muted, 'FontSize', 11);
                        lbl_r.Layout.Row = mi; lbl_r.Layout.Column = 3;
                        val_r = uilabel(metrics_grid, 'Text', '--', 'FontColor', C.fg_text, 'FontSize', 11, 'FontName', 'Consolas');
                        val_r.Layout.Row = mi; val_r.Layout.Column = 4;
                        app.handles.monitor_metric_labels(end+1) = lbl_l;
                        app.handles.monitor_metric_values(end+1) = val_l;
                        app.handles.monitor_metric_labels(end+1) = lbl_r;
                        app.handles.monitor_metric_values(end+1) = val_r;
                    end
                    continue;
                end

                plot_slot = plot_slot + 1;
                metric = app.handles.monitor_metric_catalog(plot_slot);

                % Place axes directly on the dashboard grid (no panel wrapper)
                % to maximise figure area. Titles come from apply_monitor_plot_format.
                ax = uiaxes(dash_grid);
                ax.Layout.Row = row_idx;
                ax.Layout.Column = col_idx;
                app.style_axes(ax);
                title_interp = app.pick_metric_interpreter(metric.title);
                x_interp = app.pick_metric_interpreter(metric.xlabel);
                y_interp = app.pick_metric_interpreter(metric.ylabel);
                title(ax, metric.title, 'Color', C.fg_text, 'FontSize', 16, 'FontWeight', 'bold', 'Interpreter', title_interp);
                xlabel(ax, metric.xlabel, 'Color', C.fg_text, 'FontSize', 12, 'Interpreter', x_interp);
                ylabel(ax, metric.ylabel, 'Color', C.fg_text, 'FontSize', 12, 'Interpreter', y_interp);
                grid(ax, 'on');
                ax.GridAlpha = 0.3;
                ax.FontSize = 11;
                ax.XColor = C.fg_text;
                ax.YColor = C.fg_text;
                ax.PlotBoxAspectRatio = [1 1 1];
                ax.PlotBoxAspectRatioMode = 'manual';
                app.handles.monitor_axes(plot_slot) = ax;
            end

            % Backward-compatibility aliases used by older test/helpers.
            app.handles.exec_monitor_axes1 = app.handles.monitor_axes(1);
            app.handles.exec_monitor_axes2 = app.handles.monitor_axes(2);
            app.handles.conv_monitor_axes = app.handles.monitor_axes(3);

            sidebar = uipanel(root, 'Title', T.sidebar.panel_title, ...
                'BackgroundColor', C.bg_panel_alt);
            sidebar.Layout.Row = app.layout_cfg.coords.monitor.terminal_panel(1);
            sidebar.Layout.Column = app.layout_cfg.coords.monitor.terminal_panel(2);
            side_layout = uigridlayout(sidebar, cfg.sidebar.rows_cols);
            side_layout.RowHeight = cfg.sidebar.row_heights;
            side_layout.Padding = cfg.sidebar.padding;
            side_layout.RowSpacing = cfg.sidebar.row_spacing;

            controls = uigridlayout(side_layout, [1 2]);
            controls.Layout.Row = 1;
            controls.Layout.Column = 1;
            controls.ColumnWidth = {'1x', '1x'};
            controls.Padding = [0 0 0 0];
            controls.ColumnSpacing = 6;
            uibutton(controls, 'Text', T.sidebar.save_log_button, ...
                'ButtonPushedFcn', @(~,~) app.save_terminal_log());
            uibutton(controls, 'Text', T.sidebar.clear_button, ...
                'ButtonPushedFcn', @(~,~) app.clear_terminal_view());

            progress_panel = uipanel(side_layout, 'Title', 'Progress', ...
                'BackgroundColor', C.bg_panel);
            progress_panel.Layout.Row = 2;
            progress_panel.Layout.Column = 1;
            app.handles.progress_panel = progress_panel;
            progress_grid = uigridlayout(progress_panel, [6, 2]);
            progress_grid.RowHeight = {'fit', 30, 'fit', 30, 24, 40};
            progress_grid.ColumnWidth = {'1x', 'fit'};
            progress_grid.Padding = [8 8 8 8];
            progress_grid.ColumnSpacing = 10;
            progress_grid.RowSpacing = 4;
            app.handles.progress_grid = progress_grid;

            app.handles.phase_progress_label = uilabel(progress_grid, ...
                'Text', 'Overall Progress', ...
                'FontColor', C.fg_text, ...
                'HorizontalAlignment', 'left', ...
                'FontWeight', 'bold', ...
                'FontSize', 10);
            app.handles.phase_progress_label.Layout.Row = 1;
            app.handles.phase_progress_label.Layout.Column = 1;

            app.handles.phase_progress_value = uilabel(progress_grid, ...
                'Text', '--', ...
                'FontColor', C.fg_muted, ...
                'HorizontalAlignment', 'right', ...
                'FontSize', 10);
            app.handles.phase_progress_value.Layout.Row = 1;
            app.handles.phase_progress_value.Layout.Column = 2;

            app.handles.progress_gauge = uigauge(progress_grid, 'linear');
            app.handles.progress_gauge.Layout.Row = 2;
            app.handles.progress_gauge.Layout.Column = [1 2];
            app.handles.progress_gauge.Limits = [0 100];
            app.handles.progress_gauge.Value = 0;
            app.handles.progress_gauge.ScaleColors = [ ...
                C.accent_cyan;
                C.accent_green];
            app.handles.progress_gauge.ScaleColorLimits = [0 100];
            app.handles.progress_gauge.MajorTicks = 0:20:100;

            app.handles.child_progress_label = uilabel(progress_grid, ...
                'Text', 'Child Job Progress', ...
                'FontColor', C.fg_text, ...
                'HorizontalAlignment', 'left', ...
                'FontWeight', 'bold', ...
                'FontSize', 10);
            app.handles.child_progress_label.Layout.Row = 3;
            app.handles.child_progress_label.Layout.Column = 1;

            app.handles.child_progress_value = uilabel(progress_grid, ...
                'Text', '--', ...
                'FontColor', C.fg_muted, ...
                'HorizontalAlignment', 'right', ...
                'FontSize', 10);
            app.handles.child_progress_value.Layout.Row = 3;
            app.handles.child_progress_value.Layout.Column = 2;

            app.handles.child_progress_gauge = uigauge(progress_grid, 'linear');
            app.handles.child_progress_gauge.Layout.Row = 4;
            app.handles.child_progress_gauge.Layout.Column = [1 2];
            app.handles.child_progress_gauge.Limits = [0 100];
            app.handles.child_progress_gauge.Value = 0;
            app.handles.child_progress_gauge.ScaleColors = [ ...
                C.accent_yellow;
                C.accent_blue];
            app.handles.child_progress_gauge.ScaleColorLimits = [0 100];
            app.handles.child_progress_gauge.MajorTicks = 0:20:100;

            app.handles.progress_eta_label = uilabel(progress_grid, ...
                'Text', 'ETA: --', ...
                'FontColor', C.fg_muted, ...
                'HorizontalAlignment', 'left', ...
                'FontSize', 10);
            app.handles.progress_eta_label.Layout.Row = 5;
            app.handles.progress_eta_label.Layout.Column = 1;

            app.handles.run_status = uilabel(progress_grid, 'Text', T.sidebar.run_status_idle, ...
                'FontColor', C.fg_muted, 'HorizontalAlignment', 'right', ...
                'FontWeight', 'bold', 'FontSize', 10);
            app.handles.run_status.Layout.Row = 5;
            app.handles.run_status.Layout.Column = 2;

            app.handles.workflow_activity_text = uitextarea(progress_grid, ...
                'Value', {'Run activity will appear here.', 'Status: idle'}, ...
                'Editable', 'off', ...
                'BackgroundColor', C.bg_input, ...
                'FontColor', C.fg_text, ...
                'FontName', 'Consolas', ...
                'FontSize', 10);
            app.handles.workflow_activity_text.Layout.Row = 6;
            app.handles.workflow_activity_text.Layout.Column = [1 2];

            app.handles.terminal_output = uitextarea(side_layout, ...
                'Value', app.terminal_display_lines(), ...
                'Editable', 'off', ...
                'BackgroundColor', C.bg_input, ...
                'FontColor', C.fg_text, ...
                'FontName', 'Consolas', ...
                'FontSize', 11);
            app.handles.terminal_output.Layout.Row = 3;
            app.handles.terminal_output.Layout.Column = 1;

            source_panel = uipanel(side_layout, 'Title', T.sidebar.collector_panel_title, ...
                'BackgroundColor', C.bg_panel_alt);
            source_panel.Layout.Row = 4;
            source_panel.Layout.Column = 1;
            source_grid = uigridlayout(source_panel, [4 3]);
            source_grid.Padding = [4 4 4 4];
            source_grid.RowHeight = {18, 18, 18, 24};
            source_grid.ColumnWidth = {'1x', '1x', '1x'};

            app.handles.collector_probe_status = uilabel(source_grid, ...
                'Text', T.sidebar.collector_probe_waiting, ...
                'HorizontalAlignment', 'center', 'FontColor', C.fg_muted, 'FontSize', 10);
            app.handles.collector_probe_status.Layout.Row = 1;
            app.handles.collector_probe_status.Layout.Column = [1 3];

            headers = T.sidebar.collector_headers;
            lbl = uilabel(source_grid, 'Text', headers{1}, 'HorizontalAlignment', 'center', 'FontColor', C.fg_text, 'FontSize', 10);
            lbl.Layout.Row = 2; lbl.Layout.Column = 1;
            lbl = uilabel(source_grid, 'Text', headers{2}, 'HorizontalAlignment', 'center', 'FontColor', C.fg_text, 'FontSize', 10);
