        % Action methods
        function launch_simulation(app, cfg_override)
            % Collect UI state and start the selected run path asynchronously.
            % The green-button path must return immediately so the UI stays responsive.
            if nargin < 2
                cfg_override = [];
            end
            app.clear_terminal_view();

            % Suppress traditional figure windows only while the launch is
            % running, then restore the user's MATLAB session default.
            launch_default_figure_visible = char(string(get(groot, 'DefaultFigureVisible')));
            set(groot, 'DefaultFigureVisible', 'off');
            restore_default_figure_visible = onCleanup( ...
                @() set(groot, 'DefaultFigureVisible', launch_default_figure_visible)); %#ok<NASGU>

            try
                requested_cfg = app.prepare_launch_request_config(cfg_override);
                if app.has_active_launch_request()
                    app.handle_relaunch_request_during_active_run(requested_cfg);
                    return;
                end
                app.start_green_button_async_run(requested_cfg);
            catch ME
                app.append_to_terminal(sprintf('Launch failed: [%s] %s', char(string(ME.identifier)), ME.message), 'error');
                app.stop_executor_completion_timer();
                app.pending_launch_request = struct();
                app.active_launch_context = struct();
                app.close_launch_progress_dialog();
                app.set_run_state('idle', 'Failed');
                if ~isempty(app.fig) && isvalid(app.fig)
                    fail_msg = sprintf('Identifier: %s\n\n%s', char(string(ME.identifier)), ME.message);
                    app.show_alert_latex(fail_msg, 'Launch Error', 'Icon', 'error');
                end
            end
        end

        function requested_cfg = prepare_launch_request_config(app, cfg_override)
            if nargin < 2
                cfg_override = [];
            end

            if isempty(cfg_override)
                app.set_run_state('running', 'Collecting configuration...');
                app.collect_configuration_from_ui();
            else
                app.set_run_state('running', 'Preparing launch configuration...');
                app.config = cfg_override;
            end

            requested_cfg = app.normalize_workflow_launch_config(app.config);
            requested_cfg.result_publication_mode = 'manual';
            app.config = requested_cfg;
            app.validate_launch_configuration();
        end

        function tf = has_active_launch_request(app)
            tf = ~strcmpi(app.run_lifecycle_state, 'idle') || ~isempty(app.current_executor);
        end

        function start_green_button_async_run(app, requested_cfg)
            app.ensure_executor_ready_for_run();
            app.reset_published_completion_registry();
            app.reset_deferred_live_monitor_payloads();
            app.pending_launch_request = struct();
            app.active_launch_context = struct( ...
                'config', requested_cfg, ...
                'requested_at', datetime('now'), ...
                'run_started_tic', tic);
            app.run_lifecycle_state = 'starting';
            app.config = requested_cfg;
            app.log_launch_parameter_summary();
            app.emit_launch_context_banner(requested_cfg);
            if app.post_publication_queue_has_pending_work()
                app.append_to_terminal('Previous run exports are continuing in the background export queue while the new solver launch starts.', 'info');
            end
            app.append_to_terminal(sprintf('Starting %s run (%s)...', requested_cfg.mode, requested_cfg.method), 'info');

            [run_config, parameters, settings] = app.build_runtime_inputs(requested_cfg);
            app.active_launch_context.run_config = run_config;
            app.active_launch_context.parameters = parameters;
            app.active_launch_context.settings = settings;

            app.reset_live_monitor_history_for_run(requested_cfg);
            app.reset_deferred_live_monitor_payloads();
            settings.ui_progress_callback = app.build_live_monitor_payload_callback(requested_cfg);

            app.current_executor = ParallelSimulationExecutor( ...
                app.build_live_monitor_payload_callback(requested_cfg));
            app.current_executor.start(run_config, parameters, settings);
            app.run_lifecycle_state = 'running';

            if isfield(run_config, 'workflow_kind') && app.is_live_monitor_workflow_kind(run_config.workflow_kind)
                app.append_to_terminal('Phase workflow running in background via RunDispatcher...', 'info');
            else
                app.append_to_terminal('Simulation running in background...', 'info');
            end
            app.log_executor_resource_banner(settings, run_config);
            app.start_executor_completion_timer();
        end

        function handle_relaunch_request_during_active_run(app, requested_cfg)
            app.pending_launch_request = struct( ...
                'config', requested_cfg, ...
                'requested_at', datetime('now'));

            if app.active_launch_has_reached_completion()
                app.append_to_terminal('Current run already reached 100%. The new launch is queued and will start once executor teardown finishes.', 'info');
                app.set_run_state('running', 'Queued next launch...');
                return;
            end

            app.append_to_terminal('A new green-button launch replaced the unfinished run. Cancelling the current executor...', 'warning');
            try
                if ~isempty(app.current_executor) && isvalid(app.current_executor)
                    app.current_executor.cancel();
                end
            catch ME
                app.append_to_terminal(sprintf('Cancellation warning: %s', ME.message), 'warning');
            end
            app.stop_executor_completion_timer();
            app.current_executor = [];
            app.run_lifecycle_state = 'idle';
            app.close_launch_progress_dialog();
            app.set_run_state('idle', 'Cancelled');
            app.append_to_terminal('Previous run cancelled. Starting the replacement launch...', 'warning');
            app.maybe_start_pending_launch_request();
        end

        function tf = active_launch_has_reached_completion(app)
            tf = false;
            if isstruct(app.cached_completion_report_payload) && ~isempty(fieldnames(app.cached_completion_report_payload))
                tf = true;
                return;
            end
            executor = app.current_executor;
            if isempty(executor) || ~isvalid(executor)
                return;
            end
            try
                tf = executor.get_progress() >= 1.0;
            catch
                tf = false;
            end
        end

        function maybe_start_pending_launch_request(app)
            if ~isstruct(app.pending_launch_request) || ~isfield(app.pending_launch_request, 'config') || ...
                    isempty(app.pending_launch_request.config)
                return;
            end
            if app.has_active_launch_request()
                return;
            end
            staged_cfg = app.pending_launch_request.config;
            app.pending_launch_request = struct();
            app.start_green_button_async_run(staged_cfg);
        end

        function stop_executor_completion_timer(app)
            app.safe_stop_timer('executor_completion_timer');
        end

        function start_executor_completion_timer(app)
            app.stop_executor_completion_timer();
            app.executor_completion_timer = timer( ...
                'ExecutionMode', 'fixedSpacing', ...
                'BusyMode', 'drop', ...
                'Period', 0.10, ...
                'TimerFcn', {@ui_controller_timer_poll_active_executor_completion, app});
            start(app.executor_completion_timer);
        end

        function poll_active_executor_completion(app)
            executor = app.current_executor;
            if isempty(executor) || ~isvalid(executor)
                app.stop_executor_completion_timer();
                app.run_lifecycle_state = 'idle';
                app.maybe_start_pending_launch_request();
                return;
            end

            try
                completion = executor.poll_completion(@() app.flush_deferred_live_monitor_payloads());
                app.flush_deferred_live_monitor_payloads();
            catch ME
                failure_error = app.resolve_async_completion_error(executor, ME);
                app.stop_executor_completion_timer();
                app.current_executor = [];
                app.run_lifecycle_state = 'idle';
                app.close_launch_progress_dialog();
                app.set_run_state('idle', 'Failed');
                app.append_to_terminal(sprintf('Async launch completion failed: [%s] %s', ...
                    char(string(failure_error.identifier)), failure_error.message), 'error');
                app.active_launch_context = struct();
                app.maybe_start_pending_launch_request();
                return;
            end

            if ~isstruct(completion) || ~isfield(completion, 'done') || ~completion.done
                return;
            end

            app.stop_executor_completion_timer();
            app.current_executor = [];
            app.run_lifecycle_state = 'idle';
            app.close_launch_progress_dialog();

            switch lower(char(string(completion.state)))
                case 'finished'
                    summary = app.build_async_completion_summary(completion.results, completion.paths);
                    published = app.publish_host_completion_summary(summary);
                    if ~published
                        app.append_to_terminal('Run completed, but no new Results entry was published.', 'warning');
                    end
                    app.active_launch_context = struct();
                    app.set_run_state('idle', 'Completed');
                case 'cancelled'
                    app.append_to_terminal('Simulation cancelled by user', 'warning');
                    app.active_launch_context = struct();
                    app.set_run_state('idle', 'Cancelled');
                case 'failed'
                    failure_error = completion.error;
                    if isempty(failure_error)
                        failure_error = MException('UIController:AsyncLaunchFailed', ...
                            'Background simulation failed without a captured error.');
                    end
                    app.append_to_terminal(sprintf('Launch failed: [%s] %s', ...
                        char(string(failure_error.identifier)), failure_error.message), 'error');
                    app.active_launch_context = struct();
                    app.set_run_state('idle', 'Failed');
                otherwise
                    app.active_launch_context = struct();
                    app.set_run_state('idle', 'Completed');
            end

            drawnow limitrate nocallbacks;
            app.maybe_start_pending_launch_request();
        end

        function summary = build_async_completion_summary(app, results, paths)
            summary = struct();
            context = app.active_launch_context;
            if ~isstruct(context)
                context = struct();
            end
            cfg = app.pick_field(context, {'config'}, struct());
            if ~isstruct(cfg)
                cfg = struct();
            end
            summary.mode = app.pick_field(cfg, {'mode'}, app.pick_field(app.config, {'mode'}, ''));
            summary.run_config = app.pick_field(context, {'run_config'}, struct());
            summary.parameters = app.pick_field(context, {'parameters'}, struct());
            summary.settings = app.pick_field(context, {'settings'}, struct());
            summary.results = results;
            summary.paths = paths;
            run_started_tic = app.pick_field(context, {'run_started_tic'}, []);
            if ~isempty(run_started_tic)
                summary.wall_time = toc(run_started_tic);
            else
                summary.wall_time = NaN;
            end
            if isstruct(results) && isfield(results, 'analysis') && isstruct(results.analysis)
                summary.analysis = results.analysis;
            end
            summary.solver_complete = true;
            summary.minimal_results_persisted = true;
            summary.results_published = false;
            summary.exports_complete = false;
        end

        function log_executor_resource_banner(app, settings, run_config)
            try
                pool = gcp('nocreate');
                if ~isempty(pool)
                    app.append_to_terminal(sprintf('Parallel pool workers: %d', pool.NumWorkers), 'info');
                end
            catch
                % Best-effort introspection only.
            end
            if isfield(settings, 'resource_allocation') && isstruct(settings.resource_allocation)
                ra = settings.resource_allocation;
                worker_req = app.pick_field(ra, {'pool_workers_requested', 'pool_workers'}, 1);
                worker_eff = app.pick_field(ra, {'pool_workers_effective', 'pool_workers'}, worker_req);
                thread_cap = app.pick_field(ra, {'thread_cap', 'max_threads'}, 1);
                gpu_eff = app.on_off(logical(app.pick_field(ra, {'gpu_enabled_effective'}, false)));
                profile_id = char(string(app.pick_field(ra, {'host_profile_id'}, 'none')));
                app.append_to_terminal(sprintf( ...
                    ['Allocator -> CPU %.0f%% | MEM %.0f%% | GPU %.0f%% | monitor %.1f Hz | ' ...
                     'progress %.1f Hz | workers %d->%d | thread cap %d | GPU eff %s | host %s'], ...
                    ra.cpu_target_pct, ra.memory_target_pct, ra.gpu_target_pct, ra.monitor_hz, ra.progress_hz, ...
                    worker_req, worker_eff, thread_cap, upper(gpu_eff), profile_id), 'info');
                note_lines = app.pick_field(ra, {'planner_notes'}, {});
                if iscell(note_lines)
                    for i_note = 1:numel(note_lines)
                        note_text = char(string(note_lines{i_note}));
                        note_cmp = lower(strtrim(note_text));
                        if isempty(note_cmp)
                            continue;
                        end
                        if contains(note_cmp, 'gpu') || contains(note_cmp, 'workers clamped') || contains(note_cmp, 'thread cap')
                            app.append_to_terminal(sprintf('Allocator note: %s', note_text), 'info');
                        end
                    end
                end
            end
        end

        function log_launch_parameter_summary(app)
            % Print selected launch parameters before any run-status lines.
            cfg = app.config;
            method_label = app.humanize_token(cfg.method);
            mode_label = app.humanize_token(cfg.mode);
            run_mode_label = app.humanize_token(cfg.run_mode_internal);
            ic_label = cfg.ic_type;
            plot_snapshots = cfg.num_snapshots;
            if isfield(cfg, 'num_plot_snapshots') && isnumeric(cfg.num_plot_snapshots)
                plot_snapshots = max(1, round(cfg.num_plot_snapshots));
            end

            lines = {
                '=== Selected Run Parameters ==='
                sprintf('Method: %s | Mode: %s | Dispatcher: %s', method_label, mode_label, run_mode_label)
                sprintf('Grid: Nx=%d Ny=%d | Domain: Lx=%.4g Ly=%.4g', cfg.Nx, cfg.Ny, cfg.Lx, cfg.Ly)
                sprintf('Time: dt=%.4g Tfinal=%.4g | Plot snapshots=%d | Frame snapshots=%d', ...
                    cfg.dt, cfg.Tfinal, plot_snapshots, cfg.num_snapshots)
                sprintf('IC: %s | Scale=%.4g | Count=%d', ic_label, cfg.ic_scale, cfg.ic_count)
                sprintf('Output: CSV=%s MAT=%s PNG=%s PDF=%s', ...
                    app.on_off(cfg.save_csv), app.on_off(cfg.save_mat), ...
                    app.on_off(cfg.figures_save_png), app.on_off(cfg.figures_save_fig))
                sprintf('Sustainability: monitor=%s interval=%.4gs autolog=%s', ...
                    app.on_off(cfg.enable_monitoring), cfg.sample_interval, app.on_off(cfg.sustainability_auto_log))
                sprintf('Launch monitoring: HWiNFO=%s', ...
                    app.on_off(app.pick_field(app.pick_field(cfg, {'collectors'}, struct()), {'hwinfo'}, false)))
                '================================'
            };

            if strcmp(cfg.mode, 'sweep')
                lines{end + 1} = sprintf('Sweep: %s = [%s]', cfg.sweep_parameter, ...
                    strjoin(arrayfun(@(v) sprintf('%.4g', v), cfg.sweep_values, 'UniformOutput', false), ', ')); %#ok<AGROW>
            end

            for i = 1:numel(lines)
                app.append_to_terminal(lines{i}, 'info');
            end
        end

        function collect_configuration_from_ui(app)
            % Gather normalized runtime configuration from UI handles
            method_val = app.handles.method_dropdown.Value;
            switch method_val
                case 'Finite Difference'
                    app.config.method = 'finite_difference';
                case 'Finite Volume'
                    app.config.method = 'finite_volume';
                case 'Shallow Water'
                    app.config.method = 'shallow_water';
                case 'Spectral'
                    app.config.method = 'spectral';
                otherwise
                    app.config.method = 'finite_difference';
            end

            mode_val = app.handles.mode_dropdown.Value;
            switch mode_val
                case 'Evolution'
                    app.config.mode = 'evolution';
                    app.config.run_mode_internal = 'Evolution';
                case 'Convergence'
                    app.config.mode = 'convergence';
                    app.config.run_mode_internal = 'Convergence';
                case {'Parameter Sweep', 'Sweep'}
                    app.config.mode = 'sweep';
                    app.config.run_mode_internal = 'ParameterSweep';
                case 'Animation'
                    app.config.mode = 'animation';
                    app.config.run_mode_internal = 'Evolution';
                otherwise
                    app.config.mode = 'evolution';
                    app.config.run_mode_internal = 'Evolution';
            end

            app.config.Nx = max(2, round(app.handles.Nx.Value));
            app.config.Ny = max(2, round(app.handles.Ny.Value));
            app.config.Lx = max(1e-9, double(app.handles.Lx.Value));
            app.config.Ly = max(1e-9, double(app.handles.Ly.Value));
            app.config.Nz = 12;
            app.config.Lz = 1.0;
            app.config.delta = max(1e-9, double(app.handles.delta.Value));
            app.config.equal_spacing = false;
            if app.has_valid_handle('equal_spacing')
                app.config.equal_spacing = logical(app.handles.equal_spacing.Value);
            end
            app.config.grid_mode = app.get_grid_mode_token();

            app.config.Lx = max(1e-9, double(app.handles.Lx.Value));
            app.config.Ly = max(1e-9, double(app.handles.Ly.Value));
            app.config.dx = app.config.Lx / max(app.config.Nx, 1);
            app.config.dy = app.config.Ly / max(app.config.Ny, 1);
            app.config.delta = min(app.config.dx, app.config.dy);
            app.config.is_anisotropic = abs(app.config.dx - app.config.dy) > ...
                1.0e-12 * max(app.config.dx, app.config.dy);

            % --- Boundary conditions ---
            % Collect the BC Case label and map to internal key
            if app.has_valid_handle('bc_case')
                bc_case_label = char(string(app.handles.bc_case.Value));
            else
                bc_case_label = 'Periodic (All)';
            end
            switch bc_case_label
                case 'Lid Driven Cavity',            app.config.bc_case = 'lid_driven_cavity';
                case 'Driven Channel Flow',          app.config.bc_case = 'driven_channel_flow';
                case 'Lid & Bottom Driven Cavity',   app.config.bc_case = 'lid_and_bottom_driven_cavity';
                case 'Enclosed Shear Layer',         app.config.bc_case = 'enclosed_shear_layer';
                case 'Enclosed Cavity',              app.config.bc_case = 'enclosed_cavity';
                case 'User Defined',                 app.config.bc_case = 'user_defined';
                otherwise,                           app.config.bc_case = 'periodic';
            end
            [app.config.bc_top, app.config.bc_top_math, app.config.bc_top_physical] = ...
                app.normalize_bc_selection(app.safe_bc_value('bc_top', 'Periodic'));
            [app.config.bc_bottom, app.config.bc_bottom_math, app.config.bc_bottom_physical] = ...
                app.normalize_bc_selection(app.safe_bc_value('bc_bottom', 'Periodic'));
            [app.config.bc_left, app.config.bc_left_math, app.config.bc_left_physical] = ...
                app.normalize_bc_selection(app.safe_bc_value('bc_left', 'Periodic'));
            [app.config.bc_right, app.config.bc_right_math, app.config.bc_right_physical] = ...
                app.normalize_bc_selection(app.safe_bc_value('bc_right', 'Periodic'));
            app.config.U_top = app.safe_numeric_value('U_top', 0.0);
            app.config.U_bottom = app.safe_numeric_value('U_bottom', 0.0);
            app.config.U_left = app.safe_numeric_value('U_left', 0.0);
            app.config.U_right = app.safe_numeric_value('U_right', 0.0);
            app.config.use_explicit_delta = false;
            app.config.dt = app.handles.dt.Value;
            app.config.Tfinal = app.handles.t_final.Value;
            app.config.t_final = app.config.Tfinal;
            app.config.nu = app.handles.nu.Value;
            app.config.num_plot_snapshots = max(1, round(app.handles.num_snapshots.Value));
            app.config.num_snapshots = app.config.num_plot_snapshots;
            app.config.analysis_method = app.handles.method_dropdown.Value;

            app.config.save_csv = app.handles.save_csv.Value;
            app.config.save_mat = app.handles.save_mat.Value;
            app.update_animation_export_controls();
            app.config.figures_save_png = false;
            app.config.figures_save_fig = app.handles.figures_save_fig.Value;
            app.config.figures_dpi = app.handles.figures_dpi.Value;
            app.config.figures_close_after_save = app.handles.figures_close_after_save.Value;
            app.config.figures_use_owl_saver = app.handles.figures_use_owl_saver.Value;
            app.config.create_animations = app.handles.create_animations.Value;
            app.config.animation_format = char(string(app.handles.animation_format.Value));
            app.config.animation_export_format = app.config.animation_format;
            app.config.animation_export_formats = {'mp4', 'gif'};
            app.config.animation_fps = app.handles.animation_fps.Value;
            app.config.animation_duration_s = app.handles.animation_duration_s.Value;
            if ~isfield(app.config, 'animation_gif_min_frames') || ~isfinite(app.config.animation_gif_min_frames)
                app.config.animation_gif_min_frames = 2;
            end
            app.config.animation_export_preset = char(string(app.handles.animation_export_preset.Value));
            app.config.animation_export_dpi = app.handles.animation_export_dpi.Value;
            [anim_width_in, anim_height_in] = app.resolve_animation_export_inches(app.config.animation_export_preset);
            app.config.animation_export_width_in = anim_width_in;
            app.config.animation_export_height_in = anim_height_in;
            app.config.animation_export_resolution_px = max(2, round([anim_width_in, anim_height_in] * app.config.animation_export_dpi));
            requested_animation_frames = max(2, round(app.handles.animation_num_frames.Value));
            app.config.animation_gif_min_frames = min(max(2, round(double(app.config.animation_gif_min_frames))), ...
                requested_animation_frames);
            app.config.animation_num_frames = requested_animation_frames;
            if strcmp(app.config.mode, 'animation')
                app.config.create_animations = true;
            end
            app.config.num_snapshots = app.config.num_plot_snapshots;

            if app.has_valid_handle('simulation_scenario')
                app.config.simulation_scenario = char(string(app.handles.simulation_scenario.Value));
            elseif ~isfield(app.config, 'simulation_scenario')
                app.config.simulation_scenario = 'Manual';
            end
            if app.has_valid_handle('bathymetry_scenario')
                app.config.bathymetry_scenario = normalize_bathymetry_scenario_token(app.handles.bathymetry_scenario.Value);
            elseif ~isfield(app.config, 'bathymetry_scenario')
                app.config.bathymetry_scenario = 'flat_2d';
            end
            if app.has_valid_handle('bathymetry_bed_slope')
                app.config.bathymetry_bed_slope = double(app.handles.bathymetry_bed_slope.Value);
            elseif ~isfield(app.config, 'bathymetry_bed_slope')
                app.config.bathymetry_bed_slope = 0.03;
            end
            if app.has_valid_handle('bathymetry_depth_offset')
                app.config.bathymetry_depth_offset = double(app.handles.bathymetry_depth_offset.Value);
            elseif ~isfield(app.config, 'bathymetry_depth_offset')
                app.config.bathymetry_depth_offset = 1000.0;
            end
            if app.has_valid_handle('bathymetry_relief_amplitude')
                app.config.bathymetry_relief_amplitude = double(app.handles.bathymetry_relief_amplitude.Value);
            elseif ~isfield(app.config, 'bathymetry_relief_amplitude')
                app.config.bathymetry_relief_amplitude = 180.0;
            end
            if ~isfield(app.config, 'bathymetry_resolution') || ~isfinite(app.config.bathymetry_resolution)
                app.config.bathymetry_resolution = app.get_bathymetry_resolution();
            end
            if ~isfield(app.config, 'bathymetry_custom_points') || isempty(app.config.bathymetry_custom_points)
                app.config.bathymetry_custom_points = app.get_bathymetry_control_points();
            end
            if ~isfield(app.config, 'bathymetry_dynamic_params') || ~isstruct(app.config.bathymetry_dynamic_params)
                if isfield(app.layout_cfg, 'ui_defaults') && isstruct(app.layout_cfg.ui_defaults) && ...
                        isfield(app.layout_cfg.ui_defaults, 'bathymetry_dynamic_params') && ...
                        isstruct(app.layout_cfg.ui_defaults.bathymetry_dynamic_params)
                    app.config.bathymetry_dynamic_params = app.layout_cfg.ui_defaults.bathymetry_dynamic_params;
                else
                    app.config.bathymetry_dynamic_params = struct();
                end
            end
            app.config.bathymetry_dimension_policy = 'by_method';
            app.config.bathymetry_enabled = true;
            if ~isfield(app.config, 'bathymetry_file')
                app.config.bathymetry_file = '';
            end

            % Legacy motion controls are removed from the Method tab.
            % Preserve imported/runtime compatibility fields as inert values.
            if ~isfield(app.config, 'motion_enabled')
                app.config.motion_enabled = false;
            end
            if ~isfield(app.config, 'motion_model')
                app.config.motion_model = 'none';
            end
            if ~isfield(app.config, 'motion_amplitude')
                app.config.motion_amplitude = 0.0;
            end
            app.config = app.normalize_vorticity_only_legacy_fields(app.config, 'startup');

            % Solver options: Arakawa and GPU toggles
            if app.has_valid_handle('arakawa_enable')
                app.config.use_arakawa = app.handles.arakawa_enable.Value;
            else
                app.config.use_arakawa = false;
            end
            if app.has_valid_handle('gpu_enable')
                app.config.use_gpu = app.handles.gpu_enable.Value;
            else
                app.config.use_gpu = false;
            end
            app.config.cpu_allocation_pct = min(max(app.safe_numeric_value('cpu_allocation_pct', 80), 5), 100);
            app.config.memory_allocation_pct = min(max(app.safe_numeric_value('memory_allocation_pct', 70), 10), 95);
            app.config.gpu_allocation_pct = min(max(app.safe_numeric_value('gpu_allocation_pct', 80), 0), 100);
            app.config.monitor_update_hz = min(max(app.safe_numeric_value('monitor_update_hz', 2), 0.5), 20);
            app.config.progress_update_hz = min(max(app.safe_numeric_value('progress_update_hz', 6), 0.5), 30);
            app.config.pool_workers = max(1, round(app.safe_numeric_value('pool_workers', 1)));
            app.config.resource_strategy = 'mode_adaptive';
            if app.has_valid_handle('resource_strategy')
                app.config.resource_strategy = char(string(app.handles.resource_strategy.Value));
            end
            app.config.gpu_policy = 'auto';
            if app.has_valid_handle('gpu_policy')
                app.config.gpu_policy = char(string(app.handles.gpu_policy.Value));
            end
            app.config.planner_use_host_profiles = true;
            if app.has_valid_handle('planner_use_host_profiles')
                app.config.planner_use_host_profiles = logical(app.handles.planner_use_host_profiles.Value);
            end
            app.config.interactive_pool_workers_max = max(1, round(app.safe_numeric_value('interactive_pool_workers_max', 2)));
            app.config.throughput_pool_workers_min = max(1, round(app.safe_numeric_value('throughput_pool_workers_min', 2)));
            app.config.interactive_thread_headroom_pct = min(max(app.safe_numeric_value('interactive_thread_headroom_pct', 75), 0), 99);
            app.config.gpu_min_workload_cells_steps = max(0, app.safe_numeric_value('gpu_min_workload_cells_steps', 0));
            app.config.gpu_memory_guard_pct = min(max(app.safe_numeric_value('gpu_memory_guard_pct', 80), 1), 99);
            app.config.pool_workers_max_override = max(0, round(app.safe_numeric_value('pool_workers_max_override', 0)));
            app.config.time_integrator = 'RK4';
            if app.has_valid_handle('time_integrator')
                app.config.time_integrator = char(string(app.handles.time_integrator.Value));
            end

            method_cfg = struct();
            if isfield(app.config, 'method_config') && isstruct(app.config.method_config)
                method_cfg = app.config.method_config;
            end
            if ~isfield(method_cfg, 'fd') || ~isstruct(method_cfg.fd)
                method_cfg.fd = struct('advection_scheme', 'SparseMatrix', 'time_integrator', 'RK4');
            end
            method_cfg.fd.advection_scheme = 'SparseMatrix';
            if logical(app.config.use_arakawa)
                method_cfg.fd.advection_scheme = 'Arakawa';
            end
            if ~isfield(method_cfg, 'spectral') || ~isstruct(method_cfg.spectral)
                method_cfg.spectral = struct('dealiasing_rule', '2/3', 'time_integrator', 'RK4');
            end
            if ~isfield(method_cfg, 'fv') || ~isstruct(method_cfg.fv)
                method_cfg.fv = struct('reconstruction', 'MUSCL', 'flux', 'Roe', 'time_integrator', 'RK3');
            end
            if ~isfield(method_cfg, 'fv3d') || ~isstruct(method_cfg.fv3d)
                method_cfg.fv3d = struct('vertical_diffusivity_scale', 1.0, 'z_boundary', 'no_flux');
            end
            if ~isfield(method_cfg, 'swe2d') || ~isstruct(method_cfg.swe2d)
                method_cfg.swe2d = struct( ...
                    'gravity', 9.81, ...
                    'base_depth', 1.0, ...
                    'dry_tolerance', 1.0e-4, ...
                    'cfl', 0.45, ...
                    'bed_relief_fraction', 1.15, ...
                    'bed_friction_coeff', 0.015, ...
                    'enable_wind', false, ...
                    'wind_velocity_x', 0.0, ...
                    'wind_velocity_y', 0.0, ...
                    'wind_drag_coeff', 1.5e-3, ...
                    'air_density', 1.225, ...
                    'water_density', 1000.0, ...
                    'initial_condition', 'lake_at_rest', ...
                    'surface_amplitude', 0.08, ...
                    'surface_sigma_x', 0.9, ...
                    'surface_sigma_y', 0.6, ...
                    'surface_center_x', -3.5, ...
                    'surface_center_y', 0.0, ...
                    'momentum_amplitude_x', 0.0, ...
                    'momentum_amplitude_y', 0.0, ...
                    'time_integrator', 'RK3');
            end
            switch app.config.method
                case 'finite_difference'
                    method_cfg.fd.time_integrator = app.config.time_integrator;
                case 'spectral'
                    method_cfg.spectral.time_integrator = app.config.time_integrator;
                case 'finite_volume'
                    method_cfg.fv.time_integrator = app.config.time_integrator;
                case 'shallow_water'
                    method_cfg.swe2d.time_integrator = app.config.time_integrator;
            end
            app.config.method_config = method_cfg;

            [active_ic_type, active_schema] = app.resolve_active_ic_type();
            ic_state = app.collect_ic_state(active_schema);
            app.config.ic_type = active_ic_type;
            app.config.ic_pattern = ic_state.ic_pattern;
            app.config.ic_arrangement = ic_state.ic_arrangement;
            app.config.ic_count = ic_state.ic_count;
            app.config.ic_coeff1 = ic_state.ic_coeff1;
            app.config.ic_coeff2 = ic_state.ic_coeff2;
            app.config.ic_coeff3 = ic_state.ic_coeff3;
            app.config.ic_coeff4 = ic_state.ic_coeff4;
            app.config.ic_center_x = ic_state.ic_center_x;
            app.config.ic_center_y = ic_state.ic_center_y;
            app.config.ic_scale = ic_state.ic_scale;
            if app.has_valid_handle('ic_scenario')
                app.config.ic_scenario = char(string(app.handles.ic_scenario.Value));
            else
                app.config.ic_scenario = 'Manual';
            end
            app.config.ic_amplitude = ic_state.ic_amplitude;
            if app.has_valid_handle('ic_contour_bands_btn')
                app.config.ic_contour_bands = logical(app.handles.ic_contour_bands_btn.Value);
            else
                app.config.ic_contour_bands = false;
            end
            if ~isfield(app.config, 'ic_multi_vortex_rows') || isempty(app.config.ic_multi_vortex_rows)
                app.config.ic_multi_vortex_rows = app.seed_multi_vortex_rows(app.config.ic_type);
            end
            if ~isfield(app.config, 'ic_multi_vortex_experimental')
                app.config.ic_multi_vortex_experimental = false;
            end
            app.config.ic_dynamic_values = ic_state.ic_dynamic_values;
            app.config.ic_coeff = app.build_ic_coeff_vector(app.config.ic_type);

            app.config.convergence_N_coarse = app.handles.conv_N_coarse.Value;
            app.config.convergence_N_max = app.handles.conv_N_max.Value;
            app.config.convergence_dt_values = app.parse_numeric_csv(app.handles.conv_dt_values.Value);
            app.config.convergence_tol = app.handles.conv_tolerance.Value;
            app.config.convergence_criterion_type = app.normalize_convergence_criterion_token(app.handles.conv_criterion.Value);
            app.config.convergence_binary = app.handles.conv_binary.Value;
            app.config.convergence_use_adaptive = app.handles.conv_use_adaptive.Value;
            app.config.convergence_max_jumps = app.handles.conv_max_jumps.Value;
            app.config.convergence_agent_enabled = app.handles.conv_agent_enabled.Value;
            objective_mode = 'balanced';
            if app.has_valid_handle('conv_agent_objective_mode')
                objective_mode = char(string(app.handles.conv_agent_objective_mode.Value));
            end
            conv_strategy = 'standard';
            if logical(app.config.convergence_agent_enabled)
                conv_strategy = 'agent_guided';
            end
            app.config.convergence = struct();
            app.config.convergence.dispatch = struct( ...
                'strategy', conv_strategy, ...
                'progress_telemetry', true, ...
                'artifact_verbosity', 'normal', ...
                'reuse_cache', true);
            app.config.convergence.study = struct( ...
                'N_coarse', app.config.convergence_N_coarse, ...
                'N_max', app.config.convergence_N_max, ...
                'tolerance', app.config.convergence_tol, ...
                'criterion_type', char(string(app.config.convergence_criterion_type)), ...
                'binary_search', logical(app.config.convergence_binary), ...
                'use_adaptive', logical(app.config.convergence_use_adaptive), ...
                'max_jumps', app.config.convergence_max_jumps, ...
                'verification_case', '', ...
                'temporal', struct( ...
                    'dt_values', double(app.config.convergence_dt_values(:).'), ...
                    'fine_N', app.config.convergence_N_max), ...
                'spatial', struct( ...
                    'N_values', [], ...
                    'Nz_fixed', app.config.Nz), ...
                'modal', struct( ...
                    'N_values', []), ...
                'reference', struct( ...
                    'preferred_strategy', '', ...
                    'allow_self_reference', true, ...
                    'refinement_multiplier', 2.0), ...
                'verdict', struct( ...
                    'monotonicity_relaxation', 0.05, ...
                    'minimum_improvement_factor', 1.05));
            app.config.convergence.agent = struct( ...
                'enabled', logical(app.config.convergence_agent_enabled), ...
                'objective_mode', objective_mode);

            defaults = app.initialize_default_config();
            if isfield(defaults, 'mesh_convergence') && isstruct(defaults.mesh_convergence)
                app.config.mesh_convergence = app.collect_mesh_convergence_settings_from_ui(defaults);
            elseif ~isfield(app.config, 'mesh_convergence') || ~isstruct(app.config.mesh_convergence)
                error('UIController:MissingMeshConvergenceDefaults', ...
                    'create_default_parameters must define mesh_convergence defaults.');
            end
            if isfield(defaults, 'phase1') && isstruct(defaults.phase1)
                app.config.phase1 = app.collect_phase1_settings_from_ui(defaults);
            elseif ~isfield(app.config, 'phase1') || ~isstruct(app.config.phase1)
                error('UIController:MissingPhase1Defaults', ...
                    'create_default_parameters must define phase1 defaults.');
            end
            if app.has_valid_handle('phase1_use_converged_mesh_seed')
                app.config.phase1.use_converged_mesh_seed = logical(app.handles.phase1_use_converged_mesh_seed.Value);
            end
            if isfield(defaults, 'phase2') && isstruct(defaults.phase2)
                app.config.phase2 = app.collect_phase2_settings_from_ui(defaults);
            elseif ~isfield(app.config, 'phase2') || ~isstruct(app.config.phase2)
                error('UIController:MissingPhase2Defaults', ...
                    'create_default_parameters must define phase2 defaults.');
            end
            if isfield(defaults, 'phase3') && isstruct(defaults.phase3)
                app.config.phase3 = app.collect_phase3_settings_from_ui(defaults);
            elseif ~isfield(app.config, 'phase3') || ~isstruct(app.config.phase3)
                error('UIController:MissingPhase3Defaults', ...
                    'create_default_parameters must define phase3 defaults.');
            end

            app.config.sweep_parameter = defaults.sweep_parameter;
            app.config.sweep_values = defaults.sweep_values;
            if isfield(defaults, 'experimentation') && isstruct(defaults.experimentation)
                app.config.experimentation = defaults.experimentation;
            elseif ~isfield(app.config, 'experimentation') || ~isstruct(app.config.experimentation)
                % Legacy compatibility only; active execution no longer uses experimentation mode.
                app.config.experimentation = struct( ...
                    'coeff_selector', 'ic_coeff1', ...
                    'range_start', 0.5, ...
                    'range_end', 2.0, ...
                    'num_points', 4);
            end

            if app.has_valid_handle('sweep_parameter')
                app.config.sweep_parameter = app.handles.sweep_parameter.Value;
            end
            if app.has_valid_handle('sweep_values')
                app.config.sweep_values = app.parse_numeric_csv(app.handles.sweep_values.Value);
                app.config.sweep_values = unique(app.config.sweep_values, 'stable');
            end
            if app.has_valid_handle('exp_coeff_selector')
                app.config.experimentation.coeff_selector = app.handles.exp_coeff_selector.Value;
            end
            if app.has_valid_handle('exp_range_start')
                app.config.experimentation.range_start = app.handles.exp_range_start.Value;
            end
            if app.has_valid_handle('exp_range_end')
                app.config.experimentation.range_end = app.handles.exp_range_end.Value;
            end
            if app.has_valid_handle('exp_num_points')
                app.config.experimentation.num_points = round(app.handles.exp_num_points.Value);
            end

            app.config.enable_monitoring = app.handles.enable_monitoring.Value;
            app.config.launch_progress_only = app.safe_checkbox_value('launch_progress_only', false);
            app.config.sample_interval = app.handles.sample_interval.Value;
            app.config.sustainability_auto_log = app.handles.sustainability_auto_log.Value;
            app.config.collectors = struct( ...
                'hwinfo', app.handles.hwinfo_enable.Value, ...
                'icue', app.handles.icue_enable.Value, ...
                'strict', app.handles.collector_strict.Value, ...
                'machine_tag', app.handles.machine_tag.Value);
            if isfield(app.config, 'collector_machine_profile') && ~isempty(app.config.collector_machine_profile)
                app.config.collectors.machine_profile = char(string(app.config.collector_machine_profile));
            end
            if isfield(app.config, 'collector_panel_profile') && ~isempty(app.config.collector_panel_profile)
                app.config.collectors.panel_profile = char(string(app.config.collector_panel_profile));
            end
            collector_runtime = struct();
            sustainability_cfg = struct();
            collector_paths = struct('hwinfo', '', 'icue', '');
            if isfield(app.config, 'sustainability') && isstruct(app.config.sustainability) && ...
                    ~isempty(fieldnames(app.config.sustainability))
                sustainability_cfg = app.config.sustainability;
                if isfield(app.config.sustainability, 'collector_runtime') && isstruct(app.config.sustainability.collector_runtime)
                    collector_runtime = app.config.sustainability.collector_runtime;
                end
                if isfield(app.config.sustainability, 'collector_paths') && isstruct(app.config.sustainability.collector_paths)
                    collector_paths = app.config.sustainability.collector_paths;
                end
            end
            if isfield(app.config, 'collector_paths') && isstruct(app.config.collector_paths)
                collector_paths = app.config.collector_paths;
            end
            collector_runtime.collector_launch_root_dir = char(string(app.handles.hwinfo_csv_target_dir.Value));
            collector_runtime.collector_launch_csv_file = char(string(app.handles.hwinfo_csv_target_path.Value));
            collector_runtime.hwinfo_control_mode = char(string(app.handles.hwinfo_mode.Value));
            collector_runtime.hwinfo_pro_cli_enabled = true;
            collector_runtime.hwinfo_pro_log_write_direct = true;
            collector_runtime.hwinfo_pro_poll_rate_ms = max(100, round(double(app.handles.sample_interval.Value) * 1000));
            collector_runtime.hwinfo_pro_launch_timeout_s = 20;
            collector_runtime.hwinfo_pro_csv_timeout_s = 45;
            collector_runtime.hwinfo_pro_force_stop_fallback = true;
            collector_runtime.hwinfo_transport_mode = 'auto';
            collector_runtime.hwinfo_csv_target_dir = '';
            collector_runtime.hwinfo_csv_target_path = '';
            sustainability_cfg.collector_runtime = collector_runtime;
            sustainability_cfg.collector_paths = collector_paths;
            sustainability_cfg.collector_panel_profile = char(string(app.pick_field(app.config, {'collector_panel_profile'}, ...
                app.pick_field(sustainability_cfg, {'collector_panel_profile'}, ''))));
            app.config.sustainability = sustainability_cfg;
            app.config.collector_paths = collector_paths;

            setappdata(app.fig, 'ui_config', app.config);
        end

        function validate_launch_configuration(app)
            method_token = lower(char(string(app.config.method)));
            method_token = strrep(method_token, '-', '_');
            method_token = strrep(method_token, ' ', '_');
            integrator_token = upper(char(string(app.config.time_integrator)));
            integrator_token = strrep(integrator_token, '-', '_');
            integrator_token = strrep(integrator_token, ' ', '_');
            if strcmp(integrator_token, 'EULER')
                integrator_token = 'FORWARD_EULER';
            end

            if app.config.Nx < 8 || app.config.Ny < 8
                error('Grid resolution must be at least 8x8.');
            end

            if app.config.dt <= 0 || app.config.Tfinal <= 0
                error('dt and Tfinal must both be positive.');
            end

            if strcmp(app.config.mode, 'sweep') && numel(app.config.sweep_values) < 2
                error('Sweep mode requires at least two sweep values.');
            end

            if strcmp(app.config.mode, 'animation')
                if app.config.animation_fps <= 0
                    error('Animation FPS must be positive.');
                end
                if app.config.animation_num_frames < 2
                    error('Animation requires at least two frames.');
                end
            end

            if app.config.ic_count < 1
                error('Initial-condition vortex count must be >= 1.');
            end
            if strcmp(method_token, 'shallow_water') && strcmpi(char(string(app.config.ic_type)), 'no_initial_condition')
                error('Shallow Water does not accept the No Initial Condition vorticity initializer.');
            end

            bc_top = lower(char(string(app.config.bc_top)));
            bc_bottom = lower(char(string(app.config.bc_bottom)));
            bc_left = lower(char(string(app.config.bc_left)));
            bc_right = lower(char(string(app.config.bc_right)));
            is_periodic_top = contains(bc_top, 'periodic');
            is_periodic_bottom = contains(bc_bottom, 'periodic');
            is_periodic_left = contains(bc_left, 'periodic');
            is_periodic_right = contains(bc_right, 'periodic');

            if xor(is_periodic_left, is_periodic_right)
                error('Left and right boundaries must both be periodic or both non-periodic.');
            end
            if xor(is_periodic_top, is_periodic_bottom)
                error('Top and bottom boundaries must both be periodic or both non-periodic.');
            end

            bathy_entry = app.find_bathymetry_scenario_entry(app.config.bathymetry_scenario);
            bc = BCDispatcher.resolve(app.config, method_token, struct( ...
                'Lx', app.config.Lx, 'Ly', app.config.Ly, ...
                'Nx', app.config.Nx, 'Ny', app.config.Ny, ...
                'dx', app.config.dx, 'dy', app.config.dy));
            if ~bc.capability.supported
                error('%s', bc.capability.reason);
            end

            switch method_token
                case 'finite_difference'
                    if ~any(strcmp(integrator_token, {'RK4', 'FORWARD_EULER'}))
                        error('Finite Difference supports integrators: RK4 or Forward Euler.');
                    end
                case 'spectral'
                    if ~strcmp(integrator_token, 'RK4')
                        error('Spectral method supports RK4 only.');
                    end
                    if strcmpi(char(string(app.config.mode)), 'Convergence') && ~bc.method.spectral.is_periodic
                        error('Spectral convergence currently supports periodic transform families only.');
                    end
                case 'finite_volume'
                    if ~strcmp(integrator_token, 'RK3')
                        error('Finite Volume method supports RK3 only.');
                    end
                case 'shallow_water'
                    if ~strcmp(integrator_token, 'RK3')
                        error('Shallow Water supports RK3 only.');
                    end
                    if any(strcmp({app.config.bc_top_physical, app.config.bc_bottom_physical, ...
                            app.config.bc_left_physical, app.config.bc_right_physical}, 'driven'))
                        error('Shallow Water supports periodic, reflective wall, and open-absorbing boundaries only.');
                    end
                otherwise
                    error('Unsupported method token "%s".', method_token);
            end

            if is_periodic_top && abs(app.config.U_top) > 1e-12
                error('Top boundary is periodic, so U_top must be 0.');
            end
            if is_periodic_bottom && abs(app.config.U_bottom) > 1e-12
                error('Bottom boundary is periodic, so U_bottom must be 0.');
            end
            if is_periodic_left && abs(app.config.U_left) > 1e-12
                error('Left boundary is periodic, so U_left must be 0.');
            end
            if is_periodic_right && abs(app.config.U_right) > 1e-12
                error('Right boundary is periodic, so U_right must be 0.');
            end
        end

        function summary = execute_single_run(app, cfg_override)
            % Build runtime structs and dispatch one run
            if nargin < 2 || isempty(cfg_override)
                cfg_override = app.config;
            end
            cfg_override = app.normalize_workflow_launch_config(cfg_override);
            SafeConsoleIO.reset_stream_failure();
            SafeConsoleIO.push_suppression('UIController.execute_single_run');
            restore_console_output = onCleanup(@() SafeConsoleIO.pop_suppression()); %#ok<NASGU>

            app.ensure_executor_ready_for_run();
            [run_config, parameters, settings] = app.build_runtime_inputs(cfg_override);
            app.reset_live_monitor_history_for_run(cfg_override);
            app.reset_deferred_live_monitor_payloads();
            settings.ui_progress_callback = app.build_live_monitor_payload_callback(cfg_override);
            run_started = tic;
            cleanup_executor = onCleanup(@() app.teardown_current_executor('execute_single_run')); %#ok<NASGU>
            app.run_lifecycle_state = 'starting';

            % Create parallel executor for background simulation
            app.current_executor = ParallelSimulationExecutor(...
                app.build_live_monitor_payload_callback(cfg_override));

            % Start simulation in background - UI remains responsive
            app.current_executor.start(run_config, parameters, settings);
            app.run_lifecycle_state = 'running';
            if isfield(run_config, 'workflow_kind') && app.is_live_monitor_workflow_kind(run_config.workflow_kind)
                app.append_to_terminal('Phase workflow running in background via RunDispatcher...', 'info');
            else
                app.append_to_terminal('Simulation running in background...', 'info');
            end
            try
                pool = gcp('nocreate');
                if ~isempty(pool)
                    app.append_to_terminal(sprintf('Parallel pool workers: %d', pool.NumWorkers), 'info');
                end
            catch
                % Non-fatal: pool introspection is best-effort.
            end
            if isfield(settings, 'resource_allocation') && isstruct(settings.resource_allocation)
                ra = settings.resource_allocation;
                worker_req = app.pick_field(ra, {'pool_workers_requested', 'pool_workers'}, 1);
                worker_eff = app.pick_field(ra, {'pool_workers_effective', 'pool_workers'}, worker_req);
                thread_cap = app.pick_field(ra, {'thread_cap', 'max_threads'}, 1);
                gpu_eff = app.on_off(logical(app.pick_field(ra, {'gpu_enabled_effective'}, false)));
                profile_id = char(string(app.pick_field(ra, {'host_profile_id'}, 'none')));
                app.append_to_terminal(sprintf( ...
                    ['Allocator -> CPU %.0f%% | MEM %.0f%% | GPU %.0f%% | monitor %.1f Hz | ' ...
                     'progress %.1f Hz | workers %d->%d | thread cap %d | GPU eff %s | host %s'], ...
                    ra.cpu_target_pct, ra.memory_target_pct, ra.gpu_target_pct, ra.monitor_hz, ra.progress_hz, ...
                    worker_req, worker_eff, thread_cap, upper(gpu_eff), profile_id), 'info');
                note_lines = app.pick_field(ra, {'planner_notes'}, {});
                if iscell(note_lines)
                    for i_note = 1:numel(note_lines)
                        note_text = char(string(note_lines{i_note}));
                        note_cmp = lower(strtrim(note_text));
                        if isempty(note_cmp)
                            continue;
                        end
                        if contains(note_cmp, 'gpu') || contains(note_cmp, 'workers clamped') || contains(note_cmp, 'thread cap')
                            app.append_to_terminal(sprintf('Allocator note: %s', note_text), 'info');
                        end
                    end
                end
            end

            % Wait for completion (UI updates via worker DataQueue + host monitor timer)
            try
                [results, paths] = app.current_executor.wait_for_completion(@() app.flush_deferred_live_monitor_payloads());
                app.flush_deferred_live_monitor_payloads();
            catch ME
                app.run_lifecycle_state = 'tearing_down';
                app.flush_deferred_live_monitor_payloads();
                app.log_executor_failure_details(ME, cfg_override);
                rethrow(ME);
            end

            app.run_lifecycle_state = 'finalizing';
            app.set_completion_finalizing_state();

            wall = toc(run_started);

            summary = struct();
            summary.mode = cfg_override.mode;
            summary.run_config = run_config;
            summary.parameters = parameters;
            summary.settings = settings;
            summary.results = results;
            summary.paths = paths;
            summary.wall_time = wall;
            if isfield(results, 'analysis') && isstruct(results.analysis)
                summary.analysis = results.analysis;
            end

            if isfield(results, 'max_omega')
                max_omega_val = results.max_omega;
                if ~isscalar(max_omega_val)
                    max_omega_val = max(abs(max_omega_val), [], 'all', 'omitnan');
                end
                app.set_optional_label_text('metrics_vorticity', sprintf('%.3e', max_omega_val));
            end
            app.set_optional_label_text('metrics_iterations', num2str(max(1, round(cfg_override.Tfinal / max(cfg_override.dt, eps)))));
            app.set_optional_label_text('metrics_time_elapsed', sprintf('%.2f s', wall));
            app.set_optional_label_text('metrics_grid', sprintf('%dx%d', cfg_override.Nx, cfg_override.Ny));
            app.set_optional_label_text('metrics_phys_time', sprintf('%.3f s', cfg_override.Tfinal));
            summary.monitor_series = app.collect_live_monitor_series_for_summary(summary);
            try
                summary.collector_artifacts = RunCollectorCoverageComparison(summary);
                app.log_collector_artifact_status(summary.collector_artifacts);
            catch ME
                app.append_to_terminal(sprintf('Collector artifact warning: %s', ME.message), 'warning');
            end
            app.refresh_monitor_dashboard(summary, cfg_override);
            if isstruct(paths)
                app.log_resolved_output_paths(paths);
            end

            if isfield(app.handles, 'figure_selector') && isfield(paths, 'figures_evolution')
                app.append_to_terminal(sprintf('Figures: %s', char(string(paths.figures_evolution))), 'info');
            end
        end

        function log_resolved_output_paths(app, paths)
            if nargin < 2 || ~isstruct(paths) || isempty(fieldnames(paths))
                return;
            end

            output_root = app.pick_field(paths, {'output_root_resolved', 'results_root'}, '');
            base_path = app.pick_field(paths, {'base'}, '');
            data_path = app.pick_field(paths, {'data'}, '');
            figures_path = app.pick_field(paths, {'figures_root', 'figures_evolution'}, '');
            reports_path = app.pick_field(paths, {'reports'}, '');

            if strlength(string(output_root)) > 0
                app.append_to_terminal(sprintf('Output root: %s', char(string(output_root))), 'info');
            end
            if strlength(string(base_path)) > 0
                app.append_to_terminal(sprintf('Base path: %s', char(string(base_path))), 'info');
            end
            if strlength(string(data_path)) > 0
                app.append_to_terminal(sprintf('Data path: %s', char(string(data_path))), 'info');
            end
            if strlength(string(figures_path)) > 0
                app.append_to_terminal(sprintf('Figures path: %s', char(string(figures_path))), 'info');
            end
            if strlength(string(reports_path)) > 0
                app.append_to_terminal(sprintf('Reports path: %s', char(string(reports_path))), 'info');
            end

            issues = app.audit_output_paths(paths);
            for i_issue = 1:numel(issues)
                app.append_to_terminal(issues{i_issue}, 'warning');
            end
        end

        function issues = audit_output_paths(app, paths)
            issues = {};
            if nargin < 2 || ~isstruct(paths) || isempty(fieldnames(paths))
                issues{end + 1} = 'Output path audit skipped: no path metadata provided.'; %#ok<AGROW>
                return;
            end

            canonical_root = app.pick_field(paths, {'output_root_resolved', 'results_root'}, '');
            canonical_root = app.canonicalize_path_string(canonical_root);
            audit_fields = {'base', 'data', 'figures_root', 'reports'};

            for i_field = 1:numel(audit_fields)
                field_name = audit_fields{i_field};
                if ~isfield(paths, field_name) || strlength(string(paths.(field_name))) == 0
                    issues{end + 1} = sprintf('Output path audit: missing %s path.', field_name); %#ok<AGROW>
                    continue;
                end
                target = app.canonicalize_path_string(paths.(field_name));
                if strlength(string(canonical_root)) > 0 && strlength(string(target)) > 0
                    root_cmp = lower(char(string(canonical_root)));
                    target_cmp = lower(char(string(target)));
                    if ~startsWith(target_cmp, root_cmp)
                        issues{end + 1} = sprintf('Output path audit: %s is outside the canonical root -> %s', ...
                            field_name, char(string(target))); %#ok<AGROW>
                    end
                end
                if ~isfolder(char(string(target)))
                    issues{end + 1} = sprintf('Output path audit: %s directory missing -> %s', ...
                        field_name, char(string(target))); %#ok<AGROW>
                end
            end
        end

        function log_animation_export_status(app, context_label, animation_exports)
            if nargin < 3 || ~isstruct(animation_exports) || isempty(fieldnames(animation_exports))
                return;
            end
            media_status = app.pick_field(animation_exports, {'media_status'}, struct());
            if ~isstruct(media_status) || isempty(fieldnames(media_status))
                return;
            end

            requested_profile = app.format_animation_media_profile(app.pick_field(media_status, {'requested_media'}, struct()));
            retry_profile = app.format_animation_media_profile(app.pick_field(media_status, {'retry_media'}, struct()));
            if strlength(string(requested_profile)) > 0
                app.append_to_terminal(sprintf('%s requested profile: %s', ...
                    char(string(context_label)), char(string(requested_profile))), 'info');
            end

            combined_status = app.pick_field(media_status, {'combined'}, struct());
            formats = {'mp4', 'gif'};
            for i = 1:numel(formats)
                fmt = formats{i};
                status = app.pick_field(combined_status, {fmt}, struct());
                if ~isstruct(status) || isempty(fieldnames(status))
                    continue;
                end
                status_token = char(string(app.pick_field(status, {'status'}, '')));
                saved_path = char(string(app.pick_field(status, {'validated_output_path'}, '')));
                frames_written = double(app.pick_field(status, {'frames_written'}, NaN));
                retry_used = logical(app.pick_field(status, {'retry_used'}, false));
                if strcmpi(status_token, 'saved') && ~isempty(strtrim(saved_path))
                    retry_tag = '';
                    if retry_used
                        retry_tag = ' (safe retry used)';
                    end
                    app.append_to_terminal(sprintf('%s %s%s saved [%s frames]: %s', ...
                        char(string(context_label)), upper(fmt), retry_tag, ...
                        app.if_nan_num_fixed(frames_written, '%.0f'), saved_path), 'info');
                elseif strcmpi(status_token, 'failed')
                    app.append_to_terminal(sprintf('%s %s failed: %s', ...
                        char(string(context_label)), upper(fmt), ...
                        char(string(app.pick_field(status, {'failure_message'}, 'Unknown animation export failure.')))), 'warning');
                    if retry_used && strlength(string(retry_profile)) > 0
                        app.append_to_terminal(sprintf('%s %s retry profile: %s', ...
                            char(string(context_label)), upper(fmt), char(string(retry_profile))), 'info');
                    end
                end
            end

            pane_status = app.pick_field(media_status, {'panes'}, struct());
            if isstruct(pane_status) && ~isempty(fieldnames(pane_status))
                pane_tokens = fieldnames(pane_status);
                for i = 1:numel(pane_tokens)
                    token = pane_tokens{i};
                    status = app.pick_field(pane_status.(token), {'gif'}, struct());
                    if ~isstruct(status) || isempty(fieldnames(status))
                        continue;
                    end
                    status_token = char(string(app.pick_field(status, {'status'}, '')));
                    saved_path = char(string(app.pick_field(status, {'validated_output_path'}, '')));
                    frames_written = double(app.pick_field(status, {'frames_written'}, NaN));
                    if strcmpi(status_token, 'saved') && ~isempty(strtrim(saved_path))
                        app.append_to_terminal(sprintf('%s GIF [%s] saved [%s frames]: %s', ...
                            char(string(context_label)), char(string(token)), ...
                            app.if_nan_num_fixed(frames_written, '%.0f'), saved_path), 'info');
                    elseif strcmpi(status_token, 'failed')
                        app.append_to_terminal(sprintf('%s GIF [%s] failed: %s', ...
                            char(string(context_label)), char(string(token)), ...
                            char(string(app.pick_field(status, {'failure_message'}, 'Unknown animation export failure.')))), ...
                            'warning');
                    end
                end
            end

            failure_messages = app.pick_field(media_status, {'failure_messages'}, {});
            if iscell(failure_messages)
                for i = 1:numel(failure_messages)
                    app.append_to_terminal(sprintf('%s detail: %s', ...
                        char(string(context_label)), char(string(failure_messages{i}))), 'warning');
                end
            end
        end

        function text = format_animation_media_profile(app, media)
            text = '';
            if ~isstruct(media) || isempty(fieldnames(media))
                return;
            end
            resolution = [NaN, NaN];
            if isfield(media, 'resolution_px') && isnumeric(media.resolution_px) && numel(media.resolution_px) >= 2
                resolution = round(double(media.resolution_px(1:2)));
            end
            fps = NaN;
            if isfield(media, 'fps') && isnumeric(media.fps) && isscalar(media.fps)
                fps = double(media.fps);
            end
            frame_count = NaN;
            if isfield(media, 'frame_count') && isnumeric(media.frame_count) && isscalar(media.frame_count)
                frame_count = double(media.frame_count);
            end
            duration_s = NaN;
            if isfield(media, 'duration_s') && isnumeric(media.duration_s) && isscalar(media.duration_s)
                duration_s = double(media.duration_s);
            end
            quality = NaN;
            if isfield(media, 'quality') && isnumeric(media.quality) && isscalar(media.quality)
                quality = double(media.quality);
            end
            text = sprintf('%sx%s | fps=%s | frames=%s | duration=%ss | quality=%s', ...
                app.if_nan_num_fixed(resolution(1), '%.0f'), ...
                app.if_nan_num_fixed(resolution(2), '%.0f'), ...
                app.if_nan_num_fixed(fps, '%.4g'), ...
                app.if_nan_num_fixed(frame_count, '%.0f'), ...
                app.if_nan_num_fixed(duration_s, '%.4g'), ...
                app.if_nan_num_fixed(quality, '%.0f'));
        end

        function log_collector_artifact_status(app, collector_artifacts)
            if nargin < 2 || ~isstruct(collector_artifacts) || isempty(fieldnames(collector_artifacts))
                return;
            end
            workbook_path = char(string(app.pick_field(collector_artifacts, {'phase_workbook_path'}, '')));
            workbook_root_path = char(string(app.pick_field(collector_artifacts, {'phase_workbook_root_path'}, '')));
            workbook_status = char(string(app.pick_field(collector_artifacts, {'phase_workbook_status'}, '')));
            formatting_status = char(string(app.pick_field(collector_artifacts, {'phase_workbook_formatting_status'}, '')));
            if ~isempty(strtrim(workbook_path))
                app.append_to_terminal(sprintf('Sustainability workbook (%s, %s): %s', ...
                    app.if_empty(workbook_status, 'created'), ...
                    app.if_empty(formatting_status, 'unstyled'), ...
                    workbook_path), 'info');
            end
            if ~isempty(strtrim(workbook_root_path))
                app.append_to_terminal(sprintf('Sustainability workbook mirror: %s', workbook_root_path), 'info');
            end
            if isfield(collector_artifacts, 'artifact_failures') && isstruct(collector_artifacts.artifact_failures)
                for i = 1:numel(collector_artifacts.artifact_failures)
                    app.append_to_terminal(sprintf('Collector artifact warning [%s]: %s', ...
                        char(string(app.pick_field(collector_artifacts.artifact_failures(i), {'artifact'}, 'artifact'))), ...
                        char(string(app.pick_field(collector_artifacts.artifact_failures(i), {'message'}, 'Unknown artifact failure.')))), ...
                        'warning');
                end
            end
        end

        function emit_launch_context_banner(app, cfg)
            launch_origin = char(string(app.pick_field(cfg, {'launch_origin'}, 'launch_button')));
            if strcmpi(launch_origin, 'phase_button')
                phase_label = char(string(app.pick_field(cfg, {'phase_label'}, 'Phase Workflow')));
                app.append_to_terminal(sprintf('Starting %s through the standard launch architecture...', phase_label), 'info');
                if strcmpi(char(string(app.pick_field(cfg, {'workflow_kind'}, ''))), 'mesh_convergence_study')
                    app.append_to_terminal(sprintf('Mesh convergence IC: %s', char(string(app.pick_field(cfg, {'ic_type'}, '')))), 'info');
                    app.append_to_terminal('Mesh convergence queue: FD sweep -> Spectral sweep', 'info');
                    app.append_to_terminal('Mesh convergence policy: dedicated 8-level periodic mesh ladder study.', 'info');
                    app.set_ic_preview_export_status('Mesh convergence workflow running...', app.layout_cfg.colors.accent_cyan);
                elseif strcmpi(char(string(app.pick_field(cfg, {'workflow_kind'}, ''))), 'phase1_periodic_comparison')
                    app.append_to_terminal(sprintf('Phase 1 IC: %s', char(string(app.pick_field(cfg, {'ic_type'}, '')))), 'info');
                    app.append_to_terminal('Phase 1 queue: FD Evolution -> Spectral Evolution -> IC study jobs', 'info');
                    app.append_to_terminal('Phase 1 overrides: BC=periodic all sides | bathymetry=flat_2d | methods=FD + Spectral', 'info');
                    app.set_ic_preview_export_status('Phase 1 workflow running...', app.layout_cfg.colors.accent_cyan);
                elseif strcmpi(char(string(app.pick_field(cfg, {'workflow_kind'}, ''))), 'phase2_boundary_condition_study')
                    app.append_to_terminal(sprintf('Phase 2 IC: %s', char(string(app.pick_field(cfg, {'ic_type'}, '')))), 'info');
                    app.append_to_terminal('Phase 2 queue: Enclosed Driven Cavity -> Driven Channel Flow -> Enclosed Shear Layer', 'info');
                    app.append_to_terminal('Phase 2 policy: FD-only wall-bounded scenario study.', 'info');
                    app.set_ic_preview_export_status('Phase 2 workflow running...', app.layout_cfg.colors.accent_cyan);
                elseif strcmpi(char(string(app.pick_field(cfg, {'workflow_kind'}, ''))), 'phase3_bathymetry_study')
                    app.append_to_terminal(sprintf('Phase 3 IC: %s', char(string(app.pick_field(cfg, {'ic_type'}, '')))), 'info');
                    app.append_to_terminal('Phase 3 queue: Simple Default Bathymetry -> Composite Tsunami Run-up -> Tohoku Profile', 'info');
                    app.append_to_terminal('Phase 3 policy: enclosed-shear bathymetry study with FD + Spectral immersed-mask comparison.', 'info');
                    app.set_ic_preview_export_status('Phase 3 workflow running...', app.layout_cfg.colors.accent_cyan);
                end
            end
        end

        function normalized = canonicalize_path_string(~, raw_path)
            normalized = char(string(raw_path));
            if isempty(strtrim(normalized))
                normalized = '';
                return;
            end
            normalized = char(string(normalized));
            try
                normalized = char(java.io.File(normalized).getCanonicalPath());
            catch
                try
                    normalized = char(string(fullfile(normalized)));
                catch
                    normalized = char(string(raw_path));
                end
            end
        end

        function cancel_simulation(app)
            % Cancel currently running simulation
            if ~isempty(app.current_executor)
                app.append_to_terminal('Cancelling simulation...', 'warning');
                app.stop_executor_completion_timer();
                app.pending_launch_request = struct();
                app.active_launch_context = struct();
                app.teardown_current_executor('cancel request');
                app.close_launch_progress_dialog();
                app.set_run_state('idle', 'Cancelled');
                app.append_to_terminal('Simulation cancelled by user', 'warning');
            else
                app.append_to_terminal('No simulation is currently running', 'info');
            end
        end

        function summary = execute_experimentation_sweep(app)
            % Experimentation mode: coefficient sweep over repeated Evolution runs
            base_cfg = app.config;
            idx = find(strcmp({'ic_coeff1', 'ic_coeff2', 'ic_coeff3', 'ic_coeff4'}, base_cfg.experimentation.coeff_selector), 1);
            if isempty(idx)
                idx = 1;
            end

            values = linspace(base_cfg.experimentation.range_start, ...
                              base_cfg.experimentation.range_end, ...
                              max(2, base_cfg.experimentation.num_points));
            max_omega_values = zeros(size(values));
            run_ids = strings(size(values));

            app.append_to_terminal(sprintf('Experimentation sweep on %s with %d points', ...
                base_cfg.experimentation.coeff_selector, numel(values)), 'info');

            for k = 1:numel(values)
                cfg_k = base_cfg;
                coeffs = [cfg_k.ic_coeff1, cfg_k.ic_coeff2, cfg_k.ic_coeff3, cfg_k.ic_coeff4];
                coeffs(idx) = values(k);
                cfg_k.ic_coeff1 = coeffs(1);
                cfg_k.ic_coeff2 = coeffs(2);
                cfg_k.ic_coeff3 = coeffs(3);
                cfg_k.ic_coeff4 = coeffs(4);
                cfg_k.ic_coeff = app.build_ic_coeff_vector(cfg_k.ic_type, coeffs);

                app.append_to_terminal(sprintf('Experiment %d/%d: %s=%.4g', ...
                    k, numel(values), base_cfg.experimentation.coeff_selector, values(k)), 'info');

                run_summary = app.execute_single_run(cfg_k);
                if isfield(run_summary.results, 'max_omega')
                    max_omega_values(k) = run_summary.results.max_omega;
                else
                    max_omega_values(k) = NaN;
                end
                if isfield(run_summary.results, 'run_id')
                    run_ids(k) = string(run_summary.results.run_id);
                end
            end

            summary = struct();
            summary.mode = 'experimentation';
            summary.coeff_name = base_cfg.experimentation.coeff_selector;
            summary.values = values;
            summary.max_omega = max_omega_values;
            summary.run_ids = run_ids;
            summary.paths = struct();
            summary.results = struct('max_omega', max(max_omega_values, [], 'omitnan'));
            summary.wall_time = NaN;

            lines = {'Experimentation sweep complete:'};
            for k = 1:numel(values)
                lines{end+1} = sprintf('  %s=%.4g -> max|omega|=%.4e', ...
                    base_cfg.experimentation.coeff_selector, values(k), max_omega_values(k)); %#ok<AGROW>
            end
            if isfield(app.handles, 'metrics_text') && isvalid(app.handles.metrics_text)
                app.handles.metrics_text.Value = lines;
            end
        end

