            if ~isfield(cfg, 'bathymetry_relief_amplitude') || ~isfinite(cfg.bathymetry_relief_amplitude), cfg.bathymetry_relief_amplitude = 180.0; end
            if ~isfield(cfg, 'bathymetry_resolution') || ~isfinite(cfg.bathymetry_resolution), cfg.bathymetry_resolution = app.get_bathymetry_resolution(); end
            if ~isfield(cfg, 'bathymetry_custom_points') || isempty(cfg.bathymetry_custom_points)
                cfg.bathymetry_custom_points = app.get_bathymetry_control_points();
