        function mesh_sizes = build_mesh_sizes(~, n_coarse, n_max)
            n0 = max(8, round(n_coarse));
            nmax = max(n0, round(n_max));
            mesh_sizes = n0;
            n = n0;
            while n < nmax
                n = min(nmax, 2 * n);
                mesh_sizes(end+1) = n; %#ok<AGROW>
            end
            mesh_sizes = unique(mesh_sizes, 'stable');
        end

        function values = parse_numeric_csv(~, txt)
            if iscell(txt)
                txt = strjoin(string(txt), ' ');
            end
            if isstring(txt)
                txt = char(txt);
            end
            if isempty(txt)
                values = [];
                return;
            end
            parts = regexp(txt, '[,;\s]+', 'split');
            parts = parts(~cellfun(@isempty, parts));
            values = zeros(1, numel(parts));
            for i = 1:numel(parts)
                values(i) = str2double(parts{i});
            end
            values = values(isfinite(values));
        end

        function txt = numeric_csv_string(app, values)
            if isempty(values)
                txt = '';
                return;
            end
            if isstruct(values)
                if isscalar(values)
                    candidate_keys = {'value', 'values', 'velocity_scales', 'dt_values', 'scale'};
                    resolved = false;
                    for i = 1:numel(candidate_keys)
                        key = candidate_keys{i};
                        if isfield(values, key) && (isnumeric(values.(key)) || islogical(values.(key)))
                            values = values.(key);
                            resolved = true;
                            break;
                        end
                    end
                    if ~resolved
                        txt = app.to_text(values, '');
                        return;
                    end
                else
                    txt = '';
                    return;
                end
            end
            values = double(values(:).');
            parts = arrayfun(@(v) sprintf('%.6g', v), values, 'UniformOutput', false);
            txt = strjoin(parts, ', ');
        end

        function method_token = get_dispatch_method(~, method_name)
            normalized = lower(strtrim(char(string(method_name))));
            normalized = regexprep(normalized, '[\s-]+', '_');
            switch string(normalized)
                case {"finite_difference", "fd"}
                    method_token = 'FD';
                case {"finite_volume", "fv"}
                    method_token = 'FV';
                case {"shallow_water", "swe"}
                    method_token = 'SWE';
                case {"spectral", "fft", "pseudo_spectral"}
                    method_token = 'Spectral';
                otherwise
                    method_token = 'FD';
            end
        end

        function set_run_state(app, state, status_text)
            if nargin < 3
                status_text = 'Idle';
            end
            if isfield(app.handles, 'btn_launch') && isvalid(app.handles.btn_launch)
                if strcmpi(state, 'running')
                    app.handles.btn_launch.Enable = 'on';
                    if app.active_launch_has_reached_completion()
                        app.handles.btn_launch.Text = 'Queue Launch';
                    else
                        app.handles.btn_launch.Text = 'Restart Run';
                    end
                else
                    app.handles.btn_launch.Enable = 'on';
                    app.handles.btn_launch.Text = 'Launch';
                end
            end
            if isfield(app.handles, 'run_status') && isvalid(app.handles.run_status)
                app.handles.run_status.Text = status_text;
            end
            drawnow limitrate;
        end

        function tf = is_progress_only_launch(app, cfg)
            if nargin < 2 || isempty(cfg)
                cfg = app.config;
            end
            tf = logical(app.pick_field(cfg, {'launch_progress_only'}, false));
        end

        function ensure_launch_progress_dialog(app, cfg)
            if ~app.has_valid_handle('launch_progress_strip')
                return;
            end
            if app.is_progress_only_launch(cfg)
                app.handles.launch_progress_strip.Visible = 'on';
            else
                app.handles.launch_progress_strip.Visible = 'off';
            end
        end

        function update_launch_progress_dialog(app, cfg, progress_pct, title_text, message_text)
            if ~app.is_progress_only_launch(cfg)
                return;
            end
            app.ensure_launch_progress_dialog(cfg);
            if ~app.has_valid_handle('launch_progress_strip')
                return;
            end

            if nargin < 4 || strlength(string(strtrim(title_text))) == 0
                title_text = 'Simulation Progress';
            end
            if nargin < 5 || strlength(string(strtrim(message_text))) == 0
                message_text = 'Running...';
            end

            status_text = sprintf('%s | %s', char(string(title_text)), char(string(message_text)));
            if app.has_valid_handle('launch_progress_status')
                app.handles.launch_progress_status.Text = status_text;
            end
            if isfinite(progress_pct)
                if app.has_valid_handle('launch_progress_gauge')
                    app.handles.launch_progress_gauge.Value = min(max(double(progress_pct), 0), 100);
                end
                if app.has_valid_handle('launch_progress_value')
                    app.handles.launch_progress_value.Text = sprintf('%6.2f%%', progress_pct);
                end
            else
                if app.has_valid_handle('launch_progress_value')
                    app.handles.launch_progress_value.Text = '--';
                end
            end
        end

        function close_launch_progress_dialog(app)
            if ~app.has_valid_handle('launch_progress_strip')
                return;
            end
            app.handles.launch_progress_strip.Visible = 'off';
            if app.has_valid_handle('launch_progress_gauge')
                app.handles.launch_progress_gauge.Value = 0;
            end
            if app.has_valid_handle('launch_progress_value')
                app.handles.launch_progress_value.Text = '--';
            end
            if app.has_valid_handle('launch_progress_status')
                app.handles.launch_progress_status.Text = 'Progress-only launch mode is idle.';
            end
        end

        function ensure_executor_ready_for_run(app)
            if ~strcmpi(app.run_lifecycle_state, 'idle') || ~isempty(app.current_executor)
                app.append_to_terminal('Pre-run executor reset: cleaning up stale async state.', 'warning');
                app.teardown_current_executor('pre-run reset');
            end
            if ~strcmpi(app.run_lifecycle_state, 'idle') || ~isempty(app.current_executor)
                error('UIController:StaleExecutorState', ...
                    'A previous run left asynchronous executor state behind; launch was blocked to avoid a crash-prone rerun.');
            end
        end

        function teardown_current_executor(app, reason)
            if nargin < 2 || isempty(reason)
                reason = 'teardown';
            end

            executor = app.current_executor;
            app.run_lifecycle_state = 'tearing_down';
            cleanup_ok = true;

            if ~isempty(executor)
                try
                    if isvalid(executor)
                        executor.cleanup();
                    end
                catch ME
                    cleanup_ok = false;
                    app.append_to_terminal(sprintf('Executor teardown warning (%s): %s', ...
                        char(string(reason)), ME.message), 'warning');
                end

                try
                    if isvalid(executor) && app.executor_has_live_async_state(executor)
                        cleanup_ok = false;
                    end
                catch
                    cleanup_ok = false;
                end
            end

            app.current_executor = [];
            app.run_lifecycle_state = 'idle';

            if ~cleanup_ok
                error('UIController:ExecutorTeardownIncomplete', ...
                    'Executor teardown did not fully release async state during %s.', char(string(reason)));
            end
        end

        function tf = executor_has_live_async_state(~, executor)
            tf = false;
            if isempty(executor) || ~isvalid(executor)
                return;
            end

            if isprop(executor, 'monitor_timer') && ~isempty(executor.monitor_timer)
                try
                    tf = tf || isvalid(executor.monitor_timer);
                catch
                    tf = true;
                end
            end
            if isprop(executor, 'queue_listener') && ~isempty(executor.queue_listener)
                tf = true;
            end
            if isprop(executor, 'future_obj') && ~isempty(executor.future_obj)
                tf = true;
            end
            if isprop(executor, 'progress_data_queue') && ~isempty(executor.progress_data_queue)
                tf = true;
            end
            if isprop(executor, 'is_running') && logical(executor.is_running)
                tf = true;
            end
        end

        function update_results_summary(app, summary)
            if ~isfield(app.handles, 'metrics_text') || ~isvalid(app.handles.metrics_text)
                return;
            end

            lines = {};
            lines{end+1} = sprintf('Mode: %s', char(string(summary.mode))); %#ok<AGROW>
            if isfield(summary, 'results') && isstruct(summary.results)
                if isfield(summary.results, 'run_id')
                    lines{end+1} = sprintf('Run ID: %s', char(string(summary.results.run_id))); %#ok<AGROW>
                end
                if isfield(summary.results, 'max_omega')
                    max_omega_val = summary.results.max_omega;
                    if ~isscalar(max_omega_val)
                        max_omega_val = max(abs(max_omega_val), [], 'all', 'omitnan');
                    end
                    lines{end+1} = sprintf('max|omega|: %.4e', max_omega_val); %#ok<AGROW>
                end
                if isfield(summary.results, 'wall_time')
                    lines{end+1} = sprintf('Wall time: %.2f s', summary.results.wall_time); %#ok<AGROW>
                end
            end
            if isfield(summary, 'wall_time') && isfinite(summary.wall_time)
                lines{end+1} = sprintf('Elapsed (UI): %.2f s', summary.wall_time); %#ok<AGROW>
            end
            if isfield(summary, 'paths') && isstruct(summary.paths)
                if isfield(summary.paths, 'base')
                    lines{end+1} = sprintf('Output: %s', char(string(summary.paths.base))); %#ok<AGROW>
                end
            end
            if isfield(summary, 'monitor_series') && isstruct(summary.monitor_series) && ...
                    isfield(summary.monitor_series, 'collector_status')
                status_struct = summary.monitor_series.collector_status;
                if isstruct(status_struct)
                    hwinfo_status = app.pick_field(status_struct, {'hwinfo'}, 'off');
                    icue_status = app.pick_field(status_struct, {'icue'}, 'off');
                    lines{end+1} = sprintf('Collectors: HWiNFO %s | iCUE %s', ...
                        char(string(hwinfo_status)), char(string(icue_status))); %#ok<AGROW>
                end
            end
            app.handles.metrics_text.Value = lines;
        end

        function published = publish_completed_run(app, summary_or_payload)
            published = false;
            summary = app.normalize_completion_summary(summary_or_payload);
            if isempty(summary) || ~isstruct(summary) || isempty(fieldnames(summary))
                return;
            end

            app.ensure_published_completion_registry();
            publication_key = app.resolve_completion_publication_key(summary);
            existing_idx = app.find_registered_result_entry_index(publication_key);
            if existing_idx > 0
                app.hydrate_registered_result_entry(existing_idx, summary);
                app.maybe_enqueue_completion_package_persist(existing_idx, summary);
                app.maybe_enqueue_completion_artifact_finalization(existing_idx, summary);
                app.update_results_summary(summary);
                app.select_results_tab();
                drawnow limitrate nocallbacks;
                app.maybe_emit_result_completion_line(existing_idx);
                if ~isKey(app.published_completion_keys, publication_key)
                    app.published_completion_keys(publication_key) = true;
                end
                published = true;
                return;
            end

            idx = app.register_simulation_result(summary);
            app.maybe_enqueue_completion_package_persist(idx, summary);
            app.maybe_enqueue_completion_artifact_finalization(idx, summary);
            app.update_results_summary(summary);
            app.select_results_tab();
            drawnow limitrate nocallbacks;
            if app.defer_result_autosave
                app.enqueue_post_publication_job(struct( ...
                    'scope', 'report', ...
                    'idx', idx, ...
                    'summary', summary));
            else
                app.generate_report_to_tab();
                app.select_results_tab();
            end
            app.published_completion_keys(publication_key) = true;
            if isnumeric(idx) && isfinite(idx) && idx >= 1
                app.published_completion_entry_indices(publication_key) = double(idx);
                app.maybe_emit_result_completion_line(idx);
            end
            published = true;
        end

        function published = publish_host_completion_summary(app, summary_or_payload)
            published = false;
            before_count = numel(app.session_figures);
            previous_defer_state = app.defer_result_autosave;
            restore_defer_state = onCleanup(@() app.set_result_autosave_defer_state(previous_defer_state)); %#ok<NASGU>
            arm_post_publication = onCleanup(@() app.maybe_start_post_publication_timer()); %#ok<NASGU>
            app.set_result_autosave_defer_state(true);
            summary = app.enrich_summary_from_cached_completion_payload(summary_or_payload);
            summary = app.normalize_completion_summary(summary);
            if isempty(summary) || ~isstruct(summary) || isempty(fieldnames(summary))
                return;
            end

            published = app.publish_completed_run(summary);
            if published || numel(app.session_figures) > before_count
                app.persist_completion_publication_state(summary, 'published', '');
                return;
            end

            app.ensure_published_completion_registry();
            summary_key = app.resolve_completion_publication_key(summary);
            if ~isempty(summary_key) && isKey(app.published_completion_keys, summary_key)
                published = true;
                app.persist_completion_publication_state(summary, 'published', 'duplicate completion payload');
                return;
            end

            cached_payload = app.cached_completion_report_payload;
            if isstruct(cached_payload) && ~isempty(fieldnames(cached_payload))
                cached_summary = app.normalize_completion_summary(cached_payload);
                cached_key = app.resolve_completion_publication_key(cached_summary);
                if isempty(cached_key) || ~isKey(app.published_completion_keys, cached_key)
                    try
                        published = app.publish_completed_run(cached_payload);
                    catch ME
                        app.append_to_terminal(sprintf('Completion publication retry failed: %s', ME.message), 'warning');
                    end
                else
                    published = true;
                end
            end
            if published || numel(app.session_figures) > before_count
                app.persist_completion_publication_state(summary, 'published', 'cached completion payload');
                return;
            end

            recovered_summary = app.recover_completion_summary_from_saved_artifacts(summary);
            if isstruct(recovered_summary) && ~isempty(fieldnames(recovered_summary))
                try
                    published = app.publish_completed_run(recovered_summary);
                    if published || numel(app.session_figures) > before_count
                        app.persist_completion_publication_state(recovered_summary, 'published_with_warnings', ...
                            'Recovered Results publication from saved artifacts.');
                        app.append_to_terminal('Completion publication fallback repaired the Results relay from saved artifacts.', 'warning');
                        return;
                    end
                catch ME
                    app.append_to_terminal(sprintf('Completion publication disk-recovery fallback failed: %s', ME.message), 'warning');
                end
            end

            try
                idx = app.register_simulation_result(summary);
                app.maybe_enqueue_completion_package_persist(idx, summary);
                app.update_results_summary(summary);
                app.select_results_tab();
                drawnow limitrate nocallbacks;
                app.enqueue_post_publication_job(struct( ...
                    'scope', 'report', ...
                    'summary', summary));
                if ~isempty(summary_key)
                    app.published_completion_keys(summary_key) = true;
                end
                published = numel(app.session_figures) > before_count;
                if published
                    app.persist_completion_publication_state(summary, 'published_with_warnings', ...
                        'Recovered Results publication from the host fallback path.');
                    app.append_to_terminal('Completion publication fallback repaired the Results relay.', 'warning');
                end
                return;
            catch ME
                app.persist_completion_publication_state(summary, 'failed', ME.message);
                app.append_to_terminal(sprintf('Completion publication fallback failed: %s', ME.message), 'error');
            end
        end

        function set_result_autosave_defer_state(app, tf)
            app.defer_result_autosave = logical(tf);
        end

        function select_results_tab(app)
            if isprop(app, 'tab_group') && ~isempty(app.tab_group) && isvalid(app.tab_group) && ...
                    isprop(app, 'tabs') && isstruct(app.tabs) && isfield(app.tabs, 'results') && ...
                    ~isempty(app.tabs.results) && isvalid(app.tabs.results)
                app.tab_group.SelectedTab = app.tabs.results;
            end
        end

        function idx = find_registered_result_entry_index(app, publication_key)
            idx = 0;
            if nargin < 2 || strlength(string(strtrim(publication_key))) == 0
                return;
            end
            app.ensure_published_completion_registry();
            if isKey(app.published_completion_entry_indices, publication_key)
                candidate = double(app.published_completion_entry_indices(publication_key));
                if isfinite(candidate) && candidate >= 1 && candidate <= numel(app.session_figures)
                    idx = candidate;
                    return;
                end
            end
            for i = 1:numel(app.session_figures)
                if isfield(app.session_figures(i), 'publication_key') && ...
                        strcmp(char(string(app.session_figures(i).publication_key)), char(string(publication_key)))
                    idx = i;
                    app.published_completion_entry_indices(publication_key) = double(i);
                    return;
                end
            end
        end

        function remember_registered_result_entry(app, idx, publication_key)
            if nargin < 3 || strlength(string(strtrim(publication_key))) == 0 || ...
                    ~isfinite(idx) || idx < 1 || idx > numel(app.session_figures)
                return;
            end
            app.ensure_published_completion_registry();
            app.session_figures(idx).publication_key = char(string(publication_key));
            app.published_completion_entry_indices(publication_key) = double(idx);
        end

        function hydrate_registered_result_entry(app, idx, summary)
            if nargin < 3 || ~isstruct(summary) || ~isfinite(idx) || idx < 1 || idx > numel(app.session_figures)
                return;
            end
            entry = app.session_figures(idx);
            [entry, meta, analysis, results, params, run_cfg, artifacts, monitor_series_entry] = ...
                app.build_result_entry_from_summary(summary, idx);
            entry.analysis = analysis;
            entry.results = results;
            entry.parameters = params;
            entry.run_config = run_cfg;
            entry.metadata = meta;
            entry.monitor_series = monitor_series_entry;
            entry.artifacts = app.merge_result_entry_artifacts(entry.artifacts, artifacts);
            entry.launch_origin = char(string(app.pick_field(run_cfg, {'launch_origin'}, entry.launch_origin)));
            entry.result_layout_kind = char(string(app.resolve_result_layout_kind(summary, results, run_cfg)));
            if isfield(summary, 'results') && isstruct(summary.results) && isfield(summary.results, 'workflow_kind')
                entry.workflow_kind = char(string(summary.results.workflow_kind));
            end
            switch lower(char(string(entry.result_layout_kind)))
                case 'mesh_convergence_workflow'
                    entry.workflow = app.build_phase1_workflow_model(results);
                    entry.workflow_kind = 'mesh_convergence_study';
                case 'phase1_workflow'
                    entry.workflow = app.build_phase1_workflow_model(results);
                    entry.workflow_kind = 'phase1_periodic_comparison';
                case 'phase2_workflow'
                    entry.workflow = app.build_phase2_workflow_model(results);
                    entry.workflow_kind = 'phase2_boundary_condition_study';
                case 'phase3_workflow'
                    entry.workflow = app.build_phase3_workflow_model(results);
                    entry.workflow_kind = 'phase3_bathymetry_study';
            end
            if isempty(strtrim(char(string(entry.publication_key))))
                entry.publication_key = app.resolve_completion_publication_key(summary);
            end
            entry.hydration_state = 'hydrated';
            if isempty(strtrim(char(string(entry.publication_state))))
                entry.publication_state = 'published';
            end
            if isempty(strtrim(char(string(entry.post_publication_state))))
                entry.post_publication_state = 'pending';
            end
            app.session_figures(idx) = entry;
            app.refresh_registered_result_entry_tab(idx);
            app.remember_registered_result_entry(idx, entry.publication_key);
        end

        function finalize_result_registration_ui(app, idx, tab)
            if nargin < 2 || ~isscalar(idx) || idx < 1 || idx > numel(app.session_figures)
                return;
            end
            app.refresh_session_figure_dropdown();
            app.update_result_identifier_tags(idx);
            app.update_metrics_summary(idx);
            app.update_result_entry_status_badge(idx);
            if nargin >= 3 && ~isempty(tab) && isvalid(tab) && ...
                    isfield(app.handles, 'figure_tabs') && ~isempty(app.handles.figure_tabs) && ...
                    isvalid(app.handles.figure_tabs)
                app.handles.figure_tabs.SelectedTab = tab;
            end
            app.select_results_tab();
            drawnow limitrate nocallbacks;
        end

        function update_result_entry_status_badge(app, idx)
            if nargin < 2 || ~isscalar(idx) || idx < 1 || idx > numel(app.session_figures)
                return;
            end
            entry = app.session_figures(idx);
            plot_tabs = app.pick_field(entry, {'plot_tabs'}, struct());
            status_label = app.pick_field(plot_tabs, {'status_label'}, []);
            if isempty(status_label) || ~isvalid(status_label)
                return;
            end

            publication_state = lower(char(string(app.pick_field(entry, {'publication_state'}, 'published'))));
            hydration_state = lower(char(string(app.pick_field(entry, {'hydration_state'}, 'hydrated'))));
            post_state = lower(char(string(app.pick_field(entry, {'post_publication_state'}, 'pending'))));

            status_text = 'Published';
            bg_color = [0.76 0.89 0.78];
            fg_color = [0.08 0.08 0.08];
            if strcmp(post_state, 'saving_in_background')
                status_text = 'Saving visuals...';
                bg_color = [0.97 0.85 0.54];
            elseif strcmp(post_state, 'completed')
                status_text = 'Exports complete';
                bg_color = [0.76 0.89 0.78];
            elseif strcmp(post_state, 'completed_with_warnings')
                status_text = 'Exports warned';
                bg_color = [0.95 0.72 0.48];
            elseif strcmp(hydration_state, 'shell')
                status_text = 'Hydrating...';
                bg_color = [0.72 0.84 0.97];
            elseif strcmp(publication_state, 'failed')
                status_text = 'Publication failed';
                bg_color = [0.92 0.55 0.55];
            end

            status_label.Text = status_text;
            if isprop(status_label, 'BackgroundColor')
                status_label.BackgroundColor = bg_color;
            end
            if isprop(status_label, 'FontColor')
                status_label.FontColor = fg_color;
            end
        end

        function run_or_defer_registered_result_autosave(app, idx, summary, autosave_scope)
            if nargin < 4 || isempty(autosave_scope)
                autosave_scope = 'session';
            end
            if nargin < 3 || ~isstruct(summary)
                summary = struct();
            end
            if nargin < 2 || ~isscalar(idx) || idx < 1 || idx > numel(app.session_figures)
                return;
            end

            if app.defer_result_autosave
                app.session_figures(idx).post_publication_state = 'saving_in_background';
                app.update_result_entry_status_badge(idx);
                app.enqueue_post_publication_job(struct( ...
                    'scope', char(string(autosave_scope)), ...
                    'idx', idx, ...
                    'summary', summary));
                app.append_to_terminal('Results tab published; save/export verification is continuing in the background.', 'info');
                return;
            end

            app.session_figures(idx).post_publication_state = 'saving_in_background';
            app.update_result_entry_status_badge(idx);
            app.execute_post_publication_job(struct( ...
                'scope', char(string(autosave_scope)), ...
                'idx', idx, ...
                'summary', summary));
        end

        function maybe_enqueue_completion_package_persist(app, idx, summary)
            if nargin < 3 || ~isstruct(summary) || ~isscalar(idx) || idx < 1 || idx > numel(app.session_figures)
                return;
            end
            if isfield(summary, 'completion_results_already_persisted') && ...
                    logical(summary.completion_results_already_persisted)
                if ~isfield(app.session_figures(idx), 'artifacts') || ~isstruct(app.session_figures(idx).artifacts)
                    app.session_figures(idx).artifacts = struct();
                end
                app.session_figures(idx).artifacts.final_results_package_state = 'completed';
                return;
            end

            results = app.pick_field(summary, {'results'}, struct());
            paths = app.pick_field(summary, {'paths'}, struct());
            if ~isstruct(results) || isempty(fieldnames(results)) || ~isstruct(paths) || isempty(fieldnames(paths))
                return;
            end

            if ~isfield(app.session_figures(idx), 'artifacts') || ~isstruct(app.session_figures(idx).artifacts)
                app.session_figures(idx).artifacts = struct();
            end
            persist_state = lower(char(string(app.pick_field(app.session_figures(idx).artifacts, ...
                {'final_results_package_state'}, 'pending'))));
            if any(strcmp(persist_state, {'queued', 'running', 'completed'}))
                return;
            end

            app.session_figures(idx).artifacts.final_results_package_state = 'queued';
            if strcmpi(char(string(app.pick_field(app.session_figures(idx), {'post_publication_state'}, 'pending'))), 'pending')
                app.session_figures(idx).post_publication_state = 'saving_in_background';
            end
            app.update_result_entry_status_badge(idx);
            app.enqueue_post_publication_job(struct( ...
                'scope', 'persist_completion_package', ...
                'idx', idx, ...
                'summary', summary), true);
        end

        function maybe_enqueue_completion_artifact_finalization(app, idx, summary)
            if nargin < 3 || ~isstruct(summary) || ~isscalar(idx) || idx < 1 || idx > numel(app.session_figures)
                return;
            end
            if ~app.summary_requires_deferred_artifact_finalization(summary)
                return;
            end
            if ~isfield(app.session_figures(idx), 'artifacts') || ~isstruct(app.session_figures(idx).artifacts)
                app.session_figures(idx).artifacts = struct();
            end
            finalize_state = lower(char(string(app.pick_field(app.session_figures(idx).artifacts, ...
                {'artifact_finalization_state'}, 'pending'))));
            if any(strcmp(finalize_state, {'queued', 'running', 'completed'}))
                return;
            end
            app.session_figures(idx).artifacts.artifact_finalization_state = 'queued';
            if strcmpi(char(string(app.pick_field(app.session_figures(idx), {'post_publication_state'}, 'pending'))), 'pending')
                app.session_figures(idx).post_publication_state = 'saving_in_background';
            end
            app.update_result_entry_status_badge(idx);
            app.enqueue_post_publication_job(struct( ...
                'scope', 'complete_run_artifacts', ...
                'idx', idx, ...
                'summary', summary));
        end

        function enqueue_result_entry_hydration(app, idx, summary)
            if nargin < 3 || ~isstruct(summary) || ~isscalar(idx) || idx < 1 || idx > numel(app.session_figures)
                return;
            end
            hydration_state = lower(char(string(app.pick_field(app.session_figures(idx), {'hydration_state'}, 'hydrated'))));
            if ~strcmp(hydration_state, 'shell')
                return;
            end
            app.enqueue_post_publication_job(struct( ...
                'scope', 'hydrate_result_entry', ...
                'idx', idx, ...
                'summary', summary), true);
        end

        function tf = workflow_shell_registration_requested(app, summary)
            tf = logical(app.defer_result_autosave);
            if ~tf || nargin < 2 || ~isstruct(summary)
                return;
            end
            import_markers = {'imported_name', 'imported_results', 'imported_analysis', 'imported_metadata'};
            for i = 1:numel(import_markers)
                key = import_markers{i};
                if isfield(summary, key) && ~isempty(summary.(key))
                    tf = false;
                    return;
                end
            end
        end

        function tf = summary_requires_deferred_artifact_finalization(app, summary) %#ok<INUSL>
            tf = false;
            if nargin < 2 || ~isstruct(summary)
                return;
            end
            results = app.pick_field(summary, {'results'}, struct());
            artifacts = app.pick_field(results, {'artifacts'}, struct());
            finalization_scope = lower(char(string(app.pick_field(artifacts, {'finalization_scope'}, ''))));
            deferred_rich_artifacts = logical(app.pick_field(artifacts, {'deferred_rich_artifacts'}, false));
            tf = deferred_rich_artifacts || strcmp(finalization_scope, 'minimal');
        end

        function enqueue_post_publication_job(app, job, prepend)
            if nargin < 2 || ~isstruct(job)
                return;
            end
            if nargin < 3
                prepend = false;
            end
            if ~iscell(app.pending_post_publication_jobs)
                app.pending_post_publication_jobs = {};
            end
            if logical(prepend)
                app.pending_post_publication_jobs = [{job}, app.pending_post_publication_jobs];
            else
                app.pending_post_publication_jobs{end + 1} = job;
            end
        end

        function maybe_start_post_publication_timer(app)
            if app.is_draining_post_publication_jobs
                return;
            end
            if (~iscell(app.pending_post_publication_jobs) || isempty(app.pending_post_publication_jobs)) && ...
                    isempty(app.active_post_publication_worker_job)
                return;
            end
            app.start_post_publication_timer();
        end

        function start_post_publication_timer(app)
            if ~isempty(app.post_publication_timer)
                try
                    if isvalid(app.post_publication_timer) && strcmpi(char(string(app.post_publication_timer.Running)), 'on')
                        return;
                    end
                catch
                end
            end

            app.safe_stop_timer('post_publication_timer');
            app.post_publication_timer = timer( ...
                'ExecutionMode', 'fixedSpacing', ...
                'BusyMode', 'drop', ...
                'Period', 0.10, ...
                'TimerFcn', {@ui_controller_timer_flush_post_publication_queue, app, 'timer'});
            start(app.post_publication_timer);
        end

        function flush_post_publication_queue(app, reason)
            if nargin < 2 || strlength(string(reason)) == 0
                reason = 'manual';
            end
            blocking_reason = any(strcmpi(char(string(reason)), {'test', 'ui cleanup', 'ui delete'}));
            if blocking_reason
                app.safe_stop_timer('post_publication_timer');
                while app.post_publication_queue_has_pending_work()
                    app.run_single_post_publication_queue_cycle(reason);
                    pause(0.05);
                    drawnow limitrate nocallbacks;
                end
                app.safe_stop_timer('post_publication_timer');
                return;
            end

            app.run_single_post_publication_queue_cycle(reason);
            if app.post_publication_queue_has_pending_work()
                app.start_post_publication_timer();
            else
                app.safe_stop_timer('post_publication_timer');
            end
        end

        function reset_post_publication_queue_state(app)
            app.is_draining_post_publication_jobs = false;
        end

        function tf = post_publication_queue_has_pending_work(app)
            tf = (iscell(app.pending_post_publication_jobs) && ~isempty(app.pending_post_publication_jobs)) || ...
                ~isempty(app.active_post_publication_worker_job);
        end

        function run_single_post_publication_queue_cycle(app, reason)
            if nargin < 2 || strlength(string(reason)) == 0
                reason = 'manual';
            end
            if app.is_draining_post_publication_jobs
                return;
            end
            if ~app.post_publication_queue_has_pending_work()
                return;
            end

            app.is_draining_post_publication_jobs = true;
            reset_guard = onCleanup(@() app.reset_post_publication_queue_state()); %#ok<NASGU>

            if ~isempty(app.active_post_publication_worker_job)
                app.poll_active_post_publication_worker(reason);
                if ~isempty(app.active_post_publication_worker_job)
                    return;
                end
            end

            if ~iscell(app.pending_post_publication_jobs) || isempty(app.pending_post_publication_jobs)
                return;
            end

            job = app.pending_post_publication_jobs{1};
            if numel(app.pending_post_publication_jobs) == 1
                app.pending_post_publication_jobs = {};
            else
                app.pending_post_publication_jobs(1) = [];
            end

            if app.post_publication_job_prefers_worker(job) && app.start_post_publication_worker_job(job)
                return;
            end

            try
                app.execute_post_publication_job(job);
            catch ME
                app.handle_post_publication_job_failure(job, ME, reason);
            end
        end

        function tf = post_publication_job_prefers_worker(~, job)
            tf = false;
            if nargin < 2 || ~isstruct(job)
                return;
            end
            scope = lower(char(string(job.scope)));
            tf = any(strcmp(scope, {'persist_completion_package', 'complete_run_artifacts'}));
        end

        function tf = start_post_publication_worker_job(app, job)
            tf = false;
            if nargin < 2 || ~isstruct(job) || ~app.post_publication_job_prefers_worker(job)
                return;
            end
            if ~isempty(app.active_post_publication_worker_job)
                return;
            end

            repo_root = pwd;
            try
                if exist('PathBuilder', 'class') == 8 || exist('PathBuilder', 'file') == 2
                    repo_root = PathBuilder.get_repo_root();
                end
            catch
            end
            additional_paths = app.build_post_publication_worker_additional_paths(repo_root);
            sanitized_job = filter_graphics_objects(job);
            sanitized_job.worker_repo_root = repo_root;
            try
                for path_idx = 1:numel(additional_paths)
                    addpath(additional_paths{path_idx});
                end
                app.active_post_publication_worker_job = parfeval(backgroundPool, ...
                    @run_post_publication_worker_job, 1, sanitized_job);
                app.active_post_publication_worker_payload = sanitized_job;
                idx = double(app.pick_field(sanitized_job, {'idx'}, NaN));
                if isfinite(idx) && idx >= 1 && idx <= numel(app.session_figures)
                    switch lower(char(string(app.pick_field(sanitized_job, {'scope'}, ''))))
                        case 'persist_completion_package'
                            app.session_figures(idx).artifacts.final_results_package_worker_state = 'running';
                        case 'complete_run_artifacts'
                            app.session_figures(idx).artifacts.artifact_finalization_worker_state = 'running';
                    end
                    app.update_result_entry_status_badge(idx);
                end
                tf = true;
                app.append_to_terminal(sprintf('Background export worker started: %s.', ...
                    app.describe_post_publication_scope(sanitized_job)), 'info');
            catch ME
                app.active_post_publication_worker_job = [];
                app.active_post_publication_worker_payload = struct();
                app.handle_post_publication_job_failure(sanitized_job, ME, 'worker-start');
                app.append_to_terminal(sprintf('Background export worker warning: %s. Host-thread fallback suppressed to keep the UI responsive.', ...
                    ME.message), 'warning');
                tf = true;
            end
        end

        function poll_active_post_publication_worker(app, reason)
            if nargin < 2 || strlength(string(reason)) == 0
                reason = 'timer';
            end
            worker_job = app.active_post_publication_worker_job;
            if isempty(worker_job)
                return;
            end

            job_payload = app.active_post_publication_worker_payload;
            try
                state = lower(char(string(worker_job.State)));
            catch
                state = '';
            end
            switch state
                case {'queued', 'running'}
                    return;
                case 'finished'
                    try
                        worker_result = fetchOutputs(worker_job);
                        if iscell(worker_result)
                            if isempty(worker_result)
                                worker_result = struct();
                            else
                                worker_result = worker_result{1};
                            end
                        end
                    catch ME
                        worker_result = struct( ...
                            'ok', false, ...
                            'scope', app.pick_field(job_payload, {'scope'}, ''), ...
                            'error_identifier', char(string(ME.identifier)), ...
                            'error_message', char(string(ME.message)), ...
                            'artifact_summary', struct());
                    end
                    app.close_active_post_publication_worker_job();
                    app.apply_completed_post_publication_worker_result(job_payload, worker_result);
                case 'failed'
                    failure_message = 'Background export worker failed.';
                    failure_identifier = 'UIController:PostPublicationWorkerFailed';
                    try
                        if isprop(worker_job, 'Error') && ~isempty(worker_job.Error)
                            failure_message = char(string(worker_job.Error.message));
                            failure_identifier = char(string(worker_job.Error.identifier));
                        elseif isprop(worker_job, 'Tasks') && ~isempty(worker_job.Tasks) && ~isempty(worker_job.Tasks(1).Error)
                            failure_message = char(string(worker_job.Tasks(1).Error.message));
                            failure_identifier = char(string(worker_job.Tasks(1).Error.identifier));
                        end
                    catch
                    end
                    app.close_active_post_publication_worker_job();
                    app.handle_post_publication_job_failure(job_payload, ...
                        MException(failure_identifier, failure_message), reason);
                otherwise
                    app.close_active_post_publication_worker_job();
                    app.handle_post_publication_job_failure(job_payload, ...
                        MException('UIController:UnknownPostPublicationWorkerState', ...
                        sprintf('Background export worker entered an unexpected state: %s', state)), reason);
            end
        end

        function close_active_post_publication_worker_job(app)
            worker_job = app.active_post_publication_worker_job;
            app.active_post_publication_worker_job = [];
            app.active_post_publication_worker_payload = struct();
            if isempty(worker_job)
                return;
            end
            try
                cancel(worker_job);
            catch
            end
            try
                delete(worker_job);
            catch
            end
        end

        function apply_completed_post_publication_worker_result(app, job, worker_result)
            if nargin < 3 || ~isstruct(worker_result)
                worker_result = struct();
            end
            if ~logical(app.pick_field(worker_result, {'ok'}, false))
                identifier = char(string(app.pick_field(worker_result, {'error_identifier'}, ...
                    'UIController:PostPublicationWorkerFailed')));
                message = char(string(app.pick_field(worker_result, {'error_message'}, ...
                    'Background export worker failed without a captured message.')));
                app.handle_post_publication_job_failure(job, MException(identifier, message), 'worker');
                return;
            end

            idx = double(app.pick_field(job, {'idx'}, NaN));
            scope = lower(char(string(app.pick_field(job, {'scope'}, ''))));
            if isfinite(idx) && idx >= 1 && idx <= numel(app.session_figures)
                switch scope
                    case 'persist_completion_package'
                        app.session_figures(idx).artifacts.final_results_package_state = 'completed';
                        app.session_figures(idx).artifacts.final_results_package_worker_state = 'completed';
                    case 'complete_run_artifacts'
                        app.session_figures(idx).artifacts.artifact_finalization_state = 'completed';
                        app.session_figures(idx).artifacts.artifact_finalization_worker_state = 'completed';
                        artifact_summary = app.pick_field(worker_result, {'artifact_summary'}, struct());
                        app.session_figures(idx).artifacts = app.merge_result_entry_artifacts( ...
                            app.session_figures(idx).artifacts, artifact_summary);
                end
                if strcmpi(char(string(app.pick_field(app.session_figures(idx), {'post_publication_state'}, 'pending'))), 'pending') && ...
                        ~app.has_pending_post_publication_jobs_for_entry(idx)
                    app.session_figures(idx).post_publication_state = 'completed';
                end
                app.update_result_entry_status_badge(idx);
                app.maybe_emit_result_completion_line(idx);
            end
            app.append_to_terminal(sprintf('Background export worker completed: %s.', ...
                app.describe_post_publication_scope(job)), 'info');
        end

        function handle_post_publication_job_failure(app, job, ME, reason)
            idx = double(app.pick_field(job, {'idx'}, NaN));
            if isfinite(idx) && idx >= 1 && idx <= numel(app.session_figures)
                app.session_figures(idx).post_publication_state = 'completed_with_warnings';
                if strcmpi(char(string(app.pick_field(job, {'scope'}, ''))), 'persist_completion_package')
                    app.session_figures(idx).artifacts.final_results_package_state = 'failed';
                    app.session_figures(idx).artifacts.final_results_package_worker_state = 'failed';
                    app.session_figures(idx).artifacts.final_results_package_error = ME.message;
                elseif strcmpi(char(string(app.pick_field(job, {'scope'}, ''))), 'complete_run_artifacts')
                    app.session_figures(idx).artifacts.artifact_finalization_state = 'failed';
                    app.session_figures(idx).artifacts.artifact_finalization_worker_state = 'failed';
                    app.session_figures(idx).artifacts.artifact_finalization_error = ME.message;
                end
                app.update_result_entry_status_badge(idx);
                app.maybe_emit_result_completion_line(idx);
            end
            app.append_to_terminal(sprintf('Post-publication autosave warning (%s): %s', ...
                char(string(reason)), ME.message), 'warning');
        end

        function label = describe_post_publication_scope(~, job)
            label = 'post-publication work';
            if isstruct(job) && isfield(job, 'scope') && ~isempty(job.scope)
                label = char(string(job.scope));
            end
            switch lower(label)
                case 'persist_completion_package'
                    label = 'final results package persistence';
                case 'complete_run_artifacts'
                    label = 'run artifact finalization';
                case 'report'
                    label = 'interactive report generation';
                case 'session'
                    label = 'results export bundle';
                case 'workflow'
                    label = 'workflow export bundle';
            end
        end

        function additional_paths = build_post_publication_worker_additional_paths(~, repo_root)
            additional_paths = {};
            if nargin < 2 || ~(ischar(repo_root) || isstring(repo_root))
                return;
            end
            path_blob = genpath(char(string(fullfile(repo_root, 'Scripts'))));
            if exist(fullfile(repo_root, 'utilities'), 'dir') == 7
                path_blob = [path_blob, pathsep, fullfile(repo_root, 'utilities')];
            end
            raw_paths = regexp(path_blob, pathsep, 'split');
            raw_paths = raw_paths(~cellfun(@isempty, raw_paths));
            additional_paths = raw_paths(:).';
        end

        function tf = has_pending_post_publication_jobs_for_entry(app, idx)
            tf = false;
            if nargin < 2 || ~isscalar(idx) || idx < 1
                return;
            end
            if isstruct(app.active_post_publication_worker_payload) && ~isempty(fieldnames(app.active_post_publication_worker_payload))
                active_idx = double(app.pick_field(app.active_post_publication_worker_payload, {'idx'}, NaN));
                if isfinite(active_idx) && active_idx == idx
                    tf = true;
                    return;
                end
            end
            if iscell(app.pending_post_publication_jobs)
                for i = 1:numel(app.pending_post_publication_jobs)
                    job = app.pending_post_publication_jobs{i};
                    if ~isstruct(job)
                        continue;
                    end
                    job_idx = double(app.pick_field(job, {'idx'}, NaN));
                    if isfinite(job_idx) && job_idx == idx
                        tf = true;
                        return;
                    end
                end
            end
        end

        function maybe_emit_result_completion_line(app, idx)
            if nargin < 2 || ~isscalar(idx) || idx < 1 || idx > numel(app.session_figures)
                return;
            end
            entry = app.session_figures(idx);
            artifacts = app.pick_field(entry, {'artifacts'}, struct());
            if logical(app.pick_field(artifacts, {'completion_notice_emitted'}, false))
                return;
            end
            if ~isempty(app.current_executor) && isvalid(app.current_executor)
                return;
            end

            post_state = lower(char(string(app.pick_field(entry, {'post_publication_state'}, 'pending'))));
            if any(strcmp(post_state, {'pending', 'saving_in_background'}))
                return;
            end
            if app.has_pending_post_publication_jobs_for_entry(idx)
                return;
            end

            package_state = lower(char(string(app.pick_field(artifacts, {'final_results_package_state'}, 'completed'))));
            if any(strcmp(package_state, {'pending', 'queued', 'running'}))
                return;
            end
            finalize_state = lower(char(string(app.pick_field(artifacts, {'artifact_finalization_state'}, 'completed'))));
            if any(strcmp(finalize_state, {'pending', 'queued', 'running'}))
                return;
            end

            run_id = char(string(app.pick_field(app.pick_field(entry, {'metadata'}, struct()), {'run_id'}, '')));
            if strcmp(post_state, 'completed') && strcmp(package_state, 'completed') && ...
                    any(strcmp(finalize_state, {'completed', ''}))
                msg = 'Run fully completed: results saved and viewable in Results and Figures.';
                if ~isempty(strtrim(run_id))
                    msg = sprintf('Run fully completed: results saved and viewable in Results and Figures (%s).', run_id);
                end
                app.append_to_terminal(msg, 'success');
            else
                msg = 'Run completed with warnings: results are viewable in Results and Figures, and background saves finished with warnings.';
                if ~isempty(strtrim(run_id))
                    msg = sprintf('Run completed with warnings: results are viewable in Results and Figures (%s).', run_id);
                end
                app.append_to_terminal(msg, 'warning');
            end
            app.session_figures(idx).artifacts.completion_notice_emitted = true;
        end

        function execute_post_publication_job(app, job)
            if nargin < 2 || ~isstruct(job)
                return;
            end
            summary = app.pick_field(job, {'summary'}, struct());
            autosave_scope = lower(char(string(app.pick_field(job, {'scope'}, 'session'))));
            idx = double(app.pick_field(job, {'idx'}, NaN));
            switch autosave_scope
                case 'hydrate_result_entry'
                    if ~isfinite(idx) || idx < 1 || idx > numel(app.session_figures)
                        return;
                    end
                    app.hydrate_registered_result_entry(idx, summary);
                case 'persist_completion_package'
                    results = app.pick_field(summary, {'results'}, struct());
                    paths = app.pick_field(summary, {'paths'}, struct());
                    ParallelSimulationExecutor.persist_results_package(results, paths);
                    if isfinite(idx) && idx >= 1 && idx <= numel(app.session_figures)
                        app.session_figures(idx).artifacts.final_results_package_state = 'completed';
                        app.session_figures(idx).artifacts.final_results_package_worker_state = 'completed';
                    end
                case 'complete_run_artifacts'
                    if ~isfinite(idx) || idx < 1 || idx > numel(app.session_figures)
                        return;
                    end
                    artifact_summary = RunArtifactsManager.finalize( ...
                        app.pick_field(summary, {'run_config'}, struct()), ...
                        app.pick_field(summary, {'parameters'}, struct()), ...
                        app.pick_field(summary, {'settings'}, struct()), ...
                        app.pick_field(summary, {'results'}, struct()), ...
                        app.pick_field(summary, {'paths'}, struct()));
                    app.session_figures(idx).artifacts = app.merge_result_entry_artifacts( ...
                        app.session_figures(idx).artifacts, artifact_summary);
                    app.session_figures(idx).artifacts.artifact_finalization_state = 'completed';
                    app.session_figures(idx).artifacts.artifact_finalization_worker_state = 'completed';
                case 'report'
                    app.generate_report_to_tab();
                    app.select_results_tab();
                case 'workflow'
                    if ~isfinite(idx) || idx < 1 || idx > numel(app.session_figures)
                        return;
                    end
                    app.autosave_workflow_result_views(idx, summary);
                    entry = app.session_figures(idx);
                    if strcmpi(char(string(app.pick_field(entry, {'workflow_kind'}, ''))), 'phase1_periodic_comparison')
                        app.ensure_phase1_workflow_publication(idx, summary);
                    end
                otherwise
                    if ~isfinite(idx) || idx < 1 || idx > numel(app.session_figures)
                        return;
                    end
                    app.autosave_session_result_views(idx, summary);
            end
            if ~any(strcmpi(autosave_scope, {'persist_completion_package', 'hydrate_result_entry'})) && ...
                    isfinite(idx) && idx >= 1 && idx <= numel(app.session_figures)
                app.session_figures(idx).post_publication_state = 'completed';
                app.update_result_entry_status_badge(idx);
                app.maybe_emit_result_completion_line(idx);
            elseif any(strcmpi(autosave_scope, {'persist_completion_package', 'hydrate_result_entry'})) && ...
                    isfinite(idx) && idx >= 1 && idx <= numel(app.session_figures)
                app.update_result_entry_status_badge(idx);
                app.maybe_emit_result_completion_line(idx);
            end
        end

        function summary = normalize_completion_summary(app, summary_or_payload)
            summary = struct();
            if nargin < 2 || ~isstruct(summary_or_payload)
                return;
            end

            if isfield(summary_or_payload, 'summary') && isstruct(summary_or_payload.summary) && ...
                    ~isempty(fieldnames(summary_or_payload.summary))
                summary = summary_or_payload.summary;
            else
                summary = summary_or_payload;
            end

            fields_to_copy = {'results', 'paths', 'run_config', 'parameters', 'settings', 'analysis'};
            for fi = 1:numel(fields_to_copy)
                field_name = fields_to_copy{fi};
                if (~isfield(summary, field_name) || isempty(summary.(field_name))) && isfield(summary_or_payload, field_name)
                    summary.(field_name) = summary_or_payload.(field_name);
                end
            end
            outer_results = app.pick_field(summary_or_payload, {'results'}, struct());
            outer_paths = app.pick_field(summary_or_payload, {'paths'}, struct());
            if ~isfield(summary, 'results') || ~isstruct(summary.results)
                summary.results = struct();
            end
            if ~isfield(summary, 'paths') || ~isstruct(summary.paths)
                summary.paths = struct();
            end
            summary.results = app.overlay_completion_result_fields(summary.results, outer_results);
            summary.paths = app.overlay_completion_path_fields(summary.paths, outer_paths);
            outer_run_config = app.pick_field(summary_or_payload, {'run_config'}, struct());
            if ~isfield(summary, 'run_config') || ~isstruct(summary.run_config)
                summary.run_config = struct();
            end
            if isstruct(outer_run_config) && ~isempty(fieldnames(outer_run_config))
                run_config_backfill_fields = {'workflow_kind', 'result_layout_kind', 'launch_origin', ...
                    'phase_label', 'phase_id', 'run_id', 'mode'};
                for fi = 1:numel(run_config_backfill_fields)
                    field_name = run_config_backfill_fields{fi};
                    if (~isfield(summary.run_config, field_name) || isempty(summary.run_config.(field_name))) && ...
                            isfield(outer_run_config, field_name) && ~isempty(outer_run_config.(field_name))
                        summary.run_config.(field_name) = outer_run_config.(field_name);
                    end
                end
            end
            if ~isfield(summary, 'wall_time') && isfield(summary_or_payload, 'wall_time')
                summary.wall_time = summary_or_payload.wall_time;
            end
            if ~isfield(summary, 'completion_results_already_persisted') && ...
                    isfield(summary_or_payload, 'completion_results_already_persisted')
                summary.completion_results_already_persisted = logical(summary_or_payload.completion_results_already_persisted);
            end
            completion_state_fields = {'solver_complete', 'minimal_results_persisted', 'results_published', 'exports_complete'};
            for fi = 1:numel(completion_state_fields)
                field_name = completion_state_fields{fi};
                if ~isfield(summary, field_name) && isfield(summary_or_payload, field_name)
                    summary.(field_name) = logical(summary_or_payload.(field_name));
                end
            end
            if ~isfield(summary, 'mode')
                summary.mode = char(string(app.pick_field(app.pick_field(summary, {'run_config'}, struct()), {'mode'}, ...
                    app.pick_field(app.pick_field(summary, {'results'}, struct()), {'mode'}, ...
                    app.pick_field(outer_run_config, {'mode'}, '')))));
            end
            completion_meta_fields = {'workflow_kind', 'result_layout_kind', 'launch_origin', 'phase_label'};
            for fi = 1:numel(completion_meta_fields)
                field_name = completion_meta_fields{fi};
                if isfield(summary, field_name) && ~isempty(summary.(field_name))
                    continue;
                end
                candidate_value = app.pick_field(summary_or_payload, {field_name}, []);
                if isempty(candidate_value)
                    candidate_value = app.pick_field(app.pick_field(summary, {'run_config'}, struct()), {field_name}, []);
                end
                if isempty(candidate_value)
                    candidate_value = app.pick_field(app.pick_field(summary, {'results'}, struct()), {field_name}, []);
                end
                if ~isempty(candidate_value)
                    summary.(field_name) = candidate_value;
                end
            end
            completion_monitor_series = app.collect_live_monitor_series_for_summary(summary);
            if app.monitor_series_has_meaningful_payload(completion_monitor_series) || ...
                    ~isfield(summary, 'monitor_series') || ~isstruct(summary.monitor_series) || ...
                    isempty(fieldnames(summary.monitor_series))
                summary.monitor_series = completion_monitor_series;
            end
        end

        function merged_results = overlay_completion_result_fields(app, base_results, payload_results)
            merged_results = base_results;
            if ~isstruct(merged_results)
                merged_results = struct();
            end
            if ~isstruct(payload_results) || isempty(fieldnames(payload_results))
                return;
            end

            overlay_fields = {'collector_samples', 'collector_last_sample', 'collector_session', ...
                'collector_status', 'collector_metric_catalog', 'artifact_layout_version'};
            for i = 1:numel(overlay_fields)
                field_name = overlay_fields{i};
                if isfield(payload_results, field_name) && ~isempty(payload_results.(field_name))
                    merged_results.(field_name) = payload_results.(field_name);
                end
            end

            payload_paths = app.pick_field(payload_results, {'paths'}, struct());
            if isstruct(payload_paths) && ~isempty(fieldnames(payload_paths))
                existing_paths = app.pick_field(merged_results, {'paths'}, struct());
                merged_results.paths = app.overlay_nonempty_struct_fields(existing_paths, payload_paths);
            end
        end

        function merged_paths = overlay_completion_path_fields(app, base_paths, payload_paths)
            merged_paths = app.overlay_nonempty_struct_fields(base_paths, payload_paths);
        end

        function merged = overlay_nonempty_struct_fields(app, base_struct, overlay_struct) %#ok<INUSL>
            merged = base_struct;
            if ~isstruct(merged)
                merged = struct();
            end
            if ~isstruct(overlay_struct) || isempty(fieldnames(overlay_struct))
                return;
            end

            overlay_fields = fieldnames(overlay_struct);
            for i = 1:numel(overlay_fields)
                field_name = overlay_fields{i};
                value = overlay_struct.(field_name);
                if isstruct(value)
                    if ~isscalar(value)
                        merged.(field_name) = value;
                        continue;
                    end
                    base_value = struct();
                    if isfield(merged, field_name) && isstruct(merged.(field_name)) && isscalar(merged.(field_name))
                        base_value = merged.(field_name);
                    end
                    merged.(field_name) = app.overlay_nonempty_struct_fields(base_value, value);
                    continue;
                end
                if isempty(value)
                    continue;
                end
                merged.(field_name) = value;
            end
        end

        function recovered_summary = recover_completion_summary_from_saved_artifacts(app, summary)
            recovered_summary = struct();
            if nargin < 2 || ~isstruct(summary)
                return;
            end

            live_summary = app.normalize_completion_summary(summary);
            paths = app.pick_field(live_summary, {'paths'}, struct());
            if isempty(fieldnames(paths))
                paths = app.pick_field(app.pick_field(live_summary, {'results'}, struct()), {'paths'}, struct());
            end
            data_root = char(string(app.pick_field(paths, {'matlab_data_root', 'data'}, '')));
            if isempty(data_root)
                base_root = char(string(app.pick_field(paths, {'base'}, '')));
                if ~isempty(base_root)
                    data_root = fullfile(base_root, 'Data');
                end
            end
            manifest_fallback = '';
            if ~isempty(data_root)
                manifest_fallback = fullfile(data_root, 'artifact_manifest.json');
            end
            manifest_path = char(string(app.pick_field(paths, {'manifest_path'}, manifest_fallback)));

            candidate_mat_paths = strings(1, 0);
            if ~isempty(data_root)
                candidate_mat_paths = [candidate_mat_paths, string({ ...
                    fullfile(data_root, 'mesh_convergence_results.mat'), ...
                    fullfile(data_root, 'phase1_results.mat'), ...
                    fullfile(data_root, 'phase2_results.mat'), ...
                    fullfile(data_root, 'phase3_results.mat'), ...
                    fullfile(data_root, 'results.mat'), ...
                    fullfile(data_root, 'convergence_results.mat'), ...
                    fullfile(data_root, 'mesh_convergence_workflow_manifest.mat'), ...
                    fullfile(data_root, 'phase1_workflow_manifest.mat'), ...
                    fullfile(data_root, 'phase2_workflow_manifest.mat'), ...
                    fullfile(data_root, 'phase3_workflow_manifest.mat')})];
            end
            candidate_mat_paths = unique(candidate_mat_paths(strlength(strtrim(candidate_mat_paths)) > 0), 'stable');
            for i = 1:numel(candidate_mat_paths)
                candidate_path = char(candidate_mat_paths(i));
                if exist(candidate_path, 'file') ~= 2
                    continue;
                end
                try
                    loaded = load(candidate_path);
                catch
                    continue;
                end
                imported_summary = app.build_summary_from_import_payload(loaded, candidate_path);
                if isempty(imported_summary)
                    imported_summary = app.build_summary_from_saved_package_payload(loaded, paths);
                end
                if isstruct(imported_summary) && ~isempty(fieldnames(imported_summary))
                    recovered_summary = app.merge_saved_summary_candidate(live_summary, imported_summary);
                    return;
                end
            end

            candidate_json_paths = strings(1, 0);
            if ~isempty(manifest_path)
                candidate_json_paths(end + 1) = string(manifest_path); %#ok<AGROW>
            end
            if ~isempty(data_root)
                candidate_json_paths = [candidate_json_paths, string({ ...
                    fullfile(data_root, 'mesh_convergence_workflow_manifest.json'), ...
                    fullfile(data_root, 'phase1_workflow_manifest.json'), ...
                    fullfile(data_root, 'phase2_workflow_manifest.json'), ...
                    fullfile(data_root, 'phase3_workflow_manifest.json')})];
            end
            candidate_json_paths = unique(candidate_json_paths(strlength(strtrim(candidate_json_paths)) > 0), 'stable');
            for i = 1:numel(candidate_json_paths)
                candidate_path = char(candidate_json_paths(i));
                if exist(candidate_path, 'file') ~= 2
                    continue;
                end
                try
                    payload = jsondecode(fileread(candidate_path));
                catch
                    continue;
                end
                imported_summary = app.build_summary_from_saved_package_payload(payload, paths);
                if isstruct(imported_summary) && ~isempty(fieldnames(imported_summary))
                    recovered_summary = app.merge_saved_summary_candidate(live_summary, imported_summary);
                    return;
                end
            end
        end

        function merged_summary = merge_saved_summary_candidate(app, live_summary, saved_summary)
            merged_summary = app.normalize_completion_summary(saved_summary);
            live_summary = app.normalize_completion_summary(live_summary);
            if isempty(merged_summary) || ~isstruct(merged_summary)
                merged_summary = struct();
            end

            struct_fields = {'results', 'paths', 'run_config', 'parameters', 'settings', 'analysis', 'monitor_series'};
            for i = 1:numel(struct_fields)
                field_name = struct_fields{i};
                saved_value = app.pick_field(merged_summary, {field_name}, struct());
                live_value = app.pick_field(live_summary, {field_name}, struct());
                if ~isstruct(saved_value)
                    continue;
                end
                merged_summary.(field_name) = app.overlay_nonempty_struct_fields(saved_value, live_value);
            end

            scalar_fields = {'mode', 'wall_time', 'workflow_kind', 'result_layout_kind', 'launch_origin', 'phase_label'};
            for i = 1:numel(scalar_fields)
                field_name = scalar_fields{i};
                if (~isfield(merged_summary, field_name) || isempty(merged_summary.(field_name))) && ...
                        isfield(live_summary, field_name) && ~isempty(live_summary.(field_name))
                    merged_summary.(field_name) = live_summary.(field_name);
                end
            end
        end

        function summary = build_summary_from_saved_package_payload(app, payload, paths)
            summary = struct();
            if nargin < 2 || ~isstruct(payload)
                return;
            end

            if isfield(payload, 'workflow_manifest')
                summary = app.build_summary_from_import_payload(payload, 'workflow_manifest');
                if ~isempty(summary)
                    return;
                end
            end
            if any(isfield(payload, {'entry_to_save', 'analysis', 'ResultsForSave'}))
                summary = app.build_summary_from_import_payload(payload, 'saved_package');
                if ~isempty(summary)
                    return;
                end
            end

            results = app.pick_field(payload, {'results', 'Results'}, struct());
            if ~isstruct(results) || isempty(fieldnames(results))
                return;
            end
            params = app.pick_field(payload, {'parameters'}, struct());
            settings = app.pick_field(payload, {'settings'}, struct());
            run_cfg = app.pick_field(payload, {'run_config'}, struct());
            saved_paths = app.pick_field(payload, {'paths'}, paths);
            if ~isfield(run_cfg, 'method') && isfield(payload, 'method')
                run_cfg.method = payload.method;
            end
            if ~isfield(run_cfg, 'mode') && isfield(payload, 'mode')
                run_cfg.mode = payload.mode;
            end
            if ~isfield(run_cfg, 'ic_type') && isfield(payload, 'ic_type')
                run_cfg.ic_type = payload.ic_type;
            end
            if ~isfield(run_cfg, 'workflow_kind')
                run_cfg.workflow_kind = app.pick_field(results, {'workflow_kind'}, app.pick_field(payload, {'workflow_kind'}, ''));
            end
            if ~isfield(run_cfg, 'result_layout_kind')
                run_cfg.result_layout_kind = app.pick_field(results, {'result_layout_kind'}, app.pick_field(payload, {'result_layout_kind'}, ''));
            end
            if ~isfield(run_cfg, 'phase_label')
                run_cfg.phase_label = app.pick_field(results, {'phase_label'}, app.pick_field(payload, {'phase_label'}, ''));
            end
            if ~isfield(run_cfg, 'launch_origin') && ~isempty(app.pick_field(results, {'workflow_kind'}, ''))
                run_cfg.launch_origin = 'phase_button';
            end

            analysis = app.pick_field(payload, {'analysis'}, struct());
            if ~isstruct(analysis) || isempty(fieldnames(analysis))
                data_path = char(string(app.pick_field(results, {'data_path'}, '')));
                if isempty(data_path) && isstruct(saved_paths)
                    data_root = char(string(app.pick_field(saved_paths, {'matlab_data_root', 'data'}, '')));
                    if ~isempty(data_root)
                        candidate_path = fullfile(data_root, 'results.mat');
                        if exist(candidate_path, 'file') == 2
                            data_path = candidate_path;
                        end
                    end
                end
                if ~isempty(data_path) && exist(data_path, 'file') == 2
                    try
                        loaded = load(data_path, 'analysis');
                        analysis = app.pick_field(loaded, {'analysis'}, struct());
                    catch
                        analysis = struct();
                    end
                end
            end

            summary = struct( ...
                'results', results, ...
                'parameters', params, ...
                'settings', settings, ...
                'run_config', run_cfg, ...
                'paths', saved_paths, ...
                'analysis', analysis, ...
                'workflow_kind', app.pick_field(run_cfg, {'workflow_kind'}, ''), ...
                'result_layout_kind', app.pick_field(run_cfg, {'result_layout_kind'}, ''), ...
                'phase_label', app.pick_field(run_cfg, {'phase_label'}, ''));
        end

        function persist_completion_publication_state(app, summary, publication_status, publication_note)
            if nargin < 3 || ~isstruct(summary)
                return;
            end
            paths = app.pick_field(summary, {'paths'}, struct());
            if isempty(fieldnames(paths))
                paths = app.pick_field(app.pick_field(summary, {'results'}, struct()), {'paths'}, struct());
            end
            data_root = char(string(app.pick_field(paths, {'matlab_data_root', 'data'}, '')));
            manifest_fallback = '';
            if ~isempty(data_root)
                manifest_fallback = fullfile(data_root, 'artifact_manifest.json');
            end
            manifest_path = char(string(app.pick_field(paths, {'manifest_path'}, manifest_fallback)));
            if isempty(manifest_path)
                return;
            end

            payload = struct();
            if exist(manifest_path, 'file') == 2
                try
                    payload = jsondecode(fileread(manifest_path));
                catch
                    payload = struct();
                end
            end

            payload.publication_status = char(string(publication_status));
            payload.publication_note = char(string(publication_note));
            payload.published_at = char(datetime('now', 'Format', 'yyyy-MM-dd HH:mm:ss'));
            payload.workflow_kind = char(string(app.pick_field(summary, {'workflow_kind'}, ...
                app.pick_field(app.pick_field(summary, {'run_config'}, struct()), {'workflow_kind'}, ...
                app.pick_field(app.pick_field(summary, {'results'}, struct()), {'workflow_kind'}, '')))));
            payload.result_layout_kind = char(string(app.pick_field(summary, {'result_layout_kind'}, ...
                app.pick_field(app.pick_field(summary, {'run_config'}, struct()), {'result_layout_kind'}, ...
                app.pick_field(app.pick_field(summary, {'results'}, struct()), {'result_layout_kind'}, '')))));
            payload.phase_label = char(string(app.pick_field(summary, {'phase_label'}, ...
                app.pick_field(app.pick_field(summary, {'run_config'}, struct()), {'phase_label'}, ...
                app.pick_field(app.pick_field(summary, {'results'}, struct()), {'phase_label'}, '')))));
            if ~isfield(payload, 'paths') || ~isstruct(payload.paths) || isempty(fieldnames(payload.paths))
                payload.paths = paths;
            end
            try
                app.write_json_text_file(manifest_path, app.make_workflow_manifest_json_safe(payload));
            catch
            end
        end

        function ensure_published_completion_registry(app)
            if ~isa(app.published_completion_keys, 'containers.Map')
                app.published_completion_keys = containers.Map('KeyType', 'char', 'ValueType', 'logical');
            end
            if ~isa(app.published_completion_entry_indices, 'containers.Map')
                app.published_completion_entry_indices = containers.Map('KeyType', 'char', 'ValueType', 'double');
            end
        end

        function reset_published_completion_registry(app)
            app.published_completion_keys = containers.Map('KeyType', 'char', 'ValueType', 'logical');
            app.published_completion_entry_indices = containers.Map('KeyType', 'char', 'ValueType', 'double');
        end

        function reset_deferred_live_monitor_payloads(app)
            app.deferred_live_monitor_payloads = {};
            app.is_flushing_live_monitor_payloads = false;
            app.cached_completion_report_payload = struct();
        end

        function cache_completion_report_payload(app, payload)
            if nargin < 2 || ~isstruct(payload)
                app.cached_completion_report_payload = struct();
                return;
            end
            app.cached_completion_report_payload = payload;
        end

        function summary = enrich_summary_from_cached_completion_payload(app, summary)
            if nargin < 2 || ~isstruct(summary)
                summary = struct();
            end
            payload = app.cached_completion_report_payload;
            if ~isstruct(payload) || isempty(fieldnames(payload))
                return;
            end
            payload.summary = summary;
            summary = app.normalize_completion_summary(payload);
        end

        function tf = completion_publication_owned_by_host(app, payload)
            tf = false;
            if nargin < 2 || ~isstruct(payload)
                return;
            end
            publication_mode = lower(app.pick_text_field(payload, {'result_publication_mode'}, 'manual'));
            if strcmp(publication_mode, 'manual')
                tf = true;
                return;
            end
            tf = ~strcmpi(app.run_lifecycle_state, 'idle') || ~isempty(app.current_executor);
        end

        function set_completion_finalizing_state(app)
            status_text = 'Finalizing results...';
            if isfield(app.handles, 'run_status') && isvalid(app.handles.run_status)
                app.handles.run_status.Text = status_text;
            end
            if app.has_valid_handle('progress_eta_label')
                app.handles.progress_eta_label.Text = status_text;
            end
            if isfield(app.handles, 'monitor_live_state') && isstruct(app.handles.monitor_live_state)
                state = app.handles.monitor_live_state;
                state.status_text = status_text;
                app.handles.monitor_live_state = state;
                app.update_workflow_activity_display(state);
            end
        end

        function enqueue_live_monitor_payload(app, payload, cfg)
            if nargin < 3 || isempty(cfg)
                cfg = app.config;
            end
            if ~iscell(app.deferred_live_monitor_payloads)
                app.deferred_live_monitor_payloads = {};
            end
            app.deferred_live_monitor_payloads{end + 1} = struct( ...
                'payload', payload, ...
                'cfg', cfg);
        end

        function progress_callback = build_live_monitor_payload_callback(app, cfg)
            if nargin < 2 || isempty(cfg)
                cfg = app.config;
            end
            progress_callback = struct( ...
                'callback_kind', 'ui_controller_live_monitor', ...
                'app', app, ...
                'cfg', cfg);
        end

        function deliver_live_monitor_payload(app, payload, cfg)
            if nargin < 3 || isempty(cfg)
                cfg = app.config;
            end
            app.enqueue_live_monitor_payload(payload, cfg);
            if ~app.is_flushing_live_monitor_payloads
                app.flush_deferred_live_monitor_payloads();
            end
        end

        function flush_deferred_live_monitor_payloads(app)
            if app.is_flushing_live_monitor_payloads
                return;
            end
            if ~iscell(app.deferred_live_monitor_payloads) || isempty(app.deferred_live_monitor_payloads)
                return;
            end

            app.is_flushing_live_monitor_payloads = true;
            cleanup_guard = onCleanup(@() app.set_deferred_live_monitor_flush_state(false)); %#ok<NASGU>

            while ~isempty(app.deferred_live_monitor_payloads)
                item = app.deferred_live_monitor_payloads{1};
                if numel(app.deferred_live_monitor_payloads) == 1
                    app.deferred_live_monitor_payloads = {};
                else
                    app.deferred_live_monitor_payloads(1) = [];
                end

                if ~isstruct(item) || ~isfield(item, 'payload')
                    continue;
                end
                payload = item.payload;
                payload_cfg = app.config;
                if isfield(item, 'cfg') && isstruct(item.cfg)
                    payload_cfg = item.cfg;
                end
                try
                    app.handle_live_monitor_progress(payload, payload_cfg);
                catch ME
                    payload_channel = '';
                    if isstruct(payload) && isfield(payload, 'channel')
                        payload_channel = app.to_text(payload.channel, '');
                    end
                    app.append_to_terminal(sprintf( ...
                        'Live monitor payload warning [%s]: %s', ...
                        app.if_empty(payload_channel, 'unknown'), ME.message), 'warning');
                end
            end
        end

        function set_deferred_live_monitor_flush_state(app, tf)
            app.is_flushing_live_monitor_payloads = logical(tf);
        end

        function key = resolve_completion_publication_key(app, summary)
            key_parts = { ...
                app.pick_field(app.pick_field(summary, {'paths'}, struct()), {'base'}, ''), ...
                app.pick_field(app.pick_field(summary, {'results'}, struct()), {'data_path'}, ''), ...
                app.pick_field(app.pick_field(summary, {'results'}, struct()), {'run_id'}, ''), ...
                app.pick_field(app.pick_field(summary, {'results'}, struct()), {'phase_id'}, ''), ...
                app.pick_field(app.pick_field(summary, {'run_config'}, struct()), {'phase_id'}, ''), ...
                app.pick_field(app.pick_field(summary, {'run_config'}, struct()), {'run_id'}, '')};
            key = '';
            for i = 1:numel(key_parts)
                candidate = char(string(key_parts{i}));
                if strlength(string(strtrim(candidate))) > 0
                    key = candidate;
                    break;
                end
            end
            if strlength(string(strtrim(key))) == 0
                key = sprintf('%s|%.6f|%.6f', ...
                    char(string(app.pick_field(summary, {'mode'}, 'run'))), ...
                    app.pick_field(summary, {'wall_time'}, NaN), ...
                    app.pick_field(app.pick_field(summary, {'results'}, struct()), {'max_omega'}, NaN));
            end
        end

        function ic_coeff = build_ic_coeff_vector(app, ic_type, coeff_override)
            ic_type = lower(char(string(ic_type)));
            schema = app.get_ic_schema(ic_type);
            shared = app.read_ic_shared_values();

            if nargin < 3
                dyn = app.default_dynamic_values(schema);
                if isfield(app.handles, 'ic_active_schema') && isstruct(app.handles.ic_active_schema) && ...
                        isfield(app.handles.ic_active_schema, 'ic_type') && ...
                        strcmpi(char(string(app.handles.ic_active_schema.ic_type)), schema.ic_type)
                    dyn = app.read_ic_dynamic_values_from_schema(schema);
                end
            else
                dyn = app.dynamic_from_legacy_coeff_override(schema, coeff_override);
            end
            ic_coeff = app.pack_ic_coeff_from_values(ic_type, schema, shared, dyn);
        end

        function ic_coeff = pack_ic_coeff_from_values(app, ic_type, schema, shared, dyn)
            flags = schema.shared_flags;
            x0 = 0.0;
            y0 = 0.0;
            if isfield(flags, 'show_position') && flags.show_position
                x0 = app.get_dynamic_value(shared, 'center_x', 0.0);
                y0 = app.get_dynamic_value(shared, 'center_y', 0.0);
            end
            scale = 1.0;
            if isfield(flags, 'show_scale') && flags.show_scale
                scale = max(app.get_dynamic_value(shared, 'scale', 1.0), 1e-8);
            end
            n_vort = 1;
            if isfield(flags, 'show_count') && flags.show_count
                n_vort = max(1, round(app.get_dynamic_value(shared, 'count', 1.0)));
            end
            pattern = char(string(app.pick_field(shared, {'arrangement', 'pattern'}, 'single')));
            amp = max(app.get_dynamic_value(shared, 'amplitude', 1.0), 1e-8);
            charge = app.get_dynamic_value(shared, 'charge', 1.0);
            domain_lx = 10.0;
            domain_ly = 10.0;
            if app.has_valid_handle('Lx'), domain_lx = app.handles.Lx.Value; end
            if app.has_valid_handle('Ly'), domain_ly = app.handles.Ly.Value; end

            switch ic_type
                case 'no_initial_condition'
                    ic_coeff = [];
                case 'stretched_gaussian'
                    a = app.get_dynamic_value(dyn, 'stretch_x', 2.15);
                    b = app.get_dynamic_value(dyn, 'stretch_y', 0.18);
                    ic_coeff = [max(a, 1e-8), max(b, 1e-8), max(scale, 1e-8) * amp, 0, x0, y0];
                case 'vortex_blob_gaussian'
                    gamma = app.get_dynamic_value(dyn, 'circulation', 1.0) * scale * charge;
                    radius = app.get_dynamic_value(dyn, 'radius', 0.35);
                    ic_coeff = [gamma, max(radius, 1e-6), x0, y0, x0, y0];
                case 'vortex_pair'
                    gamma1 = app.get_dynamic_value(dyn, 'gamma1', 1.0) * scale * charge;
                    sep = max(app.get_dynamic_value(dyn, 'separation', 2.0), 1e-6);
                    rad = max(app.get_dynamic_value(dyn, 'core_radius', 0.4), 1e-6);
                    gamma2 = -abs(gamma1);
                    x1 = x0 - sep / 2;
                    x2 = x0 + sep / 2;
                    ic_coeff = [gamma1, rad, x1, y0, gamma2, x2];
                case 'multi_vortex'
                    n_actual = max(1, n_vort);
                    [centers_x, centers_y] = app.build_vortex_centers(n_actual, pattern, domain_lx, domain_ly, x0, y0);
                    g = app.get_dynamic_value(dyn, 'gamma', 1.0) * scale * charge;
                    r = max(app.get_dynamic_value(dyn, 'core_radius', 0.3), 1e-6);
                    ic_coeff = zeros(1, 4 * n_actual);
                    for vi = 1:n_actual
                        idx = (vi - 1) * 4;
                        ic_coeff(idx + 1) = g;
                        ic_coeff(idx + 2) = r;
                        ic_coeff(idx + 3) = centers_x(vi);
                        ic_coeff(idx + 4) = centers_y(vi);
                    end
                case 'lamb_oseen'
                    gamma = app.get_dynamic_value(dyn, 'circulation', 1.0) * scale * charge;
                    t0 = app.get_dynamic_value(dyn, 'virtual_time', 100.0);
                    nu = app.get_dynamic_value(dyn, 'nu', 1e-3);
                    ic_coeff = [gamma, max(t0, 1e-6), max(nu, 1e-8), 0, x0, y0];
                case 'rankine'
                    omega0 = app.get_dynamic_value(dyn, 'core_vorticity', 1.0) * scale * charge;
                    rc = app.get_dynamic_value(dyn, 'core_radius', 1.0);
                    ic_coeff = [omega0, max(rc, 1e-6), 0, 0, x0, y0];
                case 'lamb_dipole'
                    U = app.get_dynamic_value(dyn, 'translation_speed', 0.5) * scale;
                    a = app.get_dynamic_value(dyn, 'dipole_radius', 1.0);
                    ic_coeff = [U, max(a, 1e-6), 0, 0, x0, y0];
                case 'taylor_green'
                    k = max(1, round(app.get_dynamic_value(dyn, 'wavenumber', 1.0)));
                    G = app.get_dynamic_value(dyn, 'strength', 1.0) * scale;
                    ic_coeff = [k, G, 0, 0, x0, y0];
                case 'random_turbulence'
                    alpha = app.get_dynamic_value(dyn, 'spectrum_exponent', 5/3);
                    e0 = app.get_dynamic_value(dyn, 'energy_level', 1.0) * scale;
                    seed = round(app.get_dynamic_value(dyn, 'seed', 0));
                    ic_coeff = [max(alpha, 0.1), e0, seed, 0, 0, 0];
                case 'elliptical_vortex'
                    w0 = app.get_dynamic_value(dyn, 'peak_vorticity', 1.0) * scale * charge;
                    sx = app.get_dynamic_value(dyn, 'sigma_x', 1.0 / sqrt(2.0 * 2.15));
                    sy = app.get_dynamic_value(dyn, 'sigma_y', 1.0 / sqrt(2.0 * 0.18));
                    theta = app.get_dynamic_value(dyn, 'rotation_theta', 0.0);
                    ic_coeff = [w0, max(sx, 1e-6), max(sy, 1e-6), theta, x0, y0];
                otherwise
                    coeffs = app.legacy_coeff_vector_from_dynamic(schema, dyn);
                    ic_coeff = [coeffs(1), coeffs(2), coeffs(3), coeffs(4), x0, y0];
            end
        end

        function sync_multi_vortex_preview_state(app, ic_type, schema)
            if ~isfield(schema, 'supports_multi_vortex') || ~logical(schema.supports_multi_vortex)
                return;
            end
            if ~logical(app.pick_field(app.config, {'ic_multi_vortex_experimental'}, false))
                return;
            end
            if ~isfield(app.config, 'ic_multi_vortex_rows') || isempty(app.config.ic_multi_vortex_rows)
                return;
            end

            rows = app.normalize_multi_vortex_rows(app.config.ic_multi_vortex_rows, ic_type);
            if numel(rows) ~= 1
                return;
            end

            shared = app.read_ic_shared_values();
            dyn = app.read_ic_dynamic_values_from_schema(schema);
            rows(1).ic_type = ic_type;
            rows(1).enabled = true;
            rows(1).center_x = app.pick_field(shared, {'center_x'}, rows(1).center_x);
            rows(1).center_y = app.pick_field(shared, {'center_y'}, rows(1).center_y);
            rows(1).scale = max(1.0e-6, app.pick_field(shared, {'scale'}, rows(1).scale));
            rows(1).amplitude = max(1.0e-6, app.pick_field(shared, {'amplitude'}, rows(1).amplitude));
            rows(1).dynamic_values = dyn;
            app.config.ic_multi_vortex_rows = rows;
        end

        function mirror_single_multi_vortex_row_to_controls(app, row)
            if ~isstruct(row)
                return;
            end
            ic_type = app.map_ic_display_to_type(char(string(row.ic_type)));
            schema = app.get_ic_schema(ic_type);
            if app.has_valid_handle('ic_dropdown')
                app.handles.ic_dropdown.Value = app.map_ic_type_to_display(ic_type);
            end
            app.sync_ic_scenario_items_for_active_ic(app.pick_field(app.config, {'ic_scenario'}, 'Manual'));
            app.apply_shared_values(struct( ...
                'center_x', row.center_x, ...
                'center_y', row.center_y, ...
                'scale', row.scale, ...
                'count', 1, ...
                'amplitude', row.amplitude, ...
                'arrangement', app.pick_field(app.config, {'ic_arrangement', 'ic_pattern'}, 'single')));
            app.write_ic_dynamic_values(schema, row.dynamic_values);
        end

        function tf = should_use_multi_vortex_rows(app, ic_type, schema)
            tf = false;
            if ~isfield(app.config, 'ic_multi_vortex_rows') || isempty(app.config.ic_multi_vortex_rows)
                return;
            end
            if ~isfield(schema, 'supports_multi_vortex') || ~logical(schema.supports_multi_vortex)
                return;
            end
            rows = app.normalize_multi_vortex_rows(app.config.ic_multi_vortex_rows, ic_type);
            if isempty(rows)
                return;
            end
            tf = logical(app.pick_field(app.config, {'ic_multi_vortex_experimental'}, false));
        end

        function Z = evaluate_multi_vortex_rows(app, X, Y, rows, fallback_ic_type)
            rows = app.normalize_multi_vortex_rows(rows, fallback_ic_type);
            Z = zeros(size(X));
            if isempty(rows)
                return;
            end
            enabled_mask = [rows.enabled];
            if ~any(enabled_mask)
                enabled_mask = true(size(enabled_mask));
            end
            active_rows = rows(enabled_mask);
            for i = 1:numel(active_rows)
                schema = app.get_ic_schema(active_rows(i).ic_type);
                shared = struct( ...
                    'center_x', active_rows(i).center_x, ...
                    'center_y', active_rows(i).center_y, ...
                    'scale', active_rows(i).scale, ...
                    'count', 1, ...
                    'pattern', 'single', ...
                    'arrangement', 'single', ...
                    'amplitude', active_rows(i).amplitude, ...
                    'charge', active_rows(i).charge);
                coeff = app.pack_ic_coeff_from_values(active_rows(i).ic_type, schema, shared, active_rows(i).dynamic_values);
                Z = Z + ICDispatcher.evaluate_catalog(X, Y, active_rows(i).ic_type, coeff);
            end
        end

        function [c1, c2, c3, c4, x0, y0] = get_ic_coeff_control_values(app)
            [ic_type, schema] = app.resolve_active_ic_type();
            dyn = app.read_ic_dynamic_values_from_schema(schema);
            coeffs = app.legacy_coeff_vector_from_dynamic(schema, dyn);
            c1 = coeffs(1);
            c2 = coeffs(2);
            c3 = coeffs(3);
            c4 = coeffs(4);

            shared = app.read_ic_shared_values();
            if isfield(schema, 'shared_flags') && isstruct(schema.shared_flags) && ...
                    isfield(schema.shared_flags, 'show_position') && schema.shared_flags.show_position
                x0 = shared.center_x;
                y0 = shared.center_y;
            else
                x0 = 0.0;
                y0 = 0.0;
            end
            if isempty(ic_type)
                x0 = 0.0; y0 = 0.0;
            end
        end

        function coeffs = legacy_coeff_vector_from_dynamic(~, schema, dyn)
            coeffs = zeros(1, 4);
            if ~isfield(schema, 'dynamic_fields') || isempty(schema.dynamic_fields)
                return;
            end
            n = min(4, numel(schema.dynamic_fields));
            for i = 1:n
                id = schema.dynamic_fields(i).id;
                if isfield(dyn, id)
                    coeffs(i) = double(dyn.(id));
                end
            end
        end

        function dyn = dynamic_from_legacy_coeff_override(app, schema, coeff_override)
            dyn = app.default_dynamic_values(schema);
            coeff_override = double(coeff_override(:)).';
            if isempty(coeff_override)
                return;
            end
            if ~isfield(schema, 'dynamic_fields') || isempty(schema.dynamic_fields)
                return;
            end
            n = min(numel(coeff_override), numel(schema.dynamic_fields));
            for i = 1:n
                id = schema.dynamic_fields(i).id;
                dyn.(id) = coeff_override(i);
            end
        end

        function val = get_dynamic_value(~, dyn, field_id, default_val)
            val = default_val;
            if isstruct(dyn) && isfield(dyn, field_id)
                val = double(dyn.(field_id));
            end
        end

        function [x_list, y_list] = build_vortex_centers(~, n_vort, pattern, Lx, Ly, x0, y0)
            try
                [x_list, y_list] = disperse_vortices(n_vort, pattern, Lx, Ly);
            catch ME
                if UIController.is_missing_symbol_error(ME)
                    UIController.attach_project_paths_from_ui();
                    [x_list, y_list] = disperse_vortices(n_vort, pattern, Lx, Ly);
                else
                    rethrow(ME);
                end
            end
            x_list = x_list(:) + x0;
            y_list = y_list(:) + y0;
        end

        function update_mode_control_visibility(app)
            mode_val = app.handles.mode_dropdown.Value;
            sweep_on = strcmp(mode_val, 'Parameter Sweep') || strcmp(mode_val, 'Sweep');
            exp_on = false;

            sweep_state = app.on_off(sweep_on);
            exp_state = app.on_off(exp_on);
            sweep_vis = app.on_off(sweep_on);
            exp_vis = app.on_off(exp_on);

            app.set_optional_handle_enable('sweep_parameter', sweep_state);
            app.set_optional_handle_enable('sweep_values', sweep_state);
            app.set_optional_handle_property('sweep_parameter', 'Visible', sweep_vis);
            app.set_optional_handle_property('sweep_values', 'Visible', sweep_vis);
            app.set_optional_handle_property('sweep_parameter_label', 'Visible', sweep_vis);
            app.set_optional_handle_property('sweep_values_label', 'Visible', sweep_vis);

            app.set_optional_handle_enable('exp_coeff_selector', exp_state);
            app.set_optional_handle_enable('exp_range_start', exp_state);
            app.set_optional_handle_enable('exp_range_end', exp_state);
            app.set_optional_handle_enable('exp_num_points', exp_state);
            app.set_optional_handle_property('exp_coeff_selector', 'Visible', exp_vis);
            app.set_optional_handle_property('exp_range_start', 'Visible', exp_vis);
            app.set_optional_handle_property('exp_range_end', 'Visible', exp_vis);
            app.set_optional_handle_property('exp_num_points', 'Visible', exp_vis);
            app.set_optional_handle_property('exp_coeff_label', 'Visible', exp_vis);
            app.set_optional_handle_property('exp_range_start_label', 'Visible', exp_vis);
            app.set_optional_handle_property('exp_range_end_label', 'Visible', exp_vis);
            app.set_optional_handle_property('exp_num_points_label', 'Visible', exp_vis);
        end

