        function reset_live_monitor_history_for_run(app, cfg)
            % Reset monitor plots/table to a clean per-run state while preserving files on disk.
            if nargin < 2 || isempty(cfg)
                cfg = app.config;
            end

            % Clear all monitor axes to remove stale plot data
            if isfield(app.handles, 'monitor_axes')
                for ax_idx = 1:numel(app.handles.monitor_axes)
                    if isvalid(app.handles.monitor_axes(ax_idx))
                        cla(app.handles.monitor_axes(ax_idx));
                    end
                end
            end
            if isfield(app.handles, 'monitor_line_handles')
                app.handles.monitor_line_handles = cell(1, numel(app.handles.monitor_axes));
            end
            if isfield(app.handles, 'monitor_slot_metric_ids')
                app.handles.monitor_slot_metric_ids = repmat({''}, 1, numel(app.handles.monitor_axes));
            end

            app.start_live_monitor_session(cfg);
            if app.is_progress_only_launch(cfg)
                app.ensure_launch_progress_dialog(cfg);
                app.update_launch_progress_dialog(cfg, 0, 'Simulation Progress', 'Preparing run...');
                drawnow limitrate;
                return;
            end
            if isfield(app.handles, 'monitor_axes') && ~isempty(app.handles.monitor_axes) && ...
                    isfield(app.handles, 'monitor_numeric_table')
                summary_seed = struct('results', struct(), 'monitor_series', app.handles.monitor_live_state);
                app.refresh_monitor_dashboard(summary_seed, cfg);
                drawnow limitrate;
            end
        end

        function handle_live_monitor_progress(app, payload, cfg)
            % Consume runtime progress payloads emitted by mode loops.
            % Monitor data source chain:
            %   Mode loops emit `payload` structs -> this method normalizes fields
            %   -> app.handles.monitor_live_state ring buffers -> refresh_monitor_dashboard().
            runtime_text = app.layout_cfg.ui_text.monitor.runtime;
            if nargin < 3 || isempty(cfg)
                cfg = app.config;
            end
            if nargin < 2 || ~isstruct(payload)
                return;
            end

            channel = '';
            if isfield(payload, 'channel')
                channel = lower(app.to_text(payload.channel, ''));
            end
            if isfield(payload, 'worker_topology') && ...
                    isfield(app.handles, 'monitor_live_state') && isstruct(app.handles.monitor_live_state)
                worker_topology = app.to_text(payload.worker_topology, '');
                if strlength(string(strtrim(worker_topology))) > 0
                    app.handles.monitor_live_state.worker_topology = worker_topology;
                end
            end

            if strcmp(channel, 'log')
                log_message = app.pick_text_field(payload, {'log_message'}, '');
                if strlength(string(strtrim(log_message))) > 0
                    log_type = app.pick_text_field(payload, {'log_type'}, 'info');
                    app.append_to_terminal(log_message, log_type);
                end
                return;
            end

            if strcmp(channel, 'workflow')
                app.handle_workflow_progress_payload(payload, cfg);
                return;
            end

            if strcmp(channel, 'report')
                if isfield(payload, 'phase') && strcmpi(app.to_text(payload.phase, ''), 'failure')
                    app.cached_completion_report_payload = struct();
                    fail_id = app.pick_text_field(payload, {'failure_identifier'}, 'worker_failure');
                    fail_msg = app.pick_text_field(payload, {'failure_message'}, 'Background worker failed.');
                    app.update_launch_progress_dialog(cfg, NaN, 'Simulation Failed', fail_msg);
                    app.append_to_terminal(sprintf('Worker failure [%s]: %s', ...
                        fail_id, fail_msg), 'error');
                    if isfield(payload, 'failure_report') && ~isempty(payload.failure_report)
                        app.append_to_terminal('Detailed worker report captured by executor.', 'warning');
                    end
                    if app.has_valid_handle('run_status')
                        app.handles.run_status.Text = 'Failed';
                    end
                    app.set_phase_progress_display(NaN, 'Overall Progress');
                    app.set_child_progress_display(NaN, 'Child Job Progress');
                    return;
                end
                app.cache_completion_report_payload(payload);
                app.set_phase_progress_display(100, 'Overall Progress');
                app.set_child_progress_display(100, 'Child Job Progress');
                app.update_launch_progress_dialog(cfg, 100, 'Finalizing Results', 'Publishing outputs...');
                publication_mode = lower(app.pick_text_field(payload, {'result_publication_mode'}, 'manual'));
                host_owned = app.completion_publication_owned_by_host(payload);
                if host_owned
                    app.set_completion_finalizing_state();
                    try
                        published = app.publish_host_completion_summary(payload);
                        if published
                            app.append_to_terminal('Results tab published from the completion payload while background saves continue.', 'info');
                        end
                    catch ME
                        app.append_to_terminal(sprintf('Result publication failed: %s', ME.message), 'error');
                    end
                elseif strcmp(publication_mode, 'auto')
                    try
                        app.publish_completed_run(payload);
                    catch ME
                        app.append_to_terminal(sprintf('Result publication failed: %s', ME.message), 'error');
                    end
                end
                if ~host_owned
                    if app.has_valid_handle('run_status')
                        app.handles.run_status.Text = 'Completed';
                    end
                    if app.has_valid_handle('progress_eta_label')
                        app.handles.progress_eta_label.Text = 'ETA: 0.0s';
                    end
                end
                if isfield(app.handles, 'monitor_live_state') && isstruct(app.handles.monitor_live_state)
                    state = app.handles.monitor_live_state;
                    if host_owned
                        state.status_text = 'Finalizing results...';
                    else
                        state.status_text = 'Completed';
                    end
                    app.handles.monitor_live_state = state;
                    app.update_workflow_activity_display(state);
                end
                return;
            end

            % Check if this is a background timer update (from ParallelSimulationExecutor)
            is_background = strcmp(channel, 'metrics') || ...
                (isfield(payload, 'is_background_update') && payload.is_background_update);

            if is_background
                % Update only system metrics display from timer
                app.update_system_metrics_display(payload);
                return;
            end

            % Normal progress update from simulation
            if ~isfield(app.handles, 'monitor_live_state') || ~isstruct(app.handles.monitor_live_state)
                app.start_live_monitor_session(cfg);
            end
            update_policy = app.resolve_monitor_update_policy(cfg);
            state = app.handles.monitor_live_state;

            iter = app.progress_field(payload, {'iteration', 'step'}, NaN);
            if ~isfinite(iter)
                iter = numel(state.iters) + 1;
            end

            total_iter = app.progress_field(payload, {'total_iterations', 'total'}, NaN);
            display_iter = app.progress_field(payload, {'display_iteration'}, NaN);
            display_total_iter = app.progress_field(payload, {'display_total_iterations'}, NaN);
            display_progress_pct = app.progress_field(payload, {'display_progress_pct'}, NaN);
            payload_progress_pct = app.progress_field(payload, {'progress_pct'}, NaN);
            sim_time = app.progress_field(payload, {'time', 't'}, iter * max(cfg.dt, eps));
            wall_time = app.progress_field(payload, ...
                {'elapsed_wall', 'wall_time', 'elapsed_time', 'elapsed_seconds', 'wall_time_s'}, NaN);
            max_omega = app.progress_field(payload, {'max_vorticity', 'max_omega'}, NaN);
            energy_proxy = app.progress_field(payload, {'kinetic_energy', 'energy_proxy'}, NaN);
            enstrophy_proxy = app.progress_field(payload, {'enstrophy', 'enstrophy_proxy'}, NaN);
            conv_residual = app.progress_field(payload, {'convergence_residual', 'residual'}, NaN);
            conv_peak = app.progress_field(payload, {'convergence_residual_peak', 'convergence_metric_peak', 'xi_peak_pct'}, NaN);
            mesh_nx = app.progress_field(payload, {'mesh_nx', 'mesh_n', 'Nx', 'nx'}, NaN);
            mesh_ny = app.progress_field(payload, {'mesh_ny', 'mesh_n', 'Ny', 'ny'}, NaN);
            dt_used = app.progress_field(payload, {'dt_used', 'dt_step_used', 'dt_step', 'dt'}, NaN);
            dt_cfl = app.progress_field(payload, {'dt_cfl', 'dt_final'}, NaN);
            dt_adv = app.progress_field(payload, {'dt_adv'}, NaN);
            dt_diff = app.progress_field(payload, {'dt_diff'}, NaN);
            cfl_adv = app.progress_field(payload, {'cfl_adv'}, NaN);
            cfl_diff = app.progress_field(payload, {'cfl_diff'}, NaN);
            cfl_terminal = app.progress_field(payload, {'cfl_terminal', 'cfl_observed', 'cfl'}, NaN);
            display_mesh_nx = app.progress_field(payload, {'display_mesh_nx'}, NaN);
            display_mesh_ny = app.progress_field(payload, {'display_mesh_ny'}, NaN);
            payload_method = app.pick_text_field(payload, {'method'}, '');
            payload_mode = app.pick_text_field(payload, {'mode', 'phase'}, '');
            payload_run_id = app.pick_text_field(payload, {'run_id', 'study_id'}, '');

            cpu_pct = app.progress_field(payload, {'cpu_usage', 'cpu_percent', 'cpu_proxy'}, NaN);
            gpu_pct = app.progress_field(payload, {'gpu_usage', 'gpu_percent'}, NaN);
            cpu_temp_c = app.progress_field(payload, {'cpu_temp_c', 'cpu_temp'}, NaN);
            power_w = app.progress_field(payload, {'power_w', 'power_consumption', 'power_draw_w'}, NaN);
            energy_j = app.progress_field(payload, {'energy_joules', 'energy_j'}, NaN);

            % Keep this callback lightweight; host memory/CPU are sampled by
            % ParallelSimulationExecutor's timer and injected separately.
            mem_now = app.progress_field(payload, {'memory_usage', 'memory_mb'}, NaN);
            if ~isfinite(mem_now) && ~isempty(state.memory_series)
                mem_now = state.memory_series(end);
            end
            if ~isfinite(mem_now), mem_now = NaN; end

            workflow_active = app.is_live_monitor_workflow_kind( ...
                app.pick_text_field(state, {'workflow_kind'}, ''));
            if workflow_active
                workflow_iter = iter;
                if isfinite(display_iter)
                    workflow_iter = display_iter;
                end
                workflow_total_iter = total_iter;
                if isfinite(display_total_iter)
                    workflow_total_iter = display_total_iter;
                end
                if strlength(string(strtrim(payload_method))) > 0
                    state.workflow_child_method = payload_method;
                end
                if strlength(string(strtrim(payload_mode))) > 0
                    state.workflow_child_mode = app.normalize_mode_token(payload_mode);
                end
                if strlength(string(strtrim(payload_run_id))) > 0
                    state.workflow_child_run_id = payload_run_id;
                end
                if isfield(payload, 'display_mesh_nx')
                    if isfinite(display_mesh_nx)
                        state.workflow_child_mesh_nx = display_mesh_nx;
                    end
                elseif isfinite(mesh_nx)
                    state.workflow_child_mesh_nx = mesh_nx;
                end
                if isfield(payload, 'display_mesh_ny')
                    if isfinite(display_mesh_ny)
                        state.workflow_child_mesh_ny = display_mesh_ny;
                    end
                elseif isfinite(mesh_ny)
                    state.workflow_child_mesh_ny = mesh_ny;
                end
                if isfinite(workflow_iter)
                    state.workflow_child_iteration = workflow_iter;
                end
                if isfinite(workflow_total_iter)
                    state.workflow_child_total_iterations = workflow_total_iter;
                end
                if isfinite(conv_residual)
                    state.workflow_child_conv_residual = conv_residual;
                end
                if isfinite(conv_peak)
                    state.workflow_child_conv_peak = conv_peak;
                end
                if isfinite(dt_used)
                    state.workflow_child_dt_used = dt_used;
                end
                if isfinite(dt_cfl)
                    state.workflow_child_dt_cfl = dt_cfl;
                end
                if isfinite(dt_adv)
                    state.workflow_child_dt_adv = dt_adv;
                end
                if isfinite(dt_diff)
                    state.workflow_child_dt_diff = dt_diff;
                end
                if isfinite(cfl_adv)
                    state.workflow_child_cfl_adv = cfl_adv;
                end
                if isfinite(cfl_diff)
                    state.workflow_child_cfl_diff = cfl_diff;
                end
                if isfinite(display_progress_pct)
                    state.workflow_child_progress_pct = min(max(display_progress_pct, 0), 100);
                elseif isfinite(workflow_total_iter) && workflow_total_iter > 0
                    state.workflow_child_progress_pct = 100 * min(max(workflow_iter / workflow_total_iter, 0), 1);
                elseif isfinite(payload_progress_pct)
                    state.workflow_child_progress_pct = min(max(payload_progress_pct, 0), 100);
                elseif isfinite(workflow_iter)
                    state.workflow_child_progress_pct = NaN;
                end
                if strcmpi(app.normalize_mode_token(payload_mode), 'convergence') && isfinite(conv_residual)
                    conv_mesh_n = mesh_nx;
                    if isfield(payload, 'display_mesh_nx') && isfinite(display_mesh_nx)
                        conv_mesh_n = display_mesh_nx;
                    end
                    state = app.append_workflow_convergence_sample(state, state.workflow_child_method, conv_mesh_n, workflow_iter, conv_residual);
                end
                state.workflow_overall_progress_pct = app.compute_workflow_overall_progress_pct( ...
                    state, app.pick_field(state, {'workflow_queue_progress_pct'}, NaN));
                state = app.maybe_log_workflow_child_progress(state);
            end

            should_append = isempty(state.iters) || iter > state.iters(end) || ...
                (~isempty(state.t) && sim_time > state.t(end) + eps);
            if should_append
                state.iters(end + 1) = iter; %#ok<AGROW>
                state.t(end + 1) = sim_time; %#ok<AGROW>
                state.max_omega(end + 1) = NaN; %#ok<AGROW>
                state.energy_proxy(end + 1) = NaN; %#ok<AGROW>
                state.enstrophy_proxy(end + 1) = NaN; %#ok<AGROW>
                state.cfl_adv_series(end + 1) = NaN; %#ok<AGROW>
                state.cfl_diff_series(end + 1) = NaN; %#ok<AGROW>
                state.cfl_terminal_series(end + 1) = NaN; %#ok<AGROW>
                state.conv_x(end + 1) = iter; %#ok<AGROW>
                state.conv_residual(end + 1) = NaN; %#ok<AGROW>
                state.gpu_series(end + 1) = NaN; %#ok<AGROW>
                state.cpu_temp_c(end + 1) = NaN; %#ok<AGROW>
                state.power_w(end + 1) = NaN; %#ok<AGROW>
                state.energy_joules(end + 1) = NaN; %#ok<AGROW>
                state.energy_rate_w(end + 1) = NaN; %#ok<AGROW>
                state.memory_series(end + 1) = NaN; %#ok<AGROW>
                state.wall_clock_time(end + 1) = NaN; %#ok<AGROW>
                state.cpu_proxy(end + 1) = NaN; %#ok<AGROW>
                cpu_index = numel(state.iters);
            else
                cpu_index = max(1, numel(state.iters));
            end

            idx = cpu_index;
            state.collector_series = app.ensure_collector_series_length(state.collector_series, idx);
            state.t(idx) = sim_time;
            state.iters(idx) = iter;
            state.max_omega(idx) = max_omega;
            state.energy_proxy(idx) = energy_proxy;
            state.enstrophy_proxy(idx) = enstrophy_proxy;
            if isfinite(cfl_adv)
                state.cfl_adv_series(idx) = cfl_adv;
            end
            if isfinite(cfl_diff)
                state.cfl_diff_series(idx) = cfl_diff;
            end
            if ~isfinite(cfl_terminal)
                cfl_candidates = [cfl_adv, cfl_diff];
                cfl_candidates = cfl_candidates(isfinite(cfl_candidates));
                if ~isempty(cfl_candidates)
                    cfl_terminal = max(cfl_candidates);
                end
            end
            if isfinite(cfl_terminal)
                state.cfl_terminal_series(idx) = cfl_terminal;
            end
            state.conv_x(idx) = iter;
            state.conv_residual(idx) = conv_residual;
            state.memory_series(idx) = mem_now;
            if isfinite(gpu_pct)
                state.gpu_series(idx) = gpu_pct;
            end
            if isfinite(cpu_temp_c)
                state.cpu_temp_c(idx) = cpu_temp_c;
            end
            if isfinite(power_w)
                state.power_w(idx) = power_w;
            end

            if ~isfinite(wall_time)
                if numel(state.elapsed_wall_time) >= idx && isfinite(state.elapsed_wall_time(idx))
                    wall_time = state.elapsed_wall_time(idx);
                elseif isfield(state, 'run_start_tic') && ~isempty(state.run_start_tic)
                    wall_time = toc(state.run_start_tic);
                else
                    wall_time = max(sim_time, 0);
                end
            end
            state.elapsed_wall_time(idx) = wall_time;
            wall_clock_now = app.progress_field(payload, {'wall_clock_time'}, NaN);
            if ~isfinite(wall_clock_now)
                wall_clock_now = posixtime(datetime('now', 'TimeZone', 'UTC'));
            end
            state.wall_clock_time(idx) = wall_clock_now;

            if idx >= 2
                dt = max(state.t(idx) - state.t(idx - 1), eps);
                di = max(state.iters(idx) - state.iters(idx - 1), 0);
                iter_rate_now = di / dt;
            else
                iter_rate_now = NaN;
            end
            state.iter_rate(idx) = iter_rate_now;
            if ~isfinite(cpu_pct)
                cpu_pct = app.live_cpu_proxy(iter_rate_now);
            end
            state.cpu_proxy(idx) = cpu_pct;

            prev_energy = NaN;
            prev_wall = NaN;
            if idx >= 2
                if numel(state.energy_joules) >= idx - 1
                    prev_energy = state.energy_joules(idx - 1);
                end
                if numel(state.elapsed_wall_time) >= idx - 1
                    prev_wall = state.elapsed_wall_time(idx - 1);
                end
            end

            if isfinite(energy_j)
                state.energy_joules(idx) = energy_j;
            elseif isfinite(power_w) && isfinite(wall_time)
                if isfinite(prev_energy) && isfinite(prev_wall)
                    delta_t = max(wall_time - prev_wall, 0);
                    state.energy_joules(idx) = prev_energy + max(power_w, 0) * delta_t;
                else
                    state.energy_joules(idx) = max(power_w, 0) * max(wall_time, 0);
                end
            else
                state.energy_joules(idx) = NaN;
            end

            if isfinite(power_w)
                state.energy_rate_w(idx) = power_w;
            elseif idx >= 2 && isfinite(state.energy_joules(idx)) && isfinite(prev_energy) && isfinite(prev_wall)
                dt_wall = max(wall_time - prev_wall, eps);
                state.energy_rate_w(idx) = max((state.energy_joules(idx) - prev_energy) / dt_wall, 0);
            else
                state.energy_rate_w(idx) = NaN;
            end

            progress_iter = iter;
            progress_total_iter = total_iter;
            progress_pct = NaN;
            if workflow_active
                if isfinite(display_iter)
                    progress_iter = display_iter;
                end
                if isfinite(display_total_iter)
                    progress_total_iter = display_total_iter;
                end
                if isfinite(display_progress_pct)
                    progress_pct = min(max(display_progress_pct, 0), 100);
                end
            end

            if isfinite(progress_total_iter) && progress_total_iter > 0
                state.total_iterations = progress_total_iter;
                if ~isfinite(progress_pct)
                    progress_pct = 100 * min(max(progress_iter / progress_total_iter, 0), 1);
                end
                state.iter_completion_pct(idx) = progress_pct;
            else
                denom = max(state.iters(end), 1);
                state.iter_completion_pct(idx) = 100 * min(max(iter / denom, 0), 1);
            end

            if idx >= 2
                dt_live = max(state.t(idx) - state.t(idx - 1), eps);
                domega = abs(state.max_omega(idx)) - abs(state.max_omega(idx - 1));
                state.vorticity_decay_rate(idx) = max(0, -domega / dt_live);
            else
                state.vorticity_decay_rate(idx) = NaN;
            end
            if ~isfinite(state.vorticity_decay_rate(idx))
                state.vorticity_decay_rate(idx) = 0;
            end
            state.stability_proxy(idx) = 1 / (1 + abs(state.vorticity_decay_rate(idx)));
            state = app.stamp_workflow_context_sample(state, idx, cfg);

            if isfinite(progress_total_iter) && progress_total_iter > 0
                if ~isfinite(progress_pct)
                    progress_pct = 100 * min(max(progress_iter / progress_total_iter, 0), 1);
                end
                is_solver_complete = progress_iter >= progress_total_iter || progress_pct >= 99.999;
                if is_solver_complete
                    state.status_text = 'Publishing results...';
                else
                    state.status_text = sprintf('Running %d/%d (%6.2f%%)', ...
                        round(progress_iter), round(progress_total_iter), progress_pct);
                end
                if workflow_active
                    app.set_phase_progress_display(app.pick_field(state, {'workflow_overall_progress_pct'}, NaN), 'Phase Queue Progress');
                    app.set_child_progress_display(app.pick_field(state, {'workflow_child_progress_pct'}, progress_pct), ...
                        app.build_workflow_child_progress_label(state));
                else
                    app.set_phase_progress_display(progress_pct, 'Run Progress');
                    app.set_child_progress_display(progress_pct, 'Child Job Progress');
                end
                if app.has_valid_handle('run_status')
                    if workflow_active
                        workflow_pct = app.pick_field(state, {'workflow_overall_progress_pct'}, NaN);
                        if isfinite(workflow_pct)
                            app.handles.run_status.Text = sprintf('%6.2f%%', workflow_pct);
                        else
                            app.handles.run_status.Text = state.status_text;
                        end
                    else
                        if is_solver_complete
                            app.handles.run_status.Text = state.status_text;
                        else
                            app.handles.run_status.Text = sprintf('%6.2f%%', progress_pct);
                        end
                    end
                end
                if app.has_valid_handle('progress_eta_label')
                    if is_solver_complete
                        app.handles.progress_eta_label.Text = 'Publishing results...';
                    else
                        iter_rate_eta = iter_rate_now;
                        if ~(isfinite(iter_rate_eta) && iter_rate_eta > 0)
                            iter_rate_eta = app.last_finite_from_series(state, 'iter_rate');
                        end
                        if isfinite(iter_rate_eta) && iter_rate_eta > 0
                            eta_s = max(progress_total_iter - progress_iter, 0) / iter_rate_eta;
                            app.handles.progress_eta_label.Text = sprintf('ETA: %.1fs', eta_s);
                        else
                            app.handles.progress_eta_label.Text = 'ETA: --';
                        end
                    end
                end
            else
                state.status_text = sprintf(runtime_text.running_iteration_pattern, round(iter));
                if workflow_active
                    app.set_phase_progress_display(app.pick_field(state, {'workflow_overall_progress_pct'}, NaN), 'Phase Queue Progress');
                    app.set_child_progress_display(app.pick_field(state, {'workflow_child_progress_pct'}, NaN), ...
                        app.build_workflow_child_progress_label(state));
                else
                    app.set_phase_progress_display(NaN, 'Run Progress');
                    app.set_child_progress_display(NaN, 'Child Job Progress');
                end
                if app.has_valid_handle('run_status')
                    app.handles.run_status.Text = state.status_text;
                end
                if app.has_valid_handle('progress_eta_label')
                    app.handles.progress_eta_label.Text = 'ETA: --';
                end
            end

            state = app.trim_live_monitor_history(state, update_policy.max_history_points);
            state.update_counter = state.update_counter + 1;
            if ~isfield(state, 'last_refresh_tic') || isempty(state.last_refresh_tic)
                state.last_refresh_tic = tic;
            end

            is_final_step = false;
            if isfinite(total_iter) && total_iter > 0
                is_final_step = iter >= total_iter;
            end
            elapsed_since_refresh = toc(state.last_refresh_tic);
            stride_hit = mod(state.update_counter, max(1, update_policy.refresh_stride)) == 0;
            cadence_hit = mod(state.update_counter, max(1, update_policy.force_refresh_every)) == 0;
            time_hit = elapsed_since_refresh >= max(update_policy.min_refresh_seconds, 0);
            should_refresh = stride_hit || cadence_hit || time_hit || is_final_step;

            app.handles.monitor_live_state = state;
            app.update_workflow_activity_display(state);
            if should_refresh
                if ~app.is_progress_only_launch(cfg)
                    summary_live = struct('results', struct('max_omega', max_omega), ...
                        'monitor_series', app.collect_live_monitor_series_for_summary(struct('monitor_series', state)));
                    app.refresh_monitor_dashboard(summary_live, cfg);
                end
                app.handles.monitor_live_state.last_refresh_tic = tic;
            end

            if workflow_active
                app.update_launch_progress_dialog(cfg, ...
                    app.pick_field(state, {'workflow_overall_progress_pct'}, NaN), ...
                    'Phase Workflow Progress', ...
                    app.build_workflow_child_progress_label(state));
            elseif isfinite(progress_pct)
                app.update_launch_progress_dialog(cfg, progress_pct, 'Simulation Progress', state.status_text);
            else
                app.update_launch_progress_dialog(cfg, NaN, 'Simulation Progress', state.status_text);
            end

            if should_refresh
                drawnow limitrate nocallbacks;
            end
        end

        function handle_workflow_progress_payload(app, payload, cfg)
            if nargin < 3 || isempty(cfg)
                cfg = app.config;
            end
            if ~isfield(app.handles, 'monitor_live_state') || ~isstruct(app.handles.monitor_live_state)
                app.start_live_monitor_session(cfg);
            end

            state = app.handles.monitor_live_state;
            status_text = app.pick_text_field(payload, {'status_text'}, 'Workflow running');
            stage_name = app.pick_text_field(payload, {'stage_name'}, 'workflow');
            stage_index = app.progress_field(payload, {'stage_index'}, NaN);
            stage_total = app.progress_field(payload, {'stage_total'}, NaN);
            queue_index = app.progress_field(payload, {'queue_index'}, NaN);
            queue_total = app.progress_field(payload, {'queue_total'}, NaN);
            queue_progress_pct = app.progress_field(payload, {'workflow_overall_progress_pct', 'progress_pct'}, NaN);
            elapsed_wall = app.progress_field(payload, {'elapsed_wall', 'elapsed_time'}, NaN);
            terminal_message = app.pick_text_field(payload, {'terminal_message'}, '');
            event_key = app.pick_text_field(payload, {'event_key'}, '');
            workflow_kind = app.pick_text_field(payload, {'workflow_kind'}, '');
            workflow_phase_id = app.pick_text_field(payload, {'phase_id'}, '');
            current_job_key = app.pick_text_field(payload, {'job_key'}, '');
            current_job_label = app.pick_text_field(payload, {'job_label'}, '');
            current_status = app.pick_text_field(payload, {'status'}, '');
            stage_id = app.pick_text_field(payload, {'stage_id', 'job_key'}, '');
            stage_label = app.pick_text_field(payload, {'stage_label', 'job_label'}, '');
            stage_type = app.pick_text_field(payload, {'stage_type', 'mode'}, '');
            child_method = app.pick_text_field(payload, {'method'}, '');
            child_mode = app.pick_text_field(payload, {'mode'}, '');
            child_run_id = app.pick_text_field(payload, {'child_run_id'}, '');
            child_mesh_nx = app.progress_field(payload, {'mesh_nx'}, NaN);
            child_mesh_ny = app.progress_field(payload, {'mesh_ny'}, NaN);
            scenario_id = app.pick_text_field(payload, {'scenario_id', 'phase_scenario_id'}, '');
            mesh_level = app.progress_field(payload, {'mesh_level'}, NaN);
            mesh_index = app.progress_field(payload, {'mesh_index'}, NaN);
            workflow_test_case_setup = app.pick_text_field(payload, {'test_case_setup'}, '');
            workflow_current_scenario = app.pick_text_field(payload, {'scenario_label', 'current_scenario'}, '');
            child_artifact_root = app.pick_text_field(payload, {'child_artifact_root', 'artifact_root'}, '');
            child_figures_root = app.pick_text_field(payload, {'child_figures_root', 'figures_root'}, '');
            child_reports_root = app.pick_text_field(payload, {'child_reports_root', 'reports_root'}, '');
            queue_row = struct();
            queue_row_found = false;
            if isfield(payload, 'queue_status') && isstruct(payload.queue_status) && ...
                    ~isempty(payload.queue_status) && isfield(payload.queue_status, 'queue_index')
                if isfinite(queue_index)
                    idx_match = find([payload.queue_status.queue_index] == queue_index, 1, 'first');
                    if isempty(idx_match) && strlength(string(strtrim(current_job_key))) > 0
                        if isfield(payload.queue_status, 'job_key')
                            idx_match = find(strcmp({payload.queue_status.job_key}, current_job_key), 1, 'first');
                        end
                    end
                    if ~isempty(idx_match)
                        queue_row = payload.queue_status(idx_match);
                        queue_row_found = true;
                    end
                end
            end
            if queue_row_found
                if strlength(string(strtrim(child_method))) == 0
                    child_method = app.pick_text_field(queue_row, {'method'}, '');
                end
                if strlength(string(strtrim(child_mode))) == 0
                    child_mode = app.pick_text_field(queue_row, {'mode'}, '');
                end
                if strlength(string(strtrim(child_run_id))) == 0
                    child_run_id = app.pick_text_field(queue_row, {'run_id'}, '');
                end
                if strlength(string(strtrim(stage_id))) == 0
                    stage_id = app.pick_text_field(queue_row, {'job_key'}, '');
                end
                if strlength(string(strtrim(stage_label))) == 0
                    stage_label = app.pick_text_field(queue_row, {'job_label'}, '');
                end
                if strlength(string(strtrim(stage_type))) == 0
                    stage_type = app.pick_text_field(queue_row, {'mode'}, '');
                end
                if strlength(string(strtrim(scenario_id))) == 0
                    scenario_id = app.pick_text_field(queue_row, {'scenario_id'}, '');
                end
                if ~isfinite(child_mesh_nx)
                    child_mesh_nx = app.progress_field(queue_row, {'mesh_nx'}, NaN);
                end
                if ~isfinite(child_mesh_ny)
                    child_mesh_ny = app.progress_field(queue_row, {'mesh_ny'}, NaN);
                end
                if strlength(string(strtrim(workflow_test_case_setup))) == 0
                    workflow_test_case_setup = app.pick_text_field(queue_row, {'test_case_setup'}, '');
                end
                if strlength(string(strtrim(workflow_current_scenario))) == 0
                    workflow_current_scenario = app.pick_text_field(queue_row, {'scenario_label', 'job_label'}, '');
                end
                if strlength(string(strtrim(child_artifact_root))) == 0
                    child_artifact_root = app.pick_text_field(queue_row, {'artifact_root'}, '');
                end
                if strlength(string(strtrim(child_figures_root))) == 0
                    child_figures_root = app.pick_text_field(queue_row, {'figures_root'}, '');
                end
                if strlength(string(strtrim(child_reports_root))) == 0
                    child_reports_root = app.pick_text_field(queue_row, {'reports_root'}, '');
                end
            end
            job_changed = ~strcmp(app.pick_text_field(state, {'workflow_current_job_key'}, ''), current_job_key);

            state.status_text = status_text;
            state.workflow_kind = workflow_kind;
            state.workflow_phase_id = workflow_phase_id;
            state.workflow_queue_progress_pct = queue_progress_pct;
            state.workflow_stage_name = stage_name;
            state.workflow_stage_index = stage_index;
            state.workflow_stage_total = stage_total;
            state.workflow_stage_id = app.if_empty(stage_id, 'single_run');
            state.workflow_stage_label = app.if_empty(stage_label, app.if_empty(current_job_label, 'Single Run'));
            state.workflow_stage_type = app.normalize_mode_token(app.if_empty(stage_type, stage_name));
            state.workflow_method = app.if_empty(child_method, app.pick_text_field(cfg, {'method'}, ''));
            state.workflow_scenario_id = app.if_empty(scenario_id, '');
            state.workflow_mesh_level = mesh_level;
            state.workflow_mesh_index = mesh_index;
            state.workflow_child_run_index = queue_index;
            state.workflow_current_job_key = current_job_key;
            state.workflow_current_job_label = current_job_label;
            state.workflow_current_status = current_status;
            if isfield(payload, 'queue_status') && isstruct(payload.queue_status)
                state.workflow_queue = payload.queue_status;
            end
            if job_changed
                state.workflow_child_progress_pct = NaN;
                state.workflow_child_run_id = '';
                state.workflow_child_mesh_nx = NaN;
                state.workflow_child_mesh_ny = NaN;
                state.workflow_child_iteration = NaN;
                state.workflow_child_total_iterations = NaN;
                state.workflow_child_conv_residual = NaN;
                state.workflow_child_conv_peak = NaN;
                state.workflow_child_dt_used = NaN;
                state.workflow_child_dt_cfl = NaN;
                state.workflow_child_dt_adv = NaN;
                state.workflow_child_dt_diff = NaN;
                state.workflow_child_cfl_adv = NaN;
                state.workflow_child_cfl_diff = NaN;
                state.workflow_test_case_setup = '';
                state.workflow_current_scenario = '';
                state.workflow_child_artifact_root = '';
                state.workflow_child_figures_root = '';
                state.workflow_child_reports_root = '';
                state.last_convergence_terminal_key = '';
                state.last_workflow_child_progress_log_key = '';
                state.last_workflow_child_iteration_log_key = '';
            end
            if strlength(string(strtrim(child_method))) > 0
                state.workflow_child_method = child_method;
                state.workflow_method = child_method;
            end
            if strlength(string(strtrim(child_mode))) > 0
                state.workflow_child_mode = app.normalize_mode_token(child_mode);
            end
            if strlength(string(strtrim(child_run_id))) > 0
                state.workflow_child_run_id = child_run_id;
            end
            if isfinite(child_mesh_nx)
                state.workflow_child_mesh_nx = child_mesh_nx;
            end
            if isfinite(child_mesh_ny)
                state.workflow_child_mesh_ny = child_mesh_ny;
            end
            if isfinite(mesh_level)
                state.workflow_mesh_level = mesh_level;
            end
            if isfinite(mesh_index)
                state.workflow_mesh_index = mesh_index;
            end
            if isfinite(queue_index)
                state.workflow_child_run_index = queue_index;
            end
            if strlength(string(strtrim(workflow_test_case_setup))) > 0
                state.workflow_test_case_setup = workflow_test_case_setup;
            end
            if strlength(string(strtrim(workflow_current_scenario))) > 0
                state.workflow_current_scenario = workflow_current_scenario;
                if isempty(strtrim(state.workflow_scenario_id))
                    state.workflow_scenario_id = workflow_current_scenario;
                end
            elseif strlength(string(strtrim(current_job_label))) > 0
                state.workflow_current_scenario = current_job_label;
            end
            if strlength(string(strtrim(child_artifact_root))) > 0
                state.workflow_child_artifact_root = child_artifact_root;
            end
            if strlength(string(strtrim(child_figures_root))) > 0
                state.workflow_child_figures_root = child_figures_root;
            end
            if strlength(string(strtrim(child_reports_root))) > 0
                state.workflow_child_reports_root = child_reports_root;
            end
            if any(strcmpi(current_status, {'queued', 'running'})) && ~isfinite(state.workflow_child_progress_pct)
                state.workflow_child_progress_pct = 0;
            elseif strcmpi(current_status, 'completed')
                state.workflow_child_progress_pct = 100;
            end

            if ~isempty(event_key) && ~strcmp(state.last_workflow_event_key, event_key)
                state.last_workflow_event_key = event_key;
                state = app.log_workflow_ui_event(state, terminal_message, 'info');
                if any(strcmpi(current_status, {'completed', 'failed'}))
                    workflow_label = app.workflow_phase_display_name(workflow_kind);
                    if strlength(string(strtrim(child_artifact_root))) > 0
                        state = app.log_workflow_ui_event(state, ...
                            sprintf('%s child artifacts: %s', workflow_label, child_artifact_root), 'info');
                    end
                    if strlength(string(strtrim(child_figures_root))) > 0
                        state = app.log_workflow_ui_event(state, ...
                            sprintf('%s child figures: %s', workflow_label, child_figures_root), 'info');
                    end
                    if strlength(string(strtrim(child_reports_root))) > 0
                        state = app.log_workflow_ui_event(state, ...
                            sprintf('%s child reports: %s', workflow_label, child_reports_root), 'info');
                    end
                end
            end

            state.workflow_overall_progress_pct = app.compute_workflow_overall_progress_pct(state, queue_progress_pct);

            idx = max(1, numel(state.t));
            if isempty(state.t)
                state.t(1) = 0;
                state.iters(1) = 0;
                idx = 1;
            end

            if isfinite(elapsed_wall)
                state.elapsed_wall_time(idx) = elapsed_wall;
                if app.has_valid_handle('monitor_elapsed_label')
                    app.handles.monitor_elapsed_label.Text = sprintf('Elapsed: %8.2f s', elapsed_wall);
                end
            end
            state.wall_clock_time(idx) = posixtime(datetime('now', 'TimeZone', 'UTC'));

            if isfinite(state.workflow_overall_progress_pct) && app.has_valid_handle('progress_gauge')
                app.set_phase_progress_display(state.workflow_overall_progress_pct, 'Phase Queue Progress');
            else
                app.set_phase_progress_display(NaN, 'Phase Queue Progress');
            end
            child_progress_pct = app.pick_field(state, {'workflow_child_progress_pct'}, NaN);
            child_label = app.build_workflow_child_progress_label(state);
            app.set_child_progress_display(child_progress_pct, child_label);
            if isfinite(state.workflow_overall_progress_pct) && app.has_valid_handle('run_status')
                app.handles.run_status.Text = sprintf('%6.2f%%', state.workflow_overall_progress_pct);
            elseif app.has_valid_handle('run_status')
                app.handles.run_status.Text = status_text;
            end

            if app.has_valid_handle('progress_eta_label')
                if isfinite(queue_index) && isfinite(queue_total) && queue_total > 0
                    app.handles.progress_eta_label.Text = sprintf('Queue: %d/%d', round(queue_index), round(queue_total));
                elseif isfinite(stage_index) && isfinite(stage_total) && stage_total > 0
                    app.handles.progress_eta_label.Text = sprintf('Stage: %d/%d', round(stage_index), round(stage_total));
                else
                    app.handles.progress_eta_label.Text = 'Stage: --';
                end
            end

            app.handles.monitor_live_state = state;
            app.update_workflow_activity_display(state);
            app.update_launch_progress_dialog(cfg, ...
                state.workflow_overall_progress_pct, ...
                'Phase Workflow Progress', ...
                app.build_workflow_child_progress_label(state));
            if ~app.is_progress_only_launch(cfg)
                summary_live = struct( ...
                    'results', struct('max_omega', app.last_finite_from_series(state, 'max_omega')), ...
                    'monitor_series', app.collect_live_monitor_series_for_summary(struct('monitor_series', state)));
                app.refresh_monitor_dashboard(summary_live, cfg);
            end
            if isfield(app.handles, 'monitor_live_state') && isstruct(app.handles.monitor_live_state)
                app.handles.monitor_live_state.last_refresh_tic = tic;
            end
            drawnow limitrate nocallbacks;
        end

        function update_system_metrics_display(app, payload)
            % Update system metrics displays from background timer updates
            % This is called by ParallelSimulationExecutor's monitoring timer

            if ~isfield(app.handles, 'monitor_live_state') || ~isstruct(app.handles.monitor_live_state)
                return;
            end
            payload = app.normalize_monitor_series_collector_payload(payload);
            state = app.handles.monitor_live_state;
            [state, idx] = app.prepare_background_metrics_slot(state, payload);

            % Update CPU usage if available
            if isfield(payload, 'cpu_usage') && isfinite(payload.cpu_usage)
                if app.has_valid_handle('monitor_cpu_label')
                    app.handles.monitor_cpu_label.Text = sprintf('CPU: %6.2f%%', payload.cpu_usage);
                end
                state.cpu_proxy(idx) = payload.cpu_usage;
            end

            % Update memory usage
            if isfield(payload, 'memory_usage') && isfinite(payload.memory_usage)
                if app.has_valid_handle('monitor_memory_label')
                    app.handles.monitor_memory_label.Text = sprintf('Memory: %8.2f MB', payload.memory_usage);
                end
                state.memory_series(idx) = payload.memory_usage;
            end

            if isfield(payload, 'matlab_cpu_usage') && isfinite(payload.matlab_cpu_usage)
                state.collector_series.matlab.cpu_proxy(idx) = payload.matlab_cpu_usage;
            end
            if isfield(payload, 'matlab_memory_usage') && isfinite(payload.matlab_memory_usage)
                state.collector_series.matlab.memory_series(idx) = payload.matlab_memory_usage;
            end
            if isfield(payload, 'matlab_gpu_usage') && isfinite(payload.matlab_gpu_usage)
                state.collector_series.matlab.gpu_series(idx) = payload.matlab_gpu_usage;
            end

            if isfield(payload, 'gpu_usage') && isfinite(payload.gpu_usage)
                state.gpu_series(idx) = payload.gpu_usage;
            end
            if isfield(payload, 'cpu_temp_c') && isfinite(payload.cpu_temp_c)
                state.cpu_temp_c(idx) = payload.cpu_temp_c;
            end
            if isfield(payload, 'cpu_temp_c') && isfinite(payload.cpu_temp_c) && ...
                    isfield(payload, 'matlab_cpu_usage')
                state.collector_series.matlab.cpu_temp_c(idx) = NaN;
            end
            power_payload = NaN;
            if isfield(payload, 'power_w') && isfinite(payload.power_w)
                power_payload = payload.power_w;
            elseif isfield(payload, 'cpu_usage') && isfinite(payload.cpu_usage)
                load_pct = min(max(double(payload.cpu_usage), 0), 100);
                power_payload = 45 + (load_pct / 100) * (220 - 45);
            end
            if isfinite(power_payload)
                state.power_w(idx) = power_payload;
            end
            if isfield(payload, 'matlab_power_w') && isfinite(payload.matlab_power_w)
                state.collector_series.matlab.power_w(idx) = payload.matlab_power_w;
            end

            if isfield(payload, 'collector_series') && isstruct(payload.collector_series)
                state.collector_series = app.store_collector_series_sample( ...
                    state.collector_series, payload.collector_series, idx);
            end
            if isfield(payload, 'collector_status') && isstruct(payload.collector_status)
                state.collector_status = payload.collector_status;
                state.collector_status.matlab = 'connected';
            end
            if isfield(payload, 'coverage_domains') && isstruct(payload.coverage_domains)
                state.coverage_domains = payload.coverage_domains;
            end
            if isfield(payload, 'preferred_source') && isstruct(payload.preferred_source)
                state.preferred_source = payload.preferred_source;
            end
            if isfield(payload, 'raw_log_paths') && isstruct(payload.raw_log_paths)
                state.raw_log_paths = payload.raw_log_paths;
            end
            if isfield(payload, 'overlay_metrics') && ~isempty(payload.overlay_metrics)
                state.overlay_metrics = payload.overlay_metrics;
            end
            if isfield(payload, 'collector_metric_catalog') && ~isempty(payload.collector_metric_catalog)
                state.collector_metric_catalog = payload.collector_metric_catalog;
            end
            if isfield(payload, 'hwinfo_transport')
                state.hwinfo_transport = app.to_text(payload.hwinfo_transport, '');
            end
            if isfield(payload, 'hwinfo_status_reason')
                state.hwinfo_status_reason = app.to_text(payload.hwinfo_status_reason, '');
            end
            if isfield(payload, 'collector_probe_details') && isstruct(payload.collector_probe_details)
                state.collector_probe_details = payload.collector_probe_details;
            end

            % Update elapsed time
            elapsed_wall = app.progress_field(payload, {'elapsed_wall', 'elapsed_time'}, NaN);
            if isfinite(elapsed_wall)
                if app.has_valid_handle('monitor_elapsed_label')
                    app.handles.monitor_elapsed_label.Text = sprintf('Elapsed: %8.2f s', elapsed_wall);
                end
                state.elapsed_wall_time(idx) = elapsed_wall;
                if numel(state.t) < idx || ~isfinite(state.t(idx))
                    state.t(idx) = elapsed_wall;
                end
            end
            wall_clock_now = app.progress_field(payload, {'wall_clock_time'}, NaN);
            if ~isfinite(wall_clock_now)
                wall_clock_now = posixtime(datetime('now', 'TimeZone', 'UTC'));
            end
            state.wall_clock_time(idx) = wall_clock_now;

            if isfield(payload, 'energy_joules') && isfinite(payload.energy_joules)
                state.energy_joules(idx) = payload.energy_joules;
            elseif isfinite(power_payload) && ...
                    isfinite(elapsed_wall) && idx >= 2 && numel(state.elapsed_wall_time) >= idx - 1 && ...
                    isfinite(state.elapsed_wall_time(idx - 1))
                delta_t = max(elapsed_wall - state.elapsed_wall_time(idx - 1), 0);
                prev_energy = NaN;
                if numel(state.energy_joules) >= idx - 1
                    prev_energy = state.energy_joules(idx - 1);
                end
                if isfinite(prev_energy)
                    state.energy_joules(idx) = prev_energy + max(power_payload, 0) * delta_t;
                else
                    state.energy_joules(idx) = max(power_payload, 0) * max(elapsed_wall, 0);
                end
            end
            if isfinite(power_payload)
                state.energy_rate_w(idx) = power_payload;
            end

            workflow_active = app.is_live_monitor_workflow_kind( ...
                app.pick_text_field(state, {'workflow_kind'}, ''));
            if isfield(payload, 'progress_pct') && isfinite(payload.progress_pct) && app.has_valid_handle('run_status')
                if workflow_active
                    workflow_pct = app.pick_field(state, {'workflow_overall_progress_pct'}, NaN);
                    child_pct = app.pick_field(state, {'workflow_child_progress_pct'}, NaN);
                    child_label = app.build_workflow_child_progress_label(state);
                    app.set_phase_progress_display(workflow_pct, 'Phase Queue Progress');
                    app.set_child_progress_display(child_pct, child_label);
                    if isfinite(workflow_pct)
                        app.handles.run_status.Text = sprintf('%6.2f%%', workflow_pct);
                    else
                        app.handles.run_status.Text = app.pick_text_field(state, {'status_text'}, 'Running');
                    end
                    if isfinite(child_pct)
                        state.iter_completion_pct(idx) = child_pct;
                    end
                else
                    app.set_phase_progress_display(payload.progress_pct, 'Run Progress');
                    app.set_child_progress_display(payload.progress_pct, 'Child Job Progress');
                    app.handles.run_status.Text = sprintf('%6.2f%%', payload.progress_pct);
                    state.iter_completion_pct(idx) = payload.progress_pct;
                end
            end

            runtime_metrics = struct( ...
                'cpu_proxy', app.progress_field(payload, {'cpu_usage'}, NaN), ...
                'gpu_series', app.progress_field(payload, {'gpu_usage'}, NaN), ...
                'cpu_temp_c', app.progress_field(payload, {'cpu_temp_c'}, NaN), ...
                'power_w', power_payload, ...
                'fan_rpm', app.last_collector_metric_sample(payload, 'hwinfo', 'fan_rpm', NaN), ...
                'pump_rpm', app.last_collector_metric_sample(payload, 'hwinfo', 'pump_rpm', NaN));
            runtime_sample = payload;
            runtime_sample.metrics = runtime_metrics;
            app.store_collector_probe_runtime_state('all', runtime_sample);
            app.handles.monitor_live_state = state;
            app.refresh_collector_probe_status('runtime');
            app.update_workflow_activity_display(state);
            if app.is_progress_only_launch(app.config)
                workflow_pct = app.pick_field(state, {'workflow_overall_progress_pct'}, NaN);
                child_label = app.build_workflow_child_progress_label(state);
                if workflow_active
                    app.update_launch_progress_dialog(app.config, workflow_pct, 'Phase Workflow Progress', child_label);
                elseif isfield(payload, 'progress_pct') && isfinite(payload.progress_pct)
                    app.update_launch_progress_dialog(app.config, payload.progress_pct, 'Simulation Progress', ...
                        app.pick_text_field(state, {'status_text'}, 'Running'));
                end
            end
            if isfield(state, 'last_refresh_tic') && ~isempty(state.last_refresh_tic) && toc(state.last_refresh_tic) >= 0.4
                if ~app.is_progress_only_launch(app.config)
                    summary_live = struct('results', struct(), 'monitor_series', ...
                        app.collect_live_monitor_series_for_summary(struct('monitor_series', state)));
                    app.refresh_monitor_dashboard(summary_live, app.config);
                end
                app.handles.monitor_live_state.last_refresh_tic = tic;
                drawnow limitrate nocallbacks;
            end
        end

        function [state, idx] = prepare_background_metrics_slot(app, state, payload)
            if ~isfield(state, 't') || isempty(state.t)
                state.t(1) = 0;
            end
            if ~isfield(state, 'iters') || isempty(state.iters)
                state.iters(1) = 0;
            end

            idx = max(1, numel(state.t));
            elapsed_wall = app.progress_field(payload, {'elapsed_wall', 'elapsed_time'}, NaN);
            last_elapsed = NaN;
            if isfield(state, 'elapsed_wall_time') && isnumeric(state.elapsed_wall_time) && ~isempty(state.elapsed_wall_time)
                finite_elapsed = state.elapsed_wall_time(isfinite(state.elapsed_wall_time));
                if ~isempty(finite_elapsed)
                    last_elapsed = finite_elapsed(end);
                end
            end

            if isfinite(elapsed_wall) && isfinite(last_elapsed)
                tol = max(1e-6, eps(max(abs([elapsed_wall, last_elapsed, 1]))));
                if elapsed_wall > last_elapsed + tol
                    state = app.append_background_metrics_slot(state);
                    idx = numel(state.t);
                end
            end

            state.collector_series = app.ensure_collector_series_length(state.collector_series, idx);
        end

        function state = append_background_metrics_slot(app, state)
            if ~isfield(state, 't') || isempty(state.t)
                state.t = 0;
            end
            if ~isfield(state, 'iters') || isempty(state.iters)
                state.iters = 0;
            end

            prev_idx = max(1, numel(state.t));
            vec_fields = {'t', 'iters', 'iter_rate', 'max_omega', 'energy_proxy', ...
                'enstrophy_proxy', 'cfl_adv_series', 'cfl_diff_series', 'cfl_terminal_series', ...
                'cpu_proxy', 'gpu_series', 'cpu_temp_c', 'power_w', ...
                'cpu_voltage_v', 'gpu_voltage_v', 'memory_voltage_v', ...
                'cpu_power_w_hwinfo', 'gpu_power_w_hwinfo', 'memory_power_w_or_proxy', ...
                'system_power_w', 'environmental_energy_wh_cum', 'environmental_co2_g_cum', ...
                'energy_joules', 'energy_rate_w', 'memory_series', 'elapsed_wall_time', ...
                'wall_clock_time', 'iter_completion_pct', 'vorticity_decay_rate', ...
                'stability_proxy', 'conv_x', 'conv_residual'};
            for i = 1:numel(vec_fields)
                key = vec_fields{i};
                if ~isfield(state, key) || ~isnumeric(state.(key))
                    state.(key) = nan(1, prev_idx);
                end
                vec = state.(key);
                if numel(vec) < prev_idx
                    vec(end + 1:prev_idx) = nan;
                end
                vec(prev_idx + 1) = vec(prev_idx);
                state.(key) = vec;
            end

            state.collector_series = app.ensure_collector_series_length(state.collector_series, prev_idx + 1);
        end

        function value = progress_field(~, payload, field_names, fallback)
            % First available scalar numeric field from payload, else fallback.
            value = fallback;
            for i = 1:numel(field_names)
                key = field_names{i};
                if isfield(payload, key)
                    candidate = payload.(key);
                    if isnumeric(candidate) && isscalar(candidate) && isfinite(candidate)
                        value = candidate;
                        return;
                    end
                end
            end
        end

        function cpu_pct = live_cpu_proxy(~, iter_rate_now)
            % Lightweight throughput proxy for monitor continuity when no sensor feed is active.
            if ~isfinite(iter_rate_now) || iter_rate_now <= 0
                cpu_pct = NaN;
                return;
            end
            cpu_pct = max(0, min(100, 20 + 10 * log10(1 + iter_rate_now)));
        end

        function bar = terminal_progress_bar(~, pct, width)
            if nargin < 3 || ~isfinite(width) || width < 4
                width = 12;
            end
            p = max(0, min(100, double(pct)));
            filled = round((p / 100) * width);
            bar = ['[', repmat('#', 1, filled), repmat('-', 1, width - filled), ']'];
        end

        function set_phase_progress_display(app, progress_pct, label_text)
            label_text = app.to_text(label_text, 'Overall Progress');
            if nargin < 3 || strlength(string(strtrim(label_text))) == 0
                label_text = 'Overall Progress';
            end
            if app.has_valid_handle('phase_progress_label')
                app.handles.phase_progress_label.Text = label_text;
            end
            if isfinite(progress_pct)
                if app.has_valid_handle('progress_gauge')
                    app.handles.progress_gauge.Value = progress_pct;
                end
                if app.has_valid_handle('phase_progress_value')
                    app.handles.phase_progress_value.Text = sprintf('%6.2f%%', progress_pct);
                end
            else
                if app.has_valid_handle('phase_progress_value')
                    app.handles.phase_progress_value.Text = '--';
                end
            end
        end

        function set_child_progress_display(app, progress_pct, label_text)
            label_text = app.to_text(label_text, 'Child Job Progress');
            if nargin < 3 || strlength(string(strtrim(label_text))) == 0
                label_text = 'Child Job Progress';
            end
            if app.has_valid_handle('child_progress_label')
                app.handles.child_progress_label.Text = label_text;
            end
            if isfinite(progress_pct)
                if app.has_valid_handle('child_progress_gauge')
                    app.handles.child_progress_gauge.Value = progress_pct;
                end
                if app.has_valid_handle('child_progress_value')
                    app.handles.child_progress_value.Text = sprintf('%6.2f%%', progress_pct);
                end
            else
                if app.has_valid_handle('child_progress_value')
                    app.handles.child_progress_value.Text = '--';
                end
            end
        end

        function label_text = build_workflow_child_progress_label(app, state)
            if nargin < 2 || ~isstruct(state)
                label_text = 'Child Job: active';
                return;
            end
            detail = app.describe_workflow_current_activity(state);
            if strlength(string(strtrim(detail))) == 0
                detail = app.pick_text_field(state, {'workflow_current_job_label'}, 'active');
            end
            label_text = sprintf('Child Job: %s', app.to_text(detail, 'active'));
        end

        function update_workflow_activity_display(app, state)
            if nargin < 2 || ~isstruct(state) || ~app.has_valid_handle('workflow_activity_text')
                return;
            end

            workflow_kind = app.pick_text_field(state, {'workflow_kind'}, '');
            if app.is_live_monitor_workflow_kind(workflow_kind)
                workflow_label = app.workflow_phase_display_name(workflow_kind);
                status_text = app.pick_text_field(state, {'status_text'}, 'Running');
                detail = app.describe_workflow_current_activity(state);
                lines = {sprintf('Workflow: %s', workflow_label)};
                if strlength(string(strtrim(status_text))) > 0
                    lines{end + 1} = sprintf('Status: %s', app.to_text(status_text, 'Running')); %#ok<AGROW>
                end
                stage_name = app.pick_text_field(state, {'workflow_stage_name'}, '');
                stage_index = app.pick_field(state, {'workflow_stage_index'}, NaN);
                stage_total = app.pick_field(state, {'workflow_stage_total'}, NaN);
                if isfinite(stage_index) && isfinite(stage_total) && stage_total > 0
                    lines{end + 1} = sprintf('Stage: %d/%d - %s', ... %#ok<AGROW>
                        round(stage_index), round(stage_total), app.humanize_token(stage_name));
                elseif strlength(string(strtrim(stage_name))) > 0
                    lines{end + 1} = sprintf('Stage: %s', app.humanize_token(stage_name)); %#ok<AGROW>
                end
                if strlength(string(strtrim(detail))) > 0
                    lines{end + 1} = sprintf('Activity: %s', app.to_text(detail, '')); %#ok<AGROW>
                end
                child_pct = app.pick_field(state, {'workflow_child_progress_pct'}, NaN);
                if isfinite(child_pct)
                    lines{end + 1} = sprintf('Child progress: %.2f%%', child_pct); %#ok<AGROW>
                end
                recent_events = app.pick_field(state, {'workflow_event_log'}, {});
                if iscell(recent_events) && ~isempty(recent_events)
                    lines{end + 1} = sprintf('Recent: %s', app.to_text(recent_events{end}, '')); %#ok<AGROW>
                end
            else
                status_text = app.pick_text_field(state, {'status_text'}, 'Idle');
                lines = {'Run activity will appear here.', sprintf('Status: %s', app.to_text(status_text, 'Idle'))};
                iter_now = app.last_finite_from_series(state, 'iters');
                total_iter = app.pick_field(state, {'total_iterations'}, NaN);
                if isfinite(iter_now)
                    if isfinite(total_iter) && total_iter > 0
                        lines{end + 1} = sprintf('Iteration: %d/%d', round(iter_now), round(total_iter)); %#ok<AGROW>
                    else
                        lines{end + 1} = sprintf('Iteration: %d', round(iter_now)); %#ok<AGROW>
                    end
                end
            end
            app.handles.workflow_activity_text.Value = lines;
        end

        function tf = is_live_monitor_workflow_kind(app, workflow_kind)
            workflow_kind = lower(strtrim(app.to_text(workflow_kind, '')));
            tf = any(strcmp(workflow_kind, { ...
                'mesh_convergence_study', ...
                'phase1_periodic_comparison', ...
                'phase2_boundary_condition_study', ...
                'phase3_bathymetry_study'}));
        end

        function tf = is_phase1_style_workflow_kind(app, workflow_kind)
            workflow_kind = lower(strtrim(app.to_text(workflow_kind, '')));
            tf = any(strcmp(workflow_kind, { ...
                'mesh_convergence_study', ...
                'phase1_periodic_comparison'}));
        end

        function label = workflow_phase_display_name(app, workflow_kind)
            switch lower(strtrim(app.to_text(workflow_kind, '')))
                case 'mesh_convergence_study'
                    label = 'Mesh Convergence';
                case 'phase1_periodic_comparison'
                    label = 'Phase 1';
                case 'phase2_boundary_condition_study'
                    label = 'Phase 2';
                case 'phase3_bathymetry_study'
                    label = 'Phase 3';
                otherwise
                    label = 'Workflow';
            end
        end

        function detail = describe_workflow_current_activity(app, monitor_series)
            workflow_kind = app.pick_text_field(monitor_series, {'workflow_kind'}, '');
            method_txt = app.pick_text_field(monitor_series, {'workflow_child_method'}, '--');
            mode_txt = app.humanize_token(app.pick_text_field(monitor_series, {'workflow_child_mode'}, '--'));
            setup_txt = app.pick_text_field(monitor_series, {'workflow_test_case_setup'}, '');
            scenario_txt = app.pick_text_field(monitor_series, {'workflow_current_scenario', 'workflow_current_job_label'}, '');
            mesh_txt = app.workflow_mesh_label( ...
                app.pick_field(monitor_series, {'workflow_child_mesh_nx'}, NaN), ...
                app.pick_field(monitor_series, {'workflow_child_mesh_ny'}, NaN));
            iteration_txt = app.workflow_iteration_label( ...
                app.pick_field(monitor_series, {'workflow_child_iteration'}, NaN), ...
                app.pick_field(monitor_series, {'workflow_child_total_iterations'}, NaN));

            switch lower(strtrim(workflow_kind))
                case {'mesh_convergence_study', 'phase1_periodic_comparison'}
                    parts = {method_txt, mode_txt};
                    if strlength(string(strtrim(mesh_txt))) > 0
                        parts{end + 1} = ['mesh ' mesh_txt]; %#ok<AGROW>
                    end
                    if strlength(string(strtrim(iteration_txt))) > 0
                        parts{end + 1} = ['iter ' iteration_txt]; %#ok<AGROW>
                    end
                case {'phase2_boundary_condition_study', 'phase3_bathymetry_study'}
                    parts = {method_txt};
                    if strlength(string(strtrim(setup_txt))) > 0
                        parts{end + 1} = ['setup ' setup_txt]; %#ok<AGROW>
                    end
                    if strlength(string(strtrim(scenario_txt))) > 0
                        parts{end + 1} = ['scenario ' scenario_txt]; %#ok<AGROW>
                    end
                    if strlength(string(strtrim(iteration_txt))) > 0
                        parts{end + 1} = ['iter ' iteration_txt]; %#ok<AGROW>
                    end
                otherwise
                    parts = {app.pick_text_field(monitor_series, {'workflow_current_job_label'}, '')};
            end

            parts = parts(~cellfun(@(p) strlength(string(strtrim(p))) == 0, parts));
            if isempty(parts)
                detail = '';
            else
                detail = strjoin(parts, ' | ');
            end
        end

        function state = log_workflow_ui_event(app, state, message, msg_type)
            msg_type = app.to_text(msg_type, 'info');
            if nargin < 4 || strlength(string(strtrim(msg_type))) == 0
                msg_type = 'info';
            end
            message = app.to_text(message, '');
            if nargin < 3 || strlength(string(strtrim(message))) == 0
                return;
            end
            [state, ~] = app.append_workflow_event_log(state, message);
            app.append_to_terminal(message, msg_type);
        end

        function [state, formatted_line] = append_workflow_event_log(app, state, message)
            formatted_line = '';
            message = app.to_text(message, '');
            if nargin < 3 || strlength(string(strtrim(message))) == 0
                return;
            end
            formatted_line = app.format_monitor_log_line(message);
            events = app.pick_field(state, {'workflow_event_log'}, {});
            if ~iscell(events)
                events = {};
            end
            events{end + 1} = formatted_line;
            max_lines = app.workflow_event_log_capacity();
            if numel(events) > max_lines
                events = events(end - max_lines + 1:end);
            end
            state.workflow_event_log = events;
        end

        function count = workflow_event_log_capacity(~)
            count = 40;
        end

        function line = format_monitor_log_line(app, message)
            timestamp = char(datetime('now', 'Format', 'HH:mm:ss'));
            line = sprintf('[%s] %s', timestamp, app.to_text(message, ''));
        end

        function progress_pct = compute_workflow_overall_progress_pct(app, state, fallback_progress_pct)
            if nargin < 3
                fallback_progress_pct = NaN;
            end
            progress_pct = fallback_progress_pct;
            stage_total = app.pick_field(state, {'workflow_stage_total'}, NaN);
            stage_index = app.pick_field(state, {'workflow_stage_index'}, NaN);
            if ~(isfinite(stage_total) && stage_total > 0 && isfinite(stage_index) && stage_index >= 1)
                return;
            end
            child_progress_pct = app.pick_field(state, {'workflow_child_progress_pct'}, NaN);
            current_status = lower(strtrim(app.pick_text_field(state, {'workflow_current_status'}, '')));
            completed_jobs = max(stage_index - 1, 0);
            child_fraction = 0;
            switch current_status
                case 'completed'
                    completed_jobs = min(stage_index, stage_total);
                case 'running'
                    if isfinite(child_progress_pct)
                        child_fraction = min(max(child_progress_pct, 0), 100) / 100;
                    end
                case {'queued', 'failed'}
                    child_fraction = 0;
                otherwise
                    if isfinite(child_progress_pct)
                        child_fraction = min(max(child_progress_pct, 0), 100) / 100;
                    end
            end
            progress_pct = 100 * min(max((completed_jobs + child_fraction) / stage_total, 0), 1);
        end

        function state = maybe_log_workflow_child_progress(app, state)
            workflow_kind = app.pick_text_field(state, {'workflow_kind'}, '');
            if ~app.is_live_monitor_workflow_kind(workflow_kind)
                return;
            end

            detail = app.to_text(app.describe_workflow_current_activity(state), '');
            if strlength(string(strtrim(detail))) == 0
                return;
            end
            run_key = app.pick_text_field(state, {'workflow_child_run_id', 'workflow_current_job_key'}, '');
            child_progress_pct = app.pick_field(state, {'workflow_child_progress_pct'}, NaN);
            iteration = app.pick_field(state, {'workflow_child_iteration'}, NaN);
            total_iterations = app.pick_field(state, {'workflow_child_total_iterations'}, NaN);
            residual = app.pick_field(state, {'workflow_child_conv_residual'}, NaN);
            residual_peak = app.pick_field(state, {'workflow_child_conv_peak'}, NaN);
            dt_used = app.pick_field(state, {'workflow_child_dt_used'}, NaN);
            dt_cfl = app.pick_field(state, {'workflow_child_dt_cfl'}, NaN);
            dt_adv = app.pick_field(state, {'workflow_child_dt_adv'}, NaN);
            dt_diff = app.pick_field(state, {'workflow_child_dt_diff'}, NaN);
            cfl_adv = app.pick_field(state, {'workflow_child_cfl_adv'}, NaN);
            cfl_diff = app.pick_field(state, {'workflow_child_cfl_diff'}, NaN);
            child_mode = lower(strtrim(app.pick_text_field(state, {'workflow_child_mode'}, '')));

            if isfinite(iteration) && isfinite(total_iterations) && total_iterations > 0 && ...
                    (strcmpi(child_mode, 'convergence') || total_iterations <= 20)
                log_key = sprintf('%s|iter|%d|%d', run_key, round(iteration), round(total_iterations));
                if strcmp(log_key, app.pick_text_field(state, {'last_workflow_child_iteration_log_key'}, ''))
                    return;
                end
                state.last_workflow_child_iteration_log_key = log_key;
                message = detail;
                if isfinite(child_progress_pct)
                    message = sprintf('%s | %.2f%%', message, child_progress_pct);
                end
                if strcmpi(child_mode, 'convergence')
                    message = app.append_convergence_timestep_diagnostics(message, residual, residual_peak, cfl_adv, cfl_diff, dt_used, dt_cfl, dt_adv, dt_diff);
                elseif isfinite(residual)
                    message = sprintf('%s | residual=%s', message, app.if_nan_num(residual));
                end
                state = app.log_workflow_ui_event(state, message, 'info');
                return;
            end

            if ~(isfinite(child_progress_pct) && child_progress_pct > 0)
                return;
            end
            progress_bucket = 10 * floor(min(max(child_progress_pct, 0), 100) / 10);
            if child_progress_pct >= 100
                progress_bucket = 100;
            end
            if progress_bucket < 10
                return;
            end
            log_key = sprintf('%s|progress|%d', run_key, progress_bucket);
            if strcmp(log_key, app.pick_text_field(state, {'last_workflow_child_progress_log_key'}, ''))
                return;
            end
            state.last_workflow_child_progress_log_key = log_key;
            message = sprintf('%s | %.0f%% complete', detail, progress_bucket);
            if strcmpi(child_mode, 'convergence') && isfinite(residual)
                message = app.append_convergence_timestep_diagnostics(message, residual, residual_peak, cfl_adv, cfl_diff, dt_used, dt_cfl, dt_adv, dt_diff);
            elseif strcmpi(child_mode, 'convergence')
                message = app.append_convergence_timestep_diagnostics(message, residual, residual_peak, cfl_adv, cfl_diff, dt_used, dt_cfl, dt_adv, dt_diff);
            end
            state = app.log_workflow_ui_event(state, message, 'info');
        end

        function message = append_convergence_timestep_diagnostics(app, message, xi_value, xi_peak_value, cfl_adv, cfl_diff, dt_used, dt_cfl, dt_adv, dt_diff)
            message = sprintf('%s | xi_L2=%s', message, app.if_nan_percent_fixed(xi_value, '%.3f%%'));
            message = sprintf('%s | xi_peak=%s', message, app.if_nan_percent_fixed(xi_peak_value, '%.3f%%'));
            message = sprintf('%s | CFLa=%s', message, app.if_nan_num_fixed(cfl_adv, '%.6e'));
            message = sprintf('%s | CFLd=%s', message, app.if_nan_num_fixed(cfl_diff, '%.6e'));
            message = sprintf('%s | dt_used=%s', message, app.if_nan_num_fixed(dt_used, '%.6e'));
            message = sprintf('%s | dt_cfl=%s', message, app.if_nan_num_fixed(dt_cfl, '%.6e'));
            message = sprintf('%s | dt_adv=%s', message, app.if_nan_num_fixed(dt_adv, '%.6e'));
            message = sprintf('%s | dt_diff=%s', message, app.if_nan_num_fixed(dt_diff, '%.6e'));
        end

        function text = describe_workflow_queue_entry(app, workflow_kind, queue_row)
            if ~isstruct(queue_row) || isempty(queue_row)
                text = '--';
                return;
            end

            method_txt = app.pick_text_field(queue_row, {'method'}, '--');
            mode_txt = app.humanize_token(app.pick_text_field(queue_row, {'mode'}, '--'));
            setup_txt = app.pick_text_field(queue_row, {'test_case_setup'}, '');
            scenario_txt = app.pick_text_field(queue_row, {'scenario_label', 'job_label'}, '');
            mesh_txt = app.workflow_mesh_label( ...
                app.pick_field(queue_row, {'mesh_nx'}, NaN), ...
                app.pick_field(queue_row, {'mesh_ny'}, NaN));
            status_txt = app.pick_text_field(queue_row, {'status'}, '--');

            switch lower(strtrim(workflow_kind))
                case {'mesh_convergence_study', 'phase1_periodic_comparison'}
                    parts = {method_txt, mode_txt};
                    if strlength(string(strtrim(mesh_txt))) > 0
                        parts{end + 1} = ['mesh ' mesh_txt]; %#ok<AGROW>
                    end
                case {'phase2_boundary_condition_study', 'phase3_bathymetry_study'}
                    parts = {method_txt};
                    if strlength(string(strtrim(setup_txt))) > 0
                        parts{end + 1} = ['setup ' setup_txt]; %#ok<AGROW>
                    end
                    if strlength(string(strtrim(scenario_txt))) > 0
                        parts{end + 1} = ['scenario ' scenario_txt]; %#ok<AGROW>
                    end
                otherwise
                    parts = {app.pick_text_field(queue_row, {'job_label'}, '--')};
            end

            parts = parts(~cellfun(@(p) strlength(string(strtrim(p))) == 0, parts));
            core = '--';
            if ~isempty(parts)
                core = strjoin(parts, ' | ');
            end
            text = sprintf('%s (%s)', core, status_txt);
        end

        function text = workflow_mesh_label(~, nx, ny)
            text = '';
            if isfinite(nx) && isfinite(ny)
                text = sprintf('%dx%d', round(double(nx)), round(double(ny)));
            end
        end

        function text = workflow_iteration_label(app, iteration, total_iterations)
            if isfinite(iteration) && isfinite(total_iterations) && total_iterations > 0
                text = sprintf('%d/%d', round(double(iteration)), round(double(total_iterations)));
            elseif isfinite(iteration)
                text = app.if_nan_num_fixed(iteration, '%.0f');
            else
                text = '';
            end
        end

        function state = append_workflow_convergence_sample(app, state, method_name, mesh_n, iteration, conv_residual)
            if nargin < 6 || ~isfinite(iteration) || ~isfinite(conv_residual)
                return;
            end
            method_key = lower(strtrim(app.to_text(method_name, '')));
            switch method_key
                case {'fd', 'finite difference', 'finite_difference'}
                    x_field = 'workflow_convergence_fd_x';
                    y_field = 'workflow_convergence_fd_residual';
                case {'spectral', 'fft', 'pseudospectral', 'pseudo_spectral'}
                    x_field = 'workflow_convergence_spectral_x';
                    y_field = 'workflow_convergence_spectral_residual';
                otherwise
                    return;
            end
            x_value = iteration;
            workflow_kind = app.pick_text_field(state, {'workflow_kind'}, '');
            if ~strcmpi(workflow_kind, 'phase1_periodic_comparison') && isfinite(mesh_n) && mesh_n > 0
                x_value = mesh_n;
            end
            x_hist = app.rowvec(app.pick_field(state, {x_field}, zeros(1, 0)));
            y_hist = app.rowvec(app.pick_field(state, {y_field}, zeros(1, 0)));
            if ~isempty(x_hist) && abs(x_hist(end) - x_value) < eps(max(abs(x_value), 1))
                y_hist(end) = conv_residual;
            else
                x_hist(end + 1) = x_value; %#ok<AGROW>
                y_hist(end + 1) = conv_residual; %#ok<AGROW>
            end
            state.(x_field) = x_hist;
            state.(y_field) = y_hist;
        end

        function policy = resolve_monitor_update_policy(app, cfg)
            % Resolve live-monitor redraw policy from layout config with safe defaults.
            policy = struct( ...
                'refresh_stride', 1, ...
                'min_refresh_seconds', 0.04, ...
                'force_refresh_every', 10, ...
                'max_history_points', 0);

            if isfield(app.layout_cfg, 'monitor_tab') && isfield(app.layout_cfg.monitor_tab, 'live_update')
                user_policy = app.layout_cfg.monitor_tab.live_update;
                if isstruct(user_policy)
                    if isfield(user_policy, 'refresh_stride') && isnumeric(user_policy.refresh_stride)
                        policy.refresh_stride = max(1, round(double(user_policy.refresh_stride)));
                    end
                    if isfield(user_policy, 'min_refresh_seconds') && isnumeric(user_policy.min_refresh_seconds)
                        policy.min_refresh_seconds = max(0, double(user_policy.min_refresh_seconds));
                    end
                    if isfield(user_policy, 'force_refresh_every') && isnumeric(user_policy.force_refresh_every)
                        policy.force_refresh_every = max(1, round(double(user_policy.force_refresh_every)));
                    end
                    if isfield(user_policy, 'max_history_points') && isnumeric(user_policy.max_history_points)
                        raw_limit = round(double(user_policy.max_history_points));
                        if isfinite(raw_limit)
                            if raw_limit <= 0
                                policy.max_history_points = 0; % unlimited
                            else
                                policy.max_history_points = max(50, raw_limit);
                            end
                        end
                    end
                end
            end

            if nargin >= 2 && isstruct(cfg) && isfield(cfg, 'enable_monitoring') && ~logical(cfg.enable_monitoring)
                % Keep responsive redraw cadence when monitor toggles are off.
                policy.refresh_stride = 1;
                policy.min_refresh_seconds = 0;
            end
        end

        function state = stamp_workflow_context_sample(app, state, idx, cfg)
            if nargin < 4 || isempty(cfg)
                cfg = app.config;
            end
            if nargin < 3 || ~isfinite(idx) || idx < 1
                return;
            end
            default_stage_type = app.normalize_mode_token(app.pick_text_field(cfg, {'mode', 'run_mode_internal'}, ''));
            default_method = app.pick_text_field(cfg, {'method'}, '');
            state.workflow_kind_series = app.ensure_string_series_length(app.pick_field(state, {'workflow_kind_series'}, strings(1, 0)), idx);
            state.workflow_phase_id_series = app.ensure_string_series_length(app.pick_field(state, {'workflow_phase_id_series'}, strings(1, 0)), idx);
            state.workflow_stage_id_series = app.ensure_string_series_length(app.pick_field(state, {'workflow_stage_id_series'}, strings(1, 0)), idx);
            state.workflow_stage_label_series = app.ensure_string_series_length(app.pick_field(state, {'workflow_stage_label_series'}, strings(1, 0)), idx);
            state.workflow_stage_type_series = app.ensure_string_series_length(app.pick_field(state, {'workflow_stage_type_series'}, strings(1, 0)), idx);
            state.workflow_method_series = app.ensure_string_series_length(app.pick_field(state, {'workflow_method_series'}, strings(1, 0)), idx);
            state.workflow_scenario_id_series = app.ensure_string_series_length(app.pick_field(state, {'workflow_scenario_id_series'}, strings(1, 0)), idx);
            state.workflow_mesh_level_series = app.ensure_numeric_series_length(app.pick_field(state, {'workflow_mesh_level_series'}, zeros(1, 0)), idx);
            state.workflow_mesh_index_series = app.ensure_numeric_series_length(app.pick_field(state, {'workflow_mesh_index_series'}, zeros(1, 0)), idx);
            state.workflow_child_run_index_series = app.ensure_numeric_series_length(app.pick_field(state, {'workflow_child_run_index_series'}, zeros(1, 0)), idx);
            state.workflow_child_mesh_nx_series = app.ensure_numeric_series_length(app.pick_field(state, {'workflow_child_mesh_nx_series'}, zeros(1, 0)), idx);
            state.workflow_child_mesh_ny_series = app.ensure_numeric_series_length(app.pick_field(state, {'workflow_child_mesh_ny_series'}, zeros(1, 0)), idx);

            workflow_kind = string(app.pick_text_field(state, {'workflow_kind'}, ''));
            phase_id = string(app.pick_text_field(state, {'workflow_phase_id'}, ''));
            stage_id = string(app.pick_text_field(state, {'workflow_stage_id'}, 'single_run'));
            stage_label = string(app.pick_text_field(state, {'workflow_stage_label'}, 'Single Run'));
            stage_type = string(app.pick_text_field(state, {'workflow_stage_type'}, default_stage_type));
            stage_method = string(app.pick_text_field(state, {'workflow_method', 'workflow_child_method'}, default_method));
            scenario_id = string(app.pick_text_field(state, {'workflow_scenario_id'}, ''));
            if strlength(strtrim(workflow_kind)) == 0
                stage_id = "single_run";
                stage_label = "Single Run";
            end
            state.workflow_kind_series(idx) = workflow_kind;
            state.workflow_phase_id_series(idx) = phase_id;
            state.workflow_stage_id_series(idx) = stage_id;
            state.workflow_stage_label_series(idx) = stage_label;
            state.workflow_stage_type_series(idx) = stage_type;
            state.workflow_method_series(idx) = stage_method;
            state.workflow_scenario_id_series(idx) = scenario_id;
            state.workflow_mesh_level_series(idx) = app.pick_field(state, {'workflow_mesh_level'}, NaN);
            state.workflow_mesh_index_series(idx) = app.pick_field(state, {'workflow_mesh_index'}, NaN);
            state.workflow_child_run_index_series(idx) = app.pick_field(state, {'workflow_child_run_index'}, NaN);
            state.workflow_child_mesh_nx_series(idx) = app.pick_field(state, {'workflow_child_mesh_nx'}, NaN);
            state.workflow_child_mesh_ny_series(idx) = app.pick_field(state, {'workflow_child_mesh_ny'}, NaN);
        end

        function values = ensure_string_series_length(app, values, idx)
            if nargin < 3 || ~isfinite(idx) || idx < 1
                return;
            end
            if isstring(values)
                values = reshape(values, 1, []);
            elseif ischar(values)
                values = string({values});
            elseif iscell(values)
                tmp = strings(1, numel(values));
                for vi = 1:numel(values)
                    tmp(vi) = string(app.to_text(values{vi}, ''));
                end
                values = tmp;
            else
                try
                    values = reshape(string(values), 1, []);
                catch
                    if isscalar(values)
                        values = string(app.to_text(values, ''));
                    else
                        values = strings(1, 0);
                    end
                end
            end
            if numel(values) < idx
                values(end + 1:idx) = "";
            end
        end

        function values = ensure_numeric_series_length(~, values, idx)
            if nargin < 3 || ~isfinite(idx) || idx < 1
                return;
            end
            values = double(values);
            if numel(values) < idx
                values(end + 1:idx) = NaN;
            end
        end

        function state = trim_live_monitor_history(~, state, max_points)
            % Keep only tail samples to avoid progressively slower redraws.
            if nargin < 3 || ~isfinite(max_points) || max_points <= 0
                return;
            end
            if ~isfield(state, 't') || numel(state.t) <= max_points
                return;
            end

            keep_idx = (numel(state.t) - max_points + 1):numel(state.t);
            vec_fields = {'t', 'iters', 'iter_rate', 'max_omega', 'energy_proxy', ...
                'enstrophy_proxy', 'cfl_adv_series', 'cfl_diff_series', 'cfl_terminal_series', ...
                'cpu_proxy', 'gpu_series', 'cpu_temp_c', 'power_w', ...
                'cpu_voltage_v', 'gpu_voltage_v', 'memory_voltage_v', ...
                'cpu_power_w_hwinfo', 'gpu_power_w_hwinfo', 'memory_power_w_or_proxy', ...
                'system_power_w', 'environmental_energy_wh_cum', 'environmental_co2_g_cum', ...
                'energy_joules', 'energy_rate_w', 'memory_series', 'elapsed_wall_time', 'wall_clock_time', ...
                'iter_completion_pct', 'vorticity_decay_rate', 'stability_proxy', ...
                'conv_x', 'conv_residual', ...
                'workflow_convergence_fd_x', 'workflow_convergence_fd_residual', ...
                'workflow_convergence_spectral_x', 'workflow_convergence_spectral_residual', ...
                'workflow_mesh_level_series', 'workflow_mesh_index_series', 'workflow_child_run_index_series', ...
                'workflow_child_mesh_nx_series', 'workflow_child_mesh_ny_series'};
            for i = 1:numel(vec_fields)
                key = vec_fields{i};
                if isfield(state, key) && isnumeric(state.(key)) && ~isempty(state.(key))
                    vec = state.(key);
                    if numel(vec) >= keep_idx(end)
                        state.(key) = vec(keep_idx);
                    elseif numel(vec) > max_points
                        state.(key) = vec(end - max_points + 1:end);
                    end
                end
            end
            text_fields = {'workflow_kind_series', 'workflow_phase_id_series', 'workflow_stage_id_series', ...
                'workflow_stage_label_series', 'workflow_stage_type_series', 'workflow_method_series', ...
                'workflow_scenario_id_series'};
            for i = 1:numel(text_fields)
                key = text_fields{i};
                if isfield(state, key) && ~isempty(state.(key))
                    raw_vec = state.(key);
                    if isstring(raw_vec)
                        vec = raw_vec;
                    elseif iscell(raw_vec)
                        vec = strings(size(raw_vec));
                        for vi = 1:numel(raw_vec)
                            vec(vi) = string(app.to_text(raw_vec{vi}, ''));
                        end
                    else
                        vec = strings(size(raw_vec));
                        for vi = 1:numel(raw_vec)
                            vec(vi) = string(app.to_text(raw_vec(vi), ''));
                        end
                    end
                    if numel(vec) >= keep_idx(end)
                        state.(key) = vec(keep_idx);
                    elseif numel(vec) > max_points
                        state.(key) = vec(end - max_points + 1:end);
                    end
                end
            end
            if isfield(state, 'collector_series') && isstruct(state.collector_series)
                source_names = fieldnames(state.collector_series);
                for si = 1:numel(source_names)
                    source = source_names{si};
                    source_struct = state.collector_series.(source);
                    if ~isstruct(source_struct)
                        continue;
                    end
                    metric_names = fieldnames(source_struct);
                    for mi = 1:numel(metric_names)
                        metric_name = metric_names{mi};
                        vec = source_struct.(metric_name);
                        if ~isnumeric(vec) || isempty(vec)
                            continue;
                        end
                        if numel(vec) >= keep_idx(end)
                            state.collector_series.(source).(metric_name) = vec(keep_idx);
                        elseif numel(vec) > max_points
                            state.collector_series.(source).(metric_name) = vec(end - max_points + 1:end);
                        end
                    end
                end
            end
        end

        function monitor_series = collect_live_monitor_series_for_summary(app, summary)
            if nargin < 2 || ~isstruct(summary)
                summary = struct();
            end
            monitor_series = struct();
            summary_candidate = struct();
            live_candidate = struct();
            result_candidate = struct();

            if isfield(summary, 'monitor_series') && isstruct(summary.monitor_series)
                summary_candidate = app.normalize_monitor_series_collector_payload(summary.monitor_series);
            end
            if isfield(app.handles, 'monitor_live_state') && isstruct(app.handles.monitor_live_state)
                live_candidate = app.normalize_monitor_series_collector_payload(app.handles.monitor_live_state);
            end
            if isfield(summary, 'results') && isstruct(summary.results)
                result_candidate = app.normalize_monitor_series_collector_payload( ...
                    app.synthesize_monitor_series_from_collector_results(summary.results));
            end

            hwinfo_requested = app.summary_requests_hwinfo(summary, summary_candidate, live_candidate, result_candidate);
            if app.monitor_series_source_authoritative(summary_candidate, hwinfo_requested)
                monitor_series = summary_candidate;
            elseif app.monitor_series_source_authoritative(live_candidate, hwinfo_requested)
                monitor_series = live_candidate;
            elseif app.monitor_series_has_meaningful_payload(result_candidate)
                monitor_series = result_candidate;
            elseif app.monitor_series_has_meaningful_payload(summary_candidate)
                monitor_series = summary_candidate;
            elseif app.monitor_series_has_meaningful_payload(live_candidate)
                monitor_series = live_candidate;
            end

            if app.monitor_series_has_meaningful_payload(monitor_series) && ...
                    app.monitor_series_has_meaningful_payload(result_candidate) && ...
                    app.hwinfo_payload_complete(result_candidate) && ~app.hwinfo_payload_complete(monitor_series)
                monitor_series = app.merge_monitor_series_collector_payload(monitor_series, result_candidate);
            end
            monitor_series = ExternalCollectorDispatcher.recover_monitor_series( ...
                summary, monitor_series, app.pick_field(summary, {'paths'}, struct()));
            monitor_series = app.normalize_monitor_series_collector_payload(monitor_series);
        end

        function monitor_series = synthesize_monitor_series_from_collector_results(app, results)
            monitor_series = struct();
            if ~isstruct(results)
                return;
            end
            sample = struct();
            if isfield(results, 'collector_last_sample') && isstruct(results.collector_last_sample)
                sample = app.normalize_monitor_series_collector_payload(results.collector_last_sample);
            end
            if isfield(results, 'collector_session') && isstruct(results.collector_session)
                session_sample = app.normalize_monitor_series_collector_payload(results.collector_session);
                if app.hwinfo_payload_complete(session_sample) && ~app.hwinfo_payload_complete(sample)
                    sample = app.merge_monitor_series_collector_payload(sample, session_sample);
                elseif ~app.monitor_series_has_meaningful_payload(sample) && ...
                        app.monitor_series_has_meaningful_payload(session_sample)
                    sample = session_sample;
                end
            end
            if ~isstruct(sample) || isempty(fieldnames(sample))
                return;
            end
            t = [0, 1];
            collector_series = app.empty_collector_series();
            if isfield(sample, 'collector_series') && isstruct(sample.collector_series)
                collector_series = sample.collector_series;
            elseif isfield(sample, 'metrics') && isstruct(sample.metrics)
                sources = {'hwinfo', 'icue'};
                metric_keys = fieldnames(sample.metrics);
                for si = 1:numel(sources)
                    source = sources{si};
                    if ~isfield(collector_series, source)
                        continue;
                    end
                    for ki = 1:numel(metric_keys)
                        key = metric_keys{ki};
                        if isfield(collector_series.(source), key)
                            val = sample.metrics.(key);
                            if isnumeric(val) && isscalar(val) && isfinite(val)
                                collector_series.(source).(key) = [val, val];
                            end
                        end
                    end
                end
            end
            unified_metric_keys = {'cpu_proxy', 'gpu_series', 'memory_series', 'cpu_temp_c', 'power_w', ...
                'cpu_voltage_v', 'gpu_voltage_v', 'memory_voltage_v', ...
                'cpu_power_w_hwinfo', 'gpu_power_w_hwinfo', 'memory_power_w_or_proxy', ...
                'system_power_w', 'environmental_energy_wh_cum', 'environmental_co2_g_cum', ...
                'fan_rpm', 'pump_rpm', 'coolant_temp_c', 'device_battery_level'};
            monitor_series = struct( ...
                't', t, ...
                'elapsed_wall_time', t, ...
                'collector_series', collector_series, ...
                'collector_status', app.pick_field(sample, {'collector_status'}, struct('matlab', 'connected', 'hwinfo', 'disabled', 'icue', 'disabled')), ...
                'coverage_domains', app.pick_field(sample, {'coverage_domains'}, struct('hwinfo', {{}}, 'icue', {{}})), ...
                'preferred_source', app.pick_field(sample, {'preferred_source'}, struct()), ...
                'raw_log_paths', app.pick_field(sample, {'raw_log_paths'}, struct('hwinfo', '', 'icue', '')), ...
                'overlay_metrics', {app.pick_field(sample, {'overlay_metrics'}, {'cpu_proxy', 'gpu_series', 'memory_series', 'system_power_w'})}, ...
                'collector_metric_catalog', app.pick_field(sample, {'collector_metric_catalog'}, struct([])), ...
                'hwinfo_transport', char(string(app.pick_field(sample, {'hwinfo_transport'}, 'none'))), ...
                'hwinfo_status_reason', char(string(app.pick_field(sample, {'hwinfo_status_reason'}, ''))), ...
                'collector_probe_details', app.pick_field(sample, {'collector_probe_details'}, struct('hwinfo', struct(), 'icue', struct())));
            for ki = 1:numel(unified_metric_keys)
                metric_key = unified_metric_keys{ki};
                metric_vec = app.collector_metric_vector_from_sample(sample, metric_key, numel(t));
                if ~isempty(metric_vec)
                    monitor_series.(metric_key) = metric_vec;
                end
            end
            monitor_series = app.normalize_monitor_series_collector_payload(monitor_series);
        end

        function tf = summary_requests_hwinfo(app, summary, varargin)
            tf = false;
            if nargin >= 2 && isstruct(summary)
                settings_struct = app.pick_field(summary, {'settings'}, struct());
                if isstruct(settings_struct) && isfield(settings_struct, 'sustainability') && ...
                        isstruct(settings_struct.sustainability) && ...
                        isfield(settings_struct.sustainability, 'external_collectors') && ...
                        isstruct(settings_struct.sustainability.external_collectors) && ...
                        isfield(settings_struct.sustainability.external_collectors, 'hwinfo')
                    tf = logical(settings_struct.sustainability.external_collectors.hwinfo);
                    if tf
                        return;
                    end
                end
                run_cfg = app.pick_field(summary, {'run_config'}, struct());
                if isstruct(run_cfg) && isfield(run_cfg, 'collectors') && isstruct(run_cfg.collectors) && ...
                        isfield(run_cfg.collectors, 'hwinfo')
                    tf = logical(run_cfg.collectors.hwinfo);
                    if tf
                        return;
                    end
                end
            end
            if isstruct(app.config) && isfield(app.config, 'collectors') && isstruct(app.config.collectors) && ...
                    isfield(app.config.collectors, 'hwinfo') && logical(app.config.collectors.hwinfo)
                tf = true;
                return;
            end
            if isfield(app.handles, 'hwinfo_enable') && isvalid(app.handles.hwinfo_enable) && logical(app.handles.hwinfo_enable.Value)
                tf = true;
                return;
            end
            for i = 1:numel(varargin)
                if app.monitor_series_has_hwinfo_context(varargin{i})
                    tf = true;
                    return;
                end
            end
        end

        function tf = monitor_series_source_authoritative(app, monitor_series, require_complete_hwinfo)
            if nargin < 3
                require_complete_hwinfo = false;
            end
            tf = app.monitor_series_has_meaningful_payload(monitor_series);
            if ~tf
                return;
            end
            if require_complete_hwinfo
                tf = app.hwinfo_payload_complete(monitor_series);
            end
        end

        function tf = monitor_series_has_meaningful_payload(app, monitor_series)
            tf = false;
            if ~isstruct(monitor_series) || isempty(fieldnames(monitor_series))
                return;
            end
            if app.hwinfo_payload_complete(monitor_series) || ...
                    app.collector_source_series_present(monitor_series, 'icue') || ...
                    app.collector_source_series_present(monitor_series, 'matlab')
                tf = true;
                return;
            end
            numeric_fields = fieldnames(monitor_series);
            for i = 1:numel(numeric_fields)
                field_name = numeric_fields{i};
                if strcmp(field_name, 'collector_series')
                    continue;
                end
                value = monitor_series.(field_name);
                if isnumeric(value) || islogical(value)
                    if ~isempty(value) && any(isfinite(double(value(:))))
                        tf = true;
                        return;
                    end
                end
            end
        end

        function tf = monitor_series_has_hwinfo_context(app, monitor_series)
            tf = false;
            if ~isstruct(monitor_series) || isempty(fieldnames(monitor_series))
                return;
            end
            status_struct = app.pick_field(monitor_series, {'collector_status'}, struct());
            hwinfo_status = lower(strtrim(app.pick_text_field(status_struct, {'hwinfo'}, '')));
            hwinfo_transport = lower(strtrim(app.pick_text_field(monitor_series, {'hwinfo_transport'}, 'none')));
            if ~isempty(hwinfo_status) && ~strcmp(hwinfo_status, 'disabled')
                tf = true;
                return;
            end
            if ~isempty(hwinfo_transport) && ~strcmp(hwinfo_transport, 'none')
                tf = true;
                return;
            end
            tf = app.collector_source_series_present(monitor_series, 'hwinfo') || ...
                app.hwinfo_catalog_present(monitor_series);
        end

        function tf = hwinfo_payload_complete(app, monitor_series)
            tf = false;
            if ~isstruct(monitor_series) || isempty(fieldnames(monitor_series))
                return;
            end
            status_struct = app.pick_field(monitor_series, {'collector_status'}, struct());
            status_value = app.pick_text_field(status_struct, {'hwinfo'}, '');
            transport_value = app.pick_text_field(monitor_series, {'hwinfo_transport'}, 'none');
            has_status = strlength(string(strtrim(status_value))) > 0 && ~strcmpi(status_value, 'disabled');
            has_transport = strlength(string(strtrim(transport_value))) > 0 && ~strcmpi(transport_value, 'none');
            tf = has_status && has_transport && ...
                app.collector_source_series_present(monitor_series, 'hwinfo') && ...
                app.hwinfo_catalog_present(monitor_series);
        end

        function tf = collector_source_series_present(app, monitor_series, source)
            tf = false;
            collector_series = app.pick_field(monitor_series, {'collector_series'}, struct());
            if ~isstruct(collector_series) || ~isfield(collector_series, source) || ...
                    ~isstruct(collector_series.(source))
                return;
            end
            source_struct = collector_series.(source);
            source_fields = fieldnames(source_struct);
            for i = 1:numel(source_fields)
                value = source_struct.(source_fields{i});
                if isnumeric(value) || islogical(value)
                    if ~isempty(value) && any(isfinite(double(value(:))))
                        tf = true;
                        return;
                    end
                elseif iscell(value) || isstring(value) || ischar(value) || isstruct(value)
                    if ~isempty(value)
                        tf = true;
                        return;
                    end
                end
            end
        end

        function tf = hwinfo_catalog_present(~, monitor_series)
            tf = false;
            if ~isstruct(monitor_series) || ~isfield(monitor_series, 'collector_metric_catalog') || ...
                    isempty(monitor_series.collector_metric_catalog) || ~isstruct(monitor_series.collector_metric_catalog)
                return;
            end
            catalog = monitor_series.collector_metric_catalog;
            for i = 1:numel(catalog)
                if isfield(catalog(i), 'source') && strcmpi(char(string(catalog(i).source)), 'hwinfo')
                    tf = true;
                    return;
                end
            end
        end

        function monitor_series = normalize_monitor_series_collector_payload(~, monitor_series)
            if ~isstruct(monitor_series) || isempty(fieldnames(monitor_series))
                monitor_series = struct();
                return;
            end
            monitor_series = ExternalCollectorDispatcher.normalize_collector_payload(monitor_series);
        end

        function merged = merge_monitor_series_collector_payload(app, base_series, overlay_series)
            merged = base_series;
            if ~app.monitor_series_has_meaningful_payload(overlay_series) && ~app.monitor_series_has_hwinfo_context(overlay_series)
                return;
            end
            collector_fields = {'collector_series', 'collector_status', 'coverage_domains', 'preferred_source', ...
                'raw_log_paths', 'overlay_metrics', 'collector_metric_catalog', 'hwinfo_transport', ...
                'hwinfo_status_reason', 'collector_probe_details'};
            for i = 1:numel(collector_fields)
                field_name = collector_fields{i};
                if isfield(overlay_series, field_name) && ~isempty(overlay_series.(field_name))
                    merged.(field_name) = overlay_series.(field_name);
                end
            end
            metric_fields = {'cpu_proxy', 'gpu_series', 'memory_series', 'cpu_temp_c', 'power_w', ...
                'cpu_voltage_v', 'gpu_voltage_v', 'memory_voltage_v', ...
                'cpu_power_w_hwinfo', 'gpu_power_w_hwinfo', 'memory_power_w_or_proxy', ...
                'system_power_w', 'environmental_energy_wh_cum', 'environmental_co2_g_cum', ...
                'fan_rpm', 'pump_rpm', 'coolant_temp_c', 'device_battery_level'};
            for i = 1:numel(metric_fields)
                field_name = metric_fields{i};
                base_metric = [];
                overlay_metric = [];
                if isfield(merged, field_name)
                    base_metric = merged.(field_name);
                end
                if isfield(overlay_series, field_name)
                    overlay_metric = overlay_series.(field_name);
                end
                base_has_metric = isfield(merged, field_name) && isnumeric(merged.(field_name)) && ...
                    ~isempty(base_metric) && any(isfinite(double(base_metric(:))));
                if ~base_has_metric && isnumeric(overlay_metric) && ...
                        ~isempty(overlay_metric) && any(isfinite(double(overlay_metric(:))))
                    merged.(field_name) = overlay_metric;
                end
            end
            merged = app.normalize_monitor_series_collector_payload(merged);
        end

        function metric_vec = collector_metric_vector_from_sample(~, sample, metric_key, target_len)
            if nargin < 4 || ~isfinite(target_len) || target_len < 1
                target_len = 2;
            end
            metric_vec = [];
            if isstruct(sample) && isfield(sample, 'metrics') && isstruct(sample.metrics) && ...
                    isfield(sample.metrics, metric_key)
                value = sample.metrics.(metric_key);
                if isnumeric(value) && isscalar(value) && isfinite(value)
                    metric_vec = repmat(double(value), 1, target_len);
                    return;
                end
            end
            if ~(isstruct(sample) && isfield(sample, 'collector_series') && isstruct(sample.collector_series))
                return;
            end
            source_names = {'hwinfo', 'icue', 'matlab'};
            for si = 1:numel(source_names)
                source = source_names{si};
                if ~isfield(sample.collector_series, source) || ~isstruct(sample.collector_series.(source)) || ...
                        ~isfield(sample.collector_series.(source), metric_key)
                    continue;
                end
                value = sample.collector_series.(source).(metric_key);
                if ~(isnumeric(value) && ~isempty(value))
                    continue;
                end
                numeric_value = reshape(double(value), 1, []);
                if ~any(isfinite(numeric_value))
                    continue;
                end
                if numel(numeric_value) == 1
                    metric_vec = repmat(numeric_value, 1, target_len);
                else
                    metric_vec = numeric_value;
                end
                return;
            end
        end

        function series = empty_collector_series(~)
            base_metrics = struct( ...
                'cpu_proxy', zeros(1, 0), ...
                'gpu_series', zeros(1, 0), ...
                'memory_series', zeros(1, 0), ...
                'cpu_voltage_v', zeros(1, 0), ...
                'gpu_voltage_v', zeros(1, 0), ...
                'memory_voltage_v', zeros(1, 0), ...
                'cpu_temp_c', zeros(1, 0), ...
                'power_w', zeros(1, 0), ...
                'cpu_power_w_hwinfo', zeros(1, 0), ...
                'gpu_power_w_hwinfo', zeros(1, 0), ...
                'memory_power_w_or_proxy', zeros(1, 0), ...
                'system_power_w', zeros(1, 0), ...
                'fan_rpm', zeros(1, 0), ...
                'pump_rpm', zeros(1, 0), ...
                'coolant_temp_c', zeros(1, 0), ...
                'device_battery_level', zeros(1, 0));
            series = struct('matlab', base_metrics, 'hwinfo', base_metrics, 'icue', base_metrics);
        end

        function series = ensure_collector_series_length(app, series, idx)
            if nargin < 3 || ~isfinite(idx) || idx < 1
                return;
            end
            if nargin < 2 || ~isstruct(series)
                series = app.empty_collector_series();
            end
            sources = {'matlab', 'hwinfo', 'icue'};
            metrics = fieldnames(series.matlab);
            for si = 1:numel(sources)
                source = sources{si};
                if ~isfield(series, source) || ~isstruct(series.(source))
                    series.(source) = app.empty_collector_series().(source);
                end
                for mi = 1:numel(metrics)
                    key = metrics{mi};
                    if ~isfield(series.(source), key) || ~isnumeric(series.(source).(key))
                        series.(source).(key) = nan(1, 0);
                    end
                    current = series.(source).(key);
                    if numel(current) < idx
                        current(end + 1:idx) = nan;
                    end
                    series.(source).(key) = current;
                end
            end
        end

        function series = store_collector_series_sample(app, series, payload_series, idx)
            series = app.ensure_collector_series_length(series, idx);
            sources = {'hwinfo', 'icue'};
            for si = 1:numel(sources)
                source = sources{si};
                if ~isfield(payload_series, source) || ~isstruct(payload_series.(source))
                    continue;
                end
                keys = fieldnames(payload_series.(source));
                for ki = 1:numel(keys)
                    key = keys{ki};
                    if ~isfield(series.(source), key)
                        series.(source).(key) = nan(1, idx);
                    elseif numel(series.(source).(key)) < idx
                        series.(source).(key)(end + 1:idx) = nan;
                    end
                    value = payload_series.(source).(key);
                    if isnumeric(value) && isscalar(value) && isfinite(value)
                        series.(source).(key)(idx) = double(value);
                    else
                        series.(source).(key)(idx) = nan;
                    end
                end
            end
        end

        function value = last_collector_metric_sample(~, payload, source, metric_key, fallback)
            if nargin < 5
                fallback = NaN;
            end
            value = fallback;
            if ~isstruct(payload) || ~isfield(payload, 'collector_series') || ...
                    ~isstruct(payload.collector_series) || ~isfield(payload.collector_series, source) || ...
                    ~isstruct(payload.collector_series.(source)) || ...
                    ~isfield(payload.collector_series.(source), metric_key)
                return;
            end
            candidate = payload.collector_series.(source).(metric_key);
            if isnumeric(candidate) && ~isempty(candidate)
                finite_vals = candidate(isfinite(candidate));
                if ~isempty(finite_vals)
                    value = finite_vals(end);
                end
            end
        end

        function style_axes(app, ax)
            C = app.layout_cfg.colors;
            ax.Color = C.bg_dark;
            ax.XColor = C.fg_text;
            ax.YColor = C.fg_text;
            ax.ZColor = C.fg_text;
            ax.GridColor = C.accent_gray;
            try
                disableDefaultInteractivity(ax);
            catch
                % Older MATLAB releases or non-standard axes may not expose this helper.
            end
            if isprop(ax, 'Interactions')
                try
                    ax.Interactions = [];
                catch
                    % Ignore when UIAxes interactivity collection is not writable.
                end
            end
            if isprop(ax, 'Toolbar')
                try
                    if ~isempty(ax.Toolbar) && isprop(ax.Toolbar, 'Visible')
                        ax.Toolbar.Visible = 'off';
                    end
                catch
                    % Toolbar visibility is best-effort only.
                end
            end
            if isprop(ax, 'XMinorGrid')
                ax.XMinorGrid = 'off';
            end
            if isprop(ax, 'YMinorGrid')
                ax.YMinorGrid = 'off';
            end
            if isprop(ax, 'ZMinorGrid')
                ax.ZMinorGrid = 'off';
            end
        end

        function style_results_axes(app, ax)
            app.style_axes(ax);
            if isempty(ax) || ~isgraphics(ax)
                return;
            end

            try
                enableDefaultInteractivity(ax);
            catch
                % Some MATLAB releases may not expose the helper for every axes type.
            end

            tb = [];
            if isprop(ax, 'Toolbar')
                try
                    tb = ax.Toolbar;
                catch
                    tb = [];
                end
            end
            if isempty(tb)
                try
                    tb = axtoolbar(ax, {'zoomin', 'zoomout', 'pan', 'restoreview'});
                catch
                    tb = [];
                end
            end
            if ~isempty(tb) && isprop(tb, 'Visible')
                try
                    tb.Visible = 'on';
                catch
                    % Toolbar visibility is best-effort only.
                end
            end
        end

        function enforce_dark_theme(app)
            % Enforce dark theme across all known UI handles after layout creation.
            if isempty(app.layout_cfg) || ~isfield(app.layout_cfg, 'colors')
                return;
            end
            C = app.layout_cfg.colors;
            if ~isempty(app.fig) && isvalid(app.fig) && isprop(app.fig, 'Color')
                app.fig.Color = C.bg_dark;
            end

            if isfield(app, 'handles') && isstruct(app.handles)
                fn = fieldnames(app.handles);
                for i = 1:numel(fn)
                    h = app.handles.(fn{i});
                    app.apply_dark_theme_to_handle(h, C);
                end
            end
            ResultsPlotDispatcher.apply_dark_theme(app.fig, ResultsPlotDispatcher.default_colors());
        end

        function apply_dark_theme_to_handle(app, h, C)
            if isempty(h)
                return;
            end
            if numel(h) > 1
                for i = 1:numel(h)
                    app.apply_dark_theme_to_handle(h(i), C);
                end
                return;
            end
            if ~app.is_live_handle(h)
                return;
            end

            cls = class(h);
            is_button = contains(lower(cls), 'button');
            is_input = contains(lower(cls), 'editfield') || contains(lower(cls), 'dropdown') || ...
                contains(lower(cls), 'textarea') || contains(lower(cls), 'table') || ...
                contains(lower(cls), 'spinner');
            is_panel = contains(lower(cls), 'panel') || contains(lower(cls), 'tab');

            if isprop(h, 'FontColor')
                h.FontColor = C.fg_text;
            end
            if isprop(h, 'BackgroundColor')
                if is_panel
                    h.BackgroundColor = C.bg_panel_alt;
                elseif is_input
                    h.BackgroundColor = C.bg_input;
                elseif ~is_button
                    h.BackgroundColor = C.bg_dark;
                end
            end
            if isgraphics(h, 'axes')
                app.style_axes(h);
            end
        end

        function log_executor_failure_details(app, ME, cfg_override)
            % Persist a detailed worker-failure report and mirror key fields in the terminal.
            if nargin < 3 || ~isstruct(cfg_override)
                cfg_override = struct();
            end
            err_id = char(string(ME.identifier));
            if isempty(strtrim(err_id))
                err_id = 'unknown_identifier';
            end
            try
                report_txt = getReport(ME, 'extended', 'hyperlinks', 'off');
            catch
                report_txt = char(string(ME.message));
            end

            run_id_hint = '';
            if isfield(cfg_override, 'run_id') && ~isempty(cfg_override.run_id)
                run_id_hint = char(string(cfg_override.run_id));
            else
                run_id_hint = char(datetime('now', 'Format', 'yyyy-MM-dd_HH-mm-ss'));
            end
            safe_name = regexprep(run_id_hint, '[^A-Za-z0-9_.-]', '_');
            log_file = fullfile(tempdir, sprintf('ui_worker_failure_%s.log', safe_name));
            fid = fopen(log_file, 'w');
            if fid ~= -1
                fprintf(fid, 'Identifier: %s\n', err_id);
                fprintf(fid, 'Message: %s\n\n', char(string(ME.message)));
                fprintf(fid, '%s\n', report_txt);
                fclose(fid);
            end

            app.append_to_terminal(sprintf('Worker failure identifier: %s', err_id), 'error');
            app.append_to_terminal(sprintf('Worker failure details: %s', char(string(ME.message))), 'error');
            [root_id, root_msg] = app.extract_deepest_error_cause(ME);
            if ~(isempty(root_id) && isempty(root_msg))
                app.append_to_terminal(sprintf('Worker root cause: [%s] %s', root_id, root_msg), 'error');
            end
            if fid ~= -1
                app.append_to_terminal(sprintf('Worker failure report: %s', log_file), 'warning');
            end
        end

        function [cause_id, cause_message] = extract_deepest_error_cause(~, ME)
            % Traverse nested causes to surface the most actionable leaf error.
            cause_id = '';
            cause_message = '';
            if nargin < 2 || isempty(ME)
                return;
            end

            current = ME;
            for depth = 1:16
                if ~isprop(current, 'cause') || isempty(current.cause)
                    break;
                end
                next_cause = current.cause{1};
                if isempty(next_cause)
                    break;
                end
                current = next_cause;
            end

            cause_id = strtrim(char(string(current.identifier)));
            cause_message = strtrim(char(string(current.message)));
            if isempty(cause_id)
                cause_id = 'unknown_identifier';
            end
        end

        function apply_responsive_breakpoint(app)
            % Responsive reflow using compact-first design baseline values.
            if isempty(app.fig) || ~isvalid(app.fig)
                return;
            end
            fig_pos = app.fig.Position;
            if numel(fig_pos) < 4
                return;
            end
            width_px = max(fig_pos(3), 1);
            height_px = max(fig_pos(4), 1);

            design_w = 1920;
            design_h = 1080;
            min_scale = 0.82;
            max_scale = 1.30;
            if isfield(app.layout_cfg, 'sizes') && isstruct(app.layout_cfg.sizes)
                design_w = app.pick_field(app.layout_cfg.sizes, {'design_width'}, design_w);
                design_h = app.pick_field(app.layout_cfg.sizes, {'design_height'}, design_h);
                min_scale = app.pick_field(app.layout_cfg.sizes, {'min_scale'}, min_scale);
                max_scale = app.pick_field(app.layout_cfg.sizes, {'max_scale'}, max_scale);
            end
            ui_scale = min(width_px / max(design_w, 1), height_px / max(design_h, 1));
            ui_scale = max(min_scale, min(max_scale, ui_scale));

            compact_width_cutoff = max(1024, round(design_w * 0.78));
            compact_height_cutoff = max(620, round(design_h * 0.82));
            wide_width_cutoff = round(design_w * 1.22);
            wide_height_cutoff = round(design_h * 1.18);

            profile = 'standard';
            if width_px <= compact_width_cutoff || height_px <= compact_height_cutoff
                profile = 'compact';
            elseif width_px >= wide_width_cutoff && height_px >= wide_height_cutoff
                profile = 'wide';
            end

            if isfield(app.handles, 'config_root_grid') && isvalid(app.handles.config_root_grid)
                app.apply_config_layout_profile(profile);
            end

            if isfield(app.handles, 'config_right_layout') && isvalid(app.handles.config_right_layout)
                button_row_h = max(28, min(38, round(32 * ui_scale)));
                quick_progress_h = max(40, min(56, round(48 * ui_scale)));
                app.handles.config_right_layout.RowHeight = {button_row_h, quick_progress_h, '1x', '1x'};
                app.handles.config_right_layout.RowSpacing = max(3, round(4 * ui_scale));
            end

            app.apply_config_form_layout_profile(profile, ui_scale);

            top_row = max(38, min(56, round(44 * ui_scale)));
            form_row = max(22, min(36, round(app.layout_cfg.heights.form_row * ui_scale)));
            eq_row = max(54, min(88, round(72 * ui_scale)));
            status_row = max(18, min(24, round(20 * ui_scale)));
            app.handles.ic_top_row_px = top_row;
            app.handles.ic_form_row_px = form_row;
            app.handles.ic_eq_row_px = eq_row;
            app.handles.ic_status_row_px = status_row;
            app.update_ic_compact_layout();

            if isfield(app.handles, 'ic_dynamic_grid') && ~isempty(app.handles.ic_dynamic_grid)
                try
                    if isvalid(app.handles.ic_dynamic_grid) && isprop(app.handles.ic_dynamic_grid, 'GridSize')
                        n_dyn_rows = max(1, app.handles.ic_dynamic_grid.GridSize(1));
                        app.handles.ic_dynamic_grid.RowHeight = repmat({'fit'}, 1, n_dyn_rows);
                    end
                catch
                end
            end

            if isfield(app.handles, 'monitor_root_grid') && isvalid(app.handles.monitor_root_grid)
                switch profile
                    case 'compact'
                        app.handles.monitor_root_grid.ColumnWidth = {'2x', '1x'};
                    case 'wide'
                        app.handles.monitor_root_grid.ColumnWidth = {'3.2x', '1x'};
                    otherwise
                        app.handles.monitor_root_grid.ColumnWidth = app.layout_cfg.monitor_tab.root.col_widths;
                end
            end

            if isfield(app.handles, 'results_main_grid') && isvalid(app.handles.results_main_grid)
                switch profile
                    case 'compact'
                        app.handles.results_main_grid.ColumnWidth = {'1.8x', '1x'};
                    case 'wide'
                        app.handles.results_main_grid.ColumnWidth = {'3.5x', '1x'};
                    otherwise
                        app.handles.results_main_grid.ColumnWidth = app.layout_cfg.results_tab.main.col_widths;
                end
            end

            app.enforce_container_content_margins(app.tab_group);
        end

        function validate_parameters(app)
            errors = {};
            
            % Check UI components exist
            if ~isfield(app.handles, 'Nx') || ~ishghandle(app.handles.Nx)
                app.show_alert_latex('UI components not ready', 'Error', 'Icon', 'error');
                return;
            end
            
            % Grid validation
            if app.handles.Nx.Value < 32
                errors{end+1} = 'Nx must be >= 32 points';
            end
            if app.handles.Ny.Value < 32
                errors{end+1} = 'Ny must be >= 32 points';
            end
            if app.handles.Nx.Value > 1024 || app.handles.Ny.Value > 1024
                errors{end+1} = 'Grid size should not exceed 1024ÃƒÆ’Ã¢â‚¬â€1024 (memory limits)';
            end
            
            % Time integration validation
            if app.handles.dt.Value <= 0 || app.handles.dt.Value > 0.1
                errors{end+1} = 'dt must be in (0, 0.1]';
            end
            if app.handles.t_final.Value <= 0
                errors{end+1} = 't_final must be positive';
            end
            if app.handles.t_final.Value / app.handles.dt.Value > 100000
                errors{end+1} = 'Too many timesteps (T/dt > 100k)';
            end
            
            % CFL stability check (rough estimate)
            Nx_local = max(2, round(app.handles.Nx.Value));
            dx = max(app.handles.Lx.Value, 1e-6) / Nx_local;
            if app.has_valid_handle('dx')
                dx = max(app.handles.dx.Value, 1e-9);
            end
            cfl = app.handles.dt.Value / (dx * dx);
            if cfl > 0.5
                errors{end+1} = sprintf('CFL number %.2f may be unstable (should be < 0.5)', cfl);
            end
            
            % Physics validation
            if app.handles.nu.Value < 0 || app.handles.nu.Value > 0.1
                errors{end+1} = 'Viscosity must be in [0, 0.1]';
            end
            
            % IC validation
            if isempty(app.handles.ic_dropdown.Value)
                errors{end+1} = 'Initial condition type not selected';
            end
            
            if isempty(errors)
                msg = sprintf('All parameters valid!\n\nGrid: %d ÃƒÆ’Ã¢â‚¬â€ %d\ndt = %.4f, T = %.2f\nÃƒÅ½Ã‚Â½ = %.4f', ...
                    round(app.handles.Nx.Value), round(app.handles.Ny.Value), ...
                    app.handles.dt.Value, app.handles.t_final.Value, app.handles.nu.Value);
                app.show_alert_latex(msg, 'Validation Passed', 'Icon', 'success');
                app.append_to_terminal('ÃƒÂ¢Ã…â€œÃ¢â‚¬Å“ All parameters validated successfully', 'success');
            else
                msg = sprintf('Found %d validation error(s):\n\nÃƒÂ¢Ã¢â€šÂ¬Ã‚Â¢ %s', ...
                    length(errors), strjoin(errors, '\nÃƒÂ¢Ã¢â€šÂ¬Ã‚Â¢ '));
                app.show_alert_latex(msg, 'Validation Errors', 'Icon', 'error');
                app.append_to_terminal(sprintf('ÃƒÂ¢Ã…â€œÃ¢â‚¬â€ Validation errors: %s', strjoin(errors, ', ')), 'error');
            end

            app.update_checklist();
        end

        function update_delta(app)
            % Update grid point count and synchronize derived spacing fields.
            Nx = max(2, round(app.handles.Nx.Value));
            Ny = max(2, round(app.handles.Ny.Value));
            app.handles.Nx.Value = Nx;
            app.handles.Ny.Value = Ny;
            Lx = max(app.safe_numeric_value('Lx', 1.0), 1e-9);
            Ly = max(app.safe_numeric_value('Ly', 1.0), 1e-9);
            app.handles.Lx.Value = Lx;
            app.handles.Ly.Value = Ly;
            app.handles.grid_points.Text = sprintf('%d', Nx * Ny);
            dx_val = Lx / Nx;
            dy_val = Ly / Ny;
            if app.has_valid_handle('dx')
                app.handles.dx.Value = max(dx_val, 1e-9);
            end
            if app.has_valid_handle('dy')
                app.handles.dy.Value = max(dy_val, 1e-9);
            end
            if app.has_valid_handle('delta') && app.has_valid_handle('dx') && app.has_valid_handle('dy')
                app.handles.delta.Value = min(max(app.handles.dx.Value, 1e-9), max(app.handles.dy.Value, 1e-9));
            end

            app.sync_grid_mode_controls();
            app.update_checklist();
            app.update_ic_preview();
        end

        function on_lx_changed(app)
            if app.has_valid_handle('Lx')
                app.handles.Lx.Value = max(app.handles.Lx.Value, 1e-9);
            end
            if app.has_valid_handle('dx') && app.has_valid_handle('Lx') && app.has_valid_handle('Nx')
                Nx = max(2, round(app.handles.Nx.Value));
                app.handles.dx.Value = app.handles.Lx.Value / Nx;
            end
            if app.has_valid_handle('delta') && app.has_valid_handle('dx') && app.has_valid_handle('dy')
                app.handles.delta.Value = min(max(app.handles.dx.Value, 1e-9), max(app.handles.dy.Value, 1e-9));
            end
            app.update_grid_domain_plots();
        end

        function on_ly_changed(app)
            if app.has_valid_handle('Ly')
                app.handles.Ly.Value = max(app.handles.Ly.Value, 1e-9);
            end
            if app.has_valid_handle('dy') && app.has_valid_handle('Ly') && app.has_valid_handle('Ny')
                Ny = max(2, round(app.handles.Ny.Value));
                app.handles.dy.Value = app.handles.Ly.Value / Ny;
            end
            if app.has_valid_handle('delta') && app.has_valid_handle('dx') && app.has_valid_handle('dy')
                app.handles.delta.Value = min(max(app.handles.dx.Value, 1e-9), max(app.handles.dy.Value, 1e-9));
            end
            app.update_grid_domain_plots();
        end

        function on_delta_changed(app)
            if ~app.has_valid_handle('delta')
                return;
            end
            delta_val = max(app.handles.delta.Value, 1e-9);
            app.handles.delta.Value = delta_val;
            Lx = max(app.safe_numeric_value('Lx', 1.0), 1e-9);
            Ly = max(app.safe_numeric_value('Ly', 1.0), 1e-9);
            if app.has_valid_handle('dx')
                app.handles.dx.Value = delta_val;
            end
            if app.has_valid_handle('dy')
                app.handles.dy.Value = delta_val;
            end
            if app.has_valid_handle('Nx')
                app.handles.Nx.Value = max(2, round(Lx / delta_val));
            end
            if app.has_valid_handle('Ny')
                app.handles.Ny.Value = max(2, round(Ly / delta_val));
            end
            app.update_grid_domain_plots();
        end

        function on_dx_changed(app)
            if app.has_valid_handle('dx')
                app.handles.dx.Value = max(app.handles.dx.Value, 1e-9);
            end
            if app.has_valid_handle('Nx') && app.has_valid_handle('Lx') && app.has_valid_handle('dx')
                Lx = max(app.safe_numeric_value('Lx', 1.0), 1e-9);
                app.handles.Nx.Value = max(2, round(Lx / max(app.handles.dx.Value, 1e-9)));
            end
            app.update_grid_domain_plots();
        end

        function on_dy_changed(app)
            if app.has_valid_handle('dy')
                app.handles.dy.Value = max(app.handles.dy.Value, 1e-9);
            end
            if app.has_valid_handle('Ny') && app.has_valid_handle('Ly') && app.has_valid_handle('dy')
                Ly = max(app.safe_numeric_value('Ly', 1.0), 1e-9);
                app.handles.Ny.Value = max(2, round(Ly / max(app.handles.dy.Value, 1e-9)));
            end
            app.update_grid_domain_plots();
        end

        function on_grid_mode_changed(app)
            app.sync_grid_mode_controls();
            app.update_grid_domain_plots();
        end

        function mode_token = get_grid_mode_token(app)
            mode_token = 'domain_driven';
            raw = '';
            if app.has_valid_handle('grid_mode')
                raw = char(string(app.handles.grid_mode.Value));
            end
            raw_token = lower(strtrim(raw));
            if ~isempty(raw_token) && contains(raw_token, 'spacing')
                mode_token = 'spacing_driven';
            end
        end

        function sync_grid_mode_controls(app)
            if app.has_valid_handle('Lx')
                app.handles.Lx.Editable = 'on';
            end
            if app.has_valid_handle('Ly')
                app.handles.Ly.Editable = 'on';
            end
            if app.has_valid_handle('delta')
                app.handles.delta.Editable = 'on';
            end
            if app.has_valid_handle('dx')
                app.handles.dx.Editable = 'on';
            end
            if app.has_valid_handle('dy')
                app.handles.dy.Editable = 'on';
            end
        end

        function update_grid_domain_plots(app)
            % Update delta display + boundary/domain plot
            % ---- DEVELOPER GUIDE ----
            % Mesh plot: grid lines + 5-point stencil; edit below to change stencil style
            % Domain plot: reads BC dropdowns (bc_top/bottom/left/right handles); edit to change arrow style
            % Resolution preview: shows dx, dy, delta from Grid Parameters panel
            % BC colors: mapped in bc_color_map struct below
            app.update_delta();
            C = app.layout_cfg.colors;

            Nx = max(2, round(app.handles.Nx.Value));
            Ny = max(2, round(app.handles.Ny.Value));
            Lx = max(app.handles.Lx.Value, 1e-6);
            Ly = max(app.handles.Ly.Value, 1e-6);

            % --- Mesh grid plot (top-right) ---
            if app.has_valid_handle('grid_mesh_axes')
                ax = app.handles.grid_mesh_axes;
                cla(ax);
                n_show_x = min(Nx, 32); n_show_y = min(Ny, 32);
                x_lines = linspace(-Lx/2, Lx/2, n_show_x);
                y_lines = linspace(-Ly/2, Ly/2, n_show_y);
                hold(ax, 'on');
                for i = 1:numel(x_lines)
                    plot(ax, [x_lines(i) x_lines(i)], [-Ly/2 Ly/2], '-', ...
                        'Color', [0.3 0.7 1.0 0.4], 'LineWidth', 0.5);
                end
                for j = 1:numel(y_lines)
                    plot(ax, [-Lx/2 Lx/2], [y_lines(j) y_lines(j)], '-', ...
                        'Color', [0.3 0.7 1.0 0.4], 'LineWidth', 0.5);
                end

                % --- 5-point computational stencil diagram ---
                % Draw a small stencil at the mesh center to illustrate the FD molecule.
                dx_mol = Lx / n_show_x;
                dy_mol = Ly / n_show_y;
                cx = 0; cy = 0; % stencil center
                mol_pts_x = [cx, cx+dx_mol, cx-dx_mol, cx, cx];
                mol_pts_y = [cy, cy, cy, cy+dy_mol, cy-dy_mol];
                % Stencil arms (connecting lines)
                plot(ax, [cx-dx_mol cx+dx_mol], [cy cy], '-', 'Color', C.accent_yellow, 'LineWidth', 1.5);
                plot(ax, [cx cx], [cy-dy_mol cy+dy_mol], '-', 'Color', C.accent_yellow, 'LineWidth', 1.5);
                % Center node (m,n)
                plot(ax, cx, cy, 'o', 'Color', C.accent_red, 'MarkerFaceColor', C.accent_red, 'MarkerSize',4);
                % Neighbor nodes
                plot(ax, mol_pts_x(2:end), mol_pts_y(2:end), 'o', 'Color', C.accent_yellow, ...
                    'MarkerFaceColor', C.accent_yellow, 'MarkerSize', 4);
                % Stencil labels
                text(ax, cx, cy + dy_mol*0.35, '$\psi_{m,n}$', 'Color', C.fg_text, ...
                    'FontSize', 9, 'HorizontalAlignment', 'center', 'Interpreter', 'latex');

                hold(ax, 'off');
                xlabel(ax, '$L_x$', 'Interpreter', 'latex', 'FontSize', 12, 'Color', C.fg_text);
                ylabel(ax, '$L_y$', 'Interpreter', 'latex', 'FontSize', 12, 'Color', C.fg_text);
                title(ax, sprintf('Mesh / Stencil: $%d \\times %d$', Nx, Ny), 'Interpreter', 'latex', ...
                    'FontSize', 12, 'Color', C.fg_text);
                xlim(ax, [-Lx/2, Lx/2]); ylim(ax, [-Ly/2, Ly/2]);
                ax.XTick = [-Lx/2, 0, Lx/2]; ax.YTick = [-Ly/2, 0, Ly/2];
                axis(ax, 'equal');

                % --- FD Stencil Magnification Inset ---
                % When FD method selected, draw a magnified stencil diagram
                % as an inset in the bottom-right corner of the mesh plot.
                is_fd = false;
                if app.has_valid_handle('method_dropdown')
                    is_fd = strcmp(app.handles.method_dropdown.Value, 'Finite Difference');
                end

                if is_fd
                    hold(ax, 'on');
                    % Inset position in data coordinates (bottom-right corner)
                    inset_w = Lx * 0.38;
                    inset_h = Ly * 0.38;
                    inset_x = Lx/2 - inset_w - Lx*0.02;
                    inset_y = -Ly/2 + Ly*0.02;

                    % Background rectangle for inset
                    rectangle(ax, 'Position', [inset_x, inset_y, inset_w, inset_h], ...
                        'FaceColor', [C.bg_panel_alt, 0.92], ...
                        'EdgeColor', C.accent_yellow, 'LineWidth', 1.5, ...
                        'Curvature', [0.05, 0.05]);

                    % Inset center and scale
                    icx = inset_x + inset_w/2;
                    icy = inset_y + inset_h/2;
                    s = min(inset_w, inset_h) * 0.32; % stencil arm length

                    % Stencil connecting lines
                    plot(ax, [icx-s, icx+s], [icy, icy], '-', ...
                        'Color', C.accent_yellow, 'LineWidth', 2);
                    plot(ax, [icx, icx], [icy-s, icy+s], '-', ...
                        'Color', C.accent_yellow, 'LineWidth', 2);

                    % Center point (m,n)
                    plot(ax, icx, icy, 'o', 'Color', C.accent_red, ...
                        'MarkerFaceColor', C.accent_red, 'MarkerSize', 4);

                    % Neighbor points
                    plot(ax, [icx+s, icx-s, icx, icx], [icy, icy, icy+s, icy-s], 'o', ...
                        'Color', C.accent_cyan, 'MarkerFaceColor', C.accent_cyan, 'MarkerSize', 4);

                    % LaTeX labels
                    text(ax, icx + s*0.15, icy + s*0.25, '$\psi_{m,n}$', ...
                        'Interpreter', 'latex', 'FontSize', 14, 'Color', C.fg_text);
                    text(ax, icx + s, icy - s*0.3, '$m{+}1$', ...
                        'Interpreter', 'latex', 'FontSize', 14, 'Color', C.fg_muted, ...
                        'HorizontalAlignment', 'center');
                    text(ax, icx - s, icy - s*0.3, '$m{-}1$', ...
                        'Interpreter', 'latex', 'FontSize', 14, 'Color', C.fg_muted, ...
                        'HorizontalAlignment', 'center');
                    text(ax, icx + s*0.3, icy + s, '$n{+}1$', ...
                        'Interpreter', 'latex', 'FontSize', 14, 'Color', C.fg_muted);
                    text(ax, icx + s*0.3, icy - s, '$n{-}1$', ...
                        'Interpreter', 'latex', 'FontSize', 14, 'Color', C.fg_muted);

                    % Inset title
                    text(ax, icx, inset_y + inset_h - inset_h*0.08, ...
                        'FD Stencil', 'Color', C.accent_yellow, ...
                        'FontSize', 10, 'FontWeight', 'bold', ...
                        'HorizontalAlignment', 'center');

                    % Connecting line from stencil center to inset
                    plot(ax, [cx, inset_x], [cy, icy], ':', ...
                        'Color', [C.accent_yellow, 0.4], 'LineWidth', 1);

                    hold(ax, 'off');
                end
            end

            % --- Domain & Boundary conditions plot (bottom-left) ---
            % Reads BC types from the 4 boundary dropdowns and renders
            % persistent physical|math legend with side-specific overlays.
            if app.has_valid_handle('grid_domain_axes')
                Lx = max(app.handles.Lx.Value, 1e-6);
                Ly = max(app.handles.Ly.Value, 1e-6);
                ax = app.handles.grid_domain_axes;
                cla(ax);
                hold(ax, 'on');
                rectangle(ax, 'Position', [-Lx/2 -Ly/2 Lx Ly], ...
                    'EdgeColor', C.accent_cyan, 'LineWidth', 2.2, 'LineStyle', '-');

                % Read BC selections (safe defaults)
                bc_top_raw    = app.safe_bc_value('bc_top',    'Periodic');
                bc_bottom_raw = app.safe_bc_value('bc_bottom', 'Periodic');
                bc_left_raw   = app.safe_bc_value('bc_left',   'Periodic');
                bc_right_raw  = app.safe_bc_value('bc_right',  'Periodic');
                U_top = app.safe_numeric_value('U_top', 0.0);
                U_bottom = app.safe_numeric_value('U_bottom', 0.0);
                U_left = app.safe_numeric_value('U_left', 0.0);
                U_right = app.safe_numeric_value('U_right', 0.0);

                [bc_top, top_math, top_phys] = app.normalize_bc_selection(bc_top_raw);
                [bc_bottom, bottom_math, bottom_phys] = app.normalize_bc_selection(bc_bottom_raw);
                [bc_left, left_math, left_phys] = app.normalize_bc_selection(bc_left_raw);
                [bc_right, right_math, right_phys] = app.normalize_bc_selection(bc_right_raw);

                arr_len = min(Lx, Ly) * 0.14;
                offset = min(Lx, Ly) * 0.06;
                periodic_lr_color = app.hex_to_rgb('#2DD4BF');
                periodic_tb_color = app.hex_to_rgb('#38BDF8');
                noslip_color = app.hex_to_rgb('#F87171');
                noflux_color = app.hex_to_rgb('#A3E635');
                driven_color = app.hex_to_rgb('#F59E0B');
                is_spectral = app.has_valid_handle('method_dropdown') && ...
                    strcmpi(char(string(app.handles.method_dropdown.Value)), 'Spectral');
                is_swe = app.has_valid_handle('method_dropdown') && ...
                    strcmpi(char(string(app.handles.method_dropdown.Value)), 'Shallow Water');

                % Periodic connectors (left-right pair, top-bottom pair).
                if strcmp(left_phys, 'periodic') && strcmp(right_phys, 'periodic')
                    quiver(ax, -Lx/2 - offset, 0, Lx + 2*offset, 0, 0, ...
                        'Color', periodic_lr_color, 'LineWidth', 1.8, 'MaxHeadSize', 0.45);
                    quiver(ax, Lx/2 + offset, 0, -(Lx + 2*offset), 0, 0, ...
                        'Color', periodic_lr_color, 'LineWidth', 1.8, 'MaxHeadSize', 0.45);
                end
                if strcmp(top_phys, 'periodic') && strcmp(bottom_phys, 'periodic')
                    quiver(ax, 0, Ly/2 + offset, 0, -(Ly + 2*offset), 0, ...
                        'Color', periodic_tb_color, 'LineWidth', 1.8, 'MaxHeadSize', 0.45);
                    quiver(ax, 0, -Ly/2 - offset, 0, (Ly + 2*offset), 0, ...
                        'Color', periodic_tb_color, 'LineWidth', 1.8, 'MaxHeadSize', 0.45);
                end

                % No-slip markers (red blocked-harpoon style).
                if any(strcmp(top_phys, {'no_slip', 'pinned'}))
                    plot(ax, [-Lx/4, Lx/4], [Ly/2 + offset, Ly/2 + offset], '-', ...
                        'Color', noslip_color, 'LineWidth', 1.8);
                    plot(ax, [0, 0], [Ly/2 + offset - offset*0.45, Ly/2 + offset + offset*0.45], '-', ...
                        'Color', noslip_color, 'LineWidth', 1.8);
                end
                if any(strcmp(bottom_phys, {'no_slip', 'pinned'}))
                    plot(ax, [-Lx/4, Lx/4], [-Ly/2 - offset, -Ly/2 - offset], '-', ...
                        'Color', noslip_color, 'LineWidth', 1.8);
                    plot(ax, [0, 0], [-Ly/2 - offset - offset*0.45, -Ly/2 - offset + offset*0.45], '-', ...
                        'Color', noslip_color, 'LineWidth', 1.8);
                end
                if any(strcmp(left_phys, {'no_slip', 'pinned'}))
                    plot(ax, [-Lx/2 - offset, -Lx/2 - offset], [-Ly/4, Ly/4], '-', ...
                        'Color', noslip_color, 'LineWidth', 1.8);
                    plot(ax, [-Lx/2 - offset - offset*0.45, -Lx/2 - offset + offset*0.45], [0, 0], '-', ...
                        'Color', noslip_color, 'LineWidth', 1.8);
                end
                if any(strcmp(right_phys, {'no_slip', 'pinned'}))
                    plot(ax, [Lx/2 + offset, Lx/2 + offset], [-Ly/4, Ly/4], '-', ...
                        'Color', noslip_color, 'LineWidth', 1.8);
                    plot(ax, [Lx/2 + offset - offset*0.45, Lx/2 + offset + offset*0.45], [0, 0], '-', ...
                        'Color', noslip_color, 'LineWidth', 1.8);
                end

                if strcmp(top_phys, 'no_flux')
                    plot(ax, [-Lx/4, Lx/4], [Ly/2 + offset, Ly/2 + offset], '--', ...
                        'Color', noflux_color, 'LineWidth', 1.8);
                end
                if strcmp(bottom_phys, 'no_flux')
                    plot(ax, [-Lx/4, Lx/4], [-Ly/2 - offset, -Ly/2 - offset], '--', ...
                        'Color', noflux_color, 'LineWidth', 1.8);
                end
                if strcmp(left_phys, 'no_flux')
                    plot(ax, [-Lx/2 - offset, -Lx/2 - offset], [-Ly/4, Ly/4], '--', ...
                        'Color', noflux_color, 'LineWidth', 1.8);
                end
                if strcmp(right_phys, 'no_flux')
                    plot(ax, [Lx/2 + offset, Lx/2 + offset], [-Ly/4, Ly/4], '--', ...
                        'Color', noflux_color, 'LineWidth', 1.8);
                end

                % Driven arrows (signed tangent direction).
                if strcmp(top_phys, 'driven')
                    quiver(ax, 0, Ly/2, app.sign_or_one(U_top) * arr_len, 0, 0, ...
                        'Color', driven_color, 'LineWidth', 2.0, 'MaxHeadSize', 0.7);
                end
                if strcmp(bottom_phys, 'driven')
                    quiver(ax, 0, -Ly/2, app.sign_or_one(U_bottom) * arr_len, 0, 0, ...
                        'Color', driven_color, 'LineWidth', 2.0, 'MaxHeadSize', 0.7);
                end
                if strcmp(left_phys, 'driven')
                    quiver(ax, -Lx/2, 0, 0, app.sign_or_one(U_left) * arr_len, 0, ...
                        'Color', driven_color, 'LineWidth', 2.0, 'MaxHeadSize', 0.7);
                end
                if strcmp(right_phys, 'driven')
                    quiver(ax, Lx/2, 0, 0, app.sign_or_one(U_right) * arr_len, 0, ...
                        'Color', driven_color, 'LineWidth', 2.0, 'MaxHeadSize', 0.7);
                end

                % Per-side labels with physical and math meaning.
                top_label = app.format_bc_side_label(top_phys, top_math);
                bottom_label = app.format_bc_side_label(bottom_phys, bottom_math);
                left_label = app.format_bc_side_label(left_phys, left_math);
                right_label = app.format_bc_side_label(right_phys, right_math);
                text(ax, 0, Ly/2 + Ly*0.09, top_label, 'Color', C.fg_text, ...
                    'HorizontalAlignment', 'center', 'FontSize', 11, 'Interpreter', 'none');
                text(ax, 0, -Ly/2 - Ly*0.09, bottom_label, 'Color', C.fg_text, ...
                    'HorizontalAlignment', 'center', 'FontSize', 11, 'Interpreter', 'none');
                text(ax, -Lx/2 - Lx*0.10, 0, left_label, 'Color', C.fg_text, ...
                    'HorizontalAlignment', 'center', 'FontSize', 11, 'Rotation', 90, 'Interpreter', 'none');
                text(ax, Lx/2 + Lx*0.10, 0, right_label, 'Color', C.fg_text, ...
                    'HorizontalAlignment', 'center', 'FontSize', 11, 'Rotation', 90, 'Interpreter', 'none');

                text(ax, 0, -Ly/2 - Ly*0.18, sprintf('$L_x = %.2g$', Lx), 'Color', C.fg_text, ...
                    'HorizontalAlignment', 'center', 'FontSize', 12, 'Interpreter', 'latex');
                text(ax, Lx/2 + Lx*0.20, 0, sprintf('$L_y = %.2g$', Ly), 'Color', C.fg_text, ...
                    'HorizontalAlignment', 'center', 'FontSize', 12, 'Rotation', 90, 'Interpreter', 'latex');

                % Persistent legend (always shown regardless of active BC set).
                h_per = plot(ax, nan, nan, '-', 'Color', periodic_lr_color, 'LineWidth', 2.0);
                h_nos = plot(ax, nan, nan, '-', 'Color', noslip_color, 'LineWidth', 2.0);
                if is_spectral
                    h_nfx = plot(ax, nan, nan, '--', 'Color', noflux_color, 'LineWidth', 2.0);
                    legend(ax, [h_per, h_nos, h_nfx], ...
                        {'Periodic', 'Pinned | dirichlet', 'No-flux | neumann'}, ...
                        'Location', 'southoutside', 'NumColumns', 3, 'TextColor', C.fg_text, ...
                        'Color', C.bg_panel_alt, 'EdgeColor', C.accent_gray);
                elseif is_swe
                    h_opn = plot(ax, nan, nan, '-', 'Color', app.hex_to_rgb('#A78BFA'), 'LineWidth', 2.0);
                    legend(ax, [h_per, h_nos, h_opn], ...
                        {'Periodic', 'Reflective wall', 'Open | absorbing'}, ...
                        'Location', 'southoutside', 'NumColumns', 3, 'TextColor', C.fg_text, ...
                        'Color', C.bg_panel_alt, 'EdgeColor', C.accent_gray);
                else
                    h_drv = plot(ax, nan, nan, '-', 'Color', driven_color, 'LineWidth', 2.0);
                    legend(ax, [h_per, h_nos, h_drv], ...
                        {'Periodic', 'No-slip wall | psi const', 'Driven wall | psi const + wall speed'}, ...
                        'Location', 'southoutside', 'NumColumns', 3, 'TextColor', C.fg_text, ...
                        'Color', C.bg_panel_alt, 'EdgeColor', C.accent_gray);
                end

                hold(ax, 'off');
                title(ax, 'Domain \& Boundary Conditions', 'Interpreter', 'latex', ...
                    'FontSize', 13, 'Color', C.fg_text);
                margin = max(Lx, Ly) * 0.24;
                xlim(ax, [-Lx/2 - margin, Lx/2 + margin]);
                ylim(ax, [-Ly/2 - margin, Ly/2 + margin]);
                axis(ax, 'equal');
                axis(ax, 'off');
                grid(ax, 'off');
            end
            app.update_bathymetry_preview();
            app.update_all_phase2_previews();
        end

        function apply_config_layout_profile(app, profile)
            if ~isfield(app.handles, 'config_root_grid') || ~isvalid(app.handles.config_root_grid)
                return;
            end
            root = app.handles.config_root_grid;

            left_ok = isfield(app.handles, 'config_left_panel') && isvalid(app.handles.config_left_panel);
            right_ok = isfield(app.handles, 'config_right_panel') && isvalid(app.handles.config_right_panel);
            can_resize = isprop(root, 'GridSize');

            coords_left = app.layout_cfg.coords.config.left;
            coords_right = app.layout_cfg.coords.config.right;

            switch char(string(profile))
                case 'compact'
                    if can_resize
                        root.GridSize = [1, 2];
                    end
                    root.RowHeight = app.layout_cfg.config_tab.root.row_heights;
                    root.ColumnWidth = app.layout_cfg.config_tab.root.col_widths;
                    root.Padding = [4 4 4 4];
                    root.ColumnSpacing = 6;
                    if left_ok
                        app.handles.config_left_panel.Layout.Row = coords_left(1);
                        app.handles.config_left_panel.Layout.Column = coords_left(2);
                    end
                    if right_ok
                        app.handles.config_right_panel.Layout.Row = coords_right(1);
                        app.handles.config_right_panel.Layout.Column = coords_right(2);
                    end
                case 'wide'
                    if can_resize
                        root.GridSize = [1, 2];
                    end
                    root.RowHeight = app.layout_cfg.config_tab.root.row_heights;
                    root.ColumnWidth = app.layout_cfg.config_tab.root.col_widths;
                    root.Padding = app.layout_cfg.config_tab.root.padding;
                    root.ColumnSpacing = app.layout_cfg.config_tab.root.col_spacing;
                    if left_ok
                        app.handles.config_left_panel.Layout.Row = coords_left(1);
                        app.handles.config_left_panel.Layout.Column = coords_left(2);
                    end
                    if right_ok
                        app.handles.config_right_panel.Layout.Row = coords_right(1);
                        app.handles.config_right_panel.Layout.Column = coords_right(2);
                    end
                otherwise
                    if can_resize
                        root.GridSize = [1, 2];
                    end
                    root.RowHeight = app.layout_cfg.config_tab.root.row_heights;
                    root.ColumnWidth = app.layout_cfg.config_tab.root.col_widths;
                    root.Padding = app.layout_cfg.config_tab.root.padding;
                    root.ColumnSpacing = app.layout_cfg.config_tab.root.col_spacing;
                    if left_ok
                        app.handles.config_left_panel.Layout.Row = coords_left(1);
                        app.handles.config_left_panel.Layout.Column = coords_left(2);
                    end
                    if right_ok
                        app.handles.config_right_panel.Layout.Row = coords_right(1);
                        app.handles.config_right_panel.Layout.Column = coords_right(2);
                    end
            end
        end

        function apply_config_form_layout_profile(app, profile, ui_scale)
            if nargin < 3 || isempty(ui_scale)
                ui_scale = 1;
            end

            switch char(string(profile))
                case 'compact'
                    panel_pad = [4 4 4 4];
                    grid_spacing = 4;
                    quad_spacing = 6;
                    ic_pad = [3 3 3 3];
                    ic_spacing = 3;
                case 'wide'
                    panel_pad = [6 6 6 6];
                    grid_spacing = 6;
                    quad_spacing = 8;
                    ic_pad = [4 4 4 4];
                    ic_spacing = 4;
                otherwise
                    panel_pad = [5 5 5 5];
                    grid_spacing = 5;
                    quad_spacing = 8;
                    ic_pad = [4 4 4 4];
                    ic_spacing = 4;
            end

            panel_pad = max(2, round(double(panel_pad) * max(ui_scale, 0.9)));
            grid_spacing = max(3, round(grid_spacing * max(ui_scale, 0.9)));
            quad_spacing = max(4, round(quad_spacing * max(ui_scale, 0.9)));
            ic_spacing = max(3, round(ic_spacing * max(ui_scale, 0.9)));

            if app.has_valid_handle('config_grid_quad_layout')
                app.handles.config_grid_quad_layout.Padding = panel_pad;
                app.handles.config_grid_quad_layout.RowSpacing = quad_spacing;
                app.handles.config_grid_quad_layout.ColumnSpacing = quad_spacing;
            end

            if app.has_valid_handle('config_method_grid')
                app.handles.config_method_grid.Padding = panel_pad;
                app.handles.config_method_grid.RowSpacing = grid_spacing;
            end

            if app.has_valid_handle('config_grid_layout')
                app.handles.config_grid_layout.ColumnWidth = app.build_config_form_column_widths('grid', profile);
                app.handles.config_grid_layout.Padding = panel_pad;
                app.handles.config_grid_layout.RowSpacing = grid_spacing;
                app.handles.config_grid_layout.ColumnSpacing = grid_spacing;
            end

            if app.has_valid_handle('config_time_layout')
                app.handles.config_time_layout.ColumnWidth = app.build_config_form_column_widths('time', profile);
                app.handles.config_time_layout.Padding = panel_pad;
                app.handles.config_time_layout.RowSpacing = grid_spacing;
                app.handles.config_time_layout.ColumnSpacing = grid_spacing;
            end

            if app.has_valid_handle('config_wave_layout')
                app.handles.config_wave_layout.ColumnWidth = app.build_config_form_column_widths('wave', profile);
                app.handles.config_wave_layout.Padding = panel_pad;
                app.handles.config_wave_layout.RowSpacing = grid_spacing;
                app.handles.config_wave_layout.ColumnSpacing = grid_spacing;
            end

            if app.has_valid_handle('config_sim_layout')
                app.handles.config_sim_layout.ColumnWidth = app.build_config_form_column_widths('simulation', profile);
                app.handles.config_sim_layout.Padding = panel_pad;
                app.handles.config_sim_layout.RowSpacing = grid_spacing;
                app.handles.config_sim_layout.ColumnSpacing = grid_spacing;
            end

            if app.has_valid_handle('config_conv_layout')
                app.handles.config_conv_layout.ColumnWidth = app.build_config_form_column_widths('convergence', profile);
                app.handles.config_conv_layout.Padding = panel_pad;
                app.handles.config_conv_layout.RowSpacing = grid_spacing;
                app.handles.config_conv_layout.ColumnSpacing = grid_spacing;
            end

            if app.has_valid_handle('config_sus_layout')
                app.handles.config_sus_layout.ColumnWidth = app.build_config_form_column_widths('sustainability', profile);
                app.handles.config_sus_layout.Padding = panel_pad;
                app.handles.config_sus_layout.RowSpacing = grid_spacing;
                app.handles.config_sus_layout.ColumnSpacing = grid_spacing;
            end

            if app.has_valid_handle('ic_editor_grid')
                app.handles.ic_editor_grid.ColumnWidth = app.build_ic_editor_column_widths(profile);
                app.handles.ic_editor_grid.Padding = ic_pad;
                app.handles.ic_editor_grid.RowSpacing = ic_spacing;
                app.handles.ic_editor_grid.ColumnSpacing = ic_spacing;
            end
        end

        function label = format_bc_side_label(app, physical_name, math_name)
            phys = lower(strtrim(char(string(physical_name))));
            math_tok = lower(strtrim(char(string(math_name))));
            switch phys
                case 'periodic'
                    label = 'periodic';
                case 'open_absorbing'
                    label = 'open | absorbing';
                case 'pinned'
                    label = 'pinned | dirichlet';
                case 'no_flux'
                    label = 'no-flux | neumann';
                case 'driven'
                    label = 'driven wall | psi const + wall speed';
                otherwise
                    if strcmp(app.resolve_bc_method_token(), 'shallow_water')
                        label = 'no-slip | reflective wall';
                    else
                        label = 'no-slip wall | psi const';
                    end
            end
        end

        function rgb = hex_to_rgb(~, hex_code)
            token = upper(strrep(char(string(hex_code)), '#', ''));
            if numel(token) ~= 6
                rgb = [0.5 0.5 0.5];
                return;
            end
            rgb = [ ...
                hex2dec(token(1:2)), ...
                hex2dec(token(3:4)), ...
                hex2dec(token(5:6))] / 255;
        end

        function render_fd_stencil(app, ax)
            % Render 5-point FD computational stencil with LaTeX labels
            % Displays the finite difference computational molecule showing
            % the 5-point stencil used for Laplacian discretization
            C = app.layout_cfg.colors;

            cla(ax);
            hold(ax, 'on');

            % Center point (i,j)
            scatter(ax, 0, 0, 200, 'filled', 'MarkerFaceColor', C.accent_red, ...
                'MarkerEdgeColor', C.fg_text, 'LineWidth', 1.5);

            % Neighboring points (iÃ‚Â±1,j) and (i,jÃ‚Â±1)
            scatter(ax, [1, -1, 0, 0], [0, 0, 1, -1], 120, 'filled', ...
                'MarkerFaceColor', C.accent_cyan, ...
                'MarkerEdgeColor', C.fg_text, 'LineWidth', 1.0);

            % Draw connecting lines (stencil arms)
            plot(ax, [-1 1], [0 0], '-', 'Color', C.accent_yellow, 'LineWidth', 2.5);
            plot(ax, [0 0], [-1 1], '-', 'Color', C.accent_yellow, 'LineWidth', 2.5);

            % LaTeX labels for grid points
            text(ax, 0, 0, '  $\omega_{i,j}$', 'Interpreter', 'latex', ...
                'FontSize', 14, 'Color', C.fg_text, 'HorizontalAlignment', 'left', ...
                'VerticalAlignment', 'middle', 'FontWeight', 'bold');

            text(ax, 1, 0, '  $\omega_{i+1,j}$', 'Interpreter', 'latex', ...
                'FontSize', 12, 'Color', C.fg_text, 'HorizontalAlignment', 'left', ...
                'VerticalAlignment', 'middle');

            text(ax, -1, 0, '$\omega_{i-1,j}$  ', 'Interpreter', 'latex', ...
                'FontSize', 12, 'Color', C.fg_text, 'HorizontalAlignment', 'right', ...
                'VerticalAlignment', 'middle');

            text(ax, 0, 1, '$\omega_{i,j+1}$', 'Interpreter', 'latex', ...
                'FontSize', 12, 'Color', C.fg_text, 'HorizontalAlignment', 'center', ...
                'VerticalAlignment', 'bottom');

            text(ax, 0, -1, '$\omega_{i,j-1}$', 'Interpreter', 'latex', ...
                'FontSize', 12, 'Color', C.fg_text, 'HorizontalAlignment', 'center', ...
                'VerticalAlignment', 'top');

            % Direction labels (iÃ¢â€ â€™ and jÃ¢â€ â€˜)
            text(ax, 1.3, 0, '$i \rightarrow$', 'Interpreter', 'latex', ...
                'FontSize', 11, 'Color', C.fg_muted, 'FontAngle', 'italic');

            text(ax, 0, 1.3, '$j \uparrow$', 'Interpreter', 'latex', ...
                'FontSize', 11, 'Color', C.fg_muted, 'FontAngle', 'italic');

            % Axis configuration
            axis(ax, 'equal');
            xlim(ax, [-1.6, 1.6]);
            ylim(ax, [-1.6, 1.6]);
            ax.XColor = 'none';
            ax.YColor = 'none';
            ax.Color = C.bg_panel_alt;

            % Title
            title(ax, 'FD Stencil (5-point Laplacian)', 'Interpreter', 'latex', ...
                'Color', C.fg_text, 'FontSize', 12, 'FontWeight', 'bold');

            % Discretization equation annotation
            annotation_text = {
                '$\nabla^2\omega \approx \frac{\omega_{i+1,j} - 2\omega_{i,j} + \omega_{i-1,j}}{\Delta x^2}$',
                '$ + \frac{\omega_{i,j+1} - 2\omega_{i,j} + \omega_{i,j-1}}{\Delta y^2}$'
            };

            text(ax, 0, -1.4, annotation_text, 'Interpreter', 'latex', ...
                'FontSize', 9, 'Color', C.fg_muted, 'HorizontalAlignment', 'center');

            hold(ax, 'off');
        end

        function on_method_changed(app)
            method_val = app.handles.method_dropdown.Value;
            is_fd = strcmp(method_val, 'Finite Difference');
            is_fv = strcmp(method_val, 'Finite Volume');
            is_swe = strcmp(method_val, 'Shallow Water');
            is_spectral = strcmp(method_val, 'Spectral');
            switch method_val
                case 'Finite Difference'
                    app.config.method = 'finite_difference';
                case 'Finite Volume'
                    app.config.method = 'finite_volume';
                case 'Shallow Water'
                    app.config.method = 'shallow_water';
                case 'Spectral'
                    app.config.method = 'spectral';
            end
            app.set_optional_handle_enable('arakawa_enable', app.on_off(is_fd));
            if ~is_fd && app.has_valid_handle('arakawa_enable')
                app.handles.arakawa_enable.Value = false;
            end
            app.set_optional_handle_enable('gpu_enable', 'on');

            app.update_time_integrator_options(is_fd, is_fv, is_swe, is_spectral);
            app.sync_ic_dropdown_items_for_active_method();
            app.update_ic_fields();
            if isfield(app.handles, 'bathymetry_active_entry') && isstruct(app.handles.bathymetry_active_entry) && ...
                    isfield(app.handles.bathymetry_active_entry, 'id') && ~isempty(app.handles.bathymetry_active_entry.id)
                app.persist_active_bathymetry_state(app.handles.bathymetry_active_entry);
            end
            app.sync_bathymetry_scenario_items_for_method();
            app.sync_bathymetry_controls('interactive');
            
            % Update convergence display with selected method
            app.update_convergence_display();
            app.update_ic_preview();
            app.update_bathymetry_preview();
            app.update_grid_domain_plots(); % Refresh grid visualization (FD stencil toggle)
            app.update_checklist();
            app.audit_math_rendering('method-change');
        end

        function on_simulation_scenario_changed(app)
            if ~app.has_valid_handle('simulation_scenario')
                return;
            end
            if isfield(app.handles, 'bathymetry_active_entry') && isstruct(app.handles.bathymetry_active_entry) && ...
                    isfield(app.handles.bathymetry_active_entry, 'id') && ~isempty(app.handles.bathymetry_active_entry.id)
                app.persist_active_bathymetry_state(app.handles.bathymetry_active_entry);
            end
            req_name = char(string(app.handles.simulation_scenario.Value));
            entry = app.find_simulation_scenario_entry(req_name);
            app.config.simulation_scenario = entry.scenario_name;
            app.apply_simulation_scenario_overrides(entry);
            app.sync_bathymetry_scenario_items_for_method();
            app.sync_bathymetry_controls('interactive');
            app.update_bathymetry_preview();
            app.update_all_phase2_previews();
            app.update_checklist();
        end

        function on_bathymetry_scenario_changed(app)
            if isfield(app.handles, 'bathymetry_active_entry') && isstruct(app.handles.bathymetry_active_entry) && ...
                    isfield(app.handles.bathymetry_active_entry, 'id') && ~isempty(app.handles.bathymetry_active_entry.id)
                app.persist_active_bathymetry_state(app.handles.bathymetry_active_entry);
            end
            app.sync_bathymetry_controls('interactive');
            app.update_bathymetry_preview();
            app.update_checklist();
        end

        function on_bathymetry_bed_slope_changed(app)
            app.on_bathymetry_dynamic_control_changed();
        end

        function on_bathymetry_dynamic_control_changed(app)
            if ~app.has_valid_handle('bathymetry_scenario')
                return;
            end
            entry = app.find_bathymetry_scenario_entry(app.handles.bathymetry_scenario.Value);
            app.persist_active_bathymetry_state(entry);
            app.update_bathymetry_preview();
            app.update_checklist();
        end

        function sync_bathymetry_scenario_items_for_method(app)
            if ~app.has_valid_handle('bathymetry_scenario')
                return;
            end
            dim = app.get_active_bathymetry_dimension();
            catalog = app.get_bathymetry_catalog(dim);
            ids = cell(1, numel(catalog));
            labels = cell(1, numel(catalog));
            for i = 1:numel(catalog)
                ids{i} = char(string(catalog(i).id));
                labels{i} = char(string(catalog(i).display_name));
            end
            app.handles.bathymetry_scenario.Items = labels;
            app.handles.bathymetry_scenario.ItemsData = ids;

            requested = '';
            if isfield(app.config, 'bathymetry_scenario')
                requested = char(string(app.config.bathymetry_scenario));
            elseif app.has_valid_handle('bathymetry_scenario')
                requested = char(string(app.handles.bathymetry_scenario.Value));
            end
            requested = normalize_bathymetry_scenario_token(requested);
            if ~any(strcmpi(requested, ids))
                requested = ids{1};
            end
            app.handles.bathymetry_scenario.Value = requested;
            app.config.bathymetry_dimension_policy = 'by_method';
            app.config.bathymetry_scenario = requested;
        end

        function dim = get_active_bathymetry_dimension(app)
            dim = '2d';
            method_name = '';
            if app.has_valid_handle('method_dropdown')
                method_name = char(string(app.handles.method_dropdown.Value));
            elseif isfield(app.config, 'method')
                method_token = lower(char(string(app.config.method)));
                if strcmp(method_token, 'finite_volume')
                    method_name = 'Finite Volume';
                end
            end
            if strcmpi(method_name, 'Finite Volume')
                dim = '3d';
            end
        end

        function catalog = get_bathymetry_catalog(app, dim)
            dim_token = lower(char(string(dim)));
            source = struct();
            if isfield(app.layout_cfg, 'ui_defaults') && isstruct(app.layout_cfg.ui_defaults)
                source = app.layout_cfg.ui_defaults;
            end
            field_name = 'bathymetry_scenario_catalog_2d';
            if strcmp(dim_token, '3d')
                field_name = 'bathymetry_scenario_catalog_3d';
            end
            if ~isfield(source, field_name)
                error('UIController:MissingBathymetryCatalog', ...
                    'Missing required defaults field: %s', field_name);
            end
            catalog = source.(field_name);
            if ~isstruct(catalog) || isempty(catalog)
                error('UIController:InvalidBathymetryCatalog', ...
                    'Bathymetry catalog %s is empty or invalid.', field_name);
            end
        end

        function entry = find_bathymetry_scenario_entry(app, req)
            req_token = normalize_bathymetry_scenario_token(req);
            dim = app.get_active_bathymetry_dimension();
            catalog = app.get_bathymetry_catalog(dim);
            entry = catalog(1);
            idx = find(strcmpi(req_token, lower(string({catalog.id}))), 1, 'first');
            if isempty(idx)
                idx = find(strcmpi(req_token, lower(string({catalog.display_name}))), 1, 'first');
            end
            if isempty(idx)
                for i = 1:numel(catalog)
                    aliases = {};
                    if isfield(catalog(i), 'legacy_aliases') && ~isempty(catalog(i).legacy_aliases)
                        aliases = cellstr(string(catalog(i).legacy_aliases));
                    end
                    if any(strcmpi(req_token, aliases))
                        idx = i;
                        break;
                    end
                end
            end
            if isempty(idx)
                error('UIController:UnknownBathymetryScenario', ...
                    'Unknown bathymetry scenario token: %s', req_token);
            end
            entry = catalog(idx);
        end

        function flags = get_bathymetry_shared_flags(~, entry)
            flags = struct('show_bed_slope', false, 'show_depth_offset', false, ...
                'show_relief_amplitude', false, 'show_resolution', false);
            if isstruct(entry) && isfield(entry, 'shared_flags') && isstruct(entry.shared_flags)
                entry_flags = entry.shared_flags;
                names = fieldnames(entry_flags);
                for i = 1:numel(names)
                    flags.(names{i}) = logical(entry_flags.(names{i}));
                end
            end
        end

        function state = default_bathymetry_state(app, entry)
            state = struct();
            defaults = struct();
            if isfield(app.layout_cfg, 'ui_defaults') && isstruct(app.layout_cfg.ui_defaults)
                defaults = app.layout_cfg.ui_defaults;
            end

            if isfield(defaults, 'bathymetry_dynamic_params') && isstruct(defaults.bathymetry_dynamic_params) && ...
                    isfield(defaults.bathymetry_dynamic_params, entry.id) && ...
                    isstruct(defaults.bathymetry_dynamic_params.(entry.id))
                state = defaults.bathymetry_dynamic_params.(entry.id);
            end

            flags = app.get_bathymetry_shared_flags(entry);
            if flags.show_bed_slope && ~isfield(state, 'bed_slope')
                state.bed_slope = double(app.pick_field_required(defaults, {'bathymetry_bed_slope'}, 0.03));
            end
            if flags.show_depth_offset && ~isfield(state, 'depth_offset')
                state.depth_offset = double(app.pick_field_required(defaults, {'bathymetry_depth_offset'}, 1000.0));
            end
            if flags.show_relief_amplitude && ~isfield(state, 'relief_amplitude')
                state.relief_amplitude = double(app.pick_field_required(defaults, {'bathymetry_relief_amplitude'}, 180.0));
            end
            if flags.show_resolution && ~isfield(state, 'interpolation_resolution')
                state.interpolation_resolution = round(double(app.pick_field_required(defaults, {'bathymetry_resolution'}, 96)));
            end

            if isfield(entry, 'dynamic_fields') && ~isempty(entry.dynamic_fields)
                for i = 1:numel(entry.dynamic_fields)
                    field = entry.dynamic_fields(i);
                    if ~isfield(state, field.id)
                        state.(field.id) = double(field.default);
                    end
                end
            end
        end

        function state = get_bathymetry_state_for_entry(app, entry)
            state = app.default_bathymetry_state(entry);
            if isfield(app.config, 'bathymetry_dynamic_params') && isstruct(app.config.bathymetry_dynamic_params) && ...
                    isfield(app.config.bathymetry_dynamic_params, entry.id) && ...
                    isstruct(app.config.bathymetry_dynamic_params.(entry.id))
                state = app.overlay_numeric_struct(state, app.config.bathymetry_dynamic_params.(entry.id));
            else
                flags = app.get_bathymetry_shared_flags(entry);
                if flags.show_bed_slope && isfield(app.config, 'bathymetry_bed_slope') && isfinite(app.config.bathymetry_bed_slope)
                    state.bed_slope = double(app.config.bathymetry_bed_slope);
                end
                if flags.show_depth_offset && isfield(app.config, 'bathymetry_depth_offset') && isfinite(app.config.bathymetry_depth_offset)
                    state.depth_offset = double(app.config.bathymetry_depth_offset);
                end
                if flags.show_relief_amplitude && isfield(app.config, 'bathymetry_relief_amplitude') && isfinite(app.config.bathymetry_relief_amplitude)
                    state.relief_amplitude = double(app.config.bathymetry_relief_amplitude);
                end
                if flags.show_resolution && isfield(app.config, 'bathymetry_resolution') && isfinite(app.config.bathymetry_resolution)
                    state.interpolation_resolution = round(double(app.config.bathymetry_resolution));
                end
            end
        end

        function build_bathymetry_dynamic_controls(app, entry, seed_state)
            if ~app.has_valid_handle('bathymetry_dynamic_box')
                return;
            end
            if nargin < 3 || ~isstruct(seed_state)
                seed_state = struct();
            end

            box = app.handles.bathymetry_dynamic_box;
            if ~isempty(box.Children)
                delete(box.Children);
            end

            flags = app.get_bathymetry_shared_flags(entry);
            shared_specs = {};
            if flags.show_bed_slope
                shared_specs{end + 1} = struct('label_handle', 'bathymetry_bed_slope_label', 'input_handle', 'bathymetry_bed_slope', ... %#ok<AGROW>
                    'label', 'Bed Elevation', 'value_key', 'bed_slope', 'default', 0.03, ...
                    'limits', [-2.0 2.0], 'integer', false, 'callback', @(~,~) app.on_bathymetry_dynamic_control_changed(), ...
                    'tooltip', app.pick_field(app.layout_cfg.tooltips, {'bathymetry_bed_slope'}, 'Shared bathymetry slope control.'));
            end
            if flags.show_depth_offset
                shared_specs{end + 1} = struct('label_handle', 'bathymetry_depth_offset_label', 'input_handle', 'bathymetry_depth_offset', ... %#ok<AGROW>
                    'label', 'Depth Offset', 'value_key', 'depth_offset', 'default', 1000.0, ...
                    'limits', [0 1e6], 'integer', false, 'callback', @(~,~) app.on_bathymetry_dynamic_control_changed(), ...
                    'tooltip', app.pick_field(app.layout_cfg.tooltips, {'bathymetry_depth_offset'}, 'Base depth/elevation offset for 3D bathymetry presets.'));
            end
            if flags.show_relief_amplitude
                shared_specs{end + 1} = struct('label_handle', 'bathymetry_relief_amplitude_label', 'input_handle', 'bathymetry_relief_amplitude', ... %#ok<AGROW>
                    'label', 'Relief Amplitude', 'value_key', 'relief_amplitude', 'default', 180.0, ...
                    'limits', [0 1e6], 'integer', false, 'callback', @(~,~) app.on_bathymetry_dynamic_control_changed(), ...
                    'tooltip', app.pick_field(app.layout_cfg.tooltips, {'bathymetry_relief_amplitude'}, 'Shared relief amplitude used by 3D bathymetry presets.'));
            end
            if flags.show_resolution
                shared_specs{end + 1} = struct('label_handle', 'bathymetry_resolution_label', 'input_handle', 'bathymetry_resolution', ... %#ok<AGROW>
                    'label', 'Interpolation Resolution', 'value_key', 'interpolation_resolution', 'default', 96, ...
                    'limits', [24 256], 'integer', true, 'callback', @(~,~) app.on_bathymetry_dynamic_control_changed(), ...
                    'tooltip', app.pick_field(app.layout_cfg.tooltips, {'bathymetry_resolution'}, 'Auxiliary interpolation resolution for custom-point bathymetry previewing.'));
            end

            for i = 1:numel(shared_specs)
                spec = shared_specs{i};
                if isfield(seed_state, spec.value_key)
                    spec.default = double(seed_state.(spec.value_key));
                end
                shared_specs{i} = spec;
            end

            dynamic_fields = struct([]);
            if isfield(entry, 'dynamic_fields')
                dynamic_fields = entry.dynamic_fields;
            end

            total_controls = numel(shared_specs) + numel(dynamic_fields);
            n_rows = max(1, ceil(total_controls / 4));
            grid = uigridlayout(box, [n_rows, 12]);
            grid.ColumnWidth = {96, '1x', '1x', 96, '1x', '1x', 96, '1x', '1x', 96, '1x', '1x'};
            grid.RowHeight = repmat({'fit'}, 1, n_rows);
            grid.Padding = [6 6 6 6];
            grid.RowSpacing = 5;
            grid.ColumnSpacing = 6;

            inputs = struct();
            labels = struct();
            C = app.layout_cfg.colors;
            app.handles.bathymetry_bed_slope_label = [];
            app.handles.bathymetry_bed_slope = [];
            app.handles.bathymetry_depth_offset_label = [];
            app.handles.bathymetry_depth_offset = [];
            app.handles.bathymetry_relief_amplitude_label = [];
            app.handles.bathymetry_relief_amplitude = [];
            app.handles.bathymetry_resolution_label = [];
            app.handles.bathymetry_resolution = [];

            if total_controls == 0
                empty_text = 'No conditional settings are required for the active bathymetry.';
                if isfield(entry, 'empty_state_text') && strlength(string(entry.empty_state_text)) > 0
                    empty_text = char(string(entry.empty_state_text));
                end
                empty_lbl = uilabel(grid, 'Text', empty_text, ...
                    'FontColor', C.fg_muted, 'FontSize', 11, 'HorizontalAlignment', 'left');
                empty_lbl.Layout.Row = 1;
                empty_lbl.Layout.Column = [1 12];
                if isprop(empty_lbl, 'WordWrap')
                    empty_lbl.WordWrap = 'on';
                end
                app.handles.bathymetry_dynamic_grid = grid;
                app.handles.bathymetry_dynamic_inputs = inputs;
                app.handles.bathymetry_dynamic_labels = labels;
                app.handles.bathymetry_active_entry = entry;
                return;
            end

            for i = 1:numel(shared_specs)
                spec = shared_specs{i};
                row = ceil(i / 4);
                slot = mod(i - 1, 4);
                base_col = slot * 3 + 1;
                lbl = uilabel(grid, 'Text', spec.label, ...
                    'FontColor', C.fg_text, 'FontSize', 11, 'HorizontalAlignment', 'right');
                lbl.Layout.Row = row;
                lbl.Layout.Column = base_col;
                if isprop(lbl, 'WordWrap')
                    lbl.WordWrap = 'on';
                end
                if isfield(spec, 'tooltip') && isprop(lbl, 'Tooltip')
                    lbl.Tooltip = char(string(spec.tooltip));
                end

                input = uieditfield(grid, 'numeric', ...
                    'Value', double(spec.default), ...
                    'ValueChangedFcn', spec.callback);
                if ~isempty(spec.limits)
                    input.Limits = double(spec.limits(:)).';
                end
                if spec.integer && isprop(input, 'RoundFractionalValues')
                    input.RoundFractionalValues = 'on';
                end
                if isfield(spec, 'tooltip') && isprop(input, 'Tooltip')
                    input.Tooltip = char(string(spec.tooltip));
                end
                input.Layout.Row = row;
                input.Layout.Column = [base_col + 1, base_col + 2];

                app.handles.(spec.label_handle) = lbl;
                app.handles.(spec.input_handle) = input;
            end

            for i = 1:numel(dynamic_fields)
                field = dynamic_fields(i);
                control_idx = numel(shared_specs) + i;
                row = ceil(control_idx / 4);
                slot = mod(control_idx - 1, 4);
                base_col = slot * 3 + 1;
                lbl = uilabel(grid, 'Text', field.label, ...
                    'FontColor', C.fg_text, 'FontSize', 11, 'HorizontalAlignment', 'right');
                lbl.Layout.Row = row;
                lbl.Layout.Column = base_col;
                if isprop(lbl, 'WordWrap')
                    lbl.WordWrap = 'on';
                end
                if isfield(field, 'tooltip') && isprop(lbl, 'Tooltip')
                    lbl.Tooltip = char(string(field.tooltip));
                end

                seed_value = double(field.default);
                if isfield(seed_state, field.id)
                    seed_value = double(seed_state.(field.id));
                end
                input = uieditfield(grid, 'numeric', ...
                    'Value', seed_value, ...
                    'ValueChangedFcn', @(~,~) app.on_bathymetry_dynamic_control_changed());
                if isfield(field, 'limits') && isnumeric(field.limits) && numel(field.limits) == 2
                    input.Limits = double(field.limits(:)).';
                end
                if isfield(field, 'is_integer') && logical(field.is_integer) && isprop(input, 'RoundFractionalValues')
                    input.RoundFractionalValues = 'on';
                end
                if isfield(field, 'tooltip') && isprop(input, 'Tooltip')
                    input.Tooltip = char(string(field.tooltip));
                end
                input.Layout.Row = row;
                input.Layout.Column = [base_col + 1, base_col + 2];

                labels.(field.id) = lbl;
                inputs.(field.id) = input;
            end

            app.handles.bathymetry_dynamic_grid = grid;
            app.handles.bathymetry_dynamic_inputs = inputs;
            app.handles.bathymetry_dynamic_labels = labels;
            app.handles.bathymetry_active_entry = entry;
        end

        function state = read_active_bathymetry_state(app, entry)
            state = app.get_bathymetry_state_for_entry(entry);
            if app.has_valid_handle('bathymetry_bed_slope')
                state.bed_slope = double(app.handles.bathymetry_bed_slope.Value);
            end
            if app.has_valid_handle('bathymetry_depth_offset')
                state.depth_offset = double(app.handles.bathymetry_depth_offset.Value);
            end
            if app.has_valid_handle('bathymetry_relief_amplitude')
                state.relief_amplitude = double(app.handles.bathymetry_relief_amplitude.Value);
            end
            if app.has_valid_handle('bathymetry_resolution')
                state.interpolation_resolution = round(double(app.handles.bathymetry_resolution.Value));
            end

            if isfield(entry, 'dynamic_fields') && ~isempty(entry.dynamic_fields) && ...
                    isfield(app.handles, 'bathymetry_dynamic_inputs') && isstruct(app.handles.bathymetry_dynamic_inputs)
                inputs = app.handles.bathymetry_dynamic_inputs;
                for i = 1:numel(entry.dynamic_fields)
                    field = entry.dynamic_fields(i);
                    if ~isfield(inputs, field.id)
                        continue;
                    end
                    h = inputs.(field.id);
                    if isempty(h) || ~isvalid(h)
                        continue;
                    end
                    value = double(h.Value);
                    if isfield(field, 'is_integer') && logical(field.is_integer)
                        value = round(value);
                    end
                    state.(field.id) = value;
                end
            end
        end

        function persist_active_bathymetry_state(app, entry)
            state = app.read_active_bathymetry_state(entry);
            if ~isfield(app.config, 'bathymetry_dynamic_params') || ~isstruct(app.config.bathymetry_dynamic_params)
                app.config.bathymetry_dynamic_params = struct();
            end
            app.config.bathymetry_dynamic_params.(entry.id) = state;
            app.config.bathymetry_scenario = entry.id;
            if isfield(state, 'bed_slope')
                app.config.bathymetry_bed_slope = double(state.bed_slope);
            end
            if isfield(state, 'depth_offset')
                app.config.bathymetry_depth_offset = double(state.depth_offset);
            end
            if isfield(state, 'relief_amplitude')
                app.config.bathymetry_relief_amplitude = double(state.relief_amplitude);
            end
            if isfield(state, 'interpolation_resolution')
                app.config.bathymetry_resolution = round(double(state.interpolation_resolution));
            end
        end

        function merged = overlay_numeric_struct(~, base, override)
            merged = base;
            if ~isstruct(override)
                return;
            end
            keys = fieldnames(override);
            for i = 1:numel(keys)
                key = keys{i};
                value = override.(key);
                if isnumeric(value) && isscalar(value) && isfinite(value)
                    merged.(key) = double(value);
                end
            end
        end

        function params = build_active_bathymetry_parameter_struct(app, entry)
            state = app.get_bathymetry_state_for_entry(entry);
            params = struct( ...
                'bed_slope', double(app.pick_field(state, {'bed_slope'}, app.pick_field(app.config, {'bathymetry_bed_slope'}, 0.03))), ...
                'depth_offset', double(app.pick_field(state, {'depth_offset'}, app.pick_field(app.config, {'bathymetry_depth_offset'}, 1000.0))), ...
                'relief_amplitude', double(app.pick_field(state, {'relief_amplitude'}, app.pick_field(app.config, {'bathymetry_relief_amplitude'}, 180.0))), ...
                'bathymetry_resolution', round(double(app.pick_field(state, {'interpolation_resolution'}, app.get_bathymetry_resolution()))), ...
                'bathymetry_custom_points', app.get_bathymetry_control_points());
            if isfield(app.config, 'bathymetry_dynamic_params') && isstruct(app.config.bathymetry_dynamic_params)
                params.bathymetry_dynamic_params = app.config.bathymetry_dynamic_params;
            else
                params.bathymetry_dynamic_params = struct();
            end
            params.z0 = params.depth_offset;
            params.amplitude = params.relief_amplitude;
            params.bathymetry_depth_offset = params.depth_offset;
            params.bathymetry_relief_amplitude = params.relief_amplitude;
            keys = fieldnames(state);
            for i = 1:numel(keys)
                params.(keys{i}) = state.(keys{i});
            end
        end

        function params = build_active_bathymetry_dispatcher_parameters(app, entry)
            params = app.config;
            if ~isstruct(params)
                params = struct();
            end
            bathymetry_params = app.build_active_bathymetry_parameter_struct(entry);
            fields = fieldnames(bathymetry_params);
            for i = 1:numel(fields)
                params.(fields{i}) = bathymetry_params.(fields{i});
            end
            params.bathymetry_scenario = char(string(entry.id));
            params.Nx = max(8, round(app.safe_numeric_value('Nx', app.pick_field(params, {'Nx'}, 64.0))));
            params.Ny = max(8, round(app.safe_numeric_value('Ny', app.pick_field(params, {'Ny'}, 64.0))));
            params.Lx = max(1.0e-6, app.safe_numeric_value('Lx', app.pick_field(params, {'Lx'}, 10.0)));
            params.Ly = max(1.0e-6, app.safe_numeric_value('Ly', app.pick_field(params, {'Ly'}, 10.0)));
        end

        function sync_bathymetry_controls(app, change_source)
            if nargin < 2 || isempty(change_source)
                change_source = 'interactive';
            end
            if ~app.has_valid_handle('bathymetry_scenario')
                return;
            end

            entry = app.find_bathymetry_scenario_entry(app.handles.bathymetry_scenario.Value);
            app.config.bathymetry_scenario = entry.id;
            seed_state = app.get_bathymetry_state_for_entry(entry);
            app.build_bathymetry_dynamic_controls(entry, seed_state);
            app.persist_active_bathymetry_state(entry);

            enabled_points = app.get_enabled_bathymetry_point_count();
            if app.has_valid_handle('btn_bathymetry_points')
                app.handles.btn_bathymetry_points.Text = sprintf('Edit Points (%d)', enabled_points);
                app.set_optional_handle_enable('btn_bathymetry_points', app.on_off(logical(entry.uses_point_editor)));
            end

            app.sync_bathymetry_bc_controls(entry, change_source);
        end

        function sync_bathymetry_bc_controls(app, entry, change_source)
            if nargin < 3 || isempty(change_source)
                change_source = 'interactive';
            end

            bc_case_items = {'Periodic (All)', 'Lid Driven Cavity', 'Driven Channel Flow', ...
                'Lid & Bottom Driven Cavity', 'Enclosed Shear Layer', 'Enclosed Cavity', 'User Defined'};
            side_items = {'Periodic', 'No-slip wall (psi const)', 'Driven wall (psi const + wall speed)'};
            top_bottom_items = side_items;
            left_right_items = side_items;
            notice_text = '';
            blocks_periodic = isstruct(entry) && isfield(entry, 'blocks_periodic_bc') && logical(entry.blocks_periodic_bc);
            supports_periodic_x = false;
            is_spectral = app.has_valid_handle('method_dropdown') && ...
                strcmpi(char(string(app.handles.method_dropdown.Value)), 'Spectral');
            is_swe = app.has_valid_handle('method_dropdown') && ...
                strcmpi(char(string(app.handles.method_dropdown.Value)), 'Shallow Water');

            if is_spectral
                bc_case_items = {'Periodic (All)', 'Pinned Box', 'No-flux Box', 'Lid Driven Cavity', ...
                    'Driven Channel Flow', 'Lid & Bottom Driven Cavity', 'Enclosed Shear Layer', 'Enclosed Cavity', 'User Defined'};
                side_items = {'Periodic', 'Pinned (Dirichlet)', 'No-flux (Neumann)', ...
                    'No-slip wall (psi const)', 'Driven wall (psi const + wall speed)'};
                top_bottom_items = side_items;
                left_right_items = side_items;
                notice_text = 'Spectral supports transform-family boxes, lifted wall-bounded scenarios, and immersed-mask 2D bathymetry for supported cases.';
            elseif is_swe
                bc_case_items = bc_case_items(~ismember(bc_case_items, ...
                    {'Lid Driven Cavity', 'Driven Channel Flow', 'Lid & Bottom Driven Cavity', 'Enclosed Shear Layer'}));
                side_items = {'Periodic', 'No-slip (Dirichlet)', 'Open (Absorbing)'};
                top_bottom_items = side_items;
                left_right_items = side_items;
            end

            if blocks_periodic
                if ~is_swe
                    supports_periodic_x = app.active_bathymetry_supports_periodic_x(entry);
                end
                bc_case_items = bc_case_items(~strcmp(bc_case_items, 'Periodic (All)'));
                top_bottom_items = top_bottom_items(~strcmp(top_bottom_items, 'Periodic'));
                if supports_periodic_x
                    notice_text = 'Non-flat bathymetry disables Periodic (All) and y-periodic walls. Periodic-x channel cases remain available when the bed is periodic in x.';
                else
                    bc_case_items = bc_case_items(~strcmp(bc_case_items, 'Driven Channel Flow'));
                    left_right_items = left_right_items(~strcmp(left_right_items, 'Periodic'));
                    notice_text = 'Non-flat bathymetry disables periodic BCs.';
                end
                if app.current_bc_selection_violates_bathymetry_periodicity(supports_periodic_x)
                    if strcmpi(change_source, 'interactive') && app.has_valid_handle('bc_case')
                        app.handles.bc_case.Value = 'Enclosed Cavity';
                        app.apply_bc_case_to_dropdowns();
                        if supports_periodic_x
                            notice_text = 'Non-flat bathymetry disables Periodic (All) and y-periodic walls. Switched to Enclosed Cavity. Periodic-x channel cases remain available when the bed is periodic in x.';
                        else
                            notice_text = 'Non-flat bathymetry disables periodic BCs. Switched to Enclosed Cavity.';
                        end
                    end
                end
            end
            if app.has_valid_handle('bc_case')
                app.handles.bc_case.Items = bc_case_items;
                if ~any(strcmp(app.handles.bc_case.Value, bc_case_items))
                    if is_spectral
                        app.handles.bc_case.Value = app.resolve_spectral_bc_case_from_current_selection();
                    else
                        app.handles.bc_case.Value = 'Enclosed Cavity';
                    end
                end
            end
            app.update_bc_side_items('bc_top', top_bottom_items, is_spectral);
            app.update_bc_side_items('bc_bottom', top_bottom_items, is_spectral);
            app.update_bc_side_items('bc_left', left_right_items, is_spectral);
            app.update_bc_side_items('bc_right', left_right_items, is_spectral);
            app.sync_bc_velocity_controls();
            if app.has_valid_handle('bathymetry_notice_label')
                app.handles.bathymetry_notice_label.Text = notice_text;
            end
        end

        function tf = active_bathymetry_supports_periodic_x(app, entry)
            if nargin < 2 || isempty(entry)
                entry = app.find_bathymetry_scenario_entry(app.handles.bathymetry_scenario.Value);
            end
            params = app.build_active_bathymetry_dispatcher_parameters(entry);
            tf = BCDispatcher.bathymetry_axis_is_periodic(params, 'x');
        end

        function tf = current_bc_selection_violates_bathymetry_periodicity(app, supports_periodic_x)
            tf = app.is_bc_handle_periodic('bc_top') || app.is_bc_handle_periodic('bc_bottom');
            if ~supports_periodic_x
                tf = tf || app.is_bc_handle_periodic('bc_left') || app.is_bc_handle_periodic('bc_right');
            end
        end

        function tf = is_bc_handle_periodic(app, handle_name)
            tf = false;
            if app.has_valid_handle(handle_name)
                tf = contains(lower(char(string(app.handles.(handle_name).Value))), 'periodic');
            end
        end

        function update_bc_side_items(app, handle_name, items, is_spectral)
            if ~app.has_valid_handle(handle_name)
                return;
            end
            app.handles.(handle_name).Items = items;
            if any(strcmp(app.handles.(handle_name).Value, items))
                return;
            end
            if is_spectral
                app.handles.(handle_name).Value = app.normalize_spectral_bc_display_label(app.handles.(handle_name).Value);
            else
                app.handles.(handle_name).Value = app.resolve_bc_display_label('dirichlet', 'no_slip');
            end
        end

        function label = normalize_spectral_bc_display_label(app, raw_label)
            [~, math_type, physical_type] = app.normalize_bc_selection(raw_label);
            if strcmp(physical_type, 'pinned') || strcmp(physical_type, 'no_slip') || strcmp(math_type, 'dirichlet')
                label = 'Pinned (Dirichlet)';
            elseif strcmp(physical_type, 'no_flux')
                label = 'No-flux (Neumann)';
            else
                label = 'Periodic';
            end
        end

        function case_label = resolve_spectral_bc_case_from_current_selection(app)
            labels = { ...
                app.normalize_spectral_bc_display_label(app.safe_bc_value('bc_top', 'Periodic')), ...
                app.normalize_spectral_bc_display_label(app.safe_bc_value('bc_bottom', 'Periodic')), ...
                app.normalize_spectral_bc_display_label(app.safe_bc_value('bc_left', 'Periodic')), ...
                app.normalize_spectral_bc_display_label(app.safe_bc_value('bc_right', 'Periodic'))};
            if all(strcmp(labels, 'Periodic'))
                case_label = 'Periodic (All)';
            elseif all(strcmp(labels, 'Pinned (Dirichlet)'))
                case_label = 'Pinned Box';
            elseif all(strcmp(labels, 'No-flux (Neumann)'))
                case_label = 'No-flux Box';
            else
                case_label = 'User Defined';
            end
        end

        function sync_bc_velocity_controls(app)
            disable_velocity = app.has_valid_handle('method_dropdown') && ...
                any(strcmpi(char(string(app.handles.method_dropdown.Value)), {'Shallow Water'}));
            state = app.on_off(~disable_velocity);
            app.set_optional_handle_enable('U_top', state);
            app.set_optional_handle_enable('U_bottom', state);
            app.set_optional_handle_enable('U_left', state);
            app.set_optional_handle_enable('U_right', state);
        end

        function catalog = get_simulation_scenario_catalog(app)
            if ~(isfield(app.layout_cfg, 'ui_defaults') && ...
                    isfield(app.layout_cfg.ui_defaults, 'simulation_scenario_catalog'))
                error('UIController:MissingSimulationScenarioCatalog', ...
                    'simulation_scenario_catalog is required in UI defaults.');
            end
            catalog = app.layout_cfg.ui_defaults.simulation_scenario_catalog;
            if ~isstruct(catalog) || isempty(catalog)
                error('UIController:InvalidSimulationScenarioCatalog', ...
                    'simulation_scenario_catalog is empty or invalid.');
            end
        end

        function entry = find_simulation_scenario_entry(app, req_name)
            catalog = app.get_simulation_scenario_catalog();
            req = lower(strtrim(char(string(req_name))));
            idx = find(strcmpi(req, lower(string({catalog.scenario_name}))), 1, 'first');
            if isempty(idx)
                error('UIController:UnknownSimulationScenario', ...
                    'Unknown simulation scenario token: %s', req);
            end
            entry = catalog(idx);
        end

        function apply_simulation_scenario_overrides(app, entry)
            if ~isstruct(entry) || ~isfield(entry, 'overrides') || ~isstruct(entry.overrides)
                return;
            end
            ov = entry.overrides;
            if isempty(fieldnames(ov))
                return;
            end

            if isfield(ov, 'method') && app.has_valid_handle('method_dropdown')
                method_token = lower(char(string(ov.method)));
                switch method_token
                    case 'finite_difference'
                        app.handles.method_dropdown.Value = 'Finite Difference';
                    case 'spectral'
                        app.handles.method_dropdown.Value = 'Spectral';
                    case 'finite_volume'
                        app.handles.method_dropdown.Value = 'Finite Volume';
                    case {'shallow_water', 'swe'}
                        app.handles.method_dropdown.Value = 'Shallow Water';
                    otherwise
                        error('UIController:UnknownScenarioMethod', ...
                            'Unsupported simulation scenario method token: %s', method_token);
                end
            end
            app.on_method_changed();

            if isfield(ov, 'mode') && app.has_valid_handle('mode_dropdown')
                mode_token = lower(char(string(ov.mode)));
                switch mode_token
                    case 'evolution'
                        app.handles.mode_dropdown.Value = 'Evolution';
                    case 'convergence'
                        app.handles.mode_dropdown.Value = 'Convergence';
                    case {'sweep', 'parameter_sweep', 'parametersweep'}
                        app.handles.mode_dropdown.Value = 'Parameter Sweep';
                    case 'animation'
                        app.handles.mode_dropdown.Value = 'Animation';
                    otherwise
                        error('UIController:UnknownScenarioMode', ...
                            'Unsupported simulation scenario mode token: %s', mode_token);
                end
            end
            app.on_mode_changed();

            if isfield(ov, 'Nx') && app.has_valid_handle('Nx'), app.handles.Nx.Value = double(ov.Nx); end
            if isfield(ov, 'Ny') && app.has_valid_handle('Ny'), app.handles.Ny.Value = double(ov.Ny); end
            if isfield(ov, 'Lx') && app.has_valid_handle('Lx'), app.handles.Lx.Value = double(ov.Lx); end
            if isfield(ov, 'Ly') && app.has_valid_handle('Ly'), app.handles.Ly.Value = double(ov.Ly); end
            if isfield(ov, 'dt') && app.has_valid_handle('dt'), app.handles.dt.Value = double(ov.dt); end
            if isfield(ov, 'Tfinal') && app.has_valid_handle('t_final'), app.handles.t_final.Value = double(ov.Tfinal); end

            if isfield(ov, 'bc_case') && app.has_valid_handle('bc_case')
                req_case = lower(char(string(ov.bc_case)));
                switch req_case
                    case 'periodic'
                        app.handles.bc_case.Value = 'Periodic (All)';
                    case 'lid_driven_cavity'
                        app.handles.bc_case.Value = 'Lid Driven Cavity';
                    case 'driven_channel_flow'
                        app.handles.bc_case.Value = 'Driven Channel Flow';
                    case 'lid_and_bottom_driven_cavity'
                        app.handles.bc_case.Value = 'Lid & Bottom Driven Cavity';
                    case 'enclosed_shear_layer'
                        app.handles.bc_case.Value = 'Enclosed Shear Layer';
                    case 'enclosed_cavity'
                        app.handles.bc_case.Value = 'Enclosed Cavity';
                    case 'user_defined'
                        app.handles.bc_case.Value = 'User Defined';
                end
                app.apply_bc_case_to_dropdowns();
            end

            side_handles = {'top', 'bottom', 'left', 'right'};
            for i = 1:numel(side_handles)
                sid = side_handles{i};
                bc_field = sprintf('bc_%s', sid);
                ui_field = sprintf('bc_%s', sid);
                if isfield(ov, bc_field) && app.has_valid_handle(ui_field)
                    req_bc = char(string(ov.(bc_field)));
                    if any(strcmp(req_bc, app.handles.(ui_field).Items))
                        app.handles.(ui_field).Value = req_bc;
                    else
                        [display_label, ~, ~] = app.normalize_bc_selection(req_bc);
                        if any(strcmp(display_label, app.handles.(ui_field).Items))
                            app.handles.(ui_field).Value = display_label;
                        end
                    end
                end
                u_field = sprintf('U_%s', sid);
                if isfield(ov, u_field) && app.has_valid_handle(u_field)
                    app.handles.(u_field).Value = double(ov.(u_field));
                end
            end

            if isfield(ov, 'ic_type') && app.has_valid_handle('ic_dropdown')
                req_ic = lower(char(string(ov.ic_type)));
                for i = 1:numel(app.handles.ic_dropdown.Items)
                    item = app.handles.ic_dropdown.Items{i};
                    if strcmpi(app.map_ic_display_to_type(item), req_ic)
                        app.handles.ic_dropdown.Value = item;
                        break;
                    end
                end
            end
            req_scn = app.pick_field(ov, {'ic_scenario'}, 'Manual');
            app.sync_ic_scenario_items_for_active_ic(req_scn);
            app.update_ic_fields();
            app.update_ic_preview();

            if isfield(ov, 'bathymetry_bed_slope')
                app.config.bathymetry_bed_slope = double(ov.bathymetry_bed_slope);
                if isfield(app.config, 'bathymetry_dynamic_params') && isstruct(app.config.bathymetry_dynamic_params) && ...
                        isfield(ov, 'bathymetry_scenario')
                    req_bathy_state = normalize_bathymetry_scenario_token(ov.bathymetry_scenario);
                    if isfield(app.config.bathymetry_dynamic_params, req_bathy_state) && isstruct(app.config.bathymetry_dynamic_params.(req_bathy_state))
                        app.config.bathymetry_dynamic_params.(req_bathy_state).bed_slope = double(ov.bathymetry_bed_slope);
                    end
                end
            end
            if isfield(ov, 'bathymetry_scenario') && app.has_valid_handle('bathymetry_scenario')
                req_bathy = normalize_bathymetry_scenario_token(ov.bathymetry_scenario);
                entry_bathy = app.find_bathymetry_scenario_entry(req_bathy);
                app.handles.bathymetry_scenario.Value = entry_bathy.id;
                app.config.bathymetry_scenario = entry_bathy.id;
            end
            if isfield(ov, 'bathymetry_depth_offset')
                app.config.bathymetry_depth_offset = double(ov.bathymetry_depth_offset);
            end
            if isfield(ov, 'bathymetry_relief_amplitude')
                app.config.bathymetry_relief_amplitude = double(ov.bathymetry_relief_amplitude);
            end
            if isfield(ov, 'bathymetry_dynamic_params') && isstruct(ov.bathymetry_dynamic_params)
                app.config.bathymetry_dynamic_params = ov.bathymetry_dynamic_params;
            end

            if isfield(ov, 'time_integrator') && app.has_valid_handle('time_integrator')
                req_integrator = char(string(ov.time_integrator));
                if any(strcmp(req_integrator, app.handles.time_integrator.Items))
                    app.handles.time_integrator.Value = req_integrator;
                end
            end
            if isfield(ov, 'method_config') && isstruct(ov.method_config)
                if ~isfield(app.config, 'method_config') || ~isstruct(app.config.method_config)
                    app.config.method_config = struct();
                end
                if isfield(ov.method_config, 'swe2d') && isstruct(ov.method_config.swe2d)
                    if ~isfield(app.config.method_config, 'swe2d') || ~isstruct(app.config.method_config.swe2d)
                        app.config.method_config.swe2d = struct();
                    end
                    swe_keys = fieldnames(ov.method_config.swe2d);
                    for k = 1:numel(swe_keys)
                        app.config.method_config.swe2d.(swe_keys{k}) = ov.method_config.swe2d.(swe_keys{k});
                    end
                end
            end

            app.config = app.normalize_vorticity_only_legacy_fields(app.config, 'simulation scenario');
        end

        function cfg = normalize_vorticity_only_legacy_fields(app, cfg, source_label) %#ok<INUSD>
            if ~isstruct(cfg)
                return;
            end

            if nargin < 3 || strlength(string(source_label)) == 0
                source_label = 'runtime';
            end

            if isfield(cfg, 'wave_model') && ~isempty(cfg.wave_model)
                wave_model = lower(char(string(cfg.wave_model)));
                if strcmp(wave_model, 'none')
                    wave_model = 'vorticity';
                elseif strcmp(wave_model, 'nswe')
                    wave_model = 'nswe_2d';
                end
                if ~strcmp(wave_model, 'vorticity')
                    error('UIController:LegacyWaveModelUnsupported', ...
                        'Configuration import from %s requested legacy wave model "%s". The runtime is vorticity-streamfunction only.', ...
                        char(string(source_label)), wave_model);
                end
            end

            if isfield(cfg, 'wave_solver_level') && ~isempty(cfg.wave_solver_level)
                wave_solver_level = lower(char(string(cfg.wave_solver_level)));
                if ~strcmp(wave_solver_level, 'none')
                    error('UIController:LegacyWaveSolverLevelUnsupported', ...
                        'Configuration import from %s requested legacy wave_solver_level "%s". The runtime is vorticity-streamfunction only.', ...
                        char(string(source_label)), wave_solver_level);
                end
            end

            if isfield(cfg, 'wave_model')
                cfg = rmfield(cfg, 'wave_model');
            end
            if isfield(cfg, 'wave_solver_level')
                cfg = rmfield(cfg, 'wave_solver_level');
            end
            if isfield(cfg, 'nswe_initial_condition')
                cfg = rmfield(cfg, 'nswe_initial_condition');
            end
        end

        function update_bathymetry_preview(app)
            if ~app.has_valid_handle('bathymetry_preview_axes') || ~app.has_valid_handle('bathymetry_scenario')
                return;
            end
            ax = app.handles.bathymetry_preview_axes;
            payload = app.build_current_bathymetry_export_payload();
            app.render_bathymetry_payload_axes(ax, payload);
            if app.has_valid_handle('bathymetry_irl_label')
                app.handles.bathymetry_irl_label.Text = char(string(payload.meta.irl_label));
            end
        end

        function payload = build_current_bathymetry_export_payload(app)
            if ~app.has_valid_handle('bathymetry_scenario')
                error('UIController:MissingBathymetrySelection', ...
                    'Bathymetry scenario control is not available.');
            end
            dim = app.get_active_bathymetry_dimension();
            req = char(string(app.handles.bathymetry_scenario.Value));
            scenario_entry = app.find_bathymetry_scenario_entry(req);
            Lx = max(1.0e-6, app.safe_numeric_value('Lx', 10.0));
            Ly = max(1.0e-6, app.safe_numeric_value('Ly', 10.0));
            n = min(220, max(72, round(max([app.get_bathymetry_resolution(), 72]))));
            [X, Y] = meshgrid(linspace(-Lx / 2, Lx / 2, n), linspace(-Ly / 2, Ly / 2, n));
            params = app.build_active_bathymetry_parameter_struct(scenario_entry);
            [B, meta] = generate_bathymetry_field(X, Y, scenario_entry.id, params);
            profile_x = X(1, :);
            profile_y = B(max(1, round(size(B, 1) / 2)), :);
            if isfield(meta, 'profile_x') && ~isempty(meta.profile_x)
                profile_x = double(meta.profile_x(:)).';
            end
            if isfield(meta, 'profile_y') && ~isempty(meta.profile_y)
                profile_y = double(meta.profile_y(:)).';
            end
            payload = struct( ...
                'X', X, ...
                'Y', Y, ...
                'B', B, ...
                'meta', meta, ...
                'params', params, ...
                'scenario_entry', scenario_entry, ...
                'dimension', char(string(dim)), ...
                'Lx', double(Lx), ...
                'Ly', double(Ly), ...
                'profile_x', double(profile_x), ...
                'profile_y', double(profile_y));
        end

        function render_bathymetry_payload_axes(app, ax, payload)
            cla(ax);
            dim = char(string(payload.dimension));
            X = payload.X;
            Y = payload.Y;
            B = payload.B;
            if strcmp(dim, '2d')
                profile_x = double(payload.profile_x(:)).';
                profile_y = double(payload.profile_y(:)).';
                bed_fill_y = (-payload.Ly / 2) * ones(size(profile_x));
                patch(ax, [profile_x, fliplr(profile_x)], [profile_y, fliplr(bed_fill_y)], ...
                    [0.20 0.35 0.48], 'FaceAlpha', 0.18, 'EdgeColor', 'none');
                hold(ax, 'on');
                plot(ax, profile_x, profile_y, 'LineWidth', 2.2, 'Color', [0.36 0.73 0.96]);
                if isfield(payload.meta, 'uses_custom_points') && logical(payload.meta.uses_custom_points) && ...
                        isfield(payload.meta, 'control_points') && ~isempty(payload.meta.control_points)
                    pts = payload.meta.control_points;
                    scatter(ax, [pts.x], [pts.elevation], 38, [0.98 0.78 0.18], ...
                        'filled', 'MarkerEdgeColor', [0.15 0.15 0.15]);
                end
                hold(ax, 'off');
                grid(ax, 'on');
                xlim(ax, [-payload.Lx / 2, payload.Lx / 2]);
                ylim(ax, [-payload.Ly / 2, payload.Ly / 2]);
                xlabel(ax, 'x', 'Color', app.layout_cfg.colors.fg_muted, 'Interpreter', 'none');
                ylabel(ax, 'bed elevation', 'Color', app.layout_cfg.colors.fg_muted, 'Interpreter', 'none');
            else
                surf(ax, X, Y, B, 'EdgeColor', 'none');
                view(ax, 42, 32);
                colormap(ax, turbo(256));
                xlabel(ax, 'x', 'Color', app.layout_cfg.colors.fg_muted, 'Interpreter', 'none');
                ylabel(ax, 'y', 'Color', app.layout_cfg.colors.fg_muted, 'Interpreter', 'none');
                zlabel(ax, 'zb', 'Color', app.layout_cfg.colors.fg_muted, 'Interpreter', 'none');
            end
            title(ax, sprintf('%s (%s)', payload.scenario_entry.display_name, upper(dim)), ...
                'Interpreter', 'none', 'Color', app.layout_cfg.colors.fg_text, 'FontSize', 11);
        end

        function resolution = get_bathymetry_resolution(app)
            resolution = 96;
            if app.has_valid_handle('bathymetry_resolution')
                resolution = round(double(app.handles.bathymetry_resolution.Value));
            elseif isfield(app.config, 'bathymetry_resolution') && isnumeric(app.config.bathymetry_resolution) && ...
                    isscalar(app.config.bathymetry_resolution) && isfinite(app.config.bathymetry_resolution)
                resolution = round(double(app.config.bathymetry_resolution));
            elseif isfield(app.layout_cfg, 'ui_defaults') && isstruct(app.layout_cfg.ui_defaults) && ...
                    isfield(app.layout_cfg.ui_defaults, 'bathymetry_resolution')
                resolution = round(double(app.layout_cfg.ui_defaults.bathymetry_resolution));
            end
            resolution = max(24, min(256, resolution));
        end

        function points = get_bathymetry_control_points(app)
            points = struct('enabled', {}, 'x', {}, 'y', {}, 'elevation', {});
            if isfield(app.config, 'bathymetry_custom_points') && ~isempty(app.config.bathymetry_custom_points)
                points = app.config.bathymetry_custom_points;
                return;
            end

            if isfield(app.layout_cfg, 'ui_defaults') && isstruct(app.layout_cfg.ui_defaults) && ...
                    isfield(app.layout_cfg.ui_defaults, 'bathymetry_custom_points') && ...
                    ~isempty(app.layout_cfg.ui_defaults.bathymetry_custom_points)
                points = app.layout_cfg.ui_defaults.bathymetry_custom_points;
                return;
            end

            Lx = max(1.0e-6, app.safe_numeric_value('Lx', 10.0));
            Ly = max(1.0e-6, app.safe_numeric_value('Ly', 10.0));
            points = create_default_bathymetry_control_points(Lx, Ly);
        end

        function count = get_enabled_bathymetry_point_count(app)
            points = app.get_bathymetry_control_points();
            count = 0;
            for idx = 1:numel(points)
                enabled = true;
                if isfield(points(idx), 'enabled')
                    enabled = logical(points(idx).enabled);
                end
                if enabled
                    count = count + 1;
                end
            end
        end

        function open_bathymetry_point_editor(app)
            entry = app.find_bathymetry_scenario_entry(app.handles.bathymetry_scenario.Value);
            if ~(isfield(entry, 'uses_point_editor') && logical(entry.uses_point_editor))
                return;
            end

            if isfield(app.handles, 'bathymetry_point_editor_dialog') && ...
                    isvalid(app.handles.bathymetry_point_editor_dialog)
                app.handles.bathymetry_point_editor_dialog.Visible = 'on';
                drawnow;
                return;
            end

            dlg = uifigure( ...
                'Name', 'Bathymetry Point Editor', ...
                'Color', app.layout_cfg.colors.bg_panel, ...
                'Position', [160 140 900 520]);
            root = uigridlayout(dlg, [3, 1]);
            root.RowHeight = {'fit', '1x', 'fit'};
            root.ColumnWidth = {'1x'};
            root.Padding = [8 8 8 8];
            root.RowSpacing = 8;

            top = uigridlayout(root, [1, 4]);
            top.Layout.Row = 1;
            top.ColumnWidth = {'fit', 'fit', 'fit', '1x'};
            top.Padding = [0 0 0 0];
            top.ColumnSpacing = 8;
            uibutton(top, 'Text', 'Add Point', 'ButtonPushedFcn', @(~,~) app.add_bathymetry_point_editor_row());
            uibutton(top, 'Text', 'Remove Point', 'ButtonPushedFcn', @(~,~) app.remove_bathymetry_point_editor_rows());
            uibutton(top, 'Text', 'Reset Defaults', 'ButtonPushedFcn', @(~,~) app.reset_bathymetry_point_editor_rows());
            uilabel(top, 'Text', 'Points use physical x/y coordinates; elevation is clamped inside the current domain.', ...
                'FontColor', app.layout_cfg.colors.fg_muted, 'HorizontalAlignment', 'right');

            body = uigridlayout(root, [1, 2]);
            body.Layout.Row = 2;
            body.ColumnWidth = {'1.4x', '1x'};
            body.RowHeight = {'1x'};
            body.Padding = [0 0 0 0];
            body.ColumnSpacing = 8;

            tbl = uitable(body, ...
                'ColumnName', {'Enabled', 'x', 'y', 'Elevation'}, ...
                'ColumnEditable', [true true true true], ...
                'ColumnFormat', {'logical', 'numeric', 'numeric', 'numeric'}, ...
                'Data', app.bathymetry_control_points_to_table_data(app.get_bathymetry_control_points()), ...
                'CellEditCallback', @(~,~) app.refresh_bathymetry_point_editor_preview(), ...
                'CellSelectionCallback', @(src,evt) app.capture_bathymetry_point_editor_selection(src, evt));
            tbl.Layout.Row = 1;
            tbl.Layout.Column = 1;

            preview_panel = uipanel(body, 'Title', 'Preview', ...
                'BackgroundColor', app.layout_cfg.colors.bg_panel_alt, ...
                'ForegroundColor', app.layout_cfg.colors.accent_gray);
            preview_panel.Layout.Row = 1;
            preview_panel.Layout.Column = 2;
            preview_grid = uigridlayout(preview_panel, [1, 1]);
            preview_grid.Padding = [4 4 4 4];
            preview_grid.RowHeight = {'1x'};
            preview_grid.ColumnWidth = {'1x'};
            ax = uiaxes(preview_grid);
            ax.Layout.Row = 1;
            ax.Layout.Column = 1;
            app.style_axes(ax);

            bottom = uigridlayout(root, [1, 4]);
            bottom.Layout.Row = 3;
            bottom.ColumnWidth = {'1x', 'fit', 'fit', 'fit'};
            bottom.Padding = [0 0 0 0];
            bottom.ColumnSpacing = 8;
            status = uilabel(bottom, 'Text', '', 'FontColor', app.layout_cfg.colors.fg_muted, ...
                'HorizontalAlignment', 'left');
            status.Layout.Row = 1;
            status.Layout.Column = 1;
            btn_apply = uibutton(bottom, 'Text', 'Apply', ...
                'ButtonPushedFcn', @(~,~) app.apply_bathymetry_point_editor(false));
            btn_apply.Layout.Row = 1;
            btn_apply.Layout.Column = 2;
            btn_apply_close = uibutton(bottom, 'Text', 'Apply & Close', ...
                'ButtonPushedFcn', @(~,~) app.apply_bathymetry_point_editor(true));
            btn_apply_close.Layout.Row = 1;
            btn_apply_close.Layout.Column = 3;
            btn_close = uibutton(bottom, 'Text', 'Close', ...
                'ButtonPushedFcn', @(~,~) delete(dlg));
            btn_close.Layout.Row = 1;
            btn_close.Layout.Column = 4;

            app.handles.bathymetry_point_editor_dialog = dlg;
            app.handles.bathymetry_point_editor_table = tbl;
            app.handles.bathymetry_point_editor_preview_axes = ax;
            app.handles.bathymetry_point_editor_status = status;
            app.handles.bathymetry_point_editor_apply_btn = btn_apply;
            app.handles.bathymetry_point_editor_apply_close_btn = btn_apply_close;
            app.handles.bathymetry_point_editor_selected_rows = [];
            dlg.CloseRequestFcn = @(src,~) app.close_bathymetry_point_editor(src);

            app.refresh_bathymetry_point_editor_preview();
        end

        function close_bathymetry_point_editor(app, src)
            if nargin < 2 || isempty(src)
                if isfield(app.handles, 'bathymetry_point_editor_dialog') && isvalid(app.handles.bathymetry_point_editor_dialog)
                    src = app.handles.bathymetry_point_editor_dialog;
                else
                    return;
                end
            end
            if isvalid(src)
                src.CloseRequestFcn = [];
                delete(src);
            end
            cleanup_names = {'bathymetry_point_editor_dialog', 'bathymetry_point_editor_table', ...
                'bathymetry_point_editor_preview_axes', 'bathymetry_point_editor_status', ...
                'bathymetry_point_editor_apply_btn', 'bathymetry_point_editor_apply_close_btn', ...
                'bathymetry_point_editor_selected_rows'};
            for idx = 1:numel(cleanup_names)
                if isfield(app.handles, cleanup_names{idx})
                    app.handles = rmfield(app.handles, cleanup_names{idx});
                end
            end
        end

        function capture_bathymetry_point_editor_selection(app, ~, evt)
            rows = [];
            if isstruct(evt) && isfield(evt, 'Indices') && ~isempty(evt.Indices)
                rows = unique(evt.Indices(:, 1));
            end
            app.handles.bathymetry_point_editor_selected_rows = rows;
        end

        function add_bathymetry_point_editor_row(app)
            if ~app.has_valid_handle('bathymetry_point_editor_table')
                return;
            end
            data = app.handles.bathymetry_point_editor_table.Data;
            if isempty(data)
                data = cell(0, 4);
            end
            data(end + 1, :) = {true, 0.0, 0.0, -0.35 * max(1.0, app.safe_numeric_value('Ly', 10.0))};
            app.handles.bathymetry_point_editor_table.Data = data;
            app.refresh_bathymetry_point_editor_preview();
        end

        function remove_bathymetry_point_editor_rows(app)
            if ~app.has_valid_handle('bathymetry_point_editor_table')
                return;
            end
            data = app.handles.bathymetry_point_editor_table.Data;
            if isempty(data)
                return;
            end
            rows = [];
            if isfield(app.handles, 'bathymetry_point_editor_selected_rows')
                rows = app.handles.bathymetry_point_editor_selected_rows;
            end
            if isempty(rows)
                rows = size(data, 1);
            end
            rows = unique(max(1, min(size(data, 1), rows)));
            data(rows, :) = [];
            app.handles.bathymetry_point_editor_table.Data = data;
            app.handles.bathymetry_point_editor_selected_rows = [];
            app.refresh_bathymetry_point_editor_preview();
        end

        function reset_bathymetry_point_editor_rows(app)
            if ~app.has_valid_handle('bathymetry_point_editor_table')
                return;
            end
            Lx = max(1.0e-6, app.safe_numeric_value('Lx', 10.0));
            Ly = max(1.0e-6, app.safe_numeric_value('Ly', 10.0));
            defaults = create_default_bathymetry_control_points(Lx, Ly);
            app.handles.bathymetry_point_editor_table.Data = app.bathymetry_control_points_to_table_data(defaults);
            app.handles.bathymetry_point_editor_selected_rows = [];
            app.refresh_bathymetry_point_editor_preview();
        end

        function refresh_bathymetry_point_editor_preview(app)
            if ~app.has_valid_handle('bathymetry_point_editor_table') || ~app.has_valid_handle('bathymetry_point_editor_preview_axes')
                return;
            end

            ax = app.handles.bathymetry_point_editor_preview_axes;
            cla(ax);
            data = app.handles.bathymetry_point_editor_table.Data;
            Lx = max(1.0e-6, app.safe_numeric_value('Lx', 10.0));
            Ly = max(1.0e-6, app.safe_numeric_value('Ly', 10.0));
            x_vec = linspace(-Lx / 2, Lx / 2, max(48, min(160, app.get_bathymetry_resolution())));
            y_floor = -Ly / 2 + (Ly / max(8, app.safe_numeric_value('Ny', 128)));
            y_ceiling = Ly / 2 - (Ly / max(8, app.safe_numeric_value('Ny', 128)));
            points = app.bathymetry_control_points_from_table_data(data, false);

            if numel(points) >= 3
                x_domain = linspace(-Lx / 2, Lx / 2, app.get_bathymetry_resolution());
                y_domain = linspace(-Ly / 2, Ly / 2, app.get_bathymetry_resolution());
                [Xg, Yg] = meshgrid(x_domain, y_domain);
                F = scatteredInterpolant([points.x].', [points.y].', [points.elevation].', 'linear', 'nearest');
                bath = F(Xg, Yg);
                bath = max(y_floor, min(y_ceiling, bath));
                profile = max(bath, [], 1);
                patch(ax, [x_domain, fliplr(x_domain)], [profile, fliplr((-Ly / 2) * ones(size(profile)))], ...
                    [0.20 0.35 0.48], 'FaceAlpha', 0.18, 'EdgeColor', 'none');
                hold(ax, 'on');
                plot(ax, x_domain, profile, 'LineWidth', 2.0, 'Color', [0.36 0.73 0.96]);
                scatter(ax, [points.x], [points.elevation], 34, [0.98 0.78 0.18], ...
                    'filled', 'MarkerEdgeColor', [0.15 0.15 0.15]);
                hold(ax, 'off');
                if app.has_valid_handle('bathymetry_point_editor_status')
                    app.handles.bathymetry_point_editor_status.Text = sprintf('%d enabled point(s).', numel(points));
                end
            else
                scatter(ax, [points.x], [points.elevation], 34, [0.98 0.78 0.18], ...
                    'filled', 'MarkerEdgeColor', [0.15 0.15 0.15]);
                if app.has_valid_handle('bathymetry_point_editor_status')
                    app.handles.bathymetry_point_editor_status.Text = 'Need at least 3 enabled points to build a profile.';
                end
            end

            grid(ax, 'on');
            xlim(ax, [-Lx / 2, Lx / 2]);
            ylim(ax, [-Ly / 2, Ly / 2]);
            xlabel(ax, 'x', 'Color', app.layout_cfg.colors.fg_muted, 'Interpreter', 'none');
            ylabel(ax, 'bed elevation', 'Color', app.layout_cfg.colors.fg_muted, 'Interpreter', 'none');
            title(ax, 'Custom lower-surface preview', 'Color', app.layout_cfg.colors.fg_text, ...
                'Interpreter', 'none', 'FontSize', 11);
        end

        function apply_bathymetry_point_editor(app, close_after_apply)
            if nargin < 2
                close_after_apply = false;
            end
            if ~app.has_valid_handle('bathymetry_point_editor_table')
                return;
            end

            try
                points = app.bathymetry_control_points_from_table_data( ...
                    app.handles.bathymetry_point_editor_table.Data, true);
                if numel(points) < 3
                    error('UIController:InsufficientBathymetryPoints', ...
                        'Custom bathymetry requires at least 3 enabled points.');
                end
                app.config.bathymetry_custom_points = points;
                app.sync_bathymetry_controls('interactive');
                app.update_bathymetry_preview();
                if app.has_valid_handle('bathymetry_point_editor_status')
                    app.handles.bathymetry_point_editor_status.Text = sprintf('Applied %d enabled point(s).', numel(points));
                end
                if close_after_apply
                    app.close_bathymetry_point_editor();
                end
            catch ME
                app.show_alert_latex(ME.message, 'Bathymetry Point Editor', 'Icon', 'error');
            end
        end

        function data = bathymetry_control_points_to_table_data(~, points)
            if isempty(points)
                data = cell(0, 4);
                return;
            end
            data = cell(numel(points), 4);
            for idx = 1:numel(points)
                enabled = true;
                if isfield(points(idx), 'enabled') && ~isempty(points(idx).enabled)
                    enabled = logical(points(idx).enabled);
                end
                data(idx, :) = {enabled, double(points(idx).x), double(points(idx).y), double(points(idx).elevation)};
            end
        end

        function points = bathymetry_control_points_from_table_data(app, data, clamp_to_domain)
            if nargin < 3
                clamp_to_domain = true;
            end
            points = struct('enabled', {}, 'x', {}, 'y', {}, 'elevation', {});
            if isempty(data)
                return;
            end

            Lx = max(1.0e-6, app.safe_numeric_value('Lx', 10.0));
            Ly = max(1.0e-6, app.safe_numeric_value('Ly', 10.0));
            x_min = -Lx / 2;
            x_max = Lx / 2;
            y_min = -Ly / 2;
            y_max = Ly / 2;
            dy_margin = Ly / max(8, app.safe_numeric_value('Ny', 128));
            elev_min = y_min + dy_margin;
            elev_max = y_max - dy_margin;

            for idx = 1:size(data, 1)
                row = data(idx, :);
                enabled = logical(row{1});
                if ~enabled
                    continue;
                end
                point = struct();
                point.enabled = true;
                point.x = double(row{2});
                point.y = double(row{3});
                point.elevation = double(row{4});
                if clamp_to_domain
                    point.x = min(max(point.x, x_min), x_max);
                    point.y = min(max(point.y, y_min), y_max);
                    point.elevation = min(max(point.elevation, elev_min), elev_max);
                end
                if ~(isfinite(point.x) && isfinite(point.y) && isfinite(point.elevation))
                    error('UIController:InvalidBathymetryPoints', ...
                        'Bathymetry control points must be finite.');
                end
                points(end + 1) = point; %#ok<AGROW>
            end
        end

        function update_time_integrator_options(app, is_fd, is_fv, is_swe, is_spectral)
            if nargin < 2
                method_val = app.handles.method_dropdown.Value;
                is_fd = strcmp(method_val, 'Finite Difference');
                is_fv = strcmp(method_val, 'Finite Volume');
                is_swe = strcmp(method_val, 'Shallow Water');
                is_spectral = strcmp(method_val, 'Spectral');
            end
            if ~app.has_valid_handle('time_integrator')
                return;
            end

            if is_fd
                items = {'RK4', 'Forward Euler'};
            elseif is_spectral
                items = {'RK4'};
            elseif is_fv || is_swe
                items = {'RK3'};
            else
                items = {'RK4'};
            end

            current_val = char(string(app.handles.time_integrator.Value));
            app.handles.time_integrator.Items = items;
            if ~any(strcmp(items, current_val))
                app.handles.time_integrator.Value = items{1};
            end
        end

        function on_mode_changed(app)
            % Update mode-dependent views safely to avoid callback aborts.
            try
                app.update_convergence_display();
                app.update_mode_control_visibility();
                app.update_convergence_control_state();
                app.update_checklist();
            catch ME
                app.append_to_terminal(sprintf('Mode change update failed: %s', ME.message), 'error');
            end
        end

        function on_convergence_agent_changed(app)
            % When agent-guided convergence is active, lock manual controls.
            if isfield(app.handles, 'conv_mode_selected')
                if logical(app.handles.conv_agent_enabled.Value)
                    if strcmpi(char(string(app.handles.conv_mode_selected)), 'manual')
                        app.handles.conv_mode_selected = 'agent';
                    end
                else
                    app.handles.conv_mode_selected = 'manual';
                end
            end
            app.update_convergence_control_state();
            app.update_convergence_display();
            app.update_checklist();
        end

        function on_convergence_mode_button(app, mode_token)
            if ~app.has_valid_handle('conv_agent_enabled')
                return;
            end
            token = lower(strtrim(char(string(mode_token))));
            switch token
                case 'manual'
                    app.handles.conv_agent_enabled.Value = false;
                    app.handles.conv_mode_selected = 'manual';
                case 'agent'
                    app.handles.conv_agent_enabled.Value = true;
                    app.handles.conv_mode_selected = 'agent';
                case 'advanced'
                    app.handles.conv_agent_enabled.Value = true;
                    app.handles.conv_mode_selected = 'advanced';
                    if app.has_valid_handle('conv_agent_objective_mode')
                        if strcmp(char(string(app.handles.conv_agent_objective_mode.Value)), 'balanced')
                            app.handles.conv_agent_objective_mode.Value = 'accuracy_first';
                        end
                    end
                otherwise
                    return;
            end
            app.update_convergence_control_state();
            app.update_convergence_display();
            app.update_checklist();
        end

        function refresh_convergence_mode_buttons(app)
            selected = 'manual';
            if isfield(app.handles, 'conv_mode_selected')
                selected = lower(char(string(app.handles.conv_mode_selected)));
            end
            button_specs = { ...
                'conv_mode_manual', '#64748B', '#334155', strcmp(selected, 'manual'); ...
                'conv_mode_agent', '#16A34A', '#166534', strcmp(selected, 'agent'); ...
                'conv_mode_advanced', '#0EA5E9', '#0369A1', strcmp(selected, 'advanced')};
            for i = 1:size(button_specs, 1)
                key = button_specs{i, 1};
                if ~app.has_valid_handle(key)
                    continue;
                end
                if button_specs{i, 4}
                    app.handles.(key).BackgroundColor = app.hex_to_rgb(button_specs{i, 2});
                    app.handles.(key).FontWeight = 'bold';
                else
                    app.handles.(key).BackgroundColor = app.hex_to_rgb(button_specs{i, 3});
                    app.handles.(key).FontWeight = 'normal';
                end
            end
        end

        function update_convergence_control_state(app)
            T = app.layout_cfg.ui_text;
            mode_val = app.handles.mode_dropdown.Value;
            conv_on = strcmp(mode_val, 'Convergence');
            agent_on = conv_on && app.handles.conv_agent_enabled.Value;
            selected_mode = 'manual';
            if isfield(app.handles, 'conv_mode_selected')
                selected_mode = lower(char(string(app.handles.conv_mode_selected)));
            end
            if agent_on && strcmp(selected_mode, 'manual')
                selected_mode = 'agent';
                if isfield(app.handles, 'conv_mode_selected')
                    app.handles.conv_mode_selected = 'agent';
                end
            end
            advanced_on = agent_on && strcmp(selected_mode, 'advanced');
            if ~agent_on
                selected_mode = 'manual';
                if isfield(app.handles, 'conv_mode_selected')
                    app.handles.conv_mode_selected = 'manual';
                end
            end

            manual_fields = {'conv_N_coarse', 'conv_N_max', 'conv_dt_values', 'conv_tolerance', ...
                'conv_criterion', 'conv_binary', 'conv_use_adaptive', 'conv_max_jumps'};
            for i = 1:numel(manual_fields)
                app.set_optional_handle_enable(manual_fields{i}, app.on_off(conv_on && ~agent_on));
            end
            app.set_optional_handle_enable('conv_agent_enabled', app.on_off(conv_on));
            app.set_optional_handle_enable('btn_load_converged_mesh', app.on_off(conv_on));
            app.set_optional_handle_enable('conv_mode_manual', app.on_off(conv_on));
            app.set_optional_handle_enable('conv_mode_agent', app.on_off(conv_on));
            app.set_optional_handle_enable('conv_mode_advanced', app.on_off(conv_on));
            app.set_optional_handle_enable('conv_agent_objective_mode', app.on_off(conv_on && agent_on));
            app.set_optional_handle_property('conv_agent_objective_mode', 'Visible', app.on_off(conv_on && agent_on));
            app.set_optional_handle_property('conv_agent_objective_mode_label', 'Visible', app.on_off(conv_on && agent_on));
            app.refresh_convergence_mode_buttons();
            app.update_convergence_method_labels();

            if app.has_valid_handle('conv_agent_status')
                if ~conv_on
                    app.handles.conv_agent_status.Text = T.config.convergence.agent_status_inactive;
                    app.handles.conv_agent_status.FontColor = app.layout_cfg.colors.fg_muted;
                elseif advanced_on
                    app.handles.conv_agent_status.Text = 'Agent mode: advanced tuning enabled';
                    app.handles.conv_agent_status.FontColor = app.layout_cfg.colors.accent_cyan;
                elseif agent_on
                    app.handles.conv_agent_status.Text = T.config.convergence.agent_status_locked;
                    app.handles.conv_agent_status.FontColor = app.layout_cfg.colors.accent_yellow;
                else
                    app.handles.conv_agent_status.Text = T.config.convergence.agent_status_manual;
                    app.handles.conv_agent_status.FontColor = app.layout_cfg.colors.accent_green;
                end
            end
        end

        function update_convergence_method_labels(app)
            primary_start = 'Spatial coarse';
            primary_end = 'Spatial fine';
            temporal_label = 'Temporal dt ladder';

            method_token = char(string(app.get_dispatch_method(app.handles.method_dropdown.Value)));
            switch upper(method_token)
                case 'SPECTRAL'
                    primary_start = 'Modal coarse';
                    primary_end = 'Modal fine';
                case 'FV'
                    primary_start = 'Cell coarse';
                    primary_end = 'Cell fine';
            end

            app.set_optional_handle_property('conv_primary_start_label', 'Text', primary_start);
            app.set_optional_handle_property('conv_primary_end_label', 'Text', primary_end);
            app.set_optional_handle_property('conv_dt_values_label', 'Text', temporal_label);
        end

        function update_animation_export_controls(app)
            fps = 30;
            if app.has_valid_handle('animation_fps')
                fps = max(1, double(app.handles.animation_fps.Value));
                app.handles.animation_fps.Value = fps;
            end

            duration_s = 10;
            if app.has_valid_handle('animation_duration_s')
                duration_s = max(0.1, double(app.handles.animation_duration_s.Value));
                app.handles.animation_duration_s.Value = duration_s;
            end

            dpi = 600;
            if app.has_valid_handle('animation_export_dpi')
                dpi = max(72, double(app.handles.animation_export_dpi.Value));
                app.handles.animation_export_dpi.Value = dpi;
            end

            preset = 'double_column_report';
            if app.has_valid_handle('animation_export_preset')
                preset = char(string(app.handles.animation_export_preset.Value));
            end
            gif_min_frames = 2;
            if isstruct(app.config) && isfield(app.config, 'animation_gif_min_frames') && isfinite(app.config.animation_gif_min_frames)
                gif_min_frames = max(2, round(double(app.config.animation_gif_min_frames)));
            end

            [width_in, height_in] = app.resolve_animation_export_inches(preset);
            resolution_px = max(2, round([width_in, height_in] * dpi));
            frame_count = NaN;
            if app.has_valid_handle('animation_num_frames') && isfinite(app.handles.animation_num_frames.Value)
                frame_count = max(2, round(double(app.handles.animation_num_frames.Value)));
            end
            if ~isfinite(frame_count)
                frame_count = max(2, round(duration_s * fps));
            end
            gif_min_frames = min(gif_min_frames, frame_count);

            if app.has_valid_handle('animation_num_frames')
                app.handles.animation_num_frames.Value = frame_count;
            end
            if app.has_valid_handle('animation_export_resolution')
                app.handles.animation_export_resolution.Text = sprintf('%d x %d px', ...
                    resolution_px(1), resolution_px(2));
            end

            if isstruct(app.config)
                app.config.animation_fps = fps;
                app.config.animation_duration_s = duration_s;
                app.config.animation_num_frames = frame_count;
                app.config.animation_format = 'mp4+gif';
                app.config.animation_export_format = 'mp4+gif';
                app.config.animation_export_formats = {'mp4', 'gif'};
                app.config.animation_gif_min_frames = gif_min_frames;
                app.config.animation_export_preset = preset;
                app.config.animation_export_dpi = dpi;
                app.config.animation_export_width_in = width_in;
                app.config.animation_export_height_in = height_in;
                app.config.animation_export_resolution_px = resolution_px;
            end
        end

        function [width_in, height_in] = resolve_animation_export_inches(~, preset)
            width_in = 7.16;
            height_in = 5.37;
            switch lower(char(string(preset)))
                case 'double_column_report'
                    width_in = 7.16;
                    height_in = 5.37;
            end
        end

        function update_checklist(app)
            % Update readiness checklist lights
            T = app.layout_cfg.ui_text;
            grid_ok = app.handles.Nx.Value >= 2 && app.handles.Ny.Value >= 2;
            domain_ok = app.handles.Lx.Value > 0 && app.handles.Ly.Value > 0;
            time_ok = app.handles.dt.Value > 0 && app.handles.t_final.Value > 0;
            ic_ok = ~isempty(app.handles.ic_dropdown.Value);
            conv_ok = true;
            mode_val = app.handles.mode_dropdown.Value;
            defaults = app.initialize_default_config();
            if strcmp(mode_val, 'Convergence')
                dt_values = app.parse_numeric_csv(app.handles.conv_dt_values.Value);
                conv_ok = app.handles.conv_N_max.Value > app.handles.conv_N_coarse.Value && numel(dt_values) >= 2;
            elseif strcmp(mode_val, 'Parameter Sweep') || strcmp(mode_val, 'Sweep')
                sweep_values = defaults.sweep_values;
                if app.has_valid_handle('sweep_values')
                    sweep_values = app.parse_numeric_csv(app.handles.sweep_values.Value);
                elseif isfield(app.config, 'sweep_values')
                    sweep_values = app.config.sweep_values;
                end
                conv_ok = numel(sweep_values) >= 2;
            end

            app.handles.check_grid.FontColor = app.bool_to_color(grid_ok);
            app.handles.check_domain.FontColor = app.bool_to_color(domain_ok);
            app.handles.check_time.FontColor = app.bool_to_color(time_ok);
            app.handles.check_ic.FontColor = app.bool_to_color(ic_ok);
            app.handles.check_conv.FontColor = app.bool_to_color(conv_ok);

            monitor_ok = app.handles.enable_monitoring.Value && app.handles.sample_interval.Value > 0;
            outputs_ok = app.handles.save_csv.Value || app.handles.save_mat.Value || ...
                app.handles.figures_save_png.Value || app.handles.figures_save_fig.Value;
            collector_probe = app.refresh_collector_probe_status('runtime');
            collectors_ok = true;
            if app.handles.collector_strict.Value
                collectors_ok = collector_probe.connected_external_count >= 1;
            end

            if app.has_valid_handle('check_monitor')
                app.handles.check_monitor.FontColor = app.bool_to_color(monitor_ok);
            end
            if app.has_valid_handle('check_collectors')
                app.handles.check_collectors.FontColor = app.bool_to_color(collectors_ok);
            end
            if app.has_valid_handle('check_outputs')
                app.handles.check_outputs.FontColor = app.bool_to_color(outputs_ok);
            end

            if app.has_valid_handle('collector_status')
                collector_msg = sprintf(T.config.sustainability.collector_status_template, ...
                    collector_probe.connected_external_count, collector_probe.enabled_external_count);
                if app.handles.collector_strict.Value && ~collectors_ok
                    collector_msg = T.config.sustainability.collector_status_strict;
                    app.handles.collector_status.FontColor = app.layout_cfg.colors.accent_yellow;
                else
                    app.handles.collector_status.FontColor = app.layout_cfg.colors.fg_muted;
                end
                app.handles.collector_status.Text = char(collector_msg);
            end

            if app.has_valid_handle('solver_options_status')
                arakawa_state = app.on_off(app.has_valid_handle('arakawa_enable') && app.handles.arakawa_enable.Value);
                gpu_state = app.on_off(app.has_valid_handle('gpu_enable') && app.handles.gpu_enable.Value);
                cpu_alloc = app.safe_numeric_value('cpu_allocation_pct', 80);
                mem_alloc = app.safe_numeric_value('memory_allocation_pct', 70);
                advection_label = 'SparseMatrix';
                if strcmpi(arakawa_state, 'on')
                    advection_label = 'Arakawa';
                end
                app.handles.solver_options_status.Text = sprintf('Advection: %s | GPU: %s | CPU %.0f%% | MEM %.0f%%', ...
                    advection_label, upper(gpu_state), cpu_alloc, mem_alloc);
            end

            if app.has_valid_handle('resource_status')
                try
                    preview = app.build_resource_preview_policy();
                    workers_req = app.pick_field(preview, {'pool_workers_requested'}, 1);
                    workers_eff = app.pick_field(preview, {'pool_workers_effective', 'pool_workers'}, workers_req);
                    thread_cap = app.pick_field(preview, {'thread_cap', 'max_threads'}, 1);
                    gpu_eff = app.on_off(logical(app.pick_field(preview, {'gpu_enabled_effective'}, false)));
                    host_profile = char(string(app.pick_field(preview, {'host_profile_id'}, 'none')));
                    app.handles.resource_status.Text = sprintf( ...
                        'Allocator: workers %d->%d | thread cap %d | GPU eff %s | host %s', ...
                        workers_req, workers_eff, thread_cap, upper(gpu_eff), host_profile);

                    if app.has_valid_handle('resource_effective_policy')
                        note_lines = app.pick_field(preview, {'planner_notes'}, {});
                        top_note = 'planner note unavailable';
                        if iscell(note_lines) && ~isempty(note_lines)
                            top_note = char(string(note_lines{1}));
                        end
                        app.handles.resource_effective_policy.Text = sprintf( ...
                            'Effective policy: workers %d->%d | thread %d | GPU %s | host %s | %s', ...
                            workers_req, workers_eff, thread_cap, upper(gpu_eff), host_profile, top_note);
                    end
                catch ME
                    app.handles.resource_status.Text = sprintf('Allocator preview unavailable (%s)', ME.identifier);
                    if app.has_valid_handle('resource_effective_policy')
                        app.handles.resource_effective_policy.Text = char(string(ME.message));
                    end
                end
            end

            method_ok = ~isempty(app.handles.method_dropdown.Value) && ~isempty(app.handles.mode_dropdown.Value);
            app.update_config_subtab_titles(method_ok, grid_ok && domain_ok, time_ok, outputs_ok, conv_ok, monitor_ok && collectors_ok);
        end

        function [gpu_capable, gpu_reason] = host_gpu_capability(app)
            gpu_capable = false;
            gpu_reason = 'No compatible GPU detected.';
            probe = app.planner_host_probe;
            if ~isstruct(probe) || isempty(fieldnames(probe))
                gpu_reason = 'GPU host probe unavailable.';
                return;
            end
            has_api = logical(app.pick_field(probe, {'has_gpu_api'}, false));
            has_device = logical(app.pick_field(probe, {'gpu_device_available'}, false));
            gpu_name = char(string(app.pick_field(probe, {'gpu_name'}, '')));
            if ~(has_api && has_device)
                if ~has_api
                    gpu_reason = 'MATLAB gpuDevice API unavailable on this machine.';
                else
                    gpu_reason = 'No compatible GPU device is currently available.';
                end
                return;
            end
            gpu_capable = true;
            if isempty(strtrim(gpu_name))
                gpu_reason = 'Compatible GPU detected. Untick to force CPU execution.';
            else
                gpu_reason = sprintf('Compatible GPU detected: %s. Untick to force CPU execution.', gpu_name);
            end
        end

        function sync_gpu_toggle_state(app, preserve_current_value)
            if nargin < 2
                preserve_current_value = true;
            end
            if ~app.has_valid_handle('gpu_enable')
                return;
            end

            requested_value = logical(app.pick_field(app.config, {'use_gpu'}, false));
            if preserve_current_value
                requested_value = logical(app.handles.gpu_enable.Value);
            end

            [gpu_capable, gpu_reason] = app.host_gpu_capability();
            if gpu_capable
                app.handles.gpu_enable.Enable = 'on';
                app.handles.gpu_enable.Value = requested_value;
            else
                app.handles.gpu_enable.Enable = 'off';
                app.handles.gpu_enable.Value = false;
            end
            if isprop(app.handles.gpu_enable, 'Tooltip')
                app.handles.gpu_enable.Tooltip = gpu_reason;
            end
            app.config.use_gpu = logical(app.handles.gpu_enable.Value);
        end

        function preview = build_resource_preview_policy(app)
            if ~(exist('ExecutionResourcePlanner', 'class') == 8 || exist('ExecutionResourcePlanner', 'file') == 2)
                error('UIController:MissingExecutionResourcePlanner', ...
                    'ExecutionResourcePlanner is required for UI policy preview.');
            end

            method_token = 'FD';
            if app.has_valid_handle('method_dropdown')
                method_name = app.handles.method_dropdown.Value;
                if strcmp(method_name, 'Finite Difference')
                    method_token = 'FD';
                elseif strcmp(method_name, 'Finite Volume')
                    method_token = 'FV';
                elseif strcmp(method_name, 'Shallow Water')
                    method_token = 'SWE';
                elseif strcmp(method_name, 'Spectral')
                    method_token = 'Spectral';
                end
            end

            mode_token = 'Evolution';
            if app.has_valid_handle('mode_dropdown')
                mode_name = app.handles.mode_dropdown.Value;
                switch char(string(mode_name))
                    case 'Convergence'
                        mode_token = 'Convergence';
                    case {'Parameter Sweep', 'Sweep'}
                        mode_token = 'ParameterSweep';
                    case 'Animation'
                        mode_token = 'Evolution';
                    otherwise
                        mode_token = 'Evolution';
                end
            end

            params_preview = struct( ...
                'use_gpu', logical(app.has_valid_handle('gpu_enable') && app.handles.gpu_enable.Value), ...
                'Nx', max(2, round(app.safe_numeric_value('Nx', 128))), ...
                'Ny', max(2, round(app.safe_numeric_value('Ny', 128))), ...
                'dt', max(1e-9, app.safe_numeric_value('dt', 0.01)), ...
                'Tfinal', max(1e-9, app.safe_numeric_value('t_final', 1.0)), ...
                'method', char(string(method_token)), ...
                'bc_case', char(string(app.safe_bc_value('bc_case', 'Periodic (All)'))), ...
                'bc_top', char(string(app.safe_bc_value('bc_top', 'Periodic'))), ...
                'bc_bottom', char(string(app.safe_bc_value('bc_bottom', 'Periodic'))), ...
                'bc_left', char(string(app.safe_bc_value('bc_left', 'Periodic'))), ...
                'bc_right', char(string(app.safe_bc_value('bc_right', 'Periodic'))));

            ra_preview = struct( ...
                'cpu_target_pct', min(max(app.safe_numeric_value('cpu_allocation_pct', 80), 5), 100), ...
                'memory_target_pct', min(max(app.safe_numeric_value('memory_allocation_pct', 70), 10), 95), ...
                'gpu_target_pct', min(max(app.safe_numeric_value('gpu_allocation_pct', 80), 0), 100), ...
                'monitor_hz', min(max(app.safe_numeric_value('monitor_update_hz', 2), 0.5), 20), ...
                'progress_hz', min(max(app.safe_numeric_value('progress_update_hz', 6), 0.5), 30), ...
                'pool_workers', max(1, round(app.safe_numeric_value('pool_workers', 1))), ...
                'resource_strategy', char(string(app.pick_field(app.handles, {'resource_strategy'}, struct('Value', 'mode_adaptive')).Value)), ...
                'gpu_policy', char(string(app.pick_field(app.handles, {'gpu_policy'}, struct('Value', 'auto')).Value)), ...
                'planner_use_host_profiles', logical(app.has_valid_handle('planner_use_host_profiles') && app.handles.planner_use_host_profiles.Value), ...
                'interactive_pool_workers_max', max(1, round(app.safe_numeric_value('interactive_pool_workers_max', 2))), ...
                'throughput_pool_workers_min', max(1, round(app.safe_numeric_value('throughput_pool_workers_min', 2))), ...
                'interactive_thread_headroom_pct', min(max(app.safe_numeric_value('interactive_thread_headroom_pct', 75), 0), 99), ...
                'gpu_min_workload_cells_steps', max(0, app.safe_numeric_value('gpu_min_workload_cells_steps', 0)), ...
                'gpu_memory_guard_pct', min(max(app.safe_numeric_value('gpu_memory_guard_pct', 80), 1), 99), ...
                'pool_workers_max_override', max(0, round(app.safe_numeric_value('pool_workers_max_override', 0))));
            settings_preview = struct('resource_allocation', ra_preview);

            preview = ExecutionResourcePlanner.plan(params_preview, settings_preview, ...
                'HostProbe', app.planner_host_probe, ...
                'ModeToken', mode_token, ...
                'MethodToken', method_token);
        end

        function update_convergence_display(app)
            % Update convergence criterion display without sprintf parsing risk.
            method_val = app.handles.method_dropdown.Value;
            mode_val = app.handles.mode_dropdown.Value;

            method_txt = string(method_val);
            mode_txt = string(mode_val);
            header = method_txt + " | " + mode_txt + " Mode";
            method_token = string(app.get_dispatch_method(method_val));
            primary_label = "spatial";
            eqn = "$$\\epsilon_h = \\|\\omega_h-\\omega_{ref}\\|_2$$";
            if strcmpi(method_token, "Spectral")
                primary_label = "modal";
                eqn = "$$\\epsilon_N = \\|\\omega_N-\\omega_{ref}\\|_2$$";
            elseif strcmpi(method_token, "FV")
                primary_label = "cell";
                eqn = "$$\\epsilon_h = \\|\\omega_h-\\omega_{ref}\\|_2$$";
            end
            objective_mode = "balanced";
            if app.has_valid_handle('conv_agent_objective_mode')
                objective_mode = string(app.handles.conv_agent_objective_mode.Value);
            end
            ui_mode = "manual";
            if isfield(app.handles, 'conv_mode_selected')
                ui_mode = string(app.handles.conv_mode_selected);
            end
            details = "Method: <b>" + method_txt + "</b> | Mode: <b>" + ...
                mode_txt + "</b> | Agent: <b>" + ...
                app.to_yes_no(app.handles.conv_agent_enabled.Value) + "</b> | Binary: <b>" + ...
                app.to_yes_no(app.handles.conv_binary.Value) + "</b> | Objective: <b>" + ...
                objective_mode + "</b> | UI mode: <b>" + ui_mode + "</b> | Primary study: <b>" + primary_label + "</b>";

            html_content = "<div style='font-family:Segoe UI;font-size:12px;color:#dcdcdc;'>" + ...
                "<b style='color:#80c7ff;'>" + header + "</b><br>" + ...
                "<b>Staged Criterion:</b><br>" + ...
                "<span>Temporal study at fine resolution, then " + primary_label + " study at small dt.</span><br>" + ...
                eqn + "<br>" + ...
                "<span style='font-size:11px;color:#a0a0a0;'>" + details + "</span>" + ...
                "</div>" + ...
                "<script src='https://cdn.jsdelivr.net/npm/mathjax@3/es5/tex-mml-chtml.js'></script>";

            if app.has_valid_handle('conv_math')
                app.handles.conv_math.HTMLSource = char(string(html_content));
            end
        end

        function color = bool_to_color(~, ok)
            if ok
                color = [0.25 0.78 0.35];
            else
                color = [0.90 0.35 0.35];
            end
        end

        function retry_collector_connection(app, source)
            % Re-probe one or all external collectors and refresh status lights.
            if nargin < 2 || isempty(source)
                source = 'all';
            end
            app.safe_stop_timer('startup_collector_probe_timer');
            runtime_sample = struct();
            try
                runtime_sample = app.probe_collectors_runtime(source);
                app.store_collector_probe_runtime_state(source, runtime_sample);
            catch ME
                app.append_to_terminal(sprintf('Collector runtime probe warning: %s', ME.message), 'warning');
            end
            probe = app.refresh_collector_probe_status(source);
            if app.has_valid_handle('collector_probe_status')
                app.handles.collector_probe_status.Text = probe.status_text;
            end
            if isstruct(runtime_sample) && ~isempty(fieldnames(runtime_sample))
                hwinfo_status = '';
                if isfield(runtime_sample, 'collector_status') && isstruct(runtime_sample.collector_status) && ...
                        isfield(runtime_sample.collector_status, 'hwinfo')
                    hwinfo_status = runtime_sample.collector_status.hwinfo;
                end
                if ~isempty(char(string(hwinfo_status)))
                    app.append_to_terminal(sprintf('Collector runtime probe [%s]: HWiNFO %s (%s)', ...
                        lower(char(string(source))), char(string(hwinfo_status)), ...
                        char(string(app.pick_field(runtime_sample, {'hwinfo_transport'}, 'none')))), 'info');
                end
            end
            app.update_checklist();
        end

        function schedule_startup_parallel_pool_warmup(app)
            % Warm the pool shortly after the UI becomes visible so the first
            % green-button launch does not pay the full cold-start penalty.
            if isempty(app.fig) || ~isvalid(app.fig)
                return;
            end
            app.safe_stop_timer('startup_pool_warm_timer');
            app.startup_pool_warm_timer = timer( ...
                'ExecutionMode', 'singleShot', ...
                'StartDelay', 0.35, ...
                'TimerFcn', {@ui_controller_timer_run_startup_parallel_pool_warmup, app});
            start(app.startup_pool_warm_timer);
        end

        function run_startup_parallel_pool_warmup(app)
            app.safe_stop_timer('startup_pool_warm_timer');
            if isempty(app.fig) || ~isvalid(app.fig)
                return;
            end
            if app.has_active_launch_request()
                return;
            end

            target_workers = app.resolve_startup_pool_warm_target_workers();
            try
                pool = ParallelSimulationExecutor.prewarm_pool(target_workers);
                if isempty(pool) || ~isvalid(pool)
                    return;
                end
                app.append_to_terminal(sprintf('Parallel pool ready on startup: %d workers.', pool.NumWorkers), 'info');
            catch ME
                app.append_to_terminal(sprintf('Parallel pool warm-up warning: %s', ME.message), 'warning');
            end
        end

        function target_workers = resolve_startup_pool_warm_target_workers(app)
            target_workers = 1;
            cfg = app.config;
            if ~isstruct(cfg)
                return;
            end

            target_workers = max(1, round(double(app.pick_field(cfg, {'pool_workers'}, 1))));
            interactive_cap = max(1, round(double(app.pick_field(cfg, {'interactive_pool_workers_max'}, target_workers))));
            target_workers = min(target_workers, interactive_cap);

            max_override = round(double(app.pick_field(cfg, {'pool_workers_max_override'}, 0)));
            if isfinite(max_override) && max_override >= 1
                target_workers = min(target_workers, max_override);
            end
        end

        function schedule_startup_collector_probe(app)
            % Defer heavyweight collector probing until after the UI becomes visible.
            % This keeps tab construction responsive while still refreshing the
            % probe badges shortly after startup.
            if isempty(app.fig) || ~isvalid(app.fig)
                return;
            end
            app.safe_stop_timer('startup_collector_probe_timer');
            app.startup_collector_probe_timer = timer( ...
                'ExecutionMode', 'singleShot', ...
                'StartDelay', 0.25, ...
                'TimerFcn', {@ui_controller_timer_run_startup_collector_probe, app});
            start(app.startup_collector_probe_timer);
        end

        function run_startup_collector_probe(app)
            app.safe_stop_timer('startup_collector_probe_timer');
            if isempty(app.fig) || ~isvalid(app.fig)
                return;
            end
            try
                app.refresh_collector_probe_status('all');
                app.update_checklist();
            catch ME
                app.append_to_terminal(sprintf('Startup collector probe warning: %s', ME.message), 'warning');
            end
        end

        function probe = refresh_collector_probe_status(app, source)
            % Update collector connection indicators from lightweight installation probes.
            T = app.layout_cfg.ui_text.monitor;
            if nargin < 2 || isempty(source)
                source = 'all';
            end
            source = lower(char(string(source)));
            runtime_only = strcmp(source, 'runtime');

            enabled = struct( ...
                'hwinfo', app.has_valid_handle('hwinfo_enable') && app.handles.hwinfo_enable.Value, ...
                'icue', app.has_valid_handle('icue_enable') && app.handles.icue_enable.Value);

            if isfield(app.handles, 'collector_probe_state') && isstruct(app.handles.collector_probe_state)
                state = app.handles.collector_probe_state;
            else
                state = struct('hwinfo', struct(), 'icue', struct());
            end
            runtime_state = app.resolve_collector_runtime_state();
            runtime_state = ExternalCollectorDispatcher.normalize_collector_payload(runtime_state);
            runtime_collector_status = app.pick_field(runtime_state, {'collector_status'}, struct());
            runtime_raw_paths = app.pick_field(runtime_state, {'raw_log_paths'}, struct());
            runtime_probe_details = app.pick_field(runtime_state, {'collector_probe_details'}, struct());

            refresh_all = strcmp(source, 'all') || runtime_only;
            if refresh_all || strcmp(source, 'hwinfo')
                if runtime_only
                    if ~isfield(state, 'hwinfo') || ~isstruct(state.hwinfo)
                        state.hwinfo = struct();
                    end
                else
                    state.hwinfo = app.probe_external_collector('hwinfo', enabled.hwinfo);
                end
                if isstruct(runtime_collector_status) && isfield(runtime_collector_status, 'hwinfo')
                    status_token = char(string(runtime_collector_status.hwinfo));
                    if ~isempty(strtrim(status_token))
                        state.hwinfo.status = status_token;
                        state.hwinfo.available = any(strcmpi(status_token, {'shared_memory_connected', 'csv_fallback', 'csv_target_mismatch', 'connected'}));
                        state.hwinfo.transport = char(string(app.pick_field(runtime_state, {'hwinfo_transport'}, 'none')));
                        state.hwinfo.status_reason = char(string(app.pick_field(runtime_state, {'hwinfo_status_reason'}, '')));
                        state.hwinfo.message = state.hwinfo.status_reason;
                        if isstruct(runtime_probe_details) && isfield(runtime_probe_details, 'hwinfo')
                            state.hwinfo.probe_details = runtime_probe_details.hwinfo;
                        end
                        if isstruct(runtime_raw_paths) && isfield(runtime_raw_paths, 'hwinfo')
                            state.hwinfo.csv_path = char(string(runtime_raw_paths.hwinfo));
                        end
                    end
                end
            end
            if refresh_all || strcmp(source, 'icue')
                if runtime_only
                    if ~isfield(state, 'icue') || ~isstruct(state.icue)
                        state.icue = struct();
                    end
                else
                    state.icue = app.probe_external_collector('icue', enabled.icue);
                end
                if isstruct(runtime_collector_status) && isfield(runtime_collector_status, 'icue')
                    status_token = char(string(runtime_collector_status.icue));
                    if ~isempty(strtrim(status_token))
                        state.icue.status = status_token;
                        state.icue.available = any(strcmpi(status_token, {'shared_memory_connected', 'csv_fallback', 'connected'}));
                        if isfield(state.icue, 'status_reason') && ~isempty(state.icue.status_reason)
                            state.icue.message = state.icue.status_reason;
                        else
                            state.icue.message = status_token;
                        end
                    end
                end
            end
            app.handles.collector_probe_state = state;

            if app.has_valid_handle('metrics_source_matlab')
                app.handles.metrics_source_matlab.Text = T.sidebar.collector_state_connected;
                app.handles.metrics_source_matlab.FontColor = app.layout_cfg.colors.accent_green;
            end
            app.set_collector_light('metrics_source_hwinfo', enabled.hwinfo, state.hwinfo);
            app.set_collector_light('metrics_source_icue', enabled.icue, state.icue);

            enabled_external_count = double(enabled.hwinfo) + double(enabled.icue);
            connected_external_count = double(enabled.hwinfo && app.collector_snapshot_available(state.hwinfo)) + ...
                double(enabled.icue && app.collector_snapshot_available(state.icue));

            probe = struct();
            probe.enabled_external_count = enabled_external_count;
            probe.connected_external_count = connected_external_count;
            probe.status_text = sprintf( ...
                T.sidebar.collector_probe_template, ...
                char(datetime('now', 'Format', 'HH:mm:ss')), ...
                connected_external_count, enabled_external_count);
            detail_parts = {};
            if enabled.hwinfo
                hwinfo_reason = '--';
                if isstruct(state.hwinfo)
                    if isfield(state.hwinfo, 'status_reason') && ~isempty(state.hwinfo.status_reason)
                        hwinfo_reason = char(string(state.hwinfo.status_reason));
                    elseif isfield(state.hwinfo, 'message') && ~isempty(state.hwinfo.message)
                        hwinfo_reason = char(string(state.hwinfo.message));
                    elseif isfield(state.hwinfo, 'status')
                        hwinfo_reason = char(string(state.hwinfo.status));
                    end
                end
                detail_parts{end + 1} = sprintf('HWiNFO: %s', hwinfo_reason); %#ok<AGROW>
            end
            if enabled.icue
                icue_reason = '--';
                if isstruct(state.icue)
                    if isfield(state.icue, 'status_reason') && ~isempty(state.icue.status_reason)
                        icue_reason = char(string(state.icue.status_reason));
                    elseif isfield(state.icue, 'message') && ~isempty(state.icue.message)
                        icue_reason = char(string(state.icue.message));
                    elseif isfield(state.icue, 'status')
                        icue_reason = char(string(state.icue.status));
                    end
                end
                detail_parts{end + 1} = sprintf('iCUE: %s', icue_reason); %#ok<AGROW>
            end
            if ~isempty(detail_parts)
                probe.status_text = sprintf('%s | %s', probe.status_text, strjoin(detail_parts, ' | '));
            end

            if app.has_valid_handle('collector_probe_status')
                app.handles.collector_probe_status.Text = probe.status_text;
                if connected_external_count == enabled_external_count && enabled_external_count > 0
                    app.handles.collector_probe_status.FontColor = app.layout_cfg.colors.accent_green;
                elseif enabled_external_count == 0
                    app.handles.collector_probe_status.FontColor = app.layout_cfg.colors.fg_muted;
                else
                    app.handles.collector_probe_status.FontColor = app.layout_cfg.colors.accent_yellow;
                end
            end
            if app.has_valid_handle('hwinfo_runtime_status')
                launch_prefs = app.collector_launch_preferences();
                runtime_prefs = app.collector_runtime_preferences();
                launch_root_dir = char(string(launch_prefs.root_dir));
                launch_csv_file = char(string(launch_prefs.csv_file));
                launch_session_dir = '--';
                hwinfo_observed = '--';
                hwinfo_sm_state = '--';
                hwinfo_reason = '--';
                hwinfo_mode = char(string(app.pick_field(runtime_prefs, {'hwinfo_control_mode'}, 'pro_cli_csv')));
                phase_target = 'resolved at phase launch';
                hwinfo_transport = char(string(app.pick_field(runtime_state, {'hwinfo_transport'}, 'none')));
                runtime_metrics = app.pick_field(runtime_state, {'metrics'}, struct());
                sample_metrics = { ...
                    sprintf('CPU %s%%', app.if_nan_num_fixed(app.pick_field(runtime_metrics, {'cpu_proxy'}, NaN), '%5.2f')) ...
                    sprintf('GPU %s%%', app.if_nan_num_fixed(app.pick_field(runtime_metrics, {'gpu_series'}, NaN), '%5.2f')) ...
                    sprintf('Temp %s C', app.if_nan_num_fixed(app.pick_field(runtime_metrics, {'cpu_temp_c'}, NaN), '%5.2f')) ...
                    sprintf('Power %s W', app.if_nan_num_fixed(app.pick_field(runtime_metrics, {'power_w'}, NaN), '%5.2f')) ...
                    sprintf('Fan %s RPM', app.if_nan_num_fixed(app.pick_field(runtime_metrics, {'fan_rpm'}, NaN), '%5.0f')) ...
                    sprintf('Pump %s RPM', app.if_nan_num_fixed(app.pick_field(runtime_metrics, {'pump_rpm'}, NaN), '%5.0f'))};
                if ~isempty(app.collector_launch_session_dir)
                    launch_session_dir = app.collector_launch_session_dir;
                end
                if isstruct(state) && isfield(state, 'hwinfo') && isstruct(state.hwinfo)
                    if isfield(state.hwinfo, 'probe_details') && isstruct(state.hwinfo.probe_details)
                        probe_hwinfo = state.hwinfo.probe_details;
                        if isfield(probe_hwinfo, 'ini_shared_memory_state') && ~isempty(probe_hwinfo.ini_shared_memory_state)
                            hwinfo_sm_state = char(string(probe_hwinfo.ini_shared_memory_state));
                        end
                    end
                    if isfield(state.hwinfo, 'csv_path') && ~isempty(state.hwinfo.csv_path)
                        hwinfo_observed = char(string(state.hwinfo.csv_path));
                    elseif isfield(state.hwinfo, 'probe_details') && isstruct(state.hwinfo.probe_details) && ...
                            isfield(state.hwinfo.probe_details, 'csv_observed_path') && ~isempty(state.hwinfo.probe_details.csv_observed_path)
                        hwinfo_observed = char(string(state.hwinfo.probe_details.csv_observed_path));
                    end
                    if isfield(state.hwinfo, 'status_reason') && ~isempty(state.hwinfo.status_reason)
                        hwinfo_reason = char(string(state.hwinfo.status_reason));
                    elseif isfield(state.hwinfo, 'message') && ~isempty(state.hwinfo.message)
                        hwinfo_reason = char(string(state.hwinfo.message));
                    end
                    if isfield(state.hwinfo, 'probe_details') && isstruct(state.hwinfo.probe_details) && ...
                            isfield(state.hwinfo.probe_details, 'raw_csv_path') && ~isempty(state.hwinfo.probe_details.raw_csv_path)
                        phase_target = char(string(state.hwinfo.probe_details.raw_csv_path));
                    end
                end
                app.handles.hwinfo_runtime_status.Text = sprintf( ...
                    ['Mode: %s | phase target: %s\n', ...
                    'Launch root: %s | launch CSV: %s\n', ...
                    'Launch session dir: %s | Transport: %s | Observed HWiNFO CSV: %s\n', ...
                    'SensorsSM: %s | Reason: %s\n', ...
                    'Live sample: %s | %s | %s | %s | %s | %s'], ...
                    hwinfo_mode, phase_target, launch_root_dir, launch_csv_file, ...
                    launch_session_dir, hwinfo_transport, hwinfo_observed, ...
                    hwinfo_sm_state, hwinfo_reason, sample_metrics{1}, sample_metrics{2}, ...
                    sample_metrics{3}, sample_metrics{4}, sample_metrics{5}, sample_metrics{6});
            end
        end

        function snapshot = probe_external_collector(app, source, enabled)
            if ~enabled
                snapshot = struct('available', false, 'status', 'disabled', 'path', '', ...
                    'message', 'collector disabled', 'status_reason', 'collector disabled');
                return;
            end
            if exist('ExternalCollectorAdapters', 'class') == 8 || exist('ExternalCollectorAdapters', 'file') == 2
                snapshot = ExternalCollectorAdapters.extract_snapshot( ...
                    source, enabled, app.collector_probe_paths(source), app.collector_runtime_preferences());
                return;
            end

            snapshot = struct('available', false, 'status', 'not_found', 'path', '', ...
                'message', 'collector executable not found', 'status_reason', 'collector executable not found');
            paths = app.collector_probe_paths(source);
            for i = 1:numel(paths)
                if exist(paths{i}, 'file') == 2
                    snapshot.status = 'connected';
                    snapshot.path = paths{i};
                    snapshot.available = true;
                    snapshot.message = 'collector executable found';
                    if strcmpi(source, 'hwinfo')
                        snapshot.available = false;
                        snapshot.status = 'csv_missing';
                        snapshot.message = 'shared memory unavailable; CSV logging not active';
                    end
                    snapshot.status_reason = snapshot.message;
                    return;
                end
            end
        end

        function paths = collector_probe_paths(~, source)
            if exist('ExternalCollectorAdapters', 'class') == 8 || exist('ExternalCollectorAdapters', 'file') == 2
                paths = ExternalCollectorAdapters.default_paths(source);
                return;
            end
            switch lower(char(string(source)))
                case 'hwinfo'
                    paths = {
                        'C:\Program Files\HWiNFO64\HWiNFO64.exe', ...
                        'C:\Program Files\HWiNFO32\HWiNFO32.exe', ...
                        'C:\Program Files\HWiNFO\HWiNFO.exe'
                    };
                case 'icue'
                    paths = {
                        'C:\Program Files\Corsair\Corsair iCUE5 Software\iCUE.exe', ...
                        'C:\Program Files\CORSAIR\CORSAIR iCUE 4 Software\iCUE.exe', ...
                        'C:\Program Files\Corsair\CORSAIR iCUE 3 Software\iCUE.exe', ...
                        'C:\Program Files\Corsair\CORSAIR iCUE Software\iCUE.exe'
                    };
                otherwise
                    paths = {};
            end
        end

        function runtime_cfg = collector_runtime_preferences(app)
            runtime_cfg = struct();
            if isfield(app, 'config') && isstruct(app.config) && ...
                    isfield(app.config, 'sustainability') && isstruct(app.config.sustainability) && ...
                    isfield(app.config.sustainability, 'collector_runtime') && ...
                    isstruct(app.config.sustainability.collector_runtime)
                runtime_cfg = app.config.sustainability.collector_runtime;
            end
            if ~isfield(runtime_cfg, 'collector_launch_root_dir')
                runtime_cfg.collector_launch_root_dir = '';
            end
            if ~isfield(runtime_cfg, 'collector_launch_csv_file')
                runtime_cfg.collector_launch_csv_file = 'launch_telemetry.csv';
            end
            if app.has_valid_handle('hwinfo_csv_target_dir')
                runtime_cfg.collector_launch_root_dir = char(string(app.handles.hwinfo_csv_target_dir.Value));
            end
            if app.has_valid_handle('hwinfo_csv_target_path')
                runtime_cfg.collector_launch_csv_file = char(string(app.handles.hwinfo_csv_target_path.Value));
            end
            if ~isfield(runtime_cfg, 'hwinfo_control_mode')
                runtime_cfg.hwinfo_control_mode = 'pro_cli_csv';
            end
            if app.has_valid_handle('hwinfo_mode')
                runtime_cfg.hwinfo_control_mode = char(string(app.handles.hwinfo_mode.Value));
            end
            if ~isfield(runtime_cfg, 'hwinfo_csv_target_dir')
                runtime_cfg.hwinfo_csv_target_dir = '';
            end
            if ~isfield(runtime_cfg, 'hwinfo_transport_mode')
                runtime_cfg.hwinfo_transport_mode = 'auto';
            end
            if ~isfield(runtime_cfg, 'hwinfo_csv_target_path')
                runtime_cfg.hwinfo_csv_target_path = '';
            end
            if ~isfield(runtime_cfg, 'hwinfo_pro_cli_enabled')
                runtime_cfg.hwinfo_pro_cli_enabled = true;
            end
            if ~isfield(runtime_cfg, 'hwinfo_pro_log_write_direct')
                runtime_cfg.hwinfo_pro_log_write_direct = true;
            end
            if ~isfield(runtime_cfg, 'hwinfo_pro_poll_rate_ms')
                runtime_cfg.hwinfo_pro_poll_rate_ms = max(100, round(double(app.pick_field(app.config, {'sample_interval'}, 1.0)) * 1000));
            end
            if ~isfield(runtime_cfg, 'hwinfo_pro_launch_timeout_s')
                runtime_cfg.hwinfo_pro_launch_timeout_s = 20;
            end
            if ~isfield(runtime_cfg, 'hwinfo_pro_csv_timeout_s')
                runtime_cfg.hwinfo_pro_csv_timeout_s = 45;
            end
            if ~isfield(runtime_cfg, 'hwinfo_pro_force_stop_fallback')
                runtime_cfg.hwinfo_pro_force_stop_fallback = true;
            end
        end

        function runtime_state = resolve_collector_runtime_state(app)
            runtime_state = struct();
            if isfield(app.handles, 'collector_probe_runtime_state') && ...
                    isstruct(app.handles.collector_probe_runtime_state)
                probe_state = app.handles.collector_probe_runtime_state;
                if isfield(probe_state, 'hwinfo')
                    runtime_state = app.merge_collector_runtime_source(runtime_state, probe_state.hwinfo, 'hwinfo');
                end
                if isfield(probe_state, 'icue')
                    runtime_state = app.merge_collector_runtime_source(runtime_state, probe_state.icue, 'icue');
                end
            end
            if isfield(app.handles, 'monitor_live_state') && isstruct(app.handles.monitor_live_state)
                runtime_state = app.merge_collector_runtime_source(runtime_state, app.handles.monitor_live_state, 'hwinfo');
                runtime_state = app.merge_collector_runtime_source(runtime_state, app.handles.monitor_live_state, 'icue');
            end
        end

        function runtime_state = merge_collector_runtime_source(app, runtime_state, sample, source)
            if nargin < 4 || ~isstruct(sample) || isempty(fieldnames(sample))
                return;
            end
            existing_score = app.collector_runtime_source_score(runtime_state, source);
            incoming_score = app.collector_runtime_source_score(sample, source);
            nested_fields = {'collector_status', 'raw_log_paths', 'collector_probe_details', 'coverage_domains', 'collector_series'};
            for field_index = 1:numel(nested_fields)
                field_name = nested_fields{field_index};
                nested_value = app.pick_field(sample, {field_name}, struct());
                if ~(isstruct(nested_value) && isfield(nested_value, source))
                    continue;
                end
                if ~app.collector_source_nested_value_has_content(nested_value, source, field_name)
                    continue;
                end
                if strcmp(field_name, 'collector_status')
                    existing_status = '';
                    if isfield(runtime_state, 'collector_status') && isstruct(runtime_state.collector_status) && ...
                            isfield(runtime_state.collector_status, source)
                        existing_status = char(string(runtime_state.collector_status.(source)));
                    end
                    incoming_status = char(string(nested_value.(source)));
                    if app.collector_status_rank(incoming_status) < app.collector_status_rank(existing_status)
                        continue;
                    end
                end
                if ~isfield(runtime_state, field_name) || ~isstruct(runtime_state.(field_name))
                    runtime_state.(field_name) = struct();
                end
                existing_has_content = isfield(runtime_state.(field_name), source) && ...
                    app.collector_source_nested_value_has_content(runtime_state.(field_name), source, field_name);
                if incoming_score >= existing_score || ~existing_has_content
                    runtime_state.(field_name).(source) = nested_value.(source);
                end
            end
            if isfield(sample, 'metrics') && isstruct(sample.metrics) && ~isempty(fieldnames(sample.metrics))
                if ~isfield(runtime_state, 'metrics') || ~isstruct(runtime_state.metrics) || ...
                        isempty(fieldnames(runtime_state.metrics)) || incoming_score >= existing_score
                    runtime_state.metrics = sample.metrics;
                end
            end
            if isfield(sample, 'collector_metric_catalog') && ~isempty(sample.collector_metric_catalog)
                runtime_state.collector_metric_catalog = sample.collector_metric_catalog;
            end
            if isfield(sample, 'overlay_metrics') && ~isempty(sample.overlay_metrics)
                runtime_state.overlay_metrics = sample.overlay_metrics;
            end
            if isfield(sample, 'timestamp_utc')
                runtime_state.timestamp_utc = sample.timestamp_utc;
            end
            if strcmpi(source, 'hwinfo')
                if isfield(sample, 'hwinfo_transport')
                    incoming_transport = char(string(sample.hwinfo_transport));
                    existing_transport = char(string(app.pick_field(runtime_state, {'hwinfo_transport'}, 'none')));
                    if strlength(string(strtrim(incoming_transport))) > 0 && ...
                            (~strcmpi(incoming_transport, 'none') || strcmpi(existing_transport, 'none') || incoming_score >= existing_score)
                        runtime_state.hwinfo_transport = incoming_transport;
                    end
                end
                if isfield(sample, 'hwinfo_status_reason')
                    incoming_reason = char(string(sample.hwinfo_status_reason));
                    existing_reason = char(string(app.pick_field(runtime_state, {'hwinfo_status_reason'}, '')));
                    if strlength(string(strtrim(incoming_reason))) > 0 && ...
                            (incoming_score >= existing_score || strlength(string(strtrim(existing_reason))) == 0)
                        runtime_state.hwinfo_status_reason = incoming_reason;
                    end
                end
            end
            runtime_state = ExternalCollectorDispatcher.normalize_collector_payload(runtime_state);
        end

        function score = collector_runtime_source_score(app, sample, source)
            score = 0;
            if nargin < 3 || ~isstruct(sample) || isempty(fieldnames(sample))
                return;
            end
            status_struct = app.pick_field(sample, {'collector_status'}, struct());
            status_value = char(string(app.pick_field(status_struct, {source}, '')));
            score = score + app.collector_status_rank(status_value);
            if strcmpi(source, 'hwinfo')
                transport_value = char(string(app.pick_field(sample, {'hwinfo_transport'}, 'none')));
                if strlength(string(strtrim(transport_value))) > 0 && ~strcmpi(transport_value, 'none')
                    score = score + 40;
                end
                if app.hwinfo_catalog_present(sample)
                    score = score + 35;
                end
            end
            if app.collector_source_series_present(sample, source)
                score = score + 45;
            end
            raw_paths = app.pick_field(sample, {'raw_log_paths'}, struct());
            if isstruct(raw_paths) && isfield(raw_paths, source) && strlength(string(strtrim(raw_paths.(source)))) > 0
                score = score + 10;
            end
            probe_details = app.pick_field(sample, {'collector_probe_details'}, struct());
            if isstruct(probe_details) && isfield(probe_details, source) && isstruct(probe_details.(source)) && ...
                    ~isempty(fieldnames(probe_details.(source)))
                score = score + 5;
            end
        end

        function rank = collector_status_rank(~, status_value)
            status_token = lower(strtrim(char(string(status_value))));
            switch status_token
                case {'shared_memory_connected', 'connected'}
                    rank = 100;
                case 'csv_fallback'
                    rank = 80;
                case {'shared_memory_incomplete', 'csv_target_mismatch', 'shared_memory_disabled', ...
                        'shared_memory_expired', 'csv_missing', 'parse_error', 'not_found'}
                    rank = 60;
                case {'disabled', 'off', 'none', ''}
                    rank = 0;
                otherwise
                    rank = 40;
            end
        end

        function tf = collector_source_nested_value_has_content(app, sample, source, field_name)
            tf = false;
            if nargin < 4 || ~isstruct(sample) || ~isfield(sample, source)
                return;
            end
            value = sample.(source);
            switch field_name
                case 'collector_status'
                    tf = strlength(string(strtrim(char(string(value))))) > 0;
                case 'raw_log_paths'
                    tf = strlength(string(strtrim(char(string(value))))) > 0;
                case 'coverage_domains'
                    tf = ~isempty(value);
                case 'collector_series'
                    tf = app.collector_source_series_present(struct('collector_series', sample), source);
                case 'collector_probe_details'
                    tf = isstruct(value) && ~isempty(fieldnames(value));
                otherwise
                    if isstruct(value)
                        tf = ~isempty(fieldnames(value));
                    elseif isnumeric(value) || islogical(value)
                        tf = ~isempty(value) && any(isfinite(double(value(:))));
                    else
                        tf = ~isempty(value);
                    end
            end
        end

        function sample = probe_collectors_runtime(app, source)
            sample = struct();
            if nargin < 2 || isempty(source)
                source = 'all';
            end
            source = lower(char(string(source)));
            app.collect_configuration_from_ui();
            [~, ~, settings] = app.build_runtime_inputs(app.config);
            settings = ExternalCollectorDispatcher.normalize_settings(settings);
            switch source
                case 'hwinfo'
                    settings.sustainability.external_collectors.icue = false;
                case 'icue'
                    settings.sustainability.external_collectors.hwinfo = false;
            end
            if ~ExternalCollectorDispatcher.any_external_enabled(settings)
                return;
            end
            sample = ExternalCollectorDispatcher.runtime_probe(settings);
        end

        function store_collector_probe_runtime_state(app, source, sample)
            if nargin < 3 || ~isstruct(sample) || isempty(fieldnames(sample))
                return;
            end
            if ~isfield(app.handles, 'collector_probe_runtime_state') || ...
                    ~isstruct(app.handles.collector_probe_runtime_state)
                app.handles.collector_probe_runtime_state = struct();
            end
            source = lower(char(string(source)));
            switch source
                case 'hwinfo'
                    app.handles.collector_probe_runtime_state.hwinfo = sample;
                case 'icue'
                    app.handles.collector_probe_runtime_state.icue = sample;
                otherwise
                    app.handles.collector_probe_runtime_state.hwinfo = sample;
                    app.handles.collector_probe_runtime_state.icue = sample;
            end
        end

        function prefs = collector_launch_preferences(app, runtime_cfg)
            if nargin < 2 || ~isstruct(runtime_cfg)
                runtime_cfg = app.collector_runtime_preferences();
            end

            root_dir = '';
            if isfield(runtime_cfg, 'collector_launch_root_dir') && ~isempty(runtime_cfg.collector_launch_root_dir)
                root_dir = char(string(runtime_cfg.collector_launch_root_dir));
            end

            csv_file = 'launch_telemetry.csv';
            if isfield(runtime_cfg, 'collector_launch_csv_file') && ~isempty(runtime_cfg.collector_launch_csv_file)
                csv_file = char(string(runtime_cfg.collector_launch_csv_file));
            end

            if isempty(strtrim(root_dir))
                root_dir = fullfile(app.default_collector_launch_root_dir(), '');
            end
            if isempty(strtrim(csv_file))
                csv_file = 'launch_telemetry.csv';
            end

            prefs = struct('root_dir', root_dir, 'csv_file', csv_file);
        end

        function session = ensure_collector_launch_session(app, runtime_cfg)
            prefs = app.collector_launch_preferences(runtime_cfg);
            root_dir = char(string(prefs.root_dir));
            csv_file = char(string(prefs.csv_file));

            [csv_parent, csv_name, csv_ext] = fileparts(csv_file);
            if ~isempty(csv_parent)
                root_dir = csv_parent;
                csv_file = [csv_name, csv_ext];
            end
            if isempty(csv_file)
                csv_file = 'launch_telemetry.csv';
            end
            if isempty(csv_ext)
                csv_file = [csv_file, '.csv'];
            end

            if isempty(app.collector_launch_session_id)
                app.collector_launch_session_id = char(datetime('now', 'Format', 'yyyyMMdd_HHmmss'));
            end
            if isempty(app.collector_launch_root_dir)
                app.collector_launch_root_dir = root_dir;
            end
            if isempty(app.collector_launch_csv_file)
                app.collector_launch_csv_file = csv_file;
            end
            if isempty(app.collector_launch_session_dir)
                app.collector_launch_session_dir = fullfile(app.collector_launch_root_dir, ...
                    sprintf('ui_launch_%s', app.collector_launch_session_id));
            end
            if exist(app.collector_launch_root_dir, 'dir') ~= 7
                mkdir(app.collector_launch_root_dir);
            end
            if exist(app.collector_launch_session_dir, 'dir') ~= 7
                mkdir(app.collector_launch_session_dir);
            end
            if isempty(app.collector_launch_csv_path)
                app.collector_launch_csv_path = fullfile(app.collector_launch_session_dir, app.collector_launch_csv_file);
            end

            session = struct( ...
                'session_id', app.collector_launch_session_id, ...
                'root_dir', app.collector_launch_root_dir, ...
                'session_output_dir', app.collector_launch_session_dir, ...
                'session_csv_path', app.collector_launch_csv_path, ...
                'csv_file', app.collector_launch_csv_file);
        end

        function artifact = persist_collector_launch_csv(app)
            artifact = struct( ...
                'session_id', '', ...
                'session_output_dir', '', ...
                'session_csv_path', '', ...
                'rows_written', 0, ...
                'run_count', 0);

            session = app.ensure_collector_launch_session(app.collector_runtime_preferences());
            artifact.session_id = session.session_id;
            artifact.session_output_dir = session.session_output_dir;
            artifact.session_csv_path = session.session_csv_path;

            if isempty(app.session_figures)
                return;
            end

            tables = cell(1, 0);
            for i = 1:numel(app.session_figures)
                entry = app.session_figures(i);
                if ~isfield(entry, 'artifacts') || ~isstruct(entry.artifacts)
                    continue;
                end
                if isfield(entry.artifacts, 'is_imported') && logical(entry.artifacts.is_imported)
                    continue;
                end
                if ~isfield(entry, 'monitor_series') || ~isstruct(entry.monitor_series)
                    continue;
                end
                run_table = ExternalCollectorDispatcher.launch_session_table( ...
                    session.session_id, i, entry.metadata, entry.run_config, entry.parameters, entry.monitor_series);
                if ~isempty(run_table)
                    tables{end + 1} = run_table; %#ok<AGROW>
                end
            end

            if isempty(tables)
                return;
            end

            combined = tables{1};
            for i = 2:numel(tables)
                combined = [combined; tables{i}]; %#ok<AGROW>
            end
            writetable(combined, session.session_csv_path);
            artifact.rows_written = height(combined);
            artifact.run_count = numel(tables);
        end

        function root_dir = default_collector_launch_root_dir(~)
            try
                root_dir = fullfile(PathBuilder.get_repo_root(), 'Artifacts', 'CollectorLaunches');
            catch
                root_dir = fullfile(pwd, 'Artifacts', 'CollectorLaunches');
            end
        end

        function set_collector_light(app, handle_name, enabled, snapshot)
            T = app.layout_cfg.ui_text.monitor;
            if ~app.has_valid_handle(handle_name)
                return;
            end
            if ~enabled
                app.handles.(handle_name).Text = T.sidebar.collector_state_off;
                app.handles.(handle_name).FontColor = app.layout_cfg.colors.fg_muted;
                return;
            end
            status_text = T.sidebar.collector_state_missing;
            if isstruct(snapshot) && isfield(snapshot, 'status')
                switch lower(char(string(snapshot.status)))
                    case 'shared_memory_connected'
                        status_text = 'shared mem';
                    case 'csv_fallback'
                        status_text = 'csv fallback';
                    case 'csv_target_mismatch'
                        status_text = 'target mismatch';
                    case 'shared_memory_disabled'
                        status_text = 'shm disabled';
                    case 'shared_memory_expired'
                        status_text = 'shm expired';
                    case 'csv_missing'
                        status_text = 'csv missing';
                    case 'parse_error'
                        status_text = 'parse error';
                    case 'executable_found'
                        status_text = 'exe found';
                    case {'not_found', 'not_configured'}
                        status_text = 'not found';
                    case 'disabled'
                        status_text = 'off';
                    case 'connected'
                        status_text = 'connected';
                end
            end
            if isstruct(snapshot) && isfield(snapshot, 'status') && strcmpi(char(string(snapshot.status)), 'csv_target_mismatch')
                app.handles.(handle_name).Text = status_text;
                app.handles.(handle_name).FontColor = app.layout_cfg.colors.accent_yellow;
            elseif app.collector_snapshot_available(snapshot)
                app.handles.(handle_name).Text = status_text;
                app.handles.(handle_name).FontColor = app.layout_cfg.colors.accent_green;
            else
                app.handles.(handle_name).Text = status_text;
                app.handles.(handle_name).FontColor = app.layout_cfg.colors.accent_yellow;
            end
        end

        function tf = collector_snapshot_available(~, snapshot)
            tf = false;
            if ~isstruct(snapshot)
                return;
            end
            if isfield(snapshot, 'available')
                tf = logical(snapshot.available);
                if tf
                    return;
                end
            end
            if isfield(snapshot, 'status')
                status = lower(char(string(snapshot.status)));
                tf = any(strcmp(status, {'shared_memory_connected', 'csv_fallback', 'csv_target_mismatch', 'connected'}));
            end
        end

        function state = on_off(~, tf)
            if tf
                state = 'on';
            else
                state = 'off';
            end
        end

        function label = on_off_label(~, tf)
            if tf
                label = 'on';
            else
                label = 'off';
            end
        end

        function restore_contour_warning_state(~, warn1, warn2, warn3, warn4)
            % Restore contour warning states after guarded contour rendering.
            if isstruct(warn1) && isfield(warn1, 'identifier') && ~isempty(warn1.identifier)
                warning(warn1.state, warn1.identifier);
            end
            if isstruct(warn2) && isfield(warn2, 'identifier') && ~isempty(warn2.identifier)
                warning(warn2.state, warn2.identifier);
            end
            if nargin >= 4 && isstruct(warn3) && isfield(warn3, 'identifier') && ~isempty(warn3.identifier)
                warning(warn3.state, warn3.identifier);
            end
            if nargin >= 5 && isstruct(warn4) && isfield(warn4, 'identifier') && ~isempty(warn4.identifier)
                warning(warn4.state, warn4.identifier);
            end
        end
        
        function yesno = to_yes_no(~, tf)
            if tf
                yesno = 'Yes';
            else
                yesno = 'No';
            end
        end

        function load_preset(app, preset_name)
            if app.has_valid_handle('ic_scenario')
                app.handles.ic_scenario.Value = 'Manual';
            end
            switch preset_name
                case 'stretched_gaussian'
                    app.handles.ic_dropdown.Value = 'Stretched Gaussian';
                    app.update_ic_fields();
                    [~, schema] = app.resolve_active_ic_type();
                    app.write_ic_dynamic_values(schema, app.default_dynamic_values(schema));
                    app.append_to_terminal('ÃƒÂ¢Ã…â€œÃ¢â‚¬Å“ Loaded: Stretched Gaussian preset');
                    
                case 'lamb_oseen'
                    app.handles.ic_dropdown.Value = 'Lamb-Oseen';
                    app.update_ic_fields();
                    [~, schema] = app.resolve_active_ic_type();
                    app.write_ic_dynamic_values(schema, struct('circulation', 1.0, 'virtual_time', 100.0, 'nu', 0.001));
                    app.append_to_terminal('ÃƒÂ¢Ã…â€œÃ¢â‚¬Å“ Loaded: Lamb-Oseen preset');
                    
                case 'rankine'
                    app.handles.ic_dropdown.Value = 'Rankine';
                    app.update_ic_fields();
                    [~, schema] = app.resolve_active_ic_type();
                    app.write_ic_dynamic_values(schema, struct('core_vorticity', 1.0, 'core_radius', 1.0));
                    app.append_to_terminal('ÃƒÂ¢Ã…â€œÃ¢â‚¬Å“ Loaded: Rankine preset');
                    
                case 'lamb_dipole'
                    app.handles.ic_dropdown.Value = 'Lamb Dipole';
                    app.update_ic_fields();
                    [~, schema] = app.resolve_active_ic_type();
                    app.write_ic_dynamic_values(schema, struct('translation_speed', 0.5, 'dipole_radius', 1.0));
                    app.append_to_terminal('ÃƒÂ¢Ã…â€œÃ¢â‚¬Å“ Loaded: Lamb Dipole preset');
            end
            app.update_ic_preview();
        end
        
        function export_configuration(app)
            [file, path] = uiputfile({'*.json';'*.mat'}, 'Export Configuration', 'simulation_config.json');
            if isequal(file, 0)
                return;
            end
            
            filepath = fullfile(path, file);
            config_export = struct();
            method_val = app.handles.method_dropdown.Value;
            switch method_val
                case 'Finite Difference'
                    config_export.method = 'finite_difference';
                case 'Finite Volume'
                    config_export.method = 'finite_volume';
                case 'Shallow Water'
                    config_export.method = 'shallow_water';
                case 'Spectral'
                    config_export.method = 'spectral';
                otherwise
                    config_export.method = 'finite_difference';
            end

            mode_val = app.handles.mode_dropdown.Value;
            switch mode_val
                case 'Evolution'
                    config_export.mode = 'evolution';
                    config_export.run_mode_internal = 'Evolution';
                case 'Convergence'
                    config_export.mode = 'convergence';
                    config_export.run_mode_internal = 'Convergence';
                case {'Parameter Sweep', 'Sweep'}
                    config_export.mode = 'sweep';
                    config_export.run_mode_internal = 'ParameterSweep';
                case 'Animation'
                    config_export.mode = 'animation';
                    config_export.run_mode_internal = 'Evolution';
                otherwise
                    config_export.mode = 'evolution';
                    config_export.run_mode_internal = 'Evolution';
            end

            config_export.Nx = round(app.handles.Nx.Value);
            config_export.Ny = round(app.handles.Ny.Value);
            config_export.Nz = 12;
            config_export.Lx = max(1e-9, double(app.handles.Lx.Value));
            config_export.Ly = max(1e-9, double(app.handles.Ly.Value));
            config_export.Lz = 1.0;
            config_export.equal_spacing = false;
            if app.has_valid_handle('equal_spacing')
                config_export.equal_spacing = logical(app.handles.equal_spacing.Value);
            end
            config_export.grid_mode = app.get_grid_mode_token();
            config_export.dx = config_export.Lx / max(config_export.Nx, 1);
            config_export.dy = config_export.Ly / max(config_export.Ny, 1);
            config_export.is_anisotropic = abs(config_export.dx - config_export.dy) > ...
                1.0e-12 * max(config_export.dx, config_export.dy);
            config_export.delta = min(config_export.dx, config_export.dy);
            config_export.dt = app.handles.dt.Value;
            config_export.t_final = app.handles.t_final.Value;
            config_export.Tfinal = app.handles.t_final.Value;
            config_export.nu = app.handles.nu.Value;
            config_export.num_plot_snapshots = max(1, round(app.handles.num_snapshots.Value));
