            config_export.animation_export_resolution_px = max(2, round([anim_width_in, anim_height_in] * config_export.animation_export_dpi));
            config_export.animation_num_frames = max(2, round(app.handles.animation_num_frames.Value));
            config_export.animation_gif_min_frames = min(max(2, round(double(config_export.animation_gif_min_frames))), ...
                config_export.animation_num_frames);
            config_export.num_frame_snapshots = max(config_export.num_plot_snapshots, config_export.animation_num_frames);

            config_export.enable_monitoring = app.handles.enable_monitoring.Value;
            config_export.launch_progress_only = app.safe_checkbox_value('launch_progress_only', false);
