            config_export.sustainability_auto_log = app.handles.sustainability_auto_log.Value;
            config_export.collectors = struct( ...
                'hwinfo', app.handles.hwinfo_enable.Value, ...
                'icue', app.handles.icue_enable.Value, ...
                'strict', app.handles.collector_strict.Value, ...
                'machine_tag', app.handles.machine_tag.Value);
            config_export.sustainability = struct( ...
                'collector_runtime', struct( ...
                    'hwinfo_control_mode', char(string(app.handles.hwinfo_mode.Value)), ...
                    'collector_launch_root_dir', char(string(app.handles.hwinfo_csv_target_dir.Value)), ...
                    'collector_launch_csv_file', char(string(app.handles.hwinfo_csv_target_path.Value))));
            if isfield(app.config, 'defaults_source') && isstruct(app.config.defaults_source)
                config_export.defaults_source = app.config.defaults_source;
            elseif isfield(app.layout_cfg, 'defaults_source')
                config_export.defaults_source = app.layout_cfg.defaults_source;
            end
            
            if endsWith(file, '.json')
                json_str = jsonencode(config_export);
                fid = fopen(filepath, 'w');
                fprintf(fid, '%s', json_str);
                fclose(fid);
            else
                save(filepath, 'config_export');
            end
            
            app.append_to_terminal(sprintf('ÃƒÂ¢Ã…â€œÃ¢â‚¬Å“ Configuration exported to: %s', file));
        end
        
        function import_configuration(app)
            [file, path] = uigetfile({'*.json;*.mat', 'Config Files (*.json, *.mat)'}, ...
                'Import Configuration');
            if isequal(file, 0)
                return;
            end

            filepath = fullfile(path, file);
            cfg = struct();
            try
                if endsWith(lower(file), '.json')
                    cfg = jsondecode(fileread(filepath));
                else
                    payload = load(filepath);
                    if isfield(payload, 'config_export')
                        cfg = payload.config_export;
                    else
                        keys = fieldnames(payload);
                        if ~isempty(keys) && isstruct(payload.(keys{1}))
                            cfg = payload.(keys{1});
                        end
                    end
                end
            catch ME
                uialert(app.fig, sprintf('Could not import config: %s', ME.message), ...
                    'Import Error', 'icon', 'error');
                app.append_to_terminal(sprintf('Import failed: %s', ME.message), 'error');
                return;
            end

            if ~isstruct(cfg) || isempty(fieldnames(cfg))
                uialert(app.fig, 'Config file contained no usable fields.', ...
                    'Import Error', 'icon', 'error');
                app.append_to_terminal('Import failed: no usable fields found.', 'error');
                return;
            end

            if ~isfield(cfg, 'time_integrator') && isfield(cfg, 'use_rk4')
                if logical(cfg.use_rk4)
                    cfg.time_integrator = 'RK4';
                else
                    cfg.time_integrator = 'Forward Euler';
                end
            end
            if ~isfield(cfg, 'equal_spacing') && isfield(cfg, 'grid_mode')
                cfg.equal_spacing = false;
            end
            if isfield(cfg, 'grid_mode')
                app.config.grid_mode = char(string(cfg.grid_mode));
            end
            if ~isfield(cfg, 'ic_scenario')
                cfg.ic_scenario = 'Manual';
            end
            if ~isfield(cfg, 'ic_amplitude')
                if isfield(cfg, 'ic_scale')
                    cfg.ic_amplitude = cfg.ic_scale;
                else
                    cfg.ic_amplitude = 1.0;
                end
            end
            if ~isfield(cfg, 'fd_post_closure_edge_omega_zero')
                cfg.fd_post_closure_edge_omega_zero = false;
            end

            if isfield(cfg, 'method')
                method_token = lower(char(string(cfg.method)));
                switch method_token
                    case 'finite_difference'
                        app.handles.method_dropdown.Value = 'Finite Difference';
                    case 'finite_volume'
                        app.handles.method_dropdown.Value = 'Finite Volume';
                    case {'shallow_water', 'swe'}
                        app.handles.method_dropdown.Value = 'Shallow Water';
                    case 'spectral'
                        app.handles.method_dropdown.Value = 'Spectral';
                    case 'bathymetry'
                        app.handles.method_dropdown.Value = 'Finite Difference';
                        if app.has_valid_handle('bathymetry_scenario')
                            app.handles.bathymetry_scenario.Value = 'shore_runup_2d';
                        end
                end
            end

            requested_method_token = lower(char(string(app.handles.method_dropdown.Value)));
            requested_ic_token = '';
            if isfield(cfg, 'ic_type')
                requested_ic_token = lower(char(string(cfg.ic_type)));
            end
            if strcmp(requested_method_token, 'shallow water') && strcmp(requested_ic_token, 'no_initial_condition')
                error('UIController:UnsupportedImportedIC', ...
                    'Shallow Water does not accept the No Initial Condition vorticity initializer during config import.');
            end

            if isfield(cfg, 'mode')
                mode_token = lower(char(string(cfg.mode)));
                switch mode_token
                    case 'evolution'
                        app.handles.mode_dropdown.Value = 'Evolution';
                    case 'convergence'
                        app.handles.mode_dropdown.Value = 'Convergence';
                    case {'sweep', 'parameter_sweep', 'parametersweep'}
                        app.handles.mode_dropdown.Value = 'Parameter Sweep';
                    case 'animation'
                        app.handles.mode_dropdown.Value = 'Animation';
                    case 'experimentation'
                        app.handles.mode_dropdown.Value = 'Parameter Sweep';
                end
            end

            if isfield(cfg, 'Nx'), app.handles.Nx.Value = cfg.Nx; end
            if isfield(cfg, 'Ny'), app.handles.Ny.Value = cfg.Ny; end
            if isfield(cfg, 'Lx'), app.handles.Lx.Value = cfg.Lx; end
            if isfield(cfg, 'Ly'), app.handles.Ly.Value = cfg.Ly; end
            if app.has_valid_handle('equal_spacing')
                app.handles.equal_spacing.Value = false;
            end
            if isfield(cfg, 'dx') && app.has_valid_handle('dx')
                app.handles.dx.Value = cfg.dx;
            end
            if isfield(cfg, 'dy') && app.has_valid_handle('dy')
                app.handles.dy.Value = cfg.dy;
            end
            if isfield(cfg, 'delta')
                app.handles.delta.Value = cfg.delta;
            elseif isfield(cfg, 'dx') && isfield(cfg, 'dy')
                app.handles.delta.Value = min(cfg.dx, cfg.dy);
            end
            if isfield(cfg, 'dt'), app.handles.dt.Value = cfg.dt; end
            if isfield(cfg, 't_final'), app.handles.t_final.Value = cfg.t_final; end
            if isfield(cfg, 'Tfinal'), app.handles.t_final.Value = cfg.Tfinal; end
            if isfield(cfg, 'nu'), app.handles.nu.Value = cfg.nu; end
            if isfield(cfg, 'num_plot_snapshots')
                app.handles.num_snapshots.Value = cfg.num_plot_snapshots;
            elseif isfield(cfg, 'num_snapshots')
                app.handles.num_snapshots.Value = cfg.num_snapshots;
            end

            if isfield(cfg, 'ic_type')
                target_ic = lower(char(string(cfg.ic_type)));
                for k = 1:numel(app.handles.ic_dropdown.Items)
                    item = app.handles.ic_dropdown.Items{k};
                    if strcmp(app.map_ic_display_to_type(item), target_ic)
                        app.handles.ic_dropdown.Value = item;
                        break;
                    end
                end
            end
            app.sync_ic_scenario_items_for_active_ic(app.pick_field(cfg, {'ic_scenario'}, 'Manual'));

            if isfield(cfg, 'ic_arrangement')
                app.config.ic_arrangement = app.find_ic_arrangement_entry(cfg.ic_arrangement).id;
                app.config.ic_pattern = app.config.ic_arrangement;
            elseif isfield(cfg, 'ic_pattern')
                app.config.ic_arrangement = app.find_ic_arrangement_entry(cfg.ic_pattern).id;
                app.config.ic_pattern = app.config.ic_arrangement;
            end
            if isfield(cfg, 'ic_contour_bands') && app.has_valid_handle('ic_contour_bands_btn')
                app.handles.ic_contour_bands_btn.Value = logical(cfg.ic_contour_bands);
                app.sync_ic_contour_bands_button();
            end
            if isfield(cfg, 'ic_multi_vortex_rows')
                app.config.ic_multi_vortex_rows = cfg.ic_multi_vortex_rows;
            end
            if isfield(cfg, 'ic_multi_vortex_experimental')
                app.config.ic_multi_vortex_experimental = logical(cfg.ic_multi_vortex_experimental);
            end

            app.update_ic_fields();
            app.apply_imported_ic_shared_state(cfg);
            [~, import_schema] = app.resolve_active_ic_type();
            if isfield(cfg, 'ic_dynamic_values') && isstruct(cfg.ic_dynamic_values)
                app.write_ic_dynamic_values(import_schema, cfg.ic_dynamic_values);
            else
                coeff_legacy = [
                    app.pick_field(cfg, {'ic_coeff1'}, 0), ...
                    app.pick_field(cfg, {'ic_coeff2'}, 0), ...
                    app.pick_field(cfg, {'ic_coeff3'}, 0), ...
                    app.pick_field(cfg, {'ic_coeff4'}, 0)
                ];
                app.write_ic_dynamic_values(import_schema, app.dynamic_from_legacy_coeff_override(import_schema, coeff_legacy));
            end

            if isfield(cfg, 'simulation_scenario') && app.has_valid_handle('simulation_scenario')
                req_sim_scn = char(string(cfg.simulation_scenario));
                match_idx = find(strcmpi(req_sim_scn, app.handles.simulation_scenario.Items), 1, 'first');
                if ~isempty(match_idx)
                    app.handles.simulation_scenario.Value = app.handles.simulation_scenario.Items{match_idx};
                end
                app.config.simulation_scenario = req_sim_scn;
            end
            if isfield(cfg, 'bathymetry_scenario') && app.has_valid_handle('bathymetry_scenario')
                req_bathy = normalize_bathymetry_scenario_token(cfg.bathymetry_scenario);
                app.sync_bathymetry_scenario_items_for_method();
                if any(strcmpi(req_bathy, app.handles.bathymetry_scenario.ItemsData))
                    app.handles.bathymetry_scenario.Value = req_bathy;
                end
                app.config.bathymetry_scenario = req_bathy;
            end
            if isfield(cfg, 'bathymetry_bed_slope')
                app.config.bathymetry_bed_slope = double(cfg.bathymetry_bed_slope);
            end
            if isfield(cfg, 'bathymetry_depth_offset')
                app.config.bathymetry_depth_offset = double(cfg.bathymetry_depth_offset);
            end
            if isfield(cfg, 'bathymetry_relief_amplitude')
                app.config.bathymetry_relief_amplitude = double(cfg.bathymetry_relief_amplitude);
            end
            if isfield(cfg, 'bathymetry_resolution') && isfinite(cfg.bathymetry_resolution)
                app.config.bathymetry_resolution = round(double(cfg.bathymetry_resolution));
            end
            if isfield(cfg, 'bathymetry_custom_points') && ~isempty(cfg.bathymetry_custom_points)
                app.config.bathymetry_custom_points = cfg.bathymetry_custom_points;
            end
            if isfield(cfg, 'bathymetry_dynamic_params') && isstruct(cfg.bathymetry_dynamic_params)
                app.config.bathymetry_dynamic_params = cfg.bathymetry_dynamic_params;
            end
            if isfield(cfg, 'bathymetry_file')
                app.config.bathymetry_file = char(string(cfg.bathymetry_file));
            end
            if isfield(cfg, 'fd_post_closure_edge_omega_zero')
                app.config.fd_post_closure_edge_omega_zero = logical(cfg.fd_post_closure_edge_omega_zero);
            end
            app.sync_bathymetry_controls('interactive');
            if isfield(cfg, 'motion_enabled')
                app.config.motion_enabled = logical(cfg.motion_enabled);
            end
            if isfield(cfg, 'motion_model')
                app.config.motion_model = char(string(cfg.motion_model));
            end
            if isfield(cfg, 'motion_amplitude')
                app.config.motion_amplitude = double(cfg.motion_amplitude);
            end
            cfg = app.normalize_vorticity_only_legacy_fields(cfg, 'config import');
            if isfield(cfg, 'cpu_allocation_pct') && app.has_valid_handle('cpu_allocation_pct')
                app.handles.cpu_allocation_pct.Value = cfg.cpu_allocation_pct;
            end
            if isfield(cfg, 'memory_allocation_pct') && app.has_valid_handle('memory_allocation_pct')
                app.handles.memory_allocation_pct.Value = cfg.memory_allocation_pct;
            end
            if isfield(cfg, 'gpu_allocation_pct') && app.has_valid_handle('gpu_allocation_pct')
                app.handles.gpu_allocation_pct.Value = cfg.gpu_allocation_pct;
            end
            if isfield(cfg, 'monitor_update_hz') && app.has_valid_handle('monitor_update_hz')
                app.handles.monitor_update_hz.Value = cfg.monitor_update_hz;
            end
            if isfield(cfg, 'progress_update_hz') && app.has_valid_handle('progress_update_hz')
                app.handles.progress_update_hz.Value = cfg.progress_update_hz;
            end
            if isfield(cfg, 'pool_workers') && app.has_valid_handle('pool_workers')
                app.handles.pool_workers.Value = max(1, round(double(cfg.pool_workers)));
            end
            if isfield(cfg, 'resource_strategy') && app.has_valid_handle('resource_strategy')
                requested_strategy = char(string(cfg.resource_strategy));
                if any(strcmp(requested_strategy, app.handles.resource_strategy.Items))
                    app.handles.resource_strategy.Value = requested_strategy;
                end
            end
            if isfield(cfg, 'gpu_policy') && app.has_valid_handle('gpu_policy')
                requested_gpu_policy = char(string(cfg.gpu_policy));
                if any(strcmp(requested_gpu_policy, app.handles.gpu_policy.Items))
                    app.handles.gpu_policy.Value = requested_gpu_policy;
                end
            end
            if isfield(cfg, 'planner_use_host_profiles') && app.has_valid_handle('planner_use_host_profiles')
                app.handles.planner_use_host_profiles.Value = logical(cfg.planner_use_host_profiles);
            end
            if isfield(cfg, 'interactive_pool_workers_max') && app.has_valid_handle('interactive_pool_workers_max')
                app.handles.interactive_pool_workers_max.Value = max(1, round(double(cfg.interactive_pool_workers_max)));
            end
            if isfield(cfg, 'throughput_pool_workers_min') && app.has_valid_handle('throughput_pool_workers_min')
                app.handles.throughput_pool_workers_min.Value = max(1, round(double(cfg.throughput_pool_workers_min)));
            end
            if isfield(cfg, 'interactive_thread_headroom_pct') && app.has_valid_handle('interactive_thread_headroom_pct')
                app.handles.interactive_thread_headroom_pct.Value = min(max(double(cfg.interactive_thread_headroom_pct), 0), 99);
            end
            if isfield(cfg, 'gpu_min_workload_cells_steps') && app.has_valid_handle('gpu_min_workload_cells_steps')
                app.handles.gpu_min_workload_cells_steps.Value = max(0, double(cfg.gpu_min_workload_cells_steps));
            end
            if isfield(cfg, 'gpu_memory_guard_pct') && app.has_valid_handle('gpu_memory_guard_pct')
                app.handles.gpu_memory_guard_pct.Value = min(max(double(cfg.gpu_memory_guard_pct), 1), 99);
            end
            if isfield(cfg, 'pool_workers_max_override') && app.has_valid_handle('pool_workers_max_override')
                app.handles.pool_workers_max_override.Value = max(0, round(double(cfg.pool_workers_max_override)));
            end
            if isfield(cfg, 'time_integrator') && app.has_valid_handle('time_integrator')
                requested_integrator = char(string(cfg.time_integrator));
                if any(strcmp(requested_integrator, app.handles.time_integrator.Items))
                    app.handles.time_integrator.Value = requested_integrator;
                end
            end
            if app.has_valid_handle('arakawa_enable')
                use_arakawa = false;
                if isfield(cfg, 'method_config') && isstruct(cfg.method_config) && ...
                        isfield(cfg.method_config, 'fd') && isstruct(cfg.method_config.fd) && ...
                        isfield(cfg.method_config.fd, 'advection_scheme') && ...
                        ~isempty(cfg.method_config.fd.advection_scheme)
                    use_arakawa = strcmpi(char(string(cfg.method_config.fd.advection_scheme)), 'Arakawa');
                elseif isfield(cfg, 'use_arakawa')
                    use_arakawa = logical(cfg.use_arakawa);
                end
                app.handles.arakawa_enable.Value = use_arakawa;
            end
            if isfield(cfg, 'use_gpu') && app.has_valid_handle('gpu_enable')
                app.handles.gpu_enable.Value = logical(cfg.use_gpu);
            end
            app.sync_gpu_toggle_state(true);

            if isfield(cfg, 'convergence_N_coarse'), app.handles.conv_N_coarse.Value = cfg.convergence_N_coarse; end
            if isfield(cfg, 'convergence_N_max'), app.handles.conv_N_max.Value = cfg.convergence_N_max; end
            if isfield(cfg, 'convergence_dt_values') && app.has_valid_handle('conv_dt_values')
                app.handles.conv_dt_values.Value = app.numeric_csv_string(cfg.convergence_dt_values);
            end
            if isfield(cfg, 'convergence_tol'), app.handles.conv_tolerance.Value = cfg.convergence_tol; end
            if isfield(cfg, 'convergence_criterion_type')
                app.handles.conv_criterion.Value = app.normalize_convergence_criterion_token(cfg.convergence_criterion_type);
            end
            if isfield(cfg, 'convergence_binary'), app.handles.conv_binary.Value = logical(cfg.convergence_binary); end
            if isfield(cfg, 'convergence_use_adaptive'), app.handles.conv_use_adaptive.Value = logical(cfg.convergence_use_adaptive); end
            if isfield(cfg, 'convergence_max_jumps'), app.handles.conv_max_jumps.Value = cfg.convergence_max_jumps; end
            if isfield(cfg, 'convergence_agent_enabled'), app.handles.conv_agent_enabled.Value = logical(cfg.convergence_agent_enabled); end
            if isfield(cfg, 'convergence_agent_objective_mode') && app.has_valid_handle('conv_agent_objective_mode')
                requested_obj = char(string(cfg.convergence_agent_objective_mode));
                if any(strcmp(requested_obj, app.handles.conv_agent_objective_mode.Items))
                    app.handles.conv_agent_objective_mode.Value = requested_obj;
                end
            end
            if isfield(cfg, 'convergence_agent_ui_mode') && isfield(app.handles, 'conv_mode_selected')
                requested_ui_mode = lower(char(string(cfg.convergence_agent_ui_mode)));
                if any(strcmp(requested_ui_mode, {'manual', 'agent', 'advanced'}))
                    app.handles.conv_mode_selected = requested_ui_mode;
                end
            end

            if isfield(cfg, 'sweep_parameter')
                app.config.sweep_parameter = char(string(cfg.sweep_parameter));
                if app.has_valid_handle('sweep_parameter')
                    app.handles.sweep_parameter.Value = app.config.sweep_parameter;
                end
            end
            if isfield(cfg, 'sweep_values')
                vals = cfg.sweep_values;
                if isnumeric(vals)
                    app.config.sweep_values = vals(:).';
                    if app.has_valid_handle('sweep_values')
                        app.handles.sweep_values.Value = strjoin(arrayfun(@(x) sprintf('%.6g', x), vals(:).', 'UniformOutput', false), ',');
                    end
                elseif ischar(vals) || isstring(vals)
                    app.config.sweep_values = app.parse_numeric_csv(char(string(vals)));
                    if app.has_valid_handle('sweep_values')
                        app.handles.sweep_values.Value = char(string(vals));
                    end
                end
            end
            if isfield(cfg, 'experimentation') && isstruct(cfg.experimentation)
                exp_cfg = cfg.experimentation;
                if ~isfield(app.config, 'experimentation') || ~isstruct(app.config.experimentation)
                    defaults_local = app.initialize_default_config();
                    if isfield(defaults_local, 'experimentation') && isstruct(defaults_local.experimentation)
                        app.config.experimentation = defaults_local.experimentation;
                    else
                        app.config.experimentation = struct( ...
                            'coeff_selector', 'ic_coeff1', ...
                            'range_start', 0.5, ...
                            'range_end', 2.0, ...
                            'num_points', 4);
                    end
                end
                if isfield(exp_cfg, 'coeff_selector')
                    app.config.experimentation.coeff_selector = char(string(exp_cfg.coeff_selector));
                    if app.has_valid_handle('exp_coeff_selector')
                        app.handles.exp_coeff_selector.Value = app.config.experimentation.coeff_selector;
                    end
                end
                if isfield(exp_cfg, 'range_start')
                    app.config.experimentation.range_start = exp_cfg.range_start;
                    if app.has_valid_handle('exp_range_start')
                        app.handles.exp_range_start.Value = exp_cfg.range_start;
                    end
                end
                if isfield(exp_cfg, 'range_end')
                    app.config.experimentation.range_end = exp_cfg.range_end;
                    if app.has_valid_handle('exp_range_end')
                        app.handles.exp_range_end.Value = exp_cfg.range_end;
                    end
                end
                if isfield(exp_cfg, 'num_points')
                    app.config.experimentation.num_points = exp_cfg.num_points;
                    if app.has_valid_handle('exp_num_points')
                        app.handles.exp_num_points.Value = exp_cfg.num_points;
                    end
                end
            end

            if isfield(cfg, 'save_csv'), app.handles.save_csv.Value = logical(cfg.save_csv); end
            if isfield(cfg, 'save_mat'), app.handles.save_mat.Value = logical(cfg.save_mat); end
            app.handles.figures_save_png.Value = false;
            if isfield(cfg, 'figures_save_fig'), app.handles.figures_save_fig.Value = logical(cfg.figures_save_fig); end
            if isfield(cfg, 'figures_dpi'), app.handles.figures_dpi.Value = cfg.figures_dpi; end
            if isfield(cfg, 'figures_close_after_save'), app.handles.figures_close_after_save.Value = logical(cfg.figures_close_after_save); end
            if isfield(cfg, 'figures_use_owl_saver'), app.handles.figures_use_owl_saver.Value = logical(cfg.figures_use_owl_saver); end
            if isfield(cfg, 'create_animations'), app.handles.create_animations.Value = logical(cfg.create_animations); end
            if isfield(cfg, 'animation_format'), app.handles.animation_format.Value = 'mp4+gif'; end
            if isfield(cfg, 'animation_fps'), app.handles.animation_fps.Value = cfg.animation_fps; end
            if isfield(cfg, 'animation_duration_s'), app.handles.animation_duration_s.Value = cfg.animation_duration_s; end
            if isfield(cfg, 'animation_export_preset'), app.handles.animation_export_preset.Value = char(string(cfg.animation_export_preset)); end
            if isfield(cfg, 'animation_export_dpi'), app.handles.animation_export_dpi.Value = cfg.animation_export_dpi; end
            if isfield(cfg, 'animation_num_frames'), app.handles.animation_num_frames.Value = cfg.animation_num_frames; end
            app.update_animation_export_controls();

            if isfield(cfg, 'enable_monitoring'), app.handles.enable_monitoring.Value = logical(cfg.enable_monitoring); end
            if isfield(cfg, 'launch_progress_only') && app.has_valid_handle('launch_progress_only')
                app.handles.launch_progress_only.Value = logical(cfg.launch_progress_only);
            end
            if isfield(cfg, 'sample_interval'), app.handles.sample_interval.Value = cfg.sample_interval; end
            if isfield(cfg, 'sustainability_auto_log'), app.handles.sustainability_auto_log.Value = logical(cfg.sustainability_auto_log); end
            if isfield(cfg, 'collectors') && isstruct(cfg.collectors)
                c = cfg.collectors;
                if isfield(c, 'hwinfo'), app.handles.hwinfo_enable.Value = logical(c.hwinfo); end
                if isfield(c, 'icue'), app.handles.icue_enable.Value = logical(c.icue); end
                if isfield(c, 'strict'), app.handles.collector_strict.Value = logical(c.strict); end
                if isfield(c, 'machine_tag'), app.handles.machine_tag.Value = char(string(c.machine_tag)); end
            end
            if isfield(cfg, 'sustainability') && isstruct(cfg.sustainability) && ...
                    isfield(cfg.sustainability, 'collector_runtime') && isstruct(cfg.sustainability.collector_runtime)
                runtime_cfg = cfg.sustainability.collector_runtime;
                if isfield(runtime_cfg, 'hwinfo_control_mode') && app.has_valid_handle('hwinfo_mode')
                    app.handles.hwinfo_mode.Value = char(string(runtime_cfg.hwinfo_control_mode));
                end
                if isfield(runtime_cfg, 'collector_launch_root_dir')
                    app.handles.hwinfo_csv_target_dir.Value = char(string(runtime_cfg.collector_launch_root_dir));
                elseif isfield(runtime_cfg, 'hwinfo_csv_target_dir')
                    app.handles.hwinfo_csv_target_dir.Value = char(string(runtime_cfg.hwinfo_csv_target_dir));
                end
                if isfield(runtime_cfg, 'collector_launch_csv_file')
                    app.handles.hwinfo_csv_target_path.Value = char(string(runtime_cfg.collector_launch_csv_file));
                elseif isfield(runtime_cfg, 'hwinfo_csv_target_path')
                    app.handles.hwinfo_csv_target_path.Value = char(string(runtime_cfg.hwinfo_csv_target_path));
                end
            end
            if isfield(cfg, 'defaults_source') && isstruct(cfg.defaults_source)
                app.config.defaults_source = cfg.defaults_source;
            end
            if app.has_valid_handle('defaults_source_info')
                defaults_summary = sprintf(app.layout_cfg.ui_text.config.readiness.defaults_summary_template, ...
                    app.layout_cfg.defaults_source.editable_parameters, ...
                    app.layout_cfg.defaults_source.editable_settings);
                if isfield(app.config, 'defaults_source') && isstruct(app.config.defaults_source) && ...
                        isfield(app.config.defaults_source, 'summary')
                    defaults_summary = char(string(app.config.defaults_source.summary));
                end
                app.handles.defaults_source_info.Text = sprintf( ...
                    app.layout_cfg.ui_text.config.readiness.legend_template, defaults_summary);
            end

            app.on_method_changed();
            if isfield(cfg, 'time_integrator') && app.has_valid_handle('time_integrator')
                requested_integrator = char(string(cfg.time_integrator));
                if any(strcmp(requested_integrator, app.handles.time_integrator.Items))
                    app.handles.time_integrator.Value = requested_integrator;
                end
            end
            app.on_mode_changed();
            app.on_ic_changed();
            app.on_grid_mode_changed();
            app.audit_math_rendering('post-import');
            app.update_checklist();
            app.append_to_terminal(sprintf('Configuration imported from: %s', file), 'success');
        end

        function save_terminal_log(app)
            A = app.layout_cfg.ui_text.alerts;
            if isempty(app.terminal_log)
                uialert(app.fig, A.empty_log_body, A.empty_log_title, 'icon', 'warning');
                return;
            end
            
            timestamp = char(datetime('now', 'Format', 'yyyyMMdd_HHmmss'));
            [file, path] = uiputfile('*.log', A.save_terminal_log_dialog_title, sprintf('sim_log_%s.log', timestamp));
            if isequal(file, 0)
                return;
            end
            
            filepath = fullfile(path, file);
            fid = fopen(filepath, 'w');
            for i = 1:length(app.terminal_log)
                fprintf(fid, '%s\n', app.terminal_log{i});
            end
            fclose(fid);
            
            app.append_to_terminal(sprintf('ÃƒÂ¢Ã…â€œÃ¢â‚¬Å“ Terminal log saved (%d lines) to: %s', length(app.terminal_log), file));
        end
        
        function save_current_figure(app)
            A = app.layout_cfg.ui_text.alerts;
            if isempty(app.session_figures)
                uialert(app.fig, A.no_figures_body, A.no_figures_title, 'icon', 'warning');
                return;
            end

            [file, path] = uiputfile({'*.fig', 'MATLAB Figure (*.fig)'}, A.save_figure_dialog_title, 'result_plot.fig');
            if isequal(file, 0)
                return;
            end

            try
                [current_idx, entry] = app.get_selected_session_result();
                if isempty(current_idx)
                    uialert(app.fig, A.no_figures_body, A.no_figures_title, 'icon', 'warning');
                    return;
                end

                output_path = fullfile(path, file);
                app.export_result_tab(entry.tab_handle, output_path);
                app.append_to_terminal(sprintf('Saved result to: %s', output_path), 'success');
            catch ME
                app.append_to_terminal(sprintf('Error saving result: %s', ME.message), 'error');
            end
        end

        function export_all_figures(app)
            A = app.layout_cfg.ui_text.alerts;
            if isempty(app.session_figures)
                uialert(app.fig, A.no_figures_export_body, A.no_figures_title, 'icon', 'warning');
                return;
            end

            path = uigetdir(pwd, A.export_directory_dialog_title);
            if isequal(path, 0)
                return;
            end

            try
                for i = 1:numel(app.session_figures)
                    entry = app.session_figures(i);
                    base_name = sprintf('%03d_%s', i, app.sanitize_filename(entry.name));
                    fig_path = fullfile(path, [base_name, '.fig']);
                    app.export_result_tab(entry.tab_handle, fig_path);
                end
                app.append_to_terminal(sprintf('Exported %d results to: %s', numel(app.session_figures), path), 'success');
            catch ME
                app.append_to_terminal(sprintf('Error exporting results: %s', ME.message), 'error');
            end
        end

        function import_result_bundle(app)
            [file, path] = uigetfile('*.mat', 'Import Result Bundle');
            if isequal(file, 0)
                return;
            end

            try
                payload = load(fullfile(path, file));
                summary = app.build_summary_from_import_payload(payload, file);
                if isempty(summary)
                    uialert(app.fig, 'Selected MAT file does not contain importable analysis data.', ...
                        'Import Failed', 'Icon', 'warning');
                    return;
                end
                app.register_simulation_result(summary);
                app.append_to_terminal(sprintf('Imported result bundle: %s', file), 'success');
            catch ME
                app.append_to_terminal(sprintf('Import failed: %s', ME.message), 'error');
            end
        end

        function summary = build_summary_from_import_payload(app, payload, fallback_name)
            summary = [];
            analysis = struct();
            params = struct();
            run_cfg = struct();
            meta = struct();
            monitor_series = struct();
            artifacts = struct();
            workflow_results = struct();

            if isfield(payload, 'entry_to_save') && isstruct(payload.entry_to_save)
                entry = payload.entry_to_save;
                if isfield(entry, 'analysis') && isstruct(entry.analysis), analysis = entry.analysis; end
                if isfield(entry, 'parameters') && isstruct(entry.parameters), params = entry.parameters; end
                if isfield(entry, 'run_config') && isstruct(entry.run_config), run_cfg = entry.run_config; end
                if isfield(entry, 'metadata') && isstruct(entry.metadata), meta = entry.metadata; end
                if isfield(entry, 'monitor_series') && isstruct(entry.monitor_series), monitor_series = entry.monitor_series; end
                if isfield(entry, 'artifacts') && isstruct(entry.artifacts), artifacts = entry.artifacts; end
                if isfield(entry, 'name') && strlength(string(entry.name)) > 0
                    fallback_name = char(string(entry.name));
                end
            end

            if isempty(fieldnames(analysis)) && isfield(payload, 'analysis') && isstruct(payload.analysis)
                analysis = payload.analysis;
            end
            if isempty(fieldnames(params)) && isfield(payload, 'parameters') && isstruct(payload.parameters)
                params = payload.parameters;
            end
            if isempty(fieldnames(run_cfg)) && isfield(payload, 'run_config') && isstruct(payload.run_config)
                run_cfg = payload.run_config;
            end
            if isempty(fieldnames(meta)) && isfield(payload, 'metadata') && isstruct(payload.metadata)
                meta = payload.metadata;
            end

            if isfield(payload, 'ResultsForSave') && isstruct(payload.ResultsForSave) && ...
                    isfield(payload.ResultsForSave, 'workflow_kind') && ...
                    strcmpi(char(string(payload.ResultsForSave.workflow_kind)), 'mesh_convergence_study')
