                    strcmpi(char(string(payload.ResultsForSave.workflow_kind)), 'phase2_boundary_condition_study')
                workflow_results = payload.ResultsForSave;
                workflow_results.result_layout_kind = 'phase2_workflow';
            elseif isfield(payload, 'ResultsForSave') && isstruct(payload.ResultsForSave) && ...
                    isfield(payload.ResultsForSave, 'workflow_kind') && ...
                    strcmpi(char(string(payload.ResultsForSave.workflow_kind)), 'phase3_bathymetry_study')
                workflow_results = payload.ResultsForSave;
                workflow_results.result_layout_kind = 'phase3_workflow';
            elseif isfield(payload, 'workflow_manifest') && isstruct(payload.workflow_manifest) && ...
                    isfield(payload.workflow_manifest, 'workflow_kind') && ...
