                    'workflow_kind', 'mesh_convergence_study', ...
                    'result_layout_kind', 'mesh_convergence_workflow', ...
                    'phase_id', app.pick_field(payload.workflow_manifest, {'phase_id'}, ''), ...
                    'run_id', app.pick_field(payload.workflow_manifest, {'phase_id'}, ''), ...
                    'phase_config', app.pick_field(payload.workflow_manifest, {'phase_config'}, struct()), ...
                    'parent_parameters', app.pick_field(payload.workflow_manifest, {'parent_parameters'}, struct()), ...
                    'parent_run_config', app.pick_field(payload.workflow_manifest, {'parent_run_config'}, struct()), ...
                    'children', app.pick_field(payload.workflow_manifest, {'children'}, struct()), ...
                    'combined', app.pick_field(payload.workflow_manifest, {'combined'}, struct()), ...
                    'workflow_queue', app.pick_field(payload.workflow_manifest, {'queue'}, struct([])), ...
                    'workflow_manifest', payload.workflow_manifest, ...
                    'paths', app.pick_field(payload.workflow_manifest, {'paths'}, struct()));
                workflow_children = app.pick_field(workflow_results, {'children'}, struct());
                workflow_results.metrics = struct( ...
                    'FD', app.pick_field(app.pick_field(workflow_children, {'fd'}, struct()), {'metrics'}, struct()), ...
                    'Spectral', app.pick_field(app.pick_field(workflow_children, {'spectral'}, struct()), {'metrics'}, struct()), ...
                    'summary', app.pick_field(payload.workflow_manifest, {'metrics_summary'}, struct()));
            elseif isfield(payload, 'workflow_manifest') && isstruct(payload.workflow_manifest) && ...
                    isfield(payload.workflow_manifest, 'workflow_kind') && ...
                    strcmpi(char(string(payload.workflow_manifest.workflow_kind)), 'phase1_periodic_comparison')
                workflow_results = struct( ...
                    'workflow_kind', 'phase1_periodic_comparison', ...
                    'result_layout_kind', 'phase1_workflow', ...
                    'phase_id', app.pick_field(payload.workflow_manifest, {'phase_id'}, ''), ...
                    'run_id', app.pick_field(payload.workflow_manifest, {'phase_id'}, ''), ...
                    'phase_config', app.pick_field(payload.workflow_manifest, {'phase_config'}, struct()), ...
                    'parent_parameters', app.pick_field(payload.workflow_manifest, {'parent_parameters'}, struct()), ...
                    'parent_run_config', app.pick_field(payload.workflow_manifest, {'parent_run_config'}, struct()), ...
                    'children', app.pick_field(payload.workflow_manifest, {'children'}, struct()), ...
                    'combined', app.pick_field(payload.workflow_manifest, {'combined'}, struct()), ...
                    'workflow_queue', app.pick_field(payload.workflow_manifest, {'queue'}, struct([])), ...
                    'workflow_manifest', payload.workflow_manifest, ...
                    'paths', app.pick_field(payload.workflow_manifest, {'paths'}, struct()));
                workflow_children = app.pick_field(workflow_results, {'children'}, struct());
                workflow_results.metrics = struct( ...
                    'FD', app.pick_field(app.pick_field(workflow_children, {'fd'}, struct()), {'metrics'}, struct()), ...
                    'Spectral', app.pick_field(app.pick_field(workflow_children, {'spectral'}, struct()), {'metrics'}, struct()), ...
                    'summary', app.pick_field(payload.workflow_manifest, {'metrics_summary'}, struct()));
            elseif isfield(payload, 'workflow_manifest') && isstruct(payload.workflow_manifest) && ...
                    isfield(payload.workflow_manifest, 'workflow_kind') && ...
                    strcmpi(char(string(payload.workflow_manifest.workflow_kind)), 'phase2_boundary_condition_study')
                workflow_results = struct( ...
                    'workflow_kind', 'phase2_boundary_condition_study', ...
                    'result_layout_kind', 'phase2_workflow', ...
                    'phase_id', app.pick_field(payload.workflow_manifest, {'phase_id'}, ''), ...
                    'run_id', app.pick_field(payload.workflow_manifest, {'phase_id'}, ''), ...
                    'phase_config', app.pick_field(payload.workflow_manifest, {'phase_config'}, struct()), ...
                    'parent_parameters', app.pick_field(payload.workflow_manifest, {'parent_parameters'}, struct()), ...
                    'parent_run_config', app.pick_field(payload.workflow_manifest, {'parent_run_config'}, struct()), ...
                    'scenarios', app.pick_field(payload.workflow_manifest, {'scenarios'}, struct([])), ...
                    'workflow_queue', app.pick_field(payload.workflow_manifest, {'queue'}, struct([])), ...
                    'workflow_manifest', payload.workflow_manifest, ...
                    'paths', app.pick_field(payload.workflow_manifest, {'paths'}, struct()));
            elseif isfield(payload, 'workflow_manifest') && isstruct(payload.workflow_manifest) && ...
                    isfield(payload.workflow_manifest, 'workflow_kind') && ...
                    strcmpi(char(string(payload.workflow_manifest.workflow_kind)), 'phase3_bathymetry_study')
                workflow_results = struct( ...
                    'workflow_kind', 'phase3_bathymetry_study', ...
                    'result_layout_kind', 'phase3_workflow', ...
                    'phase_id', app.pick_field(payload.workflow_manifest, {'phase_id'}, ''), ...
                    'run_id', app.pick_field(payload.workflow_manifest, {'phase_id'}, ''), ...
                    'phase_config', app.pick_field(payload.workflow_manifest, {'phase_config'}, struct()), ...
                    'parent_parameters', app.pick_field(payload.workflow_manifest, {'parent_parameters'}, struct()), ...
                    'parent_run_config', app.pick_field(payload.workflow_manifest, {'parent_run_config'}, struct()), ...
                    'scenarios', app.pick_field(payload.workflow_manifest, {'scenarios'}, struct([])), ...
                    'workflow_queue', app.pick_field(payload.workflow_manifest, {'queue'}, struct([])), ...
                    'workflow_manifest', payload.workflow_manifest, ...
                    'paths', app.pick_field(payload.workflow_manifest, {'paths'}, struct()));
            end

            if ~isempty(fieldnames(workflow_results))
                if isempty(fieldnames(params))
                    params = app.pick_field(workflow_results, {'parent_parameters'}, struct());
                end
                if isempty(fieldnames(run_cfg))
                    run_cfg = app.pick_field(workflow_results, {'parent_run_config'}, struct());
                end
                workflow_kind = char(string(app.pick_field(workflow_results, {'workflow_kind'}, 'phase1_periodic_comparison')));
                if ~isfield(run_cfg, 'workflow_kind') || isempty(run_cfg.workflow_kind)
                    run_cfg.workflow_kind = workflow_kind;
                end
                if strcmpi(workflow_kind, 'mesh_convergence_study')
                    run_cfg.result_layout_kind = 'mesh_convergence_workflow';
                elseif strcmpi(workflow_kind, 'phase2_boundary_condition_study')
                    run_cfg.result_layout_kind = 'phase2_workflow';
                elseif strcmpi(workflow_kind, 'phase3_bathymetry_study')
                    run_cfg.result_layout_kind = 'phase3_workflow';
                else
                    run_cfg.result_layout_kind = 'phase1_workflow';
                end
                run_cfg.launch_origin = 'phase_button';
                if isempty(fieldnames(meta))
                    meta = struct();
                end
                if strcmpi(workflow_kind, 'mesh_convergence_study')
                    meta.method = 'Mesh Convergence';
                elseif strcmpi(workflow_kind, 'phase2_boundary_condition_study')
                    meta.method = 'Phase 2';
                elseif strcmpi(workflow_kind, 'phase3_bathymetry_study')
