                    elseif strcmpi(workflow_kind, 'phase2_boundary_condition_study')
                        name_only = sprintf('%s | Phase 2', meta.run_id);
                    elseif strcmpi(workflow_kind, 'phase3_bathymetry_study')
                        name_only = sprintf('%s | Phase 3', meta.run_id);
