                    'results', workflow_results, ...
                    'parameters', params, ...
                    'run_config', run_cfg, ...
                    'imported_metadata', meta, ...
                    'imported_monitor_series', monitor_series, ...
                    'imported_artifacts', artifacts, ...
                    'imported_name', name_only, ...
                    'workflow_kind', workflow_kind, ...
                    'result_layout_kind', char(string(run_cfg.result_layout_kind)));
                return;
            end

            if isempty(fieldnames(analysis))
                return;
            end

            if isempty(fieldnames(params))
                params = create_default_parameters();
            end

            if isempty(fieldnames(run_cfg))
                method_token = 'FD';
                if isfield(params, 'method')
                    method_token = app.get_dispatch_method(params.method);
                end
                mode_token = 'Evolution';
                ic_token = 'stretched_gaussian';
                if isfield(params, 'ic_type')
                    ic_token = char(string(params.ic_type));
                end
                run_cfg = Build_Run_Config(method_token, mode_token, ic_token);
            end

            [name_only, ~] = fileparts(char(string(fallback_name)));
            if isempty(name_only)
                name_only = 'Imported Result';
            end

            results = struct();
            if isfield(analysis, 'omega_snaps')
                results.omega_snaps = analysis.omega_snaps;
            end
            if isfield(analysis, 'peak_vorticity')
                results.max_omega = analysis.peak_vorticity;
            end

            summary = struct( ...
                'results', results, ...
                'parameters', params, ...
                'run_config', run_cfg, ...
                'imported_analysis', analysis, ...
                'imported_metadata', meta, ...
                'imported_monitor_series', monitor_series, ...
                'imported_artifacts', artifacts, ...
                'imported_name', name_only);
        end

        function [idx, entry] = get_selected_session_result(app)
            idx = [];
            entry = struct();
            if isempty(app.session_figures)
                return;
            end

            idx = find(strcmp(app.handles.figure_selector.Items, app.handles.figure_selector.Value), 1);
            if isempty(idx) || idx < 1 || idx > numel(app.session_figures)
                idx = numel(app.session_figures);
            end
            entry = app.session_figures(idx);
        end

        function export_result_tab(~, tab_handle, output_path)
            if isempty(tab_handle) || ~isvalid(tab_handle)
                error('Result tab handle is not available for export.');
            end

            [~, ~, ext] = fileparts(char(string(output_path)));
            if strcmpi(ext, '.fig')
                temp_png = [tempname, '.png'];
                cleanup_png = onCleanup(@() UIController.safe_delete_file(temp_png)); %#ok<NASGU>
                try
                    exportgraphics(tab_handle, temp_png, 'Resolution', 300);
                catch
                    axes_handles = findall(tab_handle, 'Type', 'axes');
                    if isempty(axes_handles)
                        all_children = findall(tab_handle);
                        is_ui_axes = arrayfun(@(h) isa(h, 'matlab.ui.control.UIAxes'), all_children);
                        axes_handles = all_children(is_ui_axes);
                    end
                    if isempty(axes_handles)
                        error('No axes found in the selected result tab.');
                    end
                    exportgraphics(axes_handles(1), temp_png, 'Resolution', 300);
                end
                img = imread(temp_png);
                export_fig = figure('Visible', 'off', 'Color', [1 1 1]);
                cleanup_fig = onCleanup(@() UIController.safe_close_figure(export_fig)); %#ok<NASGU>
                ax = axes(export_fig); %#ok<LAXES>
                image(ax, img);
                axis(ax, 'image');
                axis(ax, 'off');
                savefig(export_fig, output_path);
                return;
            end

            try
                exportgraphics(tab_handle, output_path, 'Resolution', 300);
                return;
            catch
                % Fallback to first axes in tab for releases that cannot export tabs directly.
            end

            axes_handles = findall(tab_handle, 'Type', 'axes');
            if isempty(axes_handles)
                all_children = findall(tab_handle);
                is_ui_axes = arrayfun(@(h) isa(h, 'matlab.ui.control.UIAxes'), all_children);
                axes_handles = all_children(is_ui_axes);
            end
            if isempty(axes_handles)
                error('No axes found in the selected result tab.');
            end
            exportgraphics(axes_handles(1), output_path, 'Resolution', 300);
        end

        function out_name = sanitize_filename(~, in_name)
            out_name = char(string(in_name));
            out_name = regexprep(out_name, '[^\w\-\.]+', '_');
            out_name = regexprep(out_name, '_+', '_');
            out_name = strtrim(out_name);
            if isempty(out_name)
                out_name = 'result';
            end
        end

        function append_to_terminal(app, message, msg_type)
            % Append colored message to terminal with timestamp
            % Args:
            %   message: String to display
            %   msg_type: 'success', 'warning', 'error', 'info', 'debug' (optional)
            %             If omitted, auto-detects from message content
            %
            % Terminal flow:
            %   UI callbacks push explicit lines through this method.
            %   Diary-captured command window lines are merged by update_terminal_from_diary().
            %   Both streams render in the monitoring tab terminal panel.
            
            if nargin < 3
                % Auto-detect message type from content
                if contains(message, {'ÃƒÂ¢Ã…â€œÃ¢â‚¬Å“', 'Success', 'Updated', 'Complete'}, 'IgnoreCase', true)
                    msg_type = 'success';
                elseif contains(message, {'ÃƒÂ¢Ã…â€œÃ¢â‚¬â€', 'Error', 'Failed', 'Exception'}, 'IgnoreCase', true)
                    msg_type = 'error';
                elseif contains(message, {'Warning', 'Caution'}, 'IgnoreCase', true)
                    msg_type = 'warning';
                else
                    msg_type = 'info';
                end
            end
            
            % Format message with timestamp
            timestamp = char(datetime('now', 'Format', 'HH:mm:ss'));
            formatted_msg = app.sanitize_terminal_text(sprintf('[%s] %s', timestamp, message));
            
            app.terminal_log{end+1} = formatted_msg;
            app.terminal_type_log{end+1} = lower(string(msg_type));
            
            % Keep only last 500 lines for responsiveness
            if numel(app.terminal_log) > 500
                app.terminal_log = app.terminal_log(end-499:end);
                app.terminal_type_log = app.terminal_type_log(end-499:end);
            end

            app.refresh_terminal_output();
        end

        function start_terminal_capture(app)
            % Capture MATLAB command window output in the UI terminal panel.
            % Data path:
            %   MATLAB diary file -> update_terminal_from_diary() timer -> app.terminal_log
            %   -> terminal_display_lines() -> terminal text area in monitoring sidebar.
            try
                app.diary_file = fullfile(tempdir, 'ui_controller_terminal.log');
                app.diary_last_size = 0;
                diary off;
                diary(app.diary_file);
                diary on;

                app.safe_stop_timer('diary_timer');

                app.diary_timer = timer('ExecutionMode', 'fixedSpacing', ...
                    'Period', 1.0, ...
                    'TimerFcn', {@ui_controller_timer_update_terminal_from_diary, app});
                start(app.diary_timer);
            catch ME
                % If diary capture fails, fall back to manual logs only.
                UIController.warn_once('UIController:DiaryCaptureInitFailed', ...
                    'Diary capture initialization failed; terminal falls back to manual logs: %s', ME.message);
            end
        end

        function update_terminal_from_diary(app)
            % Refresh terminal panel from MATLAB diary file.
            % Only reads NEW bytes since last check to avoid duplicated output.
            if isempty(app.diary_file) || ~isfile(app.diary_file)
                return;
            end
            if ~app.has_valid_handle('terminal_output')
                return;
            end

            file_info = dir(app.diary_file);
            if isempty(file_info)
                return;
            end
            current_size = file_info.bytes;
            if current_size <= app.diary_last_size
                return;
            end

            try
                % Read only the new bytes appended since last read
                fid = fopen(app.diary_file, 'r');
                if fid < 0, return; end
                fseek(fid, app.diary_last_size, 'bof');
                new_text = fread(fid, current_size - app.diary_last_size, '*char')';
                fclose(fid);
                app.diary_last_size = current_size;

                new_lines = splitlines(string(new_text));
                new_lines = new_lines(strlength(strtrim(new_lines)) > 0);
                if isempty(new_lines)
                    return;
                end

                for i = 1:numel(new_lines)
                    line_str = strtrim(new_lines(i));
                    if app.should_filter_terminal_diary_line(line_str)
                        continue;
                    end
                    app.terminal_log{end+1} = app.sanitize_terminal_text(new_lines(i));
                    app.terminal_type_log{end+1} = 'debug';
                end
                if numel(app.terminal_log) > 500
                    app.terminal_log = app.terminal_log(end-499:end);
                    app.terminal_type_log = app.terminal_type_log(end-499:end);
                end

                app.refresh_terminal_output();
            catch ME
                UIController.warn_once('UIController:DiaryRefreshFailed', ...
                    'Diary refresh failed; terminal updates may be stale: %s', ME.message);
            end
        end

        function tf = should_filter_terminal_diary_line(~, line_text)
            tf = false;
            if strlength(string(strtrim(line_text))) == 0
                tf = true;
                return;
            end
            line_text = char(string(strtrim(line_text)));
            noise_patterns = {'useCS', 'ans =', 'logical', 'HandleVisibility'};
            for np = 1:numel(noise_patterns)
                if contains(line_text, noise_patterns{np})
                    tf = true;
                    return;
                end
            end
            if ~isempty(regexp(line_text, '^(true|false|0|1)$', 'once'))
                tf = true;
                return;
            end
            if ~isempty(regexp(line_text, '^[-+]?(?:\d+\.?\d*|\.\d+)(?:[eEdD][-+]?\d+)?$', 'once'))
                tf = true;
                return;
            end
            if ~isempty(regexp(line_text, '^\[[A-Z]+\]\s+\d+(\.\d+)?%\s+\|\s+step\s+\d+/\d+\s+\|', 'once'))
                tf = true;
            end
        end
        
        function capture_run_figures(app, figs_before, summary)
            % Capture any figures created during a simulation run and add
            % them to the results tab, then close the hidden originals.
            % Also imports saved PNG files from disk when figures were
            % already closed by the mode (saveas + close pattern).
            n_captured = 0;
            try
                figs_after = findall(0, 'Type', 'figure');
                % Filter to only new figures (not present before run, not our UI)
                new_figs = setdiff(figs_after, figs_before);
                if ~isempty(app.fig) && isvalid(app.fig)
                    new_figs(new_figs == app.fig) = [];
                end
                % Remove uifigures (inspector, dialogs) - keep only standard figures
                keep = false(size(new_figs));
                for fi = 1:numel(new_figs)
                    if isvalid(new_figs(fi)) && ~isa(new_figs(fi), 'matlab.ui.Figure')
                        keep(fi) = true;
                    end
                end
                new_figs = new_figs(keep);

                for fi = 1:numel(new_figs)
                    if isvalid(new_figs(fi))
                        fig_name = get(new_figs(fi), 'Name');
                        if isempty(fig_name)
                            fig_name = sprintf('Figure %d', fi);
                        end
                        app.add_figure(new_figs(fi), fig_name);
                        n_captured = n_captured + 1;
                    end
                end
                % Close captured figures after frame capture
                for fi = 1:numel(new_figs)
                    if isvalid(new_figs(fi))
                        close(new_figs(fi));
                    end
                end
            catch ME
                app.append_to_terminal(sprintf('Figure capture warning: %s', ME.message), 'warning');
            end

            % Import saved figure files from disk (handles close-after-save pattern)
            if nargin >= 3 && isstruct(summary) && isfield(summary, 'paths') && isstruct(summary.paths)
                n_captured = n_captured + app.import_saved_figures_from_paths(summary.paths);
            end

            if n_captured > 0
                app.append_to_terminal(sprintf('Captured %d figures to Results tab', n_captured), 'info');
            end
        end

        function n_imported = import_saved_figures_from_paths(app, paths)
            % Scan run output directories for saved PNG/FIG files and import
            % them into the Results tab figures list.
            n_imported = 0;
            try
                % Collect all figure directories from the paths struct
                fig_dirs = {};
                path_fields = fieldnames(paths);
                for fi = 1:numel(path_fields)
                    fname = path_fields{fi};
                    if startsWith(fname, 'figures') && ischar(paths.(fname)) && isfolder(paths.(fname))
                        fig_dirs{end+1} = paths.(fname); %#ok<AGROW>
                    end
                end
                % Also check common subfolders
                if isfield(paths, 'base') && isfolder(paths.base)
                    sub = fullfile(paths.base, 'Figures');
                    if isfolder(sub)
                        fig_dirs{end+1} = sub;
                    end
                end

                % De-duplicate and scan for image files
                fig_dirs = unique(fig_dirs, 'stable');
                for di = 1:numel(fig_dirs)
                    png_files = [dir(fullfile(fig_dirs{di}, '*.png')); ...
                                 dir(fullfile(fig_dirs{di}, '*.fig'))];
                    for pi = 1:numel(png_files)
                        img_path = fullfile(png_files(pi).folder, png_files(pi).name);
                        % Skip if already imported (name match)
                        already = false;
                        for ei = 1:numel(app.figures_list)
                            if strcmp(app.figures_list{ei}.name, png_files(pi).name)
                                already = true;
                                break;
                            end
                        end
                        if already, continue; end

                        try
                            img_data = imread(img_path);
                            frame = struct('cdata', img_data, 'colormap', []);
                            fig_data = struct('frame', frame, 'name', png_files(pi).name, 'handle', gobjects(0));
                            app.figures_list{end+1} = fig_data;
                            n_imported = n_imported + 1;
                        catch ME
                            UIController.warn_once('UIController:UnreadableSavedFigure', ...
                                'Skipping unreadable saved figure during import: %s', ME.message);
                        end
                    end
                end

                % Refresh dropdown if we imported anything
                if n_imported > 0
                    fig_names = cell(1, numel(app.figures_list));
                    for i = 1:numel(app.figures_list)
                        if ~isempty(app.figures_list{i}.name)
                            fig_names{i} = app.figures_list{i}.name;
                        else
                            fig_names{i} = sprintf('Figure %d', i);
                        end
                    end
                    app.handles.figure_selector.Items = fig_names;
                    app.handles.figure_selector.Value = fig_names{end};
                    app.show_figure(numel(app.figures_list));
                end
            catch ME
                app.append_to_terminal(sprintf('Disk figure import warning: %s', ME.message), 'warning');
            end
        end

        function add_figure(app, fig, name)
            % Add figure to figures list (legacy screenshot mode for compatibility)
            if nargin < 3
                name = sprintf('Figure %d', length(app.figures_list) + 1);
            end
            try
                was_visible = strcmp(get(fig, 'Visible'), 'on');
                if ~was_visible
                    set(fig, 'Visible', 'on');
                    drawnow;
                end
                frame = getframe(fig);
                if ~was_visible
                    set(fig, 'Visible', 'off');
                end
                fig_data = struct('frame', frame, 'name', name, 'handle', fig);
                app.figures_list{end+1} = fig_data;
            catch ME
                fig_data = struct('frame', [], 'name', name, 'handle', fig);
                app.figures_list{end+1} = fig_data;
                app.append_to_terminal(sprintf('Warning: Could not capture frame for %s: %s', name, ME.message), 'warning');
            end
        end

        function [entry, meta, analysis, results, params, run_cfg, artifacts, monitor_series_entry, fig_name] = build_result_entry_from_summary(app, summary, idx)
            if nargin < 3 || ~isfinite(idx) || idx < 1
                idx = numel(app.session_figures) + 1;
            end

            results = struct();
            if isfield(summary, 'results') && isstruct(summary.results)
                results = summary.results;
            end

            params = struct();
            if isfield(summary, 'parameters') && isstruct(summary.parameters)
                params = summary.parameters;
            elseif isstruct(app.config)
                params = app.config;
            end

            run_cfg = struct();
            if isfield(summary, 'run_config') && isstruct(summary.run_config)
                run_cfg = summary.run_config;
            else
                run_cfg.method = app.get_dispatch_method(app.config.method);
                run_cfg.mode = app.config.run_mode_internal;
                run_cfg.ic_type = app.config.ic_type;
            end

            imported_name = app.to_text(app.pick_field(summary, {'imported_name'}, ''), '');
            if ~isempty(strtrim(imported_name))
                fig_name = imported_name;
            else
                fig_name = app.build_result_figure_name(run_cfg, params);
            end

            analysis = struct();
            if isfield(summary, 'imported_analysis') && isstruct(summary.imported_analysis)
                analysis = summary.imported_analysis;
            elseif isfield(summary, 'analysis') && isstruct(summary.analysis)
                analysis = summary.analysis;
            elseif isfield(results, 'analysis') && isstruct(results.analysis)
                analysis = results.analysis;
            elseif isfield(results, 'data_path') && exist(results.data_path, 'file')
                try
                    loaded = load(results.data_path, 'analysis');
                    analysis = loaded.analysis;
                catch ME
                    UIController.warn_once('UIController:AnalysisLoadFailed', ...
                        'Failed to load analysis from results data path: %s', ME.message);
                end
            end
            if ~isfield(analysis, 'omega_snaps') && ~isfield(analysis, 'time_vec')
                fallback_fields = {'omega_snaps', 'time_vec', 'snapshot_times', ...
                    'kinetic_energy', 'enstrophy', 'max_omega_history', 'peak_vorticity'};
                for k = 1:numel(fallback_fields)
                    key = fallback_fields{k};
                    if isfield(results, key)
                        analysis.(key) = results.(key);
                    end
                end
            end

            meta = struct();
            if isfield(summary, 'imported_metadata') && isstruct(summary.imported_metadata)
                meta = summary.imported_metadata;
            end
            if ~isfield(meta, 'method'), meta.method = ''; end
            if ~isfield(meta, 'mode'), meta.mode = ''; end
            if ~isfield(meta, 'ic_type'), meta.ic_type = ''; end
            if ~isfield(meta, 'bc_case'), meta.bc_case = ''; end
            if ~isfield(meta, 'run_id'), meta.run_id = ''; end
            if ~isfield(meta, 'launch_origin'), meta.launch_origin = ''; end
            if ~isfield(meta, 'timestamp') || isempty(meta.timestamp)
                meta.timestamp = char(datetime('now', 'Format', 'yyyy-MM-dd HH:mm:ss'));
            end
            if isfield(run_cfg, 'method'), meta.method = app.to_text(run_cfg.method, ''); end
            if isfield(run_cfg, 'mode'), meta.mode = app.to_text(run_cfg.mode, ''); end
            if isfield(run_cfg, 'ic_type'), meta.ic_type = app.to_text(run_cfg.ic_type, ''); end
            if isfield(run_cfg, 'launch_origin'), meta.launch_origin = app.to_text(run_cfg.launch_origin, ''); end
            if isfield(params, 'boundary_condition_case')
                meta.bc_case = app.to_text(params.boundary_condition_case, '');
            end
            if isempty(strtrim(app.to_text(meta.run_id, '')))
                if isfield(results, 'run_id')
                    meta.run_id = app.to_text(results.run_id, '');
                elseif isfield(run_cfg, 'run_id')
                    meta.run_id = app.to_text(run_cfg.run_id, '');
                end
            end
            if isfield(results, 'wall_time'), meta.wall_time = results.wall_time; end
            if isfield(results, 'max_omega'), meta.max_omega = results.max_omega; end
            if isfield(results, 'final_energy'), meta.final_energy = results.final_energy; end
            if isfield(results, 'final_enstrophy'), meta.final_enstrophy = results.final_enstrophy; end
            if isfield(results, 'total_steps'), meta.total_steps = results.total_steps; end

            run_color = app.result_run_color(idx);
            run_badge = app.result_run_badge(idx, meta);
            meta.run_color = run_color;
            meta.run_badge = run_badge;

            artifacts = struct();
            artifacts.is_imported = isfield(summary, 'imported_analysis') || ...
                isfield(summary, 'imported_metadata') || isfield(summary, 'imported_artifacts');
            if isfield(summary, 'paths') && isstruct(summary.paths)
                artifacts.paths = summary.paths;
            end
            if isfield(summary, 'collector_artifacts') && isstruct(summary.collector_artifacts)
                artifacts.collector_artifacts = summary.collector_artifacts;
            end
            if isfield(summary, 'imported_artifacts') && isstruct(summary.imported_artifacts)
                imported_fields = fieldnames(summary.imported_artifacts);
                for fi = 1:numel(imported_fields)
                    artifacts.(imported_fields{fi}) = summary.imported_artifacts.(imported_fields{fi});
                end
            end
            monitor_series_entry = app.collect_live_monitor_series_for_summary(summary);
            if isfield(summary, 'imported_monitor_series') && isstruct(summary.imported_monitor_series) && ...
                    ~isempty(fieldnames(summary.imported_monitor_series))
                monitor_series_entry = summary.imported_monitor_series;
            end
            monitor_cfg = app.normalize_monitor_cfg(params);
            monitor_series_entry = app.resolve_monitor_series( ...
                struct('results', results, 'monitor_series', monitor_series_entry), monitor_cfg);

            hydration_state = 'shell';
            if isstruct(analysis) && ~isempty(fieldnames(analysis))
                hydration_state = 'hydrated';
            end

            entry = struct('name', fig_name, 'analysis', analysis, ...
                'results', results, 'parameters', params, 'run_config', run_cfg, ...
                'metadata', meta, 'tab_handle', [], ...
                'run_color', run_color, 'run_badge', run_badge, ...
                'plot_tabs', struct(), ...
                'monitor_series', monitor_series_entry, ...
                'artifacts', artifacts, ...
                'workflow', struct(), ...
                'workflow_kind', '', ...
                'launch_origin', char(string(app.pick_field(run_cfg, {'launch_origin'}, ''))), ...
                'result_layout_kind', char(string(app.resolve_result_layout_kind(summary, results, run_cfg))), ...
                'publication_key', char(string(app.resolve_completion_publication_key(summary))), ...
                'publication_state', 'published', ...
                'hydration_state', hydration_state, ...
                'post_publication_state', 'pending');
        end

        function merged = merge_result_entry_artifacts(~, existing, incoming)
            if nargin < 2 || ~isstruct(existing)
                existing = struct();
            end
            if nargin < 3 || ~isstruct(incoming)
                incoming = struct();
            end
            merged = existing;
            incoming_fields = fieldnames(incoming);
            for fi = 1:numel(incoming_fields)
                merged.(incoming_fields{fi}) = incoming.(incoming_fields{fi});
            end
        end

        function refresh_registered_result_entry_tab(app, idx)
            if idx < 1 || idx > numel(app.session_figures)
                return;
            end
            entry = app.session_figures(idx);
            tab = app.pick_field(entry, {'tab_handle'}, []);
            if isempty(tab) || ~isvalid(tab)
                return;
            end
            try
                if app.is_mesh_convergence_workflow_summary(struct('run_config', entry.run_config, 'results', entry.results), entry.results, entry.run_config)
                    app.session_figures(idx).plot_tabs = app.plot_mesh_convergence_workflow_on_tab(tab, app.session_figures(idx));
                elseif app.is_phase1_workflow_summary(struct('run_config', entry.run_config, 'results', entry.results), entry.results, entry.run_config)
                    app.session_figures(idx).plot_tabs = app.plot_phase1_workflow_on_tab(tab, app.session_figures(idx));
                elseif app.is_phase2_workflow_summary(struct('run_config', entry.run_config, 'results', entry.results), entry.results, entry.run_config)
                    app.session_figures(idx).plot_tabs = app.plot_phase2_workflow_on_tab(tab, app.session_figures(idx));
                elseif app.is_phase3_workflow_summary(struct('run_config', entry.run_config, 'results', entry.results), entry.results, entry.run_config)
                    app.session_figures(idx).plot_tabs = app.plot_phase2_workflow_on_tab(tab, app.session_figures(idx));
                else
                    app.session_figures(idx).plot_tabs = app.plot_analysis_on_tab( ...
                        tab, entry.analysis, entry.parameters, entry.run_config, entry.metadata, entry.monitor_series);
                end
                app.update_result_entry_status_badge(idx);
            catch ME
                app.append_to_terminal(sprintf('Result hydration warning: %s', ME.message), 'warning');
            end
        end

        function idx = register_simulation_result(app, summary)
            % Register a completed simulation into the session figure registry
            % and plot results directly onto interactive UI tabs.
            idx = 0;
            if ~isstruct(summary)
                return;
            end
            [entry, meta, analysis, results, params, run_cfg, artifacts, monitor_series_entry, fig_name] = ...
                app.build_result_entry_from_summary(summary);
            idx = numel(app.session_figures) + 1;

            if app.is_mesh_convergence_workflow_summary(summary, results, run_cfg)
                idx = app.register_mesh_convergence_workflow_result(summary, results, params, run_cfg, meta, artifacts, monitor_series_entry, fig_name);
                return;
            end
            if app.is_phase1_workflow_summary(summary, results, run_cfg)
                idx = app.register_phase1_workflow_result(summary, results, params, run_cfg, meta, artifacts, monitor_series_entry, fig_name);
                return;
            end
            if app.is_phase2_workflow_summary(summary, results, run_cfg)
                idx = app.register_phase2_workflow_result(summary, results, params, run_cfg, meta, artifacts, monitor_series_entry, fig_name);
                return;
            end
            if app.is_phase3_workflow_summary(summary, results, run_cfg)
                idx = app.register_phase3_workflow_result(summary, results, params, run_cfg, meta, artifacts, monitor_series_entry, fig_name);
                return;
            end
            app.session_figures(idx) = entry;
            try
                launch_artifact = app.persist_collector_launch_csv();
                app.session_figures(idx).artifacts.launch_session = launch_artifact;
                if isfield(app.session_figures(idx).artifacts, 'collector_artifacts') && ...
                        isstruct(app.session_figures(idx).artifacts.collector_artifacts)
                    app.session_figures(idx).artifacts.collector_artifacts.launch_session = launch_artifact;
                end
                if isfield(launch_artifact, 'session_csv_path') && ~isempty(launch_artifact.session_csv_path)
                    app.append_to_terminal(sprintf('Collector launch CSV: %s', ...
                        char(string(launch_artifact.session_csv_path))), 'info');
                end
            catch ME
                app.append_to_terminal(sprintf('Collector launch CSV warning: %s', ME.message), 'warning');
            end

            tab = [];
            try
                tab_title = sprintf('%s %s', entry.run_badge, fig_name);
                tab = uitab(app.handles.figure_tabs, 'Title', tab_title);
                if isprop(tab, 'BackgroundColor')
                    tab.BackgroundColor = 0.82 * app.layout_cfg.colors.bg_dark + 0.18 * entry.run_color;
                end
                app.session_figures(idx).tab_handle = tab;
                app.session_figures(idx).plot_tabs = app.plot_analysis_on_tab( ...
                    tab, analysis, params, run_cfg, meta, monitor_series_entry);
            catch ME
                app.append_to_terminal(sprintf('Tab plot warning: %s', ME.message), 'warning');
            end

            app.finalize_result_registration_ui(idx, tab);
            app.remember_registered_result_entry(idx, entry.publication_key);
            app.update_result_entry_status_badge(idx);
            app.run_or_defer_registered_result_autosave(idx, summary, 'session');

            app.append_to_terminal(sprintf('Registered result: %s', fig_name), 'info');
            if isfield(app.session_figures(idx).artifacts, 'paths') && ...
                    isstruct(app.session_figures(idx).artifacts.paths)
                artifact_paths = app.session_figures(idx).artifacts.paths;
                if isfield(artifact_paths, 'figures_root') && ~isempty(artifact_paths.figures_root)
                    app.append_to_terminal(sprintf('Result view exports rooted at: %s', ...
                        char(string(artifact_paths.figures_root))), 'info');
                elseif isfield(artifact_paths, 'figures_results_tabs') && ~isempty(artifact_paths.figures_results_tabs)
                    app.append_to_terminal(sprintf('Results tab exports (legacy): %s', ...
                        char(string(artifact_paths.figures_results_tabs))), 'info');
                end
            end
        end

        function tf = is_mesh_convergence_workflow_summary(~, summary, results, run_cfg)
            tf = strcmpi(char(string(UIController.resolve_result_layout_kind_static(summary, results, run_cfg))), ...
                'mesh_convergence_workflow');
        end

        function tf = is_phase1_workflow_summary(~, summary, results, run_cfg)
            tf = strcmpi(char(string(UIController.resolve_result_layout_kind_static(summary, results, run_cfg))), ...
                'phase1_workflow');
        end

        function layout_kind = resolve_result_layout_kind(~, summary, results, run_cfg)
            layout_kind = UIController.resolve_result_layout_kind_static(summary, results, run_cfg);
        end

        function idx = register_mesh_convergence_workflow_result(app, summary, results, params, run_cfg, meta, artifacts, monitor_series_entry, fig_name)
            idx = numel(app.session_figures) + 1;
            shell_registration = app.workflow_shell_registration_requested(summary);
            run_color = app.result_run_color(idx);
            phase_id = char(string(app.pick_field(results, {'phase_id', 'run_id'}, 'mesh_convergence')));
            if ~(isfield(summary, 'imported_name') && strlength(string(summary.imported_name)) > 0)
                fig_name = sprintf('%s | Mesh Convergence | FD vs Spectral', phase_id);
            end
            meta.method = 'Mesh Convergence';
            meta.mode = 'Workflow';
            if isempty(strtrim(char(string(app.pick_field(meta, {'run_id'}, '')))))
                meta.run_id = phase_id;
            end
            meta.run_color = run_color;
            if (~isfield(artifacts, 'paths') || ~isstruct(artifacts.paths) || isempty(fieldnames(artifacts.paths))) && ...
                    isfield(results, 'paths') && isstruct(results.paths)
                artifacts.paths = results.paths;
            end
            if ~isfield(monitor_series_entry, 'workflow_kind') || isempty(monitor_series_entry.workflow_kind)
                monitor_series_entry.workflow_kind = 'mesh_convergence_study';
                monitor_series_entry.workflow_phase_id = phase_id;
                monitor_series_entry.workflow_current_job_label = 'Mesh convergence complete';
                monitor_series_entry.workflow_current_status = 'completed';
                monitor_series_entry.workflow_queue = app.pick_field(results, {'workflow_queue'}, struct([]));
            end

            run_badge = app.result_run_badge(idx, meta);
            meta.run_badge = run_badge;
            workflow = app.build_phase1_workflow_model(results);
            entry = struct( ...
                'name', fig_name, ...
                'analysis', struct(), ...
                'results', results, ...
                'parameters', params, ...
                'run_config', run_cfg, ...
                'metadata', meta, ...
                'tab_handle', [], ...
                'run_color', run_color, ...
                'run_badge', run_badge, ...
                'plot_tabs', struct(), ...
                'monitor_series', monitor_series_entry, ...
                'artifacts', artifacts, ...
                'workflow', workflow, ...
                'workflow_kind', 'mesh_convergence_study', ...
                'launch_origin', char(string(app.pick_field(run_cfg, {'launch_origin'}, ''))), ...
                'result_layout_kind', 'mesh_convergence_workflow', ...
                'publication_key', char(string(app.resolve_completion_publication_key(summary))), ...
                'publication_state', 'published', ...
                'hydration_state', 'hydrated', ...
                'post_publication_state', 'pending');
            if shell_registration
                entry.hydration_state = 'shell';
            end
            app.session_figures(idx) = entry;

            tab = [];
            try
                tab_title = sprintf('%s %s', run_badge, fig_name);
                tab = uitab(app.handles.figure_tabs, 'Title', tab_title);
                if isprop(tab, 'BackgroundColor')
                    tab.BackgroundColor = 0.82 * app.layout_cfg.colors.bg_dark + 0.18 * run_color;
                end
                app.session_figures(idx).tab_handle = tab;
                if shell_registration
                    app.session_figures(idx).plot_tabs = app.plot_workflow_result_shell_on_tab(tab, app.session_figures(idx));
                else
                    app.session_figures(idx).plot_tabs = app.plot_mesh_convergence_workflow_on_tab(tab, app.session_figures(idx));
                end
            catch ME
                app.append_to_terminal(sprintf('Mesh convergence tab plot warning: %s', ME.message), 'warning');
            end

            app.finalize_result_registration_ui(idx, tab);
            app.remember_registered_result_entry(idx, entry.publication_key);
            app.update_result_entry_status_badge(idx);
            if shell_registration
                app.enqueue_result_entry_hydration(idx, summary);
            end
            app.run_or_defer_registered_result_autosave(idx, summary, 'workflow');
            app.append_to_terminal(sprintf('Registered result: %s', fig_name), 'info');
        end

        function idx = register_phase1_workflow_result(app, summary, results, params, run_cfg, meta, artifacts, monitor_series_entry, fig_name)
            idx = numel(app.session_figures) + 1;
            shell_registration = app.workflow_shell_registration_requested(summary);
            run_color = app.result_run_color(idx);
            phase_id = char(string(app.pick_field(results, {'phase_id', 'run_id'}, 'phase1')));

            if ~(isfield(summary, 'imported_name') && strlength(string(summary.imported_name)) > 0)
                fig_name = sprintf('%s | Phase 1 | FD vs Spectral', phase_id);
            end

            meta.method = 'Phase 1';
            meta.mode = 'Workflow';
            if isfield(results, 'parent_parameters') && isstruct(results.parent_parameters)
                parent_ic = app.pick_field(results.parent_parameters, {'ic_type'}, '');
                if ~isempty(parent_ic)
                    meta.ic_type = char(string(parent_ic));
                end
                if isempty(fieldnames(params))
                    params = results.parent_parameters;
                end
            end
            if isempty(strtrim(char(string(meta.run_id))))
                meta.run_id = phase_id;
            end
            if ~isfield(meta, 'bc_case') || isempty(meta.bc_case)
                phase_cfg = app.pick_field(results, {'phase_config'}, struct());
                meta.bc_case = char(string(app.pick_field(phase_cfg, {'force_bc_case'}, 'periodic')));
            end
            if ~isfield(meta, 'timestamp') || isempty(meta.timestamp)
                meta.timestamp = char(datetime('now', 'Format', 'yyyy-MM-dd HH:mm:ss'));
            end
            if isfield(run_cfg, 'launch_origin') && ~isempty(run_cfg.launch_origin)
                meta.launch_origin = char(string(run_cfg.launch_origin));
            end
            meta.run_color = run_color;
            if (~isfield(artifacts, 'paths') || ~isstruct(artifacts.paths) || isempty(fieldnames(artifacts.paths))) && ...
                    isfield(results, 'paths') && isstruct(results.paths)
                artifacts.paths = results.paths;
            end
            if ~isfield(monitor_series_entry, 'workflow_kind') || isempty(monitor_series_entry.workflow_kind)
                monitor_series_entry.workflow_kind = 'phase1_periodic_comparison';
                monitor_series_entry.workflow_phase_id = phase_id;
                monitor_series_entry.workflow_current_job_label = 'Phase 1 complete';
                monitor_series_entry.workflow_current_status = 'completed';
                monitor_series_entry.workflow_queue = app.pick_field(results, {'workflow_queue'}, struct([]));
            end

            run_badge = app.result_run_badge(idx, meta);
            meta.run_badge = run_badge;
            workflow = app.build_phase1_workflow_model(results);

            entry = struct( ...
                'name', fig_name, ...
                'analysis', struct(), ...
                'results', results, ...
                'parameters', params, ...
                'run_config', run_cfg, ...
                'metadata', meta, ...
                'tab_handle', [], ...
                'run_color', run_color, ...
                'run_badge', run_badge, ...
                'plot_tabs', struct(), ...
                'monitor_series', monitor_series_entry, ...
                'artifacts', artifacts, ...
                'workflow', workflow, ...
                'workflow_kind', 'phase1_periodic_comparison', ...
                'launch_origin', char(string(app.pick_field(run_cfg, {'launch_origin'}, ''))), ...
                'result_layout_kind', 'phase1_workflow', ...
                'publication_key', char(string(app.resolve_completion_publication_key(summary))), ...
                'publication_state', 'published', ...
                'hydration_state', 'hydrated', ...
                'post_publication_state', 'pending');
            if shell_registration
                entry.hydration_state = 'shell';
            end

            app.session_figures(idx) = entry;
            try
                launch_artifact = app.persist_collector_launch_csv();
                app.session_figures(idx).artifacts.launch_session = launch_artifact;
                if isfield(app.session_figures(idx).artifacts, 'collector_artifacts') && ...
                        isstruct(app.session_figures(idx).artifacts.collector_artifacts)
                    app.session_figures(idx).artifacts.collector_artifacts.launch_session = launch_artifact;
                end
            catch ME
                app.append_to_terminal(sprintf('Collector launch CSV warning: %s', ME.message), 'warning');
            end

            tab = [];
            try
                tab_title = sprintf('%s %s', run_badge, fig_name);
                tab = uitab(app.handles.figure_tabs, 'Title', tab_title);
                if isprop(tab, 'BackgroundColor')
                    tab.BackgroundColor = 0.82 * app.layout_cfg.colors.bg_dark + 0.18 * run_color;
                end
                app.session_figures(idx).tab_handle = tab;
                if shell_registration
                    app.session_figures(idx).plot_tabs = app.plot_workflow_result_shell_on_tab(tab, app.session_figures(idx));
                else
                    app.session_figures(idx).plot_tabs = app.plot_phase1_workflow_on_tab(tab, app.session_figures(idx));
                end
            catch ME
                app.append_to_terminal(sprintf('Phase 1 tab plot warning: %s', ME.message), 'warning');
            end

            app.finalize_result_registration_ui(idx, tab);
            app.remember_registered_result_entry(idx, entry.publication_key);
            app.update_result_entry_status_badge(idx);
            if shell_registration
                app.enqueue_result_entry_hydration(idx, summary);
            end
            app.run_or_defer_registered_result_autosave(idx, summary, 'workflow');
            app.append_to_terminal(sprintf('Registered result: %s', fig_name), 'info');
            if isfield(artifacts, 'paths') && isstruct(artifacts.paths) && isfield(artifacts.paths, 'base')
                app.append_to_terminal(sprintf('Result view exports rooted at: %s', char(string(artifacts.paths.base))), 'info');
            end
        end

        function ensure_phase1_workflow_publication(app, idx, summary)
            if nargin < 2 || ~isscalar(idx) || idx < 1 || idx > numel(app.session_figures)
                return;
            end
            entry = app.session_figures(idx);
            if ~strcmpi(char(string(app.pick_field(entry, {'workflow_kind'}, ''))), 'phase1_periodic_comparison')
                return;
            end

            [missing_artifacts, paths] = app.phase1_publication_gaps(entry, summary);
            if isempty(missing_artifacts)
                return;
            end

            app.append_to_terminal(sprintf(['Workflow autosave info: Phase 1 publication is retrying because %d mandatory ', ...
                'artifacts were missing from the initial save pass.'], numel(missing_artifacts)), 'warning');

            retry_summary = summary;
            retry_summary.paths = paths;
            retry_summary.settings = app.resolve_workflow_autosave_settings(entry, summary);
            retry_summary.settings.workflow_import_preview_only = false;
            retry_summary.settings = app.normalize_workflow_export_settings(retry_summary.settings);
            retry_summary.settings.animation_enabled = true;
            if ~isfield(retry_summary.settings, 'media') || ~isstruct(retry_summary.settings.media)
                retry_summary.settings.media = struct();
            end
            retry_summary.settings.media.enabled = true;

            app.autosave_workflow_result_views(idx, retry_summary);

            [remaining_artifacts, ~] = app.phase1_publication_gaps(app.session_figures(idx), retry_summary);
            if isempty(remaining_artifacts)
                app.append_to_terminal('Workflow autosave info: Phase 1 publication retry completed the missing artifacts.', 'info');
            else
                app.append_to_terminal(sprintf('Workflow autosave warning: Phase 1 publication still missing: %s', ...
                    char(strjoin(string(remaining_artifacts), ', '))), 'warning');
            end
        end

        function [missing_artifacts, paths] = phase1_publication_gaps(app, entry, summary)
            missing_artifacts = strings(1, 0);
            paths = app.pick_field(app.pick_field(entry, {'artifacts'}, struct()), {'paths'}, struct());
            if isempty(fieldnames(paths)) && nargin >= 3 && isstruct(summary)
                paths = app.pick_field(summary, {'paths'}, struct());
            end
            if ~isstruct(paths) || isempty(fieldnames(paths))
                missing_artifacts(end + 1) = "paths";
                return;
            end

            matlab_data_root = char(string(app.pick_field(paths, {'matlab_data_root', 'data'}, '')));
            metrics_root = char(string(app.pick_field(paths, {'metrics_root', 'reports'}, '')));
            visuals_root = char(string(app.pick_field(paths, {'visuals_root', 'figures_root'}, '')));
            manifest_path = char(string(app.pick_field(paths, {'manifest_path'}, fullfile(matlab_data_root, 'artifact_manifest.json'))));
            manifest_pending_ui_publication = false;
            if ~isempty(manifest_path) && exist(manifest_path, 'file') == 2
                try
                    manifest_text = fileread(manifest_path);
                    if contains(lower(manifest_text), '"publication_status":"pending_ui_publication"')
                        manifest_pending_ui_publication = true;
                    end
                catch
                    manifest_pending_ui_publication = false;
                end
            end
            if isempty(manifest_path) || exist(manifest_path, 'file') ~= 2 || manifest_pending_ui_publication
                missing_artifacts(end + 1) = "artifact_manifest.json"; %#ok<AGROW>
            end

            required_fig_keys = {'evolution_3x3', 'streamfunction_3x3', 'velocity_3x3', ...
                'vector_3x3', 'contour_3x3', 'streamlines_3x3'};
            stage_specs = { ...
                struct('stage_id', 'fd_periodic_evolution', 'label', 'FD/Elliptic'), ...
                struct('stage_id', 'spectral_periodic_evolution', 'label', 'SM/Elliptic')};

            workflow = app.pick_field(entry, {'workflow'}, struct());
            ic_study = app.pick_field(workflow, {'ic_study'}, struct());
            ic_cases = app.pick_field(ic_study, {'cases'}, struct([]));
            if isstruct(ic_cases) && ~isempty(ic_cases)
                for i = 1:numel(ic_cases)
                    case_token = app.sanitize_filename(app.pick_field(ic_cases(i), {'case_id'}, sprintf('case_%02d', i)));
                    case_folder = app.phase1_publication_case_folder_name( ...
                        app.pick_field(ic_cases(i), {'case_id'}, sprintf('case_%02d', i)));
                    stage_specs{end + 1} = struct('stage_id', sprintf('fd_ic_%s', case_token), 'label', sprintf('FD/%s', case_folder)); %#ok<AGROW>
                    stage_specs{end + 1} = struct('stage_id', sprintf('spectral_ic_%s', case_token), 'label', sprintf('SM/%s', case_folder)); %#ok<AGROW>
                end
            end

            for si = 1:numel(stage_specs)
                stage_paths = app.build_workflow_stage_paths(paths, stage_specs{si}.stage_id);
                figure_stem_map = app.pick_field(stage_paths, {'figure_stem_map'}, struct());
                pane_stem_map = app.pick_field(stage_paths, {'pane_media_stem_map'}, struct());
                visuals_stage_root = char(string(app.pick_field(stage_paths, {'visuals_root', 'figures_root'}, visuals_root)));
                for fi = 1:numel(required_fig_keys)
                    fig_stem = char(string(app.pick_field(figure_stem_map, {required_fig_keys{fi}}, '')));
                    if isempty(fig_stem)
                        continue;
                    end
                    fig_path = fullfile(visuals_stage_root, sprintf('%s.fig', fig_stem));
                    if exist(fig_path, 'file') ~= 2
                        missing_artifacts(end + 1) = string(sprintf('Visuals/%s/%s.fig', stage_specs{si}.label, fig_stem)); %#ok<AGROW>
                    end
                end
                gif_stem = char(string(app.pick_field(pane_stem_map, {'evolution'}, '')));
                if ~isempty(gif_stem)
                    gif_path = fullfile(visuals_stage_root, sprintf('%s.gif', gif_stem));
                    if exist(gif_path, 'file') ~= 2
                        missing_artifacts(end + 1) = string(sprintf('Visuals/%s/%s.gif', stage_specs{si}.label, gif_stem)); %#ok<AGROW>
                    end
                end
            end

            comparison_dir = fullfile(visuals_root, 'Comparisons');
            required_comparison_figs = { ...
                'phase1_runtime_per_ic_case.fig', ...
                'phase1_cross_method_mismatch.fig', ...
                'phase1_conservation_drift.fig', ...
                'phase1_vortex_preservation.fig', ...
                'phase1_error_vs_time.fig', ...
                'phase1_overview_triptych.fig'};
            for i = 1:numel(required_comparison_figs)
                comparison_path = fullfile(comparison_dir, required_comparison_figs{i});
                if exist(comparison_path, 'file') ~= 2
                    missing_artifacts(end + 1) = string(fullfile('Visuals', 'Comparisons', required_comparison_figs{i})); %#ok<AGROW>
                end
            end

            workbook_path = char(string(app.pick_field(paths, {'run_data_workbook_path'}, fullfile(metrics_root, 'Run_Data.xlsx'))));
            if isempty(workbook_path) || exist(workbook_path, 'file') ~= 2
                missing_artifacts(end + 1) = "Metrics/Run_Data.xlsx"; %#ok<AGROW>
            end

            hwinfo_expected = app.summary_requests_hwinfo(summary, app.pick_field(entry, {'monitor_series'}, struct()));
            if hwinfo_expected
                hwinfo_csv_path = char(string(app.pick_field(paths, {'raw_hwinfo_csv_path'}, fullfile(metrics_root, 'HWiNFO_Telemetry.csv'))));
                if isempty(hwinfo_csv_path) || exist(hwinfo_csv_path, 'file') ~= 2
                    missing_artifacts(end + 1) = "Metrics/HWiNFO_Telemetry.csv"; %#ok<AGROW>
                end
                hwinfo_fig = fullfile(visuals_root, 'Collectors', 'HWiNFO_Overview.fig');
                if exist(hwinfo_fig, 'file') ~= 2
                    missing_artifacts(end + 1) = "Visuals/Collectors/HWiNFO_Overview.fig"; %#ok<AGROW>
                end
            end

            missing_artifacts = unique(missing_artifacts, 'stable');
        end

        function workflow = build_phase1_workflow_model(app, results)
            workflow = struct();
            workflow.phase_id = char(string(app.pick_field(results, {'phase_id', 'run_id'}, 'phase1')));
            workflow.manifest = app.pick_field(results, {'workflow_manifest'}, struct());
            workflow.paths = app.pick_field(results, {'paths'}, struct());
            if isempty(fieldnames(workflow.paths)) && isfield(workflow.manifest, 'paths')
                workflow.paths = workflow.manifest.paths;
            end
            workflow.phase_config = app.pick_field(results, {'phase_config'}, struct());
            if isempty(fieldnames(workflow.phase_config)) && isfield(workflow.manifest, 'phase_config')
                workflow.phase_config = workflow.manifest.phase_config;
            end
            workflow.children = app.pick_field(results, {'children'}, struct());
            if isempty(fieldnames(workflow.children)) && isfield(workflow.manifest, 'children')
                workflow.children = workflow.manifest.children;
            end
            workflow.combined = app.pick_field(results, {'combined'}, struct());
            if isempty(fieldnames(workflow.combined)) && isfield(workflow.manifest, 'combined')
                workflow.combined = workflow.manifest.combined;
            end
            workflow.ic_study = app.pick_field(results, {'ic_study'}, struct());
            if isempty(fieldnames(workflow.ic_study)) && isfield(workflow.manifest, 'ic_study')
                workflow.ic_study = workflow.manifest.ic_study;
            end
            workflow.metrics = app.pick_field(results, {'metrics'}, struct());
            if isempty(fieldnames(workflow.metrics))
                workflow.metrics = struct( ...
                    'FD', app.pick_field(app.pick_field(workflow.children, {'fd'}, struct()), {'metrics'}, struct()), ...
                    'Spectral', app.pick_field(app.pick_field(workflow.children, {'spectral'}, struct()), {'metrics'}, struct()), ...
                    'summary', app.pick_field(workflow.manifest, {'metrics_summary'}, struct()));
            end
            workflow.queue = app.pick_field(results, {'workflow_queue'}, struct([]));
            if isempty(workflow.queue) && isfield(workflow.manifest, 'queue')
                workflow.queue = workflow.manifest.queue;
            end
        end

        function tf = is_phase2_workflow_summary(~, summary, results, run_cfg)
            tf = strcmpi(char(string(UIController.resolve_result_layout_kind_static(summary, results, run_cfg))), ...
                'phase2_workflow');
        end

        function tf = is_phase3_workflow_summary(~, summary, results, run_cfg)
            tf = strcmpi(char(string(UIController.resolve_result_layout_kind_static(summary, results, run_cfg))), ...
                'phase3_workflow');
        end

        function idx = register_phase2_workflow_result(app, summary, results, params, run_cfg, meta, artifacts, monitor_series_entry, fig_name)
            idx = 0;
            workflow = app.build_phase2_workflow_model(results);
            if ~isfield(workflow, 'scenarios') || isempty(workflow.scenarios)
                app.append_to_terminal('Phase 2 registration warning: no scenarios were available to register.', 'warning');
                return;
            end
            idx = numel(app.session_figures) + 1;
            shell_registration = app.workflow_shell_registration_requested(summary);
            run_color = app.result_run_color(idx);
            phase_id = char(string(app.pick_field(workflow, {'phase_id'}, 'phase2')));

            if ~(isfield(summary, 'imported_name') && strlength(string(summary.imported_name)) > 0)
                fig_name = sprintf('%s | Phase 2 | Boundary study', phase_id);
            end

            meta.method = 'Phase 2';
            meta.mode = 'Workflow';
            if isfield(results, 'parent_parameters') && isstruct(results.parent_parameters)
                parent_ic = app.pick_field(results.parent_parameters, {'ic_type'}, '');
                if ~isempty(parent_ic)
                    meta.ic_type = char(string(parent_ic));
                end
                if isempty(fieldnames(params))
                    params = results.parent_parameters;
                end
            end
            if isempty(strtrim(char(string(app.pick_field(meta, {'run_id'}, '')))))
                meta.run_id = phase_id;
            end
            if ~isfield(meta, 'bc_case') || isempty(meta.bc_case)
                first_scenario = workflow.scenarios(1);
                meta.bc_case = char(string(app.pick_field(app.pick_field(first_scenario, {'summary'}, struct()), {'bc_id', 'scenario_id'}, '')));
            end
            if ~isfield(meta, 'timestamp') || isempty(meta.timestamp)
                meta.timestamp = char(datetime('now', 'Format', 'yyyy-MM-dd HH:mm:ss'));
            end
            if isfield(run_cfg, 'launch_origin') && ~isempty(run_cfg.launch_origin)
                meta.launch_origin = char(string(run_cfg.launch_origin));
            end
            meta.run_color = run_color;
            if (~isfield(artifacts, 'paths') || ~isstruct(artifacts.paths) || isempty(fieldnames(artifacts.paths))) && ...
                    isstruct(workflow.paths) && ~isempty(fieldnames(workflow.paths))
                artifacts.paths = workflow.paths;
            end
            if ~isfield(monitor_series_entry, 'workflow_kind') || isempty(monitor_series_entry.workflow_kind)
                monitor_series_entry.workflow_kind = 'phase2_boundary_condition_study';
                monitor_series_entry.workflow_phase_id = phase_id;
                monitor_series_entry.workflow_current_job_label = 'Phase 2 complete';
                monitor_series_entry.workflow_current_status = 'completed';
                monitor_series_entry.workflow_queue = workflow.queue;
            end

            run_badge = app.result_run_badge(idx, meta);
            meta.run_badge = run_badge;

            entry = struct( ...
                'name', fig_name, ...
                'analysis', struct(), ...
                'results', results, ...
                'parameters', params, ...
                'run_config', run_cfg, ...
                'metadata', meta, ...
                'tab_handle', [], ...
                'run_color', run_color, ...
                'run_badge', run_badge, ...
                'plot_tabs', struct(), ...
                'monitor_series', monitor_series_entry, ...
                'artifacts', artifacts, ...
                'workflow', workflow, ...
                'workflow_kind', 'phase2_boundary_condition_study', ...
                'launch_origin', char(string(app.pick_field(run_cfg, {'launch_origin'}, ''))), ...
                'result_layout_kind', 'phase2_workflow', ...
                'publication_key', char(string(app.resolve_completion_publication_key(summary))), ...
                'publication_state', 'published', ...
                'hydration_state', 'hydrated', ...
                'post_publication_state', 'pending');
            if shell_registration
                entry.hydration_state = 'shell';
            end
            app.session_figures(idx) = entry;
            try
                launch_artifact = app.persist_collector_launch_csv();
                app.session_figures(idx).artifacts.launch_session = launch_artifact;
                if isfield(app.session_figures(idx).artifacts, 'collector_artifacts') && ...
                        isstruct(app.session_figures(idx).artifacts.collector_artifacts)
                    app.session_figures(idx).artifacts.collector_artifacts.launch_session = launch_artifact;
                end
            catch ME
                app.append_to_terminal(sprintf('Collector launch CSV warning: %s', ME.message), 'warning');
            end

            tab = [];
            try
                tab_title = sprintf('%s %s', run_badge, fig_name);
                tab = uitab(app.handles.figure_tabs, 'Title', tab_title);
                if isprop(tab, 'BackgroundColor')
                    tab.BackgroundColor = 0.82 * app.layout_cfg.colors.bg_dark + 0.18 * run_color;
                end
                app.session_figures(idx).tab_handle = tab;
                if shell_registration
                    app.session_figures(idx).plot_tabs = app.plot_workflow_result_shell_on_tab(tab, app.session_figures(idx));
                else
                    app.session_figures(idx).plot_tabs = app.plot_phase2_workflow_on_tab(tab, app.session_figures(idx));
                end
            catch ME
                app.append_to_terminal(sprintf('Phase 2 tab plot warning: %s', ME.message), 'warning');
            end

            app.finalize_result_registration_ui(idx, tab);
            app.remember_registered_result_entry(idx, entry.publication_key);
            app.update_result_entry_status_badge(idx);
            if shell_registration
                app.enqueue_result_entry_hydration(idx, summary);
            end
            app.run_or_defer_registered_result_autosave(idx, summary, 'workflow');
            app.append_to_terminal(sprintf('Registered result: %s', fig_name), 'info');
        end

        function workflow = build_phase2_workflow_model(app, results)
