                monitor_series_entry.workflow_queue = workflow.queue;
            end

            run_badge = app.result_run_badge(idx, meta);
            meta.run_badge = run_badge;

            entry = struct( ...
                'name', fig_name, ...
                'analysis', struct(), ...
                'results', results, ...
                'parameters', params, ...
                'run_config', run_cfg, ...
                'metadata', meta, ...
                'tab_handle', [], ...
                'run_color', run_color, ...
                'run_badge', run_badge, ...
                'plot_tabs', struct(), ...
                'monitor_series', monitor_series_entry, ...
                'artifacts', artifacts, ...
                'workflow', workflow, ...
                'workflow_kind', 'phase3_bathymetry_study', ...
                'launch_origin', char(string(app.pick_field(run_cfg, {'launch_origin'}, ''))), ...
                'result_layout_kind', 'phase3_workflow', ...
                'publication_key', char(string(app.resolve_completion_publication_key(summary))), ...
                'publication_state', 'published', ...
                'hydration_state', 'hydrated', ...
                'post_publication_state', 'pending');
            if shell_registration
                entry.hydration_state = 'shell';
            end
            app.session_figures(idx) = entry;
            try
                launch_artifact = app.persist_collector_launch_csv();
                app.session_figures(idx).artifacts.launch_session = launch_artifact;
                if isfield(app.session_figures(idx).artifacts, 'collector_artifacts') && ...
                        isstruct(app.session_figures(idx).artifacts.collector_artifacts)
                    app.session_figures(idx).artifacts.collector_artifacts.launch_session = launch_artifact;
                end
            catch ME
                app.append_to_terminal(sprintf('Collector launch CSV warning: %s', ME.message), 'warning');
            end

            tab = [];
            try
                tab_title = sprintf('%s %s', run_badge, fig_name);
                tab = uitab(app.handles.figure_tabs, 'Title', tab_title);
                if isprop(tab, 'BackgroundColor')
                    tab.BackgroundColor = 0.82 * app.layout_cfg.colors.bg_dark + 0.18 * run_color;
                end
                app.session_figures(idx).tab_handle = tab;
                if shell_registration
                    app.session_figures(idx).plot_tabs = app.plot_workflow_result_shell_on_tab(tab, app.session_figures(idx));
                else
                    app.session_figures(idx).plot_tabs = app.plot_phase2_workflow_on_tab(tab, app.session_figures(idx));
                end
            catch ME
                app.append_to_terminal(sprintf('Phase 3 tab plot warning: %s', ME.message), 'warning');
            end

            app.finalize_result_registration_ui(idx, tab);
            app.remember_registered_result_entry(idx, entry.publication_key);
            app.update_result_entry_status_badge(idx);
            if shell_registration
                app.enqueue_result_entry_hydration(idx, summary);
            end
            app.run_or_defer_registered_result_autosave(idx, summary, 'workflow');
            app.append_to_terminal(sprintf('Registered result: %s', fig_name), 'info');
        end

        function workflow = build_phase3_workflow_model(app, results)
            workflow = struct();
            workflow.phase_id = char(string(app.pick_field(results, {'phase_id', 'run_id'}, 'phase3')));
            workflow.manifest = app.pick_field(results, {'workflow_manifest'}, struct());
            workflow.scenarios = app.pick_field(results, {'scenarios'}, struct([]));
            if isempty(workflow.scenarios) && isfield(workflow.manifest, 'scenarios')
                workflow.scenarios = workflow.manifest.scenarios;
            end
            workflow.phase_config = app.pick_field(results, {'phase_config'}, struct());
            if isempty(fieldnames(workflow.phase_config)) && isfield(workflow.manifest, 'phase_config')
                workflow.phase_config = workflow.manifest.phase_config;
            end
            workflow.queue = app.pick_field(results, {'workflow_queue'}, struct([]));
            if isempty(workflow.queue) && isfield(workflow.manifest, 'queue')
                workflow.queue = workflow.manifest.queue;
            end
            workflow.paths = app.pick_field(results, {'paths'}, struct());
            if isempty(fieldnames(workflow.paths)) && isfield(workflow.manifest, 'paths')
                workflow.paths = workflow.manifest.paths;
            end
        end

        function register_phase2_scenario_entry(app, summary, workflow, scenario, params, run_cfg, meta, artifacts, monitor_series_entry, fig_name, scenario_index)
            idx = numel(app.session_figures) + 1;
            run_color = app.result_run_color(idx);
            run_badge = app.result_run_badge(idx, meta);
            scenario_name = char(string(app.pick_field(scenario, {'scenario_label'}, sprintf('Scenario %d', scenario_index))));
            phase_id = char(string(app.pick_field(workflow, {'phase_id'}, 'phase2')));
            fig_name_local = sprintf('%s | %s', phase_id, scenario_name);
            if isfield(summary, 'imported_name') && strlength(string(summary.imported_name)) > 0
                fig_name_local = sprintf('%s | %s', char(string(summary.imported_name)), scenario_name);
            elseif nargin >= 10 && strlength(string(fig_name)) > 0
                fig_name_local = sprintf('%s | %s', char(string(fig_name)), scenario_name);
            end

            fd_summary = app.resolve_phase2_child_view_summary(app.pick_field(scenario, {'fd'}, struct()));
            fd_paths = app.pick_field(fd_summary, {'paths'}, struct());
            artifacts_local = artifacts;
            if isstruct(fd_paths) && ~isempty(fieldnames(fd_paths))
                artifacts_local.paths = fd_paths;
            end

            meta_local = meta;
            meta_local.method = 'Phase 2';
            meta_local.mode = 'Scenario';
            meta_local.bc_case = char(string(app.pick_field(scenario, {'scenario_id'}, '')));
            meta_local.run_id = sprintf('%s_%s', phase_id, char(string(app.pick_field(scenario, {'scenario_id'}, scenario_index))));
            meta_local.timestamp = char(datetime('now', 'Format', 'yyyy-MM-dd HH:mm:ss'));
            meta_local.run_color = run_color;
            meta_local.run_badge = run_badge;

            entry = struct( ...
                'name', fig_name_local, ...
                'analysis', struct(), ...
                'parameters', params, ...
                'run_config', run_cfg, ...
                'metadata', meta_local, ...
                'tab_handle', [], ...
                'run_color', run_color, ...
                'run_badge', run_badge, ...
                'plot_tabs', struct(), ...
                'monitor_series', monitor_series_entry, ...
                'artifacts', artifacts_local, ...
                'workflow', struct('phase_id', phase_id, 'scenario', scenario, 'queue', workflow.queue, 'paths', workflow.paths), ...
                'workflow_kind', 'phase2_boundary_condition_study', ...
                'launch_origin', char(string(app.pick_field(run_cfg, {'launch_origin'}, ''))), ...
                'result_layout_kind', 'phase2_scenario');
            app.session_figures(idx) = entry;

            tab = [];
            try
                tab_title = sprintf('%s %s', run_badge, fig_name_local);
                tab = uitab(app.handles.figure_tabs, 'Title', tab_title);
                if isprop(tab, 'BackgroundColor')
                    tab.BackgroundColor = 0.82 * app.layout_cfg.colors.bg_dark + 0.18 * run_color;
                end
                app.session_figures(idx).tab_handle = tab;
                app.session_figures(idx).plot_tabs = app.plot_phase2_scenario_on_tab(tab, app.session_figures(idx));
            catch ME
                app.append_to_terminal(sprintf('Phase 2 tab plot warning: %s', ME.message), 'warning');
            end

            app.refresh_session_figure_dropdown();
            app.update_result_identifier_tags(idx);
            app.update_metrics_summary(idx);
            if ~isempty(tab) && isvalid(tab)
                app.handles.figure_tabs.SelectedTab = tab;
            end
            app.append_to_terminal(sprintf('Registered result: %s', fig_name_local), 'info');
        end

