        function plot_tabs = plot_phase2_scenario_on_tab(app, tab, entry)
            C = app.layout_cfg.colors;
            if ~isempty(tab.Children)
                delete(tab.Children);
            end
            workflow = entry.workflow;
            scenario = app.pick_field(workflow, {'scenario'}, struct());
            phase_label = 'Phase 2';
            scenario_header = 'Phase 2 Scenario';
            if strcmpi(char(string(app.pick_field(entry, {'workflow_kind'}, ''))), 'phase3_bathymetry_study')
                phase_label = 'Phase 3';
                scenario_header = 'Phase 3 Scenario';
            end
            root = uigridlayout(tab, [2, 1]);
            root.RowHeight = {40, '1x'};
            root.Padding = [4 4 4 4];
            root.RowSpacing = 4;

            header = uipanel(root, 'BorderType', 'none', ...
                'BackgroundColor', 0.82 * C.bg_panel + 0.18 * entry.run_color);
            header.Layout.Row = 1;
            header_grid = uigridlayout(header, [1, 4]);
            header_grid.Padding = [8 2 8 2];
            header_grid.ColumnWidth = {'fit', '1x', 'fit', 'fit'};
            header_grid.ColumnSpacing = 10;
            uilabel(header_grid, 'Text', entry.run_badge, 'FontWeight', 'bold', 'FontSize', 11, ...
                'FontColor', [0.07 0.07 0.07], 'BackgroundColor', entry.run_color, 'HorizontalAlignment', 'center');
            uilabel(header_grid, 'Text', sprintf('Phase ID: %s', char(string(app.pick_field(workflow, {'phase_id'}, 'phase2')))), ...
                'FontColor', C.fg_text, 'FontSize', 11, 'HorizontalAlignment', 'left');
            uilabel(header_grid, 'Text', scenario_header, 'FontColor', C.fg_text, 'FontSize', 11, 'HorizontalAlignment', 'right');
            uilabel(header_grid, 'Text', char(string(app.pick_field(scenario, {'scenario_label'}, 'Scenario'))), ...
                'FontColor', C.fg_text, 'FontSize', 11, 'HorizontalAlignment', 'right');

            tabs = uitabgroup(root);
            tabs.Layout.Row = 2;
            t_fd = uitab(tabs, 'Title', 'Finite Difference');
            t_sp = [];
            t_comb = [];

            fd_summary = app.resolve_phase2_child_view_summary(app.pick_field(scenario, {'fd'}, struct()));
            fd_grid = uigridlayout(t_fd, [1, 1]);
            fd_grid.RowHeight = {'1x'};
            fd_grid.Padding = [4 4 4 4];
            fd_host = uipanel(fd_grid, 'BorderType', 'none', 'BackgroundColor', C.bg_dark);
            fd_host.Layout.Row = 1;
            if isstruct(fd_summary) && isfield(fd_summary, 'analysis') && isstruct(fd_summary.analysis) && ~isempty(fieldnames(fd_summary.analysis))
                app.plot_analysis_on_tab(fd_host, fd_summary.analysis, ...
                    app.pick_field(fd_summary, {'parameters'}, struct()), ...
                    app.pick_field(fd_summary, {'run_config'}, struct()), ...
                    app.pick_field(fd_summary, {'metadata'}, struct()), ...
                    app.pick_field(entry, {'monitor_series'}, struct()));
            end

            spectral_struct = app.pick_field(scenario, {'spectral'}, struct());
            spectral_supported = logical(app.pick_field(spectral_struct, {'supported'}, false));
            if spectral_supported
                t_sp = uitab(tabs, 'Title', 'Spectral');
                sp_summary = app.resolve_phase2_child_view_summary(spectral_struct);
                sp_grid = uigridlayout(t_sp, [1, 1]);
                sp_grid.RowHeight = {'1x'};
                sp_grid.Padding = [4 4 4 4];
                sp_host = uipanel(sp_grid, 'BorderType', 'none', 'BackgroundColor', C.bg_dark);
                sp_host.Layout.Row = 1;
                if isstruct(sp_summary) && isfield(sp_summary, 'analysis') && isstruct(sp_summary.analysis) && ~isempty(fieldnames(sp_summary.analysis))
                    app.plot_analysis_on_tab(sp_host, sp_summary.analysis, ...
                        app.pick_field(sp_summary, {'parameters'}, struct()), ...
                        app.pick_field(sp_summary, {'run_config'}, struct()), ...
                        app.pick_field(sp_summary, {'metadata'}, struct()), ...
                        app.pick_field(entry, {'monitor_series'}, struct()));
                end
            end

            combined_struct = app.pick_field(scenario, {'combined'}, struct());
            combined_supported = logical(app.pick_field(combined_struct, {'supported'}, ...
                app.pick_field(app.pick_field(combined_struct, {'phase_policy'}, struct()), {'spectral_supported'}, false)));
            if combined_supported
                t_comb = uitab(tabs, 'Title', 'Combined');
                app.render_phase2_combined_tab(t_comb, scenario);
            end
            plot_tabs = struct('group', tabs, 'fd', t_fd, 'spectral', t_sp, 'combined', t_comb);
        end

        function plot_tabs = plot_phase2_workflow_on_tab(app, tab, entry)
            C = app.layout_cfg.colors;
            tab.BackgroundColor = C.bg_dark;
            if ~isempty(tab.Children)
                delete(tab.Children);
            end

            workflow = app.pick_field(entry, {'workflow'}, struct());
            scenarios = app.pick_field(workflow, {'scenarios'}, struct([]));

            root = uigridlayout(tab, [2, 1]);
            root.RowHeight = {40, '1x'};
            root.Padding = [4 4 4 4];
            root.RowSpacing = 4;

            phase_header = 'Phase 2 Workflow';
            phase_subtitle = 'Boundary-condition scenarios';
            if strcmpi(char(string(app.pick_field(entry, {'workflow_kind'}, ''))), 'phase3_bathymetry_study')
                phase_header = 'Phase 3 Workflow';
                phase_subtitle = 'Bathymetry scenarios';
            end

            header_panel = uipanel(root, 'BorderType', 'none', ...
                'BackgroundColor', 0.82 * C.bg_panel + 0.18 * entry.run_color);
            header_panel.Layout.Row = 1;
            header_grid = uigridlayout(header_panel, [1, 4]);
            header_grid.Padding = [8 2 8 2];
            header_grid.ColumnSpacing = 10;
            header_grid.ColumnWidth = {'fit', '1x', 'fit', 'fit'};

            uilabel(header_grid, ...
                'Text', entry.run_badge, ...
                'FontWeight', 'bold', ...
                'FontSize', 11, ...
                'FontColor', [0.07 0.07 0.07], ...
                'BackgroundColor', entry.run_color, ...
                'HorizontalAlignment', 'center');
            uilabel(header_grid, ...
                'Text', sprintf('Phase ID: %s', char(string(app.pick_field(workflow, {'phase_id'}, '--')))), ...
                'FontColor', C.fg_text, ...
                'FontSize', 11, ...
                'HorizontalAlignment', 'left');
            uilabel(header_grid, ...
                'Text', phase_header, ...
                'FontColor', C.fg_text, ...
                'FontSize', 11, ...
                'HorizontalAlignment', 'right');
            uilabel(header_grid, ...
                'Text', sprintf('%d scenarios | %s', numel(scenarios), phase_subtitle), ...
                'FontColor', C.fg_text, ...
                'FontSize', 11, ...
                'HorizontalAlignment', 'right');

            workflow_tabs = uitabgroup(root);
            workflow_tabs.Layout.Row = 2;
            scenario_tabs = cell(1, numel(scenarios));
            for i = 1:numel(scenarios)
                scenario_name = char(string(app.pick_field(scenarios(i), {'scenario_label'}, sprintf('Scenario %d', i))));
                scenario_tab = uitab(workflow_tabs, 'Title', scenario_name);
                scenario_entry = entry;
                scenario_entry.workflow = struct( ...
                    'phase_id', app.pick_field(workflow, {'phase_id'}, ''), ...
                    'scenario', scenarios(i), ...
                    'scenarios', scenarios, ...
                    'queue', app.pick_field(workflow, {'queue'}, struct([])), ...
                    'paths', app.pick_field(workflow, {'paths'}, struct()), ...
                    'manifest', app.pick_field(workflow, {'manifest'}, struct()), ...
                    'phase_config', app.pick_field(workflow, {'phase_config'}, struct()));
                fd_summary = app.resolve_phase2_child_view_summary(app.pick_field(scenarios(i), {'fd'}, struct()));
                fd_paths = app.pick_field(fd_summary, {'paths'}, struct());
                scenario_entry.artifacts = entry.artifacts;
                if isstruct(fd_paths) && ~isempty(fieldnames(fd_paths))
                    scenario_entry.artifacts.paths = fd_paths;
                end
                scenario_entry.plot_tabs = app.plot_phase2_scenario_on_tab(scenario_tab, scenario_entry);
                scenario_tabs{i} = scenario_tab;
            end

            plot_tabs = struct('group', workflow_tabs, 'scenario_tabs', {scenario_tabs});
        end

        function lines = phase2_scenario_summary_lines(app, scenario, method_name)
            if nargin < 3 || isempty(method_name)
                method_name = 'fd';
            end
            summary = app.pick_field(scenario, {'summary'}, struct());
            child_struct = app.pick_field(scenario, {lower(char(string(method_name)))}, struct());
            child_view = app.pick_field(child_struct, {'view_summary'}, struct());
            child_analysis = app.pick_field(child_view, {'analysis'}, struct());
            if strcmpi(char(string(method_name)), 'spectral')
                mesh_nx = double(app.pick_field(summary, {'spectral_mesh_nx'}, NaN));
                mesh_ny = double(app.pick_field(summary, {'spectral_mesh_ny'}, NaN));
                runtime_wall = double(app.pick_field(summary, {'spectral_runtime_wall_s'}, NaN));
                artifact_root = '';
                child_paths = app.pick_field(child_struct, {'paths'}, struct());
                if isstruct(child_paths)
                    artifact_root = app.pick_field(child_paths, {'base'}, '');
                end
                method_label = 'Spectral';
            else
                mesh_nx = double(app.pick_field(summary, {'mesh_nx'}, NaN));
                mesh_ny = double(app.pick_field(summary, {'mesh_ny'}, NaN));
                runtime_wall = double(app.pick_field(summary, {'runtime_wall_s'}, NaN));
                artifact_root = app.pick_field(summary, {'artifact_root'}, '');
                method_label = 'Finite Difference';
            end
            mesh_txt = '--';
            if isfinite(mesh_nx) && isfinite(mesh_ny)
                mesh_txt = sprintf('%dx%d', round(mesh_nx), round(mesh_ny));
            end
            lines = { ...
                sprintf('Scenario: %s', app.if_empty(app.pick_field(summary, {'scenario_label'}, ''), '--')); ...
                sprintf('BC: %s', app.if_empty(app.pick_field(summary, {'bc_label', 'bc_id'}, ''), '--')); ...
                sprintf('Bathymetry: %s', app.if_empty(app.pick_field(summary, {'bathymetry_label', 'bathymetry_id'}, ''), '--')); ...
                sprintf('Method: %s', method_label); ...
                sprintf('Runtime: %s s', app.if_nan_num_fixed(runtime_wall, '%.3f')); ...
                sprintf('Mesh: %s', mesh_txt); ...
                sprintf('Artifacts: %s', app.if_empty(artifact_root, '--')); ...
                sprintf('Boundary profile: %s', app.if_empty(app.pick_field(child_analysis, {'boundary_profile'}, ''), '--')) ...
            };
        end

        function render_phase2_combined_tab(app, tab, scenario)
            C = app.layout_cfg.colors;
            if ~isempty(tab.Children)
                delete(tab.Children);
            end
            combined = app.pick_field(scenario, {'combined'}, struct());
            root = uigridlayout(tab, [1, 1]);
            root.RowHeight = {'1x'};
            root.ColumnWidth = {'1x'};
            root.Padding = [6 6 6 6];
            root.RowSpacing = 6;
            root.ColumnSpacing = 6;

            ax = uiaxes(root);
            ax.Layout.Row = 1;
            ax.Layout.Column = 1;
            app.style_results_axes(ax);
            overlay = app.pick_field(combined, {'overlay'}, struct());
            fd_overlay = app.pick_field(overlay, {'fd'}, struct());
            sp_overlay = app.pick_field(overlay, {'spectral'}, struct());
            t_fd = app.pick_field(fd_overlay, {'elapsed_wall_time'}, []);
            ke_fd = app.pick_field(fd_overlay, {'kinetic_energy'}, []);
            enst_fd = app.pick_field(fd_overlay, {'enstrophy'}, []);
            circ_fd = app.pick_field(fd_overlay, {'circulation'}, []);
            t_sp = app.pick_field(sp_overlay, {'elapsed_wall_time'}, []);
            ke_sp = app.pick_field(sp_overlay, {'kinetic_energy'}, []);
            enst_sp = app.pick_field(sp_overlay, {'enstrophy'}, []);
            circ_sp = app.pick_field(sp_overlay, {'circulation'}, []);
            cla(ax);
            hold(ax, 'on');
            if ~isempty(t_fd) && ~isempty(ke_fd)
                plot(ax, t_fd(:), ke_fd(:), 'LineWidth', 1.6, 'Color', [0.20 0.55 0.95]);
            end
            if ~isempty(t_fd) && ~isempty(enst_fd)
                plot(ax, t_fd(:), enst_fd(:), '--', 'LineWidth', 1.6, 'Color', [0.35 0.70 0.98]);
            end
            if ~isempty(t_fd) && ~isempty(circ_fd)
                plot(ax, t_fd(:), circ_fd(:), ':', 'LineWidth', 1.6, 'Color', [0.50 0.80 1.00]);
            end
            if ~isempty(t_sp) && ~isempty(ke_sp)
                plot(ax, t_sp(:), ke_sp(:), 'LineWidth', 1.6, 'Color', [0.95 0.55 0.20]);
            end
            if ~isempty(t_sp) && ~isempty(enst_sp)
                plot(ax, t_sp(:), enst_sp(:), '--', 'LineWidth', 1.6, 'Color', [0.98 0.70 0.35]);
            end
            if ~isempty(t_sp) && ~isempty(circ_sp)
                plot(ax, t_sp(:), circ_sp(:), ':', 'LineWidth', 1.6, 'Color', [1.00 0.80 0.50]);
            end
            hold(ax, 'off');
            title(ax, 'FD + Spectral elapsed-time overlays');
            xlabel(ax, 'Elapsed time from 0');
            ylabel(ax, 'Metric value');
            legend(ax, 'off');
        end

        function child_summary = resolve_phase2_child_view_summary(app, child_struct)
            child_summary = struct();
            fallback_analysis = struct();
            if ~isstruct(child_struct)
                return;
            end
            if isfield(child_struct, 'view_summary') && isstruct(child_struct.view_summary)
                child_summary = child_struct.view_summary;
            end
            if app.analysis_has_snapshot_cube(app.pick_field(child_summary, {'analysis'}, struct()))
                return;
            end
            if isfield(child_summary, 'results') && isstruct(child_summary.results) && ...
                    isfield(child_summary.results, 'analysis') && isstruct(child_summary.results.analysis) && ...
                    ~isempty(fieldnames(child_summary.results.analysis))
                fallback_analysis = child_summary.results.analysis;
                if app.analysis_has_snapshot_cube(fallback_analysis)
                    child_summary.analysis = fallback_analysis;
                    return;
                end
            end

            data_path = '';
            if isfield(child_summary, 'results') && isstruct(child_summary.results)
                data_path = char(string(app.pick_field(child_summary.results, {'data_path'}, '')));
            end
            if isempty(data_path) && isfield(child_struct, 'output') && isstruct(child_struct.output) && ...
                    isfield(child_struct.output, 'results') && isstruct(child_struct.output.results)
                data_path = char(string(app.pick_field(child_struct.output.results, {'data_path'}, '')));
            end
            if isempty(data_path) && ~isempty(fieldnames(child_summary))
                paths = app.pick_field(child_summary, {'paths'}, struct());
                if isstruct(paths) && isfield(paths, 'data')
                    candidate = fullfile(char(string(paths.data)), 'results.mat');
                    if exist(candidate, 'file') == 2
                        data_path = candidate;
                    end
                end
            end
            if ~isempty(data_path) && exist(data_path, 'file') == 2
                try
                    loaded = load(data_path, 'analysis');
                    if isfield(loaded, 'analysis') && isstruct(loaded.analysis)
                        child_summary.analysis = loaded.analysis;
                        return;
                    end
                catch ME
                    app.append_to_terminal(sprintf('Phase 2 child analysis load warning: %s', ME.message), 'warning');
                end
            end
            if isstruct(fallback_analysis) && ~isempty(fieldnames(fallback_analysis))
                child_summary.analysis = fallback_analysis;
            end
        end

        function child_summary = resolve_phase1_child_view_summary(app, child_struct)
            child_summary = struct();
            fallback_analysis = struct();
            if ~isstruct(child_struct)
                return;
            end
            if isfield(child_struct, 'view_summary') && isstruct(child_struct.view_summary)
                child_summary = child_struct.view_summary;
            end

            if app.analysis_has_snapshot_cube(app.pick_field(child_summary, {'analysis'}, struct()))
                return;
            end
            if isfield(child_summary, 'results') && isstruct(child_summary.results) && ...
                    isfield(child_summary.results, 'analysis') && isstruct(child_summary.results.analysis) && ...
                    ~isempty(fieldnames(child_summary.results.analysis))
                fallback_analysis = child_summary.results.analysis;
                if app.analysis_has_snapshot_cube(fallback_analysis)
                    child_summary.analysis = fallback_analysis;
                    return;
                end
            end

            if ~isfield(child_summary, 'analysis') || ~isstruct(child_summary.analysis) || isempty(fieldnames(child_summary.analysis)) || ...
                    ~app.analysis_has_snapshot_cube(child_summary.analysis)
                data_path = '';
                if isfield(child_summary, 'results') && isstruct(child_summary.results)
                    data_path = char(string(app.pick_field(child_summary.results, {'data_path'}, '')));
                end
                if isempty(data_path) && isfield(child_struct, 'evolution_output') && isstruct(child_struct.evolution_output) && ...
                        isfield(child_struct.evolution_output, 'results') && isstruct(child_struct.evolution_output.results)
                    data_path = char(string(app.pick_field(child_struct.evolution_output.results, {'data_path'}, '')));
                end
                if isempty(data_path) && isfield(child_struct, 'evolution_output') && isstruct(child_struct.evolution_output) && ...
                        isfield(child_struct.evolution_output, 'paths') && isstruct(child_struct.evolution_output.paths)
                    candidate = fullfile(char(string(child_struct.evolution_output.paths.data)), 'results.mat');
                    if exist(candidate, 'file') == 2
                        data_path = candidate;
                    end
                end
                if ~isempty(data_path) && exist(data_path, 'file') == 2
                    try
                        loaded = load(data_path, 'analysis');
                        if isfield(loaded, 'analysis') && isstruct(loaded.analysis)
                            child_summary.analysis = loaded.analysis;
                            return;
                        end
                    catch ME
                        app.append_to_terminal(sprintf('Phase 1 child analysis load warning: %s', ME.message), 'warning');
                    end
                end
            end
            if isstruct(fallback_analysis) && ~isempty(fieldnames(fallback_analysis))
                child_summary.analysis = fallback_analysis;
            end
        end

        function tf = analysis_has_snapshot_cube(~, analysis)
            tf = isstruct(analysis) && ~isempty(fieldnames(analysis)) && ...
                isfield(analysis, 'omega_snaps') && ~isempty(analysis.omega_snaps);
        end

        function plot_tabs = plot_workflow_result_shell_on_tab(app, tab, entry)
            C = app.layout_cfg.colors;
            tab.BackgroundColor = C.bg_dark;
            if ~isempty(tab.Children)
                delete(tab.Children);
            end

            [header_title, header_subtitle, tab_titles] = app.resolve_workflow_shell_spec(entry);
            root = uigridlayout(tab, [2, 1]);
            root.RowHeight = {40, '1x'};
            root.Padding = [4 4 4 4];
            root.RowSpacing = 4;

            header_panel = uipanel(root, 'BorderType', 'none', ...
                'BackgroundColor', 0.82 * C.bg_panel + 0.18 * entry.run_color);
            header_panel.Layout.Row = 1;
            header_grid = uigridlayout(header_panel, [1, 5]);
            header_grid.Padding = [8 2 8 2];
            header_grid.ColumnSpacing = 10;
            header_grid.ColumnWidth = {'fit', '1x', 'fit', 'fit', 'fit'};

            uilabel(header_grid, ...
                'Text', entry.run_badge, ...
                'FontWeight', 'bold', ...
                'FontSize', 11, ...
                'FontColor', [0.07 0.07 0.07], ...
                'BackgroundColor', entry.run_color, ...
                'HorizontalAlignment', 'center');
            uilabel(header_grid, ...
                'Text', sprintf('Run ID: %s', char(string(app.pick_field(app.pick_field(entry, {'metadata'}, struct()), {'run_id'}, '--')))), ...
                'FontColor', C.fg_text, ...
                'FontSize', 11, ...
                'HorizontalAlignment', 'left');
            uilabel(header_grid, ...
                'Text', header_title, ...
                'FontColor', C.fg_text, ...
                'FontSize', 11, ...
                'HorizontalAlignment', 'right');
            uilabel(header_grid, ...
                'Text', header_subtitle, ...
                'FontColor', C.fg_text, ...
                'FontSize', 11, ...
                'HorizontalAlignment', 'right');

            status_label = uilabel(header_grid, ...
                'Text', 'Hydrating...', ...
                'FontWeight', 'bold', ...
                'FontColor', [0.08 0.08 0.08], ...
                'BackgroundColor', [0.72 0.84 0.97], ...
                'HorizontalAlignment', 'center');
            status_label.Layout.Column = 5;

            workflow_tabs = uitabgroup(root);
            workflow_tabs.Layout.Row = 2;
            for i = 1:numel(tab_titles)
                shell_tab = uitab(workflow_tabs, 'Title', char(string(tab_titles{i})));
                app.render_result_tab_placeholder(shell_tab, sprintf('%s will render after Results hydration completes.', char(string(tab_titles{i}))));
            end

            plot_tabs = struct( ...
                'group', workflow_tabs, ...
                'status_label', status_label, ...
                'shell', true);
        end

        function [header_title, header_subtitle, tab_titles] = resolve_workflow_shell_spec(app, entry)
            workflow_kind = lower(char(string(app.pick_field(entry, {'workflow_kind'}, ''))));
            workflow = app.pick_field(entry, {'workflow'}, struct());
            switch workflow_kind
                case 'mesh_convergence_study'
                    header_title = 'Mesh Convergence Workflow';
                    header_subtitle = 'FD + Spectral';
                    tab_titles = {'Finite Difference', 'Spectral', 'Combined'};
                case 'phase1_periodic_comparison'
                    header_title = 'Phase 1 Workflow';
                    header_subtitle = 'FD + Spectral';
                    tab_titles = {'Periodic Comparison'};
                    ic_cases = app.pick_field(app.pick_field(workflow, {'ic_study'}, struct()), {'cases'}, struct([]));
                    if isstruct(ic_cases) && ~isempty(ic_cases)
                        tab_titles{end + 1} = 'IC Study'; %#ok<AGROW>
                    end
                case 'phase2_boundary_condition_study'
                    header_title = 'Phase 2 Workflow';
                    header_subtitle = 'Boundary-condition scenarios';
                    tab_titles = app.workflow_shell_scenario_titles(workflow, 'Scenario');
                case 'phase3_bathymetry_study'
                    header_title = 'Phase 3 Workflow';
                    header_subtitle = 'Bathymetry scenarios';
                    tab_titles = app.workflow_shell_scenario_titles(workflow, 'Scenario');
                otherwise
                    header_title = 'Workflow Results';
                    header_subtitle = 'Hydrating saved outputs';
                    tab_titles = {'Summary'};
            end
        end

        function tab_titles = workflow_shell_scenario_titles(app, workflow, fallback_prefix)
            if nargin < 3 || isempty(fallback_prefix)
                fallback_prefix = 'Scenario';
            end
            scenarios = app.pick_field(workflow, {'scenarios'}, struct([]));
            tab_titles = cell(1, 0);
            if isstruct(scenarios) && ~isempty(scenarios)
                for i = 1:numel(scenarios)
                    tab_titles{end + 1} = char(string(app.pick_field(scenarios(i), {'scenario_label'}, sprintf('%s %d', fallback_prefix, i)))); %#ok<AGROW>
                end
            end
            if isempty(tab_titles)
                tab_titles = {sprintf('%s 1', fallback_prefix)};
            end
        end

