        function render_mesh_convergence_method_tab(app, tab, child, method_label)
            if ~isempty(tab.Children)
                delete(tab.Children);
            end

            root = uigridlayout(tab, [1, 2]);
            root.RowHeight = {'1x'};
            root.ColumnWidth = {'2x', '1x'};
            root.Padding = [4 4 4 4];
            root.ColumnSpacing = 8;

            ax = uiaxes(root);
            ax.Layout.Row = 1;
            ax.Layout.Column = 1;
            app.style_results_axes(ax);
            proxy = struct('children', struct( ...
                'fd', struct(), ...
                'spectral', struct()));
            if strcmpi(method_label, 'Spectral')
                proxy.children.spectral = child;
            else
                proxy.children.fd = child;
            end
            app.plot_phase1_export_convergence_axis(ax, proxy, false);
            title(ax, sprintf('%s Mesh Convergence', method_label));

            summary = uitextarea(root, 'Editable', 'off', 'BackgroundColor', app.layout_cfg.colors.bg_panel, ...
                'FontColor', app.layout_cfg.colors.fg_text, ...
                'Value', app.phase1_child_summary_lines(child));
            summary.Layout.Row = 1;
            summary.Layout.Column = 2;
        end

