        function populate_phase1_ic_study_method_tab(app, tab, case_entry, method_key, entry)
            method_struct = app.pick_field(case_entry, {lower(char(string(method_key)))}, struct());
            method_summary = app.resolve_phase1_ic_study_stage_summary(method_struct);

            root = uigridlayout(tab, [1, 1]);
            root.RowHeight = {'1x'};
            root.ColumnWidth = {'1x'};
            root.Padding = [4 4 4 4];
            root.RowSpacing = 0;
            root.ColumnSpacing = 0;

            host = uipanel(root, 'BorderType', 'none', 'BackgroundColor', app.layout_cfg.colors.bg_dark);
            host.Layout.Row = 1;
            host.Layout.Column = 1;
            if isstruct(method_summary) && isfield(method_summary, 'analysis') && ...
                    isstruct(method_summary.analysis) && ~isempty(fieldnames(method_summary.analysis))
                app.plot_analysis_on_tab(host, method_summary.analysis, ...
                    app.pick_field(method_summary, {'parameters'}, struct()), ...
                    app.pick_field(method_summary, {'run_config'}, struct()), ...
                    app.pick_field(method_summary, {'metadata'}, struct()), ...
                    app.pick_field(entry, {'monitor_series'}, struct()));
            end
        end

        function lines = phase1_ic_study_case_summary_lines(app, case_entry)
            fd_case = app.pick_field(case_entry, {'fd'}, struct());
            sp_case = app.pick_field(case_entry, {'spectral'}, struct());
            lines = { ...
                sprintf('Case: %s', app.if_empty(app.pick_field(case_entry, {'label'}, ''), '--')); ...
                sprintf('Group: %s', app.if_empty(app.pick_field(case_entry, {'group_label'}, ''), '--')); ...
                sprintf('FD runtime: %s s', app.if_nan_num_fixed(double(app.pick_field(fd_case, {'runtime_wall_s'}, NaN)), '%.3f')); ...
                sprintf('SM runtime: %s s', app.if_nan_num_fixed(double(app.pick_field(sp_case, {'runtime_wall_s'}, NaN)), '%.3f')); ...
                sprintf('FD artifacts: %s', app.if_empty(app.pick_field(fd_case, {'artifact_root'}, ''), '--')); ...
                sprintf('SM artifacts: %s', app.if_empty(app.pick_field(sp_case, {'artifact_root'}, ''), '--')) ...
            };
        end

        function lines = phase1_ic_study_method_summary_lines(app, case_entry, method_key)
            method_token = lower(char(string(method_key)));
            method_struct = app.pick_field(case_entry, {method_token}, struct());
            method_label = 'Finite Difference';
            if strcmpi(method_token, 'spectral')
                method_label = 'Spectral';
            end
            lines = { ...
                sprintf('Case: %s', app.if_empty(app.pick_field(case_entry, {'label'}, ''), '--')); ...
                sprintf('Method: %s', method_label); ...
                sprintf('Mesh: %s', app.phase1_mesh_label(app.pick_field(method_struct, {'selected_mesh'}, struct()))); ...
                sprintf('Runtime: %s s', app.if_nan_num_fixed(double(app.pick_field(method_struct, {'runtime_wall_s'}, NaN)), '%.3f')); ...
                sprintf('Artifacts: %s', app.if_empty(app.pick_field(method_struct, {'artifact_root'}, ''), '--')) ...
            };
        end

        function lines = phase1_child_summary_lines(app, child)
            lines = {'No Phase 1 child summary available.'};
            if ~isstruct(child) || isempty(fieldnames(child))
                return;
            end
            metrics = app.pick_field(child, {'metrics'}, struct());
            mesh = app.pick_field(child, {'selected_mesh'}, struct());
            artifact_root = '';
            if isfield(child, 'evolution_output') && isstruct(child.evolution_output) && ...
                    isfield(child.evolution_output, 'paths') && isstruct(child.evolution_output.paths)
                artifact_root = app.pick_field(child.evolution_output.paths, {'base'}, '');
            end
            lines = { ...
                sprintf('Method: %s', app.pick_field(child, {'method'}, '--')); ...
                sprintf('Mesh: %s', app.phase1_mesh_label(mesh)); ...
                sprintf('Convergence: %s', app.if_empty(app.pick_field(metrics, {'mesh_convergence_verdict'}, ''), '--')); ...
                sprintf('Convergence status: %s', app.if_empty(app.pick_field(metrics, {'mesh_convergence_status'}, ''), '--')); ...
                sprintf('Selection: %s', app.if_empty(app.pick_field(metrics, {'mesh_selection_reason'}, ''), '--')); ...
                sprintf('Final successive error: %s', app.if_nan_num(double(app.pick_field(metrics, {'mesh_final_successive_vorticity_error'}, NaN)))); ...
                sprintf('Tolerance: %s', app.if_nan_num(double(app.pick_field(metrics, {'mesh_tolerance'}, NaN)))); ...
                sprintf('Runtime: %s s', app.if_nan_num_fixed(double(app.pick_field(metrics, {'runtime_wall_s'}, NaN)), '%.3f')); ...
                sprintf('Mismatch L2: %s', app.if_nan_num(double(app.pick_field(metrics, {'cross_method_mismatch_l2'}, NaN)))); ...
                sprintf('Artifacts: %s', app.if_empty(artifact_root, '--')) ...
            };
        end

        function label = phase1_mesh_label(~, mesh)
            label = '--';
            if ~isstruct(mesh) || isempty(fieldnames(mesh))
                return;
            end
            nx = NaN;
            ny = NaN;
            if isfield(mesh, 'Nx'), nx = double(mesh.Nx); end
            if isfield(mesh, 'Ny'), ny = double(mesh.Ny); end
            if isfinite(nx) && isfinite(ny)
                label = sprintf('%dx%d', round(nx), round(ny));
            end
        end

        function render_phase1_combined_tab(app, tab, workflow)
            C = app.layout_cfg.colors;
            if ~isempty(tab.Children)
                delete(tab.Children);
            end

            root = uigridlayout(tab, [2, 2]);
            root.RowHeight = {'1x', '1x'};
            root.ColumnWidth = {'1x', '1x'};
            root.Padding = [6 6 6 6];
            root.RowSpacing = 6;
            root.ColumnSpacing = 6;

            ax_hist = uiaxes(root);
            ax_hist.Layout.Row = 1;
            ax_hist.Layout.Column = 1;
            app.style_results_axes(ax_hist);

            ax_error = uiaxes(root);
            ax_error.Layout.Row = 1;
            ax_error.Layout.Column = 2;
            app.style_results_axes(ax_error);

            ax_ic_runtime = uiaxes(root);
            ax_ic_runtime.Layout.Row = 2;
            ax_ic_runtime.Layout.Column = 1;
            app.style_results_axes(ax_ic_runtime);

            ax_runtime_vs_resolution = uiaxes(root);
            ax_runtime_vs_resolution.Layout.Row = 2;
            ax_runtime_vs_resolution.Layout.Column = 2;
            app.style_results_axes(ax_runtime_vs_resolution);

            app.plot_phase1_history_overlay(ax_hist, workflow);
            app.plot_phase1_convergence_overlay(ax_error, workflow);
            app.plot_phase1_ic_runtime_bars(ax_ic_runtime, workflow);
            app.plot_phase1_runtime_vs_resolution(ax_runtime_vs_resolution, workflow);
        end

        function lines = phase1_combined_summary_lines(app, workflow)
            summary = app.pick_field(app.pick_field(workflow, {'metrics'}, struct()), {'summary'}, struct());
            fd_metrics = app.pick_field(app.pick_field(workflow, {'metrics'}, struct()), {'FD'}, struct());
            sp_metrics = app.pick_field(app.pick_field(workflow, {'metrics'}, struct()), {'Spectral'}, struct());
            lines = { ...
                sprintf('Phase 1: direct FD vs Spectral comparison using explicit method settings'); ...
                sprintf('Mean mismatch L2: %.3e', double(app.pick_field(summary, {'mean_cross_method_mismatch_l2'}, NaN))); ...
                sprintf('FD mismatch L2: %.3e | Spectral mismatch L2: %.3e', ...
                    double(app.pick_field(fd_metrics, {'cross_method_mismatch_l2'}, NaN)), ...
                    double(app.pick_field(sp_metrics, {'cross_method_mismatch_l2'}, NaN))); ...
                sprintf('Mean streamfunction L2: %.3e | Mean velocity-vector L2: %.3e', ...
                    double(app.pick_field(summary, {'mean_cross_method_streamfunction_mismatch_l2'}, NaN)), ...
                    double(app.pick_field(summary, {'mean_cross_method_velocity_vector_mismatch_l2'}, NaN))); ...
                sprintf('Runtime ratio FD/Spectral: %.3f', double(app.pick_field(summary, {'runtime_ratio_fd_over_spectral'}, NaN))); ...
                sprintf('Phase root: %s', app.if_empty(app.pick_field(app.pick_field(workflow, {'combined'}, struct()).paths, {'base'}, ''), '--')) ...
            };
        end

        function plot_phase1_history_overlay(app, ax, workflow)
            cla(ax);
            fd_summary = app.resolve_phase1_child_view_summary(app.pick_field(workflow.children, {'fd'}, struct()));
            sp_summary = app.resolve_phase1_child_view_summary(app.pick_field(workflow.children, {'spectral'}, struct()));
            if ~isfield(fd_summary, 'analysis') || ~isfield(sp_summary, 'analysis')
                title(ax, 'History overlay unavailable');
                return;
            end
            fd_analysis = fd_summary.analysis;
            sp_analysis = sp_summary.analysis;
            fd_diag = ResultsPlotDispatcher.resolve_diagnostics_payload(fd_analysis);
            sp_diag = ResultsPlotDispatcher.resolve_diagnostics_payload(sp_analysis);
            hold(ax, 'on');
            if ~isempty(fd_diag.primary) && ~isempty(fd_diag.primary_time) && numel(fd_diag.primary) == numel(fd_diag.primary_time)
                plot(ax, fd_diag.primary_time(:), fd_diag.primary(:), 'LineWidth', 1.6, 'DisplayName', 'FD KE');
            end
            if ~isempty(sp_diag.primary) && ~isempty(sp_diag.primary_time) && numel(sp_diag.primary) == numel(sp_diag.primary_time)
                plot(ax, sp_diag.primary_time(:), sp_diag.primary(:), '--', 'LineWidth', 1.6, 'DisplayName', 'Spectral KE');
            end
            if ~isempty(fd_diag.secondary) && ~isempty(fd_diag.secondary_time) && numel(fd_diag.secondary) == numel(fd_diag.secondary_time)
                plot(ax, fd_diag.secondary_time(:), fd_diag.secondary(:), ':', 'LineWidth', 1.4, 'DisplayName', 'FD Enstrophy');
            end
            if ~isempty(sp_diag.secondary) && ~isempty(sp_diag.secondary_time) && numel(sp_diag.secondary) == numel(sp_diag.secondary_time)
                plot(ax, sp_diag.secondary_time(:), sp_diag.secondary(:), '-.', 'LineWidth', 1.4, 'DisplayName', 'Spectral Enstrophy');
            end
            hold(ax, 'off');
            legend(ax, 'Location', 'best');
            title(ax, 'Time-history overlays');
            xlabel(ax, 'Time');
            ylabel(ax, 'Magnitude');
        end

        function plot_phase1_convergence_overlay(app, ax, workflow)
            cla(ax);
            hold(ax, 'on');
            error_payload = app.pick_field(workflow, {'combined'}, struct());
            error_payload = app.pick_field(error_payload, {'error_vs_time', 'rmse_vs_time'}, struct());
            time_s = double(app.pick_field(error_payload, {'time_s'}, []));
            if isempty(time_s)
                hold(ax, 'off');
                title(ax, 'Error-vs-time comparison unavailable');
                return;
            end
            plot(ax, time_s, double(app.pick_field(error_payload, {'vorticity_vector_relative_l2_mismatch'}, nan(size(time_s)))), ...
                '-', 'LineWidth', 1.6, 'DisplayName', 'Vorticity L2');
            plot(ax, time_s, double(app.pick_field(error_payload, {'velocity_vector_relative_l2_mismatch'}, nan(size(time_s)))), ...
                '-.', 'LineWidth', 1.5, 'DisplayName', 'Velocity vectors');
            plot(ax, time_s, double(app.pick_field(error_payload, {'streamline_direction_relative_l2_mismatch'}, nan(size(time_s)))), ...
                ':', 'LineWidth', 1.5, 'DisplayName', 'Streamline direction');
            hold(ax, 'off');
            title(ax, 'Error vs Time for Different Metrics');
            xlabel(ax, 'Evolution snapshot time (s)');
            ylabel(ax, 'Relative error');
            legend(ax, 'Location', 'best');
            grid(ax, 'on');
        end

        function plot_phase1_convergence_series(~, ax, child, line_spec, label_text)
            if ~isstruct(child) || ~isfield(child, 'convergence_output') || ...
                    ~isstruct(child.convergence_output) || ~isfield(child.convergence_output, 'results')
                return;
            end
            output = child.convergence_output;
            if ~isfield(output.results, 'run_records') || isempty(output.results.run_records)
                return;
            end
            records = output.results.run_records(:);
            if isfield(records, 'study_stage')
                primary_idx = ~strcmp({records.study_stage}, 'temporal');
                if any(primary_idx)
                    records = records(primary_idx);
                end
            end
            mesh_values = [records.Nx];
            errors = [records.relative_change];
            valid = isfinite(mesh_values) & isfinite(errors);
            if ~any(valid)
                return;
            end
            plot(ax, mesh_values(valid), errors(valid), line_spec, 'DisplayName', label_text, 'LineWidth', 1.5);
        end

        function plot_phase1_ic_runtime_bars(app, ax, workflow)
            cla(ax);
            [labels, data] = app.phase1_ic_runtime_chart_data(workflow);
            if isempty(labels) || isempty(data)
                title(ax, 'IC runtime comparison unavailable');
                return;
            end
            bars = bar(ax, data, 'grouped');
            plot_colors = app.result_plot_colors();
            if numel(bars) >= 1
                bars(1).FaceColor = plot_colors.tertiary;
            end
            if numel(bars) >= 2
                bars(2).FaceColor = [0.23 0.68 0.33];
            end
            ax.XTick = 1:numel(labels);
            ax.XTickLabel = labels;
            ax.XTickLabelRotation = 18;
            xlabel(ax, 'Initial Condition Case');
            ylabel(ax, 'Computational Time (s)');
            title(ax, 'Method Comparison: Time per Initial Condition');
            series_labels = {'FD', 'SM'};
            legend_count = min(numel(bars), numel(series_labels));
            if legend_count > 0
                legend(ax, bars(1:legend_count), series_labels(1:legend_count), 'Location', 'northwest');
            end
            grid(ax, 'on');
        end

        function plot_phase1_runtime_vs_resolution(app, ax, workflow)
            cla(ax);
            [labels, data] = app.phase1_resolution_runtime_chart_data(workflow);
            if isempty(labels) || isempty(data)
