            if numel(bars) >= 1
                bars(1).FaceColor = plot_colors.tertiary;
            end
            if numel(bars) >= 2
                bars(2).FaceColor = [0.23 0.68 0.33];
            end
            ax.XTick = 1:numel(labels);
            ax.XTickLabel = labels;
            ax.YScale = 'log';
            ylabel(ax, 'Computational Time (s)');
            xlabel(ax, 'Resolution $\kappa_N=N_x\times N_y=N^2$', 'Interpreter', 'latex');
            series_labels = {'FD', 'SM'};
            legend_count = min(numel(bars), numel(series_labels));
            if legend_count > 0
                legend(ax, bars(1:legend_count), series_labels(1:legend_count), 'Location', 'northwest');
            end
            title(ax, 'Computational Time vs Resolution');
            grid(ax, 'on');
        end

        function [labels, data] = phase1_ic_runtime_chart_data(app, workflow)
            labels = {};
            data = [];
            metrics = app.pick_field(workflow, {'metrics'}, struct());
            fd_metrics = app.pick_field(metrics, {'FD'}, struct());
            sp_metrics = app.pick_field(metrics, {'Spectral'}, struct());
            ic_study = app.pick_field(workflow, {'ic_study'}, struct());
            baseline_case_id = app.pick_field(ic_study, {'baseline_case_id'}, 'baseline_elliptic_single');
            baseline_label = app.phase1_publication_case_display_label(baseline_case_id, ...
                app.pick_field(ic_study, {'baseline_label'}, 'Elliptic'));
            labels = {baseline_label};
            data = [ ...
                double(app.pick_field(fd_metrics, {'runtime_wall_s'}, NaN)), ...
                double(app.pick_field(sp_metrics, {'runtime_wall_s'}, NaN))];
            cases = app.pick_field(ic_study, {'cases'}, struct([]));
            if isstruct(cases) && ~isempty(cases)
                for i = 1:numel(cases)
                    labels{end + 1} = app.phase1_publication_case_display_label( ...
                        app.pick_field(cases(i), {'case_id'}, sprintf('case_%02d', i)), ...
                        app.pick_field(cases(i), {'display_label', 'label'}, sprintf('Case %d', i))); %#ok<AGROW>
                    fd_case = app.pick_field(cases(i), {'fd'}, struct());
                    sp_case = app.pick_field(cases(i), {'spectral'}, struct());
                    data(end + 1, :) = [ ... %#ok<AGROW>
                        double(app.pick_field(fd_case, {'runtime_wall_s'}, NaN)), ...
                        double(app.pick_field(sp_case, {'runtime_wall_s'}, NaN))];
                end
            end
        end

