        function [labels, data] = phase1_resolution_runtime_chart_data(app, workflow)
            labels = {};
            data = [];
            [fd_mesh, fd_runtime] = app.phase1_resolution_runtime_series(app.pick_field(app.pick_field(workflow, {'children'}, struct()), {'fd'}, struct()));
            [sp_mesh, sp_runtime] = app.phase1_resolution_runtime_series(app.pick_field(app.pick_field(workflow, {'children'}, struct()), {'spectral'}, struct()));
            common_mesh = unique([fd_mesh(:); sp_mesh(:)]).';
            common_mesh = common_mesh(isfinite(common_mesh));
            if isempty(common_mesh)
                return;
            end
            labels = arrayfun(@(n) sprintf('%d', round(n)), common_mesh, 'UniformOutput', false);
            data = nan(numel(common_mesh), 2);
            for i = 1:numel(common_mesh)
                fd_idx = find(fd_mesh == common_mesh(i), 1, 'first');
                sp_idx = find(sp_mesh == common_mesh(i), 1, 'first');
                if ~isempty(fd_idx)
                    data(i, 1) = fd_runtime(fd_idx);
                end
                if ~isempty(sp_idx)
                    data(i, 2) = sp_runtime(sp_idx);
                end
            end
        end

        function [mesh_values, runtime_values] = phase1_resolution_runtime_series(app, child)
            mesh_values = [];
            runtime_values = [];
            convergence_output = app.pick_field(child, {'convergence_output'}, struct());
            results = app.pick_field(convergence_output, {'results'}, struct());
            records = app.pick_field(results, {'run_records'}, struct([]));
            if ~isstruct(records) || isempty(records)
                return;
            end
            if isfield(records, 'study_stage')
                primary_idx = ~strcmp({records.study_stage}, 'temporal');
                if any(primary_idx)
                    records = records(primary_idx);
                end
            end
            mesh_values = nan(1, numel(records));
            runtime_values = nan(1, numel(records));
            for i = 1:numel(records)
                mesh_values(i) = double(app.pick_field(records(i), {'Nx', 'Ny'}, NaN));
                runtime_values(i) = double(app.pick_field(records(i), {'runtime_wall_s', 'wall_time', 'total_time'}, NaN));
            end
        end

        function autosave_session_result_views(app, idx, summary)
            if idx < 1 || idx > numel(app.session_figures)
                return;
            end
            if nargin < 3 || ~isstruct(summary)
                summary = struct();
            end
            entry = app.session_figures(idx);

            settings = struct();
            if isfield(summary, 'settings') && isstruct(summary.settings)
                settings = summary.settings;
            end
            save_png = false;
            save_pdf = false;
            save_fig = false;
            if isfield(settings, 'figure_save_png')
                save_png = logical(settings.figure_save_png);
            end
            if isfield(settings, 'figure_save_pdf')
                save_pdf = logical(settings.figure_save_pdf);
            end
            if isfield(settings, 'figure_save_fig')
                save_fig = logical(settings.figure_save_fig);
            end
            export_media = false;
            if isfield(settings, 'media') && isstruct(settings.media) && isfield(settings.media, 'enabled')
                export_media = logical(settings.media.enabled);
            end
            if isfield(settings, 'animation_enabled')
                export_media = export_media || logical(settings.animation_enabled);
            end
            if ~(save_png || save_pdf || save_fig)
                if isfield(settings, 'save_figures') && logical(settings.save_figures)
                    save_fig = true;
                    settings.figure_save_png = false;
                    settings.figure_save_pdf = false;
                    settings.figure_save_fig = true;
                elseif ~(export_media || (isfield(entry.parameters, 'create_animations') && logical(entry.parameters.create_animations)))
                    return;
                end
            end

            analysis = entry.analysis;
            if ~isstruct(analysis) || isempty(fieldnames(analysis))
                return;
            end

            paths = struct();
            if isfield(summary, 'paths') && isstruct(summary.paths)
                paths = summary.paths;
            elseif isfield(entry, 'artifacts') && isstruct(entry.artifacts) && ...
                    isfield(entry.artifacts, 'paths') && isstruct(entry.artifacts.paths)
                paths = entry.artifacts.paths;
            end

            [export_targets, paths] = app.resolve_result_view_export_targets(paths);
            if isempty(fieldnames(export_targets)) && ~isfield(paths, 'media_animation')
                return;
            end

            params = entry.parameters;
            run_cfg = entry.run_config;
            meta = entry.metadata;
            packet = ResultsPlotDispatcher.dispatch(analysis, params, run_cfg, meta);
            format_opts = ResultsPlotDispatcher.defaults();
            if isfield(packet, 'format') && isstruct(packet.format)
                format_opts = packet.format;
            end
            snapshot_spec = ResultsPlotDispatcher.get_plot(packet, 'snapshot');
            diag_spec = ResultsPlotDispatcher.get_plot(packet, 'diagnostics');
            plot_labels = resolve_analysis_plot_labels(analysis);

            [x_vec, y_vec, plot_times, domain_resolved] = app.resolve_result_export_axes(analysis, params, snapshot_spec);
            raw_cube = [];
            if isfield(analysis, 'omega_snaps') && ~isempty(analysis.omega_snaps)
                raw_cube = analysis.omega_snaps;
            end

            exported = struct();
            entry_stem = app.sanitize_filename(app.pick_field(paths, {'export_file_stem'}, entry.name));
            [~, entry_stem_no_ext, ~] = fileparts(entry_stem);
            if ~isempty(entry_stem_no_ext)
                entry_stem = entry_stem_no_ext;
            end
            figure_stem_map = app.pick_field(paths, {'figure_stem_map'}, struct());
            if ~isempty(raw_cube) && (save_png || save_pdf || save_fig)
                if ~domain_resolved
                    app.append_to_terminal('Results export warning: snapshot axes could not be resolved, so editable figure exports were skipped for this run.', 'warning');
                else
                t0_str = '0';
                if ~isempty(plot_times)
                    t0_str = sprintf('%.3g', plot_times(1));
                end
                raw_psi_cube = app.extract_streamfunction_snapshot_cube(analysis, size(raw_cube));
                raw_plot_context = app.resolve_result_plot_context(analysis, size(raw_cube, 1), size(raw_cube, 2));
                [raw_u_cube, raw_v_cube] = app.extract_velocity_snapshot_cubes(analysis, size(raw_cube), raw_plot_context);
                raw_wall_cube = app.extract_wall_omega_snapshot_cube(analysis, size(raw_cube));
                raw_plot_mask = raw_plot_context.plot_mask;
                raw_wall_mask = raw_plot_context.wall_mask;
                raw_bathy_profile_x = raw_plot_context.profile_x;
                raw_bathy_profile_y = raw_plot_context.profile_y;
                main_fig = app.create_result_main_quad_figure(raw_cube(:, :, 1), x_vec, y_vec, ...
                    app.extract_cube_snapshot(raw_psi_cube, 1), ...
                    app.extract_cube_snapshot(raw_u_cube, 1), app.extract_cube_snapshot(raw_v_cube, 1), ...
                    snapshot_spec, t0_str, format_opts, raw_plot_mask, raw_bathy_profile_x, raw_bathy_profile_y, ...
                    params, run_cfg);
                base_stem = app.pick_field(figure_stem_map, {'main_plots'}, sprintf('%s_MainPlots', entry_stem));
                base_name = fullfile(export_targets.main_plots, char(string(base_stem)));
                exported.main_plots = ResultsPlotDispatcher.save_figure_bundle(main_fig, base_name, settings);
                app.close_hidden_figure(main_fig);

                gallery_idx = app.resolve_snapshot_indices_for_gallery(params, size(raw_cube, 3), 9);
                gallery_defs = { ...
                    'evolution_3x3', 'evolution', plot_labels.gallery_evolution_title; ...
                    'streamfunction_3x3', 'streamfunction', plot_labels.gallery_secondary_title; ...
                    'velocity_3x3', 'speed', plot_labels.gallery_speed_title; ...
                    'vector_3x3', 'vector', plot_labels.gallery_vector_title; ...
                    'contour_3x3', 'contour', plot_labels.gallery_contour_title; ...
                    'streamlines_3x3', 'streamline', plot_labels.gallery_streamline_title};
                if ~isempty(raw_wall_cube) && ~isempty(raw_wall_mask) && any(raw_wall_mask(:))
                    gallery_defs(end + 1, :) = { ...
                        'wall_vorticity_3x3', 'wall_omega', plot_labels.gallery_wall_omega_title}; %#ok<AGROW>
                end
                for gi = 1:size(gallery_defs, 1)
                    fig_key = gallery_defs{gi, 1};
                    fig_mode = gallery_defs{gi, 2};
                    fig_title = gallery_defs{gi, 3};
                    gallery_omega_cube = raw_cube;
                    gallery_mask = raw_plot_mask;
                    if strcmp(fig_mode, 'wall_omega')
                        gallery_omega_cube = raw_wall_cube;
                        gallery_mask = raw_wall_mask;
                    end
                    gallery_fig = app.create_snapshot_gallery_figure(gallery_omega_cube, raw_psi_cube, raw_u_cube, raw_v_cube, plot_times, x_vec, y_vec, ...
                        gallery_idx, fig_mode, fig_title, gallery_mask, raw_bathy_profile_x, raw_bathy_profile_y, params, run_cfg);
                    target_dir = app.resolve_result_export_target_dir(export_targets, fig_key);
                    if exist(target_dir, 'dir') ~= 7
                        mkdir(target_dir);
                    end
                    base_stem = app.pick_field(figure_stem_map, {fig_key}, sprintf('%s_%s', entry_stem, fig_key));
                    base_name = fullfile(target_dir, char(string(base_stem)));
                    exported.(fig_key) = ResultsPlotDispatcher.save_figure_bundle(gallery_fig, base_name, settings);
                    app.close_hidden_figure(gallery_fig);
                end
                end
            end

            has_time = isfield(analysis, 'time_vec') && ~isempty(analysis.time_vec);
            has_ke = isfield(analysis, 'kinetic_energy') && ~isempty(analysis.kinetic_energy);
            if has_time || has_ke
                diag_fig = app.create_result_diagnostics_figure(analysis, diag_spec, format_opts);
                base_stem = app.pick_field(figure_stem_map, {'diagnostics'}, sprintf('%s_Diagnostics', entry_stem));
                base_name = fullfile(export_targets.diagnostics, char(string(base_stem)));
                exported.diagnostics = ResultsPlotDispatcher.save_figure_bundle(diag_fig, base_name, settings);
                app.close_hidden_figure(diag_fig);
            end

            animation_exports = ResultsAnimationExporter.export_from_analysis(analysis, params, run_cfg, paths, settings);
            app.log_animation_export_status('Results animation', animation_exports);
            collector_exports = app.save_collector_panel_exports(entry, paths, settings, entry_stem);
            sustainability_exports = struct();
            if isfield(summary, 'collector_artifacts') && isstruct(summary.collector_artifacts)
                sustainability_exports = summary.collector_artifacts;
            elseif isfield(entry.artifacts, 'collector_artifacts') && isstruct(entry.artifacts.collector_artifacts)
                sustainability_exports = entry.artifacts.collector_artifacts;
            end

            if ~isfield(app.session_figures(idx).artifacts, 'paths') || ...
                    ~isstruct(app.session_figures(idx).artifacts.paths)
                app.session_figures(idx).artifacts.paths = struct();
            end
            app.session_figures(idx).artifacts.paths = paths;
            app.session_figures(idx).artifacts.figure_exports = exported;
            app.session_figures(idx).artifacts.collector_exports = collector_exports;
            app.session_figures(idx).artifacts.sustainability_exports = sustainability_exports;
            app.session_figures(idx).artifacts.result_view_exports = exported;
            app.session_figures(idx).artifacts.animation_exports = animation_exports;
            app.append_to_terminal(sprintf('Results tab exports saved into canonical figure folders under: %s', ...
                char(string(paths.figures_root))), 'info');
            if isstruct(animation_exports) && isfield(animation_exports, 'combined_mp4') && ~isempty(animation_exports.combined_mp4)
                app.append_to_terminal(sprintf('Results animation MP4 saved to: %s', ...
                    char(string(animation_exports.combined_mp4))), 'info');
            end
            if isstruct(animation_exports) && isfield(animation_exports, 'combined_gif') && ~isempty(animation_exports.combined_gif)
                app.append_to_terminal(sprintf('Results animation GIF saved to: %s', ...
                    char(string(animation_exports.combined_gif))), 'info');
            end
        end

        function autosave_workflow_result_views(app, idx, summary)
            if idx < 1 || idx > numel(app.session_figures)
                return;
            end
            if nargin < 3 || ~isstruct(summary)
                summary = struct();
            end
            entry = app.session_figures(idx);
            if isstruct(summary) && isfield(summary, 'results') && isstruct(summary.results) && ...
                    ~isempty(fieldnames(summary.results))
                entry.results = summary.results;
                app.session_figures(idx).results = summary.results;
            end
            settings = app.resolve_workflow_autosave_settings(entry, summary);
            collector_settings = app.normalize_workflow_export_settings(settings);

            paths = struct();
            if isfield(summary, 'paths') && isstruct(summary.paths)
                paths = summary.paths;
            elseif isfield(entry, 'artifacts') && isstruct(entry.artifacts) && ...
                    isfield(entry.artifacts, 'paths') && isstruct(entry.artifacts.paths)
                paths = entry.artifacts.paths;
            end
            [~, paths] = app.resolve_result_view_export_targets(paths);

            workflow_exports = struct('comparisons_root', char(string(app.pick_field(paths, {'figures_root', 'figures_comparisons'}, ''))), ...
                'stages', struct(), ...
                'publication_failures', repmat(struct('scope', '', 'message', ''), 1, 0));
            collector_fallback_stem = app.pick_field(app.pick_field(entry, {'metadata'}, struct()), {'run_id'}, app.pick_field(entry, {'name'}, 'collector'));
            collector_stem = app.sanitize_filename(app.pick_field(paths, {'export_file_stem'}, collector_fallback_stem));
            collector_exports = struct();
            try
                collector_exports = app.save_collector_panel_exports(entry, paths, collector_settings, collector_stem);
            catch ME
                collector_exports = struct('source_status', struct(), ...
                    'failures', struct('source', 'collector', 'reason', ME.message));
                workflow_exports.publication_failures(end + 1) = struct( ... %#ok<AGROW>
                    'scope', 'collector_exports', ...
                    'message', ME.message);
                app.append_to_terminal(sprintf('Workflow collector autosave warning: %s', ME.message), 'warning');
            end
            sustainability_exports = struct();
            if isfield(summary, 'collector_artifacts') && isstruct(summary.collector_artifacts)
                sustainability_exports = summary.collector_artifacts;
            elseif isfield(entry.artifacts, 'collector_artifacts') && isstruct(entry.artifacts.collector_artifacts)
                sustainability_exports = entry.artifacts.collector_artifacts;
            end

            workflow_kind = lower(char(string(app.pick_field(entry, {'workflow_kind'}, ''))));
            if strcmpi(workflow_kind, 'phase1_periodic_comparison')
                ic_study = app.pick_field(app.pick_field(entry, {'workflow'}, struct()), {'ic_study'}, struct());
                paths.phase1_baseline_case_id = char(string(app.pick_field(ic_study, ...
                    {'baseline_case_id', 'selected_case_id'}, 'baseline_elliptic_single')));
            end
            switch workflow_kind
                case 'mesh_convergence_study'
                    try
                        workflow_exports.stages = app.autosave_mesh_convergence_stage_exports(entry, settings, paths);
                    catch ME
                        workflow_exports.publication_failures(end + 1) = struct( ... %#ok<AGROW>
                            'scope', 'workflow_stage_exports', ...
                            'message', ME.message);
                        app.append_to_terminal(sprintf('Workflow stage autosave warning: %s', ME.message), 'warning');
                    end
                    if ~(isfield(settings, 'workflow_import_preview_only') && logical(settings.workflow_import_preview_only))
                        try
                            workflow_exports.comparisons = app.autosave_mesh_convergence_comparison_exports(entry, summary, settings, paths);
                        catch ME
                            workflow_exports.publication_failures(end + 1) = struct( ... %#ok<AGROW>
                                'scope', 'workflow_comparison_exports', ...
                                'message', ME.message);
                            app.append_to_terminal(sprintf('Workflow comparison autosave warning: %s', ME.message), 'warning');
                        end
                    end
                case 'phase1_periodic_comparison'
                    try
                        workflow_exports.stages = app.autosave_phase1_stage_exports(entry, settings, paths);
                    catch ME
                        workflow_exports.publication_failures(end + 1) = struct( ... %#ok<AGROW>
                            'scope', 'workflow_stage_exports', ...
                            'message', ME.message);
                        app.append_to_terminal(sprintf('Workflow stage autosave warning: %s', ME.message), 'warning');
                    end
                    if ~(isfield(settings, 'workflow_import_preview_only') && logical(settings.workflow_import_preview_only))
                        try
                            workflow_exports.comparisons = app.autosave_phase1_comparison_exports(entry, summary, settings, paths);
                        catch ME
                            workflow_exports.publication_failures(end + 1) = struct( ... %#ok<AGROW>
                                'scope', 'workflow_comparison_exports', ...
                                'message', ME.message);
                            app.append_to_terminal(sprintf('Workflow comparison autosave warning: %s', ME.message), 'warning');
                        end
                    end
                case {'phase2_boundary_condition_study', 'phase3_bathymetry_study'}
                    try
                        workflow_exports.stages = app.autosave_scenario_stage_exports(entry, settings, paths);
                    catch ME
                        workflow_exports.publication_failures(end + 1) = struct( ... %#ok<AGROW>
                            'scope', 'workflow_stage_exports', ...
                            'message', ME.message);
                        app.append_to_terminal(sprintf('Workflow stage autosave warning: %s', ME.message), 'warning');
                    end
            end

            manifest_root = char(string(app.pick_field(paths, {'matlab_data_root', 'data'}, '')));
            manifest_fallback = '';
            if ~isempty(manifest_root)
                manifest_fallback = fullfile(manifest_root, 'artifact_manifest.json');
            end
            manifest_path = char(string(app.pick_field(paths, {'manifest_path'}, manifest_fallback)));
            app.session_figures(idx).artifacts.paths = paths;
            app.session_figures(idx).artifacts.figure_exports = workflow_exports;
            app.session_figures(idx).artifacts.workflow_stage_exports = workflow_exports;
            app.session_figures(idx).artifacts.collector_exports = collector_exports;
            app.session_figures(idx).artifacts.sustainability_exports = sustainability_exports;

            if ~isempty(manifest_path)
                branch_failures = repmat(struct('scope', '', 'message', ''), 1, 0);
                [workflow_exports_payload, branch_failures] = app.sanitize_workflow_manifest_branch( ...
                    'workflow_stage_exports', workflow_exports, branch_failures);
                [collector_exports_payload, branch_failures] = app.sanitize_workflow_manifest_branch( ...
                    'collector_exports', collector_exports, branch_failures);
                [sustainability_exports_payload, branch_failures] = app.sanitize_workflow_manifest_branch( ...
                    'sustainability_exports', sustainability_exports, branch_failures);

                publication_status = app.resolve_workflow_manifest_publication_status( ...
                    workflow_exports_payload, collector_exports_payload, branch_failures);
                manifest_payload = struct( ...
                    'artifact_layout_version', char(string(app.pick_field(paths, {'artifact_layout_version'}, ''))), ...
                    'phase_root', char(string(app.pick_field(paths, {'base'}, ''))), ...
                    'run_settings_path', char(string(app.pick_field(paths, {'run_settings_path'}, ''))), ...
                    'matlab_data_root', char(string(app.pick_field(paths, {'matlab_data_root', 'data'}, ''))), ...
                    'metrics_root', char(string(app.pick_field(paths, {'metrics_root', 'reports'}, ''))), ...
                    'visuals_root', char(string(app.pick_field(paths, {'visuals_root', 'figures_root'}, ''))), ...
                    'publication_status', publication_status, ...
                    'publication_failures', branch_failures, ...
                    'workflow_stage_exports', workflow_exports_payload, ...
                    'collector_exports', collector_exports_payload, ...
                    'sustainability_exports', sustainability_exports_payload);
                try
                    app.write_json_text_file(manifest_path, app.make_workflow_manifest_json_safe(manifest_payload));
                catch ME
                    manifest_failures = [branch_failures, struct('scope', 'manifest_write', 'message', ME.message)];
                    fallback_payload = rmfield(manifest_payload, intersect(fieldnames(manifest_payload), {'workflow_stage_exports', 'collector_exports', 'sustainability_exports'}));
                    fallback_payload.publication_status = 'failed';
                    fallback_payload.publication_failures = manifest_failures;
                    try
                        app.write_json_text_file(manifest_path, app.make_workflow_manifest_json_safe(fallback_payload));
                    catch
                    end
                    app.session_figures(idx).artifacts.manifest_write_error = struct( ...
                        'path', manifest_path, ...
                        'message', ME.message, ...
                        'identifier', ME.identifier);
                    app.append_to_terminal(sprintf('Workflow manifest warning: %s', ME.message), 'warning');
                end
            end
        end

        function [payload_out, failures] = sanitize_workflow_manifest_branch(app, scope, payload_in, failures)
            payload_out = struct();
            if nargin < 4 || ~isstruct(failures)
                failures = repmat(struct('scope', '', 'message', ''), 1, 0);
            end
            if nargin < 3
                return;
            end
            try
                payload_out = app.make_workflow_manifest_json_safe(payload_in);
            catch ME
                failures(end + 1) = struct('scope', char(string(scope)), 'message', ME.message); %#ok<AGROW>
                payload_out = struct('serialization_status', 'failed');
                app.append_to_terminal(sprintf('Workflow manifest warning [%s]: %s', char(string(scope)), ME.message), 'warning');
            end
        end

        function cleaned = make_workflow_manifest_json_safe(app, value)
            if nargin < 2
                cleaned = [];
                return;
            end

            if isempty(value)
                cleaned = value;
                return;
            end

            if isstruct(value)
                cleaned = app.make_workflow_manifest_struct_json_safe(value);
                return;
            end

            if istable(value)
                cleaned = app.make_workflow_manifest_json_safe(table2struct(value));
                return;
            end

            if iscell(value)
                cleaned = cell(size(value));
                for idx = 1:numel(value)
                    cleaned{idx} = app.make_workflow_manifest_json_safe(value{idx});
                end
                return;
            end

            if isstring(value)
                if isscalar(value)
                    cleaned = char(value);
                else
                    cleaned = cellstr(value);
                end
                return;
            end

            if isa(value, 'datetime') || isa(value, 'duration') || isa(value, 'calendarDuration')
                cleaned = app.make_workflow_manifest_json_safe(string(value));
                return;
            end

            if iscategorical(value)
                cleaned = app.make_workflow_manifest_json_safe(string(value));
                return;
            end

            if isa(value, 'containers.Map')
                cleaned = struct( ...
                    'keys', {app.make_workflow_manifest_json_safe(keys(value))}, ...
                    'values', {app.make_workflow_manifest_json_safe(values(value))});
                return;
            end

            if app.is_manifest_excluded_object(value)
                cleaned = struct('serialization_status', 'omitted', 'class', class(value));
                return;
            end

            if isnumeric(value) || islogical(value) || ischar(value)
                cleaned = value;
                return;
            end

            if isobject(value)
                cleaned = app.make_workflow_manifest_json_safe(string(value));
                return;
            end

            cleaned = value;
        end

        function cleaned = make_workflow_manifest_struct_json_safe(app, value)
            if numel(value) > 1
                cleaned_cells = cell(size(value));
                field_union = cell(1, 0);
                for idx = 1:numel(value)
                    cleaned_cells{idx} = app.make_workflow_manifest_struct_json_safe(value(idx));
                    field_union = union(field_union, fieldnames(cleaned_cells{idx}), 'stable');
                end
                template = struct();
                for field_idx = 1:numel(field_union)
                    template.(field_union{field_idx}) = [];
                end
                cleaned = repmat(template, size(value));
                for idx = 1:numel(value)
                    element = cleaned_cells{idx};
                    for field_idx = 1:numel(field_union)
                        field_name = field_union{field_idx};
                        if isfield(element, field_name)
                            cleaned(idx).(field_name) = element.(field_name);
                        end
                    end
                end
                return;
            end

            cleaned = struct();
            field_names = fieldnames(value);
            for field_idx = 1:numel(field_names)
                field_name = field_names{field_idx};
                cleaned.(field_name) = app.make_workflow_manifest_json_safe(value.(field_name));
            end
        end

        function tf = is_manifest_excluded_object(~, value)
            tf = isa(value, 'function_handle') || ...
                isa(value, 'matlab.ui.Figure') || ...
                isa(value, 'matlab.ui.container.GridLayout') || ...
                isa(value, 'matlab.ui.container.Tab') || ...
                isa(value, 'matlab.ui.container.TabGroup') || ...
                isa(value, 'matlab.ui.container.Panel') || ...
                isa(value, 'matlab.ui.control.UIControl') || ...
                isa(value, 'matlab.ui.control.UIAxes') || ...
                isa(value, 'matlab.ui.control.Button') || ...
                isa(value, 'matlab.ui.control.Label') || ...
                isa(value, 'matlab.graphics.axis.Axes') || ...
                isa(value, 'matlab.graphics.chart.Chart') || ...
                isa(value, 'matlab.graphics.primitive.Line') || ...
                isa(value, 'matlab.graphics.primitive.Patch') || ...
                isa(value, 'matlab.graphics.primitive.Surface') || ...
                isa(value, 'matlab.graphics.Graphics');
        end

        function status = resolve_workflow_manifest_publication_status(~, workflow_exports, collector_exports, branch_failures)
            status = 'published';
            if nargin >= 4 && ~isempty(branch_failures)
                status = 'published_with_warnings';
                return;
            end
            workflow_failures = [];
            if nargin >= 2 && isstruct(workflow_exports) && isfield(workflow_exports, 'publication_failures')
                workflow_failures = workflow_exports.publication_failures;
            end
            collector_failures = [];
            if nargin >= 3 && isstruct(collector_exports) && isfield(collector_exports, 'failures')
                collector_failures = collector_exports.failures;
            end
            if ~isempty(workflow_failures) || ~isempty(collector_failures)
                status = 'published_with_warnings';
            end
        end

        function settings = resolve_workflow_autosave_settings(app, entry, summary)
            settings = struct();
            if nargin >= 3 && isstruct(summary) && isfield(summary, 'settings') && isstruct(summary.settings)
                settings = summary.settings;
            end
            if ~isempty(fieldnames(settings))
                return;
            end

            imported_result = false;
            if nargin >= 2 && isstruct(entry) && isfield(entry, 'artifacts') && ...
                    isstruct(entry.artifacts) && isfield(entry.artifacts, 'is_imported')
                imported_result = logical(entry.artifacts.is_imported);
            end
            imported_result = imported_result || ...
                (nargin >= 3 && isstruct(summary) && ( ...
                isfield(summary, 'imported_analysis') || ...
                isfield(summary, 'imported_metadata') || ...
                isfield(summary, 'imported_artifacts')));
            if imported_result
                settings.workflow_import_preview_only = true;
                settings.workflow_preview_frame_cap = 4;
                return;
            end

            workflow_kind = char(string(app.pick_field(entry, {'workflow_kind'}, ...
                app.pick_field(app.pick_field(summary, {'results'}, struct()), {'workflow_kind'}, 'workflow'))));
            app.append_to_terminal(sprintf(['Workflow autosave info: no explicit settings were provided for the completed %s result; ', ...
                'using live export defaults instead of import-preview mode.'], ...
                app.if_empty(workflow_kind, 'workflow')), 'info');
        end

        function stage_exports = autosave_phase1_stage_exports(app, entry, settings, base_paths)
            stage_exports = struct();
            workflow = app.pick_field(entry, {'workflow'}, struct());
            children = app.pick_field(workflow, {'children'}, struct());
            combined = app.pick_field(workflow, {'combined'}, struct());
            ic_study = app.pick_field(workflow, {'ic_study'}, struct());
            stage_paths_base = base_paths;
            stage_paths_base.phase1_baseline_case_id = char(string(app.pick_field(ic_study, ...
                {'baseline_case_id', 'selected_case_id'}, 'baseline_elliptic_single')));
            preview_only = isfield(settings, 'workflow_import_preview_only') && ...
                logical(settings.workflow_import_preview_only);
            if preview_only
                return;
            end
            fd_evolution_summary = app.resolve_phase1_evolution_stage_summary( ...
                app.pick_field(combined, {'fd_view_summary'}, struct()), app.pick_field(children, {'fd'}, struct()));
            spectral_evolution_summary = app.resolve_phase1_evolution_stage_summary( ...
                app.pick_field(combined, {'spectral_view_summary'}, struct()), app.pick_field(children, {'spectral'}, struct()));
            baseline_stage_label = char(string(app.pick_field(ic_study, {'baseline_label'}, 'Elliptic')));
            stage_exports.fd_periodic_evolution = app.export_workflow_stage_summary(entry, ...
                fd_evolution_summary, ...
                settings, stage_paths_base, 'fd_periodic_evolution', sprintf('FD | %s', baseline_stage_label));
            stage_exports.spectral_periodic_evolution = app.export_workflow_stage_summary(entry, ...
                spectral_evolution_summary, ...
                settings, stage_paths_base, 'spectral_periodic_evolution', sprintf('SM | %s', baseline_stage_label));

            cases = app.pick_field(ic_study, {'cases'}, struct([]));
            if ~isstruct(cases) || isempty(cases)
                return;
            end

            for i = 1:numel(cases)
                case_token = app.sanitize_filename(app.pick_field(cases(i), {'case_id'}, sprintf('case_%02d', i)));
                case_label = char(string(app.pick_field(cases(i), {'label'}, sprintf('IC Study %d', i))));
                case_display = app.phase1_publication_case_display_label( ...
                    app.pick_field(cases(i), {'case_id'}, sprintf('case_%02d', i)), case_label);

                fd_method = app.pick_field(cases(i), {'fd'}, struct());
                fd_summary = app.resolve_phase1_ic_study_stage_summary(fd_method);
                fd_field = matlab.lang.makeValidName(sprintf('fd_ic_%s', case_token));
                stage_exports.(fd_field) = app.export_workflow_stage_summary(entry, ...
                    fd_summary, settings, stage_paths_base, sprintf('fd_ic_%s', case_token), ...
                    sprintf('FD | %s', case_display));
                stage_exports.(fd_field).quad_animation = struct( ...
                    'mp4', '', 'gif', '', 'status', 'skipped', 'failure', '', 'media_status', struct());

                spectral_method = app.pick_field(cases(i), {'spectral'}, struct());
                spectral_summary = app.resolve_phase1_ic_study_stage_summary(spectral_method);
                spectral_field = matlab.lang.makeValidName(sprintf('spectral_ic_%s', case_token));
                stage_exports.(spectral_field) = app.export_workflow_stage_summary(entry, ...
                    spectral_summary, settings, stage_paths_base, sprintf('spectral_ic_%s', case_token), ...
                    sprintf('SM | %s', case_display));
                stage_exports.(spectral_field).quad_animation = struct( ...
                    'mp4', '', 'gif', '', 'status', 'skipped', 'failure', '', 'media_status', struct());
            end
        end

        function comparison_exports = autosave_phase1_comparison_exports(app, entry, summary, settings, paths)
            comparison_exports = struct();
            workflow = app.pick_field(entry, {'workflow'}, struct());
            results_payload = app.pick_field(summary, {'results'}, app.pick_field(entry, {'results'}, struct()));
            comparisons_root = char(string(app.pick_field(paths, {'figures_comparisons'}, ...
                fullfile(char(string(app.pick_field(paths, {'visuals_root', 'figures_root'}, ''))), 'Comparisons'))));
            if isempty(comparisons_root)
                return;
            end
            if exist(comparisons_root, 'dir') ~= 7
                mkdir(comparisons_root);
            end

            export_settings = app.normalize_workflow_export_settings(settings);
            export_settings.figure_save_fig = true;

            fig = app.create_phase1_runtime_export_figure(workflow);
            comparison_exports.runtime_per_ic_case = app.save_phase1_comparison_bundle(fig, comparisons_root, ...
                'phase1_runtime_per_ic_case', export_settings);

