        function stage_exports = autosave_mesh_convergence_stage_exports(app, entry, settings, base_paths)
            stage_exports = struct();
            workflow = app.pick_field(entry, {'workflow'}, struct());
            children = app.pick_field(workflow, {'children'}, struct());
            preview_only = isfield(settings, 'workflow_import_preview_only') && ...
                logical(settings.workflow_import_preview_only);
            preview_settings = settings;
            preview_settings.workflow_stage_data_only = true;
            active_settings = settings;
            if preview_only
                active_settings = preview_settings;
            end

            fd_summary = app.resolve_phase1_evolution_stage_summary(struct(), app.pick_field(children, {'fd'}, struct()));
            sp_summary = app.resolve_phase1_evolution_stage_summary(struct(), app.pick_field(children, {'spectral'}, struct()));
            stage_exports.fd_mesh_levels = app.export_workflow_stage_summary(entry, ...
                fd_summary, active_settings, base_paths, 'fd_mesh_levels', 'FD | Selected Mesh');
            if preview_only
                return;
            end
            stage_exports.spectral_mesh_levels = app.export_workflow_stage_summary(entry, ...
                sp_summary, active_settings, base_paths, 'spectral_mesh_levels', 'Spectral | Selected Mesh');
        end

        function comparison_exports = autosave_mesh_convergence_comparison_exports(app, entry, ~, settings, paths)
            comparison_exports = struct();
