        function fig = create_phase1_vortex_export_figure(app, workflow)
            fig = figure('Visible', 'off', 'Color', 'w', 'Units', 'pixels', 'Position', [120 120 760 420]);
            ax = axes(fig); %#ok<LAXES>
            metrics = app.pick_field(workflow, {'metrics'}, struct());
            fd_metrics = app.pick_field(metrics, {'FD'}, struct());
            sp_metrics = app.pick_field(metrics, {'Spectral'}, struct());
            labels = categorical({'Peak Ratio Error', 'Centroid Drift', 'Core Anisotropy Error'});
            labels = reordercats(labels, {'Peak Ratio Error', 'Centroid Drift', 'Core Anisotropy Error'});
            bars = bar(ax, labels, [ ...
                abs(double(app.pick_field(fd_metrics, {'peak_vorticity_ratio'}, NaN)) - 1), ...
                double(app.pick_field(fd_metrics, {'centroid_drift'}, NaN)), ...
                abs(double(app.pick_field(fd_metrics, {'core_anisotropy_final'}, NaN)) - double(app.pick_field(fd_metrics, {'core_anisotropy_initial'}, NaN))); ...
                abs(double(app.pick_field(sp_metrics, {'peak_vorticity_ratio'}, NaN)) - 1), ...
                double(app.pick_field(sp_metrics, {'centroid_drift'}, NaN)), ...
                abs(double(app.pick_field(sp_metrics, {'core_anisotropy_final'}, NaN)) - double(app.pick_field(sp_metrics, {'core_anisotropy_initial'}, NaN)))]', ...
                'grouped');
            if numel(bars) >= 2
                bars(1).DisplayName = 'FD';
                bars(2).DisplayName = 'SM';
            end
            xlabel(ax, 'Metric');
            ylabel(ax, 'Error');
            title(ax, 'Phase 1 Vortex Preservation');
            grid(ax, 'on');
            legend(ax, 'Location', 'best');
        end

