        function plot_phase1_export_convergence_axis(app, ax, workflow, detailed_title)
            if nargin < 4
                detailed_title = false;
            end
            cla(ax);
            hold(ax, 'on');
            app.plot_phase1_export_convergence_series(ax, workflow, 'fd', 'FD', [0.00 0.28 0.72], [0.90 0.35 0.00]);
            app.plot_phase1_export_convergence_series(ax, workflow, 'spectral', 'SM', [0.10 0.58 0.22], [0.68 0.10 0.55]);
            tolerance = double(app.pick_field(app.pick_field(workflow, {'phase_config'}, struct()), {'convergence_tolerance'}, NaN));
            if ~isfinite(tolerance)
                tolerance = double(app.pick_field(app.pick_field(app.pick_field(workflow, {'metrics'}, struct()), {'FD'}, struct()), {'mesh_tolerance'}, NaN));
            end
            if isfinite(tolerance) && tolerance > 0
                yline(ax, tolerance, '--', 'Tolerance (%)', 'Color', [0.35 0.35 0.35], 'LineWidth', 1.2, ...
                    'LabelHorizontalAlignment', 'left', 'HandleVisibility', 'off');
            end
            hold(ax, 'off');
            xlabel(ax, 'Resolution $\kappa_N=N_x=N_y=N$', 'Interpreter', 'latex');
            ylabel(ax, {'Convergence error (\%)', '$\xi_{L_2}$ and $\xi_{|\omega|_{\max}}$'}, 'Interpreter', 'latex');
            if detailed_title
                title(ax, 'Mesh convergence of vorticity error metrics');
            else
                title(ax, 'Mesh Convergence');
            end
            grid(ax, 'on');
            app.apply_phase1_export_convergence_axis_limits(ax);
            legend(ax, 'Location', 'best');
        end

        function plot_phase1_export_convergence_series(app, ax, workflow, method_key, method_label, color_l2, color_abs)
            records = app.phase1_convergence_records_for_export(workflow, method_key);
            if isempty(records)
                return;
            end
            mesh_values = [records.Nx];
            xi_l2 = [records.xi];
            xi_abs = [records.max_vorticity_rel_error_pct];
            valid_l2 = isfinite(mesh_values) & isfinite(xi_l2);
            valid_abs = isfinite(mesh_values) & isfinite(xi_abs);
            if any(valid_l2)
                plot(ax, mesh_values(valid_l2), xi_l2(valid_l2), 'o-', 'LineWidth', 1.4, ...
                    'Color', color_l2, 'MarkerFaceColor', color_l2, 'DisplayName', sprintf('%s L2', method_label));
            end
            if any(valid_abs)
                plot(ax, mesh_values(valid_abs), xi_abs(valid_abs), 's-', 'LineWidth', 1.4, ...
                    'Color', color_abs, 'MarkerFaceColor', color_abs, 'DisplayName', sprintf('%s peak', method_label));
            end
            tolerance = double(app.pick_field(app.pick_field(workflow, {'phase_config'}, struct()), {'convergence_tolerance'}, NaN));
            if isfinite(tolerance)
                joint_idx = find(xi_l2 <= tolerance, 1, 'first');
                if ~isempty(joint_idx) && isfinite(mesh_values(joint_idx))
                    xline(ax, mesh_values(joint_idx), '--', sprintf('%s L2 converged', method_label), ...
                        'Color', color_l2, 'LineWidth', 1.4, 'HandleVisibility', 'off');
                end
            end
        end

        function apply_phase1_export_convergence_axis_limits(~, ax)
            y_values = [];
            for idx = 1:numel(ax.Children)
                child = ax.Children(idx);
                if isprop(child, 'YData')
                    y_values = [y_values, double(child.YData(:)).']; %#ok<AGROW>
                elseif isprop(child, 'Value')
                    y_values = [y_values, double(child.Value)]; %#ok<AGROW>
                end
            end
            y_values = y_values(isfinite(y_values));
            if isempty(y_values)
                return;
            end
            y_min = min(y_values);
            y_max = max(y_values);
            if y_max <= y_min
                pad = max(1.0e-3, abs(y_max) * 0.05 + 1.0e-3);
                lower = y_min - pad;
                if all(y_values >= 0)
                    lower = min(lower, -0.05 * max(abs(y_max), 1.0));
                end
                ylim(ax, [lower, y_max + pad]);
                return;
            end
            pad = 0.08 * (y_max - y_min);
            lower = y_min - pad;
            if all(y_values >= 0)
                lower = min(lower, -0.05 * max(abs(y_max), 1.0));
            end
            ylim(ax, [lower, y_max + pad]);
        end

        function plot_phase1_adaptive_timestep_axis(app, ax, workflow, method_key, method_label)
            %#ok<INUSD>
            fd_records = app.phase1_convergence_records_for_export(workflow, 'fd');
            sp_records = app.phase1_convergence_records_for_export(workflow, 'spectral');
            cla(ax);
            if isempty(fd_records) && isempty(sp_records)
                text(ax, 0.5, 0.5, 'No advective timestep data available.', 'HorizontalAlignment', 'center', 'VerticalAlignment', 'middle');
                axis(ax, 'off');
                return;
            end
            mesh_values = unique([app.local_mesh_values(fd_records), app.local_mesh_values(sp_records)], 'stable');
            mesh_values = mesh_values(isfinite(mesh_values));
            data = nan(numel(mesh_values), 2);
            for i = 1:numel(mesh_values)
                data(i, 1) = app.local_field_for_mesh(fd_records, mesh_values(i), 'dt_adv');
                data(i, 2) = app.local_field_for_mesh(sp_records, mesh_values(i), 'dt_adv');
            end
            bars = bar(ax, data, 'grouped');
            if numel(bars) >= 2
                bars(1).FaceColor = [0.08 0.36 0.78];
                bars(1).DisplayName = 'FD';
                bars(2).FaceColor = [0.88 0.32 0.10];
                bars(2).DisplayName = 'SM';
            end
            ax.XTick = 1:numel(mesh_values);
            ax.XTickLabel = compose('%d', round(mesh_values));
            ax.XTickLabelRotation = 25;
            xlabel(ax, 'Resolution $\kappa_N=N_x=N_y=N$', 'Interpreter', 'latex');
            ylabel(ax, '$\Delta t_{\mathrm{adv}}$ recommendation (s)', 'Interpreter', 'latex');
            title(ax, 'Convergence of the advective timestep recommendation');
            grid(ax, 'on');
            box(ax, 'on');
            legend(ax, 'Location', 'northeast');
        end

        function plot_mesh_convergence_runtime_axis(app, ax, workflow, use_log_y)
            if nargin < 4
                use_log_y = false;
            end
            fd_records = app.phase1_convergence_records_for_export(workflow, 'fd');
            sp_records = app.phase1_convergence_records_for_export(workflow, 'spectral');
            cla(ax);
            if isempty(fd_records) && isempty(sp_records)
                text(ax, 0.5, 0.5, 'No runtime data available.', 'HorizontalAlignment', 'center', 'VerticalAlignment', 'middle');
                axis(ax, 'off');
                return;
            end

            mesh_values = [app.local_mesh_values(fd_records), app.local_mesh_values(sp_records)];
            mesh_values = unique(mesh_values(isfinite(mesh_values)), 'stable');
            if isempty(mesh_values)
                mesh_values = 1:max(numel(fd_records), numel(sp_records));
            end
            labels = compose('%d', round(mesh_values));
            fd_runtime = nan(size(mesh_values));
            sp_runtime = nan(size(mesh_values));
            for i = 1:numel(mesh_values)
                fd_runtime(i) = app.local_runtime_for_mesh(fd_records, mesh_values(i));
                sp_runtime(i) = app.local_runtime_for_mesh(sp_records, mesh_values(i));
            end

            bars = bar(ax, [fd_runtime(:), sp_runtime(:)], 'grouped');
            if numel(bars) >= 2
                bars(1).DisplayName = 'FD';
                bars(2).DisplayName = 'SM';
            end
            ax.XTick = 1:numel(mesh_values);
            ax.XTickLabel = labels;
            xlabel(ax, 'Resolution $\kappa_N=N_x\times N_y=N^2$', 'Interpreter', 'latex');
            ylabel(ax, 'Computational time (s)');
            title(ax, 'Runtime vs Resolution');
            if use_log_y
                set(ax, 'YScale', 'log');
            end
            grid(ax, 'on');
            legend(ax, 'Location', 'northwest');
        end

        function plot_mesh_cfl_dt_adv_axis(app, ax, workflow)
            fd_records = app.phase1_convergence_records_for_export(workflow, 'fd');
            sp_records = app.phase1_convergence_records_for_export(workflow, 'spectral');
            cla(ax);
            mesh_values = unique([app.local_mesh_values(fd_records), app.local_mesh_values(sp_records)], 'stable');
            mesh_values = mesh_values(isfinite(mesh_values));
            if isempty(mesh_values)
                text(ax, 0.5, 0.5, 'No CFL/timestep data available.', 'HorizontalAlignment', 'center', 'VerticalAlignment', 'middle');
                axis(ax, 'off');
                return;
            end
            fd_cfl = nan(size(mesh_values));
            sp_cfl = nan(size(mesh_values));
            fd_dt = nan(size(mesh_values));
            sp_dt = nan(size(mesh_values));
            for i = 1:numel(mesh_values)
                fd_cfl(i) = app.local_field_for_mesh(fd_records, mesh_values(i), 'cfl_adv');
                sp_cfl(i) = app.local_field_for_mesh(sp_records, mesh_values(i), 'cfl_adv');
                fd_dt(i) = app.local_field_for_mesh(fd_records, mesh_values(i), 'dt_adv');
                sp_dt(i) = app.local_field_for_mesh(sp_records, mesh_values(i), 'dt_adv');
            end
            yyaxis(ax, 'left');
            semilogy(ax, mesh_values, fd_cfl, 'o-', 'LineWidth', 1.4, 'Color', [0.00 0.28 0.72], ...
                'MarkerFaceColor', [0.00 0.28 0.72], 'DisplayName', 'FD $C_{\mathrm{adv}}$');
            hold(ax, 'on');
            semilogy(ax, mesh_values, sp_cfl, 's-', 'LineWidth', 1.4, 'Color', [0.10 0.58 0.22], ...
                'MarkerFaceColor', [0.10 0.58 0.22], 'DisplayName', 'SM $C_{\mathrm{adv}}$');
            ylabel(ax, '$C_{\mathrm{adv}}$', 'Interpreter', 'latex');
            yyaxis(ax, 'right');
            semilogy(ax, mesh_values, fd_dt, 'o--', 'LineWidth', 1.4, 'Color', [0.90 0.35 0.00], ...
                'DisplayName', 'FD $\Delta t_{\mathrm{adv}}$');
            semilogy(ax, mesh_values, sp_dt, 's--', 'LineWidth', 1.4, 'Color', [0.68 0.10 0.55], ...
                'DisplayName', 'SM $\Delta t_{\mathrm{adv}}$');
            ylabel(ax, '$\Delta t_{\mathrm{adv}}$ (s)', 'Interpreter', 'latex');
            try
                if numel(ax.YAxis) >= 2
                    ax.YAxis(2).Label.Units = 'normalized';
                    ax.YAxis(2).Label.Position = [1.14, 0.5, 0];
                    ax.YAxis(2).Label.HorizontalAlignment = 'center';
                    ax.YAxis(2).Label.VerticalAlignment = 'middle';
                end
            catch
                % Cosmetic spacing only; keep UI export robust.
            end
            hold(ax, 'off');
            xlabel(ax, 'Resolution $\kappa_N=N_x=N_y=N$', 'Interpreter', 'latex');
            title(ax, 'Advective CFL and timestep vs resolution');
            grid(ax, 'on');
            box(ax, 'on');
            legend(ax, 'Location', 'best', 'Interpreter', 'latex');
        end

        function plot_mesh_convergence_selected_timestep_axis(app, ax, workflow)
            fd_mesh = app.pick_field(app.pick_field(app.pick_field(workflow, {'children'}, struct()), {'fd'}, struct()), {'selected_mesh'}, struct());
            sp_mesh = app.pick_field(app.pick_field(app.pick_field(workflow, {'children'}, struct()), {'spectral'}, struct()), {'selected_mesh'}, struct());
            cla(ax);
            data = [ ...
                double(app.pick_field(fd_mesh, {'dt_adv'}, NaN)); ...
                double(app.pick_field(fd_mesh, {'dt_diff'}, NaN)); ...
                double(app.pick_field(fd_mesh, {'dt_final'}, NaN)); ...
                double(app.pick_field(sp_mesh, {'dt_adv'}, NaN)); ...
                double(app.pick_field(sp_mesh, {'dt_diff'}, NaN)); ...
                double(app.pick_field(sp_mesh, {'dt_final'}, NaN))];
            data = reshape(data, [3, 2]);
            bars = bar(ax, data, 'grouped');
            if numel(bars) >= 2
                bars(1).DisplayName = 'FD';
                bars(2).DisplayName = 'SM';
            end
            ax.XTick = 1:3;
            ax.XTickLabel = {'dt_{adv}', 'dt_{diff}', 'dt_{CFL}'};
            ylabel(ax, 'Timestep value (s)');
            title(ax, 'Selected Mesh Timestep Metrics');
            grid(ax, 'on');
            legend(ax, 'Location', 'best');
        end

