                app.pick_field(sp_metrics, {'kinetic_energy_drift'}, NaN), app.pick_field(sp_metrics, {'enstrophy_drift'}, NaN), app.pick_field(sp_metrics, {'circulation_drift'}, NaN)]', ...
                'grouped');
