                sprintf('Mean vorticity L2: %.3e', double(app.pick_field(summary, {'mean_cross_method_mismatch_l2'}, NaN))); ...
                sprintf('Mean streamfunction L2: %.3e', double(app.pick_field(summary, {'mean_cross_method_streamfunction_mismatch_l2'}, NaN))); ...
                sprintf('Mean speed L2: %.3e', double(app.pick_field(summary, {'mean_cross_method_speed_mismatch_l2'}, NaN))); ...
                sprintf('Mean velocity-vector L2: %.3e', double(app.pick_field(summary, {'mean_cross_method_velocity_vector_mismatch_l2'}, NaN))); ...
                sprintf('Mean streamline-direction L2: %.3e', double(app.pick_field(summary, {'mean_cross_method_streamline_direction_mismatch_l2'}, NaN)))};
