        function plot_mesh_cross_method_field_axis(app, ax, workflow)
            cla(ax);
            summary = app.pick_field(app.pick_field(workflow, {'metrics'}, struct()), {'summary'}, struct());
            values = [ ...
                double(app.pick_field(summary, {'mean_cross_method_speed_mismatch_l2'}, NaN)); ...
                double(app.pick_field(summary, {'mean_cross_method_mismatch_l2'}, NaN)); ...
                double(app.pick_field(summary, {'mean_cross_method_streamfunction_mismatch_l2'}, NaN))];
