                if isfinite(values(idx))
                    text(ax, idx, values(idx), sprintf('%.3g', values(idx)), ...
                        'HorizontalAlignment', 'center', 'VerticalAlignment', 'bottom', ...
                        'FontSize', 9, 'Interpreter', 'none');
