        function records = phase1_convergence_records_for_export(app, workflow, method_key)
            records = struct([]);
            child = app.pick_field(app.pick_field(workflow, {'children'}, struct()), {method_key}, struct());
            output = app.pick_field(child, {'convergence_output'}, struct());
            results = app.pick_field(output, {'results'}, struct());
            raw_records = app.pick_field(results, {'run_records'}, struct([]));
            if ~isstruct(raw_records) || isempty(raw_records)
                return;
            end
            raw_records = raw_records(:);
            if isfield(raw_records, 'study_stage')
                keep_idx = ~strcmp({raw_records.study_stage}, 'temporal');
                if any(keep_idx)
                    raw_records = raw_records(keep_idx);
                end
            end
            records = raw_records;
        end

        function mesh_values = local_mesh_values(~, records)
            mesh_values = [];
            if ~isstruct(records) || isempty(records)
                return;
            end
            if isfield(records, 'Nx')
                mesh_values = double([records.Nx]);
            end
        end

        function runtime_value = local_runtime_for_mesh(~, records, mesh_value)
            runtime_value = NaN;
            if ~isstruct(records) || isempty(records)
                return;
            end
            mesh_series = [];
            if isfield(records, 'Nx')
                mesh_series = double([records.Nx]);
            end
            idx = find(isfinite(mesh_series) & abs(mesh_series - double(mesh_value)) < 1e-9, 1, 'first');
            if isempty(idx)
                return;
            end
            if isfield(records, 'runtime_wall_s')
                runtime_value = double(records(idx).runtime_wall_s);
            end
        end

        function field_value = local_field_for_mesh(~, records, mesh_value, field_name)
            field_value = NaN;
            if ~isstruct(records) || isempty(records) || ~isfield(records, field_name)
                return;
            end
            mesh_series = [];
            if isfield(records, 'Nx')
                mesh_series = double([records.Nx]);
            end
            idx = find(isfinite(mesh_series) & abs(mesh_series - double(mesh_value)) < 1e-9, 1, 'first');
            if isempty(idx)
                return;
            end
            field_value = double(records(idx).(field_name));
        end

        function rmse_payload = phase1_rmse_payload_for_export(app, workflow, results_payload)
            rmse_payload = app.pick_field(results_payload, {'error_vs_time', 'rmse_vs_time'}, struct());
            if isempty(fieldnames(rmse_payload))
                rmse_payload = app.pick_field(workflow, {'manifest'}, struct());
                rmse_payload = app.pick_field(rmse_payload, {'error_vs_time', 'rmse_vs_time'}, struct());
            end
        end

        function plot_phase1_error_metric_tile(app, ax, time_s, series_list, labels, color_rows, title_text, y_label, normalize_series)
            %#ok<INUSD>
            if nargin < 9
                normalize_series = false;
            end
            cla(ax);
            hold(ax, 'on');
            if isempty(time_s)
                text(ax, 0.5, 0.5, 'No error data available.', ...
                    'HorizontalAlignment', 'center', 'VerticalAlignment', 'middle');
                axis(ax, 'off');
                return;
            end
            if isvector(color_rows) && numel(color_rows) == 3
                color_rows = reshape(color_rows, 1, 3);
            end
            for i = 1:numel(series_list)
                color_idx = min(i, size(color_rows, 1));
                series_values = series_list{i};
                if normalize_series
                    finite_values = abs(double(series_values(isfinite(series_values))));
                    if ~isempty(finite_values)
                        scale_value = max(finite_values, [], 'omitnan');
                        if isfinite(scale_value) && scale_value > 0
                            series_values = series_values ./ scale_value;
                        end
                    end
                end
                plot(ax, time_s, series_values, 'LineWidth', 1.6, ...
                    'Color', color_rows(color_idx, :), 'DisplayName', labels{i});
            end
            hold(ax, 'off');
            title(ax, title_text);
            xlabel(ax, 'Evolution snapshot time (s)');
            if iscell(y_label) || (ischar(y_label) && contains(y_label, '$')) || (isstring(y_label) && contains(y_label, "$"))
                ylabel(ax, y_label, 'Interpreter', 'latex');
            else
                ylabel(ax, y_label);
            end
            grid(ax, 'on');
            box(ax, 'on');
            legend(ax, 'Location', 'best');
        end

        function child_summary = resolve_phase1_evolution_stage_summary(app, preferred_summary, child_struct)
            child_summary = struct();
            if isstruct(preferred_summary)
                child_summary = preferred_summary;
            end
            if app.analysis_has_snapshot_cube(app.pick_field(child_summary, {'analysis'}, struct()))
                return;
            end
            child_summary = app.resolve_phase1_child_view_summary(child_struct);
        end

        function child_summary = resolve_phase1_ic_study_stage_summary(app, method_struct)
            child_summary = struct();
            if isstruct(method_struct) && isfield(method_struct, 'view_summary') && isstruct(method_struct.view_summary)
                child_summary = method_struct.view_summary;
            end
            if app.analysis_has_snapshot_cube(app.pick_field(child_summary, {'analysis'}, struct()))
                return;
            end
            if isstruct(method_struct) && isfield(method_struct, 'output') && isstruct(method_struct.output)
                output_results = app.pick_field(method_struct.output, {'results'}, struct());
                fallback_analysis = app.pick_field(output_results, {'analysis'}, struct());
                if ~app.analysis_has_snapshot_cube(fallback_analysis)
                    fallback_analysis = app.load_saved_stage_output_analysis(method_struct.output);
                end
                if app.analysis_has_snapshot_cube(fallback_analysis)
                    child_summary.analysis = fallback_analysis;
                end
                if ~isfield(child_summary, 'results')
                    child_summary.results = output_results;
                end
                if ~isfield(child_summary, 'parameters')
                    child_summary.parameters = app.pick_field(method_struct.output, {'parameters'}, struct());
                end
                if ~isfield(child_summary, 'run_config')
                    child_summary.run_config = app.pick_field(method_struct.output, {'run_config'}, struct());
                end
                if ~isfield(child_summary, 'paths')
                    child_summary.paths = app.pick_field(method_struct.output, {'paths'}, struct());
                end
            end
            if ~isfield(child_summary, 'metadata')
                child_summary.metadata = struct();
            end
            child_summary.metadata.workflow_stage = 'ic_study';
            child_summary.metadata.ic_study_case_label = app.pick_field(method_struct, {'label'}, '');
            child_summary.metadata.ic_study_case_id = app.pick_field(method_struct, {'case_id'}, '');
        end

        function analysis = load_saved_stage_output_analysis(app, output_struct)
            analysis = struct();
            if nargin < 2 || ~isstruct(output_struct)
                return;
            end

            candidate_paths = strings(1, 0);
            results_mat = app.pick_field(app.pick_field(output_struct, {'quick_access'}, struct()), {'results_mat'}, '');
            if strlength(strtrim(string(results_mat))) > 0
                candidate_paths(end + 1) = string(results_mat); %#ok<AGROW>
            end

            data_root = app.pick_field(app.pick_field(output_struct, {'paths'}, struct()), {'data'}, '');
            if strlength(strtrim(string(data_root))) > 0
                candidate_paths(end + 1) = string(fullfile(char(string(data_root)), 'results.mat')); %#ok<AGROW>
            end

            results_path = app.pick_field(output_struct, {'results_path'}, '');
            if strlength(strtrim(string(results_path))) > 0
                candidate_paths(end + 1) = string(results_path); %#ok<AGROW>
            end

            candidate_paths = unique(candidate_paths, 'stable');
            for i = 1:numel(candidate_paths)
                candidate_path = char(candidate_paths(i));
                if isempty(candidate_path) || exist(candidate_path, 'file') ~= 2
                    continue;
                end
                try
                    loaded = load(candidate_path);
                catch
                    continue;
                end
                if isfield(loaded, 'analysis') && isstruct(loaded.analysis) && ...
                        app.analysis_has_snapshot_cube(loaded.analysis)
                    analysis = loaded.analysis;
                    return;
                end
                results_for_save = app.pick_field(loaded, {'ResultsForSave'}, struct());
                saved_analysis = app.pick_field(results_for_save, {'analysis'}, struct());
                if isstruct(saved_analysis) && app.analysis_has_snapshot_cube(saved_analysis)
                    analysis = saved_analysis;
                    return;
                end
                saved_results = app.pick_field(loaded, {'Results'}, struct());
                saved_analysis = app.pick_field(saved_results, {'analysis'}, struct());
                if isstruct(saved_analysis) && app.analysis_has_snapshot_cube(saved_analysis)
                    analysis = saved_analysis;
                    return;
                end
            end
        end

        function quad_export = export_phase1_ic_study_quad_animation(app, child_summary, stage_paths, settings, stage_label)
            quad_export = struct('mp4', '', 'gif', '', 'status', 'skipped', 'failure', '', 'media_status', struct());
            analysis = app.pick_field(child_summary, {'analysis'}, struct());
            if ~app.analysis_has_snapshot_cube(analysis)
                quad_export.status = 'failed';
                quad_export.failure = sprintf('%s quad animation skipped because no snapshot cube was available.', char(string(stage_label)));
                app.append_to_terminal(sprintf('Workflow stage export warning: %s', quad_export.failure), 'warning');
                return;
            end

            params = app.pick_field(child_summary, {'parameters'}, struct());
            run_cfg = app.pick_field(child_summary, {'run_config'}, struct());
            output_root = char(string(app.pick_field(stage_paths, {'visuals_root', 'media_animation_panes', 'figures_root'}, '')));
            stem = sprintf('%s_Quad_Anim', char(string(app.pick_field(stage_paths, {'visual_prefix', 'export_file_stem'}, 'Stage'))));
            settings.animation_format = 'gif';
            settings.animation_export_format = 'gif';
            settings.animation_export_formats = {'gif'};
            if ~isfield(settings, 'media') || ~isstruct(settings.media)
                settings.media = struct();
            end
            settings.media.format = 'gif';
            settings.media.formats = {'gif'};
            quad_artifacts = ResultsAnimationExporter.export_quad_from_analysis(analysis, params, run_cfg, output_root, stem, settings);
            quad_export.mp4 = char(string(app.pick_field(quad_artifacts, {'mp4'}, '')));
            quad_export.gif = char(string(app.pick_field(quad_artifacts, {'gif'}, '')));
            quad_export.media_status = app.pick_field(quad_artifacts, {'media_status'}, struct());
            if (~isempty(quad_export.mp4) && exist(quad_export.mp4, 'file') == 2) || ...
                    (~isempty(quad_export.gif) && exist(quad_export.gif, 'file') == 2)
                if logical(app.pick_field(app.pick_field(quad_artifacts, {'media_status'}, struct()), {'any_failure'}, false))
                    quad_export.status = 'published_with_warnings';
                else
                    quad_export.status = 'published';
                end
            else
                quad_export.status = 'failed';
                quad_export.failure = sprintf('%s quad animation did not emit MP4/GIF outputs.', char(string(stage_label)));
                app.append_to_terminal(sprintf('Workflow stage export warning: %s', quad_export.failure), 'warning');
            end
        end

        function stage_exports = autosave_scenario_stage_exports(app, entry, settings, base_paths)
            stage_exports = struct();
            workflow = app.pick_field(entry, {'workflow'}, struct());
            scenarios = app.pick_field(workflow, {'scenarios'}, struct([]));
            preview_only = isfield(settings, 'workflow_import_preview_only') && ...
                logical(settings.workflow_import_preview_only);
            preview_settings = settings;
            preview_settings.workflow_stage_data_only = true;
            for i = 1:numel(scenarios)
                scenario_id = char(string(app.pick_field(scenarios(i), {'scenario_id', 'bc_id'}, sprintf('scenario_%02d', i))));
                scenario_label = char(string(app.pick_field(scenarios(i), {'scenario_label'}, scenario_id)));
                scenario_token = app.sanitize_filename(sprintf('%02d_%s', i, scenario_id));
                fd_summary = app.resolve_phase2_child_view_summary(app.pick_field(scenarios(i), {'fd'}, struct()));
                sp_summary = app.resolve_phase2_child_view_summary(app.pick_field(scenarios(i), {'spectral'}, struct()));
                active_settings = settings;
                if preview_only
                    active_settings = preview_settings;
                end
                stage_exports.(matlab.lang.makeValidName(sprintf('%s_fd', scenario_token))) = ...
                    app.export_workflow_stage_summary(entry, fd_summary, active_settings, base_paths, ...
                    sprintf('%s_fd', scenario_token), sprintf('%s | FD', scenario_label));
                if preview_only
                    return;
                end
                stage_exports.(matlab.lang.makeValidName(sprintf('%s_spectral', scenario_token))) = ...
                    app.export_workflow_stage_summary(entry, sp_summary, active_settings, base_paths, ...
                    sprintf('%s_spectral', scenario_token), sprintf('%s | Spectral', scenario_label));
            end
        end

        function stage_export = export_workflow_stage_summary(app, parent_entry, child_summary, settings, base_paths, stage_id, stage_label)
            stage_paths = app.build_workflow_stage_paths(base_paths, stage_id);
            stage_export = struct('paths', stage_paths, 'figure_exports', struct(), 'animation_exports', struct(), ...
                'data_exports', struct(), 'status', 'pending', 'failure', '', ...
                'artifact_failures', repmat(struct('artifact', '', 'message', ''), 1, 0));
            if ~isstruct(child_summary) || isempty(fieldnames(child_summary))
                stage_export.status = 'failed';
                stage_export.failure = sprintf('No child summary was available for %s.', char(string(stage_label)));
                app.append_to_terminal(sprintf('Workflow stage export warning: %s', stage_export.failure), 'warning');
                return;
            end
            stage_entry = app.build_workflow_stage_entry(parent_entry, child_summary, stage_label);
            stage_entry.parameters = app.normalize_workflow_stage_parameters(stage_entry.parameters, ...
                app.pick_field(parent_entry, {'parameters'}, struct()));
            stage_export.data_exports = app.save_workflow_stage_data(stage_paths, stage_id, stage_label, child_summary, stage_entry);
            if isfield(settings, 'workflow_stage_data_only') && logical(settings.workflow_stage_data_only)
                stage_export.status = 'data_only';
                return;
            end
            if ~isstruct(stage_entry.analysis) || isempty(fieldnames(stage_entry.analysis))
                stage_export.status = 'failed';
                stage_export.failure = sprintf('Stage analysis payload was empty for %s.', char(string(stage_label)));
                app.append_to_terminal(sprintf('Workflow stage export warning: %s', stage_export.failure), 'warning');
                return;
            end
            stage_settings = app.normalize_workflow_export_settings(settings);
            stage_settings = app.apply_workflow_stage_animation_settings(stage_settings, stage_entry.parameters);
            stage_settings.workflow_minimal_figure_bundle = false;
            stage_settings.workflow_skip_main_plots = true;
            stage_settings.workflow_skip_diagnostics = true;
            stage_settings.workflow_exclude_wall_vorticity = true;
            stage_settings.workflow_requested_gallery_tokens = {'evolution', 'streamfunction', 'speed', 'vector', 'contour', 'streamlines'};
            if strcmpi(char(string(app.pick_field(parent_entry, {'workflow_kind'}, ''))), 'phase1_periodic_comparison')
                stage_settings.figure_save_fig = true;
                stage_settings.figure_save_png = false;
                stage_settings.figure_save_pdf = false;
            end
            if ~isfield(stage_settings, 'media') || ~isstruct(stage_settings.media)
                stage_settings.media = struct();
            end
            workflow_kind = lower(char(string(app.pick_field(parent_entry, {'workflow_kind'}, ''))));
            stage_settings.media.export_panes = true;
            stage_settings.media.export_pane_mp4s = false;
            stage_settings.media.export_pane_gifs = true;
            stage_settings.media.export_combined_mp4 = false;
            stage_settings.media.export_combined_gif = false;
            stage_settings.media.pane_tokens = {'evolution', 'streamfunction', 'speed', 'vector', 'contour'};
            if any(strcmp(workflow_kind, {'phase1_periodic_comparison', 'phase2_boundary_condition_study'}))
                stage_settings.animation_export_resolution_px = [1600, 1200];
                stage_settings.animation_export_dpi = 200;
                stage_settings.animation_export_width_in = 8.0;
                stage_settings.animation_export_height_in = 6.0;
                stage_settings.media.resolution_px = [1600, 1200];
                stage_settings.media.dpi = 200;
                stage_settings.media.width_in = 8.0;
                stage_settings.media.height_in = 6.0;
            end
            if any(strcmp(workflow_kind, {'phase1_periodic_comparison', 'phase2_boundary_condition_study'}))
                stage_settings.animation_format = 'gif';
                stage_settings.animation_export_format = 'gif';
                stage_settings.animation_export_formats = {'gif'};
                stage_settings.media.format = 'gif';
                stage_settings.media.formats = {'gif'};
            end
            expected_media = app.workflow_stage_media_expected(stage_settings);
            if expected_media && ~app.analysis_has_snapshot_cube(stage_entry.analysis)
                stage_export.failure = sprintf('%s is missing snapshot cube data; MP4/GIF export skipped.', ...
                    char(string(stage_label)));
                app.append_to_terminal(sprintf('Workflow stage animation warning: %s', stage_export.failure), 'warning');
            end
            [figure_exports, animation_exports, stage_paths] = app.export_result_entry_view_bundle(stage_entry, stage_settings, stage_paths);
            app.log_animation_export_status(sprintf('Workflow stage %s', char(string(stage_label))), animation_exports);
            if expected_media && app.analysis_has_snapshot_cube(stage_entry.analysis) && ...
                    ~app.workflow_animation_exports_present(animation_exports)
                failure_messages = app.pick_field(app.pick_field(animation_exports, {'media_status'}, struct()), {'failure_messages'}, {});
                if iscell(failure_messages) && ~isempty(failure_messages)
                    app.append_to_terminal(sprintf('Workflow stage animation warning: %s did not emit MP4/GIF artifacts. %s', ...
                        char(string(stage_label)), char(string(strjoin(string(failure_messages), ' | ')))), 'warning');
                else
                    app.append_to_terminal(sprintf('Workflow stage animation warning: %s did not emit MP4/GIF artifacts.', ...
                        char(string(stage_label))), 'warning');
                end
            end
            stage_export.artifact_failures = app.collect_workflow_stage_artifact_failures( ...
                stage_label, figure_exports, animation_exports, stage_settings);
            if ~isempty(stage_export.artifact_failures)
                artifact_messages = string({stage_export.artifact_failures.message});
                artifact_messages = artifact_messages(strlength(strtrim(artifact_messages)) > 0);
                if ~isempty(artifact_messages)
                    if isempty(stage_export.failure)
                        stage_export.failure = char(strjoin(artifact_messages, ' | '));
                    else
                        stage_export.failure = sprintf('%s | %s', stage_export.failure, char(strjoin(artifact_messages, ' | ')));
                    end
                end
            end
            stage_export.paths = stage_paths;
            stage_export.figure_exports = figure_exports;
            stage_export.animation_exports = animation_exports;
            if isempty(stage_export.failure)
                stage_export.status = 'published';
            else
                stage_export.status = 'published_with_warnings';
            end
        end

        function params = normalize_workflow_stage_parameters(app, params, fallback_params)
            if nargin < 2 || ~isstruct(params)
                params = struct();
            end
            if nargin < 3 || ~isstruct(fallback_params)
                fallback_params = struct();
            end
            plot_count = app.workflow_numeric_field(params, fallback_params, {'num_plot_snapshots'}, 9);
            animation_count = app.workflow_numeric_field(params, fallback_params, ...
                {'animation_num_frames', 'num_animation_frames', 'animation_frame_count'}, NaN);
            runtime_count = app.workflow_numeric_field(params, fallback_params, {'num_snapshots'}, plot_count);
            params.num_plot_snapshots = max(1, round(plot_count));
            if isfinite(animation_count)
                params.animation_num_frames = max(2, round(animation_count));
                params.num_animation_frames = params.animation_num_frames;
                runtime_count = max([runtime_count, params.num_plot_snapshots, params.animation_num_frames]);
            else
                runtime_count = max(runtime_count, params.num_plot_snapshots);
            end
            params.num_snapshots = max(1, round(runtime_count));
        end

        function settings = apply_workflow_stage_animation_settings(app, settings, params)
            if nargin < 2 || ~isstruct(settings)
                settings = struct();
            end
            if nargin < 3 || ~isstruct(params)
                params = struct();
            end
            frame_count = app.workflow_numeric_field(params, struct(), ...
                {'animation_num_frames', 'num_animation_frames', 'animation_frame_count', 'num_snapshots'}, NaN);
            if ~isfinite(frame_count)
                return;
            end
            if isfield(settings, 'workflow_preview_frame_cap') && ...
                    isnumeric(settings.workflow_preview_frame_cap) && ...
                    isscalar(settings.workflow_preview_frame_cap) && ...
                    isfinite(settings.workflow_preview_frame_cap)
                frame_count = min(frame_count, double(settings.workflow_preview_frame_cap));
            end
            frame_count = max(2, round(frame_count));
            settings.animation_frame_count = frame_count;
            settings.animation_num_frames = frame_count;
            if ~isfield(settings, 'media') || ~isstruct(settings.media)
                settings.media = struct();
            end
            settings.media.frame_count = frame_count;
            if ~isfield(settings.media, 'gif_min_frame_count') || ~isfinite(double(settings.media.gif_min_frame_count))
                settings.media.gif_min_frame_count = frame_count;
            else
                settings.media.gif_min_frame_count = min(frame_count, max(2, round(double(settings.media.gif_min_frame_count))));
            end
        end

        function requested = workflow_requested_pane_tokens(~, settings)
            requested = {};
            if nargin < 2 || ~isstruct(settings) || ~isfield(settings, 'media') || ...
                    ~isstruct(settings.media) || ~isfield(settings.media, 'pane_tokens') || ...
                    isempty(settings.media.pane_tokens)
                return;
            end

            requested = cellstr(string(settings.media.pane_tokens));
            requested = lower(strtrim(requested(:).'));
            requested = requested(~cellfun(@isempty, requested));
        end

        function requested = workflow_requested_gallery_tokens(app, settings)
            requested = {};
            if nargin >= 2 && isstruct(settings) && isfield(settings, 'workflow_requested_gallery_tokens') && ...
                    ~isempty(settings.workflow_requested_gallery_tokens)
                requested = cellstr(string(settings.workflow_requested_gallery_tokens));
                requested = lower(strtrim(requested(:).'));
                requested = requested(~cellfun(@isempty, requested));
                return;
            end
            requested = app.workflow_requested_pane_tokens(settings);
        end

        function figure_keys = workflow_requested_figure_keys(app, settings)
            requested = app.workflow_requested_gallery_tokens(settings);
            if isempty(requested)
                requested = {'evolution', 'streamfunction', 'speed', 'vector', 'contour', 'streamlines'};
            end
            figure_keys = cell(1, 0);
            for i = 1:numel(requested)
                token = lower(char(string(requested{i})));
                switch token
                    case 'evolution'
                        fig_key = 'evolution_3x3';
                    case 'streamfunction'
                        fig_key = 'streamfunction_3x3';
                    case {'speed', 'velocity'}
                        fig_key = 'velocity_3x3';
                    case 'vector'
                        fig_key = 'vector_3x3';
                    case 'contour'
                        fig_key = 'contour_3x3';
                    case {'streamline', 'streamlines'}
                        fig_key = 'streamlines_3x3';
                    case {'wall_omega', 'wall_vorticity'}
                        fig_key = 'wall_vorticity_3x3';
                    otherwise
                        fig_key = '';
                end
                if ~isempty(fig_key)
                    figure_keys{end + 1} = fig_key; %#ok<AGROW>
                end
            end
            figure_keys = unique(figure_keys, 'stable');
        end

        function gallery_defs = filter_gallery_defs_by_requested_panes(app, gallery_defs, settings)
            if isempty(gallery_defs)
                return;
            end

            requested = app.workflow_requested_gallery_tokens(settings);
            if isempty(requested)
                return;
            end

            keep = false(size(gallery_defs, 1), 1);
            for gi = 1:size(gallery_defs, 1)
                fig_mode = lower(char(string(gallery_defs{gi, 2})));
                aliases = app.gallery_mode_aliases(fig_mode);
                keep(gi) = any(ismember(aliases, requested));
            end
            gallery_defs = gallery_defs(keep, :);
        end

        function aliases = gallery_mode_aliases(~, fig_mode)
            switch lower(char(string(fig_mode)))
                case 'evolution'
                    aliases = {'evolution'};
                case 'streamfunction'
                    aliases = {'streamfunction'};
                case 'speed'
                    aliases = {'speed', 'velocity'};
                case 'vector'
                    aliases = {'vector'};
                case 'contour'
                    aliases = {'contour'};
                case 'streamline'
                    aliases = {'streamline', 'streamlines'};
                case 'wall_omega'
                    aliases = {'wall_omega', 'wall_vorticity'};
                otherwise
                    aliases = {fig_mode};
            end
        end

        function value = workflow_numeric_field(~, primary, secondary, field_names, fallback)
            if nargin < 5
                fallback = NaN;
            end
            value = fallback;
            candidates = {primary, secondary};
            for si = 1:numel(candidates)
                source = candidates{si};
                if ~isstruct(source)
                    continue;
                end
                for fi = 1:numel(field_names)
                    field_name = field_names{fi};
                    if isfield(source, field_name) && isnumeric(source.(field_name)) && ...
                            isscalar(source.(field_name)) && isfinite(source.(field_name))
                        value = double(source.(field_name));
                        return;
                    end
                end
            end
        end

        function tf = workflow_stage_media_expected(~, settings)
            tf = false;
            if isstruct(settings) && isfield(settings, 'media') && isstruct(settings.media) && ...
                    isfield(settings.media, 'enabled')
                tf = logical(settings.media.enabled);
            end
            if isstruct(settings) && isfield(settings, 'animation_enabled')
                tf = tf || logical(settings.animation_enabled);
            end
        end

        function tf = workflow_animation_exports_present(~, animation_exports)
            tf = false;
            if ~isstruct(animation_exports)
                return;
            end
            direct_fields = {'combined_mp4', 'combined_gif'};
            for i = 1:numel(direct_fields)
                if isfield(animation_exports, direct_fields{i}) && ~isempty(animation_exports.(direct_fields{i}))
                    tf = true;
                    return;
                end
            end
            pane_fields = {'pane_mp4s', 'pane_gifs'};
            for i = 1:numel(pane_fields)
                if isfield(animation_exports, pane_fields{i}) && isstruct(animation_exports.(pane_fields{i})) && ...
                        ~isempty(fieldnames(animation_exports.(pane_fields{i})))
                    tf = true;
                    return;
                end
            end
        end

        function failures = collect_workflow_stage_artifact_failures(app, stage_label, figure_exports, animation_exports, settings)
            failures = repmat(struct('artifact', '', 'message', ''), 1, 0);
            required_figure_keys = app.workflow_requested_figure_keys(settings);
            if isempty(required_figure_keys)
                required_figure_keys = {'evolution_3x3'};
            end
            for i = 1:numel(required_figure_keys)
                fig_key = required_figure_keys{i};
                fig_output = app.pick_field(figure_exports, {fig_key}, struct());
                fig_path = char(string(app.pick_field(fig_output, {'fig_path'}, '')));
                if isempty(fig_path) || exist(fig_path, 'file') ~= 2
                    failures(end + 1) = struct( ... %#ok<AGROW>
                        'artifact', fig_key, ...
                        'message', sprintf('%s missing %s .fig output.', ...
                        char(string(stage_label)), app.workflow_gallery_artifact_label(fig_key)));
                    app.append_to_terminal(sprintf('Workflow stage export warning: %s', failures(end).message), 'warning');
                end
            end

            if ~app.workflow_stage_media_expected(settings)
                return;
            end

            requested_tokens = app.workflow_requested_pane_tokens(settings);
            expect_mp4 = isstruct(settings) && isfield(settings, 'media') && isstruct(settings.media) && ...
                isfield(settings.media, 'export_pane_mp4s') && logical(settings.media.export_pane_mp4s);
            expect_gif = isstruct(settings) && isfield(settings, 'media') && isstruct(settings.media) && ...
                isfield(settings.media, 'export_pane_gifs') && logical(settings.media.export_pane_gifs);
            if isempty(requested_tokens) || (~expect_mp4 && ~expect_gif)
                return;
            end
            mp4_outputs = app.pick_field(animation_exports, {'pane_mp4s'}, struct());
            gif_outputs = app.pick_field(animation_exports, {'pane_gifs'}, struct());
            for i = 1:numel(requested_tokens)
                token = char(string(requested_tokens{i}));
                mp4_path = char(string(app.pick_field(mp4_outputs, {token}, '')));
                gif_path = char(string(app.pick_field(gif_outputs, {token}, '')));
                if expect_mp4 && (isempty(mp4_path) || exist(mp4_path, 'file') ~= 2)
                    failures(end + 1) = struct( ... %#ok<AGROW>
                        'artifact', sprintf('%s_mp4', token), ...
                        'message', sprintf('%s missing %s MP4 animation.', ...
                        char(string(stage_label)), app.workflow_pane_artifact_label(token)));
                    app.append_to_terminal(sprintf('Workflow stage export warning: %s', failures(end).message), 'warning');
                end
                if expect_gif && (isempty(gif_path) || exist(gif_path, 'file') ~= 2)
                    failures(end + 1) = struct( ... %#ok<AGROW>
                        'artifact', sprintf('%s_gif', token), ...
                        'message', sprintf('%s missing %s GIF animation.', ...
                        char(string(stage_label)), app.workflow_pane_artifact_label(token)));
                    app.append_to_terminal(sprintf('Workflow stage export warning: %s', failures(end).message), 'warning');
                end
            end
        end

        function label = workflow_gallery_artifact_label(~, fig_key)
            switch lower(char(string(fig_key)))
                case 'evolution_3x3'
                    label = 'Evolution 3x3';
                case 'streamfunction_3x3'
                    label = 'Streamfunction 3x3';
                case 'velocity_3x3'
                    label = 'Velocity 3x3';
                case 'vector_3x3'
                    label = 'Vector 3x3';
                case 'contour_3x3'
                    label = 'Contour 3x3';
                case 'streamlines_3x3'
                    label = 'Streamlines 3x3';
                otherwise
                    label = char(string(fig_key));
            end
        end

        function label = workflow_pane_artifact_label(~, token)
            switch lower(char(string(token)))
                case 'speed'
                    label = 'Velocity';
                case 'streamfunction'
                    label = 'Streamfunction';
                case 'streamlines'
                    label = 'Streamlines';
                case 'contour'
                    label = 'Contour';
                case 'vector'
                    label = 'Vector';
                case 'evolution'
                    label = 'Evolution';
                otherwise
                    label = char(string(token));
            end
        end

        function stage_export = export_phase1_mesh_level_animation(app, parent_entry, child_struct, settings, base_paths, stage_id, stage_label)
            stage_paths = app.build_workflow_stage_paths(base_paths, sprintf('%s_mesh_levels', stage_id));
            stage_export = struct('paths', stage_paths, 'figure_exports', struct(), 'animation_exports', struct(), ...
                'data_exports', struct(), 'status', 'pending', 'failure', '', ...
                'artifact_failures', repmat(struct('artifact', '', 'message', ''), 1, 0));
            payload = app.pick_phase1_convergence_media_payload(child_struct);
            omega_cube = app.pick_field(payload, {'omega_initial_cube'}, []);
            if isempty(omega_cube) || ndims(omega_cube) < 3 || size(omega_cube, 3) < 2
                stage_export.status = 'failed';
                stage_export.failure = sprintf('%s is missing mesh-level initial-state payload.', char(string(stage_label)));
                app.append_to_terminal(sprintf('Workflow stage export warning: %s', stage_export.failure), 'warning');
                return;
            end

            figure_exports = app.save_phase1_mesh_level_stage_artifacts(child_struct, stage_paths, payload);
            named_gif = app.write_phase1_mesh_level_cycle_gif(stage_paths, child_struct, payload, settings);
            stage_export.paths = stage_paths;
            stage_export.figure_exports = figure_exports;
            stage_export.animation_exports = struct( ...
                'mesh_convergence_gif', named_gif, ...
                'frame_count', size(omega_cube, 3));
            if isempty(named_gif) || exist(named_gif, 'file') ~= 2
                stage_export.failure = sprintf('%s missing mesh-cycle GIF output.', char(string(stage_label)));
                stage_export.artifact_failures(end + 1) = struct( ... %#ok<AGROW>
                    'artifact', 'mesh_cycle_gif', ...
                    'message', stage_export.failure);
                stage_export.status = 'published_with_warnings';
                app.append_to_terminal(sprintf('Workflow stage export warning: %s', stage_export.failure), 'warning');
            elseif isfield(figure_exports, 'failures') && ~isempty(figure_exports.failures)
                stage_export.artifact_failures = figure_exports.failures;
                stage_export.failure = char(strjoin(string({figure_exports.failures.message}), ' | '));
                stage_export.status = 'published_with_warnings';
            else
                stage_export.status = 'published';
            end
        end

        function payload = pick_phase1_convergence_media_payload(app, child_struct)
            payload = struct();
            if ~isstruct(child_struct)
                return;
            end
            payload = app.pick_field(child_struct, {'convergence_media'}, struct());
            if isstruct(payload) && ~isempty(fieldnames(payload))
                return;
            end
            convergence_output = app.pick_field(child_struct, {'convergence_output'}, struct());
            if isstruct(convergence_output)
                payload = app.pick_field(app.pick_field(convergence_output, {'results'}, struct()), ...
                    {'mesh_level_animation'}, struct());
            end
        end

        function safe_delete_export_file(~, file_path)
            file_path = char(string(file_path));
            if isempty(file_path)
                return;
            end
            if exist(file_path, 'file') == 2
                delete(file_path);
            end
        end

        function stage_paths = build_workflow_stage_paths(app, base_paths, stage_id)
            stage_token = app.sanitize_filename(stage_id);
            if isempty(stage_token)
                stage_token = 'stage';
            end
            if app.uses_compact_phase_layout(base_paths)
                stage_paths = app.build_compact_phase_stage_paths(base_paths, stage_token);
                return;
            end
            stage_root = char(string(app.pick_field(base_paths, {'figures_root', 'figures'}, '')));
            if isempty(stage_root)
                stage_root = fullfile(char(string(app.pick_field(base_paths, {'base'}, pwd))), 'Figures');
            end
            data_root = char(string(app.pick_field(base_paths, {'data'}, fullfile(char(string(app.pick_field(base_paths, {'base'}, pwd))), 'Data'))));
            stage_paths = base_paths;
            stage_paths.matlab_data_root = data_root;
            stage_paths.visuals_root = stage_root;
            stage_paths.figures_root = stage_root;
            stage_paths.data = data_root;
            stage_paths.figures = stage_root;
            stage_paths.figures_comparisons = stage_root;
            stage_paths.figures_main_plots = stage_root;
            stage_paths.figures_diagnostics = stage_root;
            stage_paths.figures_evolution_root = stage_root;
            stage_paths.figures_evolution_combined = stage_root;
            stage_paths.figures_evolution = stage_root;
            stage_paths.figures_evolution_evolution = stage_paths.figures_evolution;
            stage_paths.figures_streamfunction = stage_root;
            stage_paths.figures_evolution_streamfunction = stage_paths.figures_streamfunction;
            stage_paths.figures_velocity = stage_root;
            stage_paths.figures_evolution_velocity = stage_paths.figures_velocity;
            stage_paths.figures_vector = stage_root;
            stage_paths.figures_evolution_vector = stage_paths.figures_vector;
            stage_paths.figures_contours = stage_root;
            stage_paths.figures_evolution_contour = stage_paths.figures_contours;
            stage_paths.figures_streamlines = stage_root;
            stage_paths.figures_evolution_streamlines = stage_paths.figures_streamlines;
            stage_paths.figures_wall_vorticity = stage_root;
            stage_paths.figures_evolution_wall_vorticity = stage_paths.figures_wall_vorticity;
            stage_paths.figures_collectors_root = stage_root;
            stage_paths.figures_collectors_hwinfo = stage_root;
            stage_paths.figures_collectors_matlab = stage_root;
            stage_paths.figures_collectors_icue = stage_root;
            stage_paths.figures_stages = stage_root;
            stage_paths.media_animation = stage_root;
            stage_paths.media_animation_combined = stage_root;
            stage_paths.media_animation_panes = stage_root;
            stage_paths.media_flatten_pane_dirs = true;
            mkdir_targets = unique({stage_paths.figures_root, stage_paths.data});
            for i = 1:numel(mkdir_targets)
                if exist(mkdir_targets{i}, 'dir') ~= 7
                    mkdir(mkdir_targets{i});
                end
            end
        end

        function tf = uses_compact_phase_layout(app, paths)
            tf = false;
            if nargin < 2 || ~isstruct(paths)
                return;
            end
            layout_version = char(string(app.pick_field(paths, {'artifact_layout_version'}, '')));
            tf = strcmpi(layout_version, 'phase_compact_v1') || strcmpi(layout_version, 'compact_v2') || strcmpi(layout_version, 'compact_v3');
        end

        function tf = uses_compact_v3_layout(app, paths)
            tf = false;
            if nargin < 2 || ~isstruct(paths)
                return;
            end
            layout_version = char(string(app.pick_field(paths, {'artifact_layout_version'}, '')));
            tf = strcmpi(layout_version, 'compact_v3');
        end

        function stage_paths = build_compact_phase_stage_paths(app, base_paths, stage_token)
            descriptor = app.resolve_compact_phase_stage_descriptor(base_paths, stage_token);
            stage_paths = base_paths;
            stage_paths.stage_token = stage_token;
            stage_paths.matlab_data_root = descriptor.data_root;
            stage_paths.visuals_root = descriptor.visuals_root;
            stage_paths.export_file_stem = descriptor.data_prefix;
            stage_paths.animation_base_stem = descriptor.visual_prefix;
            stage_paths.visual_prefix = descriptor.visual_prefix;
            stage_paths.figure_stem_map = app.compact_stage_figure_stem_map(descriptor.visual_prefix);
            stage_paths.pane_media_stem_map = app.compact_stage_media_stem_map(descriptor.visual_prefix);
            stage_paths.mesh_cycle_stem = descriptor.mesh_cycle_stem;
            stage_paths.data = descriptor.data_root;
            stage_paths.metrics_root = descriptor.metrics_root;
            stage_paths.reports = descriptor.metrics_root;
            stage_paths.run_settings_path = char(string(app.pick_field(base_paths, {'run_settings_path'}, '')));
            stage_paths.run_data_workbook_path = char(string(app.pick_field(base_paths, {'run_data_workbook_path'}, '')));
            stage_paths.figures_root = descriptor.visuals_root;
            stage_paths.figures = descriptor.visuals_root;
            stage_paths.figures_comparisons = descriptor.visuals_root;
            stage_paths.figures_main_plots = descriptor.visuals_root;
            stage_paths.figures_diagnostics = descriptor.visuals_root;
            stage_paths.figures_evolution_root = descriptor.visuals_root;
            stage_paths.figures_evolution_combined = descriptor.visuals_root;
            stage_paths.figures_evolution = descriptor.visuals_root;
            stage_paths.figures_evolution_evolution = stage_paths.figures_evolution;
            stage_paths.figures_streamfunction = descriptor.visuals_root;
            stage_paths.figures_evolution_streamfunction = stage_paths.figures_streamfunction;
            stage_paths.figures_velocity = descriptor.visuals_root;
            stage_paths.figures_evolution_velocity = stage_paths.figures_velocity;
            stage_paths.figures_vector = descriptor.visuals_root;
            stage_paths.figures_evolution_vector = stage_paths.figures_vector;
            stage_paths.figures_contours = descriptor.visuals_root;
            stage_paths.figures_evolution_contour = stage_paths.figures_contours;
            stage_paths.figures_streamlines = descriptor.visuals_root;
            stage_paths.figures_evolution_streamlines = stage_paths.figures_streamlines;
            stage_paths.figures_wall_vorticity = descriptor.visuals_root;
            stage_paths.figures_evolution_wall_vorticity = stage_paths.figures_wall_vorticity;
            stage_paths.media_animation = descriptor.visuals_root;
            stage_paths.media_animation_combined = descriptor.visuals_root;
            stage_paths.media_animation_panes = descriptor.visuals_root;
            stage_paths.media_flatten_pane_dirs = true;
            stage_paths.disable_combined_animation_dir = true;
            mkdir_targets = unique({descriptor.data_root, descriptor.metrics_root, descriptor.visuals_root});
            for i = 1:numel(mkdir_targets)
                if exist(mkdir_targets{i}, 'dir') ~= 7
                    mkdir(mkdir_targets{i});
                end
            end
        end

        function descriptor = resolve_compact_phase_stage_descriptor(app, base_paths, stage_token)
            phase_token = lower(char(string(app.pick_field(base_paths, {'phase'}, ''))));
            if isempty(phase_token)
                base_text = lower(char(string(app.pick_field(base_paths, {'base'}, ''))));
                if contains(base_text, [filesep, 'phase1', filesep])
                    phase_token = 'phase1';
                elseif contains(base_text, [filesep, 'phase2', filesep])
                    phase_token = 'phase2';
                elseif contains(base_text, [filesep, 'phase3', filesep])
                    phase_token = 'phase3';
                end
            end
            base_data_root = char(string(app.pick_field(base_paths, {'matlab_data_root', 'data'}, '')));
            base_metrics_root = char(string(app.pick_field(base_paths, {'metrics_root', 'reports'}, '')));
            base_visuals_root = char(string(app.pick_field(base_paths, {'visuals_root', 'figures_root'}, '')));
            descriptor = struct( ...
                'data_root', base_data_root, ...
                'metrics_root', base_metrics_root, ...
                'visuals_root', base_visuals_root, ...
                'data_prefix', stage_token, ...
                'visual_prefix', stage_token, ...
                'mesh_cycle_stem', 'MeshCycle');
            switch phase_token
                case 'phase1'
                    [method_dir, method_prefix] = app.resolve_compact_phase1_method(stage_token);
                    if contains(stage_token, 'mesh_levels')
                        branch_parts = {method_dir};
                        descriptor.data_prefix = sprintf('%s_MeshConvergence', method_prefix);
                        descriptor.visual_prefix = method_prefix;
                        descriptor.mesh_cycle_stem = sprintf('%s_mesh_level_cycle', method_prefix);
                    elseif contains(stage_token, 'convergence')
                        branch_parts = {'Comparisons'};
                        descriptor.data_prefix = sprintf('%s_Convergence', method_prefix);
                        descriptor.visual_prefix = method_prefix;
                        descriptor.mesh_cycle_stem = sprintf('%s_MeshCycle', method_prefix);
                    elseif contains(stage_token, 'periodic_evolution')
                        case_dir = app.phase1_publication_case_folder_name( ...
                            app.pick_field(base_paths, {'phase1_baseline_case_id'}, 'baseline_elliptic_single'));
                        branch_parts = {method_dir, case_dir};
                        descriptor.data_prefix = sprintf('%s_%s', method_prefix, case_dir);
                        descriptor.visual_prefix = descriptor.data_prefix;
                    elseif contains(stage_token, '_ic_')
                        case_dir = app.phase1_publication_case_folder_name(regexprep(stage_token, '^(fd|spectral)_ic_', ''));
                        branch_parts = {method_dir, case_dir};
                        descriptor.data_prefix = app.resolve_compact_phase1_ic_case_prefix(stage_token, method_prefix);
                        descriptor.visual_prefix = descriptor.data_prefix;
                    else
                        branch_parts = {'Comparisons'};
                        descriptor.data_prefix = sprintf('%s_Evolution', method_prefix);
                        descriptor.visual_prefix = method_prefix;
                    end
                case 'meshconvergence'
                    [method_dir, method_prefix] = app.resolve_compact_mesh_method(stage_token);
                    branch_parts = {method_dir};
                    descriptor.data_prefix = sprintf('%s_MeshConvergence', method_prefix);
                    descriptor.visual_prefix = method_prefix;
                    descriptor.mesh_cycle_stem = sprintf('%s_mesh_level_cycle', method_prefix);
                case {'phase2', 'phase3'}
                    [scenario_token, ~, method_prefix] = app.resolve_compact_phase_scenario_stage(stage_token);
                    [~, method_dir, ~] = app.resolve_compact_phase_scenario_stage(stage_token);
                    scenario_dir = app.compact_stage_folder_name(scenario_token);
                    if strcmpi(phase_token, 'phase2')
                        branch_parts = {method_dir, scenario_dir};
                    else
                        branch_parts = {scenario_dir};
                    end
                    descriptor.data_prefix = sprintf('%s_%s', method_prefix, scenario_dir);
                    descriptor.visual_prefix = method_prefix;
                otherwise
                    branch_parts = {app.compact_stage_folder_name(stage_token)};
                end
            if any(strcmpi(phase_token, {'phase1', 'phase2', 'phase3', 'meshconvergence'}))
                descriptor.data_root = base_data_root;
                descriptor.metrics_root = base_metrics_root;
            else
                descriptor.data_root = fullfile(base_data_root, branch_parts{:});
                descriptor.metrics_root = fullfile(base_metrics_root, branch_parts{:});
            end
            descriptor.visuals_root = fullfile(base_visuals_root, branch_parts{:});
        end

        function [method_dir, method_prefix] = resolve_compact_phase1_method(~, stage_token)
            if startsWith(stage_token, 'fd_')
                method_dir = 'FD';
                method_prefix = 'FD';
            elseif startsWith(stage_token, 'spectral_')
                method_dir = 'SM';
                method_prefix = 'SM';
            else
                method_dir = 'Stage';
                method_prefix = 'Stage';
            end
        end

        function [method_dir, method_prefix] = resolve_compact_mesh_method(~, stage_token)
            if startsWith(stage_token, 'fd_')
                method_dir = 'FD';
                method_prefix = 'FD';
            elseif startsWith(stage_token, 'spectral_')
                method_dir = 'Spectral';
                method_prefix = 'SM';
            else
                method_dir = 'Comparisons';
                method_prefix = 'Stage';
            end
        end

        function prefix = resolve_compact_phase1_ic_case_prefix(app, stage_token, method_prefix)
            case_token = regexprep(char(string(stage_token)), '^(fd|spectral)_ic_', '');
            prefix = sprintf('%s_%s', method_prefix, app.phase1_publication_case_prefix_token(case_token));
        end

        function folder_name = phase1_publication_case_folder_name(app, case_id)
            case_id = lower(strtrim(char(string(case_id))));
            switch case_id
                case {'baseline_stretched_single', 'stretched', 'stretched_gaussian'}
                    folder_name = 'Stretched_Gaussian';
                case {'', 'baseline_elliptic_single', 'elliptic', 'elliptical_vortex', 'elliptic_vortex'}
                    folder_name = 'Elliptic';
                case {'taylor_green', 'taylorgreen'}
                    folder_name = 'Taylor_Green';
                otherwise
                    folder_name = app.compact_stage_folder_name(case_id);
            end
        end

        function token = phase1_publication_case_prefix_token(app, case_id)
            token = strrep(app.phase1_publication_case_folder_name(case_id), '_', '');
        end

        function label = phase1_publication_case_display_label(app, case_id, fallback_label)
            case_id = lower(strtrim(char(string(case_id))));
            switch case_id
                case {'baseline_stretched_single', 'stretched', 'stretched_gaussian'}
                    label = 'Stretched Gaussian';
                case {'', 'baseline_elliptic_single', 'elliptic', 'elliptical_vortex', 'elliptic_vortex'}
                    label = 'Elliptic';
                case {'taylor_green', 'taylorgreen'}
                    label = 'Taylor-Green';
                otherwise
                    label = char(string(fallback_label));
                    if isempty(strtrim(label))
                        label = strrep(app.phase1_publication_case_folder_name(case_id), '_', ' ');
                    end
            end
        end

        function [scenario_token, method_dir, method_prefix] = resolve_compact_phase_scenario_stage(~, stage_token)
            stage_token = char(string(stage_token));
            if endsWith(stage_token, '_fd')
                scenario_token = regexprep(stage_token, '_fd$', '');
                method_dir = 'FD';
                method_prefix = 'FD';
            elseif endsWith(stage_token, '_spectral')
                scenario_token = regexprep(stage_token, '_spectral$', '');
                method_dir = 'SM';
                method_prefix = 'SM';
            else
                scenario_token = string(stage_token);
                method_dir = 'Stage';
                method_prefix = 'Stage';
            end
            scenario_token = char(string(regexprep(char(scenario_token), '^_+|_+$', '')));
            if isempty(scenario_token)
                scenario_token = 'scenario';
            end
        end

        function folder_name = compact_stage_folder_name(~, token)
            token = char(string(token));
            token = regexprep(token, '[^a-zA-Z0-9]+', '_');
            token = regexprep(token, '_+', '_');
            token = regexprep(token, '^_+|_+$', '');
            if isempty(token)
                folder_name = 'Stage';
                return;
            end
            parts = split(string(lower(token)), '_');
            for i = 1:numel(parts)
                if strlength(parts(i)) == 0
                    continue;
                end
                part = char(parts(i));
                part(1) = upper(part(1));
                parts(i) = string(part);
            end
            folder_name = char(strjoin(parts, "_"));
        end

        function stem = compact_stage_stem_token(~, token)
            token = char(string(token));
            token = regexprep(token, '[^a-zA-Z0-9]+', '_');
            token = regexprep(token, '_+', '_');
            token = regexprep(token, '^_+|_+$', '');
            if isempty(token)
                stem = 'Stage';
                return;
            end
            parts = split(string(lower(token)), '_');
            parts = parts(strlength(parts) > 0);
            for i = 1:numel(parts)
                part = char(parts(i));
                part(1) = upper(part(1));
                parts(i) = string(part);
            end
            stem = char(strjoin(parts, ''));
        end

        function stem_map = compact_stage_figure_stem_map(~, prefix)
            prefix = char(string(prefix));
            stem_map = struct( ...
                'evolution_3x3', sprintf('%s_Evolution_3x3', prefix), ...
                'streamfunction_3x3', sprintf('%s_Streamfunction_3x3', prefix), ...
                'velocity_3x3', sprintf('%s_Velocity_3x3', prefix), ...
                'vector_3x3', sprintf('%s_Vector_3x3', prefix), ...
                'contour_3x3', sprintf('%s_Contour_3x3', prefix), ...
                'streamlines_3x3', sprintf('%s_Streamlines_3x3', prefix), ...
                'wall_vorticity_3x3', sprintf('%s_WallVorticity_3x3', prefix), ...
                'diagnostics', sprintf('%s_Diagnostics', prefix), ...
                'main_plots', sprintf('%s_MainPlots', prefix));
        end

        function stem_map = compact_stage_media_stem_map(~, prefix)
            prefix = char(string(prefix));
            stem_map = struct( ...
                'evolution', sprintf('%s_Evolution_Anim', prefix), ...
                'contour', sprintf('%s_Contour_Anim', prefix), ...
                'vector', sprintf('%s_Vector_Anim', prefix), ...
                'streamlines', sprintf('%s_Streamlines_Anim', prefix), ...
                'streamfunction', sprintf('%s_Streamfunction_Anim', prefix), ...
                'speed', sprintf('%s_Velocity_Anim', prefix), ...
                'wall_vorticity', sprintf('%s_WallVorticity_Anim', prefix));
        end

        function data_exports = save_workflow_stage_data(app, stage_paths, stage_id, stage_label, child_summary, stage_entry)
            data_exports = struct();
            if app.uses_compact_phase_layout(stage_paths)
                data_exports = app.build_compact_workflow_stage_data_exports(stage_paths, stage_id, stage_label);
                return;
            end
            data_root = char(string(app.pick_field(stage_paths, {'data'}, '')));
            if isempty(data_root)
                return;
            end
            if exist(data_root, 'dir') ~= 7
                mkdir(data_root);
            end
            stage_token = app.sanitize_filename(app.pick_field(stage_paths, {'export_file_stem'}, stage_id));
            if isempty(stage_token)
                stage_token = 'stage';
            end
            payload = app.build_workflow_stage_data_payload(child_summary, stage_entry, stage_id, stage_label);
            payload = filter_graphics_objects(payload);
            mat_path = fullfile(data_root, sprintf('%s_Summary.mat', stage_token));
            json_path = fullfile(data_root, sprintf('%s_Summary.json', stage_token));
            safe_save_mat(mat_path, struct('StageDataForSave', payload));
            app.write_json_text_file(json_path, payload);
            data_exports.mat = mat_path;
            data_exports.json = json_path;
            data_exports.run_settings = char(string(app.pick_field(stage_paths, {'run_settings_path'}, '')));
        end

        function data_exports = build_compact_workflow_stage_data_exports(app, stage_paths, stage_id, stage_label)
            metrics_root = char(string(app.pick_field(stage_paths, {'metrics_root', 'reports'}, '')));
            workbook_path = char(string(app.pick_field(stage_paths, {'run_data_workbook_path'}, '')));
            if isempty(workbook_path) && ~isempty(metrics_root)
                workbook_path = fullfile(metrics_root, 'Run_Data.xlsx');
            end
            data_exports = struct( ...
                'status', 'workbook_only', ...
                'stage_id', char(string(stage_id)), ...
                'stage_label', char(string(stage_label)), ...
                'run_data_workbook', workbook_path, ...
                'phase_workbook_path', workbook_path, ...
                'metrics_root', metrics_root, ...
                'data_root', char(string(app.pick_field(stage_paths, {'data'}, ''))), ...
                'visuals_root', char(string(app.pick_field(stage_paths, {'visuals_root', 'figures_root'}, ''))), ...
                'run_settings', char(string(app.pick_field(stage_paths, {'run_settings_path'}, ''))));
        end

        function figure_exports = save_phase1_mesh_level_stage_artifacts(app, child_struct, stage_paths, payload)
            figure_exports = struct( ...
                'initial_figs', {{}}, ...
                'gallery_figs', {{}}, ...
                'failures', repmat(struct('artifact', '', 'message', ''), 1, 0));
            convergence_results = app.pick_field(app.pick_field(child_struct, {'convergence_output'}, struct()), {'results'}, struct());
            run_records = app.pick_field(convergence_results, {'run_records'}, struct([]));
            stage_summary = app.pick_field(convergence_results, {'stage_summaries'}, table());
            omega_cube = app.pick_field(payload, {'omega_initial_cube'}, []);
            x_vec = app.pick_field(payload, {'x'}, []);
            y_vec = app.pick_field(payload, {'y'}, []);
            if ~isstruct(run_records) || isempty(run_records)
                return;
            end
            n_levels = numel(run_records);
            if ~isempty(omega_cube)
                n_levels = min(n_levels, size(omega_cube, 3));
            end
            for i = 1:n_levels
                record = run_records(i);
                nx = round(app.pick_field(record, {'Nx'}, NaN));
                ny = round(app.pick_field(record, {'Ny'}, nx));
                if ~isfinite(nx), nx = i; end
                if ~isfinite(ny), ny = nx; end
                level_dir_name = sprintf('Level_%02d_%03dx%03d', i, nx, ny);
                data_dir = fullfile(char(string(app.pick_field(stage_paths, {'data'}, ''))), level_dir_name);
                metrics_dir = fullfile(char(string(app.pick_field(stage_paths, {'metrics_root', 'reports'}, ''))), level_dir_name);
                visuals_dir = fullfile(char(string(app.pick_field(stage_paths, {'figures_root'}, ''))), level_dir_name);
                mkdir_targets = unique({data_dir, metrics_dir, visuals_dir});
                for mi = 1:numel(mkdir_targets)
                    if ~isempty(mkdir_targets{mi}) && exist(mkdir_targets{mi}, 'dir') ~= 7
                        mkdir(mkdir_targets{mi});
                    end
                end
                level_prefix = sprintf('%s_L%02d_%03dx%03d', ...
                    char(string(app.pick_field(stage_paths, {'visual_prefix'}, 'Phase1'))), ...
                    i, nx, ny);

                level_payload = struct( ...
                    'mesh_level_index', i, ...
                    'record', record, ...
                    'x', x_vec, ...
                    'y', y_vec);
                if ~isempty(omega_cube)
                    level_payload.initial_omega = omega_cube(:, :, i);
                end
                safe_save_mat(fullfile(data_dir, 'mesh_level_data.mat'), ...
                    struct('MeshLevelDataForSave', filter_graphics_objects(level_payload)), '-v7.3');
                json_payload = rmfield(level_payload, intersect(fieldnames(level_payload), {'initial_omega'}));
                app.write_json_text_file(fullfile(data_dir, 'mesh_level_data.json'), filter_graphics_objects(json_payload));

                if istable(stage_summary) && height(stage_summary) >= i
                    writetable(stage_summary(i, :), fullfile(metrics_dir, 'mesh_level_metrics.csv'));
                else
                    writetable(struct2table(record, 'AsArray', true), fullfile(metrics_dir, 'mesh_level_metrics.csv'));
                end

                if ~isempty(omega_cube)
                    initial_fig_path = fullfile(visuals_dir, 'mesh_level_initial_evolution.fig');
                    app.save_phase1_mesh_level_initial_figure(initial_fig_path, omega_cube(:, :, i), x_vec, y_vec, nx, ny);
                    figure_exports.initial_figs{end + 1} = initial_fig_path; %#ok<AGROW>
                end

                analysis = app.load_phase1_mesh_level_analysis(record, convergence_results);
                if app.analysis_has_snapshot_cube(analysis)
                    gallery_fig_path = fullfile(visuals_dir, sprintf('%s_Evolution_3x3.fig', level_prefix));
                    app.save_phase1_mesh_level_gallery_figure(gallery_fig_path, analysis, nx, ny);
                    figure_exports.gallery_figs{end + 1} = gallery_fig_path; %#ok<AGROW>
                else
                    failure_message = sprintf('Mesh level L%02d %dx%d is missing saved analysis for Evolution_3x3.fig.', i, nx, ny);
                    figure_exports.failures(end + 1) = struct( ... %#ok<AGROW>
                        'artifact', sprintf('%s_Evolution_3x3', level_prefix), ...
                        'message', failure_message);
                    app.append_to_terminal(sprintf('Workflow stage export warning: %s', failure_message), 'warning');
                end
            end
        end

        function analysis = load_phase1_mesh_level_analysis(app, record, convergence_results)
            analysis = struct();
            if nargin < 2 || ~isstruct(record)
                return;
            end
            candidate_paths = strings(1, 0);
            explicit_summary_path = app.pick_field(record, {'mesh_level_summary_path'}, '');
            if strlength(string(strtrim(explicit_summary_path))) > 0
                candidate_paths(end + 1) = string(explicit_summary_path); %#ok<AGROW>
            end
            if nargin >= 3 && isstruct(convergence_results)
                summary_paths = app.pick_field(convergence_results, {'mesh_level_summary_paths'}, {});
                mesh_level_index = round(app.pick_field(record, {'mesh_level_index'}, NaN));
                if iscell(summary_paths) && isfinite(mesh_level_index) && mesh_level_index >= 1 && mesh_level_index <= numel(summary_paths)
                    summary_candidate = string(summary_paths{mesh_level_index});
                    if strlength(strtrim(summary_candidate)) > 0
                        candidate_paths(end + 1) = summary_candidate; %#ok<AGROW>
                    end
                end
            end
            data_path = string(app.pick_field(record, {'data_path'}, ''));
            if strlength(strtrim(data_path)) > 0
                mesh_level_index = round(app.pick_field(record, {'mesh_level_index'}, NaN));
                if isfinite(mesh_level_index)
                    candidate_paths(end + 1) = string(fullfile(fileparts(char(data_path)), sprintf('mesh_level_%02d.mat', mesh_level_index))); %#ok<AGROW>
                end
                candidate_paths(end + 1) = data_path; %#ok<AGROW>
            end
            candidate_paths = unique(candidate_paths, 'stable');

            for i = 1:numel(candidate_paths)
                candidate_path = char(candidate_paths(i));
                if isempty(candidate_path) || exist(candidate_path, 'file') ~= 2
                    continue;
                end
                try
                    loaded = load(candidate_path);
                    summary_analysis = struct();
                    if isfield(loaded, 'results_summary') && isstruct(loaded.results_summary)
                        summary_analysis = app.pick_field(loaded.results_summary, {'analysis'}, ...
                            app.pick_field(app.pick_field(loaded.results_summary, {'results'}, struct()), {'analysis'}, struct()));
                    end
                    if isfield(loaded, 'analysis') && isstruct(loaded.analysis) && ...
                            app.analysis_has_snapshot_cube(loaded.analysis)
                        analysis = loaded.analysis;
                        return;
                    end
                    if isstruct(summary_analysis) && app.analysis_has_snapshot_cube(summary_analysis)
                        analysis = summary_analysis;
                        return;
                    end
                    if isfield(loaded, 'analysis') && isstruct(loaded.analysis)
                        analysis = loaded.analysis;
                    elseif isstruct(summary_analysis) && ~isempty(fieldnames(summary_analysis))
                        analysis = summary_analysis;
                    end
                    if isstruct(analysis) && ~isempty(fieldnames(analysis))
                        return;
                    end
                catch ME
                    app.append_to_terminal(sprintf('Phase 1 mesh-level analysis load warning: %s', ME.message), 'warning');
                end
            end
        end

        function save_phase1_mesh_level_initial_figure(~, output_path, omega_slice, x_vec, y_vec, nx, ny)
            if isempty(output_path) || isempty(omega_slice)
                return;
            end
            fig = figure('Visible', 'off', 'HandleVisibility', 'off', ...
                'Color', [1 1 1], 'MenuBar', 'none', 'ToolBar', 'none', ...
                'Units', 'pixels', 'Position', [140 140 760 620]);
            cleaner = onCleanup(@() delete(fig));
            ax = axes(fig); %#ok<LAXES>
            if isempty(x_vec)
                x_vec = 1:size(omega_slice, 2);
            end
            if isempty(y_vec)
                y_vec = 1:size(omega_slice, 1);
            end
            imagesc(ax, x_vec, y_vec, omega_slice);
            axis(ax, 'equal');
            axis(ax, 'tight');
            set(ax, 'YDir', 'normal');
            colorbar(ax);
            title(ax, sprintf('Evolution | grid = %dx%d', nx, ny), 'Interpreter', 'none');
            xlabel(ax, 'x');
            ylabel(ax, 'y');
            savefig(fig, output_path);
        end

        function save_phase1_mesh_level_gallery_figure(app, output_path, analysis, nx, ny)
            if isempty(output_path) || ~app.analysis_has_snapshot_cube(analysis)
                return;
            end

            omega_cube = double(analysis.omega_snaps);
            psi_cube = app.extract_streamfunction_snapshot_cube(analysis, size(omega_cube));
            plot_context = app.resolve_result_plot_context(analysis, size(omega_cube, 1), size(omega_cube, 2));
            [u_cube, v_cube] = app.extract_velocity_snapshot_cubes(analysis, size(omega_cube), plot_context);
            x_vec = [];
            y_vec = [];
            if isfield(analysis, 'x') && numel(analysis.x) == size(omega_cube, 2)
                x_vec = double(analysis.x(:)).';
            end
            if isfield(analysis, 'y') && numel(analysis.y) == size(omega_cube, 1)
                y_vec = double(analysis.y(:)).';
            end
            if isempty(x_vec)
                lx = double(app.pick_field(analysis, {'Lx'}, size(omega_cube, 2)));
                x_vec = linspace(-lx / 2, lx / 2, size(omega_cube, 2));
            end
            if isempty(y_vec)
                ly = double(app.pick_field(analysis, {'Ly'}, size(omega_cube, 1)));
                y_vec = linspace(-ly / 2, ly / 2, size(omega_cube, 1));
            end
            snap_times = [];
            if isfield(analysis, 'snapshot_times_requested') && numel(analysis.snapshot_times_requested) == size(omega_cube, 3)
                snap_times = double(analysis.snapshot_times_requested(:)).';
            elseif isfield(analysis, 'snapshot_times') && numel(analysis.snapshot_times) == size(omega_cube, 3)
                snap_times = double(analysis.snapshot_times(:)).';
            elseif isfield(analysis, 'time_vec') && numel(analysis.time_vec) == size(omega_cube, 3)
                snap_times = double(analysis.time_vec(:)).';
            end
            gallery_params = struct('num_plot_snapshots', 9);
            gallery_idx = app.resolve_snapshot_indices_for_gallery(gallery_params, size(omega_cube, 3), 9);
            title_text = sprintf('Evolution | grid = %dx%d', nx, ny);
            fig = app.create_snapshot_gallery_figure(omega_cube, psi_cube, u_cube, v_cube, snap_times, x_vec, y_vec, ...
                gallery_idx, 'evolution', title_text, plot_context.plot_mask, ...
                plot_context.profile_x, plot_context.profile_y, struct(), struct());
            cleaner = onCleanup(@() app.close_hidden_figure(fig)); %#ok<NASGU>
            [target_dir, target_stem, ~] = fileparts(output_path);
            save_settings = struct('figure_save_fig', true, 'figure_save_png', false, 'figure_save_pdf', false);
            ResultsPlotDispatcher.save_figure_bundle(fig, fullfile(target_dir, target_stem), save_settings);
        end

        function output_path = write_phase1_mesh_level_cycle_gif(app, stage_paths, child_struct, payload, settings)
            output_path = '';
            omega_cube = app.pick_field(payload, {'omega_initial_cube'}, []);
            if isempty(omega_cube) || ndims(omega_cube) < 3 || size(omega_cube, 3) < 2
                return;
            end

            target_root = char(string(app.pick_field(stage_paths, {'figures_root'}, '')));
            if isempty(target_root)
                return;
            end
            if exist(target_root, 'dir') ~= 7
                mkdir(target_root);
            end

            cycle_stem = char(string(app.pick_field(stage_paths, {'mesh_cycle_stem'}, 'mesh_level_cycle')));
            output_path = fullfile(target_root, sprintf('%s.gif', cycle_stem));
            if exist(output_path, 'file') == 2
                delete(output_path);
            end

            media = app.resolve_phase1_mesh_cycle_media(settings, size(omega_cube, 3));
            x_vec = app.pick_field(payload, {'x'}, linspace(-1, 1, size(omega_cube, 2)));
            y_vec = app.pick_field(payload, {'y'}, linspace(-1, 1, size(omega_cube, 1)));
            run_records = app.pick_field(app.pick_field(app.pick_field(child_struct, {'convergence_output'}, struct()), ...
                {'results'}, struct()), {'run_records'}, struct([]));

            finite_vals = omega_cube(isfinite(omega_cube));
            if isempty(finite_vals)
                cmin = -1;
                cmax = 1;
            else
                cmin = min(finite_vals);
                cmax = max(finite_vals);
                if ~(isfinite(cmin) && isfinite(cmax)) || abs(cmax - cmin) < eps
                    span = max(1, max(abs([cmin, cmax])));
                    cmin = -span;
                    cmax = span;
                end
            end

            fig = figure('Visible', 'off', 'HandleVisibility', 'off', ...
                'Color', [1 1 1], 'MenuBar', 'none', 'ToolBar', 'none', ...
                'Units', 'pixels', 'Position', [160 160 media.resolution_px(1) media.resolution_px(2)], ...
                'PaperPositionMode', 'auto');
            cleaner = onCleanup(@() delete(fig)); %#ok<NASGU>
            ax = axes(fig, 'Units', 'normalized', 'Position', [0.08 0.09 0.72 0.84]); %#ok<LAXES>
            image_handle = imagesc(ax, x_vec, y_vec, omega_cube(:, :, 1));
            set(image_handle, 'AlphaData', double(isfinite(omega_cube(:, :, 1))));
            set(ax, 'YDir', 'normal', 'Box', 'on', 'Layer', 'top');
            axis(ax, 'equal');
            axis(ax, 'tight');
            colormap(ax, turbo);
            clim(ax, [cmin cmax]);
            cb = colorbar(ax);
            if isprop(cb, 'Color')
                cb.Color = [0 0 0];
            end
            if isprop(ax, 'LooseInset')
                ax.LooseInset = [0 0 0 0];
            end

            frame_rgb_sequence = cell(1, size(omega_cube, 3));
            for idx = 1:size(omega_cube, 3)
                [nx, ny] = app.phase1_mesh_level_size_for_index(run_records, idx, size(omega_cube, 2), size(omega_cube, 1));
                set(image_handle, 'CData', omega_cube(:, :, idx), ...
                    'AlphaData', double(isfinite(omega_cube(:, :, idx))));
                title(ax, sprintf('Vorticity Evolution | grid = %dx%d', nx, ny), ...
                    'Interpreter', 'none', 'Color', [0 0 0], 'FontWeight', 'bold', 'FontSize', 14);
                ax.XLabel.String = '';
                ax.YLabel.String = '';
                ax.XTick = [];
                ax.YTick = [];
                ax.XColor = [0 0 0];
                ax.YColor = [0 0 0];
                drawnow;
                frame_rgb_sequence{idx} = frame2im(getframe(fig));
            end

            status = ResultsAnimationExporter.write_frame_sequence_gif(output_path, frame_rgb_sequence, media);
            output_path = char(string(pick_text(status, {'validated_output_path', 'output_path'}, output_path)));
            if exist(output_path, 'file') ~= 2
                output_path = '';
            end
        end

        function media = resolve_phase1_mesh_cycle_media(~, settings, frame_count)
            media = struct( ...
                'fps', 2, ...
                'duration_s', max(1, double(frame_count)), ...
                'resolution_px', [420, 320], ...
                'delay_time_s', 0.5);

            if nargin >= 2 && isstruct(settings)
                if isfield(settings, 'animation_fps') && isnumeric(settings.animation_fps) && isscalar(settings.animation_fps)
                    media.fps = max(1, double(settings.animation_fps));
                end
                if isfield(settings, 'animation_duration_s') && isnumeric(settings.animation_duration_s) && isscalar(settings.animation_duration_s)
                    media.duration_s = max(0.1, double(settings.animation_duration_s));
                end
                if isfield(settings, 'animation_export_resolution_px') && isnumeric(settings.animation_export_resolution_px) && ...
                        numel(settings.animation_export_resolution_px) >= 2
                    media.resolution_px = round(double(settings.animation_export_resolution_px(1:2)));
                end
                if isfield(settings, 'media') && isstruct(settings.media)
                    if isfield(settings.media, 'fps') && isnumeric(settings.media.fps) && isscalar(settings.media.fps)
                        media.fps = max(1, double(settings.media.fps));
                    end
                    if isfield(settings.media, 'duration_s') && isnumeric(settings.media.duration_s) && isscalar(settings.media.duration_s)
                        media.duration_s = max(0.1, double(settings.media.duration_s));
                    end
                    if isfield(settings.media, 'resolution_px') && isnumeric(settings.media.resolution_px) && ...
                            numel(settings.media.resolution_px) >= 2
                        media.resolution_px = round(double(settings.media.resolution_px(1:2)));
                    end
                end
            end

            media.resolution_px = round(max([240, 180], media.resolution_px(:).'));
            media.delay_time_s = max(0.05, media.duration_s / max(1, double(frame_count)));
        end

        function [nx, ny] = phase1_mesh_level_size_for_index(app, run_records, idx, fallback_nx, fallback_ny)
            nx = round(double(fallback_nx));
            ny = round(double(fallback_ny));
            if ~isstruct(run_records) || isempty(run_records) || idx < 1 || idx > numel(run_records)
                return;
            end
            nx_value = round(app.pick_field(run_records(idx), {'Nx'}, nx));
            ny_value = round(app.pick_field(run_records(idx), {'Ny'}, ny));
            if isfinite(nx_value) && nx_value > 0
                nx = nx_value;
            end
            if isfinite(ny_value) && ny_value > 0
                ny = ny_value;
            else
                ny = nx;
            end
        end

        function payload = build_workflow_stage_data_payload(app, child_summary, stage_entry, stage_id, stage_label)
            payload = struct();
            payload.stage_id = char(string(stage_id));
            payload.stage_label = char(string(stage_label));
            payload.view_summary = app.strip_struct_fields(child_summary, {'analysis'});
            payload.parameters = app.pick_field(stage_entry, {'parameters'}, struct());
            payload.run_config = app.pick_field(stage_entry, {'run_config'}, struct());
            payload.metadata = app.pick_field(stage_entry, {'metadata'}, struct());
            payload.analysis_overview = app.build_analysis_overview(app.pick_field(child_summary, {'analysis'}, struct()));
        end

        function overview = build_analysis_overview(~, analysis)
            overview = struct();
            if ~isstruct(analysis) || isempty(fieldnames(analysis))
                return;
            end
            if isfield(analysis, 'omega_snaps') && ~isempty(analysis.omega_snaps)
                overview.snapshot_size = double(size(analysis.omega_snaps));
            end
            if isfield(analysis, 'time_vec') && ~isempty(analysis.time_vec)
                overview.time_samples = double(numel(analysis.time_vec));
                overview.time_start = double(analysis.time_vec(1));
                overview.time_end = double(analysis.time_vec(end));
            elseif isfield(analysis, 'snapshot_times') && ~isempty(analysis.snapshot_times)
                overview.time_samples = double(numel(analysis.snapshot_times));
                overview.time_start = double(analysis.snapshot_times(1));
                overview.time_end = double(analysis.snapshot_times(end));
            end
            if isfield(analysis, 'Nx') && isnumeric(analysis.Nx) && isscalar(analysis.Nx)
                overview.Nx = double(analysis.Nx);
            end
            if isfield(analysis, 'Ny') && isnumeric(analysis.Ny) && isscalar(analysis.Ny)
                overview.Ny = double(analysis.Ny);
            end
            if isfield(analysis, 'Lx') && isnumeric(analysis.Lx) && isscalar(analysis.Lx)
                overview.Lx = double(analysis.Lx);
            end
            if isfield(analysis, 'Ly') && isnumeric(analysis.Ly) && isscalar(analysis.Ly)
                overview.Ly = double(analysis.Ly);
            end
        end

        function stripped = strip_struct_fields(~, value, fields_to_remove)
            stripped = value;
            if ~isstruct(stripped)
                return;
            end
            for i = 1:numel(fields_to_remove)
                if isfield(stripped, fields_to_remove{i})
                    stripped = rmfield(stripped, fields_to_remove{i});
                end
            end
        end

        function animation_exports = promote_workflow_animation_exports(app, animation_exports, target_root)
            target_root = char(string(target_root));
            if isempty(target_root) || exist(target_root, 'dir') ~= 7 || ~isstruct(animation_exports)
                return;
            end
            animation_exports.combined_mp4 = app.promote_export_file(animation_exports, 'combined_mp4', target_root);
            animation_exports.combined_gif = app.promote_export_file(animation_exports, 'combined_gif', target_root);
            animation_exports.pane_mp4s = app.promote_export_struct_files( ...
                app.pick_field(animation_exports, {'pane_mp4s'}, struct()), target_root);
            animation_exports.pane_gifs = app.promote_export_struct_files( ...
                app.pick_field(animation_exports, {'pane_gifs'}, struct()), target_root);
            if isfield(animation_exports, 'media_status') && isstruct(animation_exports.media_status)
                if isfield(animation_exports.media_status, 'combined') && isstruct(animation_exports.media_status.combined)
                    if isfield(animation_exports.media_status.combined, 'mp4') && isstruct(animation_exports.media_status.combined.mp4)
                        animation_exports.media_status.combined.mp4.validated_output_path = animation_exports.combined_mp4;
                    end
                    if isfield(animation_exports.media_status.combined, 'gif') && isstruct(animation_exports.media_status.combined.gif)
                        animation_exports.media_status.combined.gif.validated_output_path = animation_exports.combined_gif;
                    end
                end
                if isfield(animation_exports.media_status, 'panes') && isstruct(animation_exports.media_status.panes)
                    pane_fields = fieldnames(animation_exports.media_status.panes);
                    for i = 1:numel(pane_fields)
                        token = pane_fields{i};
                        if isfield(animation_exports.media_status.panes.(token), 'mp4') && ...
                                isstruct(animation_exports.media_status.panes.(token).mp4) && ...
                                isfield(animation_exports.pane_mp4s, token)
                            animation_exports.media_status.panes.(token).mp4.validated_output_path = ...
                                animation_exports.pane_mp4s.(token);
                        end
                        if isfield(animation_exports.media_status.panes.(token), 'gif') && ...
                                isstruct(animation_exports.media_status.panes.(token).gif) && ...
                                isfield(animation_exports.pane_gifs, token)
                            animation_exports.media_status.panes.(token).gif.validated_output_path = ...
                                animation_exports.pane_gifs.(token);
                        end
                    end
                end
            end
        end

        function exports = promote_export_struct_files(app, exports, target_root)
            if ~isstruct(exports) || isempty(fieldnames(exports))
                return;
            end
            fields = fieldnames(exports);
            for i = 1:numel(fields)
                exports.(fields{i}) = app.promote_export_file(exports, fields{i}, target_root);
            end
        end

        function promoted_path = promote_export_file(~, payload, field_name, target_root)
            promoted_path = '';
            if ~isstruct(payload) || ~isfield(payload, field_name) || isempty(payload.(field_name))
                return;
            end
            source_path = char(string(payload.(field_name)));
            if isempty(source_path) || exist(source_path, 'file') ~= 2
                return;
            end
            source_dir = fileparts(source_path);
            if strcmpi(char(string(source_dir)), char(string(target_root)))
                promoted_path = source_path;
                return;
            end
            [~, stem, ext] = fileparts(source_path);
            target_path = fullfile(target_root, [stem, ext]);
            if exist(target_path, 'file') == 2 && ~strcmpi(source_path, target_path)
                target_path = fullfile(target_root, sprintf('%s__%s%s', ...
                    char(string(field_name)), stem, ext));
            end
            copyfile(source_path, target_path, 'f');
            promoted_path = target_path;
        end

        function write_json_text_file(~, path_value, payload)
            parent_dir = fileparts(char(string(path_value)));
            if ~isempty(parent_dir) && exist(parent_dir, 'dir') ~= 7
                mkdir(parent_dir);
            end
            fid = fopen(path_value, 'w');
            if fid < 0
                error('UIController:WorkflowStageJsonWriteFailed', ...
                    'Could not write workflow stage JSON file: %s', char(string(path_value)));
            end
            cleaner = onCleanup(@() fclose(fid));
            fprintf(fid, '%s', jsonencode(payload));
            clear cleaner
        end

        function stage_entry = build_workflow_stage_entry(app, parent_entry, child_summary, stage_label)
            stage_entry = parent_entry;
            stage_entry.name = stage_label;
            stage_entry.analysis = app.pick_field(child_summary, {'analysis'}, struct());
            stage_entry.parameters = app.pick_field(child_summary, {'parameters'}, parent_entry.parameters);
            stage_entry.run_config = app.pick_field(child_summary, {'run_config'}, parent_entry.run_config);
            meta = parent_entry.metadata;
            child_meta = app.pick_field(child_summary, {'metadata'}, struct());
            child_fields = fieldnames(child_meta);
            for i = 1:numel(child_fields)
                meta.(child_fields{i}) = child_meta.(child_fields{i});
            end
            stage_entry.metadata = meta;
        end

        function settings = normalize_workflow_export_settings(~, settings)
            if nargin < 2 || ~isstruct(settings)
                settings = struct();
            end
            settings.save_figures = true;
            settings.figure_save_fig = true;
            if ~isfield(settings, 'figure_save_png')
                settings.figure_save_png = false;
            end
            if ~isfield(settings, 'figure_save_pdf')
                settings.figure_save_pdf = false;
            end
            settings.animation_enabled = true;
            settings.animation_format = 'mp4+gif';
            settings.animation_export_format = 'mp4+gif';
            settings.animation_export_formats = {'mp4', 'gif'};
            preview_only = isfield(settings, 'workflow_import_preview_only') && ...
                logical(settings.workflow_import_preview_only);
            preview_resolution = [480, 360];
            preview_dpi = 120;
            preview_width = 4.0;
            preview_height = 3.0;
            if preview_only
                preview_resolution = [240, 180];
                preview_dpi = 90;
                preview_width = 2.4;
                preview_height = 1.8;
            end
            if ~isfield(settings, 'animation_export_resolution_px') || ...
                    ~isnumeric(settings.animation_export_resolution_px) || ...
                    numel(settings.animation_export_resolution_px) ~= 2
                settings.animation_export_resolution_px = preview_resolution;
            end
            if ~isfield(settings, 'animation_export_dpi') || ...
                    ~isnumeric(settings.animation_export_dpi) || ~isscalar(settings.animation_export_dpi)
                settings.animation_export_dpi = preview_dpi;
            end
            if ~isfield(settings, 'animation_export_width_in') || ...
                    ~isnumeric(settings.animation_export_width_in) || ~isscalar(settings.animation_export_width_in)
                settings.animation_export_width_in = preview_width;
            end
            if ~isfield(settings, 'animation_export_height_in') || ...
                    ~isnumeric(settings.animation_export_height_in) || ~isscalar(settings.animation_export_height_in)
                settings.animation_export_height_in = preview_height;
            end
            if ~isfield(settings, 'media') || ~isstruct(settings.media)
                settings.media = struct();
            end
            settings.media.enabled = true;
            settings.media.format = 'mp4+gif';
            settings.media.formats = {'mp4', 'gif'};
            if ~isfield(settings.media, 'resolution_px') || ...
                    ~isnumeric(settings.media.resolution_px) || numel(settings.media.resolution_px) ~= 2
                settings.media.resolution_px = settings.animation_export_resolution_px;
            end
            if ~isfield(settings.media, 'dpi') || ~isnumeric(settings.media.dpi) || ~isscalar(settings.media.dpi)
                settings.media.dpi = settings.animation_export_dpi;
            end
            if ~isfield(settings.media, 'width_in') || ~isnumeric(settings.media.width_in) || ~isscalar(settings.media.width_in)
                settings.media.width_in = settings.animation_export_width_in;
            end
            if ~isfield(settings.media, 'height_in') || ~isnumeric(settings.media.height_in) || ~isscalar(settings.media.height_in)
                settings.media.height_in = settings.animation_export_height_in;
            end
        end

        function [targets, paths] = resolve_result_view_export_targets(app, paths)
            targets = struct();
            if nargin < 2 || ~isstruct(paths)
                paths = struct();
                return;
            end

            figures_root = '';
            if isfield(paths, 'figures_root') && ~isempty(paths.figures_root)
                figures_root = char(string(paths.figures_root));
            elseif isfield(paths, 'figures_evolution') && ~isempty(paths.figures_evolution)
                figures_root = fileparts(char(string(paths.figures_evolution)));
            elseif isfield(paths, 'base') && ~isempty(paths.base)
                figures_root = fullfile(char(string(paths.base)), 'Figures');
            end
            if isempty(figures_root)
                return;
            end

            comparisons_root = char(string(app.pick_field(paths, {'figures_comparisons'}, fullfile(figures_root, 'Comparisons'))));
            collectors_root = char(string(app.pick_field(paths, {'figures_collectors_root'}, fullfile(figures_root, 'Collectors'))));
            if app.uses_compact_v3_layout(paths)
                evolution_root = char(string(app.pick_field(paths, {'figures_evolution_root', 'figures'}, fullfile(figures_root, 'Evolutions'))));
                targets.main_plots = char(string(app.pick_field(paths, {'figures_main_plots'}, evolution_root)));
                targets.diagnostics = char(string(app.pick_field(paths, {'figures_diagnostics'}, evolution_root)));
                targets.evolution_3x3 = evolution_root;
                targets.streamfunction_3x3 = evolution_root;
                targets.velocity_3x3 = evolution_root;
                targets.vector_3x3 = evolution_root;
                targets.contour_3x3 = evolution_root;
                targets.streamlines_3x3 = evolution_root;
                targets.wall_vorticity_3x3 = char(string(app.pick_field(paths, {'figures_evolution_wall_vorticity', 'figures_wall_vorticity'}, evolution_root)));
                targets.collectors_hwinfo = collectors_root;
                targets.collectors_matlab = collectors_root;
                targets.collectors_icue = collectors_root;
            else
                evolution_root = char(string(app.pick_field(paths, {'figures_evolution_root'}, fullfile(figures_root, 'Evolution'))));
                targets.main_plots = char(string(app.pick_field(paths, {'figures_main_plots'}, fullfile(comparisons_root, 'MainPlots'))));
                targets.diagnostics = comparisons_root;
                targets.evolution_3x3 = char(string(app.pick_field(paths, {'figures_evolution_evolution', 'figures_evolution'}, fullfile(evolution_root, 'Evolution'))));
                targets.streamfunction_3x3 = char(string(app.pick_field(paths, {'figures_evolution_streamfunction', 'figures_streamfunction'}, fullfile(evolution_root, 'Streamfunction'))));
                targets.velocity_3x3 = char(string(app.pick_field(paths, {'figures_evolution_velocity', 'figures_velocity'}, fullfile(evolution_root, 'Velocity'))));
                targets.vector_3x3 = char(string(app.pick_field(paths, {'figures_evolution_vector', 'figures_vector'}, fullfile(evolution_root, 'Vector'))));
                targets.contour_3x3 = char(string(app.pick_field(paths, {'figures_evolution_contour', 'figures_contours'}, fullfile(evolution_root, 'Contour'))));
                targets.streamlines_3x3 = char(string(app.pick_field(paths, {'figures_evolution_streamlines', 'figures_streamlines'}, fullfile(evolution_root, 'Streamlines'))));
                targets.wall_vorticity_3x3 = char(string(app.pick_field(paths, {'figures_evolution_wall_vorticity', 'figures_wall_vorticity'}, fullfile(evolution_root, 'WallVorticity'))));
                targets.collectors_hwinfo = char(string(app.pick_field(paths, {'figures_collectors_hwinfo'}, fullfile(collectors_root, 'HWiNFO'))));
                targets.collectors_matlab = char(string(app.pick_field(paths, {'figures_collectors_matlab'}, fullfile(collectors_root, 'MATLAB'))));
                targets.collectors_icue = char(string(app.pick_field(paths, {'figures_collectors_icue'}, fullfile(collectors_root, 'iCUE'))));
            end

            defer_target_creation = app.uses_compact_phase_layout(paths) || ...
                (isfield(paths, 'defer_result_target_dirs') && logical(paths.defer_result_target_dirs));
            if ~defer_target_creation
                target_names = fieldnames(targets);
                for i = 1:numel(target_names)
                    if strcmp(target_names{i}, 'wall_vorticity_3x3')
                        continue;
                    end
                    target_dir = targets.(target_names{i});
                    if ~exist(target_dir, 'dir')
                        mkdir(target_dir);
                    end
                end
            end

            paths.figures_root = figures_root;
            paths.figures_comparisons = comparisons_root;
            paths.figures_main_plots = targets.main_plots;
            paths.figures_diagnostics = targets.diagnostics;
            paths.figures_evolution_root = evolution_root;
            paths.figures_evolution = targets.evolution_3x3;
            paths.figures_evolution_evolution = targets.evolution_3x3;
            paths.figures_streamfunction = targets.streamfunction_3x3;
            paths.figures_evolution_streamfunction = targets.streamfunction_3x3;
            paths.figures_velocity = targets.velocity_3x3;
            paths.figures_evolution_velocity = targets.velocity_3x3;
            paths.figures_vector = targets.vector_3x3;
            paths.figures_evolution_vector = targets.vector_3x3;
            paths.figures_contours = targets.contour_3x3;
            paths.figures_evolution_contour = targets.contour_3x3;
            paths.figures_streamlines = targets.streamlines_3x3;
            paths.figures_evolution_streamlines = targets.streamlines_3x3;
            paths.figures_wall_vorticity = targets.wall_vorticity_3x3;
            paths.figures_evolution_wall_vorticity = targets.wall_vorticity_3x3;
            paths.figures_collectors_root = collectors_root;
            paths.figures_collectors_hwinfo = targets.collectors_hwinfo;
            paths.figures_collectors_matlab = targets.collectors_matlab;
            paths.figures_collectors_icue = targets.collectors_icue;
            paths.figures_evolution_combined = char(string(app.pick_field(paths, {'figures_evolution_combined'}, fullfile(evolution_root, 'Combined'))));
            create_combined_dir = ~(isfield(paths, 'disable_combined_animation_dir') && logical(paths.disable_combined_animation_dir));
            if create_combined_dir && ~defer_target_creation && ~exist(paths.figures_evolution_combined, 'dir')
                mkdir(paths.figures_evolution_combined);
            end
            paths.media_animation = paths.figures_evolution_root;
            paths.media_animation_combined = paths.figures_evolution_combined;
            paths.media_animation_panes = paths.figures_evolution_root;
        end

        function target_dir = resolve_result_export_target_dir(~, export_targets, fig_key)
            if nargin < 3 || ~isstruct(export_targets) || ~isfield(export_targets, fig_key)
                error('UIController:MissingResultExportTarget', ...
                    'Missing canonical export target for figure key %s.', char(string(fig_key)));
            end
            target_dir = char(string(export_targets.(fig_key)));
        end

        function collector_exports = save_collector_panel_exports(app, entry, paths, settings, entry_stem)
            collector_exports = struct('source_status', struct(), 'failures', repmat(struct( ...
                'source', '', ...
                'reason', ''), 1, 0));
            if nargin < 5 || isempty(entry_stem)
                entry_stem = app.sanitize_filename(app.pick_field(paths, {'export_file_stem'}, ...
                    app.pick_field(entry, {'name'}, 'collector')));
            end
            monitor_series = app.normalize_monitor_series_collector_payload(app.pick_field(entry, {'monitor_series'}, struct()));
            results_context = app.pick_field(entry, {'results'}, struct());
            monitor_series = ExternalCollectorDispatcher.recover_monitor_series( ...
                struct( ...
                    'workflow_kind', app.pick_field(entry, {'workflow_kind'}, ''), ...
                    'run_config', app.pick_field(entry, {'run_config'}, struct()), ...
                    'metadata', app.pick_field(entry, {'metadata'}, struct()), ...
                    'results', results_context, ...
                    'monitor_series', monitor_series, ...
                    'paths', paths), ...
                monitor_series, paths);
            if ~isstruct(monitor_series) || isempty(fieldnames(monitor_series))
                return;
            end
            bundle = ExternalCollectorDispatcher.collector_plot_bundle( ...
                monitor_series, app.pick_field(entry, {'analysis'}, struct()), app.pick_field(entry, {'parameters'}, struct()));
            if ~isstruct(bundle) || ~isfield(bundle, 'panels') || isempty(bundle.panels)
                if app.collector_source_expected_for_export(monitor_series, 'hwinfo')
                    collector_exports.failures(end + 1) = struct( ... %#ok<AGROW>
                        'source', 'hwinfo', ...
                        'reason', 'collector plot bundle was empty');
                    app.append_to_terminal(['Collector export warning: HWiNFO telemetry was available but no collector panels were built for autosave.'], ...
                        'warning');
                end
                return;
            end

            export_specs = { ...
                struct('field', 'hwinfo', 'title', 'HWiNFO Collector Overview', ...
                    'dir', app.pick_field(paths, {'figures_collectors_hwinfo'}, ''), ...
                    'sources', {{'hwinfo'}}), ...
                struct('field', 'matlab', 'title', 'MATLAB Collector Overview', ...
                    'dir', app.pick_field(paths, {'figures_collectors_matlab'}, ''), ...
                    'sources', {{'matlab'}}), ...
                struct('field', 'icue', 'title', 'iCUE Collector Overview', ...
                    'dir', app.pick_field(paths, {'figures_collectors_icue'}, ''), ...
                    'sources', {{'icue'}})};
            for i = 1:numel(export_specs)
                spec = export_specs{i};
                target_dir = char(string(spec.dir));
                if isempty(target_dir)
                    continue;
                end
                filtered_panels = app.filter_collector_bundle_panels(bundle.panels, spec.sources);
                has_traces = ~isempty(filtered_panels) && any(arrayfun(@(panel) ~isempty(panel.traces), filtered_panels));
                source_status = struct( ...
                    'expected', app.collector_source_expected_for_export(monitor_series, spec.field), ...
                    'saved', false, ...
                    'target_dir', target_dir, ...
                    'base_name', '', ...
                    'reason', '');
                if ~has_traces
                    source_status.reason = 'no traces available for export';
                    collector_exports.source_status.(spec.field) = source_status;
                    if source_status.expected
                        collector_exports.failures(end + 1) = struct( ... %#ok<AGROW>
                            'source', spec.field, ...
                            'reason', source_status.reason);
                        app.append_to_terminal(sprintf('Collector export warning: %s telemetry was expected but no traces were available to save.', ...
                            char(string(spec.title))), 'warning');
                    end
                    continue;
                end
                base_name = fullfile(target_dir, sprintf('%s_Collector_%s', entry_stem, spec.field));
                if app.uses_compact_v3_layout(paths)
                    switch lower(spec.field)
                        case 'hwinfo'
                            base_name = fullfile(target_dir, 'HWiNFO_Overview');
                        case 'matlab'
                            base_name = fullfile(target_dir, 'MATLAB_Overview');
                        case 'icue'
                            base_name = fullfile(target_dir, 'iCUE_Overview');
                    end
                end
                source_status.base_name = base_name;
                fig = [];
                try
                    if ~exist(target_dir, 'dir')
                        mkdir(target_dir);
                    end
                    fig = app.create_collector_source_export_figure(filtered_panels, spec.title);
                    collector_exports.(spec.field) = ResultsPlotDispatcher.save_figure_bundle(fig, base_name, settings);
                    source_status.saved = true;
                catch ME
                    source_status.reason = ME.message;
                    collector_exports.failures(end + 1) = struct( ... %#ok<AGROW>
                        'source', spec.field, ...
                        'reason', ME.message);
                    app.append_to_terminal(sprintf('Collector export warning: %s figure export failed: %s', ...
                        char(string(spec.title)), ME.message), 'warning');
                end
                if ~isempty(fig)
                    app.close_hidden_figure(fig);
                end
                collector_exports.source_status.(spec.field) = source_status;
            end
        end

        function tf = collector_source_expected_for_export(app, monitor_series, source)
            tf = false;
            if nargin < 3 || ~isstruct(monitor_series)
                return;
            end
            source = lower(char(string(source)));
            switch source
                case 'matlab'
                    tf = app.collector_source_series_present(monitor_series, 'matlab');
                    return;
                case 'hwinfo'
                    if app.hwinfo_payload_complete(monitor_series)
                        tf = true;
                        return;
                    end
                    raw_paths = app.pick_field(monitor_series, {'raw_log_paths'}, struct());
                    hwinfo_raw_path = '';
                    if isstruct(raw_paths)
                        hwinfo_raw_path = char(string(app.pick_field(raw_paths, {'hwinfo'}, '')));
                    end
                    if ~isempty(strtrim(hwinfo_raw_path))
                        tf = true;
                        return;
                    end
                case 'icue'
                    if app.collector_source_series_present(monitor_series, 'icue')
                        tf = true;
                        return;
                    end
                    raw_paths = app.pick_field(monitor_series, {'raw_log_paths'}, struct());
                    if isstruct(raw_paths)
                        tf = ~isempty(strtrim(char(string(app.pick_field(raw_paths, {'icue'}, '')))));
                    end
                    return;
            end
        end

        function panels = filter_collector_bundle_panels(~, panels_in, allowed_sources)
            panels = panels_in;
            for i = 1:numel(panels)
                traces = struct([]);
                if isfield(panels(i), 'traces') && ~isempty(panels(i).traces)
                    keep = false(1, numel(panels(i).traces));
                    for ti = 1:numel(panels(i).traces)
                        keep(ti) = any(strcmpi(char(string(panels(i).traces(ti).source)), allowed_sources));
                    end
                    traces = panels(i).traces(keep);
                end
                panels(i).traces = traces;
            end
        end

        function fig = create_collector_source_export_figure(app, panels, title_text)
            fig = figure('Visible', 'off', ...
                'HandleVisibility', 'off', ...
                'Color', [1 1 1], ...
                'MenuBar', 'none', ...
                'ToolBar', 'none', ...
                'Units', 'pixels', ...
                'Position', [140 140 1800 1200]);
            if numel(panels) >= 9
                n_rows = 3;
                n_cols = 4;
            else
                n_rows = 4;
                n_cols = 2;
            end
            tl = tiledlayout(fig, n_rows, n_cols, 'Padding', 'compact', 'TileSpacing', 'compact');
            for i = 1:min(numel(panels), n_rows * n_cols)
                ax = nexttile(tl, i);
                app.render_collector_plot_panel(ax, panels(i));
            end
            title(tl, char(string(title_text)), 'Interpreter', 'none');
        end

        function [exported, animation_exports, paths] = export_result_entry_view_bundle(app, entry, settings, paths)
            exported = struct();
            animation_exports = struct('combined_mp4', '', 'combined_gif', '', ...
                'pane_mp4s', struct(), 'pane_gifs', struct(), 'active_panes', {{}});
            if nargin < 3 || ~isstruct(settings)
                settings = struct();
            end
            if nargin < 4 || ~isstruct(paths)
                paths = struct();
            end

            save_png = false;
            save_pdf = false;
            save_fig = false;
            if isfield(settings, 'figure_save_png')
                save_png = logical(settings.figure_save_png);
            end
            if isfield(settings, 'figure_save_pdf')
                save_pdf = logical(settings.figure_save_pdf);
            end
            if isfield(settings, 'figure_save_fig')
                save_fig = logical(settings.figure_save_fig);
            end
            export_media = false;
            if isfield(settings, 'media') && isstruct(settings.media) && isfield(settings.media, 'enabled')
                export_media = logical(settings.media.enabled);
            end
            if isfield(settings, 'animation_enabled')
                export_media = export_media || logical(settings.animation_enabled);
            end
            if ~(save_png || save_pdf || save_fig)
                if isfield(settings, 'save_figures') && logical(settings.save_figures)
                    save_fig = true;
                    settings.figure_save_png = false;
                    settings.figure_save_pdf = false;
                    settings.figure_save_fig = true;
                elseif ~(export_media || (isfield(entry.parameters, 'create_animations') && logical(entry.parameters.create_animations)))
                    return;
                end
            end

            analysis = entry.analysis;
            if ~isstruct(analysis) || isempty(fieldnames(analysis))
                return;
            end
            [export_targets, paths] = app.resolve_result_view_export_targets(paths);
            if isempty(fieldnames(export_targets)) && ~isfield(paths, 'figures_evolution_root')
                return;
            end

            params = entry.parameters;
            run_cfg = entry.run_config;
            meta = entry.metadata;
            packet = ResultsPlotDispatcher.dispatch(analysis, params, run_cfg, meta);
            format_opts = ResultsPlotDispatcher.defaults();
            if isfield(packet, 'format') && isstruct(packet.format)
                format_opts = packet.format;
            end
            snapshot_spec = ResultsPlotDispatcher.get_plot(packet, 'snapshot');
            diag_spec = ResultsPlotDispatcher.get_plot(packet, 'diagnostics');
            plot_labels = resolve_analysis_plot_labels(analysis);

            [x_vec, y_vec, plot_times, domain_resolved] = app.resolve_result_export_axes(analysis, params, snapshot_spec);
            raw_cube = [];
            if isfield(analysis, 'omega_snaps') && ~isempty(analysis.omega_snaps)
                raw_cube = analysis.omega_snaps;
            end

            entry_stem = app.sanitize_filename(app.pick_field(paths, {'export_file_stem'}, ...
                app.pick_field(entry, {'name'}, 'result')));
            [~, entry_stem_no_ext, ~] = fileparts(entry_stem);
            if ~isempty(entry_stem_no_ext)
                entry_stem = entry_stem_no_ext;
            end
            minimal_figure_bundle = isfield(settings, 'workflow_minimal_figure_bundle') && ...
                logical(settings.workflow_minimal_figure_bundle);
            skip_main_plots = isfield(settings, 'workflow_skip_main_plots') && ...
                logical(settings.workflow_skip_main_plots);
            skip_diagnostics = isfield(settings, 'workflow_skip_diagnostics') && ...
                logical(settings.workflow_skip_diagnostics);
            exclude_wall_vorticity = isfield(settings, 'workflow_exclude_wall_vorticity') && ...
                logical(settings.workflow_exclude_wall_vorticity);
            figure_stem_map = app.pick_field(paths, {'figure_stem_map'}, struct());

            if ~isempty(raw_cube) && (save_png || save_pdf || save_fig)
                if ~domain_resolved
                    app.append_to_terminal('Workflow export warning: snapshot axes could not be resolved, so editable figure exports were skipped for this run.', 'warning');
                else
                t0_str = '0';
                if ~isempty(plot_times)
                    t0_str = sprintf('%.3g', plot_times(1));
                end
                raw_psi_cube = app.extract_streamfunction_snapshot_cube(analysis, size(raw_cube));
                raw_plot_context = app.resolve_result_plot_context(analysis, size(raw_cube, 1), size(raw_cube, 2));
                [raw_u_cube, raw_v_cube] = app.extract_velocity_snapshot_cubes(analysis, size(raw_cube), raw_plot_context);
                raw_wall_cube = app.extract_wall_omega_snapshot_cube(analysis, size(raw_cube));
                raw_plot_mask = raw_plot_context.plot_mask;
                raw_wall_mask = raw_plot_context.wall_mask;
                raw_bathy_profile_x = raw_plot_context.profile_x;
                raw_bathy_profile_y = raw_plot_context.profile_y;
                if ~minimal_figure_bundle && ~skip_main_plots
                    main_fig = app.create_result_main_quad_figure(raw_cube(:, :, 1), x_vec, y_vec, ...
                        app.extract_cube_snapshot(raw_psi_cube, 1), ...
                        app.extract_cube_snapshot(raw_u_cube, 1), app.extract_cube_snapshot(raw_v_cube, 1), ...
                        snapshot_spec, t0_str, format_opts, raw_plot_mask, raw_bathy_profile_x, raw_bathy_profile_y, ...
                        params, run_cfg);
                    base_stem = app.pick_field(figure_stem_map, {'main_plots'}, sprintf('%s__main_plots', entry_stem));
                    base_name = fullfile(export_targets.main_plots, char(string(base_stem)));
                    exported.main_plots = ResultsPlotDispatcher.save_figure_bundle(main_fig, base_name, settings);
                    app.close_hidden_figure(main_fig);
                end

                gallery_idx = app.resolve_snapshot_indices_for_gallery(params, size(raw_cube, 3), 9);
                gallery_defs = { ...
                    'evolution_3x3', 'evolution', plot_labels.gallery_evolution_title};
                if ~minimal_figure_bundle
                    gallery_defs = [gallery_defs; { ...
                        'streamfunction_3x3', 'streamfunction', plot_labels.gallery_secondary_title; ...
                        'velocity_3x3', 'speed', plot_labels.gallery_speed_title; ...
                        'vector_3x3', 'vector', plot_labels.gallery_vector_title; ...
                        'contour_3x3', 'contour', plot_labels.gallery_contour_title; ...
                        'streamlines_3x3', 'streamline', plot_labels.gallery_streamline_title}];
                    if ~exclude_wall_vorticity && ~isempty(raw_wall_cube) && ~isempty(raw_wall_mask) && any(raw_wall_mask(:))
                        gallery_defs(end + 1, :) = { ...
                            'wall_vorticity_3x3', 'wall_omega', plot_labels.gallery_wall_omega_title}; %#ok<AGROW>
                    end
                end
                gallery_defs = app.filter_gallery_defs_by_requested_panes(gallery_defs, settings);
                for gi = 1:size(gallery_defs, 1)
                    fig_key = gallery_defs{gi, 1};
                    fig_mode = gallery_defs{gi, 2};
                    fig_title = gallery_defs{gi, 3};
                    gallery_omega_cube = raw_cube;
                    gallery_mask = raw_plot_mask;
                    if strcmp(fig_mode, 'wall_omega')
                        gallery_omega_cube = raw_wall_cube;
                        gallery_mask = raw_wall_mask;
                    end
                    gallery_fig = app.create_snapshot_gallery_figure(gallery_omega_cube, raw_psi_cube, raw_u_cube, raw_v_cube, plot_times, x_vec, y_vec, ...
                        gallery_idx, fig_mode, fig_title, gallery_mask, raw_bathy_profile_x, raw_bathy_profile_y, params, run_cfg);
                    target_dir = app.resolve_result_export_target_dir(export_targets, fig_key);
                    if exist(target_dir, 'dir') ~= 7
                        mkdir(target_dir);
                    end
                    base_stem = app.pick_field(figure_stem_map, {fig_key}, sprintf('%s__%s', entry_stem, fig_key));
                    base_name = fullfile(target_dir, char(string(base_stem)));
                    exported.(fig_key) = ResultsPlotDispatcher.save_figure_bundle(gallery_fig, base_name, settings);
                    app.close_hidden_figure(gallery_fig);
                end
                end
            end

            has_time = isfield(analysis, 'time_vec') && ~isempty(analysis.time_vec);
            has_ke = isfield(analysis, 'kinetic_energy') && ~isempty(analysis.kinetic_energy);
            if (has_time || has_ke) && ~minimal_figure_bundle && ~skip_diagnostics
                diag_fig = app.create_result_diagnostics_figure(analysis, diag_spec, format_opts);
                base_stem = app.pick_field(figure_stem_map, {'diagnostics'}, sprintf('%s__diagnostics', entry_stem));
                base_name = fullfile(export_targets.diagnostics, char(string(base_stem)));
                exported.diagnostics = ResultsPlotDispatcher.save_figure_bundle(diag_fig, base_name, settings);
                app.close_hidden_figure(diag_fig);
            end

            animation_exports = ResultsAnimationExporter.export_from_analysis(analysis, params, run_cfg, paths, settings);
        end

        function [x_vec, y_vec, plot_times, domain_resolved] = resolve_result_export_axes(app, analysis, params, snapshot_spec) %#ok<INUSL>
            nx = 64;
            ny = 64;
            if isfield(analysis, 'omega_snaps') && ~isempty(analysis.omega_snaps)
                ny = size(analysis.omega_snaps, 1);
                nx = size(analysis.omega_snaps, 2);
            end
            [x_vec, domain_x] = app.resolve_export_axis_vector(analysis, params, snapshot_spec, ...
                {'x', 'x_vec', 'x_coords', 'snapshot_x', 'x_nodes'}, nx, 'Lx');
            [y_vec, domain_y] = app.resolve_export_axis_vector(analysis, params, snapshot_spec, ...
                {'y', 'y_vec', 'y_coords', 'snapshot_y', 'y_nodes'}, ny, 'Ly');
            if isstruct(snapshot_spec) && isfield(snapshot_spec, 'data') && isstruct(snapshot_spec.data)
                if isfield(snapshot_spec.data, 'x') && ~isempty(snapshot_spec.data.x)
                    x_vec = snapshot_spec.data.x;
                    domain_x = true;
                end
                if isfield(snapshot_spec.data, 'y') && ~isempty(snapshot_spec.data.y)
                    y_vec = snapshot_spec.data.y;
                    domain_y = true;
                end
            end
            domain_resolved = domain_x && domain_y;

            plot_times = [];
            if isstruct(snapshot_spec) && isfield(snapshot_spec, 'data') && isstruct(snapshot_spec.data) && ...
                    isfield(snapshot_spec.data, 'times') && ~isempty(snapshot_spec.data.times)
                plot_times = double(snapshot_spec.data.times(:)).';
            elseif isfield(analysis, 'snapshot_times_requested') && ~isempty(analysis.snapshot_times_requested)
                plot_times = double(analysis.snapshot_times_requested(:)).';
            elseif isfield(analysis, 'snapshot_times') && ~isempty(analysis.snapshot_times)
                plot_times = double(analysis.snapshot_times(:)).';
            end
        end

        function [axis_vec, resolved] = resolve_export_axis_vector(app, analysis, params, snapshot_spec, field_candidates, count, extent_field)
            axis_vec = [];
            resolved = false;
            if isstruct(snapshot_spec) && isfield(snapshot_spec, 'data') && isstruct(snapshot_spec.data)
                axis_vec = app.pick_axis_vector_from_source(snapshot_spec.data, field_candidates, count);
                if ~isempty(axis_vec)
                    resolved = true;
                end
            end
            if isempty(axis_vec)
                axis_vec = app.pick_axis_vector_from_source(analysis, field_candidates, count);
                if ~isempty(axis_vec)
                    resolved = true;
                end
            end
            if isempty(axis_vec)
                axis_vec = app.pick_axis_vector_from_source(params, field_candidates, count);
                if ~isempty(axis_vec)
                    resolved = true;
                end
            end
            if isempty(axis_vec)
                extent_value = NaN;
                if isstruct(analysis) && isfield(analysis, extent_field) && isnumeric(analysis.(extent_field)) && isscalar(analysis.(extent_field))
                    extent_value = double(analysis.(extent_field));
                end
                if ~(isfinite(extent_value) && extent_value > 0) && isstruct(params) && ...
                        isfield(params, extent_field) && isnumeric(params.(extent_field)) && isscalar(params.(extent_field))
                    extent_value = double(params.(extent_field));
                end
                if isfinite(extent_value) && extent_value > 0
                    axis_vec = linspace(-extent_value / 2, extent_value / 2, count);
                    resolved = true;
                else
                    axis_vec = 1:count;
                    resolved = false;
                end
            end
            axis_vec = double(axis_vec(:)).';
        end

        function axis_vec = pick_axis_vector_from_source(~, source, field_candidates, count)
            axis_vec = [];
            if ~isstruct(source)
                return;
            end
            for i = 1:numel(field_candidates)
                field_name = field_candidates{i};
                if ~isfield(source, field_name) || isempty(source.(field_name))
                    continue;
                end
                candidate = source.(field_name);
                if isnumeric(candidate) && isvector(candidate) && numel(candidate) == count
                    axis_vec = candidate;
                    return;
                end
                if isnumeric(candidate) && ismatrix(candidate)
                    if size(candidate, 1) == 1 && size(candidate, 2) == count
                        axis_vec = candidate;
                        return;
                    end
                    if size(candidate, 2) == 1 && size(candidate, 1) == count
                        axis_vec = candidate(:).';
                        return;
                    end
                end
            end
        end

        function fig = create_result_main_quad_figure(app, omega_slice, x_vec, y_vec, psi_slice, u_slice, v_slice, snapshot_spec, t_str, format_opts, plot_mask, bathy_profile_x, bathy_profile_y, params, run_cfg)
            fig = figure('Visible', 'off', ...
                'HandleVisibility', 'off', ...
                'Color', [1 1 1], ...
                'MenuBar', 'none', ...
                'ToolBar', 'none', ...
                'Units', 'pixels', ...
                'Position', [100 100 1400 1000]);
            tl = tiledlayout(fig, 2, 2, 'Padding', 'compact', 'TileSpacing', 'compact');
            ax_snap = nexttile(tl, 1);
            ax_contour = nexttile(tl, 2);
            ax_vector = nexttile(tl, 3);
            ax_stream = nexttile(tl, 4);
            snap_labels = struct('xlabel', 'x', 'ylabel', 'y', 'title', '\omega');
            if nargin >= 8 && isstruct(snapshot_spec) && isfield(snapshot_spec, 'labels') && isstruct(snapshot_spec.labels)
                snap_labels = snapshot_spec.labels;
            end
            if nargin < 13
                bathy_profile_y = [];
            end
            if nargin < 12
                bathy_profile_x = [];
            end
            if nargin < 11
                plot_mask = [];
            end
            if nargin < 15 || ~isstruct(params)
                params = struct();
            end
            if nargin < 16 || ~isstruct(run_cfg)
                run_cfg = struct();
            end
            light_colors = ResultsPlotDispatcher.default_light_colors();
            app.render_snapshot_quad_view(ax_snap, ax_contour, ax_vector, ax_stream, ...
                omega_slice, psi_slice, u_slice, v_slice, x_vec, y_vec, snap_labels, t_str, light_colors, format_opts, ...
                plot_mask, bathy_profile_x, bathy_profile_y);
            ResultsPlotDispatcher.apply_tiled_annotations(tl, ...
                ResultsPlotDispatcher.compose_export_title('Main Plots', params, run_cfg), ...
                'x', 'y', light_colors);
        end

        function fig = create_result_diagnostics_figure(~, analysis, diag_spec, format_opts)
            fig = figure('Visible', 'off', ...
                'HandleVisibility', 'off', ...
                'Color', [1 1 1], ...
                'MenuBar', 'none', ...
                'ToolBar', 'none', ...
                'Units', 'pixels', ...
                'Position', [120 120 1200 700]);
            ax = axes(fig); %#ok<LAXES>
            light_colors = ResultsPlotDispatcher.default_light_colors();
            plot_labels = resolve_analysis_plot_labels(analysis);
            diag_data = ResultsPlotDispatcher.resolve_diagnostics_payload(analysis);
            if nargin >= 3 && isstruct(diag_spec) && isfield(diag_spec, 'data') && isstruct(diag_spec.data)
                diag_data = diag_spec.data;
            end
            primary_time = [];
            primary_values = [];
            secondary_time = [];
            secondary_values = [];
            if isfield(diag_data, 'primary_time') && ~isempty(diag_data.primary_time)
                primary_time = double(diag_data.primary_time(:));
            elseif isfield(diag_data, 'time') && ~isempty(diag_data.time)
                primary_time = double(diag_data.time(:));
            end
            if isfield(diag_data, 'primary') && ~isempty(diag_data.primary)
                primary_values = double(diag_data.primary(:));
            end
            if isfield(diag_data, 'secondary_time') && ~isempty(diag_data.secondary_time)
                secondary_time = double(diag_data.secondary_time(:));
            elseif isfield(diag_data, 'time') && ~isempty(diag_data.time)
                secondary_time = double(diag_data.time(:));
            end
            if isfield(diag_data, 'secondary') && ~isempty(diag_data.secondary)
                secondary_values = double(diag_data.secondary(:));
            end
            if ~isempty(primary_values) && numel(primary_values) == numel(primary_time)
                plot(ax, primary_time, primary_values, 'LineWidth', format_opts.line_width, ...
                    'Color', light_colors.primary);
                hold(ax, 'on');
            end
            if ~isempty(secondary_values) && numel(secondary_values) == numel(secondary_time)
                yyaxis(ax, 'right');
                plot(ax, secondary_time, secondary_values, 'LineWidth', format_opts.secondary_line_width, ...
                    'LineStyle', '--', 'Color', light_colors.secondary);
                legend_entries = {'KE', 'Enstrophy'};
                if nargin >= 3 && isstruct(diag_spec) && isfield(diag_spec, 'legend') && ~isempty(diag_spec.legend)
                    legend_entries = diag_spec.legend;
                end
                ResultsPlotDispatcher.apply_legend(ax, legend_entries, format_opts, light_colors);
                yyaxis(ax, 'left');
            end
            hold(ax, 'off');
            diag_labels = struct('xlabel', 'Time (s)', 'ylabel', plot_labels.diagnostics_primary, ...
                'ylabel_right', plot_labels.diagnostics_secondary, ...
                'title', plot_labels.diagnostics_title);
            if nargin >= 3 && isstruct(diag_spec) && isfield(diag_spec, 'labels') && isstruct(diag_spec.labels)
                diag_labels = diag_spec.labels;
            end
            ResultsPlotDispatcher.apply_axes(ax, diag_labels, format_opts, light_colors);
            if ~isempty(secondary_values) && isfield(diag_labels, 'ylabel_right')
                yyaxis(ax, 'right');
                ylabel(ax, char(string(diag_labels.ylabel_right)), ...
                    'Color', light_colors.fg, 'Interpreter', 'latex');
                yyaxis(ax, 'left');
            end
        end

        function plot_tabs = plot_analysis_on_tab(app, tab, analysis, params, run_cfg, meta, monitor_series) %#ok<INUSL>
            % Render one run tab with nested plot subtabs.
            C = app.layout_cfg.colors;
            tab.BackgroundColor = C.bg_dark;
            plot_tabs = struct();
            if nargin < 7 || ~isstruct(monitor_series)
                monitor_series = struct();
            end

            if ~isempty(tab.Children)
                delete(tab.Children);
            end

            plot_packet = ResultsPlotDispatcher.dispatch(analysis, params, run_cfg, meta);
            plot_colors = app.result_plot_colors();

            format_opts = ResultsPlotDispatcher.defaults();
            if isfield(plot_packet, 'format') && isstruct(plot_packet.format)
                format_opts = plot_packet.format;
            end

            snapshot_spec = ResultsPlotDispatcher.get_plot(plot_packet, 'snapshot');
            diag_spec = ResultsPlotDispatcher.get_plot(plot_packet, 'diagnostics');
            plot_labels = resolve_analysis_plot_labels(analysis);

            has_snaps = isfield(analysis, 'omega_snaps') && ~isempty(analysis.omega_snaps);
            has_time = isfield(analysis, 'time_vec') && ~isempty(analysis.time_vec);
            has_ke = isfield(analysis, 'kinetic_energy') && ~isempty(analysis.kinetic_energy);
            has_snap_t = isfield(analysis, 'snapshot_times') && ~isempty(analysis.snapshot_times);
            n_snaps_raw = 0;
            if has_snaps
                n_snaps_raw = size(analysis.omega_snaps, 3);
            end

            [x, y] = ResultsPlotDispatcher.resolve_snapshot_axes(analysis, params);
            if isstruct(snapshot_spec) && isfield(snapshot_spec, 'data') && isstruct(snapshot_spec.data)
                if isfield(snapshot_spec.data, 'x') && ~isempty(snapshot_spec.data.x)
                    x = snapshot_spec.data.x;
                end
                if isfield(snapshot_spec.data, 'y') && ~isempty(snapshot_spec.data.y)
                    y = snapshot_spec.data.y;
                end
            end

            raw_snap_times = [];
            if isstruct(snapshot_spec) && isfield(snapshot_spec, 'data') && isstruct(snapshot_spec.data) && ...
                    isfield(snapshot_spec.data, 'times') && ~isempty(snapshot_spec.data.times)
                raw_snap_times = snapshot_spec.data.times(:).';
            elseif isfield(analysis, 'snapshot_times_requested') && ~isempty(analysis.snapshot_times_requested)
                raw_snap_times = analysis.snapshot_times_requested(:).';
            elseif has_snap_t
                raw_snap_times = analysis.snapshot_times(:).';
            end

            display_cube = [];
            display_times = [];
            display_psi_cube = [];
            display_u_cube = [];
            display_v_cube = [];
            display_wall_cube = [];
            animation_cube = [];
            animation_times = [];
            animation_psi_cube = [];
            animation_u_cube = [];
            animation_v_cube = [];
            animation_wall_cube = [];
            plot_cube = [];
            plot_times = [];
            plot_psi_cube = [];
            plot_u_cube = [];
            plot_v_cube = [];
            plot_wall_cube = [];
            plot_mask_2d = [];
            wall_plot_mask_2d = [];
            bathy_profile_x = [];
            bathy_profile_y = [];
            n_display_snaps = 0;
            time_span = app.resolve_snapshot_time_span(params, analysis, raw_snap_times, n_snaps_raw);
            if has_snaps
                plot_cube = analysis.omega_snaps;
                plot_psi_cube = app.extract_streamfunction_snapshot_cube(analysis, size(plot_cube));
                plot_context = app.resolve_result_plot_context(analysis, size(plot_cube, 1), size(plot_cube, 2));
                [plot_u_cube, plot_v_cube] = app.extract_velocity_snapshot_cubes(analysis, size(plot_cube), plot_context);
                plot_wall_cube = app.extract_wall_omega_snapshot_cube(analysis, size(plot_cube));
                plot_mask_2d = plot_context.plot_mask;
                wall_plot_mask_2d = plot_context.wall_mask;
                bathy_profile_x = plot_context.profile_x;
                bathy_profile_y = plot_context.profile_y;
                plot_times = raw_snap_times;
                if isempty(plot_times) || numel(plot_times) ~= n_snaps_raw
                    plot_times = linspace(0, time_span, n_snaps_raw);
                else
                    plot_times = double(plot_times(:)).';
                end

                display_cube = plot_cube;
                display_times = plot_times;
                display_psi_cube = plot_psi_cube;
                display_u_cube = plot_u_cube;
                display_v_cube = plot_v_cube;
                display_wall_cube = plot_wall_cube;
                n_display_snaps = size(display_cube, 3);

                desired_frames = n_snaps_raw;
                use_animation_frames = false;
                if isfield(params, 'create_animations') && logical(params.create_animations)
                    use_animation_frames = true;
                elseif isfield(params, 'mode') && contains(lower(app.to_text(params.mode, '')), 'animation')
                    use_animation_frames = true;
                end
                if use_animation_frames
                    if isfield(params, 'animation_num_frames') && isnumeric(params.animation_num_frames)
                        desired_frames = max(desired_frames, max(2, round(params.animation_num_frames)));
                    elseif isfield(params, 'num_animation_frames') && isnumeric(params.num_animation_frames)
                        desired_frames = max(desired_frames, max(2, round(params.num_animation_frames)));
                    end
                end
                [animation_cube, animation_times] = app.resample_snapshot_cube(plot_cube, plot_times, desired_frames, time_span);
                if ~isempty(plot_psi_cube)
                    [animation_psi_cube, ~] = app.resample_snapshot_cube(plot_psi_cube, plot_times, desired_frames, time_span);
                end
                if ~isempty(plot_u_cube) && ~isempty(plot_v_cube)
                    [animation_u_cube, ~] = app.resample_snapshot_cube(plot_u_cube, plot_times, desired_frames, time_span);
                    [animation_v_cube, ~] = app.resample_snapshot_cube(plot_v_cube, plot_times, desired_frames, time_span);
                end
                if ~isempty(plot_wall_cube)
                    [animation_wall_cube, ~] = app.resample_snapshot_cube(plot_wall_cube, plot_times, desired_frames, time_span);
                end
                if isempty(animation_cube)
                    animation_cube = display_cube;
                    animation_times = display_times;
                    animation_psi_cube = display_psi_cube;
                    animation_u_cube = display_u_cube;
                    animation_v_cube = display_v_cube;
                    animation_wall_cube = display_wall_cube;
                end
            end

            show_slider = has_snaps && n_display_snaps > 1;
            if isstruct(snapshot_spec) && isfield(snapshot_spec, 'slider')
                show_slider = show_slider && logical(snapshot_spec.slider);
            end

            run_index = max(1, numel(app.session_figures));
            run_color = app.result_run_color(run_index);
            run_badge = app.result_run_badge(run_index, meta);

            root = uigridlayout(tab, [2, 1]);
            root.RowHeight = {40, '1x'};
            root.Padding = [4 4 4 4];
            root.RowSpacing = 4;

            header_panel = uipanel(root, ...
                'BorderType', 'none', ...
                'BackgroundColor', 0.78 * C.bg_panel + 0.22 * run_color);
            header_panel.Layout.Row = 1;
            header_grid = uigridlayout(header_panel, [1, 6]);
            header_grid.Padding = [8 2 8 2];
            header_grid.ColumnSpacing = 10;
            header_grid.ColumnWidth = {'fit', '1x', 'fit', 'fit', 'fit', 'fit'};

            badge_label = uilabel(header_grid, ...
                'Text', run_badge, ...
                'FontWeight', 'bold', ...
                'FontSize', 11, ...
                'FontColor', [0.07 0.07 0.07], ...
                'BackgroundColor', run_color, ...
                'HorizontalAlignment', 'center');
            badge_label.Layout.Column = 1;

            run_id_txt = '--';
            if isfield(meta, 'run_id')
                run_id_txt = app.to_text(meta.run_id, '--');
            end
            if isempty(strtrim(run_id_txt))
                run_id_txt = '--';
            end
            run_id_label = uilabel(header_grid, ...
                'Text', sprintf('Run ID: %s', run_id_txt), ...
                'FontColor', C.fg_text, ...
                'FontSize', 11, ...
                'HorizontalAlignment', 'left');
            run_id_label.Layout.Column = 2;

            method_txt = 'Method: --';
            if isfield(meta, 'method') && ~isempty(meta.method)
                method_txt = sprintf('Method: %s', upper(app.to_text(meta.method, '--')));
            end
            method_label = uilabel(header_grid, 'Text', method_txt, ...
                'FontColor', C.fg_text, 'FontSize', 11, 'HorizontalAlignment', 'right');
            method_label.Layout.Column = 3;

            mode_txt = 'Mode: --';
            if isfield(meta, 'mode') && ~isempty(meta.mode)
                mode_txt = sprintf('Mode: %s', app.humanize_token(meta.mode));
            end
            mode_label = uilabel(header_grid, 'Text', mode_txt, ...
                'FontColor', C.fg_text, 'FontSize', 11, 'HorizontalAlignment', 'right');
            mode_label.Layout.Column = 4;

            ic_txt = 'IC: --';
            if isfield(meta, 'ic_type') && ~isempty(meta.ic_type)
                ic_txt = sprintf('IC: %s', strrep(app.to_text(meta.ic_type, '--'), '_', ' '));
            end
            ic_label = uilabel(header_grid, 'Text', ic_txt, ...
                'FontColor', C.fg_text, 'FontSize', 11, 'HorizontalAlignment', 'right');
            ic_label.Layout.Column = 5;

            status_label = uilabel(header_grid, ...
                'Text', 'Published', ...
                'FontWeight', 'bold', ...
                'FontColor', [0.08 0.08 0.08], ...
                'BackgroundColor', [0.76 0.89 0.78], ...
                'HorizontalAlignment', 'center');
            status_label.Layout.Column = 6;

            plot_group = uitabgroup(root);
            plot_group.Layout.Row = 2;
            plot_tabs.group = plot_group;
            plot_tabs.status_label = status_label;

            t_snapshot = uitab(plot_group, 'Title', 'Main Plots');
            t_snap9 = uitab(plot_group, 'Title', 'Evolution 3x3');
            t_psi9 = uitab(plot_group, 'Title', 'Streamfunction 3x3');
            t_speed9 = uitab(plot_group, 'Title', 'Velocity 3x3');
            t_vector9 = uitab(plot_group, 'Title', 'Vector 3x3');
            t_contour9 = uitab(plot_group, 'Title', 'Contour 3x3');
            t_stream9 = uitab(plot_group, 'Title', 'Streamlines 3x3');
            t_wall9 = uitab(plot_group, 'Title', 'Wall Vorticity 3x3');
            t_diag = uitab(plot_group, 'Title', 'Diagnostics');
            t_collectors = uitab(plot_group, 'Title', 'Collectors');
            t_anim = uitab(plot_group, 'Title', 'Animation');
            t_meta = uitab(plot_group, 'Title', 'Metadata');
            t_art = uitab(plot_group, 'Title', 'Artifacts');
            plot_tabs.plots = t_snapshot;
            plot_tabs.evolution_3x3 = t_snap9;
            plot_tabs.streamfunction_3x3 = t_psi9;
            plot_tabs.velocity_3x3 = t_speed9;
            plot_tabs.vector_3x3 = t_vector9;
            plot_tabs.contour_3x3 = t_contour9;
            plot_tabs.streamlines_3x3 = t_stream9;
            plot_tabs.wall_vorticity_3x3 = t_wall9;
            plot_tabs.diagnostics = t_diag;
            plot_tabs.collectors = t_collectors;
            plot_tabs.animation = t_anim;
            plot_tabs.metadata = t_meta;
            plot_tabs.artifacts = t_art;

            % Snapshot subtab
            snap_grid = uigridlayout(t_snapshot, [2, 1]);
            if show_slider
                snap_grid.RowHeight = {36, '1x'};
            else
                snap_grid.RowHeight = {0, '1x'};
            end
            snap_grid.Padding = [4 4 4 4];
            snap_grid.RowSpacing = 4;

            snap_slider = [];
            snap_time_label = [];
            snap_count_label = [];
            t0_str = '0';
            if ~isempty(display_times)
                t0_str = sprintf('%.3g', display_times(1));
            end

            if show_slider
                slider_row = uigridlayout(snap_grid, [1, 4]);
                slider_row.Layout.Row = 1;
                slider_row.ColumnWidth = {'fit', '1x', 'fit', 'fit'};
                slider_row.ColumnSpacing = 8;
                slider_row.Padding = [4 2 4 2];
                slider_row.BackgroundColor = C.bg_panel;

                slider_lbl = uilabel(slider_row, 'Text', 'Frame:', ...
                    'FontColor', C.fg_muted, 'FontSize', 11);
                slider_lbl.Layout.Column = 1;

                snap_slider = uislider(slider_row, ...
                    'Limits', [1, n_display_snaps], 'Value', 1, ...
                    'MajorTicks', unique(round(linspace(1, n_display_snaps, min(n_display_snaps, 6)))));
                snap_slider.Layout.Column = 2;

                snap_time_label = uilabel(slider_row, ...
                    'Text', sprintf('t = %s s', t0_str), ...
                    'FontColor', C.accent_cyan, 'FontSize', 11, ...
                    'HorizontalAlignment', 'right');
                snap_time_label.Layout.Column = 3;

                snap_count_label = uilabel(slider_row, ...
                    'Text', sprintf('Frame 1 / %d frames', n_display_snaps), ...
                    'FontColor', C.fg_muted, 'FontSize', 10, ...
                    'HorizontalAlignment', 'right');
                snap_count_label.Layout.Column = 4;
            end

            plots_grid = uigridlayout(snap_grid, [2, 2]);
            plots_grid.Layout.Row = 2;
            plots_grid.RowHeight = {'1x', '1x'};
            plots_grid.ColumnWidth = {'1x', '1x'};
            plots_grid.Padding = [0 0 0 0];
            plots_grid.RowSpacing = 6;
            plots_grid.ColumnSpacing = 6;

            ax_snap = uiaxes(plots_grid); ax_snap.Layout.Row = 1; ax_snap.Layout.Column = 1; app.style_results_axes(ax_snap);
            ax_contour = uiaxes(plots_grid); ax_contour.Layout.Row = 1; ax_contour.Layout.Column = 2; app.style_results_axes(ax_contour);
            ax_vector = uiaxes(plots_grid); ax_vector.Layout.Row = 2; ax_vector.Layout.Column = 1; app.style_results_axes(ax_vector);
            ax_stream = uiaxes(plots_grid); ax_stream.Layout.Row = 2; ax_stream.Layout.Column = 2; app.style_results_axes(ax_stream);

            snap_labels = struct('xlabel', 'x', 'ylabel', 'y', 'title', '\omega');
            if isstruct(snapshot_spec) && isfield(snapshot_spec, 'labels') && isstruct(snapshot_spec.labels)
                snap_labels = snapshot_spec.labels;
            end
            plot_label_fields = fieldnames(plot_labels);
            for plot_label_idx = 1:numel(plot_label_fields)
                key = plot_label_fields{plot_label_idx};
                if ~isfield(snap_labels, key) || isempty(snap_labels.(key))
                    snap_labels.(key) = plot_labels.(key);
                end
            end

            if has_snaps
                omega0 = display_cube(:,:,1);
                app.render_snapshot_quad_view(ax_snap, ax_contour, ax_vector, ax_stream, ...
                    omega0, app.extract_cube_snapshot(display_psi_cube, 1), ...
                    app.extract_cube_snapshot(display_u_cube, 1), app.extract_cube_snapshot(display_v_cube, 1), ...
                    x, y, snap_labels, t0_str, plot_colors, format_opts, ...
                    plot_mask_2d, bathy_profile_x, bathy_profile_y);
            else
                title(ax_snap, 'No snapshot data', 'Color', C.fg_text, 'Interpreter', 'none');
                title(ax_contour, 'No contour data', 'Color', C.fg_text, 'Interpreter', 'none');
                title(ax_vector, 'No vector data', 'Color', C.fg_text, 'Interpreter', 'none');
                title(ax_stream, 'No streamline data', 'Color', C.fg_text, 'Interpreter', 'none');
            end

            plot_indices = [];
            if has_snaps
                plot_indices = app.resolve_snapshot_indices_for_gallery(params, size(plot_cube, 3), 9);
            end
            render_context = struct( ...
                'plot_cube', plot_cube, ...
                'plot_times', plot_times, ...
                'plot_psi_cube', plot_psi_cube, ...
                'plot_u_cube', plot_u_cube, ...
                'plot_v_cube', plot_v_cube, ...
                'plot_wall_cube', plot_wall_cube, ...
                'plot_mask_2d', plot_mask_2d, ...
                'wall_plot_mask_2d', wall_plot_mask_2d, ...
                'bathy_profile_x', bathy_profile_x, ...
                'bathy_profile_y', bathy_profile_y, ...
                'plot_indices', plot_indices, ...
                'x', x, ...
                'y', y, ...
                'monitor_series', monitor_series, ...
                'analysis', analysis, ...
                'params', params, ...
                'snapshot_spec', snapshot_spec, ...
                'format_opts', format_opts, ...
                'plot_colors', plot_colors, ...
                'plot_labels', plot_labels, ...
                'animation_cube', animation_cube, ...
                'animation_times', animation_times, ...
                'animation_psi_cube', animation_psi_cube, ...
                'animation_u_cube', animation_u_cube, ...
                'animation_v_cube', animation_v_cube, ...
                'animation_wall_cube', animation_wall_cube, ...
                'display_cube', display_cube, ...
                'display_times', display_times, ...
                'display_psi_cube', display_psi_cube, ...
                'display_u_cube', display_u_cube, ...
                'display_v_cube', display_v_cube, ...
                'display_wall_cube', display_wall_cube, ...
                'n_display_snaps', n_display_snaps, ...
                'snap_labels', snap_labels);
            plot_group.UserData = struct('render_context', render_context, 'rendered_roles', {{'main_plots', 'diagnostics', 'metadata', 'artifacts'}});
            t_snap9.UserData = struct('lazy_role', 'evolution_3x3');
            t_psi9.UserData = struct('lazy_role', 'streamfunction_3x3');
            t_speed9.UserData = struct('lazy_role', 'velocity_3x3');
            t_vector9.UserData = struct('lazy_role', 'vector_3x3');
            t_contour9.UserData = struct('lazy_role', 'contour_3x3');
            t_stream9.UserData = struct('lazy_role', 'streamlines_3x3');
            t_wall9.UserData = struct('lazy_role', 'wall_vorticity_3x3');
            t_collectors.UserData = struct('lazy_role', 'collectors');
            t_anim.UserData = struct('lazy_role', 'animation');
            plot_group.SelectionChangedFcn = @(src, event) app.on_standard_result_plot_tab_selected(src, event);
            app.render_result_tab_placeholder(t_snap9, 'Evolution 3x3 will render when this tab is selected.');
            app.render_result_tab_placeholder(t_psi9, 'Streamfunction 3x3 will render when this tab is selected.');
            app.render_result_tab_placeholder(t_speed9, 'Velocity 3x3 will render when this tab is selected.');
            app.render_result_tab_placeholder(t_vector9, 'Vector 3x3 will render when this tab is selected.');
            app.render_result_tab_placeholder(t_contour9, 'Contour 3x3 will render when this tab is selected.');
            app.render_result_tab_placeholder(t_stream9, 'Streamlines 3x3 will render when this tab is selected.');
            app.render_result_tab_placeholder(t_wall9, 'Wall-vorticity 3x3 will render when this tab is selected.');
            app.render_result_tab_placeholder(t_collectors, 'Collector panels will render when this tab is selected.');
            app.render_result_tab_placeholder(t_anim, 'Animation grids will render when this tab is selected.');

            % Diagnostics subtab
            ax_diag = uiaxes(t_diag);
            app.style_results_axes(ax_diag);
            diag_data = ResultsPlotDispatcher.resolve_diagnostics_payload(analysis);
            primary_time = app.pick_field(diag_data, {'primary_time', 'time'}, []);
            primary_values = app.pick_field(diag_data, {'primary'}, []);
            secondary_time = app.pick_field(diag_data, {'secondary_time', 'time'}, []);
            secondary_values = app.pick_field(diag_data, {'secondary'}, []);
            if ~isempty(primary_values) && ~isempty(primary_time) && numel(primary_values) == numel(primary_time)
                ke_line_width = 1.6;
                if isfield(format_opts, 'line_width')
                    ke_line_width = format_opts.line_width;
                end
                plot(ax_diag, primary_time(:), primary_values(:), 'LineWidth', ke_line_width, ...
                    'Color', plot_colors.primary);
                hold(ax_diag, 'on');
                if ~isempty(secondary_values) && ~isempty(secondary_time) && numel(secondary_values) == numel(secondary_time)
                    enst_line_width = 1.4;
                    if isfield(format_opts, 'secondary_line_width')
                        enst_line_width = format_opts.secondary_line_width;
                    end
                    yyaxis(ax_diag, 'right');
                    plot(ax_diag, secondary_time(:), secondary_values(:), 'LineWidth', enst_line_width, ...
                        'LineStyle', '--', 'Color', plot_colors.secondary);
                    legend_entries = {'KE', 'Enstrophy'};
                    if isstruct(diag_spec) && isfield(diag_spec, 'legend') && ~isempty(diag_spec.legend)
                        legend_entries = diag_spec.legend;
                    end
                    ResultsPlotDispatcher.apply_legend(ax_diag, legend_entries, format_opts, plot_colors);
                    yyaxis(ax_diag, 'left');
                end
                hold(ax_diag, 'off');
                diag_labels = struct('xlabel', 'Time (s)', 'ylabel', plot_labels.diagnostics_primary, ...
                    'title', plot_labels.diagnostics_title);
                if isstruct(diag_spec) && isfield(diag_spec, 'labels') && isstruct(diag_spec.labels)
                    diag_labels = diag_spec.labels;
                end
                ResultsPlotDispatcher.apply_axes(ax_diag, diag_labels, format_opts, plot_colors);
                if ~isempty(secondary_values) && isfield(diag_labels, 'ylabel_right')
                    yyaxis(ax_diag, 'right');
                    ylabel(ax_diag, char(string(diag_labels.ylabel_right)), ...
                        'Color', plot_colors.fg, 'Interpreter', 'latex');
                    yyaxis(ax_diag, 'left');
                end
            else
                title(ax_diag, 'No diagnostics data', 'Color', C.fg_text, 'Interpreter', 'latex');
            end

            % Collectors and animation are hydrated lazily on first selection.

            % Artifacts subtab
            art_grid = uigridlayout(t_art, [2, 1]);
            art_grid.RowHeight = {'fit', '1x'};
            art_grid.Padding = [8 8 8 8];
            uilabel(art_grid, 'Text', 'Generated artifact paths', ...
                'FontColor', C.fg_text, 'FontWeight', 'bold');
            artifacts_lines = {'No artifact paths registered for this run.'};
            if run_index <= numel(app.session_figures) && ...
                    isfield(app.session_figures(run_index), 'artifacts') && ...
                    isstruct(app.session_figures(run_index).artifacts) && ...
                    isfield(app.session_figures(run_index).artifacts, 'paths') && ...
                    isstruct(app.session_figures(run_index).artifacts.paths)
                paths_struct = app.session_figures(run_index).artifacts.paths;
                fn = fieldnames(paths_struct);
                tmp_lines = {};
                for fi = 1:numel(fn)
                    value = paths_struct.(fn{fi});
                    if isempty(value)
                        continue;
                    end
                    tmp_lines{end + 1} = sprintf('%s: %s', fn{fi}, app.to_text(value, '')); %#ok<AGROW>
                end
                if ~isempty(tmp_lines)
                    artifacts_lines = tmp_lines;
                end
            end
            art_ta = uitextarea(art_grid, ...
                'Editable', 'off', ...
                'BackgroundColor', C.bg_input, ...
                'FontColor', C.fg_muted, ...
                'FontName', 'Consolas', ...
                'Value', artifacts_lines);
            art_ta.Layout.Row = 2;
            art_ta.Tag = 'results_artifacts_textarea';

            % Metadata subtab
            meta_grid = uigridlayout(t_meta, [1 1]);
            meta_grid.Padding = [8 8 8 8];
            meta_ta = uitextarea(meta_grid, ...
                'Editable', 'off', ...
                'BackgroundColor', C.bg_input, ...
                'FontColor', C.fg_muted, ...
                'FontSize', 11, ...
                'FontName', 'Consolas', ...
                'Value', app.format_run_metadata(meta, params));
            meta_ta.Tag = 'results_metadata_textarea';
            if isfield(plot_packet, 'metadata') && isstruct(plot_packet.metadata) && ...
                    isfield(plot_packet.metadata, 'lines') && ~isempty(plot_packet.metadata.lines)
                meta_ta.Value = plot_packet.metadata.lines;
            end

            if show_slider && ~isempty(snap_slider)
                snap_slider.ValueChangedFcn = @(src, ~) app.update_snapshot_view(src, ax_snap, ...
                    snap_time_label, snap_count_label, display_cube, display_psi_cube, display_u_cube, display_v_cube, display_times, x, y, ...
                    snapshot_spec, format_opts, plot_colors, ax_contour, ax_vector, ax_stream, ...
                    plot_mask_2d, bathy_profile_x, bathy_profile_y);
            end

            if has_snaps
                plot_group.SelectedTab = t_snapshot;
            elseif has_time
                plot_group.SelectedTab = t_diag;
            else
                plot_group.SelectedTab = t_meta;
            end
            app.enforce_container_content_margins(tab);
        end

        function on_standard_result_plot_tab_selected(app, src, event)
            if nargin < 3 || isempty(event) || ~isprop(event, 'NewValue') || isempty(event.NewValue)
                if isempty(src) || ~isvalid(src) || ~isprop(src, 'SelectedTab')
                    return;
                end
                target_tab = src.SelectedTab;
            else
                target_tab = event.NewValue;
            end
            app.render_standard_result_lazy_tab(target_tab);
        end

        function render_standard_result_lazy_tab(app, target_tab)
            if isempty(target_tab) || ~isvalid(target_tab) || ~isprop(target_tab, 'UserData') || ...
                    ~isstruct(target_tab.UserData) || ~isfield(target_tab.UserData, 'lazy_role')
                return;
            end
            group = target_tab.Parent;
            if isempty(group) || ~isvalid(group) || ~isprop(group, 'UserData') || ~isstruct(group.UserData)
                return;
            end
            state = group.UserData;
            if ~isfield(state, 'render_context') || ~isstruct(state.render_context)
                return;
            end
            if ~isfield(state, 'rendered_roles') || ~iscell(state.rendered_roles)
                state.rendered_roles = {};
            end
            role = char(string(target_tab.UserData.lazy_role));
            if any(strcmp(state.rendered_roles, role))
                return;
            end

            ctx = state.render_context;
            switch role
                case 'evolution_3x3'
                    app.populate_snapshot_gallery_tab(target_tab, ctx.plot_cube, ctx.plot_psi_cube, ctx.plot_u_cube, ctx.plot_v_cube, ...
                        ctx.plot_times, ctx.x, ctx.y, ctx.plot_indices, 'evolution', ...
                        ctx.plot_labels.gallery_evolution_title, ctx.plot_mask_2d, ctx.bathy_profile_x, ctx.bathy_profile_y);
                case 'streamfunction_3x3'
                    app.populate_snapshot_gallery_tab(target_tab, ctx.plot_cube, ctx.plot_psi_cube, ctx.plot_u_cube, ctx.plot_v_cube, ...
                        ctx.plot_times, ctx.x, ctx.y, ctx.plot_indices, 'streamfunction', ...
                        ctx.plot_labels.gallery_secondary_title, ctx.plot_mask_2d, ctx.bathy_profile_x, ctx.bathy_profile_y);
                case 'velocity_3x3'
                    app.populate_snapshot_gallery_tab(target_tab, ctx.plot_cube, ctx.plot_psi_cube, ctx.plot_u_cube, ctx.plot_v_cube, ...
                        ctx.plot_times, ctx.x, ctx.y, ctx.plot_indices, 'speed', ...
                        ctx.plot_labels.gallery_speed_title, ctx.plot_mask_2d, ctx.bathy_profile_x, ctx.bathy_profile_y);
                case 'vector_3x3'
                    app.populate_snapshot_gallery_tab(target_tab, ctx.plot_cube, ctx.plot_psi_cube, ctx.plot_u_cube, ctx.plot_v_cube, ...
                        ctx.plot_times, ctx.x, ctx.y, ctx.plot_indices, 'vector', ...
                        ctx.plot_labels.gallery_vector_title, ctx.plot_mask_2d, ctx.bathy_profile_x, ctx.bathy_profile_y);
                case 'contour_3x3'
                    app.populate_snapshot_gallery_tab(target_tab, ctx.plot_cube, ctx.plot_psi_cube, ctx.plot_u_cube, ctx.plot_v_cube, ...
                        ctx.plot_times, ctx.x, ctx.y, ctx.plot_indices, 'contour', ...
                        ctx.plot_labels.gallery_contour_title, ctx.plot_mask_2d, ctx.bathy_profile_x, ctx.bathy_profile_y);
                case 'streamlines_3x3'
                    app.populate_snapshot_gallery_tab(target_tab, ctx.plot_cube, ctx.plot_psi_cube, ctx.plot_u_cube, ctx.plot_v_cube, ...
                        ctx.plot_times, ctx.x, ctx.y, ctx.plot_indices, 'streamline', ...
                        ctx.plot_labels.gallery_streamline_title, ctx.plot_mask_2d, ctx.bathy_profile_x, ctx.bathy_profile_y);
                case 'wall_vorticity_3x3'
                    app.populate_snapshot_gallery_tab(target_tab, ctx.plot_wall_cube, ctx.plot_psi_cube, ctx.plot_u_cube, ctx.plot_v_cube, ...
                        ctx.plot_times, ctx.x, ctx.y, ctx.plot_indices, 'wall_omega', ...
                        ctx.plot_labels.gallery_wall_omega_title, ctx.wall_plot_mask_2d, ctx.bathy_profile_x, ctx.bathy_profile_y);
                case 'collectors'
                    app.render_collector_results_tab(target_tab, ctx.monitor_series, ctx.analysis, ctx.params);
                case 'animation'
                    app.render_results_animation_tab(target_tab, ctx);
                otherwise
                    return;
            end

            state.rendered_roles{end + 1} = role; %#ok<AGROW>
            group.UserData = state;
        end

        function render_results_animation_tab(app, target_tab, ctx)
            if nargin < 3 || ~isstruct(ctx)
                return;
            end
            if ~isempty(target_tab.Children)
                delete(target_tab.Children);
            end

            C = app.layout_cfg.colors;
            anim_cube = app.pick_field(ctx, {'animation_cube'}, []);
            anim_times = app.pick_field(ctx, {'animation_times'}, []);
            anim_psi_cube = app.pick_field(ctx, {'animation_psi_cube'}, []);
            anim_u_cube = app.pick_field(ctx, {'animation_u_cube'}, []);
            anim_v_cube = app.pick_field(ctx, {'animation_v_cube'}, []);
            plot_mask_2d = app.pick_field(ctx, {'plot_mask_2d'}, []);
            bathy_profile_x = app.pick_field(ctx, {'bathy_profile_x'}, []);
            bathy_profile_y = app.pick_field(ctx, {'bathy_profile_y'}, []);
            x = app.pick_field(ctx, {'x'}, []);
            y = app.pick_field(ctx, {'y'}, []);
            snapshot_spec = app.pick_field(ctx, {'snapshot_spec'}, struct());
            format_opts = app.pick_field(ctx, {'format_opts'}, ResultsPlotDispatcher.defaults());
            plot_colors = app.pick_field(ctx, {'plot_colors'}, app.result_plot_colors());
            snap_labels = app.pick_field(ctx, {'snap_labels'}, struct('title', '\omega'));

            anim_grid = uigridlayout(target_tab, [2, 1]);
            anim_grid.RowHeight = {40, '1x'};
            anim_grid.Padding = [8 8 8 8];
            anim_grid.RowSpacing = 6;
            anim_controls = uigridlayout(anim_grid, [1, 6]);
            anim_controls.Layout.Row = 1;
            anim_controls.ColumnWidth = {70, 55, '1x', 120, 110, 'fit'};
            anim_controls.Padding = [0 0 0 0];
            anim_controls.ColumnSpacing = 6;

            anim_play_toggle = uibutton(anim_controls, 'state', 'Text', 'Play', 'Value', false);
            anim_play_toggle.Layout.Column = 1;
            anim_loop = uicheckbox(anim_controls, 'Text', 'Loop', 'Value', true, ...
                'FontColor', C.fg_text);
            anim_loop.Layout.Column = 2;

            n_animation_snaps = max(1, size(anim_cube, 3));
            t0_str = '0';
            if ~isempty(anim_times)
                t0_str = sprintf('%.3g', anim_times(1));
            end
            anim_slider = uislider(anim_controls, 'Limits', [1, max(2, n_animation_snaps)], ...
                'Value', 1, 'MajorTicks', unique(round(linspace(1, max(2, n_animation_snaps), min(max(2, n_animation_snaps), 6)))));
            anim_slider.Layout.Column = 3;
            anim_time_label = uilabel(anim_controls, 'Text', sprintf('t = %s s', t0_str), ...
                'FontColor', C.accent_cyan, 'HorizontalAlignment', 'right');
            anim_time_label.Layout.Column = 4;
            anim_count_label = uilabel(anim_controls, ...
                'Text', sprintf('Frame 1 / %d', max(1, n_animation_snaps)), ...
                'FontColor', C.fg_muted, 'HorizontalAlignment', 'right');
            anim_count_label.Layout.Column = 5;
            anim_reload_btn = uibutton(anim_controls, 'Text', 'Reload', ...
                'ButtonPushedFcn', @(~,~) app.refresh_figures());
            anim_reload_btn.Layout.Column = 6;

            anim_axes_grid = uigridlayout(anim_grid, [3, 3]);
            anim_axes_grid.Layout.Row = 2;
            anim_axes_grid.RowHeight = {'1x', '1x', '1x'};
            anim_axes_grid.ColumnWidth = {'1x', '1x', '1x'};
            anim_axes_grid.Padding = [0 0 0 0];
            anim_axes_grid.RowSpacing = 6;
            anim_axes_grid.ColumnSpacing = 6;

            anim_axes = gobjects(1, 9);
            for anim_i = 1:9
                ax_anim = uiaxes(anim_axes_grid);
                ax_anim.Layout.Row = ceil(anim_i / 3);
                ax_anim.Layout.Column = mod(anim_i - 1, 3) + 1;
                app.style_results_axes(ax_anim);
                anim_axes(anim_i) = ax_anim;
            end
            anim_view_modes = {'evolution', 'contour', 'vector', 'streamline', 'streamfunction', 'speed', ...
                'reserved', 'reserved', 'reserved'};
            anim_view_titles = {'Evolution', 'Contour', 'Vector', 'Streamlines', 'Streamfunction', 'Speed', ...
                'Reserved', 'Reserved', 'Reserved'};

            if ~isempty(anim_cube)
                app.render_results_animation_grid(anim_axes, anim_view_modes, anim_view_titles, ...
                    anim_cube(:,:,1), app.extract_cube_snapshot(anim_psi_cube, 1), ...
                    app.extract_cube_snapshot(anim_u_cube, 1), app.extract_cube_snapshot(anim_v_cube, 1), ...
                    x, y, t0_str, plot_colors, plot_mask_2d, bathy_profile_x, bathy_profile_y, snap_labels);
                anim_slider.ValueChangedFcn = @(src,~) app.on_results_animation_slider(src, ...
                    anim_time_label, anim_count_label, anim_cube, anim_psi_cube, anim_u_cube, anim_v_cube, anim_times, x, y, ...
                    snapshot_spec, format_opts, plot_colors, anim_axes, anim_view_modes, anim_view_titles, ...
                    plot_mask_2d, bathy_profile_x, bathy_profile_y);
                anim_play_toggle.ValueChangedFcn = @(btn,~) app.on_results_animation_play_toggled(btn, ...
                    anim_loop, anim_slider, anim_time_label, anim_count_label, ...
                    anim_cube, anim_psi_cube, anim_u_cube, anim_v_cube, anim_times, x, y, snapshot_spec, format_opts, plot_colors, ...
                    anim_axes, anim_view_modes, anim_view_titles, plot_mask_2d, bathy_profile_x, bathy_profile_y);
            else
                anim_play_toggle.Enable = 'off';
                anim_slider.Enable = 'off';
                anim_loop.Enable = 'off';
                anim_time_label.Text = 'No snapshot data';
                anim_count_label.Text = '--';
                for anim_i = 1:numel(anim_axes)
                    app.render_results_animation_placeholder(anim_axes(anim_i), anim_view_titles{anim_i}, C.fg_text);
                end
            end
        end

        function render_result_tab_placeholder(app, target_tab, message_text)
            if nargin < 3 || strlength(string(strtrim(message_text))) == 0
                message_text = 'Content will render when this tab is selected.';
            end
            if isempty(target_tab) || ~isvalid(target_tab)
                return;
            end
            if ~isempty(target_tab.Children)
                delete(target_tab.Children);
            end
            grid = uigridlayout(target_tab, [1, 1]);
            grid.RowHeight = {'1x'};
            grid.ColumnWidth = {'1x'};
            grid.Padding = [12 12 12 12];
            label = uilabel(grid, ...
                'Text', char(string(message_text)), ...
                'HorizontalAlignment', 'center', ...
                'VerticalAlignment', 'center', ...
                'FontColor', app.layout_cfg.colors.fg_muted, ...
                'FontSize', 12);
            label.Layout.Row = 1;
            label.Layout.Column = 1;
        end

        function update_snapshot_view(app, slider, ax, time_lbl, count_lbl, ...
                omega_cube, psi_cube, u_cube, v_cube, snap_times, x_vec, y_vec, snapshot_spec, format_opts, plot_colors, varargin)
            % Callback: redraw vorticity axes for the selected snapshot index.
            if ~app.are_live_handles(slider, ax)
                return;
            end
            if nargin < 14 || ~isstruct(format_opts)
                format_opts = ResultsPlotDispatcher.defaults();
            end
            if nargin < 15 || ~isstruct(plot_colors)
                plot_colors = app.result_plot_colors();
            end
            if isempty(omega_cube) || ndims(omega_cube) < 3
                return;
            end

            if isempty(x_vec)
                x_vec = 1:size(omega_cube, 2);
            end
            if isempty(y_vec)
                y_vec = 1:size(omega_cube, 1);
            end

            n_snaps = size(omega_cube, 3);
            idx = max(1, min(n_snaps, round(slider.Value)));
            omega_slice = omega_cube(:,:,idx);
            snap_labels = struct('xlabel', 'x', 'ylabel', 'y', 'title', '\omega');
            if isstruct(snapshot_spec) && isfield(snapshot_spec, 'labels') && isstruct(snapshot_spec.labels)
                snap_labels = snapshot_spec.labels;
            end

            t_str = sprintf('%d', idx);
            if ~isempty(snap_times) && numel(snap_times) >= idx
                t_val = snap_times(idx);
                t_str = sprintf('%.3g', t_val);
                if ~isempty(time_lbl) && isvalid(time_lbl)
                    time_lbl.Text = sprintf('t = %s s', t_str);
                end
            else
                if ~isempty(time_lbl) && isvalid(time_lbl)
                    time_lbl.Text = sprintf('t = %.3g s', idx - 1);
                end
            end
            if ~isempty(count_lbl) && isvalid(count_lbl)
                count_lbl.Text = sprintf('Frame %d / %d frames', idx, n_snaps);
            end

            plot_mask = [];
            bathy_profile_x = [];
            bathy_profile_y = [];
            if numel(varargin) >= 3
                ax_contour = varargin{1};
                ax_vector = varargin{2};
                ax_stream = varargin{3};
                if numel(varargin) >= 4
                    plot_mask = varargin{4};
                end
                if numel(varargin) >= 5
                    bathy_profile_x = varargin{5};
                end
                if numel(varargin) >= 6
                    bathy_profile_y = varargin{6};
                end
                if isa(ax_contour, 'matlab.ui.control.UIAxes') && ...
                        isa(ax_vector, 'matlab.ui.control.UIAxes') && ...
                        isa(ax_stream, 'matlab.ui.control.UIAxes') && ...
                        app.are_live_handles(ax_contour, ax_vector, ax_stream)
                    app.render_snapshot_quad_view(ax, ax_contour, ax_vector, ax_stream, ...
                        omega_slice, app.extract_cube_snapshot(psi_cube, idx), ...
                        app.extract_cube_snapshot(u_cube, idx), app.extract_cube_snapshot(v_cube, idx), ...
                        x_vec, y_vec, snap_labels, t_str, plot_colors, format_opts, ...
                        plot_mask, bathy_profile_x, bathy_profile_y);
                    return;
                end
            end

            imagesc(ax, x_vec, y_vec, omega_slice);
            axis(ax, 'equal', 'tight');
            set(ax, 'YDir', 'normal');
            if isfield(format_opts, 'snapshot_colormap')
                colormap(ax, format_opts.snapshot_colormap);
            else
                colormap(ax, turbo);
            end
            cb = colorbar(ax);
            if isprop(cb, 'Color')
                cb.Color = plot_colors.fg;
            end
            ResultsPlotDispatcher.apply_axes(ax, snap_labels, format_opts, plot_colors);
            title(ax, sprintf('%s  (t = %s s)', char(string(snap_labels.title)), t_str), ...
                'Color', plot_colors.fg, 'Interpreter', 'tex');
        end

        function render_snapshot_quad_view(app, ax_snap, ax_contour, ax_vector, ax_stream, ...
                omega_slice, psi_slice, u_slice, v_slice, x_vec, y_vec, snap_labels, t_str, plot_colors, format_opts, ...
                plot_mask, bathy_profile_x, bathy_profile_y)
            % Render the 2x2 main results panel (evolution/contour/vector/streamline).
            if ~app.are_live_handles(ax_snap, ax_contour, ax_vector, ax_stream)
                return;
            end
            if nargin < 18
                bathy_profile_y = [];
            end
            if nargin < 17
                bathy_profile_x = [];
            end
            if nargin < 16
                plot_mask = [];
            end
            if nargin < 15 || ~isstruct(format_opts)
                format_opts = ResultsPlotDispatcher.defaults();
            end
            if nargin < 14 || ~isstruct(plot_colors)
                plot_colors = app.result_plot_colors();
            end
            if nargin < 13 || isempty(t_str)
                t_str = '0';
            end
            if nargin < 12 || ~isstruct(snap_labels)
                snap_labels = struct('xlabel', 'x', 'ylabel', 'y', 'title', '\omega');
            end
            if isempty(x_vec)
                x_vec = 1:size(omega_slice, 2);
            end
            if isempty(y_vec)
                y_vec = 1:size(omega_slice, 1);
            end

            [cmin, cmax] = app.compute_result_omega_limits(omega_slice, plot_mask);
            app.render_result_view_mode(ax_snap, 'evolution', omega_slice, psi_slice, u_slice, v_slice, ...
                x_vec, y_vec, t_str, plot_colors, plot_mask, bathy_profile_x, bathy_profile_y, cmin, cmax, snap_labels);
            ResultsPlotDispatcher.apply_axes(ax_snap, snap_labels, format_opts, plot_colors);
            app.render_result_view_mode(ax_contour, 'contour', omega_slice, psi_slice, u_slice, v_slice, ...
                x_vec, y_vec, t_str, plot_colors, plot_mask, bathy_profile_x, bathy_profile_y, cmin, cmax, snap_labels);
            app.render_result_view_mode(ax_vector, 'vector', omega_slice, psi_slice, u_slice, v_slice, ...
                x_vec, y_vec, t_str, plot_colors, plot_mask, bathy_profile_x, bathy_profile_y, cmin, cmax, snap_labels);
            app.render_result_view_mode(ax_stream, 'streamline', omega_slice, psi_slice, u_slice, v_slice, ...
                x_vec, y_vec, t_str, plot_colors, plot_mask, bathy_profile_x, bathy_profile_y, cmin, cmax, snap_labels);
        end

        function [cmin, cmax] = compute_result_omega_limits(~, omega_slice, plot_mask)
            scaling = resolve_result_plot_scaling(omega_slice, plot_mask, struct());
            cmin = scaling.cmin;
            cmax = scaling.cmax;
        end

        function masked = apply_result_plot_mask(~, data, plot_mask)
            masked = double(data);
            if ~isempty(plot_mask) && isequal(size(masked), size(plot_mask))
                masked(~plot_mask) = NaN;
            end
        end

        function draw_result_bathymetry_outline(~, ax, profile_x, profile_y, line_color)
            if isempty(profile_x) || isempty(profile_y) || numel(profile_x) ~= numel(profile_y)
                return;
            end
            hold(ax, 'on');
            plot(ax, double(profile_x(:)).', double(profile_y(:)).', ...
                'LineWidth', 1.4, 'LineStyle', '-', 'Color', line_color);
            hold(ax, 'off');
        end

        function render_result_scalar_field(app, ax, x_vec, y_vec, z_slice, color_limits) %#ok<INUSD>
            if app.result_field_has_variation(z_slice)
                contourf(ax, x_vec, y_vec, z_slice, 24, 'LineStyle', 'none');
            else
                h = imagesc(ax, x_vec, y_vec, z_slice);
                set(h, 'AlphaData', double(isfinite(z_slice)));
                set(ax, 'YDir', 'normal');
            end
            if nargin >= 6 && isnumeric(color_limits) && numel(color_limits) >= 2
                limits = double(color_limits(1:2));
                if all(isfinite(limits)) && limits(2) > limits(1)
                    clim(ax, limits);
                end
            end
        end

        function tf = result_field_has_variation(~, z_slice)
            tf = false;
            if isempty(z_slice)
                return;
            end
            finite_values = z_slice(isfinite(z_slice));
            if isempty(finite_values)
                return;
            end
            value_span = max(finite_values) - min(finite_values);
            value_scale = max(1.0, max(abs(finite_values)));
            tf = isfinite(value_span) && value_span > 1.0e-8 * value_scale;
        end

        function render_result_view_mode(app, ax, view_mode, omega_slice, psi_slice, u_slice, v_slice, ...
                x_vec, y_vec, t_str, plot_colors, plot_mask, bathy_profile_x, bathy_profile_y, cmin, cmax, plot_labels)
            cla(ax);
            if nargin < 17 || ~isstruct(plot_labels)
                plot_labels = resolve_analysis_plot_labels(struct());
            end
            mode_token = lower(char(string(view_mode)));
            omega_plot = app.apply_result_plot_mask(omega_slice, plot_mask);

            [Xg, Yg] = meshgrid(x_vec, y_vec);
            skip = max(1, round(min(numel(x_vec), numel(y_vec)) / 24));

            switch mode_token
                case 'evolution'
                    h = imagesc(ax, x_vec, y_vec, omega_plot);
                    set(h, 'AlphaData', double(isfinite(omega_plot)));
                    colormap(ax, turbo);
                    clim(ax, [cmin cmax]);
                    cb = colorbar(ax);
                    if isprop(cb, 'Color'), cb.Color = plot_colors.fg; end
                    title(ax, sprintf('%s (t = %s s)', plot_labels.snapshot_title_base, t_str), ...
                        'Color', plot_colors.fg, 'Interpreter', 'tex');

                case 'contour'
                    psi = app.resolve_streamfunction_slice_for_results(omega_slice, psi_slice, x_vec, y_vec);
                    psi_plot = app.apply_result_plot_mask(psi, plot_mask);
                    app.render_result_scalar_field(ax, x_vec, y_vec, omega_plot, [cmin cmax]);
                    hold(ax, 'on');
                    has_psi_overlay = app.overlay_streamfunction_contours(ax, x_vec, y_vec, psi_plot, plot_colors.fg);
                    hold(ax, 'off');
                    colormap(ax, turbo);
                    clim(ax, [cmin cmax]);
                    cb = colorbar(ax);
                    if isprop(cb, 'Color'), cb.Color = plot_colors.fg; end
                    contour_title = sprintf('%s (t = %s s)', plot_labels.contour_title_base, t_str);
                    if ~has_psi_overlay
                        contour_title = sprintf('%s (t = %s s)', plot_labels.primary_name, t_str);
                    end
                    title(ax, contour_title, 'Color', plot_colors.fg, 'Interpreter', 'tex');

                case 'vector'
                    [u, v] = app.resolve_velocity_slice_for_results(omega_slice, u_slice, v_slice, x_vec, y_vec);
                    if ~isempty(plot_mask) && isequal(size(plot_mask), size(u))
                        u(~plot_mask) = 0;
                        v(~plot_mask) = 0;
                    end
                    quiver(ax, Xg(1:skip:end,1:skip:end), Yg(1:skip:end,1:skip:end), ...
                        u(1:skip:end,1:skip:end), v(1:skip:end,1:skip:end), 1.4, ...
                        'Color', plot_colors.primary, 'LineWidth', 1.0);
                    title(ax, sprintf('%s (t = %s s)', plot_labels.vector_title_base, t_str), ...
                        'Color', plot_colors.fg, 'Interpreter', 'tex');

                case 'streamline'
                    [u, v] = app.resolve_velocity_slice_for_results(omega_slice, u_slice, v_slice, x_vec, y_vec);
                    if ~isempty(plot_mask) && isequal(size(plot_mask), size(u))
                        u(~plot_mask) = 0;
                        v(~plot_mask) = 0;
                    end
                    ResultsPlotDispatcher.render_deterministic_streamlines(ax, x_vec, y_vec, u, v, plot_colors.fg, ...
                        struct('fallback_skip', skip, 'line_width', 1.0));
                    title(ax, sprintf('%s (t = %s s)', plot_labels.streamline_title_base, t_str), ...
                        'Color', plot_colors.fg, 'Interpreter', 'tex');

                case 'streamfunction'
                    psi = app.resolve_streamfunction_slice_for_results(omega_slice, psi_slice, x_vec, y_vec);
                    psi_plot = app.apply_result_plot_mask(psi, plot_mask);
                    psi_finite = psi_plot(isfinite(psi_plot));
                    if isempty(psi_finite)
                        pmin = -1;
                        pmax = 1;
                    else
                        pmin = min(psi_finite);
                        pmax = max(psi_finite);
                    end
                    if ~isfinite(pmin) || ~isfinite(pmax) || pmax <= pmin
                        pmin = -1;
                        pmax = 1;
                    end
                    app.render_result_scalar_field(ax, x_vec, y_vec, psi_plot, [pmin pmax]);
                    colormap(ax, turbo);
                    clim(ax, [pmin pmax]);
                    cb = colorbar(ax);
                    if isprop(cb, 'Color'), cb.Color = plot_colors.fg; end
                    title(ax, sprintf('%s (t = %s s)', plot_labels.streamfunction_title_base, t_str), ...
                        'Color', plot_colors.fg, 'Interpreter', 'tex');

                case 'speed'
                    [u, v] = app.resolve_velocity_slice_for_results(omega_slice, u_slice, v_slice, x_vec, y_vec);
                    if ~isempty(plot_mask) && isequal(size(plot_mask), size(u))
                        u(~plot_mask) = 0;
                        v(~plot_mask) = 0;
                    end
                    speed_slice = hypot(u, v);
                    speed_plot = app.apply_result_plot_mask(speed_slice, plot_mask);
                    speed_finite = speed_plot(isfinite(speed_plot));
                    if isempty(speed_finite)
                        smax = 1;
                    else
                        smax = max(speed_finite);
                    end
                    if ~isfinite(smax) || smax <= 0
                        smax = 1;
                    end
                    h = imagesc(ax, x_vec, y_vec, speed_plot);
                    set(h, 'AlphaData', double(isfinite(speed_plot)));
                    colormap(ax, turbo);
                    clim(ax, [0 smax]);
                    cb = colorbar(ax);
                    if isprop(cb, 'Color'), cb.Color = plot_colors.fg; end
                    title(ax, sprintf('%s (t = %s s)', plot_labels.speed_title_base, t_str), ...
                        'Color', plot_colors.fg, 'Interpreter', 'tex');

                case 'wall_omega'
                    h = imagesc(ax, x_vec, y_vec, omega_plot);
                    set(h, 'AlphaData', double(isfinite(omega_plot)));
                    colormap(ax, turbo);
                    clim(ax, [cmin cmax]);
                    cb = colorbar(ax);
                    if isprop(cb, 'Color'), cb.Color = plot_colors.fg; end
                    title(ax, sprintf('%s (t = %s s)', plot_labels.wall_omega_title_base, t_str), ...
                        'Color', plot_colors.fg, 'Interpreter', 'tex');

                otherwise
                    app.render_results_animation_placeholder(ax, char(string(view_mode)), plot_colors.fg);
                    return;
            end

            axis(ax, 'equal');
            axis(ax, 'tight');
            set(ax, 'YDir', 'normal');
            xlabel(ax, 'x', 'Color', plot_colors.fg);
            ylabel(ax, 'y', 'Color', plot_colors.fg);
            grid(ax, 'on');
            app.draw_result_bathymetry_outline(ax, bathy_profile_x, bathy_profile_y, plot_colors.fg);
        end

        function render_results_animation_grid(app, anim_axes, anim_view_modes, anim_view_titles, ...
                omega_slice, psi_slice, u_slice, v_slice, x_vec, y_vec, t_str, plot_colors, plot_mask, bathy_profile_x, bathy_profile_y, plot_labels)
            if nargin < 15 || ~isstruct(plot_labels)
                plot_labels = resolve_analysis_plot_labels(struct());
            end
            [cmin, cmax] = app.compute_result_omega_limits(omega_slice, plot_mask);
            for i = 1:numel(anim_axes)
                if ~app.is_live_handle(anim_axes(i))
                    continue;
                end
                mode_token = lower(char(string(anim_view_modes{i})));
                if strcmp(mode_token, 'reserved')
                    app.render_results_animation_placeholder(anim_axes(i), anim_view_titles{i}, plot_colors.fg);
                    continue;
                end
                app.render_result_view_mode(anim_axes(i), anim_view_modes{i}, omega_slice, psi_slice, u_slice, v_slice, ...
                    x_vec, y_vec, t_str, plot_colors, plot_mask, bathy_profile_x, bathy_profile_y, cmin, cmax, plot_labels);
            end
        end

        function render_results_animation_placeholder(~, ax, label_text, fg_color)
            cla(ax);
            xlim(ax, [0, 1]);
            ylim(ax, [0, 1]);
            set(ax, 'YDir', 'normal');
            grid(ax, 'off');
            text(ax, 0.5, 0.5, sprintf('%s slot reserved', char(string(label_text))), ...
                'Units', 'normalized', 'HorizontalAlignment', 'center', ...
                'VerticalAlignment', 'middle', 'Color', fg_color, 'FontSize', 12);
            title(ax, char(string(label_text)), 'Color', fg_color, 'Interpreter', 'none');
            xlabel(ax, '', 'Color', fg_color);
            ylabel(ax, '', 'Color', fg_color);
        end

        function render_collector_results_tab(app, target_tab, monitor_series, analysis, params)
            if nargin < 4 || ~isstruct(analysis)
                analysis = struct();
            end
            if nargin < 5 || ~isstruct(params)
                params = struct();
            end

            bundle = ExternalCollectorDispatcher.collector_plot_bundle(monitor_series, analysis, params);
            root = uigridlayout(target_tab, [1, 2]);
            root.RowHeight = {'1x'};
            root.ColumnWidth = {'2.2x', '1x'};
            root.Padding = [8 8 8 8];
            root.RowSpacing = 6;
            root.ColumnSpacing = 8;

            plot_grid = uigridlayout(root, [4, 2]);
            plot_grid.Layout.Row = 1;
            plot_grid.Layout.Column = 1;
            plot_grid.RowHeight = {'1x', '1x', '1x', '1x'};
            plot_grid.ColumnWidth = {'1x', '1x'};
            plot_grid.Padding = [0 0 0 0];
            plot_grid.RowSpacing = 6;
            plot_grid.ColumnSpacing = 6;

            for i = 1:numel(bundle.panels)
                ax = uiaxes(plot_grid);
                ax.Layout.Row = ceil(i / 2);
                ax.Layout.Column = 1 + mod(i - 1, 2);
                app.style_results_axes(ax);
                app.render_collector_plot_panel(ax, bundle.panels(i));
            end

            side_grid = uigridlayout(root, [2, 1]);
            side_grid.Layout.Row = 1;
            side_grid.Layout.Column = 2;
            side_grid.RowHeight = {'1x', '1x'};
            side_grid.ColumnWidth = {'1x'};
            side_grid.Padding = [0 0 0 0];
            side_grid.RowSpacing = 8;

            summary_box = uitextarea(side_grid, ...
                'Editable', 'off', ...
                'FontName', 'Consolas', ...
                'BackgroundColor', app.layout_cfg.colors.bg_input, ...
                'FontColor', app.layout_cfg.colors.fg_muted);
            summary_box.Layout.Row = 1;
            summary_box.Layout.Column = 1;
            summary_box.Tag = 'results_collectors_summary_textarea';
            summary_box.Value = bundle.summary_lines;

            button_panel = uipanel(side_grid, ...
                'Title', 'Collector Plot Popup', ...
                'Scrollable', 'on', ...
                'BackgroundColor', app.layout_cfg.colors.bg_panel_alt, ...
                'ForegroundColor', app.layout_cfg.colors.fg_text);
            button_panel.Layout.Row = 2;
            button_grid = uigridlayout(button_panel, [numel(bundle.button_specs), 1]);
            button_grid.RowHeight = repmat({'fit'}, 1, numel(bundle.button_specs));
            button_grid.ColumnWidth = {'1x'};
            button_grid.Padding = [8 8 8 8];
            button_grid.RowSpacing = 6;
            button_grid.ColumnSpacing = 0;
            for i = 1:numel(bundle.button_specs)
                spec = bundle.button_specs(i);
                uibutton(button_grid, ...
                    'Text', spec.label, ...
                    'FontWeight', 'bold', ...
                    'ButtonPushedFcn', @(~,~) app.open_collector_plot_popup(spec, bundle.metric_catalog));
            end
        end

        function render_collector_plot_panel(app, ax, panel)
            cla(ax);
            line_handles = gobjects(0);
            legend_entries = {};
            hold(ax, 'on');
            for i = 1:numel(panel.traces)
                trace = panel.traces(i);
                plot_args = { ...
                    trace.x, trace.y, ...
                    'LineWidth', 1.8, ...
                    'Color', trace.color_rgb, ...
                    'LineStyle', trace.line_style};
                if isfield(trace, 'marker') && ~strcmpi(char(string(trace.marker)), 'none')
                    plot_args = [plot_args, { ...
                        'Marker', trace.marker, ...
                        'MarkerSize', 5, ...
                        'MarkerFaceColor', trace.color_rgb}]; %#ok<AGROW>
                end
                line_handles(end + 1) = plot(ax, plot_args{:}); %#ok<AGROW>
                legend_entries{end + 1} = trace.label; %#ok<AGROW>
            end
            hold(ax, 'off');
            xlabel(ax, 'Time (s)', 'Color', app.layout_cfg.colors.fg_text);
            ylabel(ax, panel.ylabel, 'Color', app.layout_cfg.colors.fg_text);
            title(ax, panel.title, 'Color', app.layout_cfg.colors.fg_text, 'Interpreter', 'none');
            grid(ax, 'on');
            if ~isempty(line_handles)
                legend(ax, line_handles, legend_entries, 'Location', 'best', 'Box', 'off', ...
                    'TextColor', app.layout_cfg.colors.fg_text, 'Color', app.layout_cfg.colors.bg_dark);
            else
                text(ax, 0.5, 0.5, char(string(panel.placeholder_text)), ...
                    'Units', 'normalized', ...
                    'HorizontalAlignment', 'center', 'VerticalAlignment', 'middle', ...
                    'Color', app.layout_cfg.colors.fg_muted);
                xlim(ax, [0, 1]);
                ylim(ax, [0, 1]);
            end
        end

        function open_collector_plot_popup(app, button_spec, metric_catalog)
            if nargin < 3 || isempty(metric_catalog)
                metric_catalog = struct([]);
            end
            existing = [];
            if isfield(app.handles, 'collector_plot_dialog') && app.is_live_handle(app.handles.collector_plot_dialog)
                existing = app.handles.collector_plot_dialog;
            end
            if ~isempty(existing)
                app.focus_collector_plot_dialog(existing);
                app.configure_collector_plot_popup(button_spec, metric_catalog);
                return;
            end

            dlg = uifigure( ...
                'Name', 'Collector Plot Popup', ...
                'Color', app.layout_cfg.colors.bg_dark, ...
                'Position', app.compute_multi_vortex_dialog_position([1120 760]));
            dlg.CloseRequestFcn = @(src,~) app.close_collector_plot_dialog(src);

            root = uigridlayout(dlg, [2, 1]);
            root.RowHeight = {'fit', '1x'};
            root.ColumnWidth = {'1x'};
            root.Padding = [10 10 10 10];
            root.RowSpacing = 8;

            control_panel = uipanel(root, ...
                'Title', 'Plot Controls', ...
                'Scrollable', 'on', ...
                'BackgroundColor', app.layout_cfg.colors.bg_panel_alt, ...
                'ForegroundColor', app.layout_cfg.colors.fg_text);
            control_panel.Layout.Row = 1;
            control_grid = uigridlayout(control_panel, [4, 4]);
            control_grid.RowHeight = {'fit', 'fit', 'fit', 'fit'};
            control_grid.ColumnWidth = {90, '1x', 90, '1x'};
            control_grid.Padding = [8 8 8 8];
            control_grid.RowSpacing = 6;
            control_grid.ColumnSpacing = 8;

            lbl_x = uilabel(control_grid, 'Text', 'X-axis', 'FontColor', app.layout_cfg.colors.fg_text);
            lbl_x.Layout.Row = 1; lbl_x.Layout.Column = 1;
            dd_x = uidropdown(control_grid, 'Items', {'Session Time (s)'}, ...
                'BackgroundColor', app.layout_cfg.colors.bg_input, ...
                'FontColor', app.layout_cfg.colors.fg_text);
            dd_x.Layout.Row = 1; dd_x.Layout.Column = 2;
            lbl_y = uilabel(control_grid, 'Text', 'Y-axis', 'FontColor', app.layout_cfg.colors.fg_text);
            lbl_y.Layout.Row = 1; lbl_y.Layout.Column = 3;
            dd_y = uidropdown(control_grid, 'Items', {'No collector metrics available'}, ...
                'BackgroundColor', app.layout_cfg.colors.bg_input, ...
                'FontColor', app.layout_cfg.colors.fg_text);
            dd_y.Layout.Row = 1; dd_y.Layout.Column = 4;

            lbl_title = uilabel(control_grid, 'Text', 'Title', 'FontColor', app.layout_cfg.colors.fg_text);
            lbl_title.Layout.Row = 2; lbl_title.Layout.Column = 1;
            txt_title = uieditfield(control_grid, 'text', ...
                'BackgroundColor', app.layout_cfg.colors.bg_input, ...
                'FontColor', app.layout_cfg.colors.fg_text);
            txt_title.Layout.Row = 2; txt_title.Layout.Column = [2 4];

            lbl_xlabel = uilabel(control_grid, 'Text', 'X label', 'FontColor', app.layout_cfg.colors.fg_text);
            lbl_xlabel.Layout.Row = 3; lbl_xlabel.Layout.Column = 1;
            txt_xlabel = uieditfield(control_grid, 'text', ...
                'BackgroundColor', app.layout_cfg.colors.bg_input, ...
                'FontColor', app.layout_cfg.colors.fg_text);
            txt_xlabel.Layout.Row = 3; txt_xlabel.Layout.Column = [2 4];

            lbl_ylabel = uilabel(control_grid, 'Text', 'Y label', 'FontColor', app.layout_cfg.colors.fg_text);
            lbl_ylabel.Layout.Row = 4; lbl_ylabel.Layout.Column = 1;
            txt_ylabel = uieditfield(control_grid, 'text', ...
                'BackgroundColor', app.layout_cfg.colors.bg_input, ...
                'FontColor', app.layout_cfg.colors.fg_text);
            txt_ylabel.Layout.Row = 4; txt_ylabel.Layout.Column = 2;

            btn_save = uibutton(control_grid, ...
                'Text', 'Save Plot', ...
                'FontWeight', 'bold', ...
                'ButtonPushedFcn', @(~,~) app.save_collector_popup_plot());
            btn_save.Layout.Row = 4; btn_save.Layout.Column = 3;
            btn_close = uibutton(control_grid, ...
                'Text', 'Close', ...
                'ButtonPushedFcn', @(~,~) app.close_collector_plot_dialog(dlg));
            btn_close.Layout.Row = 4; btn_close.Layout.Column = 4;

            preview_ax = uiaxes(root);
            preview_ax.Layout.Row = 2;
            app.style_results_axes(preview_ax);

            app.handles.collector_plot_dialog = dlg;
            app.handles.collector_plot_popup_x = dd_x;
            app.handles.collector_plot_popup_y = dd_y;
            app.handles.collector_plot_popup_title = txt_title;
            app.handles.collector_plot_popup_xlabel = txt_xlabel;
            app.handles.collector_plot_popup_ylabel = txt_ylabel;
            app.handles.collector_plot_popup_axes = preview_ax;
            app.handles.collector_plot_popup_save = btn_save;
            app.handles.collector_plot_popup_catalog = struct([]);
            app.handles.collector_plot_popup_button_spec = struct();

            dd_x.ValueChangedFcn = @(~,~) app.update_collector_plot_popup_preview();
            dd_y.ValueChangedFcn = @(~,~) app.update_collector_plot_popup_preview();
            txt_title.ValueChangedFcn = @(~,~) app.update_collector_plot_popup_preview(false);
            txt_xlabel.ValueChangedFcn = @(~,~) app.update_collector_plot_popup_preview(false);
            txt_ylabel.ValueChangedFcn = @(~,~) app.update_collector_plot_popup_preview(false);

            app.configure_collector_plot_popup(button_spec, metric_catalog);
            app.focus_collector_plot_dialog(dlg);
        end

        function configure_collector_plot_popup(app, button_spec, metric_catalog)
            if ~app.has_valid_handle('collector_plot_dialog')
                return;
            end
            popup_catalog = app.build_collector_popup_catalog(metric_catalog);
            app.handles.collector_plot_popup_catalog = popup_catalog;
            app.handles.collector_plot_popup_button_spec = button_spec;
            x_items = string({popup_catalog.display_name});
            x_data = string({popup_catalog.id});
            y_catalog = popup_catalog(~strcmp({popup_catalog.id}, 'session_time_s'));
            y_items = string({y_catalog.display_name});
            y_data = string({y_catalog.id});
            if isempty(y_items)
                y_items = "No collector metrics available";
                y_data = "";
            end

            app.handles.collector_plot_popup_x.Items = cellstr(x_items);
            app.handles.collector_plot_popup_x.ItemsData = cellstr(x_data);
            app.handles.collector_plot_popup_y.Items = cellstr(y_items);
            app.handles.collector_plot_popup_y.ItemsData = cellstr(y_data);

            app.handles.collector_plot_popup_x.Value = char(string(app.default_collector_popup_x_id(button_spec, popup_catalog)));
            default_y_id = char(string(app.default_collector_popup_y_id(button_spec, y_catalog)));
            if isempty(default_y_id)
                default_y_id = char(string(y_data(1)));
            end
            app.handles.collector_plot_popup_y.Value = default_y_id;
            app.handles.collector_plot_popup_title.Value = char(string(button_spec.default_title));
            app.handles.collector_plot_popup_xlabel.Value = char(string(button_spec.default_xlabel));
            app.handles.collector_plot_popup_ylabel.Value = char(string(button_spec.default_ylabel));
            app.update_collector_plot_popup_preview(true);
        end

        function popup_catalog = build_collector_popup_catalog(app, metric_catalog)
            popup_catalog = repmat(struct( ...
                'id', '', ...
                'display_name', '', ...
                'source', '', ...
                'metric_key', '', ...
                'table_column', '', ...
                'default_title', '', ...
                'default_xlabel', 'Time (s)', ...
                'default_ylabel', '', ...
                'raw_header', '', ...
                'column_index', 0, ...
                'origin', ''), 1, 0);
            popup_catalog(end + 1) = struct( ... %#ok<AGROW>
                'id', 'session_time_s', ...
                'display_name', 'Session Time (s)', ...
                'source', 'session', ...
                'metric_key', 'elapsed_wall_time', ...
                'table_column', 'elapsed_wall_time', ...
                'default_title', 'Collector Overlay', ...
                'default_xlabel', 'Time (s)', ...
                'default_ylabel', 'Time (s)', ...
                'raw_header', '', ...
                'column_index', 0, ...
                'origin', 'session');
            popup_catalog(end + 1) = struct( ... %#ok<AGROW>
                'id', 'wall_clock_time', ...
                'display_name', 'Wall Clock Time', ...
                'source', 'session', ...
                'metric_key', 'wall_clock_time', ...
                'table_column', 'wall_clock_time', ...
                'default_title', 'Collector Overlay', ...
                'default_xlabel', 'Wall Clock Time', ...
                'default_ylabel', 'Wall Clock Time', ...
                'raw_header', '', ...
                'column_index', 0, ...
                'origin', 'session');
            if isempty(metric_catalog)
                return;
            end
            if ~isstruct(metric_catalog)
                metric_catalog = [metric_catalog{:}];
            end
            for i = 1:numel(metric_catalog)
                item = metric_catalog(i);
                popup_catalog(end + 1) = struct( ... %#ok<AGROW>
                    'id', char(string(item.id)), ...
                    'display_name', char(string(item.display_name)), ...
                    'source', char(string(item.source)), ...
                    'metric_key', char(string(item.metric_key)), ...
                    'table_column', char(string(app.pick_field(item, {'table_column'}, ''))), ...
                    'default_title', char(string(item.default_title)), ...
                    'default_xlabel', char(string(item.default_xlabel)), ...
                    'default_ylabel', char(string(item.default_ylabel)), ...
                    'raw_header', char(string(app.pick_field(item, {'raw_header'}, ''))), ...
                    'column_index', double(app.pick_field(item, {'column_index'}, 0)), ...
                    'origin', char(string(app.pick_field(item, {'origin'}, ''))));
            end
        end

        function value = default_collector_popup_x_id(~, button_spec, popup_catalog)
            value = 'session_time_s';
            ids = string({popup_catalog.id});
            if isstruct(button_spec) && isfield(button_spec, 'default_x_id') && ...
                    any(ids == string(button_spec.default_x_id))
                value = char(string(button_spec.default_x_id));
            end
        end

        function value = default_collector_popup_y_id(~, button_spec, popup_catalog)
            value = '';
            ids = string({popup_catalog.id});
            if isstruct(button_spec) && isfield(button_spec, 'default_y_id') && ...
                    any(ids == string(button_spec.default_y_id))
                value = char(string(button_spec.default_y_id));
                return;
            end
            if ~isempty(ids)
                value = char(ids(1));
            end
        end

        function focus_collector_plot_dialog(app, dlg)
            if nargin < 2 || isempty(dlg) || ~app.is_live_handle(dlg)
                return;
            end
            try
                dlg.Position = app.compute_multi_vortex_dialog_position(dlg.Position(3:4));
                figure(dlg);
            catch
            end
        end

        function close_collector_plot_dialog(app, dlg)
            if nargin < 2 || isempty(dlg)
                if isfield(app.handles, 'collector_plot_dialog')
                    dlg = app.handles.collector_plot_dialog;
                else
                    dlg = [];
                end
            end
            if ~isempty(dlg)
                try
                    if app.is_live_handle(dlg)
                        delete(dlg);
                    end
                catch
                end
            end
            fields = { ...
                'collector_plot_dialog', ...
                'collector_plot_popup_x', ...
                'collector_plot_popup_y', ...
                'collector_plot_popup_title', ...
                'collector_plot_popup_xlabel', ...
                'collector_plot_popup_ylabel', ...
                'collector_plot_popup_axes', ...
                'collector_plot_popup_save', ...
                'collector_plot_popup_catalog', ...
                'collector_plot_popup_button_spec'};
            for i = 1:numel(fields)
                if isfield(app.handles, fields{i})
                    app.handles = rmfield(app.handles, fields{i});
                end
            end
        end

        function update_collector_plot_popup_preview(app, varargin)
            reset_labels = true;
            if nargin >= 2
                reset_labels = logical(varargin{1});
            end
            if ~app.has_valid_handle('collector_plot_popup_axes') || ...
                    ~app.has_valid_handle('collector_plot_popup_x') || ...
                    ~app.has_valid_handle('collector_plot_popup_y')
                return;
            end

            popup_catalog = app.handles.collector_plot_popup_catalog;
            x_entry = app.resolve_collector_popup_catalog_entry(char(string(app.handles.collector_plot_popup_x.Value)), popup_catalog);
            y_entry = app.resolve_collector_popup_catalog_entry(char(string(app.handles.collector_plot_popup_y.Value)), popup_catalog);
            traces = app.resolve_collector_popup_traces(x_entry, y_entry);

            if reset_labels
                if app.has_valid_handle('collector_plot_popup_title')
                    app.handles.collector_plot_popup_title.Value = char(string(y_entry.default_title));
                end
                if app.has_valid_handle('collector_plot_popup_xlabel')
                    app.handles.collector_plot_popup_xlabel.Value = char(string(x_entry.default_ylabel));
                end
                if app.has_valid_handle('collector_plot_popup_ylabel')
                    app.handles.collector_plot_popup_ylabel.Value = char(string(y_entry.default_ylabel));
                end
            end

            ax = app.handles.collector_plot_popup_axes;
            cla(ax);
            hold(ax, 'on');
            legends = {};
            handles = gobjects(0);
            for i = 1:numel(traces)
                handles(end + 1) = plot(ax, traces(i).x, traces(i).y, ... %#ok<AGROW>
                    'LineWidth', 1.7, ...
                    'Color', traces(i).color, ...
                    'LineStyle', traces(i).line_style);
                legends{end + 1} = traces(i).label; %#ok<AGROW>
            end
            hold(ax, 'off');
            xlabel(ax, char(string(app.handles.collector_plot_popup_xlabel.Value)), 'Color', app.layout_cfg.colors.fg_text);
            ylabel(ax, char(string(app.handles.collector_plot_popup_ylabel.Value)), 'Color', app.layout_cfg.colors.fg_text);
            title(ax, char(string(app.handles.collector_plot_popup_title.Value)), 'Color', app.layout_cfg.colors.fg_text, 'Interpreter', 'none');
            grid(ax, 'on');
            if isempty(handles)
                text(ax, 0.5, 0.5, 'No current-session run has this metric pair.', ...
                    'Units', 'normalized', 'HorizontalAlignment', 'center', ...
                    'VerticalAlignment', 'middle', 'Color', app.layout_cfg.colors.fg_muted);
                xlim(ax, [0, 1]);
                ylim(ax, [0, 1]);
            else
                legend(ax, handles, legends, 'Location', 'best', 'Box', 'off', ...
                    'TextColor', app.layout_cfg.colors.fg_text, 'Color', app.layout_cfg.colors.bg_dark);
            end
        end

        function entry = resolve_collector_popup_catalog_entry(~, entry_id, popup_catalog)
            entry = struct('id', 'session_time_s', 'display_name', 'Session Time (s)', ...
                'source', 'session', 'metric_key', 'elapsed_wall_time', 'default_title', 'Collector Overlay', ...
                'default_xlabel', 'Time (s)', 'default_ylabel', 'Time (s)', ...
                'raw_header', '', 'column_index', 0, 'origin', 'session');
            if isempty(popup_catalog)
                return;
            end
            idx = find(strcmp({popup_catalog.id}, char(string(entry_id))), 1, 'first');
            if ~isempty(idx)
                entry = popup_catalog(idx);
            end
        end

        function traces = resolve_collector_popup_traces(app, x_entry, y_entry)
            traces = repmat(struct('x', zeros(1, 0), 'y', zeros(1, 0), 'label', '', 'color', [0 0 0], 'line_style', '-'), 1, 0);
            entries = app.collector_popup_session_entries();
            if isempty(entries)
                return;
            end
            for i = 1:numel(entries)
                entry = entries(i);
                [x_vals, y_vals] = app.collector_popup_xy_vectors_from_launch_csv(entry, x_entry, y_entry);
                if isempty(x_vals) || isempty(y_vals)
                    [x_vals, y_vals] = app.collector_popup_xy_vectors(entry.monitor_series, x_entry, y_entry);
                end
                if isempty(x_vals) || isempty(y_vals)
                    continue;
                end
                style = ExternalCollectorDispatcher.source_plot_style(y_entry.source, y_entry.metric_key);
                traces(end + 1) = struct( ... %#ok<AGROW>
                    'x', x_vals, ...
                    'y', y_vals, ...
                    'label', sprintf('%s | %s | %s', ...
                        char(string(entry.run_badge)), ...
                        char(string(app.pick_field(entry.metadata, {'run_id'}, entry.name))), ...
                        char(string(y_entry.display_name))), ...
                    'color', style.rgb, ...
                    'line_style', style.line_style);
            end
        end

        function [x_vals, y_vals] = collector_popup_xy_vectors(app, monitor_series, x_entry, y_entry)
            y_vals = app.collector_metric_vector(monitor_series, y_entry.source, y_entry.metric_key);
            if isempty(y_vals) || ~any(isfinite(y_vals))
                x_vals = zeros(1, 0);
                y_vals = zeros(1, 0);
                return;
            end
            if strcmpi(char(string(x_entry.id)), 'session_time_s')
                x_vals = app.rowvec(app.pick_field(monitor_series, {'elapsed_wall_time', 't'}, 0:(numel(y_vals) - 1)));
            elseif strcmpi(char(string(x_entry.id)), 'wall_clock_time')
                x_vals = app.rowvec(app.pick_field(monitor_series, {'wall_clock_time', 'elapsed_wall_time', 't'}, 0:(numel(y_vals) - 1)));
            else
                x_vals = app.collector_metric_vector(monitor_series, x_entry.source, x_entry.metric_key);
            end
            x_vals = app.rowvec(x_vals);
            y_vals = app.rowvec(y_vals);
            n = min(numel(x_vals), numel(y_vals));
            if n <= 0
                x_vals = zeros(1, 0);
                y_vals = zeros(1, 0);
                return;
            end
            x_vals = double(x_vals(1:n));
            y_vals = double(y_vals(1:n));
            finite_mask = isfinite(x_vals) & isfinite(y_vals);
            x_vals = x_vals(finite_mask);
            y_vals = y_vals(finite_mask);
            if strcmpi(char(string(x_entry.id)), 'wall_clock_time') && ~isempty(x_vals) && any(x_vals > 1e9)
                x_vals = datetime(x_vals, 'ConvertFrom', 'posixtime', 'TimeZone', 'local');
            end
        end

        function entries = collector_popup_session_entries(app)
            entries = app.session_figures;
            if isempty(entries)
                return;
            end

            keep_mask = true(1, numel(entries));
            current_session_id = char(string(app.collector_launch_session_id));
            for idx = 1:numel(entries)
                entry = entries(idx);
                if isfield(entry, 'artifacts') && isstruct(entry.artifacts) && ...
                        isfield(entry.artifacts, 'is_imported') && logical(entry.artifacts.is_imported)
                    keep_mask(idx) = false;
                    continue;
                end
                if isempty(current_session_id)
                    continue;
                end
                entry_session_id = '';
                if isfield(entry, 'artifacts') && isstruct(entry.artifacts) && ...
                        isfield(entry.artifacts, 'launch_session') && isstruct(entry.artifacts.launch_session) && ...
                        isfield(entry.artifacts.launch_session, 'session_id')
                    entry_session_id = char(string(entry.artifacts.launch_session.session_id));
                end
                if ~isempty(entry_session_id) && ~strcmpi(entry_session_id, current_session_id)
                    keep_mask(idx) = false;
                end
            end
            entries = entries(keep_mask);
        end

        function [x_vals, y_vals] = collector_popup_xy_vectors_from_launch_csv(app, entry, x_entry, y_entry)
            x_vals = zeros(1, 0);
            y_vals = zeros(1, 0);
            csv_path = '';
            session_id = "";
            if isfield(entry, 'artifacts') && isstruct(entry.artifacts) && ...
                    isfield(entry.artifacts, 'launch_session') && isstruct(entry.artifacts.launch_session)
                if isfield(entry.artifacts.launch_session, 'session_csv_path')
                    csv_path = char(string(entry.artifacts.launch_session.session_csv_path));
                end
                if isfield(entry.artifacts.launch_session, 'session_id')
                    session_id = string(entry.artifacts.launch_session.session_id);
                end
            end
            if isempty(csv_path) || exist(csv_path, 'file') ~= 2
                return;
            end

            try
                data = readtable(csv_path, 'TextType', 'string');
            catch
                return;
            end
            if isempty(data) || ~any(strcmp(string(data.Properties.VariableNames), "run_id"))
                return;
            end

            run_id = string(app.pick_field(entry.metadata, {'run_id'}, ''));
            mask = true(height(data), 1);
            if strlength(run_id) > 0
                mask = mask & string(data.run_id) == run_id;
            end
            if strlength(session_id) > 0 && any(strcmp(string(data.Properties.VariableNames), "ui_launch_session_id"))
                mask = mask & string(data.ui_launch_session_id) == session_id;
            end
            if ~any(mask)
                return;
            end
            rows = data(mask, :);

            x_col = app.collector_popup_table_column(x_entry);
            y_col = app.collector_popup_table_column(y_entry);
            if ~any(strcmp(string(rows.Properties.VariableNames), x_col)) || ...
                    ~any(strcmp(string(rows.Properties.VariableNames), y_col))
                return;
            end

            x_vals = app.rowvec(rows.(x_col));
            y_vals = app.rowvec(rows.(y_col));
            n = min(numel(x_vals), numel(y_vals));
            if n <= 0
                x_vals = zeros(1, 0);
                y_vals = zeros(1, 0);
                return;
            end
            x_vals = double(x_vals(1:n));
            y_vals = double(y_vals(1:n));
            finite_mask = isfinite(x_vals) & isfinite(y_vals);
            x_vals = x_vals(finite_mask);
            y_vals = y_vals(finite_mask);
            if strcmpi(char(string(x_entry.id)), 'wall_clock_time') && ~isempty(x_vals) && any(x_vals > 1e9)
                x_vals = datetime(x_vals, 'ConvertFrom', 'posixtime', 'TimeZone', 'local');
            end
        end

        function column_name = collector_popup_table_column(~, entry)
            table_column = string(entry.table_column);
            if strlength(table_column) > 0
                column_name = table_column;
                return;
            end
            column_name = string(matlab.lang.makeValidName(sprintf('%s_%s', ...
                char(string(entry.source)), char(string(entry.metric_key)))));
        end

        function save_collector_popup_plot(app)
            if ~app.has_valid_handle('collector_plot_popup_axes')
                return;
            end
            [file, path] = uiputfile({'*.fig', 'MATLAB Figure (*.fig)'}, 'Save Collector Plot', 'collector_plot.fig');
            if isequal(file, 0)
                return;
            end
            output_path = fullfile(path, file);
            fig = figure('Visible', 'off', 'Color', [1 1 1]);
            cleanup_fig = onCleanup(@() UIController.safe_close_figure(fig)); %#ok<NASGU>
            ax = axes(fig); %#ok<LAXES>
            popup_catalog = app.handles.collector_plot_popup_catalog;
            x_entry = app.resolve_collector_popup_catalog_entry(char(string(app.handles.collector_plot_popup_x.Value)), popup_catalog);
            y_entry = app.resolve_collector_popup_catalog_entry(char(string(app.handles.collector_plot_popup_y.Value)), popup_catalog);
            traces = app.resolve_collector_popup_traces(x_entry, y_entry);
            hold(ax, 'on');
            legends = {};
            for i = 1:numel(traces)
                plot(ax, traces(i).x, traces(i).y, 'LineWidth', 1.8, ...
                    'Color', traces(i).color, 'LineStyle', traces(i).line_style);
                legends{end + 1} = traces(i).label; %#ok<AGROW>
            end
            hold(ax, 'off');
            xlabel(ax, char(string(app.handles.collector_plot_popup_xlabel.Value)));
            ylabel(ax, char(string(app.handles.collector_plot_popup_ylabel.Value)));
            title(ax, char(string(app.handles.collector_plot_popup_title.Value)), 'Interpreter', 'none');
            grid(ax, 'on');
            if ~isempty(legends)
                legend(ax, legends, 'Location', 'best', 'Box', 'off');
            end
            save_settings = struct( ...
                'figure_save_png', false, ...
                'figure_save_pdf', false, ...
                'figure_save_fig', true, ...
                'figure_dpi', app.config.figures_dpi);
            outputs = ResultsPlotDispatcher.save_figure_bundle(fig, output_path, save_settings);
            app.append_to_terminal(sprintf('Saved collector popup plot: %s', ...
                ResultsPlotDispatcher.primary_output_path(outputs, output_path)), 'success');
        end

        function on_results_animation_slider(app, slider, time_label, count_label, ...
                omega_cube, psi_cube, u_cube, v_cube, snap_times, x_vec, y_vec, snapshot_spec, format_opts, plot_colors, ...
                anim_axes, anim_view_modes, anim_view_titles, plot_mask, bathy_profile_x, bathy_profile_y)
            if ~app.are_live_handles(slider) || any(~arrayfun(@(h) app.is_live_handle(h), anim_axes))
                return;
            end
            if isempty(omega_cube) || ndims(omega_cube) < 3
                return;
            end
            n_frames = size(omega_cube, 3);
            idx = max(1, min(n_frames, round(slider.Value)));
            slider.Value = idx;

            t_str = sprintf('%d', idx);
            if ~isempty(snap_times) && numel(snap_times) >= idx
                t_str = sprintf('%.3g', snap_times(idx));
            end

            snap_labels = struct('xlabel', 'x', 'ylabel', 'y', 'title', '\omega');
            if isstruct(snapshot_spec) && isfield(snapshot_spec, 'labels') && isstruct(snapshot_spec.labels)
                snap_labels = snapshot_spec.labels;
            end

            %#ok<NASGU> % snapshot_spec/format_opts are preserved for callback contract compatibility.
            app.render_results_animation_grid(anim_axes, anim_view_modes, anim_view_titles, ...
                omega_cube(:,:,idx), app.extract_cube_snapshot(psi_cube, idx), ...
                app.extract_cube_snapshot(u_cube, idx), app.extract_cube_snapshot(v_cube, idx), ...
                x_vec, y_vec, t_str, plot_colors, plot_mask, bathy_profile_x, bathy_profile_y, snap_labels);

            if ~isempty(time_label) && isvalid(time_label)
                time_label.Text = sprintf('t = %s s', t_str);
            end
            if ~isempty(count_label) && isvalid(count_label)
                count_label.Text = sprintf('Frame %d / %d', idx, n_frames);
            end
        end

        function on_results_animation_play_toggled(app, play_toggle, loop_checkbox, slider, time_label, count_label, ...
                omega_cube, psi_cube, u_cube, v_cube, snap_times, x_vec, y_vec, snapshot_spec, format_opts, plot_colors, ...
                anim_axes, anim_view_modes, anim_view_titles, plot_mask, bathy_profile_x, bathy_profile_y)
            if ~app.are_live_handles(play_toggle)
                return;
            end
            if ~play_toggle.Value
                play_toggle.Text = 'Play';
                return;
            end

            play_toggle.Text = 'Stop';
            n_frames = size(omega_cube, 3);
            fps = 24;
            if isfield(app.config, 'animation_fps') && isnumeric(app.config.animation_fps) && isfinite(app.config.animation_fps)
                fps = max(1, double(app.config.animation_fps));
            end
            frame_pause = 1 / fps;

            while app.are_live_handles(play_toggle, loop_checkbox, slider) && ...
                    all(arrayfun(@(h) app.is_live_handle(h), anim_axes)) && ...
                    play_toggle.Value
                idx = max(1, min(n_frames, round(slider.Value)));
                if idx >= n_frames
                    if loop_checkbox.Value
                        idx = 1;
                    else
                        break;
                    end
                else
                    idx = idx + 1;
                end
                try
                    slider.Value = idx;
                    app.on_results_animation_slider(slider, time_label, count_label, ...
                        omega_cube, psi_cube, u_cube, v_cube, snap_times, x_vec, y_vec, snapshot_spec, format_opts, plot_colors, ...
                        anim_axes, anim_view_modes, anim_view_titles, plot_mask, bathy_profile_x, bathy_profile_y);
                catch ME
                    if strcmp(ME.identifier, 'MATLAB:class:InvalidHandle') || ...
                            contains(ME.message, 'Invalid or deleted object')
                        break;
                    end
                    rethrow(ME);
                end
                drawnow limitrate;
                pause(frame_pause);
            end

            if app.is_live_handle(play_toggle)
                play_toggle.Value = false;
                play_toggle.Text = 'Play';
            end
        end

        function span = resolve_snapshot_time_span(~, params, analysis, raw_snap_times, n_snaps)
            span = NaN;
            if ~isempty(raw_snap_times) && isnumeric(raw_snap_times)
                vals = double(raw_snap_times(:));
                vals = vals(isfinite(vals));
                if ~isempty(vals)
                    span = max(vals) - min(vals);
                    if span <= 0
                        span = max(vals);
                    end
                end
            end
            if (~isfinite(span) || span <= 0) && isstruct(analysis) && ...
                    isfield(analysis, 'time_vec') && isnumeric(analysis.time_vec) && ~isempty(analysis.time_vec)
                vals = double(analysis.time_vec(:));
                vals = vals(isfinite(vals));
                if ~isempty(vals)
                    span = max(vals) - min(vals);
                    if span <= 0
                        span = max(vals);
                    end
                end
            end
            if (~isfinite(span) || span <= 0) && isstruct(params)
                if isfield(params, 'Tfinal') && isnumeric(params.Tfinal) && isfinite(params.Tfinal)
                    span = double(params.Tfinal);
                elseif isfield(params, 't_final') && isnumeric(params.t_final) && isfinite(params.t_final)
                    span = double(params.t_final);
                end
            end
            if ~isfinite(span) || span <= 0
                span = max(double(n_snaps - 1), 1.0);
            end
        end

        function [omega_out, times_out] = resample_snapshot_cube(~, omega_cube, snap_times, target_count, time_span)
            omega_out = omega_cube;
            times_out = snap_times;
            if isempty(omega_cube) || ndims(omega_cube) < 3
                return;
            end

            if nargin < 5 || ~isnumeric(time_span) || ~isfinite(time_span) || time_span <= 0
                time_span = max(size(omega_cube, 3) - 1, 1);
            end

            n_src = size(omega_cube, 3);
            target_count = max(1, round(double(target_count)));
            if target_count <= n_src
                if isempty(times_out) || numel(times_out) ~= n_src
                    times_out = linspace(0, time_span, n_src);
                else
                    times_out = double(times_out(:)).';
                end
                return;
            end

            if n_src == 1
                omega_out = repmat(omega_cube, 1, 1, target_count);
                if isempty(times_out)
                    times_out = zeros(1, target_count);
                else
                    times_out = repmat(double(times_out(1)), 1, target_count);
                end
                return;
            end

            src_t = linspace(0, 1, n_src);
            tgt_t = linspace(0, 1, target_count);
            omega_flat = reshape(double(omega_cube), [], n_src).';
            omega_interp = interp1(src_t, omega_flat, tgt_t, 'linear');
            omega_out = reshape(omega_interp.', size(omega_cube, 1), size(omega_cube, 2), target_count);

            if isempty(snap_times) || numel(snap_times) ~= n_src
                times_out = linspace(0, time_span, target_count);
            else
                times_src = double(snap_times(:)).';
                times_out = interp1(src_t, times_src, tgt_t, 'linear');
            end
        end

        function indices = resolve_snapshot_indices_for_gallery(~, params, n_available, tile_count)
            n_available = max(0, round(double(n_available)));
            tile_count = max(1, round(double(tile_count)));
            if n_available <= 0
                indices = [];
                return;
            end

            plot_count = tile_count;
            if isstruct(params)
                if isfield(params, 'num_plot_snapshots') && isnumeric(params.num_plot_snapshots)
                    plot_count = max(1, round(double(params.num_plot_snapshots)));
                end
            end

            base_idx = [];
            if isstruct(params) && isfield(params, 'snapshot_plot_indices') && isnumeric(params.snapshot_plot_indices)
                base_idx = round(double(params.snapshot_plot_indices(:))).';
            end
            if ~isempty(base_idx)
                base_idx = base_idx(isfinite(base_idx));
            end
            if ~isempty(base_idx) && n_available > plot_count
                trivial_gallery_map = isequal(base_idx, 1:numel(base_idx)) || ...
                    (numel(base_idx) == min(plot_count, n_available) && max(base_idx) <= numel(base_idx));
                if trivial_gallery_map
                    base_idx = [];
                end
            end
            if isempty(base_idx)
                base_idx = round(linspace(1, n_available, min(plot_count, n_available)));
            end
            base_idx = max(1, min(n_available, base_idx));
            base_idx = unique(base_idx, 'stable');
            if isempty(base_idx)
                base_idx = 1;
            end

            pos = linspace(1, numel(base_idx), tile_count);
            pick = max(1, min(numel(base_idx), round(pos)));
            indices = base_idx(pick);
        end

        function populate_snapshot_gallery_tab(app, target_tab, omega_cube, psi_cube, u_cube, v_cube, snap_times, x_vec, y_vec, indices, view_mode, title_text, plot_mask, bathy_profile_x, bathy_profile_y)
            grid = uigridlayout(target_tab, [2, 1]);
            grid.RowHeight = {'fit', '1x'};
            grid.Padding = [8 8 8 8];
            grid.RowSpacing = 6;

            C = app.layout_cfg.colors;
            lbl = uilabel(grid, ...
                'Text', title_text, ...
                'FontColor', C.fg_muted, ...
                'FontSize', 11, ...
                'WordWrap', 'on');
            lbl.Layout.Row = 1;

            tile_grid = uigridlayout(grid, [3, 3]);
            tile_grid.Layout.Row = 2;
            tile_grid.RowHeight = {'1x', '1x', '1x'};
            tile_grid.ColumnWidth = {'1x', '1x', '1x'};
            tile_grid.Padding = [0 0 0 0];
            tile_grid.RowSpacing = 6;
            tile_grid.ColumnSpacing = 6;

            if isempty(omega_cube) || isempty(indices)
                empty_lbl = uilabel(tile_grid, ...
                    'Text', 'No snapshot data available.', ...
                    'HorizontalAlignment', 'center', ...
                    'VerticalAlignment', 'center', ...
                    'FontColor', C.fg_muted, ...
                    'WordWrap', 'on');
                empty_lbl.Layout.Row = 2;
                empty_lbl.Layout.Column = [1 3];
                return;
            end

            ny = size(omega_cube, 1);
            nx = size(omega_cube, 2);
            if isempty(x_vec) || numel(x_vec) ~= nx
                x_vec = linspace(-1, 1, nx);
            else
                x_vec = double(x_vec(:)).';
            end
            if isempty(y_vec) || numel(y_vec) ~= ny
                y_vec = linspace(-1, 1, ny);
            else
                y_vec = double(y_vec(:)).';
            end

            idx = max(1, min(size(omega_cube, 3), round(indices(:).')));
            if isempty(idx)
                idx = ones(1, 9);
            end
            if numel(idx) < 9
                idx = idx(max(1, min(numel(idx), round(linspace(1, numel(idx), 9)))));
            else
                idx = idx(1:9);
            end

            [cmin, cmax] = app.compute_result_omega_limits(omega_cube(:, :, idx), plot_mask);

            for i = 1:9
                ax = uiaxes(tile_grid);
                ax.Layout.Row = ceil(i / 3);
                ax.Layout.Column = mod(i - 1, 3) + 1;
                app.style_results_axes(ax);

                omega_slice = omega_cube(:, :, idx(i));
                psi_slice = app.extract_cube_snapshot(psi_cube, idx(i));
                u_slice = app.extract_cube_snapshot(u_cube, idx(i));
                v_slice = app.extract_cube_snapshot(v_cube, idx(i));
                app.render_result_view_mode(ax, view_mode, omega_slice, psi_slice, u_slice, v_slice, ...
                    x_vec, y_vec, sprintf('%.3g', idx(i)), ...
                    struct('fg', C.fg_text, 'primary', C.accent_cyan), plot_mask, bathy_profile_x, bathy_profile_y, cmin, cmax);
                xlabel(ax, 'x', 'Color', C.fg_muted);
                ylabel(ax, 'y', 'Color', C.fg_muted);

                if ~isempty(snap_times) && numel(snap_times) >= idx(i)
                    t_txt = sprintf('t = %.3g s', snap_times(idx(i)));
                else
                    t_txt = sprintf('Frame %d', idx(i));
                end
                title(ax, t_txt, 'Color', C.fg_text, 'Interpreter', 'none', 'FontSize', 11);
            end
        end

        function fig = create_snapshot_gallery_figure(app, omega_cube, psi_cube, u_cube, v_cube, snap_times, x_vec, y_vec, indices, view_mode, title_text, plot_mask, bathy_profile_x, bathy_profile_y, params, run_cfg)
            ny = size(omega_cube, 1);
            nx = size(omega_cube, 2);
            if isempty(x_vec) || numel(x_vec) ~= nx
                x_vec = linspace(-1, 1, nx);
            else
                x_vec = double(x_vec(:)).';
            end
            if isempty(y_vec) || numel(y_vec) ~= ny
                y_vec = linspace(-1, 1, ny);
            else
                y_vec = double(y_vec(:)).';
            end

            fig = figure('Visible', 'off', ...
                'HandleVisibility', 'off', ...
                'Color', [1 1 1], ...
                'MenuBar', 'none', ...
                'ToolBar', 'none', ...
                'Units', 'pixels', ...
                'Position', [80 80 1920 1080]);
            if nargin < 14 || ~isstruct(params)
                params = struct();
            end
            if nargin < 15 || ~isstruct(run_cfg)
                run_cfg = struct();
            end

            tl = tiledlayout(fig, 3, 3, 'Padding', 'compact', 'TileSpacing', 'compact');
            idx = max(1, min(size(omega_cube, 3), round(indices(:).')));
            if isempty(idx)
                idx = ones(1, 9);
            end
            if numel(idx) < 9
                idx = idx(max(1, min(numel(idx), round(linspace(1, numel(idx), 9)))));
            else
                idx = idx(1:9);
            end

            [cmin, cmax] = app.compute_result_omega_limits(omega_cube(:, :, idx), plot_mask);

            for i = 1:9
                ax = nexttile(tl, i);
                omega_slice = omega_cube(:, :, idx(i));
                psi_slice = app.extract_cube_snapshot(psi_cube, idx(i));
                u_slice = app.extract_cube_snapshot(u_cube, idx(i));
                v_slice = app.extract_cube_snapshot(v_cube, idx(i));
                app.render_result_view_mode(ax, view_mode, omega_slice, psi_slice, u_slice, v_slice, ...
                    x_vec, y_vec, sprintf('%.3g', idx(i)), ...
                    struct('fg', [0 0 0], 'primary', [0.05 0.20 0.55]), plot_mask, bathy_profile_x, bathy_profile_y, cmin, cmax);
                axis(ax, 'equal');
                axis(ax, 'tight');
                set(ax, 'YDir', 'normal');
                ax.Color = [1 1 1];
                ax.XColor = [0 0 0];
                ax.YColor = [0 0 0];
                ax.FontSize = 10;
                grid(ax, 'on');
                box(ax, 'on');
                xlabel(ax, 'x', 'Color', [0 0 0], 'FontSize', 10);
                ylabel(ax, 'y', 'Color', [0 0 0], 'FontSize', 10);
                if ~isempty(snap_times) && numel(snap_times) >= idx(i)
                    t_txt = sprintf('t = %.3g', snap_times(idx(i)));
                else
                    t_txt = sprintf('snap %d', idx(i));
                end
                title(ax, t_txt, 'Color', [0 0 0], 'FontWeight', 'bold', 'Interpreter', 'none', 'FontSize', 14);
            end

            ResultsPlotDispatcher.apply_tiled_annotations(tl, ...
                ResultsPlotDispatcher.compose_export_title(title_text, params, run_cfg), ...
                '', '', ResultsPlotDispatcher.default_light_colors());
        end

        function image_path = render_snapshot_gallery_image(app, omega_cube, psi_cube, u_cube, v_cube, snap_times, x_vec, y_vec, indices, view_mode, title_text, plot_mask, bathy_profile_x, bathy_profile_y)
            image_path = '';
            if isempty(omega_cube) || isempty(indices)
                return;
            end
            if nargin < 14
                bathy_profile_y = [];
            end
            if nargin < 13
                bathy_profile_x = [];
            end
            if nargin < 12
                plot_mask = [];
            end

            cache_dir = fullfile(tempdir, 'tsunami_ui_snapshot_grids');
            if ~exist(cache_dir, 'dir')
                mkdir(cache_dir);
            end
            stamp = char(datetime('now', 'Format', 'yyyyMMdd_HHmmssFFF'));
            image_path = fullfile(cache_dir, sprintf('grid_%s_%s.png', lower(char(string(view_mode))), stamp));

            fig = app.create_snapshot_gallery_figure(omega_cube, psi_cube, u_cube, v_cube, snap_times, x_vec, y_vec, indices, view_mode, title_text, ...
                plot_mask, bathy_profile_x, bathy_profile_y);
            cleanup_obj = onCleanup(@() app.close_hidden_figure(fig)); %#ok<NASGU>
            drawnow;
            exportgraphics(fig, image_path, 'Resolution', 170, 'BackgroundColor', 'white');
        end

        function html = render_animation_embed_html(app, animation_path)
            media_uri = app.local_file_uri(animation_path);
            mime = 'video/mp4';
            title_txt = 'Animation preview (MP4)';

            html = [ ...
                '<html><body style="margin:0;background:#0e1117;color:#d6dde8;font-family:Segoe UI;height:100%;">' ...
                '<div style="height:100%;display:grid;grid-template-rows:fit-content 1fr fit-content;row-gap:6px;padding:6px;box-sizing:border-box;">' ...
                '<div style="font-size:12px;color:#9fb4cc;">' char(string(app.escape_html_text(title_txt))) '</div>' ...
                '<video id="ts_anim_video" controls preload="auto" playsinline style="width:100%;height:100%;background:#0e1117;">' ...
                '<source src="' char(string(app.escape_html_text(media_uri))) '" type="' mime '">' ...
                '<source src="' char(string(app.escape_html_text(media_uri))) '">' ...
                '</video>' ...
                '<div id="ts_anim_fallback" style="display:none;padding:4px 0 0 0;font-size:12px;">Embedded playback failed. ' ...
                '<a href="' char(string(app.escape_html_text(media_uri))) '" style="color:#8ad7ff;">Open media file</a></div>' ...
                '</div>' ...
                '<script>var v=document.getElementById("ts_anim_video");var f=document.getElementById("ts_anim_fallback");' ...
                'if(v){v.addEventListener("error",function(){v.style.display="none";if(f){f.style.display="block";}});' ...
                'v.addEventListener("stalled",function(){if(f){f.style.display="block";}});}' ...
                '</script></body></html>'];
        end

        function source = render_animation_embed_source(app, animation_path)
            % Prefer local HTML file source for uihtml media playback stability.
            source = app.render_animation_embed_html(animation_path);
            try
                cache_dir = fullfile(tempdir, 'tsunami_ui_animation_embed');
                if ~exist(cache_dir, 'dir')
                    mkdir(cache_dir);
                end
                key = char(app.stable_text_hash(string(animation_path) + "|" + string(datetime('now', 'Format', 'yyyyMMddHHmmss'))));
                html_path = fullfile(cache_dir, ['anim_' key '.html']);
                fid = fopen(html_path, 'w', 'n', 'UTF-8');
                if fid >= 0
                    cleanup_obj = onCleanup(@() fclose(fid)); %#ok<NASGU>
                    fwrite(fid, source, 'char');
                    source = app.local_file_uri(html_path);
                end
            catch
                % Fall back to inline HTML source.
            end
        end

        function [psi, u, v] = velocity_from_omega_slice(~, omega_slice, x_vec, y_vec)
            % Periodic FFT-based reconstruction for visualization-only velocity fields.
            omega_slice = double(omega_slice);
            omega_slice(~isfinite(omega_slice)) = 0;
            ny = size(omega_slice, 1);
            nx = size(omega_slice, 2);
            dx = max(mean(diff(double(x_vec))), eps);
            dy = max(mean(diff(double(y_vec))), eps);

            omega0 = omega_slice - mean(omega_slice(:));
            omega_hat = fft2(omega0);
            kx = (2*pi/(nx*dx)) * [0:floor(nx/2), -floor((nx-1)/2):-1];
            ky = (2*pi/(ny*dy)) * [0:floor(ny/2), -floor((ny-1)/2):-1];
            [KX, KY] = meshgrid(kx, ky);
            k2 = KX.^2 + KY.^2;
            psi_hat = zeros(size(omega_hat));
            mask = k2 > 0;
            psi_hat(mask) = -omega_hat(mask) ./ k2(mask);
            psi = real(ifft2(psi_hat));
            % Repository convention: u = -dpsi/dy, v = dpsi/dx.
            u = -real(ifft2(1i * KY .* psi_hat));
            v = real(ifft2(1i * KX .* psi_hat));
        end

        function psi_cube = extract_streamfunction_snapshot_cube(~, analysis, omega_size)
            psi_cube = [];
            if ~isstruct(analysis) || ...
                    ~isfield(analysis, 'psi_snaps') || isempty(analysis.psi_snaps)
                return;
            end

            if isequal(size(analysis.psi_snaps), omega_size)
                psi_cube = double(analysis.psi_snaps);
            end
        end

        function wall_cube = extract_wall_omega_snapshot_cube(~, analysis, omega_size)
            wall_cube = [];
            if ~isstruct(analysis) || ...
                    ~isfield(analysis, 'fd_wall_omega_snaps') || isempty(analysis.fd_wall_omega_snaps)
                return;
            end

            if isequal(size(analysis.fd_wall_omega_snaps), omega_size)
                wall_cube = double(analysis.fd_wall_omega_snaps);
            end
        end

        function plot_context = resolve_result_plot_context(~, analysis, ny, nx)
            plot_context = resolve_bathymetry_plot_context(analysis, ny, nx);
        end

        function plot_mask = extract_result_plot_mask(app, analysis, ny, nx)
            plot_context = app.resolve_result_plot_context(analysis, ny, nx);
            plot_mask = plot_context.plot_mask;
        end

        function [profile_x, profile_y] = extract_result_bathymetry_outline(app, analysis)
            sample_cube = [];
            if isstruct(analysis) && isfield(analysis, 'omega_snaps') && ~isempty(analysis.omega_snaps)
                sample_cube = analysis.omega_snaps;
            end
            ny = 0;
            nx = 0;
            if ~isempty(sample_cube)
                ny = size(sample_cube, 1);
                nx = size(sample_cube, 2);
            end
            plot_context = app.resolve_result_plot_context(analysis, ny, nx);
            profile_x = plot_context.profile_x;
            profile_y = plot_context.profile_y;
        end

        function [u_cube, v_cube] = extract_velocity_snapshot_cubes(~, analysis, omega_size, plot_context)
            u_cube = [];
            v_cube = [];
            if nargin < 4 || ~isstruct(plot_context)
                plot_context = struct('requires_velocity_snapshots', false);
            end
            if ~isstruct(analysis) || ...
                    ~isfield(analysis, 'u_snaps') || isempty(analysis.u_snaps) || ...
                    ~isfield(analysis, 'v_snaps') || isempty(analysis.v_snaps)
                if isfield(plot_context, 'requires_velocity_snapshots') && plot_context.requires_velocity_snapshots
                    error('UIController:MissingVelocitySnapshotsForWallDomain', ...
                        ['FD wall-domain results must include solver velocity snapshots; ' ...
                         'periodic FFT reconstruction is not allowed for this plot path.']);
                end
                return;
            end

            if isequal(size(analysis.u_snaps), omega_size) && isequal(size(analysis.v_snaps), omega_size)
                u_cube = double(analysis.u_snaps);
                v_cube = double(analysis.v_snaps);
            end
        end

        function slice = extract_cube_snapshot(~, cube, idx)
            slice = [];
            if isempty(cube) || ndims(cube) < 3
                return;
            end
            idx = max(1, min(size(cube, 3), round(double(idx))));
            slice = double(cube(:, :, idx));
        end

        function [u, v] = resolve_velocity_slice_for_results(app, omega_slice, u_slice, v_slice, x_vec, y_vec)
            use_snapshots = ~isempty(u_slice) && ~isempty(v_slice) && ...
                isequal(size(u_slice), size(omega_slice)) && isequal(size(v_slice), size(omega_slice));
            if use_snapshots
                u = double(u_slice);
                v = double(v_slice);
                u(~isfinite(u)) = 0;
                v(~isfinite(v)) = 0;
                return;
            end

            [~, u, v] = app.velocity_from_omega_slice(omega_slice, x_vec, y_vec);
        end

        function psi = resolve_streamfunction_slice_for_results(app, omega_slice, psi_slice, x_vec, y_vec)
            use_snapshot = ~isempty(psi_slice) && isequal(size(psi_slice), size(omega_slice));
            if use_snapshot
                psi = double(psi_slice);
                psi(~isfinite(psi)) = 0;
                return;
            end

            [psi, ~, ~] = app.velocity_from_omega_slice(omega_slice, x_vec, y_vec);
            psi(~isfinite(psi)) = 0;
        end

        function tf = overlay_streamfunction_contours(~, ax, x_vec, y_vec, psi_slice, line_color)
            tf = false;
            if isempty(psi_slice)
                return;
            end

            psi_finite = psi_slice(isfinite(psi_slice));
            if isempty(psi_finite)
                return;
            end

            psi_span = max(psi_finite) - min(psi_finite);
            psi_scale = max(1.0, max(abs(psi_finite)));
            if ~isfinite(psi_span) || psi_span <= 1.0e-8 * psi_scale
                return;
            end

            try
                contour(ax, x_vec, y_vec, psi_slice, 12, ...
                    'LineColor', line_color, 'LineWidth', 0.9);
                tf = true;
            catch
                tf = false;
            end
        end

        function render_bc_overlay_axes(app, ax, params)
            C = app.layout_cfg.colors;
            Lx = params.Lx; Ly = params.Ly;
            %if isfield(params, 'Lx') && isnumeric(params.Lx) && isfinite(params.Lx), Lx = max(1e-6, params.Lx); end
            %if isfield(params, 'Ly') && isnumeric(params.Ly) && isfinite(params.Ly), Ly = max(1e-6, params.Ly); end
            preview_style = lower(char(string(app.pick_field(params, {'preview_style'}, 'default'))));
            is_compact_domain_only = strcmp(preview_style, 'compact_domain_only');
            [~, top_math, top_phys] = app.normalize_bc_selection(app.pick_field(params, {'bc_top'}, 'Periodic'));
            [~, bottom_math, bottom_phys] = app.normalize_bc_selection(app.pick_field(params, {'bc_bottom'}, 'Periodic'));
            [~, left_math, left_phys] = app.normalize_bc_selection(app.pick_field(params, {'bc_left'}, 'Periodic'));
            [~, right_math, right_phys] = app.normalize_bc_selection(app.pick_field(params, {'bc_right'}, 'Periodic'));
            U_top = app.pick_field(params, {'U_top'}, 0.0);
            U_bottom = app.pick_field(params, {'U_bottom'}, 0.0);
            U_left = app.pick_field(params, {'U_left'}, 0.0);
            U_right = app.pick_field(params, {'U_right'}, 0.0);

            cla(ax);
            hold(ax, 'on');
            rectangle(ax, 'Position', [-Lx/2 -Ly/2 Lx Ly], 'EdgeColor', C.fg_text, 'LineWidth', 1.2);

            arr_len = min(Lx, Ly) * 0.15;
            offset = min(Lx, Ly) * 0.05;
            inset = min(Lx, Ly) * 0.055;
            per_lr = [0.30 0.80 0.55];
            per_tb = [0.35 0.65 0.95];
            pinned = [0.95 0.30 0.30];
            noflux = [0.55 0.90 0.55];
            driven = C.accent_yellow;
            is_spectral = isfield(params, 'method') && strcmpi(char(string(params.method)), 'Spectral');

            if is_compact_domain_only
                arr_len = arr_len * 0.80;
                label_font_size = 7;
                top_edge_y = Ly/2 - inset;
                bottom_edge_y = -Ly/2 + inset;
                left_edge_x = -Lx/2 + inset;
                right_edge_x = Lx/2 - inset;
                top_label_y = Ly/2 - 2.4*inset;
                bottom_label_y = -Ly/2 + 2.4*inset;
                left_label_x = -Lx/2 + 2.0*inset;
                right_label_x = Lx/2 - 2.0*inset;
                side_label_y = 0;
                if strcmp(left_phys, 'periodic') || strcmp(right_phys, 'periodic')
                    side_label_y = 0.22 * Ly;
                end
            else
                label_font_size = 8;
                top_edge_y = Ly/2 + offset;
                bottom_edge_y = -Ly/2 - offset;
                left_edge_x = -Lx/2 - offset;
                right_edge_x = Lx/2 + offset;
                top_label_y = Ly/2 + Ly*0.10;
                bottom_label_y = -Ly/2 - Ly*0.10;
                left_label_x = -Lx/2 - Lx*0.10;
                right_label_x = Lx/2 + Lx*0.10;
                side_label_y = 0;
            end

            if strcmp(left_phys, 'periodic') && strcmp(right_phys, 'periodic')
                if is_compact_domain_only
                    quiver(ax, -Lx/2 + inset, 0, Lx - 2*inset, 0, 0, 'Color', per_lr, 'LineWidth', 1.6, 'MaxHeadSize', 0.45);
                    quiver(ax, Lx/2 - inset, 0, -(Lx - 2*inset), 0, 0, 'Color', per_lr, 'LineWidth', 1.6, 'MaxHeadSize', 0.45);
                else
                    quiver(ax, -Lx/2 - offset, 0, Lx + 2*offset, 0, 0, 'Color', per_lr, 'LineWidth', 1.6, 'MaxHeadSize', 0.45);
                    quiver(ax, Lx/2 + offset, 0, -(Lx + 2*offset), 0, 0, 'Color', per_lr, 'LineWidth', 1.6, 'MaxHeadSize', 0.45);
                end
            end
            if strcmp(top_phys, 'periodic') && strcmp(bottom_phys, 'periodic')
                if is_compact_domain_only
                    quiver(ax, 0, Ly/2 - inset, 0, -(Ly - 2*inset), 0, 'Color', per_tb, 'LineWidth', 1.6, 'MaxHeadSize', 0.45);
                    quiver(ax, 0, -Ly/2 + inset, 0, (Ly - 2*inset), 0, 'Color', per_tb, 'LineWidth', 1.6, 'MaxHeadSize', 0.45);
                else
                    quiver(ax, 0, Ly/2 + offset, 0, -(Ly + 2*offset), 0, 'Color', per_tb, 'LineWidth', 1.6, 'MaxHeadSize', 0.45);
                    quiver(ax, 0, -Ly/2 - offset, 0, (Ly + 2*offset), 0, 'Color', per_tb, 'LineWidth', 1.6, 'MaxHeadSize', 0.45);
                end
            end

            if strcmp(top_phys, 'driven')
                quiver(ax, 0, top_edge_y, app.sign_or_one(U_top) * arr_len, 0, 0, 'Color', driven, 'LineWidth', 1.8, 'MaxHeadSize', 0.7);
            elseif any(strcmp(top_phys, {'no_slip', 'pinned'}))
                plot(ax, [-Lx/4, Lx/4], [top_edge_y, top_edge_y], '-', 'Color', pinned, 'LineWidth', 1.6);
            elseif strcmp(top_phys, 'no_flux')
                plot(ax, [-Lx/4, Lx/4], [top_edge_y, top_edge_y], '--', 'Color', noflux, 'LineWidth', 1.6);
            end
            if strcmp(bottom_phys, 'driven')
                quiver(ax, 0, bottom_edge_y, app.sign_or_one(U_bottom) * arr_len, 0, 0, 'Color', driven, 'LineWidth', 1.8, 'MaxHeadSize', 0.7);
            elseif any(strcmp(bottom_phys, {'no_slip', 'pinned'}))
                plot(ax, [-Lx/4, Lx/4], [bottom_edge_y, bottom_edge_y], '-', 'Color', pinned, 'LineWidth', 1.6);
            elseif strcmp(bottom_phys, 'no_flux')
                plot(ax, [-Lx/4, Lx/4], [bottom_edge_y, bottom_edge_y], '--', 'Color', noflux, 'LineWidth', 1.6);
            end
            if strcmp(left_phys, 'driven')
                quiver(ax, left_edge_x, 0, 0, app.sign_or_one(U_left) * arr_len, 0, 'Color', driven, 'LineWidth', 1.8, 'MaxHeadSize', 0.7);
            elseif any(strcmp(left_phys, {'no_slip', 'pinned'}))
                plot(ax, [left_edge_x, left_edge_x], [-Ly/4, Ly/4], '-', 'Color', pinned, 'LineWidth', 1.6);
            elseif strcmp(left_phys, 'no_flux')
                plot(ax, [left_edge_x, left_edge_x], [-Ly/4, Ly/4], '--', 'Color', noflux, 'LineWidth', 1.6);
            end
            if strcmp(right_phys, 'driven')
                quiver(ax, right_edge_x, 0, 0, app.sign_or_one(U_right) * arr_len, 0, 'Color', driven, 'LineWidth', 1.8, 'MaxHeadSize', 0.7);
            elseif any(strcmp(right_phys, {'no_slip', 'pinned'}))
                plot(ax, [right_edge_x, right_edge_x], [-Ly/4, Ly/4], '-', 'Color', pinned, 'LineWidth', 1.6);
            elseif strcmp(right_phys, 'no_flux')
                plot(ax, [right_edge_x, right_edge_x], [-Ly/4, Ly/4], '--', 'Color', noflux, 'LineWidth', 1.6);
            end

            text(ax, 0, top_label_y, sprintf('%s | %s', strrep(top_phys, '_', '-'), top_math), ...
                'Color', C.fg_text, 'HorizontalAlignment', 'center', 'VerticalAlignment', 'middle', 'FontSize', label_font_size);
            text(ax, 0, bottom_label_y, sprintf('%s | %s', strrep(bottom_phys, '_', '-'), bottom_math), ...
                'Color', C.fg_text, 'HorizontalAlignment', 'center', 'VerticalAlignment', 'middle', 'FontSize', label_font_size);
            text(ax, left_label_x, side_label_y, sprintf('%s | %s', strrep(left_phys, '_', '-'), left_math), ...
                'Color', C.fg_text, 'HorizontalAlignment', 'center', 'VerticalAlignment', 'middle', ...
                'FontSize', label_font_size, 'Rotation', 90);
            text(ax, right_label_x, side_label_y, sprintf('%s | %s', strrep(right_phys, '_', '-'), right_math), ...
                'Color', C.fg_text, 'HorizontalAlignment', 'center', 'VerticalAlignment', 'middle', ...
                'FontSize', label_font_size, 'Rotation', 90);

            if ~is_compact_domain_only
                h_per = plot(ax, nan, nan, '-', 'Color', per_lr, 'LineWidth', 1.8);
                if is_spectral
                    h_pin = plot(ax, nan, nan, '-', 'Color', pinned, 'LineWidth', 1.8);
                    h_nof = plot(ax, nan, nan, '--', 'Color', noflux, 'LineWidth', 1.8);
                    legend(ax, [h_per, h_pin, h_nof], ...
                        {'Periodic', 'Pinned | Dirichlet', 'No-flux | Neumann'}, ...
                        'Location', 'southoutside', 'NumColumns', 3, ...
                        'TextColor', C.fg_text, 'Color', C.bg_panel_alt, 'EdgeColor', C.accent_gray);
                else
                    h_nos = plot(ax, nan, nan, '-', 'Color', pinned, 'LineWidth', 1.8);
                    h_drv = plot(ax, nan, nan, '-', 'Color', driven, 'LineWidth', 1.8);
                    legend(ax, [h_per, h_nos, h_drv], ...
                        {'Periodic', 'No-slip wall | psi const', 'Driven wall | psi const + wall speed'}, ...
                        'Location', 'southoutside', 'NumColumns', 3, ...
                        'TextColor', C.fg_text, 'Color', C.bg_panel_alt, 'EdgeColor', C.accent_gray);
                end
            else
                legend(ax, 'off');
            end
            hold(ax, 'off');
            axis(ax, 'equal');
            if is_compact_domain_only
                bg_color = C.bg_panel;
                try
                    if isnumeric(ax.Color) && numel(ax.Color) == 3
                        bg_color = ax.Color;
                    end
                catch
                end
                title(ax, '', 'Color', C.fg_text, 'Interpreter', 'none');
                xlabel(ax, '', 'Color', C.fg_text);
                ylabel(ax, '', 'Color', C.fg_text);
                xlim(ax, [-Lx/2, Lx/2]);
                ylim(ax, [-Ly/2, Ly/2]);
                grid(ax, 'off');
                box(ax, 'off');
                ax.XTick = [];
                ax.YTick = [];
                ax.XColor = bg_color;
                ax.YColor = bg_color;
            else
                title(ax, 'BC / domain overlay', 'Color', C.fg_text, 'Interpreter', 'none');
                xlabel(ax, 'x', 'Color', C.fg_text);
                ylabel(ax, 'y', 'Color', C.fg_text);
                margin = max(Lx, Ly) * 0.2;
                xlim(ax, [-Lx/2 - margin, Lx/2 + margin]);
                ylim(ax, [-Ly/2 - margin, Ly/2 + margin]);
                grid(ax, 'on');
            end
        end

        function value = bc_arrow_value(~, bc_label, speed)
            token = lower(char(string(bc_label)));
            if contains(token, 'driven')
                value = sign(double(speed));
                if value == 0
                    value = 1;
                end
            else
                value = 0;
            end
        end

        function c = bc_color(app, bc_label)
            C = app.layout_cfg.colors;
            token = lower(char(string(bc_label)));
            if contains(token, 'periodic')
                c = C.accent_cyan;
            elseif contains(token, 'driven')
                c = C.accent_yellow;
            else
                c = C.accent_green;
            end
        end

        function plot_colors = result_plot_colors(app)
            C = app.layout_cfg.colors;
            plot_colors = struct( ...
                'bg', C.bg_dark, ...
                'fg', C.fg_text, ...
                'grid', C.accent_gray, ...
                'primary', C.accent_cyan, ...
                'secondary', C.accent_yellow, ...
                'tertiary', C.accent_blue);
        end

        function color = result_run_color(app, run_index)
            C = app.layout_cfg.colors;
            palette = [ ...
                C.accent_cyan; ...
                C.accent_green; ...
                C.accent_yellow; ...
                C.accent_blue; ...
                C.accent_red];
            idx = mod(max(1, round(double(run_index))) - 1, size(palette, 1)) + 1;
            color = palette(idx, :);
        end

        function badge = result_run_badge(app, run_index, meta)
            badge = sprintf('R%02d', max(1, round(double(run_index))));
            if nargin >= 3 && isstruct(meta) && isfield(meta, 'run_id') && ...
                    ~isempty(strtrim(app.to_text(meta.run_id, '')))
                run_id_txt = app.to_text(meta.run_id, '');
                if numel(run_id_txt) > 6
                    run_id_txt = run_id_txt(end-5:end);
                end
                badge = sprintf('%s-%s', badge, run_id_txt);
            end
        end

        function lines = format_run_metadata(~, meta, params)
            % Format run metadata as a cell array of strings for uitextarea.
            lines = {};
            fields_order = {'method', 'mode', 'ic_type', 'Nx', 'Ny', 'Lx', 'Ly', ...
                'nu', 'dt', 'Tfinal', 'wall_time', 'max_omega', ...
                'final_energy', 'final_enstrophy', 'total_steps'};
            % Merge meta + params into a flat struct
            combined = struct();
            if isstruct(params)
                fn = fieldnames(params);
                for k = 1:numel(fn)
                    v = params.(fn{k});
                    if isscalar(v) || ischar(v) || isstring(v)
                        combined.(fn{k}) = v;
                    end
                end
            end
            if isstruct(meta)
                fn = fieldnames(meta);
                for k = 1:numel(fn)
                    combined.(fn{k}) = meta.(fn{k});
                end
            end
            for p = fields_order
                fname = p{1};
                if ~isfield(combined, fname); continue; end
                v = combined.(fname);
                if isnumeric(v) && isscalar(v)
                    if v == round(v) && abs(v) < 1e6
                        vs = sprintf('%d', v);
                    else
                        vs = sprintf('%.5g', v);
                    end
                elseif ischar(v) || isstring(v)
                    vs = char(string(v));
                else
                    continue;
                end
                lines{end+1} = sprintf('%-18s %s', strrep(fname,'_',' '), vs); %#ok<AGROW>
            end
            if isempty(lines)
                lines = {'No metadata available'};
            end
        end

        function update_results_empty_state_visibility(app)
            has_runs = ~isempty(app.session_figures);
            empty_vis = 'on';
            tabs_vis = 'off';
            if has_runs
                empty_vis = 'off';
                tabs_vis = 'on';
            end

            if app.has_valid_handle('results_empty_state')
                app.handles.results_empty_state.Visible = empty_vis;
            end
            if app.has_valid_handle('figure_tabs')
                app.handles.figure_tabs.Visible = tabs_vis;
            end
        end

        function refresh_session_figure_dropdown(app)
            % Update the figure selector dropdown from session_figures registry
            T = app.layout_cfg.ui_text.results;
            if isempty(app.session_figures)
                app.handles.figure_selector.Items = {T.figure_none};
                app.handles.figure_selector.Value = T.figure_none;
                app.update_results_empty_state_visibility();
                return;
            end
            names = cell(1, numel(app.session_figures));
            for i = 1:numel(app.session_figures)
                badge = '';
                if isfield(app.session_figures(i), 'run_badge')
                    badge = char(string(app.session_figures(i).run_badge));
                end
                if ~isempty(strtrim(badge))
                    names{i} = sprintf('%02d | %s %s', i, badge, app.session_figures(i).name);
                else
                    names{i} = sprintf('%02d | %s', i, app.session_figures(i).name);
                end
            end
            app.handles.figure_selector.Items = names;
            app.handles.figure_selector.Value = names{end};
            app.update_results_empty_state_visibility();
        end

        function update_result_identifier_tags(app, idx)
            % Update the method/mode/IC identifier labels for a result
            if idx < 1 || idx > numel(app.session_figures)
                return;
            end
            meta = app.session_figures(idx).metadata;
            badge = '';
            if isfield(app.session_figures(idx), 'run_badge')
                badge = char(string(app.session_figures(idx).run_badge));
            end
            if app.has_valid_handle('result_tag_method')
                method_text = upper(char(string(meta.method)));
                if ~isempty(strtrim(badge))
                    method_text = sprintf('%s | %s', badge, method_text);
                end
                app.handles.result_tag_method.Text = method_text;
            end
            if app.has_valid_handle('result_tag_mode')
                app.handles.result_tag_mode.Text = meta.mode;
            end
            if app.has_valid_handle('result_tag_ic')
                app.handles.result_tag_ic.Text = strrep(meta.ic_type, '_', ' ');
            end
        end

        function update_metrics_summary(app, idx)
            % Populate the side metrics panel with high-level summary
            if ~isfield(app.handles, 'metrics_text') || ~isvalid(app.handles.metrics_text)
                return;
            end
            if idx < 1 || idx > numel(app.session_figures)
                return;
            end
            if isfield(app.session_figures(idx), 'workflow_kind') && ...
                    strcmpi(char(string(app.session_figures(idx).workflow_kind)), 'phase1_periodic_comparison')
                app.handles.metrics_text.Value = app.phase1_metrics_summary_lines(app.session_figures(idx));
                return;
            end
            if isfield(app.session_figures(idx), 'workflow_kind') && ...
                    strcmpi(char(string(app.session_figures(idx).workflow_kind)), 'phase2_boundary_condition_study')
                app.handles.metrics_text.Value = app.phase2_metrics_summary_lines(app.session_figures(idx));
                return;
            end
            if isfield(app.session_figures(idx), 'workflow_kind') && ...
                    strcmpi(char(string(app.session_figures(idx).workflow_kind)), 'phase3_bathymetry_study')
                app.handles.metrics_text.Value = app.phase2_metrics_summary_lines(app.session_figures(idx));
                return;
            end
            meta = app.session_figures(idx).metadata;
            params = app.session_figures(idx).parameters;
            analysis = app.session_figures(idx).analysis;

            lines = {};
            lines{end+1} = '--- Run Summary ---';
            lines{end+1} = sprintf('Method:  %s', upper(meta.method));
            lines{end+1} = sprintf('Mode:    %s', meta.mode);
            lines{end+1} = sprintf('IC:      %s', strrep(meta.ic_type, '_', ' '));
            if isfield(meta, 'launch_origin') && strlength(string(meta.launch_origin)) > 0
                lines{end+1} = sprintf('Launch:  %s', strrep(char(string(meta.launch_origin)), '_', ' '));
            end
            if ~isempty(meta.bc_case)
                lines{end+1} = sprintf('BC:      %s', meta.bc_case);
            end
            lines{end+1} = sprintf('Time:    %s', meta.timestamp);
            lines{end+1} = '';
            lines{end+1} = '--- Grid ---';
            if isfield(params, 'Nx')
                lines{end+1} = sprintf('Nx x Ny: %d x %d', params.Nx, params.Ny);
            end
            if isfield(params, 'Lx')
                lines{end+1} = sprintf('Lx x Ly: %.2f x %.2f', params.Lx, params.Ly);
            end
            if isfield(params, 'dt')
                lines{end+1} = sprintf('dt:      %.4g', params.dt);
            end
            if isfield(params, 'Tfinal')
                lines{end+1} = sprintf('Tfinal:  %.4g', params.Tfinal);
            end
            if isfield(params, 'nu')
                lines{end+1} = sprintf('nu:      %.4g', params.nu);
            end
            lines{end+1} = '';
            lines{end+1} = '--- Metrics ---';
            if isfield(meta, 'total_steps')
                lines{end+1} = sprintf('Steps:       %d', meta.total_steps);
            end
            if isfield(meta, 'wall_time')
                lines{end+1} = sprintf('Wall time:   %.2f s', meta.wall_time);
            end
            if isfield(meta, 'max_omega')
                v = meta.max_omega;
                if ~isscalar(v), v = max(abs(v(:)), [], 'omitnan'); end
                lines{end+1} = sprintf('max|omega|:  %.4e', v);
            end
            if isfield(meta, 'final_energy')
                lines{end+1} = sprintf('Final KE:    %.4e', meta.final_energy);
            end
            if isfield(meta, 'final_enstrophy')
                lines{end+1} = sprintf('Final Enst:  %.4e', meta.final_enstrophy);
            end

            % Initial/final vorticity from snapshots
            if isfield(analysis, 'omega_snaps') && ~isempty(analysis.omega_snaps)
                omega_init = analysis.omega_snaps(:,:,1);
                omega_final = analysis.omega_snaps(:,:,end);
                lines{end+1} = '';
                lines{end+1} = '--- Vorticity ---';
                lines{end+1} = sprintf('Init max:    %.4e', max(abs(omega_init(:))));
                lines{end+1} = sprintf('Init mean:   %.4e', mean(omega_init(:)));
                lines{end+1} = sprintf('Final max:   %.4e', max(abs(omega_final(:))));
                lines{end+1} = sprintf('Final mean:  %.4e', mean(omega_final(:)));
                lines{end+1} = sprintf('Decay ratio: %.4f', max(abs(omega_final(:))) / max(max(abs(omega_init(:))), eps));
            end

            app.handles.metrics_text.Value = lines;
        end

        function lines = phase1_metrics_summary_lines(app, entry)
            workflow = app.pick_field(entry, {'workflow'}, struct());
            metrics = app.pick_field(workflow, {'metrics'}, struct());
            summary = app.pick_field(metrics, {'summary'}, struct());
            fd_metrics = app.pick_field(metrics, {'FD'}, struct());
            sp_metrics = app.pick_field(metrics, {'Spectral'}, struct());
            children = app.pick_field(workflow, {'children'}, struct());
            fd_child = app.pick_field(children, {'fd'}, struct());
            sp_child = app.pick_field(children, {'spectral'}, struct());
            lines = { ...
                '--- Phase 1 Summary ---'; ...
                sprintf('Phase ID: %s', app.if_empty(app.pick_field(workflow, {'phase_id'}, ''), '--')); ...
                'Methods:  FD + Spectral'; ...
                sprintf('IC:       %s', strrep(app.if_empty(app.pick_field(entry.metadata, {'ic_type'}, ''), '--'), '_', ' ')); ...
                sprintf('Launch:   %s', strrep(app.if_empty(app.pick_field(entry.metadata, {'launch_origin'}, ''), '--'), '_', ' ')); ...
                sprintf('BC:       %s', app.if_empty(app.pick_field(entry.metadata, {'bc_case'}, ''), '--')); ...
                ''; ...
                '--- Queue ---'; ...
                sprintf('Jobs:     %d', numel(app.pick_field(workflow, {'queue'}, struct([])))); ...
                sprintf('Status:   %s', app.if_empty(app.pick_field(entry.monitor_series, {'workflow_current_status'}, ''), 'completed')); ...
                ''; ...
                '--- Comparison ---'; ...
                sprintf('Mean L2 mismatch: %.3e', double(app.pick_field(summary, {'mean_cross_method_mismatch_l2'}, NaN))); ...
                sprintf('FD runtime:       %.3f s', double(app.pick_field(fd_metrics, {'runtime_wall_s'}, NaN))); ...
                sprintf('Spectral runtime: %.3f s', double(app.pick_field(sp_metrics, {'runtime_wall_s'}, NaN))); ...
                sprintf('Runtime ratio:    %.3f', double(app.pick_field(summary, {'runtime_ratio_fd_over_spectral'}, NaN))); ...
                sprintf('FD mesh:          %s', app.phase1_mesh_label(app.pick_field(fd_child, {'selected_mesh'}, struct()))); ...
                sprintf('Spectral mesh:    %s', app.phase1_mesh_label(app.pick_field(sp_child, {'selected_mesh'}, struct()))) ...
            };
        end

        function lines = phase2_metrics_summary_lines(app, entry)
            workflow = app.pick_field(entry, {'workflow'}, struct());
            scenarios = app.pick_field(workflow, {'scenarios'}, struct([]));
            scenario = app.pick_field(workflow, {'scenario'}, struct());
            if ~isempty(scenarios) && (~isstruct(scenario) || isempty(fieldnames(scenario)))
                workflow_label = 'Phase 2 Workflow';
                if strcmpi(char(string(app.pick_field(entry, {'workflow_kind'}, ''))), 'phase3_bathymetry_study')
                    workflow_label = 'Phase 3 Workflow';
                end
                lines = { ...
                    sprintf('--- %s ---', workflow_label); ...
                    sprintf('Phase ID: %s', app.if_empty(app.pick_field(workflow, {'phase_id'}, ''), '--')); ...
                    sprintf('Launch:   %s', strrep(app.if_empty(app.pick_field(entry.metadata, {'launch_origin'}, ''), '--'), '_', ' ')); ...
                    sprintf('IC:       %s', strrep(app.if_empty(app.pick_field(entry.metadata, {'ic_type'}, ''), '--'), '_', ' ')); ...
                    sprintf('Scenarios:%d', numel(scenarios)); ...
                    sprintf('Queue rows:%d', numel(app.pick_field(workflow, {'queue'}, struct([])))); ...
                    ''; ...
                    '--- Scenario Set ---' ...
                };
                for i = 1:numel(scenarios)
                    scenario_summary = app.pick_field(scenarios(i), {'summary'}, struct());
                    scenario_label = app.if_empty(app.pick_field(scenario_summary, {'scenario_label'}, ''), sprintf('Scenario %d', i));
                    bc_label = app.if_empty(app.pick_field(scenario_summary, {'bc_label', 'bc_id'}, ''), '--');
                    bathy_label = app.if_empty(app.pick_field(scenario_summary, {'bathymetry_label', 'bathymetry_id'}, ''), '--');
                    lines{end + 1} = sprintf('%d. %s | BC: %s | Bathy: %s', i, scenario_label, bc_label, bathy_label); %#ok<AGROW>
                end
                return;
            end
            summary = app.pick_field(scenario, {'summary'}, struct());
            combined = app.pick_field(scenario, {'combined'}, struct());
            overlay = app.pick_field(combined, {'overlay'}, struct());
            fd_overlay = app.pick_field(overlay, {'fd'}, struct());
            trace_key = app.pick_field(combined, {'trace_key'}, struct());
            elapsed = app.pick_field(fd_overlay, {'elapsed_wall_time'}, zeros(1, 0));
            workflow_label = 'Phase 2 Scenario';
            if strcmpi(char(string(app.pick_field(entry, {'workflow_kind'}, ''))), 'phase3_bathymetry_study')
                workflow_label = 'Phase 3 Scenario';
            end
            lines = { ...
                sprintf('--- %s ---', workflow_label); ...
                sprintf('Phase ID: %s', app.if_empty(app.pick_field(workflow, {'phase_id'}, ''), '--')); ...
                sprintf('Scenario: %s', app.if_empty(app.pick_field(summary, {'scenario_label'}, ''), '--')); ...
                sprintf('Launch:   %s', strrep(app.if_empty(app.pick_field(entry.metadata, {'launch_origin'}, ''), '--'), '_', ' ')); ...
                sprintf('IC:       %s', strrep(app.if_empty(app.pick_field(entry.metadata, {'ic_type'}, ''), '--'), '_', ' ')); ...
                sprintf('BC:       %s', app.if_empty(app.pick_field(summary, {'bc_label', 'bc_id'}, ''), '--')); ...
                sprintf('Bathy:    %s', app.if_empty(app.pick_field(summary, {'bathymetry_label', 'bathymetry_id'}, ''), '--')); ...
                ''; ...
                '--- Finite Difference ---'; ...
                sprintf('Runtime:  %.3f s', double(app.pick_field(summary, {'runtime_wall_s'}, NaN))); ...
                sprintf('Mesh:     %s x %s', ...
                    app.if_nan_num_fixed(double(app.pick_field(summary, {'mesh_nx'}, NaN)), '%.0f'), ...
                    app.if_nan_num_fixed(double(app.pick_field(summary, {'mesh_ny'}, NaN)), '%.0f')); ...
                sprintf('Artifacts:%s', app.if_empty(app.pick_field(summary, {'artifact_root'}, ''), ' --')); ...
                sprintf('Elapsed traces: %d samples', numel(elapsed)); ...
                ''; ...
                '--- Spectral ---'; ...
                sprintf('Runtime:  %.3f s', double(app.pick_field(summary, {'spectral_runtime_wall_s'}, NaN))); ...
                sprintf('Mesh:     %s x %s', ...
                    app.if_nan_num_fixed(double(app.pick_field(summary, {'spectral_mesh_nx'}, NaN)), '%.0f'), ...
                    app.if_nan_num_fixed(double(app.pick_field(summary, {'spectral_mesh_ny'}, NaN)), '%.0f')); ...
                ''; ...
                '--- Comparison ---'; ...
                sprintf('Spectral active: %s', char(string(app.pick_field(summary, {'spectral_supported'}, false)))); ...
                sprintf('Trace key: %s', app.if_empty(app.pick_field(trace_key, {'legend_policy'}, ''), 'external_only')); ...
                'Time axis: elapsed from zero' ...
            };
        end

        function name = build_result_figure_name(app, run_cfg, params)
            % Build a descriptive, parseable figure name for session registry.
            % Format: YYYYMMDD-HHMMSS | Method | Mode | IC | NxN | Lx | dt | nu
            ts = char(datetime('now', 'Format', 'yyyyMMdd-HHmmss'));

            method = 'Unknown';
            if isfield(run_cfg, 'method'), method = upper(app.to_text(run_cfg.method, 'Unknown')); end

            mode = 'Unknown';
            if isfield(run_cfg, 'mode'), mode = app.to_text(run_cfg.mode, 'Unknown'); end

            ic = 'Unknown';
            if isfield(run_cfg, 'ic_type'), ic = app.to_text(run_cfg.ic_type, 'Unknown'); end
            ic = strrep(ic, '_', '-');

            grid_str = '';
            if isfield(params, 'Nx') && isfield(params, 'Ny')
                if params.Nx == params.Ny
                    grid_str = sprintf('N%d', params.Nx);
                else
                    grid_str = sprintf('N%dx%d', params.Nx, params.Ny);
                end
            end

            Lx_str = '';
            if isfield(params, 'Lx')
                Lx_str = sprintf('Lx%.4g', params.Lx);
            end

            dt_str = '';
            if isfield(params, 'dt')
                dt_str = sprintf('dt%.2g', params.dt);
            end

            nu_str = '';
            if isfield(params, 'nu')
                nu_str = sprintf('nu%.2g', params.nu);
            end

            parts = {ts, method, mode, ic, grid_str, Lx_str, dt_str, nu_str};
            parts = parts(~cellfun(@isempty, parts));
            name = strjoin(parts, ' | ');
        end

        function on_figure_selected(app)
            % Handle figure selector dropdown change Ã¢â‚¬â€ switch to the tab
            if isempty(app.session_figures)
                return;
            end
            idx = find(strcmp(app.handles.figure_selector.Items, app.handles.figure_selector.Value), 1);
            if isempty(idx) || idx > numel(app.session_figures)
                return;
            end
            % Switch to the corresponding tab
            tab_h = app.session_figures(idx).tab_handle;
            if ~isempty(tab_h) && isvalid(tab_h)
                app.handles.figure_tabs.SelectedTab = tab_h;
            end
            % Update identifier tags and metrics
            app.update_result_identifier_tags(idx);
            app.update_metrics_summary(idx);
        end

        function refresh_figures(app)
            app.refresh_session_figure_dropdown();
            if ~isempty(app.session_figures)
                app.update_result_identifier_tags(numel(app.session_figures));
                app.update_metrics_summary(numel(app.session_figures));
            end
        end

        function show_figure(app, idx)
            % Legacy show_figure Ã¢â‚¬â€ now delegates to session registry
            if ~isempty(app.session_figures) && idx >= 1 && idx <= numel(app.session_figures)
                tab_h = app.session_figures(idx).tab_handle;
                if ~isempty(tab_h) && isvalid(tab_h)
                    app.handles.figure_tabs.SelectedTab = tab_h;
                end
                app.update_result_identifier_tags(idx);
                app.update_metrics_summary(idx);
                return;
            end
            % Fallback to legacy screenshot mode
            if isempty(app.figures_list) || idx < 1 || idx > length(app.figures_list)
                return;
            end
            if ~app.has_valid_handle('figure_axes')
                return;
            end
            try
                ax = app.handles.figure_axes;
                cla(ax);
                fig_data = app.figures_list{idx};
                if ~isempty(fig_data.frame)
                    image(ax, fig_data.frame.cdata);
                    axis(ax, 'off');
                end
            catch ME
                UIController.warn_once('UIController:ShowFigureFailed', ...
                    'Failed to render figure preview in Results tab: %s', ME.message);
            end
        end

        function cleanup(app)
            % Cleanup when UI closes
            try
                app.flush_post_publication_queue('ui cleanup');
                app.safe_stop_timer('diary_timer');
                app.safe_stop_timer('time_video_timer');
                app.safe_stop_timer('startup_collector_probe_timer');
                app.safe_stop_timer('startup_pool_warm_timer');
                app.safe_stop_timer('post_publication_timer');
                app.safe_stop_timer('executor_completion_timer');
                diary off;
                app.close_multi_vortex_dialog();
                if ~isempty(app.current_executor) || ~strcmpi(app.run_lifecycle_state, 'idle')
                    app.teardown_current_executor('ui cleanup');
                end

                % Close any stray traditional MATLAB figures that might have been created
                all_figs = findall(0, 'Type', 'figure');
                for i = 1:length(all_figs)
                    % Only close traditional figures, not the main uifigure
                    if isvalid(all_figs(i)) && ~isa(all_figs(i), 'matlab.ui.Figure')
                        delete(all_figs(i));
                    end
                end

                if ~isempty(app.fig) && isvalid(app.fig)
                    if isprop(app.fig, 'CloseRequestFcn')
                        app.fig.CloseRequestFcn = '';
                    end
                    delete(app.fig);
                end
            catch ME
                UIController.warn_once('UIController:CleanupFailed', ...
                    'UI cleanup encountered a non-fatal error: %s', ME.message);
            end
        end

        function delete(app)
            % Defensive destructor: ensure background timer is never leaked
            try
                app.flush_post_publication_queue('ui delete');
                app.safe_stop_timer('diary_timer');
                app.safe_stop_timer('time_video_timer');
                app.safe_stop_timer('startup_collector_probe_timer');
                app.safe_stop_timer('startup_pool_warm_timer');
                app.safe_stop_timer('post_publication_timer');
                app.safe_stop_timer('executor_completion_timer');
            catch ME
                UIController.warn_once('UIController:DeleteTimerCleanupFailed', ...
                    'UI destructor timer cleanup failed: %s', ME.message);
            end
            try
                diary off;
            catch ME
                UIController.warn_once('UIController:DeleteDiaryOffFailed', ...
                    'UI destructor could not disable diary cleanly: %s', ME.message);
            end
            try
                if ~isempty(app.current_executor) || ~strcmpi(app.run_lifecycle_state, 'idle')
                    app.teardown_current_executor('ui delete');
                end
            catch ME
                UIController.warn_once('UIController:DeleteExecutorCleanupFailed', ...
                    'UI destructor executor cleanup failed: %s', ME.message);
            end
        end
        
        function resize_ui(~)
            % Resize callback - NO LONGER NEEDED
            % Grid layout auto-resizes, no manual Position adjustments required
            % This method kept as stub for backwards compatibility
        end
        
        % Additional stub methods for button callbacks
        function [X, Y, Lx, Ly] = build_ic_preview_grid(app)
            Nx = max(1, round(app.safe_numeric_value('Nx', 128)));
            Ny = max(1, round(app.safe_numeric_value('Ny', 128)));
            n = min(256, max(64, round(min([Nx Ny]))));

            Lx = max(1.0e-6, app.safe_numeric_value('Lx', 10.0));
            Ly = max(1.0e-6, app.safe_numeric_value('Ly', 10.0));
            [X, Y] = meshgrid(linspace(-Lx / 2, Lx / 2, n), linspace(-Ly / 2, Ly / 2, n));
        end

        function merged = merge_ic_preview_state(~, base_state, override_state)
            merged = base_state;
            if ~isstruct(override_state)
                return;
            end
            keys = fieldnames(override_state);
            for i_key = 1:numel(keys)
                key = keys{i_key};
                value = override_state.(key);
                if isempty(value)
                    continue;
                end
                merged.(key) = value;
            end
        end

        function [shared, dyn] = resolve_ic_preview_state(app, ic_type, schema)
            app.ensure_ic_state_cache();

            defaults = app.get_ic_shared_defaults();
            shared = defaults;
            shared.pattern = app.get_ic_pattern_value();
            shared.arrangement = shared.pattern;
            shared.charge = 1.0;
            dyn = app.default_dynamic_values(schema);
            if app.has_valid_handle('ic_center_x') || app.has_valid_handle('ic_scale')
                shared = app.merge_ic_preview_state(shared, app.read_ic_shared_values());
            end

            is_active_type = false;
            if isfield(app.handles, 'ic_active_schema') && isstruct(app.handles.ic_active_schema) && ...
                    isfield(app.handles.ic_active_schema, 'ic_type')
                is_active_type = strcmpi(char(string(app.handles.ic_active_schema.ic_type)), char(string(ic_type)));
            end

            if is_active_type
                shared = app.read_ic_shared_values();
                dyn = app.read_ic_dynamic_values_from_schema(schema);
                return;
            end

            cache_key = app.build_ic_context_key(ic_type, 'Manual', false);
            if isfield(app.handles, 'ic_state_cache') && isa(app.handles.ic_state_cache, 'containers.Map') && ...
                    isKey(app.handles.ic_state_cache, cache_key)
                cached = app.handles.ic_state_cache(cache_key);
                if isstruct(cached)
                    if isfield(cached, 'shared')
                        shared = app.merge_ic_preview_state(shared, cached.shared);
                    end
                    if isfield(cached, 'dynamic')
                        dyn = app.merge_ic_preview_state(dyn, cached.dynamic);
                    end
                end
            end
        end

        function payload = build_ic_preview_payload(app, ic_type, include_structured_rows)
            if nargin < 2 || isempty(ic_type)
                [ic_type, schema] = app.resolve_active_ic_type();
            else
                ic_type = lower(char(string(ic_type)));
                schema = app.get_ic_schema(ic_type);
            end
            if nargin < 3
                include_structured_rows = false;
            end

            [X, Y, Lx, Ly] = app.build_ic_preview_grid();
            [shared, dyn] = app.resolve_ic_preview_state(ic_type, schema);
            ic_display = schema.display_name;
            used_structured_rows = false;

            if include_structured_rows && app.should_use_multi_vortex_rows(ic_type, schema)
                rows = app.normalize_multi_vortex_rows(app.config.ic_multi_vortex_rows, ic_type);
                Z = app.evaluate_multi_vortex_rows(X, Y, rows, ic_type);
                ic_display = sprintf('%s / Structured Rows', ic_display);
                used_structured_rows = true;
            else
                ic_coeff = app.pack_ic_coeff_from_values(ic_type, schema, shared, dyn);
                Z = ICDispatcher.evaluate_catalog(X, Y, ic_type, ic_coeff, struct('Lx', Lx, 'Ly', Ly));
            end

            if any(~isfinite(Z), 'all')
                error('UIController:InvalidICPreviewField', ...
                    'Initial condition generated non-finite values for preview.');
            end

            show_position_marker = false;
            if isfield(schema, 'shared_flags') && isstruct(schema.shared_flags) && ...
                    isfield(schema.shared_flags, 'show_position')
                show_position_marker = logical(schema.shared_flags.show_position);
            end

            switch lower(char(string(ic_type)))
                case 'no_initial_condition'
                    equation_tex = '\omega(x,y,0)=0';
                case 'stretched_gaussian'
                    equation_tex = '\omega(x,y)=\exp(-a(x-x_0)^2-b(y-y_0)^2)';
                case 'vortex_blob_gaussian'
                    equation_tex = '\omega(r)=\frac{\Gamma}{2\pi R^2}\exp(-\frac{r^2}{2R^2})';
                case 'vortex_pair'
                    equation_tex = '\omega=\omega_1+\omega_2,\ \Gamma_2=-|\Gamma_1|';
                case 'multi_vortex'
                    equation_tex = '\omega(x,y)=\sum_{i=1}^{N}\frac{\Gamma}{2\pi R^2}\exp(-\frac{r_i^2}{2R^2})';
                case 'lamb_oseen'
                    equation_tex = '\omega(r)=\frac{\Gamma}{4\pi\nu t_0}\exp(-\frac{r^2}{4\nu t_0})';
                case 'rankine'
                    equation_tex = '\omega(r)=\omega_0,\ r\le r_c;\ 0,\ r>r_c';
                case 'lamb_dipole'
                    equation_tex = '\omega=\omega_{\mathrm{dipole}}(r,\theta;U,a)';
                case 'taylor_green'
                    equation_tex = '\omega(x,y)=G(k_x+k_y)\sin(k_x(x-x_0))\sin(k_y(y-y_0))';
                case 'random_turbulence'
                    equation_tex = '\omega(x,y)=\sum_k A_k\sin(k\cdot x+\phi_k),\ A_k\propto|k|^{-\alpha}';
                case 'elliptical_vortex'
                    equation_tex = '\omega=w_0\exp(-\frac{x_r^2}{2\sigma_x^2}-\frac{y_r^2}{2\sigma_y^2})';
                otherwise
                    equation_tex = char(string(schema.equation_tex));
                    equation_tex = regexprep(equation_tex, '\\left|\\right', '');
                    equation_tex = regexprep(equation_tex, '\\begin\{cases\}', '');
                    equation_tex = regexprep(equation_tex, '\\end\{cases\}', '');
                    equation_tex = strrep(equation_tex, '\\\\', '; ');
            end

            payload = struct( ...
                'ic_type', char(string(ic_type)), ...
                'ic_display', char(string(ic_display)), ...
                'equation_tex', equation_tex, ...
                'schema', schema, ...
                'X', X, ...
                'Y', Y, ...
                'Z', Z, ...
                'Lx', double(Lx), ...
                'Ly', double(Ly), ...
                'shared', shared, ...
                'dynamic', dyn, ...
                'show_position_marker', show_position_marker, ...
                'used_structured_rows', used_structured_rows);
        end

        function out_text = escape_latex_text(~, in_text)
            out_text = char(string(in_text));
            out_text = strrep(out_text, '\', '\textbackslash{}');
            out_text = strrep(out_text, '_', '\_');
            out_text = strrep(out_text, '%', '\%');
            out_text = strrep(out_text, '&', '\&');
            out_text = strrep(out_text, '#', '\#');
            out_text = strrep(out_text, '{', '\{');
            out_text = strrep(out_text, '}', '\}');
        end

        function title_line = build_ic_preview_title_line(app, payload)
            title_line = sprintf('%s, $t=0$', app.escape_latex_text(payload.ic_display));
        end

        function render_ic_preview_axes(app, ax, payload, show_contour_bands)
            if nargin < 4
                show_contour_bands = false;
            end
            if isempty(ax) || ~isgraphics(ax)
                error('UIController:InvalidICPreviewAxes', ...
                    'render_ic_preview_axes requires a valid axes handle.');
            end

            cla(ax);

            if show_contour_bands
                rendered = app.render_ic_contours(ax, payload.X, payload.Y, payload.Z);
                if ~rendered
                    app.render_ic_image(ax, payload.X, payload.Y, payload.Z);
                end
            else
                app.render_ic_image(ax, payload.X, payload.Y, payload.Z);
            end

            hold(ax, 'on');
            rectangle(ax, 'Position', [-payload.Lx / 2, -payload.Ly / 2, payload.Lx, payload.Ly], ...
                'EdgeColor', app.layout_cfg.colors.accent_gray, ...
                'LineStyle', '--', ...
                'LineWidth', 1.0);
            if payload.show_position_marker
                x0_ch = app.pick_field(payload.shared, {'center_x'}, 0.0);
                y0_ch = app.pick_field(payload.shared, {'center_y'}, 0.0);
                xline(ax, x0_ch, ':', 'Color', [1 1 1 0.5], 'LineWidth', 0.8);
                yline(ax, y0_ch, ':', 'Color', [1 1 1 0.5], 'LineWidth', 0.8);
                plot(ax, x0_ch, y0_ch, '+', 'Color', app.layout_cfg.colors.accent_cyan, ...
                    'MarkerSize', 10, 'LineWidth', 1.5);
            end
            hold(ax, 'off');

            colormap(ax, turbo(256));
            cb = colorbar(ax);
            if ~isempty(cb) && isvalid(cb)
                cb.Color = app.layout_cfg.colors.fg_text;
            end

            title_text = sprintf('%s\n$%s$', app.build_ic_preview_title_line(payload), payload.equation_tex);
            title(ax, title_text, ...
                'FontSize', 11, ...
                'FontWeight', 'bold', ...
                'Color', app.layout_cfg.colors.fg_text, ...
                'Interpreter', 'latex');
            xlabel(ax, '$L_X$', 'FontSize', 10, 'Color', app.layout_cfg.colors.fg_text, 'Interpreter', 'latex');
            ylabel(ax, '$L_Y$', 'FontSize', 10, 'Color', app.layout_cfg.colors.fg_text, 'Interpreter', 'latex');
            axis(ax, 'normal');
            xlim(ax, [-payload.Lx / 2, payload.Lx / 2]);
            ylim(ax, [-payload.Ly / 2, payload.Ly / 2]);
            pbaspect(ax, [max(payload.Lx, 1.0e-6), max(payload.Ly, 1.0e-6), 1]);
            ax.XTick = [-payload.Lx / 2, 0, payload.Lx / 2];
            ax.YTick = [-payload.Ly / 2, 0, payload.Ly / 2];
            ax.XTickLabel = {sprintf('%.1f', -payload.Lx / 2), '0', sprintf('%.1f', payload.Lx / 2)};
            ax.YTickLabel = {sprintf('%.1f', -payload.Ly / 2), '0', sprintf('%.1f', payload.Ly / 2)};
            grid(ax, 'on');
        end

        function items = get_ic_preview_export_items(app)
            items = {};
            if app.has_valid_handle('ic_dropdown') && ~isempty(app.handles.ic_dropdown.Items)
                items = cellstr(app.handles.ic_dropdown.Items);
            end
            if isempty(items)
                catalog = app.get_ic_ui_catalog();
                items = cell(1, numel(catalog));
                for i = 1:numel(catalog)
                    items{i} = char(string(catalog(i).display_name));
                end
            end
        end

        function settings = get_ic_preview_export_settings(app)
            dpi_default = 300;
            if isfield(app.config, 'figures_dpi') && isfinite(app.config.figures_dpi)
                dpi_default = double(app.config.figures_dpi);
            elseif isfield(app.layout_cfg, 'ui_defaults') && isfield(app.layout_cfg.ui_defaults, 'figures_dpi') && ...
                    isfinite(app.layout_cfg.ui_defaults.figures_dpi)
                dpi_default = double(app.layout_cfg.ui_defaults.figures_dpi);
            end

            settings = struct( ...
                'figure_save_png', false, ...
                'figure_save_pdf', false, ...
                'figure_save_fig', true, ...
                'figure_dpi', dpi_default);
        end

        function set_ic_preview_export_status(app, text_value, font_color)
            if ~isfield(app.handles, 'ic_preview_export_status') || isempty(app.handles.ic_preview_export_status) || ...
                    ~isvalid(app.handles.ic_preview_export_status)
                return;
            end
            app.handles.ic_preview_export_status.Text = char(string(text_value));
            if nargin >= 3 && ~isempty(font_color)
                app.handles.ic_preview_export_status.FontColor = font_color;
            end
        end

        function saved = save_single_ic_preview_figure(app, payload, output_path, show_contour_bands, save_settings)
            fig = figure('Visible', 'off', 'Color', [1 1 1]);
            cleanup_fig = onCleanup(@() close(fig)); %#ok<NASGU>
            ax = axes('Parent', fig);
            app.style_axes(ax);
            app.render_ic_preview_axes(ax, payload, show_contour_bands);
            drawnow;
            saved = ResultsPlotDispatcher.save_figure_bundle(fig, output_path, save_settings);
        end

        function saved = save_ic_preview_grid_figure(app, ic_types, output_path, show_contour_bands, save_settings)
            fig = figure('Visible', 'off', 'Color', [1 1 1], 'Position', [100 100 1400 1000]);
            cleanup_fig = onCleanup(@() close(fig)); %#ok<NASGU>
            tiled = tiledlayout(fig, 2, 2, 'Padding', 'compact', 'TileSpacing', 'compact');
            for i_type = 1:numel(ic_types)
                ax = nexttile(tiled, i_type);
                app.style_axes(ax);
                payload = app.build_ic_preview_payload(ic_types{i_type}, false);
                app.render_ic_preview_axes(ax, payload, show_contour_bands);
            end
            drawnow;
            saved = ResultsPlotDispatcher.save_figure_bundle(fig, output_path, save_settings);
        end

        function outputs = export_ic_preview_set(app, output_dir)
            if nargin < 2 || isempty(output_dir)
                output_dir = uigetdir(pwd, 'Export IC Preview FIG Set');
                if isequal(output_dir, 0)
                    outputs = struct('directory', '', 'individual', struct(), 'grid', struct());
                    app.set_ic_preview_export_status('Export cancelled.', app.layout_cfg.colors.fg_muted);
                    return;
                end
            end

            if ~exist(output_dir, 'dir')
                mkdir(output_dir);
            end

            app.set_ic_preview_export_status('Exporting IC previews...', app.layout_cfg.colors.fg_muted);
            drawnow;

            items = app.get_ic_preview_export_items();
            save_settings = app.get_ic_preview_export_settings();
            show_contour_bands = false;
            if app.has_valid_handle('ic_contour_bands_btn')
                show_contour_bands = logical(app.handles.ic_contour_bands_btn.Value);
            end

            outputs = struct('directory', output_dir, 'individual', struct(), 'grid', struct());
            for i_item = 1:numel(items)
                ic_type = app.map_ic_display_to_type(items{i_item});
                payload = app.build_ic_preview_payload(ic_type, false);
                base_name = sprintf('%02d_%s_preview', i_item, app.sanitize_filename(payload.ic_display));
                output_path = fullfile(output_dir, base_name);
                saved = app.save_single_ic_preview_figure(payload, output_path, show_contour_bands, save_settings);
                outputs.individual.(matlab.lang.makeValidName(ic_type)) = saved;
            end

            focus_types = {'stretched_gaussian', 'taylor_green', 'random_turbulence', 'lamb_oseen'};
            outputs.grid = app.save_ic_preview_grid_figure( ...
                focus_types, ...
                fullfile(output_dir, 'ic_preview_grid_2x2'), ...
                show_contour_bands, ...
                save_settings);

            app.set_ic_preview_export_status( ...
                sprintf('Saved %d IC FIGs + 2x2 grid to %s', numel(items), output_dir), ...
                app.layout_cfg.colors.accent_green);
            app.append_to_terminal( ...
                sprintf('IC preview export saved %d FIG files to %s', numel(items) + 1, output_dir), ...
                'info');
        end

        function on_export_ic_preview_set(app)
            try
                app.export_ic_preview_set();
            catch ME
                app.set_ic_preview_export_status('IC preview export failed.', app.layout_cfg.colors.accent_red);
                app.append_to_terminal(sprintf('IC preview export failed: %s', ME.message), 'error');
                app.show_alert_latex(sprintf('IC preview export failed:\\n%s', ME.message), ...
                    'IC Preview Export', 'Icon', 'error');
            end
        end

        function update_ic_preview(app)
            % Update initial condition preview using the same coefficient
            % packing and IC factory used in launched runs.
            try
                if ~isfield(app.handles, 'ic_preview_axes') || ~isvalid(app.handles.ic_preview_axes)
                    return;
                end

                [ic_type, schema] = app.resolve_active_ic_type();
                app.sync_multi_vortex_preview_state(ic_type, schema);
                payload = app.build_ic_preview_payload(ic_type, true);
                show_contour_bands = false;
                if app.has_valid_handle('ic_contour_bands_btn')
                    show_contour_bands = logical(app.handles.ic_contour_bands_btn.Value);
                end

                app.render_ic_preview_axes(app.handles.ic_preview_axes, payload, show_contour_bands);

                if isfield(app.handles, 'ic_status') && isvalid(app.handles.ic_status)
                    app.handles.ic_status.Text = '';
                    app.handles.ic_status.Visible = 'off';
                end
                app.update_checklist();
            catch ME
                if isfield(app.handles, 'ic_status') && isvalid(app.handles.ic_status)
                    app.handles.ic_status.Text = 'IC preview error';
                    app.handles.ic_status.FontColor = app.layout_cfg.colors.accent_red;
                    app.handles.ic_status.Visible = 'on';
                end
                app.append_to_terminal(sprintf('IC preview error: %s', ME.message), 'error');
            end
        end

        function on_ic_changed(app)
            % Update IC field labels and preview when IC selection changes
            app.close_multi_vortex_dialog();
            app.sync_ic_scenario_items_for_active_ic();
            app.update_ic_fields();
            app.update_ic_preview();
            app.refresh_phase1_ic_study_preview();
        end

        function on_ic_gaussian_model_toggle_changed(app)
            if ~app.has_valid_handle('ic_dropdown') || ~app.has_valid_handle('ic_gaussian_model_toggle')
                return;
            end
            if logical(app.handles.ic_gaussian_model_toggle.Value)
                target_display = 'Elliptical Vortex';
            else
                target_display = 'Stretched Gaussian';
            end
            items = cellstr(app.handles.ic_dropdown.Items);
            if ~any(strcmpi(items, target_display))
                return;
            end
            app.handles.ic_dropdown.Value = target_display;
            app.on_ic_changed();
        end

        function sync_ic_gaussian_model_toggle(app)
            if ~app.has_valid_handle('ic_gaussian_model_toggle')
                return;
            end
            allow_toggle = false;
            active_type = 'stretched_gaussian';
            if app.has_valid_handle('ic_dropdown')
                items = cellstr(app.handles.ic_dropdown.Items);
                allow_toggle = any(strcmpi(items, 'Stretched Gaussian')) && any(strcmpi(items, 'Elliptical Vortex'));
                active_type = app.map_ic_display_to_type(app.handles.ic_dropdown.Value);
            elseif isfield(app.config, 'ic_type') && ~isempty(app.config.ic_type)
                allow_toggle = true;
                active_type = char(string(app.config.ic_type));
            end
            app.handles.ic_gaussian_model_toggle.Enable = app.on_off(allow_toggle);
            app.handles.ic_gaussian_model_toggle.Value = strcmpi(char(string(active_type)), 'elliptical_vortex');
        end

        function on_ic_contour_bands_toggled(app)
            app.sync_ic_contour_bands_button();
            app.update_ic_preview();
        end

        function sync_ic_contour_bands_button(app)
            if ~app.has_valid_handle('ic_contour_bands_btn')
                return;
            end
            if logical(app.handles.ic_contour_bands_btn.Value)
                app.handles.ic_contour_bands_btn.Text = 'Bands: On';
            else
                app.handles.ic_contour_bands_btn.Text = 'Bands: Off';
            end
        end

        function show_ic_pattern_count_help(app)
            msg = sprintf([ ...
                'Pattern and Count controls are used for multi-vortex style initial conditions.\\n\\n' ...
                'Pattern:\\n' ...
                '  - single: one center location\\n' ...
                '  - circular: centers distributed on a ring\\n' ...
                '  - grid: centers distributed on a lattice\\n' ...
                '  - random: centers scattered within the domain\\n\\n' ...
                'Count (N): number of vortex centers to generate (N >= 1).\\n\\n' ...
                'For single-vortex ICs, Pattern/Count are ignored.']);
            app.show_alert_latex(msg, 'IC Pattern/Count Help', 'Icon', 'info');
        end

        function open_multi_vortex_settings_dialog(app)
            % Configure multi-vortex rows in a two-pane editor (table + preview).
            [ic_type, ~, scenario_entry, context_key] = app.resolve_active_ic_type();
            if any(strcmpi(ic_type, {'taylor_green', 'random_turbulence'}))
                app.show_alert_latex( ...
                    'Multi-vortex editing is disabled for domain-filling ICs (Taylor-Green / Random Turbulence).', ...
                    'Multi-Vortex Settings', 'Icon', 'info');
                return;
            end

            existing = app.get_valid_multi_vortex_dialog();
            if ~isempty(existing)
                existing_context = '';
                if isfield(app.handles, 'multi_vortex_dialog_context')
                    existing_context = char(string(app.handles.multi_vortex_dialog_context));
                end
                if strcmpi(existing_context, context_key)
                    app.focus_multi_vortex_dialog(existing);
                    return;
                end
                app.close_multi_vortex_dialog(existing);
            end

            C = app.layout_cfg.colors;
            dlg = uifigure( ...
                'Name', 'Multi-Vortex Settings', ...
                'Position', app.compute_multi_vortex_dialog_position([1220 740]), ...
                'Color', C.bg_dark, ...
                'WindowStyle', 'modal');
            if isprop(dlg, 'Theme')
                dlg.Theme = 'dark';
            end
            dlg.CloseRequestFcn = @(src,~) app.close_multi_vortex_dialog(src);

            root = uigridlayout(dlg, [3, 1]);
            root.RowHeight = {46, '1x', 40};
            root.ColumnWidth = {'1x'};
            root.Padding = [10 10 10 10];
            root.RowSpacing = 8;

            rows = app.normalize_multi_vortex_rows( ...
                app.pick_field(app.config, {'ic_multi_vortex_rows'}, struct([])), ic_type);
            if isempty(rows)
                rows = app.seed_multi_vortex_rows(ic_type);
            end
            popup_ic_items = app.get_multi_vortex_popup_ic_display_items();
            selected_row = 1;
            arrangement_catalog = app.get_ic_arrangement_catalog();
            arrangement_ids = {'single', 'circular', 'grid', 'random'};
            arrangement_display = {'Single', 'Circular', 'Grid', 'Random'};
            if isstruct(arrangement_catalog) && ~isempty(arrangement_catalog)
                arrangement_ids = cell(1, numel(arrangement_catalog));
                arrangement_display = cell(1, numel(arrangement_catalog));
                for i_arr = 1:numel(arrangement_catalog)
                    arrangement_ids{i_arr} = char(string(arrangement_catalog(i_arr).id));
                    arrangement_display{i_arr} = char(string(arrangement_catalog(i_arr).display_name));
                end
            end
            current_arrangement = app.get_ic_pattern_value();
            if ~any(strcmpi(current_arrangement, arrangement_ids))
                current_arrangement = arrangement_ids{1};
            end
            lock_arrangement = isstruct(scenario_entry) && ...
                isfield(scenario_entry, 'lock_arrangement') && logical(scenario_entry.lock_arrangement);

            top = uigridlayout(root, [1, 8]);
            top.Layout.Row = 1;
            top.ColumnWidth = {'fit', 170, 110, 110, 110, '1x', 110, 130};
            top.Padding = [0 0 0 0];
            top.ColumnSpacing = 6;
            uilabel(top, 'Text', 'Arrangement', 'FontColor', C.fg_text, 'FontWeight', 'bold');
            dd_arrangement = uidropdown(top, ...
                'Items', arrangement_display, ...
                'ItemsData', arrangement_ids, ...
                'Value', current_arrangement, ...
                'Enable', app.on_off(~lock_arrangement));
            dd_arrangement.Layout.Column = 2;
            btn_add = uibutton(top, 'Text', 'Add Vortex');
            btn_add.Layout.Column = 3;
            btn_remove = uibutton(top, 'Text', 'Remove Vortex');
            btn_remove.Layout.Column = 4;
            btn_duplicate = uibutton(top, 'Text', 'Duplicate');
            btn_duplicate.Layout.Column = 5;
            spacer_lbl = uilabel(top, 'Text', '', 'FontColor', C.fg_text);
            spacer_lbl.Layout.Column = 6;
            btn_apply = uibutton(top, 'Text', 'Apply', ...
                'BackgroundColor', C.accent_green, 'FontColor', [0.05 0.05 0.05]);
            btn_apply.Layout.Column = 7;
            btn_close = uibutton(top, 'Text', 'Apply & Close', ...
                'BackgroundColor', C.accent_cyan, 'FontColor', [0.05 0.05 0.05]);
            btn_close.Layout.Column = 8;

            body = uigridlayout(root, [1, 2]);
            body.Layout.Row = 2;
            body.ColumnWidth = {'1.1x', '1x'};
            body.ColumnSpacing = 8;
            body.Padding = [0 0 0 0];

            left_panel = uigridlayout(body, [1, 1]);
            left_panel.Layout.Column = 1;
            left_panel.Padding = [0 0 0 0];
            tbl = uitable(left_panel, ...
                'ColumnName', {'enabled', 'ic_type', 'x0', 'y0', 'scale', 'amplitude', 'charge'}, ...
                'ColumnEditable', true(1, 7), ...
                'RowName', {}, ...
                'BackgroundColor', [C.bg_input; C.bg_panel_alt]);
            if isprop(tbl, 'ColumnFormat')
                tbl.ColumnFormat = {'logical', popup_ic_items, 'numeric', 'numeric', 'numeric', 'numeric', 'numeric'};
            end
            tbl.Layout.Row = 1;
            tbl.Layout.Column = 1;

            right_panel = uigridlayout(body, [1, 1]);
            right_panel.Layout.Column = 2;
            right_panel.Padding = [0 0 0 0];
            ax = uiaxes(right_panel);
            ax.Layout.Row = 1;
            ax.Layout.Column = 1;
            app.style_axes(ax);
            title(ax, 'IC Preview', 'Color', C.fg_text, 'Interpreter', 'none');
            xlabel(ax, '$L_x$', 'Color', C.fg_muted, 'Interpreter', 'latex');
            ylabel(ax, '$L_y$', 'Color', C.fg_muted, 'Interpreter', 'latex');

            bottom = uigridlayout(root, [1, 3]);
            bottom.Layout.Row = 3;
            bottom.ColumnWidth = {'1x', 110, 110};
            bottom.Padding = [0 0 0 0];
            bottom.ColumnSpacing = 6;
            lbl_status = uilabel(bottom, ...
                'Text', 'Edit vortex rows on the left; preview updates on the right.', ...
                'FontColor', C.fg_muted);
            btn_cancel = uibutton(bottom, 'Text', 'Cancel', ...
                'ButtonPushedFcn', @(~,~) app.close_multi_vortex_dialog(dlg));
            btn_cancel.Layout.Column = 2;
            btn_close_only = uibutton(bottom, 'Text', 'Close', ...
                'ButtonPushedFcn', @(~,~) app.close_multi_vortex_dialog(dlg));
            btn_close_only.Layout.Column = 3;

            app.handles.multi_vortex_dialog = dlg;
            app.handles.multi_vortex_dialog_context = context_key;
            app.handles.multi_vortex_dialog_table = tbl;
            app.handles.multi_vortex_dialog_arrangement = dd_arrangement;
            app.handles.multi_vortex_dialog_apply = btn_apply;
            app.handles.multi_vortex_dialog_preview_axes = ax;
            app.handles.multi_vortex_dialog_status = lbl_status;

            refresh_table();
            refresh_preview();

            tbl.CellSelectionCallback = @(~, evt) on_table_selection(evt);
            tbl.CellEditCallback = @(~, evt) on_table_edit(evt);
            dd_arrangement.ValueChangedFcn = @(~,~) on_arrangement_changed();
            btn_add.ButtonPushedFcn = @(~,~) add_row();
            btn_remove.ButtonPushedFcn = @(~,~) remove_row();
            btn_duplicate.ButtonPushedFcn = @(~,~) duplicate_row();
            btn_apply.ButtonPushedFcn = @(~,~) apply_rows(false);
            btn_close.ButtonPushedFcn = @(~,~) apply_rows(true);
            app.focus_multi_vortex_dialog(dlg);

            function on_table_selection(evt)
                if isfield(evt, 'Indices') && ~isempty(evt.Indices)
                    selected_row = max(1, min(numel(rows), evt.Indices(1)));
                end
            end

            function on_table_edit(evt)
                rows = app.table_data_to_multi_vortex_rows(tbl.Data, rows, ic_type);
                if isfield(evt, 'Indices') && ~isempty(evt.Indices)
                    selected_row = max(1, min(numel(rows), evt.Indices(1)));
                end
                refresh_preview();
            end

            function add_row()
                rows(end + 1) = app.default_multi_vortex_row(ic_type, numel(rows) + 1); %#ok<AGROW>
                selected_row = numel(rows);
                refresh_table();
                refresh_preview();
            end

            function remove_row()
                if isempty(rows)
                    return;
                end
                rows(selected_row) = [];
                if isempty(rows)
                    rows = app.seed_multi_vortex_rows(ic_type);
                end
                rows = app.renumber_multi_vortex_rows(rows);
                selected_row = max(1, min(selected_row, numel(rows)));
                refresh_table();
                refresh_preview();
            end

            function duplicate_row()
                if isempty(rows)
                    return;
                end
                clone = rows(selected_row);
                clone.row_id = numel(rows) + 1;
                rows(end + 1) = clone; %#ok<AGROW>
                selected_row = numel(rows);
                refresh_table();
                refresh_preview();
            end

            function refresh_table()
                tbl.Data = app.multi_vortex_rows_to_table_data(rows);
                tbl.ColumnEditable = true(1, 7);
            end

            function on_arrangement_changed()
                shared = app.read_ic_shared_values();
                rows = app.apply_multi_vortex_arrangement(rows, dd_arrangement.Value, ...
                    app.pick_field(shared, {'center_x'}, 0.0), app.pick_field(shared, {'center_y'}, 0.0));
                refresh_table();
                refresh_preview();
            end

            function refresh_preview()
                cla(ax);
                valid_rows = rows;
                [ok_rows, validation_message] = app.validate_multi_vortex_rows(valid_rows);
                if ~ok_rows
                    lbl_status.Text = validation_message;
                    lbl_status.FontColor = C.accent_red;
                else
                    if lock_arrangement
                        lbl_status.Text = sprintf('%d vortex row(s). Arrangement locked by scenario: %s', ...
                            numel(valid_rows), app.find_ic_arrangement_entry(dd_arrangement.Value).display_name);
                    else
                        lbl_status.Text = sprintf('%d vortex row(s). Arrangement: %s', ...
                            numel(valid_rows), app.find_ic_arrangement_entry(dd_arrangement.Value).display_name);
                    end
                    lbl_status.FontColor = C.fg_muted;
                end

                if ~ok_rows
                    text(ax, 0.5, 0.5, validation_message, ...
                        'Units', 'normalized', ...
                        'HorizontalAlignment', 'center', ...
                        'Color', C.accent_red, ...
                        'Interpreter', 'none');
                    return;
                end

                Lx = 10.0;
                Ly = 10.0;
                if app.has_valid_handle('Lx')
                    Lx = max(1.0e-6, double(app.handles.Lx.Value));
                end
                if app.has_valid_handle('Ly')
                    Ly = max(1.0e-6, double(app.handles.Ly.Value));
                end

                n = min(256, max(64, round(min([app.safe_numeric_value('Nx', 128), app.safe_numeric_value('Ny', 128)]))));
                [X, Y] = meshgrid(linspace(-Lx / 2, Lx / 2, n), linspace(-Ly / 2, Ly / 2, n));
                Z = app.evaluate_multi_vortex_rows(X, Y, valid_rows, ic_type);

                show_contour_bands = false;
                if app.has_valid_handle('ic_contour_bands_btn')
                    show_contour_bands = logical(app.handles.ic_contour_bands_btn.Value);
                end
                if show_contour_bands
                    rendered = app.render_ic_contours(ax, X, Y, Z);
                    if ~rendered
                        app.render_ic_image(ax, X, Y, Z);
                    end
                else
                    app.render_ic_image(ax, X, Y, Z);
                end
                hold(ax, 'on');
                rectangle(ax, 'Position', [-Lx/2 -Ly/2 Lx Ly], ...
                    'EdgeColor', C.accent_gray, 'LineStyle', '--', 'LineWidth', 1.0);
                hold(ax, 'off');
                colormap(ax, turbo(256));
                grid(ax, 'on');
                xlim(ax, [-Lx/2, Lx/2]);
                ylim(ax, [-Ly/2, Ly/2]);
                title(ax, sprintf('Multi-Vortex IC Preview (%s)', app.find_ic_arrangement_entry(dd_arrangement.Value).display_name), ...
                    'Color', C.fg_text, 'Interpreter', 'none');
            end

            function apply_rows(close_after_apply)
                [ok_rows, validation_message] = app.validate_multi_vortex_rows(rows);
                if ~ok_rows
                    lbl_status.Text = validation_message;
                    lbl_status.FontColor = C.accent_red;
                    return;
                end
                rows = app.renumber_multi_vortex_rows(rows);
                app.config.ic_multi_vortex_rows = rows;
                app.config.ic_multi_vortex_experimental = true;
                app.config.ic_arrangement = char(string(dd_arrangement.Value));
                app.config.ic_pattern = app.config.ic_arrangement;
                if numel(rows) == 1
                    app.mirror_single_multi_vortex_row_to_controls(rows(1));
                end
                if app.has_valid_handle('ic_count')
                    app.handles.ic_count.Value = max(1, numel(rows));
                end
                lbl_status.Text = sprintf('Applied %d structured vortex row(s).', numel(rows));
                lbl_status.FontColor = C.accent_green;
                app.update_ic_preview();
                if close_after_apply
                    app.close_multi_vortex_dialog(dlg);
                end
            end
        end

        function dlg = get_valid_multi_vortex_dialog(app)
            dlg = [];
            if isfield(app.handles, 'multi_vortex_dialog')
                candidate = app.handles.multi_vortex_dialog;
                if ~isempty(candidate) && isvalid(candidate)
                    dlg = candidate;
                end
            end
        end

        function focus_multi_vortex_dialog(app, dlg)
            if nargin < 2 || isempty(dlg) || ~isvalid(dlg)
                return;
            end
            try
                dlg.Position = app.compute_multi_vortex_dialog_position(dlg.Position(3:4));
            catch
            end
            try
                dlg.Visible = 'off';
                drawnow;
                dlg.Visible = 'on';
            catch
            end
            try
                figure(dlg);
            catch
            end
            drawnow;
        end

        function close_multi_vortex_dialog(app, dlg)
            if nargin < 2 || isempty(dlg)
                dlg = app.get_valid_multi_vortex_dialog();
            end
            if ~isempty(dlg) && isvalid(dlg)
                try
                    dlg.CloseRequestFcn = '';
                catch
                end
                delete(dlg);
            end
            app.clear_multi_vortex_dialog_handles();
        end

        function clear_multi_vortex_dialog_handles(app)
            fields = { ...
                'multi_vortex_dialog', ...
                'multi_vortex_dialog_context', ...
                'multi_vortex_dialog_table', ...
                'multi_vortex_dialog_arrangement', ...
                'multi_vortex_dialog_apply', ...
                'multi_vortex_dialog_preview_axes', ...
                'multi_vortex_dialog_status'};
            handles_struct = app.handles;
            for i = 1:numel(fields)
                if isfield(handles_struct, fields{i})
                    handles_struct = rmfield(handles_struct, fields{i});
                end
            end
            app.handles = handles_struct;
        end

        function position = compute_multi_vortex_dialog_position(app, requested_size)
            if nargin < 2 || isempty(requested_size)
                requested_size = [1220 740];
            end
            requested_size = double(requested_size(:).');
            if numel(requested_size) >= 4
                requested_size = requested_size(3:4);
            end
            if numel(requested_size) ~= 2
                requested_size = [1220 740];
            end

            monitor_positions = get(groot, 'MonitorPositions');
            if isempty(monitor_positions) || size(monitor_positions, 2) < 4
                monitor_positions = [1 1 1366 768];
            end
            target_monitor = double(monitor_positions(1, :));
            if ~isempty(app.fig) && isvalid(app.fig) && isprop(app.fig, 'Position')
                anchor = double(app.fig.Position);
                cx = anchor(1) + anchor(3) / 2;
                cy = anchor(2) + anchor(4) / 2;
                idx = find(cx >= monitor_positions(:, 1) & ...
                    cx <= monitor_positions(:, 1) + monitor_positions(:, 3) & ...
                    cy >= monitor_positions(:, 2) & ...
                    cy <= monitor_positions(:, 2) + monitor_positions(:, 4), 1, 'first');
                if ~isempty(idx)
                    target_monitor = double(monitor_positions(idx, :));
                end
            end

            margin_x = 20;
            margin_y = 60;
            width = min(max(480, requested_size(1)), max(480, target_monitor(3) - 2 * margin_x));
            height = min(max(360, requested_size(2)), max(360, target_monitor(4) - 2 * margin_y));
            left = target_monitor(1) + max(margin_x, floor((target_monitor(3) - width) / 2));
            bottom = target_monitor(2) + max(margin_y, floor((target_monitor(4) - height) / 2));
            position = round([left, bottom, width, height]);
        end

        function on_ic_scenario_changed(app)
            if ~app.has_valid_handle('ic_scenario')
                return;
            end
            app.close_multi_vortex_dialog();
            scenario_name = char(string(app.handles.ic_scenario.Value));
            if strcmpi(strtrim(scenario_name), 'Manual')
                app.config.ic_multi_vortex_experimental = false;
            end
            app.config.ic_scenario = scenario_name;
            app.update_ic_fields();
            app.update_ic_preview();
        end

        function render_ic_image(~, ax, X, Y, Z)
            % Render IC preview as image-only field (safe for constant Z).
            imagesc(ax, X(1, :), Y(:, 1), Z);
            set(ax, 'YDir', 'normal');
        end

        function rendered = render_ic_contours(app, ax, X, Y, Z)
            % Render contours with guarded warning handling; fallback controlled by caller.
            rendered = false;
            warn1 = warning('query', 'MATLAB:contour:ConstantZData');
            warn2 = warning('query', 'MATLAB:contourf:ConstantZData');
            warn3 = warning('query', 'MATLAB:contour:ConstantData');
            warn4 = warning('query', 'MATLAB:contourf:ConstantData');
            cleanup_obj = onCleanup(@() app.restore_contour_warning_state(warn1, warn2, warn3, warn4)); %#ok<NASGU>
            warning('off', 'MATLAB:contour:ConstantZData');
            warning('off', 'MATLAB:contourf:ConstantZData');
            warning('off', 'MATLAB:contour:ConstantData');
            warning('off', 'MATLAB:contourf:ConstantData');
            try
                contourf(ax, X, Y, Z, 20, 'LineStyle', 'none');
                hold(ax, 'on');
                contour(ax, X, Y, Z, 12, 'LineWidth', 0.9, 'LineColor', [0.82 0.82 0.82]);
                rendered = true;
            catch ME
                UIController.warn_once('UIController:ICContourRenderFailed', ...
                    'Contour rendering failed for IC preview; using image fallback: %s', ME.message);
                rendered = false;
            end
        end

        function update_ic_fields(app)
            % Schema-driven IC field update with per-context value caching.
            app.ensure_ic_state_cache();
            app.cache_active_ic_state();

            [ic_type, schema, scenario_entry, context_key] = app.resolve_active_ic_type();
            forced_ic_type = char(string(app.pick_field(scenario_entry, {'forced_ic_type'}, '')));
            if ~isempty(strtrim(forced_ic_type))
                desired_display = app.map_ic_type_to_display(forced_ic_type);
                if app.has_valid_handle('ic_dropdown')
                    items = cellstr(string(app.handles.ic_dropdown.Items));
                    if any(strcmpi(desired_display, items))
                        app.handles.ic_dropdown.Value = desired_display;
                    end
                end
                app.config.ic_type = forced_ic_type;
            end
            app.handles.ic_active_context_key = context_key;

            if app.has_valid_handle('ic_dropdown')
                lock_dropdown = false;
                if isstruct(scenario_entry) && isfield(scenario_entry, 'lock_ic_type_dropdown')
                    lock_dropdown = logical(scenario_entry.lock_ic_type_dropdown);
                end
                app.handles.ic_dropdown.Enable = app.on_off(~lock_dropdown);
            end

            shared_seed = app.read_ic_shared_values();
            app.build_ic_dynamic_controls(schema, scenario_entry, shared_seed);
            app.apply_ic_shared_visibility(schema.shared_flags, scenario_entry);
            app.set_ic_equation_and_where(schema.display_name, schema.equation_tex, schema.where_entries);

            cache_map = app.handles.ic_state_cache;
            is_new_context = ~isKey(cache_map, context_key);
            if ~is_new_context
                st = cache_map(context_key);
                if isstruct(st)
                    if isfield(st, 'shared') && isstruct(st.shared)
                        app.apply_shared_values(st.shared);
                    end
                    if isfield(st, 'dynamic') && isstruct(st.dynamic)
                        app.write_ic_dynamic_values(schema, st.dynamic);
                    end
                end
            else
                app.write_ic_dynamic_values(schema, app.default_dynamic_values(schema));
            end
            app.apply_scenario_overrides(ic_type, scenario_entry, schema);
            app.handles.ic_state_cache(context_key) = struct( ...
                'shared', app.read_ic_shared_values(), ...
                'dynamic', app.read_ic_dynamic_values_from_schema(schema));

            app.update_ic_compact_layout(numel(schema.dynamic_fields));
            app.update_ic_arrangement_control_state(schema, scenario_entry);
            app.update_ic_context_state(schema, scenario_entry);
            app.handles.ic_active_schema = schema;
            app.sync_ic_gaussian_model_toggle();
        end

        function set_ic_equation_and_where(app, ic_name, eq_tex, where_entries)
            if app.has_valid_handle('ic_equation')
                eq_handle = app.handles.ic_equation;
                if isprop(eq_handle, 'ImageSource') && app.supports_equation_image_rendering()
                    eq_path = app.render_equation_image(ic_name, eq_tex);
                    if isfile(eq_path)
                        eq_handle.ImageSource = eq_path;
                    end
                elseif isprop(eq_handle, 'Text')
                    eq_handle.Text = sprintf('Initial Condition Equation - %s', ic_name);
                end
            end
            if app.has_valid_handle('ic_where_axes')
                app.render_where_axes(where_entries);
            end
        end

        function ensure_ic_state_cache(app)
            if ~isfield(app.handles, 'ic_state_cache') || ~isa(app.handles.ic_state_cache, 'containers.Map')
                app.handles.ic_state_cache = containers.Map('KeyType', 'char', 'ValueType', 'any');
            end
            if ~isfield(app.handles, 'ic_active_context_key')
                app.handles.ic_active_context_key = '';
            end
            if ~isfield(app.handles, 'ic_active_schema')
                app.handles.ic_active_schema = struct();
            end
        end

        function cache_active_ic_state(app)
            app.ensure_ic_state_cache();
            key = '';
            if isfield(app.handles, 'ic_active_context_key')
                key = char(string(app.handles.ic_active_context_key));
            end
            if isempty(strtrim(key))
                return;
            end
            if ~isfield(app.handles, 'ic_active_schema') || ~isstruct(app.handles.ic_active_schema) || ...
                    ~isfield(app.handles.ic_active_schema, 'dynamic_fields')
                return;
            end
            schema = app.handles.ic_active_schema;
            state = struct( ...
                'shared', app.read_ic_shared_values(), ...
                'dynamic', app.read_ic_dynamic_values_from_schema(schema));
            app.handles.ic_state_cache(key) = state;
        end

        function [ic_type, schema, scenario_entry, context_key] = resolve_active_ic_type(app)
            scenario_name = 'Manual';
            if app.has_valid_handle('ic_scenario')
                scenario_name = char(string(app.handles.ic_scenario.Value));
            end
            scenario_entry = app.find_ic_scenario_entry(scenario_name);

            ic_display = 'Stretched Gaussian';
            if app.has_valid_handle('ic_dropdown')
                ic_display = app.handles.ic_dropdown.Value;
            end
            ic_type = app.map_ic_display_to_type(ic_display);
            forced_ic_type = char(string(app.pick_field(scenario_entry, {'forced_ic_type'}, '')));
            forced_by_scenario = ~isempty(strtrim(forced_ic_type));
            if forced_by_scenario
                ic_type = forced_ic_type;
            end

            schema = app.get_ic_schema(ic_type);
            context_key = app.build_ic_context_key(ic_type, scenario_name, forced_by_scenario);
        end

        function sync_ic_dropdown_items_for_active_method(app)
            if ~app.has_valid_handle('ic_dropdown')
                return;
            end

            method_token = lower(char(string(app.pick_field(app.config, {'method'}, 'finite_difference'))));
            method_token = strrep(method_token, '-', '_');
            method_token = strrep(method_token, ' ', '_');
            catalog = app.get_ic_ui_catalog();
            keep_mask = true(1, numel(catalog));
            if strcmp(method_token, 'shallow_water')
                keep_mask = ~strcmpi({catalog.ic_type}, 'no_initial_condition');
            end
            filtered = catalog(keep_mask);
            if isempty(filtered)
                error('UIController:EmptyICCatalogForMethod', ...
                    'No initial-condition entries remain for method %s.', method_token);
            end

            items = cell(1, numel(filtered));
            for i = 1:numel(filtered)
                items{i} = char(string(filtered(i).display_name));
            end

            requested = '';
            if ~isempty(app.handles.ic_dropdown.Value)
                requested = char(string(app.handles.ic_dropdown.Value));
            elseif isfield(app.config, 'ic_type') && ~isempty(app.config.ic_type)
                requested = app.map_ic_type_to_display(app.config.ic_type);
            end
            if isempty(requested) || ~any(strcmpi(requested, items))
                requested = 'Stretched Gaussian';
                if ~any(strcmpi(requested, items))
                    requested = items{1};
                end
            end

            app.handles.ic_dropdown.Items = items;
            app.handles.ic_dropdown.Value = requested;
            app.config.ic_type = app.map_ic_display_to_type(requested);
        end

        function key = build_ic_context_key(~, ic_type, scenario_name, forced_by_scenario)
            if forced_by_scenario
                key = ['scenario:' lower(strtrim(char(string(scenario_name))))];
            else
                key = ['ic:' lower(strtrim(char(string(ic_type))))];
            end
        end

        function catalog = get_ic_ui_catalog(app)
            catalog = struct([]);
            if isfield(app.layout_cfg, 'ui_defaults') && isfield(app.layout_cfg.ui_defaults, 'ic_ui_catalog')
                catalog = app.layout_cfg.ui_defaults.ic_ui_catalog;
            elseif isfield(app.config, 'ic_ui_catalog')
                catalog = app.config.ic_ui_catalog;
            else
                defaults_fallback = create_default_parameters();
                if isfield(defaults_fallback, 'ic_ui_catalog')
                    catalog = defaults_fallback.ic_ui_catalog;
                end
            end
            if isempty(catalog)
                error('UIController:MissingICUICatalog', 'IC UI catalog is missing.');
            end
        end

        function catalog = get_ic_scenario_catalog(app)
            catalog = struct([]);
            if isfield(app.layout_cfg, 'ui_defaults') && isfield(app.layout_cfg.ui_defaults, 'ic_scenario_catalog')
                catalog = app.layout_cfg.ui_defaults.ic_scenario_catalog;
            elseif isfield(app.config, 'ic_scenario_catalog')
                catalog = app.config.ic_scenario_catalog;
            else
                defaults_fallback = create_default_parameters();
                if isfield(defaults_fallback, 'ic_scenario_catalog')
                    catalog = defaults_fallback.ic_scenario_catalog;
                end
            end
            if isempty(catalog)
                catalog = struct('scenario_name', 'Manual', 'forced_ic_type', '', ...
                    'shared_overrides', struct(), 'dynamic_overrides', struct(), ...
                    'lock_ic_type_dropdown', false, 'description', '', ...
                    'lock_arrangement', false, 'charge_pattern', 'uniform_positive');
            end
        end

        function sync_ic_scenario_items_for_active_ic(app, requested_scenario)
            if nargin < 2
                requested_scenario = '';
            end
            if ~app.has_valid_handle('ic_scenario')
                return;
            end

            ic_type = 'stretched_gaussian';
            if app.has_valid_handle('ic_dropdown')
                ic_type = app.map_ic_display_to_type(app.handles.ic_dropdown.Value);
            end
            catalog = app.filter_ic_scenario_catalog_for_ic(ic_type);
            items = cell(1, numel(catalog));
            for i = 1:numel(catalog)
                items{i} = char(string(catalog(i).scenario_name));
            end
            if isempty(items)
                items = {'Manual'};
            end

            if isempty(requested_scenario)
                if isfield(app.config, 'ic_scenario') && ~isempty(app.config.ic_scenario)
                    requested_scenario = char(string(app.config.ic_scenario));
                elseif app.has_valid_handle('ic_scenario')
                    requested_scenario = char(string(app.handles.ic_scenario.Value));
                else
                    requested_scenario = 'Manual';
                end
            end
            if ~any(strcmpi(requested_scenario, items))
                requested_scenario = 'Manual';
            end

            app.handles.ic_scenario.Items = items;
            app.handles.ic_scenario.Value = requested_scenario;
            app.config.ic_scenario = requested_scenario;
        end

        function catalog = filter_ic_scenario_catalog_for_ic(app, ic_type)
            catalog = app.get_ic_scenario_catalog();
            schema = app.get_ic_schema(ic_type);
            if isfield(schema, 'supports_multi_vortex') && logical(schema.supports_multi_vortex)
                return;
            end
            idx = find(strcmpi({catalog.scenario_name}, 'Manual'), 1, 'first');
            if isempty(idx)
                catalog = struct('scenario_name', 'Manual', 'forced_ic_type', '', ...
                    'shared_overrides', struct(), 'dynamic_overrides', struct(), ...
                    'lock_ic_type_dropdown', false, 'description', '', ...
                    'lock_arrangement', false, 'charge_pattern', 'uniform_positive');
            else
                catalog = catalog(idx);
            end
        end

        function catalog = get_ic_arrangement_catalog(app)
            catalog = struct([]);
            if isfield(app.layout_cfg, 'ui_defaults') && isfield(app.layout_cfg.ui_defaults, 'ic_arrangement_catalog')
                catalog = app.layout_cfg.ui_defaults.ic_arrangement_catalog;
            elseif isfield(app.config, 'ic_arrangement_catalog')
                catalog = app.config.ic_arrangement_catalog;
            else
                defaults_fallback = create_default_parameters();
                if isfield(defaults_fallback, 'ic_arrangement_catalog')
                    catalog = defaults_fallback.ic_arrangement_catalog;
                end
            end
        end

        function defaults = get_ic_multi_vortex_defaults(app)
            defaults = struct();
            if isfield(app.layout_cfg, 'ui_defaults') && isfield(app.layout_cfg.ui_defaults, 'ic_multi_vortex_defaults')
                defaults = app.layout_cfg.ui_defaults.ic_multi_vortex_defaults;
            elseif isfield(app.config, 'ic_multi_vortex_defaults')
                defaults = app.config.ic_multi_vortex_defaults;
            else
                defaults_fallback = create_default_parameters();
                if isfield(defaults_fallback, 'ic_multi_vortex_defaults')
                    defaults = defaults_fallback.ic_multi_vortex_defaults;
                end
            end
        end

        function schema = get_ic_schema(app, ic_type)
            catalog = app.get_ic_ui_catalog();
            target = lower(strtrim(char(string(ic_type))));
            idx = find(strcmpi({catalog.ic_type}, target), 1, 'first');
            if isempty(idx)
                idx = find(strcmpi({catalog.ic_type}, 'stretched_gaussian'), 1, 'first');
            end
            if isempty(idx)
                idx = 1;
            end
            schema = catalog(idx);
        end

        function entry = find_ic_scenario_entry(app, scenario_name)
            catalog = app.get_ic_scenario_catalog();
            entry = struct('scenario_name', 'Manual', 'forced_ic_type', '', ...
                'shared_overrides', struct(), 'dynamic_overrides', struct(), ...
                'lock_ic_type_dropdown', false, 'description', '', ...
                'lock_arrangement', false, 'charge_pattern', 'uniform_positive');
            if isempty(catalog)
                return;
            end
            idx = find(strcmpi({catalog.scenario_name}, char(string(scenario_name))), 1, 'first');
            if ~isempty(idx)
                entry = catalog(idx);
            end
        end

        function entry = find_ic_arrangement_entry(app, arrangement_name)
            catalog = app.get_ic_arrangement_catalog();
            entry = struct('id', 'single', 'display_name', 'Single', 'description', '');
            if isempty(catalog)
                return;
            end
            idx = find(strcmpi({catalog.id}, char(string(arrangement_name))), 1, 'first');
            if ~isempty(idx)
                entry = catalog(idx);
            end
        end

        function dyn = default_dynamic_values(~, schema)
            dyn = struct();
            if ~isfield(schema, 'dynamic_fields') || isempty(schema.dynamic_fields)
                return;
            end
            for i = 1:numel(schema.dynamic_fields)
                f = schema.dynamic_fields(i);
                dyn.(f.id) = double(f.default);
            end
        end

        function dyn = read_ic_dynamic_values(app)
            if isfield(app.handles, 'ic_active_schema') && isstruct(app.handles.ic_active_schema) && ...
                    isfield(app.handles.ic_active_schema, 'dynamic_fields')
                dyn = app.read_ic_dynamic_values_from_schema(app.handles.ic_active_schema);
            else
                [~, schema] = app.resolve_active_ic_type();
                dyn = app.read_ic_dynamic_values_from_schema(schema);
            end
        end

        function dyn = read_ic_dynamic_values_from_schema(app, schema)
            dyn = app.default_dynamic_values(schema);
            if ~isfield(app.handles, 'ic_dynamic_inputs') || ~isstruct(app.handles.ic_dynamic_inputs)
                return;
            end
            if ~isfield(schema, 'dynamic_fields') || isempty(schema.dynamic_fields)
                return;
            end
            inputs = app.handles.ic_dynamic_inputs;
            for i = 1:numel(schema.dynamic_fields)
                f = schema.dynamic_fields(i);
                if ~isfield(inputs, f.id)
                    continue;
                end
                h = inputs.(f.id);
                if isempty(h) || ~isvalid(h)
                    continue;
                end
                val = double(h.Value);
                if isfield(f, 'is_integer') && logical(f.is_integer)
                    val = round(val);
                end
                dyn.(f.id) = val;
            end
        end

        function write_ic_dynamic_values(app, schema, values)
            if ~isfield(schema, 'dynamic_fields') || isempty(schema.dynamic_fields)
                return;
            end
            if ~isfield(app.handles, 'ic_dynamic_inputs') || ~isstruct(app.handles.ic_dynamic_inputs)
                return;
            end
            inputs = app.handles.ic_dynamic_inputs;
            for i = 1:numel(schema.dynamic_fields)
                f = schema.dynamic_fields(i);
                if ~isfield(inputs, f.id)
                    continue;
                end
                h = inputs.(f.id);
                if isempty(h) || ~isvalid(h)
                    continue;
                end
                val = double(f.default);
                if isstruct(values) && isfield(values, f.id)
                    val = double(values.(f.id));
                end
                if isfield(f, 'is_integer') && logical(f.is_integer)
                    val = round(val);
                end
                h.Value = val;
            end
        end

        function defaults = get_ic_shared_defaults(app)
            defaults = struct( ...
                'center_x', 0.0, ...
                'center_y', 0.0, ...
                'scale', 1.0, ...
                'count', 1, ...
                'amplitude', 1.0);

            source = struct();
            if isstruct(app.config) && ~isempty(fieldnames(app.config))
                source = app.config;
            elseif isfield(app.layout_cfg, 'ui_defaults') && isstruct(app.layout_cfg.ui_defaults)
                source = app.layout_cfg.ui_defaults;
            else
                source = create_default_parameters();
            end

            defaults.center_x = double(app.pick_field_required(source, {'ic_center_x'}, defaults.center_x));
            defaults.center_y = double(app.pick_field_required(source, {'ic_center_y'}, defaults.center_y));
            defaults.scale = double(app.pick_field_required(source, {'ic_scale'}, defaults.scale));
            defaults.count = max(1, round(double(app.pick_field_required(source, {'ic_count'}, defaults.count))));
            defaults.amplitude = double(app.pick_field_required(source, {'ic_amplitude'}, defaults.amplitude));
        end

        function shared = read_ic_shared_values(app)
            defaults = app.get_ic_shared_defaults();
            arrangement = app.get_ic_pattern_value();
            shared = struct( ...
                'center_x', app.safe_numeric_value('ic_center_x', defaults.center_x), ...
                'center_y', app.safe_numeric_value('ic_center_y', defaults.center_y), ...
                'scale', app.safe_numeric_value('ic_scale', defaults.scale), ...
                'count', app.get_ic_count_value(), ...
                'pattern', arrangement, ...
                'arrangement', arrangement, ...
                'amplitude', app.safe_numeric_value('ic_amplitude', defaults.amplitude));
        end

        function shared = collect_normalized_ic_shared_values(app, schema)
            if nargin < 2 || ~isstruct(schema)
                [~, schema] = app.resolve_active_ic_type();
            end

            defaults = app.get_ic_shared_defaults();
            shared = app.read_ic_shared_values();
            flags = struct('show_position', true, 'show_scale', true, ...
                'show_count', false, 'show_pattern', false, 'show_amplitude', false);
            if isfield(schema, 'shared_flags') && isstruct(schema.shared_flags)
                flags = schema.shared_flags;
            end

            if isfield(flags, 'show_position') && ~flags.show_position
                shared.center_x = defaults.center_x;
                shared.center_y = defaults.center_y;
            end
            if isfield(flags, 'show_scale') && ~flags.show_scale
                shared.scale = defaults.scale;
            end
            if isfield(flags, 'show_count') && ~flags.show_count
                shared.count = defaults.count;
            end
            if isfield(flags, 'show_amplitude') && ~flags.show_amplitude
                shared.amplitude = defaults.amplitude;
            end
            shared.count = max(1, round(double(shared.count)));
        end

        function ic_state = collect_ic_state(app, schema)
            if nargin < 2 || ~isstruct(schema)
                [active_ic_type, schema] = app.resolve_active_ic_type();
            else
                active_ic_type = app.to_text(app.pick_field(schema, {'ic_type'}, 'stretched_gaussian'), 'stretched_gaussian');
            end
            if nargin < 2 || isempty(active_ic_type)
                [active_ic_type, schema] = app.resolve_active_ic_type();
            end

            shared = app.collect_normalized_ic_shared_values(schema);
            dyn_vals = app.read_ic_dynamic_values_from_schema(schema);
            legacy_coeff = app.legacy_coeff_vector_from_dynamic(schema, dyn_vals);
            arrangement = char(string(app.pick_field(shared, {'arrangement', 'pattern'}, 'single')));
            ic_state = struct( ...
                'ic_type', active_ic_type, ...
                'ic_pattern', arrangement, ...
                'ic_arrangement', arrangement, ...
                'ic_count', shared.count, ...
                'ic_scale', double(shared.scale), ...
                'ic_amplitude', double(shared.amplitude), ...
                'ic_center_x', double(shared.center_x), ...
                'ic_center_y', double(shared.center_y), ...
                'ic_dynamic_values', dyn_vals, ...
                'ic_coeff1', legacy_coeff(1), ...
                'ic_coeff2', legacy_coeff(2), ...
                'ic_coeff3', legacy_coeff(3), ...
                'ic_coeff4', legacy_coeff(4));
        end

        function apply_imported_ic_shared_state(app, cfg)
            if ~isstruct(cfg)
                return;
            end

            defaults = app.get_ic_shared_defaults();
            shared = struct( ...
                'center_x', double(app.pick_field(cfg, {'ic_center_x'}, defaults.center_x)), ...
                'center_y', double(app.pick_field(cfg, {'ic_center_y'}, defaults.center_y)), ...
                'scale', double(app.pick_field(cfg, {'ic_scale'}, defaults.scale)), ...
                'count', max(1, round(double(app.pick_field(cfg, {'ic_count'}, defaults.count)))), ...
                'amplitude', double(app.pick_field(cfg, {'ic_amplitude'}, defaults.amplitude)));

            if isfield(cfg, 'ic_arrangement') && ~isempty(cfg.ic_arrangement)
                shared.arrangement = char(string(cfg.ic_arrangement));
            elseif isfield(cfg, 'ic_pattern') && ~isempty(cfg.ic_pattern)
                shared.arrangement = char(string(cfg.ic_pattern));
            elseif isfield(app.config, 'ic_arrangement') && ~isempty(app.config.ic_arrangement)
                shared.arrangement = char(string(app.config.ic_arrangement));
            end

            app.config.ic_center_x = shared.center_x;
            app.config.ic_center_y = shared.center_y;
            app.config.ic_scale = shared.scale;
            app.config.ic_count = shared.count;
            app.config.ic_amplitude = shared.amplitude;
            app.apply_shared_values(shared);
        end

        function apply_shared_values(app, shared)
            if ~isstruct(shared)
                return;
            end
            if isfield(shared, 'center_x') && app.has_valid_handle('ic_center_x')
                app.handles.ic_center_x.Value = shared.center_x;
            end
            if isfield(shared, 'center_y') && app.has_valid_handle('ic_center_y')
                app.handles.ic_center_y.Value = shared.center_y;
            end
            if isfield(shared, 'scale') && app.has_valid_handle('ic_scale')
                app.handles.ic_scale.Value = max(shared.scale, 0.01);
            end
            if isfield(shared, 'count') && app.has_valid_handle('ic_count')
                app.handles.ic_count.Value = max(1, round(shared.count));
            end
            if isfield(shared, 'amplitude') && app.has_valid_handle('ic_amplitude')
                app.handles.ic_amplitude.Value = max(shared.amplitude, 0.01);
            end
            req = '';
            if isfield(shared, 'arrangement')
                req = char(string(shared.arrangement));
            elseif isfield(shared, 'pattern')
                req = char(string(shared.pattern));
            end
            if ~isempty(req)
                entry = app.find_ic_arrangement_entry(req);
                app.config.ic_arrangement = entry.id;
                app.config.ic_pattern = entry.id;
            end
        end

        function apply_ic_shared_visibility(app, flags, scenario_entry)
            if ~isstruct(flags)
                flags = struct('show_position', true, 'show_scale', true, ...
                    'show_count', false, 'show_pattern', false, 'show_amplitude', false);
            end
            if nargin < 3 || ~isstruct(scenario_entry)
                scenario_entry = struct();
            end

            pos_vis = app.on_off(isfield(flags, 'show_position') && flags.show_position);
            scale_vis = app.on_off(isfield(flags, 'show_scale') && flags.show_scale);
            show_count = isfield(flags, 'show_count') && flags.show_count;
            if isfield(scenario_entry, 'shared_overrides') && isstruct(scenario_entry.shared_overrides) && ...
                    isfield(scenario_entry.shared_overrides, 'count')
                show_count = true;
            end
            count_vis = app.on_off(show_count);
            amp_vis = app.on_off(isfield(flags, 'show_amplitude') && flags.show_amplitude);

            app.set_optional_handle_property('ic_center_x_label', 'Visible', pos_vis);
            app.set_optional_handle_property('ic_center_x', 'Visible', pos_vis);
            app.set_optional_handle_property('ic_center_y_label', 'Visible', pos_vis);
            app.set_optional_handle_property('ic_center_y', 'Visible', pos_vis);

            app.set_optional_handle_property('ic_scale_label', 'Visible', scale_vis);
            app.set_optional_handle_property('ic_scale', 'Visible', scale_vis);

            app.set_optional_handle_property('ic_count_label', 'Visible', count_vis);
            app.set_optional_handle_property('ic_count', 'Visible', count_vis);

            app.set_optional_handle_property('ic_amplitude_label', 'Visible', amp_vis);
            app.set_optional_handle_property('ic_amplitude', 'Visible', amp_vis);

            app.set_optional_handle_enable('ic_count', app.on_off(strcmp(count_vis, 'on')));
        end

        function update_ic_arrangement_control_state(app, schema, ~)
            supports_multi = isfield(schema, 'supports_multi_vortex') && logical(schema.supports_multi_vortex);
            app.set_optional_handle_enable('btn_multi_vortex_settings', app.on_off(supports_multi));
            if app.has_valid_handle('btn_multi_vortex_settings')
                if supports_multi
                    app.handles.btn_multi_vortex_settings.Text = 'Open Editor';
                else
                    app.handles.btn_multi_vortex_settings.Text = 'Unavailable';
                end
            end
        end

        function update_ic_context_state(~, ~, ~)
            % Scenario context widgets were removed from the compact IC panel.
        end

        function on_ic_shared_control_changed(app)
            scenario_name = app.pick_field(app.config, {'ic_scenario'}, 'Manual');
            if ~strcmpi(char(string(scenario_name)), 'Manual')
                app.update_ic_fields();
            end
            app.update_ic_preview();
        end

        function on_ic_count_changed(app)
            [~, schema, scenario_entry] = app.resolve_active_ic_type();
            if ~strcmpi(app.pick_field(scenario_entry, {'scenario_name'}, 'Manual'), 'Manual')
                app.update_ic_fields();
                [~, schema, scenario_entry] = app.resolve_active_ic_type();
            end
            app.update_ic_arrangement_control_state(schema, scenario_entry);
            app.update_ic_preview();
        end

        function build_ic_dynamic_controls(app, schema, scenario_entry, shared_seed)
            if ~app.has_valid_handle('ic_dynamic_box')
                return;
            end
            if nargin < 3 || ~isstruct(scenario_entry)
                scenario_entry = struct();
            end
            if nargin < 4 || ~isstruct(shared_seed)
                shared_seed = struct();
            end
            defaults = struct('ic_center_x', 0.0, 'ic_center_y', 0.0, 'ic_scale', 1.0, ...
                'ic_count', 1, 'ic_amplitude', 1.0);
            if isfield(app.layout_cfg, 'ui_defaults') && isstruct(app.layout_cfg.ui_defaults)
                defaults = app.layout_cfg.ui_defaults;
            end
            box = app.handles.ic_dynamic_box;
            if ~isempty(box.Children)
                delete(box.Children);
            end

            flags = struct('show_position', true, 'show_scale', true, ...
                'show_count', false, 'show_pattern', false, 'show_amplitude', false);
            if isfield(schema, 'shared_flags') && isstruct(schema.shared_flags)
                flags = schema.shared_flags;
            end
            show_position = isfield(flags, 'show_position') && flags.show_position;
            show_scale = isfield(flags, 'show_scale') && flags.show_scale;
            show_count = isfield(flags, 'show_count') && flags.show_count;
            if isfield(scenario_entry, 'shared_overrides') && isstruct(scenario_entry.shared_overrides) && ...
                    isfield(scenario_entry.shared_overrides, 'count')
                show_count = true;
            end
            show_amplitude = isfield(flags, 'show_amplitude') && flags.show_amplitude;

            shared_specs = {};
            if show_position
                shared_specs{end + 1} = struct('label_handle', 'ic_center_x_label', 'input_handle', 'ic_center_x', ... %#ok<AGROW>
                    'label', 'Position x0', 'value_key', 'center_x', 'default', defaults.ic_center_x, ...
                    'limits', [], 'integer', false, 'callback', @(~,~) app.on_ic_shared_control_changed());
                shared_specs{end + 1} = struct('label_handle', 'ic_center_y_label', 'input_handle', 'ic_center_y', ... %#ok<AGROW>
                    'label', 'Position y0', 'value_key', 'center_y', 'default', defaults.ic_center_y, ...
                    'limits', [], 'integer', false, 'callback', @(~,~) app.on_ic_shared_control_changed());
            end
            if show_scale
                shared_specs{end + 1} = struct('label_handle', 'ic_scale_label', 'input_handle', 'ic_scale', ... %#ok<AGROW>
                    'label', 'Scale', 'value_key', 'scale', 'default', defaults.ic_scale, ...
                    'limits', [0.01 100.0], 'integer', false, 'callback', @(~,~) app.on_ic_shared_control_changed());
            end
            if show_count
                shared_specs{end + 1} = struct('label_handle', 'ic_count_label', 'input_handle', 'ic_count', ... %#ok<AGROW>
                    'label', 'Count (N)', 'value_key', 'count', 'default', defaults.ic_count, ...
                    'limits', [1 50], 'integer', true, 'callback', @(~,~) app.on_ic_count_changed());
            end
            if show_amplitude
                shared_specs{end + 1} = struct('label_handle', 'ic_amplitude_label', 'input_handle', 'ic_amplitude', ... %#ok<AGROW>
                    'label', 'Amplitude', 'value_key', 'amplitude', 'default', defaults.ic_amplitude, ...
                    'limits', [0.01 100.0], 'integer', false, 'callback', @(~,~) app.on_ic_shared_control_changed());
            end

            n_fields = 0;
            if isfield(schema, 'dynamic_fields')
                n_fields = numel(schema.dynamic_fields);
            end
            total_controls = numel(shared_specs) + n_fields;
            n_rows = max(1, ceil(total_controls / 4));
            grid = uigridlayout(box, [n_rows, 12]);
            grid.ColumnWidth = {86, '1x', '1x', 86, '1x', '1x', 86, '1x', '1x', 86, '1x', '1x'};
            grid.RowHeight = repmat({'fit'}, 1, n_rows);
            grid.Padding = [0 0 0 0];
            grid.RowSpacing = 5;
            grid.ColumnSpacing = 6;

            inputs = struct();
            labels = struct();
            C = app.layout_cfg.colors;
            app.handles.ic_center_x_label = [];
            app.handles.ic_center_x = [];
            app.handles.ic_center_y_label = [];
            app.handles.ic_center_y = [];
            app.handles.ic_scale_label = [];
            app.handles.ic_scale = [];
            app.handles.ic_count_label = [];
            app.handles.ic_count = [];
            app.handles.ic_amplitude_label = [];
            app.handles.ic_amplitude = [];

            if total_controls == 0
                empty_lbl = uilabel(grid, ...
                    'Text', 'No conditional settings are required for the active initial condition.', ...
                    'FontColor', C.fg_muted, 'FontSize', 11, 'HorizontalAlignment', 'left');
                empty_lbl.Layout.Row = 1;
                empty_lbl.Layout.Column = [1 12];
                if isprop(empty_lbl, 'WordWrap')
                    empty_lbl.WordWrap = 'on';
                end
                app.handles.ic_dynamic_grid = grid;
                app.handles.ic_dynamic_inputs = inputs;
                app.handles.ic_dynamic_labels = labels;
                return;
            end

            for i = 1:numel(shared_specs)
                spec = shared_specs{i};
                row = ceil(i / 4);
                slot = mod(i - 1, 4);
                base_col = slot * 3 + 1;
                lbl = uilabel(grid, 'Text', spec.label, ...
                    'FontColor', C.fg_text, 'FontSize', 11, 'HorizontalAlignment', 'right');
                lbl.Layout.Row = row;
                lbl.Layout.Column = base_col;
                if isprop(lbl, 'WordWrap')
                    lbl.WordWrap = 'on';
                end

                seed_val = spec.default;
                if isfield(shared_seed, spec.value_key)
                    seed_val = shared_seed.(spec.value_key);
                end
                input = uieditfield(grid, 'numeric', ...
                    'Value', double(seed_val), ...
                    'ValueChangedFcn', spec.callback);
                if ~isempty(spec.limits)
                    input.Limits = double(spec.limits(:)).';
                end
                if spec.integer && isprop(input, 'RoundFractionalValues')
                    input.RoundFractionalValues = 'on';
                end
                input.Layout.Row = row;
                input.Layout.Column = [base_col + 1, base_col + 2];

                app.handles.(spec.label_handle) = lbl;
                app.handles.(spec.input_handle) = input;
            end

            for i = 1:n_fields
                f = schema.dynamic_fields(i);
                control_idx = numel(shared_specs) + i;
                row = ceil(control_idx / 4);
                slot = mod(control_idx - 1, 4);
                base_col = slot * 3 + 1;
                lbl = uilabel(grid, 'Text', f.label, ...
                    'FontColor', C.fg_text, 'FontSize', 11, 'HorizontalAlignment', 'right');
                lbl.Layout.Row = row;
                lbl.Layout.Column = base_col;
                if isprop(lbl, 'WordWrap')
                    lbl.WordWrap = 'on';
                end
                if isfield(f, 'tooltip') && isprop(lbl, 'Tooltip')
                    lbl.Tooltip = char(string(f.tooltip));
                end

                input = uieditfield(grid, 'numeric', ...
                    'Value', double(f.default), ...
                    'ValueChangedFcn', @(~,~) app.on_ic_dynamic_control_changed());
                if isfield(f, 'limits') && isnumeric(f.limits) && numel(f.limits) == 2
                    input.Limits = double(f.limits(:)).';
                end
                if isfield(f, 'is_integer') && logical(f.is_integer) && isprop(input, 'RoundFractionalValues')
                    input.RoundFractionalValues = 'on';
                end
                if isfield(f, 'tooltip') && isprop(input, 'Tooltip')
                    input.Tooltip = char(string(f.tooltip));
                end
                input.Layout.Row = row;
                input.Layout.Column = [base_col + 1, base_col + 2];

                labels.(f.id) = lbl;
                inputs.(f.id) = input;
            end

            app.handles.ic_dynamic_grid = grid;
            app.handles.ic_dynamic_inputs = inputs;
            app.handles.ic_dynamic_labels = labels;
        end

        function apply_scenario_overrides(app, ic_type, scenario_entry, schema)
            if ~isstruct(scenario_entry)
                return;
            end

            if isfield(scenario_entry, 'shared_overrides') && isstruct(scenario_entry.shared_overrides)
                shared = app.read_ic_shared_values();
                fns = fieldnames(scenario_entry.shared_overrides);
                for i = 1:numel(fns)
                    shared.(fns{i}) = scenario_entry.shared_overrides.(fns{i});
                end
                app.apply_shared_values(shared);
            end

            if isfield(scenario_entry, 'dynamic_overrides') && isstruct(scenario_entry.dynamic_overrides)
                dyn = app.read_ic_dynamic_values_from_schema(schema);
                fns = fieldnames(scenario_entry.dynamic_overrides);
                for i = 1:numel(fns)
                    dyn.(fns{i}) = scenario_entry.dynamic_overrides.(fns{i});
                end
                app.write_ic_dynamic_values(schema, dyn);
            end
            if isfield(scenario_entry, 'runtime_overrides') && isstruct(scenario_entry.runtime_overrides) && ...
                    isfield(scenario_entry.runtime_overrides, 'nu')
                nu_value = double(scenario_entry.runtime_overrides.nu);
                if isfinite(nu_value) && nu_value > 0
                    app.config.nu = nu_value;
                    if app.has_valid_handle('nu') && isprop(app.handles.nu, 'Value')
                        try
                            app.handles.nu.Value = nu_value;
                        catch
                        end
                    end
                end
            end
            if ~isfield(scenario_entry, 'scenario_name') || ...
                    strcmpi(char(string(scenario_entry.scenario_name)), 'Manual')
                return;
            end
            if ~(isfield(schema, 'supports_multi_vortex') && logical(schema.supports_multi_vortex))
                app.config.ic_multi_vortex_experimental = false;
                return;
            end

            rows = app.build_scenario_multi_vortex_rows(ic_type, schema, scenario_entry);
            if isempty(rows)
                app.config.ic_multi_vortex_experimental = false;
                return;
            end
            app.config.ic_multi_vortex_rows = rows;
            app.config.ic_multi_vortex_experimental = true;
        end

        function rows = build_scenario_multi_vortex_rows(app, ic_type, schema, scenario_entry)
            rows = struct([]);
            if ~isstruct(scenario_entry)
                return;
            end

            shared = app.read_ic_shared_values();
            dyn = app.read_ic_dynamic_values_from_schema(schema);
            count = max(1, round(app.pick_field(shared, {'count'}, 1)));
            rows = repmat(app.default_multi_vortex_row(ic_type, 1), count, 1);
            for i = 1:count
                row = app.default_multi_vortex_row(ic_type, i);
                row.center_x = app.pick_field(shared, {'center_x'}, row.center_x);
                row.center_y = app.pick_field(shared, {'center_y'}, row.center_y);
                row.scale = max(1.0e-6, app.pick_field(shared, {'scale'}, row.scale));
                row.amplitude = max(1.0e-6, app.pick_field(shared, {'amplitude'}, row.amplitude));
                row.dynamic_values = dyn;
                rows(i) = row;
            end

            charge_pattern = app.pick_field(scenario_entry, {'charge_pattern'}, 'uniform_positive');
            rows = app.apply_multi_vortex_charge_pattern(rows, charge_pattern);
            rows = app.apply_multi_vortex_arrangement(rows, app.pick_field(shared, {'arrangement', 'pattern'}, 'single'), ...
                app.pick_field(shared, {'center_x'}, 0.0), app.pick_field(shared, {'center_y'}, 0.0));
        end

        function rows = apply_multi_vortex_charge_pattern(~, rows, charge_pattern)
            rows = rows(:);
            pattern = lower(char(string(charge_pattern)));
            switch pattern
                case 'alternating_opposed'
                    for i = 1:numel(rows)
                        rows(i).charge = 1.0;
                        if mod(i, 2) == 0
                            rows(i).charge = -1.0;
                        end
                    end
                otherwise
                    for i = 1:numel(rows)
                        rows(i).charge = 1.0;
                    end
            end
        end

        function rows = apply_multi_vortex_arrangement(app, rows, arrangement, anchor_x, anchor_y)
            rows = app.normalize_multi_vortex_rows(rows, 'stretched_gaussian');
            if isempty(rows)
                return;
            end
            enabled_mask = [rows.enabled];
            if ~any(enabled_mask)
                enabled_mask = true(size(enabled_mask));
            end
            enabled_idx = find(enabled_mask);
            n_enabled = numel(enabled_idx);
            arrangement_entry = app.find_ic_arrangement_entry(arrangement);
            arrangement_id = arrangement_entry.id;
            if strcmpi(arrangement_id, 'single') && n_enabled > 1
                return;
            end

            Lx = 10.0;
            Ly = 10.0;
            if app.has_valid_handle('Lx')
                Lx = max(1.0e-6, double(app.handles.Lx.Value));
            end
            if app.has_valid_handle('Ly')
                Ly = max(1.0e-6, double(app.handles.Ly.Value));
            end
            [centers_x, centers_y] = app.build_vortex_centers(n_enabled, arrangement_id, Lx, Ly, anchor_x, anchor_y);
            if numel(centers_x) ~= n_enabled || numel(centers_y) ~= n_enabled
                error('UIController:InvalidMultiVortexArrangement', ...
                    'Arrangement "%s" produced %d centers for %d active rows.', ...
                    arrangement_id, min(numel(centers_x), numel(centers_y)), n_enabled);
            end
            for i = 1:n_enabled
                rows(enabled_idx(i)).center_x = centers_x(i);
                rows(enabled_idx(i)).center_y = centers_y(i);
            end
        end

        function on_ic_dynamic_control_changed(app)
            scenario_name = app.pick_field(app.config, {'ic_scenario'}, 'Manual');
            if ~strcmpi(char(string(scenario_name)), 'Manual')
                app.update_ic_fields();
            end
            app.update_ic_preview();
        end

        function image_path = render_equation_image(app, ic_name, eq_tex)
            % Render equation as themed PNG so mathematical symbols display consistently.
            cache_root = fullfile(tempdir, 'tsunami_ui_equations');
            if ~exist(cache_root, 'dir')
                mkdir(cache_root);
            end

            key = app.stable_text_hash("renderer_v2|" + string(ic_name) + "|" + string(eq_tex));
            stem = "ic_eq_" + key;
            image_path = fullfile(cache_root, char(stem + ".png"));
            md_path = fullfile(cache_root, char(stem + ".md"));

            app.write_equation_markdown_source(md_path, ic_name, eq_tex);
            if isfile(image_path)
                return;
            end

            bg = app.layout_cfg.colors.bg_input;
            fg = app.layout_cfg.colors.fg_text;
            header = app.layout_cfg.colors.accent_cyan;

            % Create completely hidden figure for equation rendering
            fig = figure('Visible', 'off', ...
                'HandleVisibility', 'off', ...  % Prevents figure from appearing in findall() and figure list
                'Color', bg, ...
                'MenuBar', 'none', ...
                'ToolBar', 'none', ...
                'Units', 'pixels', ...
                'Position', [100 100 1280 220]);
            cleanup_obj = onCleanup(@() app.close_hidden_figure(fig)); %#ok<NASGU>

            ax = axes('Parent', fig, ...
                'Position', [0 0 1 1], ...
                'Visible', 'off', ...
                'Color', bg);
            axis(ax, [0 1 0 1]);
            axis(ax, 'off');

            title_str = "Initial Condition Equation - " + string(ic_name);
            eq_latex = app.normalize_equation_for_latex(eq_tex);
            plain_eq = app.equation_tex_to_plain(eq_tex);

            try
                text(ax, 0.015, 0.88, title_str, ...
                    'Interpreter', 'none', ...
                    'Color', header, ...
                    'FontWeight', 'bold', ...
                    'FontSize', 13, ...
                    'VerticalAlignment', 'top');

                text(ax, 0.02, 0.42, "$\displaystyle " + string(eq_latex) + "$", ...
                    'Interpreter', 'latex', ...
                    'Color', fg, ...
                    'FontSize', 24, ...
                    'VerticalAlignment', 'middle', ...
                    'Clipping', 'on');

                drawnow;
                exportgraphics(ax, image_path, 'Resolution', 170, 'BackgroundColor', bg);
            catch ME
                UIController.warn_once('UIController:EquationLatexRenderFailed', ...
                    'LaTeX equation rendering failed; using plain-text equation fallback: %s', ME.message);
                cla(ax);
                axis(ax, [0 1 0 1]);
                axis(ax, 'off');
                text(ax, 0.015, 0.88, title_str, ...
                    'Interpreter', 'none', ...
                    'Color', header, ...
                    'FontWeight', 'bold', ...
                    'FontSize', 13, ...
                    'VerticalAlignment', 'top');
                text(ax, 0.02, 0.42, string(plain_eq), ...
                    'Interpreter', 'none', ...
                    'Color', fg, ...
                    'FontName', 'Consolas', ...
                    'FontSize', 15, ...
                    'VerticalAlignment', 'middle', ...
                    'Clipping', 'on');
                drawnow;
                exportgraphics(ax, image_path, 'Resolution', 170, 'BackgroundColor', bg);
            end
        end

        function write_equation_markdown_source(~, md_path, ic_name, eq_tex)
            % Persist markdown source used for equation-image rendering.
            if isfile(md_path)
                return;
            end
            lines = {
                '# UI Equation Source'
                ''
                ['IC: ', char(string(ic_name))]
                ''
                '$$'
                char(string(eq_tex))
                '$$'
                ''
            };
            fid = fopen(md_path, 'w');
            if fid < 0
                return;
            end
            cleanup_obj = onCleanup(@() fclose(fid)); %#ok<NASGU>
            fprintf(fid, '%s\n', lines{:});
        end

        function close_hidden_figure(~, fig_handle)
            if isempty(fig_handle)
                return;
            end
            try
                if isvalid(fig_handle)
                    close(fig_handle);
                end
            catch ME
                UIController.warn_once('UIController:HiddenFigureCloseFailed', ...
                    'Hidden figure close failed during equation rendering cleanup: %s', ME.message);
            end
        end

        function eq_out = normalize_equation_for_latex(~, eq_tex)
            % Convert unsupported TeX fragments to MATLAB-LaTeX-safe form.
            eq_out = char(string(eq_tex));
            eq_out = strrep(eq_out, '\begin{cases}', '(');
            eq_out = strrep(eq_out, '\end{cases}', ')');
            eq_out = strrep(eq_out, '\\', '; ');
            eq_out = strrep(eq_out, '&', ' ');
            eq_out = strrep(eq_out, '\left', '');
            eq_out = strrep(eq_out, '\right', '');
            eq_out = regexprep(eq_out, '\s+', ' ');
            eq_out = strtrim(eq_out);
        end

        function eq_out = normalize_equation_for_mathjax(~, eq_tex)
            % Normalize delimiters so render_math_html can wrap equation safely once.
            eq_out = strtrim(char(string(eq_tex)));
            if strlength(string(eq_out)) >= 4 && startsWith(eq_out, '$$') && endsWith(eq_out, '$$')
                eq_out = eq_out(3:end-2);
            elseif strlength(string(eq_out)) >= 2 && startsWith(eq_out, '$') && endsWith(eq_out, '$')
                eq_out = eq_out(2:end-1);
            elseif strlength(string(eq_out)) >= 4 && startsWith(eq_out, '\(') && endsWith(eq_out, '\)')
                eq_out = eq_out(3:end-2);
            elseif strlength(string(eq_out)) >= 4 && startsWith(eq_out, '\[') && endsWith(eq_out, '\]')
                eq_out = eq_out(3:end-2);
            end
            eq_out = strtrim(eq_out);
        end

        function key = stable_text_hash(~, txt)
            raw = char(string(txt));
            if isempty(raw)
                key = "00000000";
                return;
            end
            idx = 1:numel(raw);
            bytes = double(raw);
            h = uint32(2166136261);
            for k = 1:numel(bytes)
                h = bitxor(h, uint32(bytes(k)));
                h = uint32(mod(double(h) * 16777619 + idx(k), 2^32));
            end
            key = string(dec2hex(h, 8));
        end

        function tf = supports_equation_image_rendering(~)
            % Equation snapshot rendering is available when hidden figures
            % can be created; this supports both desktop and some headless JVM sessions.
            persistent cached_tf;
            if ~isempty(cached_tf)
                tf = cached_tf;
                return;
            end

            tf = false;
            if usejava('desktop')
                tf = true;
            elseif usejava('jvm')
                fig = [];
                try
                    fig = figure('Visible', 'off', ...
                        'HandleVisibility', 'off', ...
                        'MenuBar', 'none', ...
                        'ToolBar', 'none');
                    tf = ~isempty(fig) && isvalid(fig);
                catch
                    tf = false;
                end
                if ~isempty(fig)
                    try
                        if isvalid(fig)
                            close(fig);
                        end
                    catch
                    end
                end
            end
            cached_tf = tf;
        end

        function render_where_axes(app, where_entries)
            if ~app.has_valid_handle('ic_where_axes')
                return;
            end
            ax = app.handles.ic_where_axes;
            cla(ax);
            axis(ax, 'off');
            xlim(ax, [0 1]);

            line_items = {};
            if isstruct(where_entries) && ~isempty(where_entries)
                for i = 1:numel(where_entries)
                    entry = where_entries(i);
                    symbol_tex = 'x';
                    name_txt = 'parameter';
                    range_txt = 'problem dependent';
                    effect_txt = '';
                    outcome_txt = '';
                    if isfield(entry, 'symbol_tex'), symbol_tex = char(string(entry.symbol_tex)); end
                    if isfield(entry, 'name'), name_txt = char(string(entry.name)); end
                    if isfield(entry, 'range_tex'), range_txt = char(string(entry.range_tex)); end
                    if isfield(entry, 'effect_text'), effect_txt = char(string(entry.effect_text)); end
                    if isfield(entry, 'outcome_text'), outcome_txt = char(string(entry.outcome_text)); end
                    line_items{end + 1} = sprintf('$%s$: %s', symbol_tex, name_txt); %#ok<AGROW>
                    line_items{end + 1} = sprintf('Range: $%s$', range_txt); %#ok<AGROW>
                    line_items{end + 1} = sprintf('Effect: %s', effect_txt); %#ok<AGROW>
                    line_items{end + 1} = sprintf('Outcome: %s', outcome_txt); %#ok<AGROW>
                    line_items{end + 1} = ''; %#ok<AGROW>
                end
            else
                lines = string(where_entries);
                for i = 1:numel(lines)
                    line_txt = strtrim(char(lines(i)));
                    if ~isempty(line_txt)
                        line_items{end + 1} = line_txt; %#ok<AGROW>
                    end
                end
            end
            if isempty(line_items)
                line_items = {'No variable notes provided.'};
            end

            y_top = numel(line_items) + 1;
            ylim(ax, [0 y_top + 1]);
            for i = 1:numel(line_items)
                line_txt = char(string(line_items{i}));
                if isempty(strtrim(line_txt))
                    continue;
                end
                use_latex = contains(line_txt, '$');
                interp_mode = 'none';
                if use_latex
                    interp_mode = 'latex';
                end
                text(ax, 0.02, y_top - i, line_txt, ...
                    'Interpreter', interp_mode, ...
                    'Color', app.layout_cfg.colors.fg_text, ...
                    'FontSize', 10, ...
                    'HorizontalAlignment', 'left', ...
                    'VerticalAlignment', 'top');
            end
        end

        function html = render_where_html(app, where_entries)
            % Offline HTML fallback; avoids remote script dependencies.
            entry_html = "";
            if isstruct(where_entries) && ~isempty(where_entries)
                for i = 1:numel(where_entries)
                    entry = where_entries(i);
                    symbol_tex = 'x';
                    name_txt = 'parameter';
                    range_txt = 'problem dependent';
                    effect_txt = '';
                    outcome_txt = '';
                    if isfield(entry, 'symbol_tex'), symbol_tex = char(string(entry.symbol_tex)); end
                    if isfield(entry, 'name'), name_txt = char(string(entry.name)); end
                    if isfield(entry, 'range_tex'), range_txt = char(string(entry.range_tex)); end
                    if isfield(entry, 'effect_text'), effect_txt = char(string(entry.effect_text)); end
                    if isfield(entry, 'outcome_text'), outcome_txt = char(string(entry.outcome_text)); end
                    entry_html = entry_html + ...
                        "<div style='padding:8px 0 9px 0;border-bottom:1px solid #25303c;'>" + ...
                        "<div style='font-size:12px;color:#ffffff;line-height:1.3;'><span style=""color:#8ad7ff;font-weight:700;"">" + ...
                        string(app.escape_html_text(symbol_tex)) + "</span> : " + string(app.escape_html_text(name_txt)) + "</div>" + ...
                        "<div style='font-size:10px;color:#9fb2c4;line-height:1.35;margin-top:3px;'><strong>Range</strong>: " + ...
                        string(app.escape_html_text(range_txt)) + "</div>" + ...
                        "<div style='font-size:10px;color:#d6dde8;line-height:1.35;margin-top:3px;'><strong>Effect</strong>: " + ...
                        string(app.escape_html_text(effect_txt)) + "</div>" + ...
                        "<div style='font-size:10px;color:#c8d3df;line-height:1.35;margin-top:3px;'><strong>Outcome</strong>: " + ...
                        string(app.escape_html_text(outcome_txt)) + "</div>" + ...
                        "</div>";
                end
            else
                lines = string(where_entries);
                for i = 1:numel(lines)
                    line_txt = strtrim(lines(i));
                    if strlength(line_txt) == 0
                        continue;
                    end
                    entry_html = entry_html + "<div style='padding:6px 0;line-height:1.35;'>" + ...
                        string(app.escape_html_text(char(line_txt))) + "</div>";
                end
            end
            if strlength(entry_html) == 0
                entry_html = "<div style='font-size:11px;color:#9fb2c4;'>No variable notes provided.</div>";
            end

            html = char( ...
                "<html><head><meta charset='utf-8'></head>" + ...
                "<body style='margin:0;background:#161a20;color:#d6dde8;font-family:Segoe UI,Arial,sans-serif;height:100%;'>" + ...
                "<div style='height:100%;padding:8px 9px;border:1px solid #2a3340;border-radius:8px;box-sizing:border-box;overflow-y:auto;'>" + ...
                "<div style='color:#8ad7ff;font-weight:700;font-size:12px;margin:0 0 6px 0;'>where:</div>" + ...
                "<div style='font-size:11px;line-height:1.35;white-space:normal;overflow-wrap:anywhere;word-break:break-word;'>" + ...
                entry_html + "</div>" + ...
                "</div></body></html>");
        end

