        function generate_report_to_tab(app)
            % Build Plotly.js interactive report and show in the Report tab.
            if ~app.has_valid_handle('report_html')
                return;
            end
            try
                payload = app.build_report_payload();
                html    = app.build_report_html(payload);
                app.handles.report_html.HTMLSource = html;
                app.report_html_cache = html;
                app.set_optional_handle_property('report_export_btn', 'Enable', 'on');
                app.set_optional_handle_property('report_browser_btn', 'Enable', 'on');
                app.append_to_terminal('Interactive report generated.', 'success');
            catch ex
                app.append_to_terminal(['Report generation failed: ' ex.message], 'error');
            end
        end

        function open_report_in_browser(app)
            % Save report to a temp file and open in the system default browser.
            if isempty(app.report_html_cache)
                app.append_to_terminal('Generate a report first.', 'warning');
                return;
            end
            tmp = fullfile(tempdir, 'tsunami_report_preview.html');
            fid = fopen(tmp, 'w', 'n', 'UTF-8');
            if fid == -1
                app.append_to_terminal('Cannot write temp report file.', 'error');
                return;
            end
            fwrite(fid, app.report_html_cache, 'char');
            fclose(fid);
            web(tmp, '-browser');
            app.append_to_terminal(['Report opened in browser: ' tmp], 'info');
        end

        function export_report_html(app)
            % Save the cached report HTML to a user-chosen file.
            if isempty(app.report_html_cache)
                app.append_to_terminal('No report to export. Generate one first.', 'warning');
                return;
            end
            [file, path] = uiputfile({'*.html', 'HTML files'}, 'Save Report');
            if isequal(file, 0); return; end
            fid = fopen(fullfile(path, file), 'w', 'n', 'UTF-8');
            if fid == -1
                app.append_to_terminal('Failed to write report file.', 'error');
                return;
            end
            fwrite(fid, app.report_html_cache, 'char');
            fclose(fid);
            app.append_to_terminal(['Report exported to ' fullfile(path, file)], 'info');
        end

        function payload = build_report_payload(app)
            % Assemble payload from selected run entry for multi-run sessions.
            payload = struct();
            payload.title = 'Tsunami Vortex Simulation Report';
            payload.generated_at = char(datetime('now', 'Format', 'yyyy-MM-dd HH:mm:ss'));

            [idx, entry] = app.get_selected_session_result();
            has_entry = ~isempty(idx) && isstruct(entry) && ~isempty(fieldnames(entry));

            cfg_source = struct();
            run_cfg = struct();
            meta = struct();
            monitor_src = struct();
            artifacts = struct();

            if has_entry
                if isfield(entry, 'parameters') && isstruct(entry.parameters)
                    cfg_source = entry.parameters;
                end
                if isfield(entry, 'run_config') && isstruct(entry.run_config)
                    run_cfg = entry.run_config;
                end
                if isfield(entry, 'metadata') && isstruct(entry.metadata)
                    meta = entry.metadata;
                end
                if isfield(entry, 'monitor_series') && isstruct(entry.monitor_series)
                    monitor_src = entry.monitor_series;
                end
                if isfield(entry, 'artifacts') && isstruct(entry.artifacts)
                    artifacts = entry.artifacts;
                end
            end

            if isempty(fieldnames(cfg_source)) && isprop(app, 'config') && isstruct(app.config)
                cfg_source = app.config;
            end
            if isempty(fieldnames(monitor_src)) && isfield(app.handles, 'monitor_live_state') && ...
                    isstruct(app.handles.monitor_live_state)
                monitor_src = app.handles.monitor_live_state;
            end

            % Run identifier
            payload.run_id = '';
            if isfield(meta, 'run_id') && ~isempty(meta.run_id)
                payload.run_id = char(string(meta.run_id));
            elseif isfield(run_cfg, 'run_id') && ~isempty(run_cfg.run_id)
                payload.run_id = char(string(run_cfg.run_id));
            elseif isfield(cfg_source, 'run_id') && ~isempty(cfg_source.run_id)
                payload.run_id = char(string(cfg_source.run_id));
            end

            % Scalar/string config fields only (skip nested structs / large arrays)
            cfg = struct();
            if isstruct(cfg_source) && ~isempty(fieldnames(cfg_source))
                fn = fieldnames(cfg_source);
                for k = 1:numel(fn)
                    v = cfg_source.(fn{k});
                    if (isnumeric(v) && numel(v) <= 20) || islogical(v) || ischar(v) || isstring(v)
                        cfg.(fn{k}) = v;
                    end
                end
            end
            payload.configuration = cfg;

            % Solver label
            payload.solver = '';
            if isfield(meta, 'method') && ~isempty(meta.method)
                payload.solver = app.to_text(meta.method, '');
            elseif isfield(run_cfg, 'method') && ~isempty(run_cfg.method)
                payload.solver = app.to_text(run_cfg.method, '');
            elseif isfield(cfg_source, 'analysis_method') && ~isempty(cfg_source.analysis_method)
                payload.solver = app.to_text(cfg_source.analysis_method, '');
            elseif isfield(cfg_source, 'solver_method') && ~isempty(cfg_source.solver_method)
                payload.solver = app.to_text(cfg_source.solver_method, '');
            end

            % Legacy metrics struct (used by old build_report_html fallback only)
            met = struct();
            if isfield(app.handles, 'monitor_metric_labels')
                labels = app.handles.monitor_metric_labels;
                for m = 1:2:numel(labels)
                    try
                        key = matlab.lang.makeValidName(labels(m).Text);
                        met.(key) = labels(m+1).Text;
                    catch ME
                        SafeConsoleIO.warning('UIController:MetricLabelError', ...
                            'Failed to read metric label pair at index %d: %s', m, ME.message);
                    end
                end
            end
            payload.metrics = met;
            cfg_for_report = app.normalize_monitor_cfg(cfg_source);
            resolved_monitor = app.resolve_monitor_series( ...
                struct('results', struct(), 'monitor_series', monitor_src), cfg_for_report);

            payload.monitor = struct();
            payload.monitor.t = app.rowvec(app.pick_field(resolved_monitor, {'t', 'time'}, zeros(1, 0)));
            payload.monitor.max_omega = app.rowvec(app.pick_field(resolved_monitor, {'max_omega', 'max_vorticity'}, zeros(1, 0)));
            payload.monitor.energy = app.rowvec(app.pick_field(resolved_monitor, {'energy_proxy', 'energy', 'kinetic_energy'}, zeros(1, 0)));
            payload.monitor.enstrophy = app.rowvec(app.pick_field(resolved_monitor, {'enstrophy_proxy', 'enstrophy'}, zeros(1, 0)));
            payload.monitor.cpu = app.rowvec(app.pick_field(resolved_monitor, {'cpu_proxy', 'cpu_percent'}, zeros(1, 0)));
            payload.monitor.gpu = app.rowvec(app.pick_field(resolved_monitor, {'gpu_series', 'gpu_usage'}, zeros(1, 0)));
            payload.monitor.cpu_temp_c = app.rowvec(app.pick_field(resolved_monitor, {'cpu_temp_c'}, zeros(1, 0)));
            payload.monitor.power_w = app.rowvec(app.pick_field(resolved_monitor, {'power_w'}, zeros(1, 0)));
            payload.monitor.collector_series = resolved_monitor.collector_series;
            payload.monitor.collector_status = resolved_monitor.collector_status;
            payload.monitor.coverage_domains = resolved_monitor.coverage_domains;
            payload.monitor.preferred_source = resolved_monitor.preferred_source;
            payload.monitor.raw_log_paths = resolved_monitor.raw_log_paths;
            payload.monitor.overlay_metrics = resolved_monitor.overlay_metrics;
            payload.monitor.hwinfo_transport = app.pick_field(resolved_monitor, {'hwinfo_transport'}, 'none');
            payload.monitor.hwinfo_status_reason = app.pick_field(resolved_monitor, {'hwinfo_status_reason'}, '');
            payload.monitor.collector_probe_details = app.pick_field(resolved_monitor, {'collector_probe_details'}, struct('hwinfo', struct(), 'icue', struct()));

            payload.collectors = struct();
            payload.collectors.status = resolved_monitor.collector_status;
            payload.collectors.coverage_domains = resolved_monitor.coverage_domains;
            payload.collectors.preferred_source = resolved_monitor.preferred_source;
            payload.collectors.raw_log_paths = resolved_monitor.raw_log_paths;
            payload.collectors.hwinfo_transport = app.pick_field(resolved_monitor, {'hwinfo_transport'}, 'none');
            payload.collectors.hwinfo_status_reason = app.pick_field(resolved_monitor, {'hwinfo_status_reason'}, '');
            payload.collectors.probe_details = app.pick_field(resolved_monitor, {'collector_probe_details'}, struct('hwinfo', struct(), 'icue', struct()));
            payload.collectors.coverage_rows = ExternalCollectorDispatcher.coverage_rows(resolved_monitor);

            payload.animation_path = '';
            payload.snapshot_paths = {};
            if isfield(artifacts, 'paths') && isstruct(artifacts.paths)
                payload.animation_path = app.pick_latest_animation_path(artifacts.paths);
                payload.snapshot_paths = app.pick_snapshot_paths(artifacts.paths);
            elseif isfield(cfg_source, 'animation_dir') || isfield(cfg_source, 'figures_dir')
                path_stub = struct();
                if isfield(cfg_source, 'animation_dir')
                    path_stub.animation = cfg_source.animation_dir;
                end
                if isfield(cfg_source, 'figures_dir')
                    path_stub.figures = cfg_source.figures_dir;
                end
                payload.animation_path = app.pick_latest_animation_path(path_stub);
                payload.snapshot_paths = app.pick_snapshot_paths(path_stub);
            end
        end

        function anim_path = pick_latest_animation_path(~, paths_struct)
            anim_path = '';
            if ~isstruct(paths_struct)
                return;
            end

            if isfield(paths_struct, 'media_animation_combined')
                combined_dir = char(string(paths_struct.media_animation_combined));
                if isfolder(combined_dir)
                    combined_listing = dir(fullfile(combined_dir, '**', '*.mp4'));
                    if ~isempty(combined_listing)
                        [~, newest_combined] = max([combined_listing.datenum]);
                        anim_path = fullfile(combined_listing(newest_combined).folder, combined_listing(newest_combined).name);
                        return;
                    end
                end
            end

            candidate_files = {};
            fields = fieldnames(paths_struct);
            for k = 1:numel(fields)
                key = fields{k};
                value = paths_struct.(key);
                if ~(ischar(value) || isstring(value))
                    continue;
                end
                path_token = char(string(value));
                if isempty(path_token)
                    continue;
                end
                if isfile(path_token)
                    [~, ~, ext_file] = fileparts(path_token);
                    if strcmpi(ext_file, '.mp4')
                        candidate_files{end + 1} = path_token; %#ok<AGROW>
                    end
                    continue;
                end
                if ~isfolder(path_token)
                    continue;
                end

                key_l = lower(key);
                if ~(contains(key_l, 'animation') || contains(key_l, 'media') || contains(key_l, 'video'))
                    continue;
                end

                files = dir(fullfile(path_token, '**', '*.mp4'));
                for fi = 1:numel(files)
                    candidate_files{end + 1} = fullfile(files(fi).folder, files(fi).name); %#ok<AGROW>
                end
            end

            if isempty(candidate_files)
                for k = 1:numel(fields)
                    value = paths_struct.(fields{k});
                    if ~(ischar(value) || isstring(value))
                        continue;
                    end
                    path_token = char(string(value));
                    if ~isfolder(path_token)
                        continue;
                    end
                    files = dir(fullfile(path_token, '**', '*.mp4'));
                    for fi = 1:numel(files)
                        candidate_files{end + 1} = fullfile(files(fi).folder, files(fi).name); %#ok<AGROW>
                    end
                end
            end

            if isempty(candidate_files)
                return;
            end
            candidate_files = unique(candidate_files, 'stable');
            timestamps = zeros(1, numel(candidate_files));
            for i = 1:numel(candidate_files)
                info = dir(candidate_files{i});
                if ~isempty(info)
                    timestamps(i) = info.datenum;
                end
            end
            [~, newest] = max(timestamps);
            anim_path = candidate_files{newest};
        end

        function snaps = pick_snapshot_paths(~, paths_struct)
            snaps = {};
            if ~isstruct(paths_struct)
                return;
            end

            scan_dirs = {};
            fields = fieldnames(paths_struct);
            for k = 1:numel(fields)
                key = fields{k};
                value = paths_struct.(key);
                if ~(ischar(value) || isstring(value))
                    continue;
                end
                folder_path = char(string(value));
                if isempty(folder_path) || ~isfolder(folder_path)
                    continue;
                end
                if contains(lower(key), 'figure') || contains(lower(key), 'snapshot')
                    scan_dirs{end + 1} = folder_path; %#ok<AGROW>
                end
            end

            scan_dirs = unique(scan_dirs, 'stable');
            for d = 1:numel(scan_dirs)
                pngs = dir(fullfile(scan_dirs{d}, '*.png'));
                if isempty(pngs)
                    continue;
                end
                snaps = arrayfun(@(f) fullfile(f.folder, f.name), pngs, 'UniformOutput', false);
                return;
            end
        end

        function html = build_report_html(~, payload)
            % Delegate to EnhancedReportGenerator for Plotly.js interactive HTML.
            try
                html = EnhancedReportGenerator.build_html(payload);
            catch ME
                is_missing_symbol = strcmp(ME.identifier, 'MATLAB:UndefinedFunction') || ...
                    strcmp(ME.identifier, 'MATLAB:UndefinedFunctionOrVariable') || ...
                    contains(ME.message, 'Undefined function') || ...
                    contains(ME.message, 'Unrecognized function or variable');
                if ~is_missing_symbol
                    rethrow(ME);
                end
                PathSetup.attach_and_verify();
                html = EnhancedReportGenerator.build_html(payload);
            end
        end

        function eq_plain = equation_tex_to_plain(~, eq_tex)
            eq_plain = char(string(eq_tex));
            eq_plain = regexprep(eq_plain, '\\left|\\right', '');
            eq_plain = regexprep(eq_plain, '\\mathrm\{([^{}]+)\}', '$1');
            eq_plain = regexprep(eq_plain, '\\frac\{([^{}]+)\}\{([^{}]+)\}', '($1)/($2)');
            eq_plain = strrep(eq_plain, '\omega', 'ÃƒÂÃ¢â‚¬Â°');
            eq_plain = strrep(eq_plain, '\Gamma', 'ÃƒÅ½Ã¢â‚¬Å“');
            eq_plain = strrep(eq_plain, '\nu', 'ÃƒÅ½Ã‚Â½');
            eq_plain = strrep(eq_plain, '\theta', 'ÃƒÅ½Ã‚Â¸');
            eq_plain = strrep(eq_plain, '\sigma', 'ÃƒÂÃ†â€™');
            eq_plain = strrep(eq_plain, '\alpha', 'ÃƒÅ½Ã‚Â±');
            eq_plain = strrep(eq_plain, '\pi', 'ÃƒÂÃ¢â€šÂ¬');
            eq_plain = strrep(eq_plain, '\sum', 'ÃƒÅ½Ã‚Â£');
            eq_plain = strrep(eq_plain, '\cdot', 'Ãƒâ€šÃ‚Â·');
            eq_plain = strrep(eq_plain, '\exp', 'exp');
            eq_plain = strrep(eq_plain, '\begin{cases}', '');
            eq_plain = strrep(eq_plain, '\end{cases}', '');
            eq_plain = strrep(eq_plain, '\;', ' ');
            eq_plain = strrep(eq_plain, '\\', '');
            eq_plain = strrep(eq_plain, '{', '(');
            eq_plain = strrep(eq_plain, '}', ')');
            eq_plain = regexprep(eq_plain, '\s+', ' ');
            eq_plain = strtrim(eq_plain);
        end

        function escaped = escape_html_text(~, txt)
            escaped = char(string(txt));
            escaped = strrep(escaped, '&', '&amp;');
            escaped = strrep(escaped, '<', '&lt;');
            escaped = strrep(escaped, '>', '&gt;');
        end

        function uri = local_file_uri(~, local_path)
            % Convert a local filesystem path to a uihtml-safe file URI.
            uri = char(string(local_path));
            uri = strrep(uri, '\', '/');
            uri = strrep(uri, ' ', '%20');
            if numel(uri) >= 2 && uri(2) == ':'
                uri = ['file:///' uri];
            elseif startsWith(uri, '/')
                uri = ['file://' uri];
            else
                uri = ['file:///' uri];
            end
        end

        function uri = local_image_data_uri(~, local_path)
            % Convert a local image file into an inline data URI for uihtml.
            uri = '';
            if ~(ischar(local_path) || isstring(local_path))
                return;
            end
            path_txt = char(string(local_path));
            if ~isfile(path_txt)
                return;
            end

            [~, ~, ext] = fileparts(path_txt);
            switch lower(ext)
                case '.png'
                    mime = 'image/png';
                case {'.jpg', '.jpeg'}
                    mime = 'image/jpeg';
                case '.gif'
                    mime = 'image/gif';
                otherwise
                    return;
            end

            fid = fopen(path_txt, 'r');
            if fid < 0
                return;
            end
            cleaner = onCleanup(@() fclose(fid)); %#ok<NASGU>
            bytes = fread(fid, Inf, '*uint8');
            if isempty(bytes)
                return;
            end
            uri = ['data:' mime ';base64,' char(matlab.net.base64encode(bytes))];
        end

        function row_heights = build_ic_editor_row_heights(app)
            form_row = app.layout_cfg.heights.form_row;
            top_row = max(form_row + 10, 44);
            eq_row = 72;
            status_row = 20;
            if isfield(app.handles, 'ic_top_row_px')
                cand = double(app.handles.ic_top_row_px);
                if isfinite(cand) && cand > 0
                    top_row = cand;
                end
            end
            if isfield(app.handles, 'ic_form_row_px')
                cand = double(app.handles.ic_form_row_px);
                if isfinite(cand) && cand > 0
                    form_row = cand;
                end
            end
            if isfield(app.handles, 'ic_eq_row_px')
                cand = double(app.handles.ic_eq_row_px);
                if isfinite(cand) && cand > 0
                    eq_row = cand;
                end
            end
            if isfield(app.handles, 'ic_status_row_px')
                cand = double(app.handles.ic_status_row_px);
                if isfinite(cand) && cand > 0
                    status_row = cand;
                end
            end
            row_heights = {top_row, eq_row, form_row, form_row, form_row, ...
                'fit', 'fit', 'fit', 'fit', 'fit', status_row, status_row};
        end

        function col_widths = build_config_form_column_widths(~, form_key, profile)
            if nargin < 3 || isempty(profile)
                profile = 'standard';
            end
            key = char(lower(string(form_key)));
            mode = char(lower(string(profile)));

            switch key
                case 'grid'
                    switch mode
                        case 'compact'
                            col_widths = {64, '1x', 64, '1x'};
                        case 'wide'
                            col_widths = {82, '1x', 82, '1x'};
                        otherwise
                            col_widths = {72, '1x', 72, '1x'};
                    end
                case 'time'
                    switch mode
                        case 'compact'
                            col_widths = {68, '1x', 68, '1x'};
                        case 'wide'
                            col_widths = {84, '1x', 84, '1x'};
                        otherwise
                            col_widths = {76, '1x', 76, '1x'};
                    end
                case 'wave'
                    switch mode
                        case 'compact'
                            col_widths = {96, '1x'};
                        case 'wide'
                            col_widths = {130, '1x'};
                        otherwise
                            col_widths = {112, '1x'};
                    end
                case 'simulation'
                    switch mode
                        case 'compact'
                            col_widths = {'1.00x', '0.86x', '1.00x', '0.86x'};
                        case 'wide'
                            col_widths = {'1.10x', '0.94x', '1.10x', '0.94x'};
                        otherwise
                            col_widths = {'1.04x', '0.90x', '1.04x', '0.90x'};
                    end
                case 'convergence'
                    col_widths = {'1x', '1x', '1x', '1x'};
                case 'sustainability'
                    switch mode
                        case 'compact'
                            col_widths = {'1.00x', '0.86x', '1.00x', '0.86x'};
                        case 'wide'
                            col_widths = {'1.08x', '0.94x', '1.08x', '0.94x'};
                        otherwise
                            col_widths = {'1.02x', '0.90x', '1.02x', '0.90x'};
                    end
                otherwise
                    col_widths = {'1x', '1x', '1x', '1x'};
            end
        end

        function col_widths = build_ic_editor_column_widths(~, profile)
            if nargin < 2 || isempty(profile)
                profile = 'standard';
