        function load_converged_mesh_preset(app)
            % Load latest modern convergence result as a reusable mesh seed.
            criteria = struct();
            if isfield(app.config, 'ic_type')
                criteria.ic_type = app.config.ic_type;
            end
            criteria.bc_case = 'periodic';
            criteria.bathymetry_scenario = 'flat_2d';
            entry = ConvergedMeshRegistry.select_latest('Results', criteria);
            if isempty(entry.method)
                entry = ConvergedMeshRegistry.select_latest('Results', struct());
            end

            if isempty(entry.method)
                app.append_to_terminal('No modern convergence result found under Results/*/Convergence/*/Data.', 'warning');
                if app.has_valid_handle('converged_mesh_status')
                    app.handles.converged_mesh_status.Text = 'No convergence seed found';
                    app.handles.converged_mesh_status.FontColor = app.layout_cfg.colors.accent_yellow;
                end
                return;
            end

            if isfinite(entry.Nx)
                app.handles.conv_N_max.Value = max(8, round(entry.Nx));
                app.handles.conv_N_coarse.Value = max(8, min(app.handles.conv_N_max.Value, ...
                    round(app.handles.conv_N_max.Value / 2)));
                if app.has_valid_handle('Nx')
                    app.handles.Nx.Value = max(2, round(entry.Nx));
                end
            end
            if isfinite(entry.Ny) && app.has_valid_handle('Ny')
                app.handles.Ny.Value = max(2, round(entry.Ny));
            end
            if isfinite(entry.dt) && app.has_valid_handle('dt')
                app.handles.dt.Value = max(eps, double(entry.dt));
            end
            if app.has_valid_handle('phase1_use_converged_mesh_seed')
                app.handles.phase1_use_converged_mesh_seed.Value = true;
            end

            msg = sprintf('Loaded %s seed %dx%d, dt=%.3g, verdict=%s', ...
                upper(entry.method_key), round(entry.Nx), round(entry.Ny), entry.dt, entry.verdict);
            if app.has_valid_handle('converged_mesh_status')
                app.handles.converged_mesh_status.Text = msg;
                app.handles.converged_mesh_status.FontColor = app.layout_cfg.colors.accent_green;
            end
            app.append_to_terminal(sprintf('Loaded convergence seed from %s', entry.source_path), 'success');
            app.update_checklist();
            app.update_convergence_display();
        end

