        function create_phase_settings_tabs(app, parent_panel, defaults, colors)
            host = uigridlayout(parent_panel, [1, 1]);
            host.RowHeight = {'1x'};
            host.ColumnWidth = {'1x'};
            host.Padding = [4 4 4 4];
            host.RowSpacing = 0;
            host.ColumnSpacing = 0;
            app.handles.phase_settings_host = host;

            tabs = uitabgroup(host);
            tabs.Layout.Row = 1;
            tabs.Layout.Column = 1;
            app.handles.phase_settings_tabs = tabs;

            t1 = uitab(tabs, 'Title', 'Phase 1');
            t2 = uitab(tabs, 'Title', 'Phase 2');
            t3 = uitab(tabs, 'Title', 'Phase 3');
            app.enable_scrollable_if_supported(t1);
            app.enable_scrollable_if_supported(t2);
            app.enable_scrollable_if_supported(t3);
            app.handles.phase1_settings_tab = t1;
            app.handles.phase2_settings_tab = t2;
            app.handles.phase3_settings_tab = t3;

            app.populate_phase1_settings_tab(t1, defaults, colors);
            app.populate_phase2_settings_tab(t2, defaults, colors);
            app.populate_phase3_settings_tab(t3, defaults, colors);
            app.enforce_container_content_margins(parent_panel);
        end

        function populate_mesh_settings_panel(app, parent_layout, mesh_defaults, colors)
            T = app.layout_cfg.text;
            controls_panel = uipanel(parent_layout, 'Title', 'Mesh Settings', ...
                'BackgroundColor', colors.bg_panel);
            if isprop(controls_panel, 'Scrollable')
                controls_panel.Scrollable = 'on';
            end
            controls_panel.Layout.Row = 1;
            controls_panel.Layout.Column = 1;
            app.handles.config_convergence_controls_panel = controls_panel;

            [mesh_ic_labels, mesh_ic_ids] = app.mesh_convergence_ic_preset_items();
            selected_mesh_ic_id = char(string(app.pick_field_required(mesh_defaults, {'ic_preset_id'}, 'elliptical_vortex')));
            if ~any(strcmpi(selected_mesh_ic_id, mesh_ic_ids))
                selected_mesh_ic_id = char(string(mesh_ic_ids{1}));
            end

            grid = uigridlayout(controls_panel, [6, 6]);
            grid.RowHeight = {28, 22, 28, 28, 28, 28};
            grid.ColumnWidth = {92, 70, 70, 92, 70, '1x'};
            grid.Padding = [6 6 6 6];
            grid.RowSpacing = 6;
            grid.ColumnSpacing = 6;
            app.handles.config_conv_layout = grid;

            lbl = uilabel(grid, 'Text', 'Mesh IC', 'FontColor', colors.fg_text, 'FontWeight', 'bold');
            lbl.Layout.Row = 1;
            lbl.Layout.Column = 1;
            app.handles.phase1_mesh_ic_preset = uidropdown(grid, ...
