                'RoundFractionalValues', 'on', 'Limits', [8 4096]);
            app.handles.phase1_mesh_start_nx.Layout.Row = 3;
            app.handles.phase1_mesh_start_nx.Layout.Column = 3;
            app.handles.phase1_mesh_start_ny = uieditfield(grid, 'numeric', ...
                'Value', double(app.pick_field_required(mesh_defaults, {'mesh_start_ny'}, 32)), ...
                'RoundFractionalValues', 'on', 'Limits', [8 4096]);
            app.handles.phase1_mesh_start_ny.Layout.Row = 4;
            app.handles.phase1_mesh_start_ny.Layout.Column = 3;

            app.handles.phase1_mesh_final_equal_xy = uicheckbox(grid, ...
