            app.handles.phase1_mesh_final_n.Layout.Row = 3;
            app.handles.phase1_mesh_final_n.Layout.Column = 5;
            app.handles.phase1_mesh_final_nx = uieditfield(grid, 'numeric', ...
                'Value', double(app.pick_field_required(mesh_defaults, {'mesh_final_nx'}, 768)), ...
                'RoundFractionalValues', 'on', 'Limits', [8 4096]);
