            app.handles.phase1_mesh_final_nx.Layout.Column = 6;
            app.handles.phase1_mesh_final_ny = uieditfield(grid, 'numeric', ...
                'Value', double(app.pick_field_required(mesh_defaults, {'mesh_final_ny'}, 768)), ...
                'RoundFractionalValues', 'on', 'Limits', [8 4096]);
            app.handles.phase1_mesh_final_ny.Layout.Row = 4;
            app.handles.phase1_mesh_final_ny.Layout.Column = 6;

            lbl = uilabel(grid, 'Text', 'Levels', 'FontColor', colors.fg_text);
            lbl.Layout.Row = 5;
            lbl.Layout.Column = 1;
            app.handles.phase1_mesh_level_count_label = lbl;
            app.handles.phase1_mesh_level_count = uieditfield(grid, 'numeric', ...
                'Value', double(app.pick_field_required(mesh_defaults, {'mesh_level_count'}, 8)), ...
                'RoundFractionalValues', 'on', 'Limits', [2 12]);
            app.handles.phase1_mesh_level_count.Layout.Row = 5;
            app.handles.phase1_mesh_level_count.Layout.Column = 2;
            lbl = uilabel(grid, 'Text', 'Vorticity tol (%)', 'FontColor', colors.fg_text);
            lbl.Layout.Row = 5;
            lbl.Layout.Column = 4;
            app.handles.phase1_convergence_tolerance = uieditfield(grid, 'numeric', ...
                'Value', double(app.pick_field_required(mesh_defaults, {'convergence_tolerance'}, 1.0)));
            app.handles.phase1_convergence_tolerance.Layout.Row = 5;
            app.handles.phase1_convergence_tolerance.Layout.Column = 5;

            app.handles.phase1_mesh_ladder_mode_label = uilabel(grid, ...
                'Text', 'Mesh Ladder', ...
                'FontColor', colors.fg_text);
            app.handles.phase1_mesh_ladder_mode_label.Layout.Row = 6;
            app.handles.phase1_mesh_ladder_mode_label.Layout.Column = 1;
            app.handles.phase1_mesh_ladder_mode = uidropdown(grid, ...
                'Items', {'Bounds', 'Powers of 2'}, ...
                'ItemsData', {'bounded', 'powers_of_2'}, ...
                'Value', char(string(app.pick_field_required(mesh_defaults, {'mesh_ladder_mode'}, 'bounded'))), ...
                'ValueChangedFcn', @(~,~) app.on_phase1_mesh_ladder_mode_changed());
            app.handles.phase1_mesh_ladder_mode.Layout.Row = 6;
            app.handles.phase1_mesh_ladder_mode.Layout.Column = [2 3];

            app.handles.phase1_use_converged_mesh_seed = uicheckbox(grid, ...
                'Text', 'Use Converged Mesh Seed', ...
                'Value', logical(app.pick_field(mesh_defaults, {'use_converged_mesh_seed'}, false)), ...
                'FontColor', colors.fg_text, ...
                'ValueChangedFcn', @(~,~) app.update_checklist());
            app.handles.phase1_use_converged_mesh_seed.Layout.Row = 6;
            app.handles.phase1_use_converged_mesh_seed.Layout.Column = [4 5];

            app.handles.converged_mesh_status = uilabel(grid, ...
                'Text', 'No converged mesh loaded.', ...
                'FontColor', colors.fg_muted, ...
                'WordWrap', 'on');
            app.handles.converged_mesh_status.Layout.Row = 6;
            app.handles.converged_mesh_status.Layout.Column = 6;

            compat_panel = uipanel(controls_panel, ...
                'BorderType', 'none', ...
                'Visible', 'off', ...
                'Position', [1 1 1 1]);
            app.handles.conv_mode_manual = uibutton(compat_panel, 'push', 'Text', 'Manual', 'Visible', 'off');
            app.handles.conv_mode_agent = uibutton(compat_panel, 'push', 'Text', 'Agent', 'Visible', 'off');
            app.handles.conv_mode_advanced = uibutton(compat_panel, 'push', 'Text', 'Advanced', 'Visible', 'off');
            app.handles.conv_agent_status = uilabel(compat_panel, 'Text', 'Convergence agent inactive.', 'Visible', 'off');
            app.handles.conv_N_coarse = uieditfield(compat_panel, 'numeric', ...
                'Value', double(app.pick_field(mesh_defaults, {'mesh_start_n'}, 32)), 'Visible', 'off');
            app.handles.conv_N_max = uieditfield(compat_panel, 'numeric', ...
                'Value', double(app.pick_field(mesh_defaults, {'mesh_final_n'}, 768)), 'Visible', 'off');
            app.handles.conv_dt_values_label = uilabel(compat_panel, 'Text', 'dt values', 'Visible', 'off');
            app.handles.conv_dt_values = uieditfield(compat_panel, 'text', ...
                'Value', app.numeric_csv_string(app.pick_field(app.layout_cfg.ui_defaults, {'convergence_dt_values'}, [0.1, 0.05])), ...
                'Visible', 'off');
            app.handles.conv_tolerance = uieditfield(compat_panel, 'numeric', ...
                'Value', double(app.pick_field(mesh_defaults, {'convergence_tolerance'}, 1.0)), 'Visible', 'off');
            app.handles.conv_criterion = uidropdown(compat_panel, ...
                'Items', app.layout_cfg.ui_options.convergence_criterion_items, ...
                'Value', char(string(app.pick_field(app.layout_cfg.ui_defaults, {'convergence_criterion_type'}, 'vorticity_rms'))), ...
                'Visible', 'off');
            app.handles.conv_binary = uicheckbox(compat_panel, 'Text', '', ...
                'Value', logical(app.pick_field(app.layout_cfg.ui_defaults, {'convergence_binary'}, false)), 'Visible', 'off');
            app.handles.conv_use_adaptive = uicheckbox(compat_panel, 'Text', '', ...
                'Value', logical(app.pick_field(app.layout_cfg.ui_defaults, {'convergence_use_adaptive'}, false)), 'Visible', 'off');
            app.handles.conv_max_jumps = uieditfield(compat_panel, 'numeric', ...
                'Value', double(app.pick_field(app.layout_cfg.ui_defaults, {'convergence_max_jumps'}, 3)), 'Visible', 'off');
            app.handles.conv_agent_enabled = uicheckbox(compat_panel, 'Text', '', ...
                'Value', logical(app.pick_field(app.layout_cfg.ui_defaults, {'convergence_agent_enabled'}, false)), 'Visible', 'off');
            app.handles.conv_agent_objective_mode_label = uilabel(compat_panel, 'Text', 'Objective', 'Visible', 'off');
            app.handles.conv_agent_objective_mode = uidropdown(compat_panel, ...
                'Items', {'balanced', 'accuracy_first', 'speed_first', 'energy_first'}, ...
                'Value', char(string(app.pick_field(app.layout_cfg.ui_defaults, {'convergence_agent_objective_mode'}, 'balanced'))), ...
                'Visible', 'off');
            app.handles.conv_math = uihtml(compat_panel, 'HTMLSource', '<html><body></body></html>', 'Visible', 'off');
            app.handles.btn_load_converged_mesh = uibutton(compat_panel, 'push', ...
                'Text', 'Load Converged Mesh', ...
