            app.on_phase1_equal_mesh_changed('start');
            app.on_phase1_equal_mesh_changed('final');
            app.on_phase1_mesh_ladder_mode_changed();
            app.enforce_container_content_margins(controls_panel);
        end

        function populate_phase1_settings_tab(app, tab, defaults, colors)
            phase1 = app.pick_field_required(defaults, {'phase1'}, struct());
            ic_study_cfg = app.pick_field(phase1, {'ic_study'}, struct());
            [case_labels, case_ids] = app.phase1_ic_study_case_items();
            baseline_meta = app.phase1_baseline_case_metadata(app.pick_field(ic_study_cfg, {'baseline_ic_type'}, 'stretched_gaussian'));
            selected_case_id = char(string(app.pick_field(ic_study_cfg, {'selected_case_id'}, baseline_meta.case_id)));
            if isempty(case_ids)
                case_labels = {baseline_meta.label};
                case_ids = {baseline_meta.case_id};
            end
            if ~any(strcmpi(selected_case_id, case_ids))
                selected_case_id = char(string(case_ids{1}));
            end

            root = uigridlayout(tab, [3, 1]);
            root.RowHeight = {42, 'fit', '1x'};
            root.ColumnWidth = {'1x'};
            root.Padding = [6 6 6 6];
            root.RowSpacing = 6;

            desc = uilabel(root, ...
                'Text', 'Baseline periodic vorticity comparison between FD and Spectral using directly editable per-method grid and time-step settings.', ...
                'FontColor', colors.fg_text, ...
                'WordWrap', 'on');
            desc.Layout.Row = 1;
            desc.Layout.Column = 1;

            mesh_panel = uipanel(root, ...
                'Title', 'Method Settings', ...
                'BackgroundColor', colors.bg_panel);
            mesh_panel.Layout.Row = 2;
            mesh_panel.Layout.Column = 1;

            grid = uigridlayout(mesh_panel, [5, 4]);
            grid.RowHeight = {28, 28, 24, 28, 28};
            grid.ColumnWidth = {96, 96, 96, 96};
            grid.Padding = [6 6 6 6];
            grid.RowSpacing = 6;
            grid.ColumnSpacing = 6;

            lbl = uilabel(grid, 'Text', 'FD grid N', 'FontColor', colors.fg_text, 'HorizontalAlignment', 'left');
            lbl.Layout.Row = 1; lbl.Layout.Column = 1;
            lbl = uilabel(grid, 'Text', 'FD dt', 'FontColor', colors.fg_text, 'HorizontalAlignment', 'left');
            lbl.Layout.Row = 1; lbl.Layout.Column = 2;
            lbl = uilabel(grid, 'Text', 'SM grid N', 'FontColor', colors.fg_text, 'HorizontalAlignment', 'left');
            lbl.Layout.Row = 1; lbl.Layout.Column = 3;
            lbl = uilabel(grid, 'Text', 'SM dt', 'FontColor', colors.fg_text, 'HorizontalAlignment', 'left');
            lbl.Layout.Row = 1; lbl.Layout.Column = 4;

            app.handles.phase1_fd_grid_n = uieditfield(grid, 'numeric', ...
                'Value', double(app.pick_field_required(phase1, {'fd_grid_n'}, defaults.Nx)), ...
                'RoundFractionalValues', 'on', 'Limits', [8 4096]);
            app.handles.phase1_fd_grid_n.Layout.Row = 2;
            app.handles.phase1_fd_grid_n.Layout.Column = 1;
            app.handles.phase1_fd_dt = uieditfield(grid, 'numeric', ...
                'Value', double(app.pick_field_required(phase1, {'fd_dt'}, defaults.dt)), ...
                'Limits', [eps Inf]);
            app.handles.phase1_fd_dt.Layout.Row = 2;
            app.handles.phase1_fd_dt.Layout.Column = 2;
            app.handles.phase1_spectral_grid_n = uieditfield(grid, 'numeric', ...
                'Value', double(app.pick_field_required(phase1, {'spectral_grid_n'}, defaults.Nx)), ...
                'RoundFractionalValues', 'on', 'Limits', [8 4096]);
            app.handles.phase1_spectral_grid_n.Layout.Row = 2;
            app.handles.phase1_spectral_grid_n.Layout.Column = 3;
            app.handles.phase1_spectral_dt = uieditfield(grid, 'numeric', ...
                'Value', double(app.pick_field_required(phase1, {'spectral_dt'}, defaults.dt)), ...
                'Limits', [eps Inf]);
            app.handles.phase1_spectral_dt.Layout.Row = 2;
            app.handles.phase1_spectral_dt.Layout.Column = 4;

            lbl = uilabel(grid, ...
                'Text', 'Taylor-Green Overrides', ...
                'FontColor', colors.fg_text, ...
                'FontWeight', 'bold');
            lbl.Layout.Row = 3;
            lbl.Layout.Column = [1 4];

            lbl = uilabel(grid, 'Text', 'TG FD Grid', 'FontColor', colors.fg_text, 'HorizontalAlignment', 'left');
            lbl.Layout.Row = 4; lbl.Layout.Column = 1;
            lbl = uilabel(grid, 'Text', 'TG FD dt', 'FontColor', colors.fg_text, 'HorizontalAlignment', 'left');
            lbl.Layout.Row = 4; lbl.Layout.Column = 2;
            lbl = uilabel(grid, 'Text', 'TG SM Grid', 'FontColor', colors.fg_text, 'HorizontalAlignment', 'left');
            lbl.Layout.Row = 4; lbl.Layout.Column = 3;
            lbl = uilabel(grid, 'Text', 'TG SM dt', 'FontColor', colors.fg_text, 'HorizontalAlignment', 'left');
            lbl.Layout.Row = 4; lbl.Layout.Column = 4;

            app.handles.phase1_tg_fd_grid_n = uieditfield(grid, 'numeric', ...
                'Value', double(app.pick_field_required(phase1, {'taylor_green_fd_grid_n', 'fd_grid_n'}, defaults.Nx)), ...
                'RoundFractionalValues', 'on', 'Limits', [8 4096]);
            app.handles.phase1_tg_fd_grid_n.Layout.Row = 5;
            app.handles.phase1_tg_fd_grid_n.Layout.Column = 1;
            app.handles.phase1_tg_fd_dt = uieditfield(grid, 'numeric', ...
                'Value', double(app.pick_field_required(phase1, {'taylor_green_fd_dt', 'fd_dt'}, defaults.dt)), ...
                'Limits', [eps Inf]);
            app.handles.phase1_tg_fd_dt.Layout.Row = 5;
            app.handles.phase1_tg_fd_dt.Layout.Column = 2;
            app.handles.phase1_tg_spectral_grid_n = uieditfield(grid, 'numeric', ...
                'Value', double(app.pick_field_required(phase1, {'taylor_green_spectral_grid_n', 'spectral_grid_n'}, defaults.Nx)), ...
                'RoundFractionalValues', 'on', 'Limits', [8 4096]);
            app.handles.phase1_tg_spectral_grid_n.Layout.Row = 5;
            app.handles.phase1_tg_spectral_grid_n.Layout.Column = 3;
            app.handles.phase1_tg_spectral_dt = uieditfield(grid, 'numeric', ...
                'Value', double(app.pick_field_required(phase1, {'taylor_green_spectral_dt', 'spectral_dt'}, defaults.dt)), ...
                'Limits', [eps Inf]);
            app.handles.phase1_tg_spectral_dt.Layout.Row = 5;
            app.handles.phase1_tg_spectral_dt.Layout.Column = 4;

            ic_panel = uipanel(root, ...
                'Title', 'IC Study', ...
                'BackgroundColor', colors.bg_panel);
            ic_panel.Layout.Row = 3;
            ic_panel.Layout.Column = 1;
            app.handles.phase1_ic_study_panel = ic_panel;

            ic_grid = uigridlayout(ic_panel, [1, 2]);
            ic_grid.RowHeight = {'1x'};
            ic_grid.ColumnWidth = {'1x', '3x'};
            ic_grid.Padding = [6 6 6 6];
            ic_grid.RowSpacing = 0;
            ic_grid.ColumnSpacing = 8;

            controls = uigridlayout(ic_grid, [4, 1]);
            controls.Layout.Row = 1;
            controls.Layout.Column = 1;
            controls.RowHeight = {18, 32, 24, '1x'};
            controls.ColumnWidth = {'1x'};
            controls.Padding = [0 0 0 0];
            controls.RowSpacing = 6;

            lbl = uilabel(controls, ...
                'Text', 'IC Case', ...
                'FontColor', colors.fg_text, ...
                'FontWeight', 'bold');
            lbl.Layout.Row = 1;
            lbl.Layout.Column = 1;

            app.handles.phase1_ic_study_case = uidropdown(controls, ...
                'Items', case_labels, ...
                'ItemsData', case_ids, ...
                'Value', selected_case_id, ...
                'ValueChangedFcn', @(~,~) app.on_phase1_ic_study_case_changed());
            app.handles.phase1_ic_study_case.Layout.Row = 2;
            app.handles.phase1_ic_study_case.Layout.Column = 1;

            app.handles.phase1_ic_study_include_arrangements = uicheckbox(controls, ...
                'Text', 'Include arrangement studies (polar, ring, random)', ...
                'Value', logical(app.pick_field(ic_study_cfg, {'include_arrangement_cases'}, false)), ...
                'FontColor', colors.fg_text);
            app.handles.phase1_ic_study_include_arrangements.Layout.Row = 3;
            app.handles.phase1_ic_study_include_arrangements.Layout.Column = 1;

            note = uilabel(controls, ...
                'Text', 'Preview the available Phase 1 IC cases. The workflow always runs the baseline elliptic Gaussian and Taylor-Green, and the arrangement toggle adds polar opposites, ring train, and random pack.', ...
                'FontColor', colors.fg_muted, ...
                'WordWrap', 'on');
            note.Layout.Row = 4;
            note.Layout.Column = 1;

            preview_host = uigridlayout(ic_grid, [1, 1]);
            preview_host.Layout.Row = 1;
            preview_host.Layout.Column = 2;
            preview_host.RowHeight = {'1x'};
            preview_host.ColumnWidth = {'1x'};
            preview_host.Padding = [4 4 4 4];
            preview_host.RowSpacing = 0;
            preview_host.ColumnSpacing = 0;

            ax = uiaxes(preview_host);
            ax.Layout.Row = 1;
            ax.Layout.Column = 1;
            app.style_axes(ax);
            app.handles.phase1_ic_study_preview_axes = ax;

            app.refresh_phase1_ic_study_preview();
            app.enforce_container_content_margins(tab);
        end

        function populate_phase2_settings_tab(app, tab, defaults, colors)
            phase2 = app.pick_field_required(defaults, {'phase2'}, struct());
            root = uigridlayout(tab, [5, 1]);
            root.RowHeight = {42, 18, 'fit', '1x', '1x'};
            root.ColumnWidth = {'1x'};
            root.Padding = [6 6 6 6];
            root.RowSpacing = 6;

            desc = uilabel(root, ...
                'Text', 'Boundary-condition study across three scenarios. Phase 2 uses the currently selected IC, bathymetry, domain, grid, and runtime settings.', ...
                'FontColor', colors.fg_text, 'WordWrap', 'on');
            desc.Layout.Row = 1;
            unit_note = uilabel(root, ...
                'Text', 'Domain lengths are in m. Wall speeds below are entered directly in m/s for each boundary-condition case.', ...
                'FontColor', colors.fg_muted);
            unit_note.Layout.Row = 2;

            direct_panel = uipanel(root, 'Title', 'FD Method Settings', 'BackgroundColor', colors.bg_panel);
            direct_panel.Layout.Row = 3;
            direct_panel.Layout.Column = 1;
            direct_grid = uigridlayout(direct_panel, [2, 4]);
            direct_grid.RowHeight = {24, 28};
            direct_grid.ColumnWidth = {'1x', '1x', '1x', '1x'};
            direct_grid.Padding = [6 6 6 6];
            direct_grid.RowSpacing = 6;
