            lbl.Layout.Row = 1; lbl.Layout.Column = 1;
            lbl = uilabel(direct_grid, 'Text', 'FD dt', 'FontColor', colors.fg_text);
            lbl.Layout.Row = 1; lbl.Layout.Column = 2;
            lbl = uilabel(direct_grid, 'Text', 'TG FD Grid', 'FontColor', colors.fg_text);
            lbl.Layout.Row = 1; lbl.Layout.Column = 3;
            lbl = uilabel(direct_grid, 'Text', 'TG dt', 'FontColor', colors.fg_text);
            lbl.Layout.Row = 1; lbl.Layout.Column = 4;
            app.handles.phase2_fd_grid_n = uieditfield(direct_grid, 'numeric', ...
                'Value', double(app.pick_field_required(phase2, {'fd_grid_n'}, defaults.Nx)), ...
                'RoundFractionalValues', 'on', 'Limits', [8 4096]);
            app.handles.phase2_fd_grid_n.Layout.Row = 2;
            app.handles.phase2_fd_grid_n.Layout.Column = 1;
            app.handles.phase2_fd_dt = uieditfield(direct_grid, 'numeric', ...
                'Value', double(app.pick_field(phase2, {'fd_dt'}, defaults.dt)), ...
