            scenarios = app.pick_field_required(phase2, {'scenarios'}, struct([]));
            for i = 1:min(3, numel(scenarios))
                app.populate_phase2_scenario_row(row_host, i, scenarios(i), colors);
            end
            app.update_all_phase2_previews();
            app.enforce_container_content_margins(tab);
        end

        function populate_phase2_scenario_row(app, parent_layout, index, scenario, colors)
            panel = uipanel(parent_layout, ...
                'Title', sprintf('Scenario %d', index), ...
                'BackgroundColor', colors.bg_panel);
            if isprop(panel, 'Scrollable')
                panel.Scrollable = 'on';
            end
            panel.Layout.Row = index;
            app.handles.(sprintf('phase2_row_%d_panel', index)) = panel;
            grid = uigridlayout(panel, [1, 2]);
            grid.RowHeight = {'1x'};
            grid.ColumnWidth = {'1x', '1x'};
            grid.Padding = [4 4 4 4];
            grid.RowSpacing = 4;
            grid.ColumnSpacing = 8;

            left = uigridlayout(grid, [2, 1]);
            left.Layout.Row = 1;
            left.Layout.Column = 1;
            left.RowHeight = {34, '1x'};
            left.ColumnWidth = {'1x'};
            left.Padding = [0 0 0 0];
            left.RowSpacing = 6;

            dd = uidropdown(left, ...
                'Items', app.phase2_scenario_dropdown_items(), ...
                'Value', app.phase2_scenario_id_to_label(app.pick_field(scenario, {'id'}, 'lid_driven_cavity')), ...
                'ValueChangedFcn', @(~,~) app.on_phase2_scenario_selection_changed(index));
            dd.Layout.Row = 1;
            dd.Layout.Column = 1;
            app.handles.(sprintf('phase2_scenario_%d_case', index)) = dd;

            controls_panel = uipanel(left, 'Title', 'Scenario Settings', 'BackgroundColor', colors.bg_panel_alt);
            controls_panel.Layout.Row = 2;
            controls_panel.Layout.Column = 1;
            controls = uigridlayout(controls_panel, [1, 1]);
            controls.RowHeight = {'1x'};
            controls.ColumnWidth = {'1x'};
            controls.Padding = [6 6 6 6];
            controls.RowSpacing = 5;
            controls.ColumnSpacing = 6;
            speed_grid = uigridlayout(controls, [2, 4]);
            speed_grid.Layout.Row = 1;
            speed_grid.Layout.Column = 1;
            speed_grid.RowHeight = {26, 26};
            speed_grid.ColumnWidth = {86, '1x', 86, '1x'};
            speed_grid.Padding = [0 0 0 0];
            speed_grid.RowSpacing = 5;
            speed_grid.ColumnSpacing = 6;

            speed_specs = { ...
                'top', 1, 1, 2, app.pick_field(scenario, {'top_speed_mps'}, 0.0); ...
                'bottom', 1, 3, 4, app.pick_field(scenario, {'bottom_speed_mps'}, 0.0); ...
                'left', 2, 1, 2, app.pick_field(scenario, {'left_speed_mps'}, 0.0); ...
                'right', 2, 3, 4, app.pick_field(scenario, {'right_speed_mps'}, 0.0)};
            for si = 1:size(speed_specs, 1)
                key = speed_specs{si, 1};
                lbl = uilabel(speed_grid, ...
                    'Text', app.humanize_token(key), ...
                    'FontColor', colors.fg_text, ...
                    'HorizontalAlignment', 'right');
                lbl.Layout.Row = speed_specs{si, 2};
                lbl.Layout.Column = speed_specs{si, 3};
                field = uieditfield(speed_grid, 'numeric', ...
                    'Value', double(speed_specs{si, 5}), ...
                    'ValueChangedFcn', @(~,~) app.update_phase2_preview_row(index));
                field.Layout.Row = speed_specs{si, 2};
                field.Layout.Column = speed_specs{si, 4};
                app.handles.(sprintf('phase2_scenario_%d_%s_speed_label', index, key)) = lbl;
                app.handles.(sprintf('phase2_scenario_%d_%s_speed_mps', index, key)) = field;
            end

            preview_host = uigridlayout(grid, [1, 1]);
            preview_host.Layout.Row = 1;
            preview_host.Layout.Column = 2;
            preview_host.RowHeight = {'1x'};
            preview_host.ColumnWidth = {'1x'};
            preview_host.Padding = [4 4 4 4];
            ax = uiaxes(preview_host);
            ax.Layout.Row = 1;
            ax.Layout.Column = 1;
            app.style_axes(ax);
            app.handles.(sprintf('phase2_scenario_%d_axes', index)) = ax;

            app.refresh_phase2_scenario_controls(index);
            app.enforce_container_content_margins(panel);
        end

