            app.handles.phase3_domain_lx.Layout.Column = 2;
            lbl = uilabel(grid, 'Text', 'Ly (m)', 'FontColor', colors.fg_text);
            lbl.Layout.Row = 2;
            lbl.Layout.Column = 3;
