        function on_phase1_equal_mesh_changed(app, which_side)
            eq_handle = sprintf('phase1_mesh_%s_equal_xy', lower(char(string(which_side))));
            n_handle = sprintf('phase1_mesh_%s_n', lower(char(string(which_side))));
            nx_handle = sprintf('phase1_mesh_%s_nx', lower(char(string(which_side))));
            ny_handle = sprintf('phase1_mesh_%s_ny', lower(char(string(which_side))));
            if ~app.has_valid_handle(eq_handle)
                return;
            end
            use_equal = logical(app.handles.(eq_handle).Value);
            if use_equal
                n_value = max(8, round(app.safe_numeric_value(n_handle, 32)));
                if app.has_valid_handle(nx_handle), app.handles.(nx_handle).Value = n_value; end
                if app.has_valid_handle(ny_handle), app.handles.(ny_handle).Value = n_value; end
            end
            state_xy = app.on_off(~use_equal);
            if app.has_valid_handle(nx_handle), app.handles.(nx_handle).Enable = state_xy; end
            if app.has_valid_handle(ny_handle), app.handles.(ny_handle).Enable = state_xy; end
        end

        function on_phase1_uniform_mesh_changed(app, which_side)
            n_handle = sprintf('phase1_mesh_%s_n', lower(char(string(which_side))));
            nx_handle = sprintf('phase1_mesh_%s_nx', lower(char(string(which_side))));
            ny_handle = sprintf('phase1_mesh_%s_ny', lower(char(string(which_side))));
            eq_handle = sprintf('phase1_mesh_%s_equal_xy', lower(char(string(which_side))));
            if app.has_valid_handle(eq_handle) && logical(app.handles.(eq_handle).Value)
                n_value = max(8, round(app.safe_numeric_value(n_handle, 32)));
                if app.has_valid_handle(nx_handle), app.handles.(nx_handle).Value = n_value; end
                if app.has_valid_handle(ny_handle), app.handles.(ny_handle).Value = n_value; end
            end
        end

        function on_phase1_mesh_ladder_mode_changed(app)
            use_levels = strcmpi(app.safe_text_value('phase1_mesh_ladder_mode', 'bounded'), 'bounded');
            if app.has_valid_handle('phase1_mesh_level_count')
                app.handles.phase1_mesh_level_count.Enable = app.on_off(use_levels);
            end
            if app.has_valid_handle('phase1_mesh_level_count_label')
                if use_levels
                    app.handles.phase1_mesh_level_count_label.FontColor = app.layout_cfg.colors.fg_text;
                else
                    app.handles.phase1_mesh_level_count_label.FontColor = app.layout_cfg.colors.fg_muted;
                end
            end
        end

        function items = phase2_scenario_dropdown_items(~)
            items = {'Enclosed Driven Cavity', 'Driven Channel Flow', 'Enclosed Shear Layer'};
        end

        function label = phase2_scenario_id_to_label(~, scenario_id)
            switch lower(char(string(scenario_id)))
                case 'lid_driven_cavity'
                    label = 'Enclosed Driven Cavity';
                case 'driven_channel_flow'
                    label = 'Driven Channel Flow';
                case 'enclosed_shear_layer'
                    label = 'Enclosed Shear Layer';
                otherwise
                    label = 'Enclosed Driven Cavity';
            end
        end

        function scenario_id = phase2_scenario_label_to_id(~, label)
            switch lower(strtrim(char(string(label))))
                case 'enclosed driven cavity'
                    scenario_id = 'lid_driven_cavity';
                case 'driven channel flow'
                    scenario_id = 'driven_channel_flow';
                case 'enclosed shear layer'
                    scenario_id = 'enclosed_shear_layer';
                otherwise
                    scenario_id = 'lid_driven_cavity';
            end
        end

        function on_phase2_scenario_selection_changed(app, index)
            app.refresh_phase2_scenario_controls(index);
            app.update_phase2_preview_row(index);
        end

        function refresh_phase2_scenario_controls(app, index)
            scenario_id = app.phase2_scenario_label_to_id(app.safe_text_value( ...
                sprintf('phase2_scenario_%d_case', index), 'Enclosed Driven Cavity'));
            field_specs = app.phase_boundary_control_specs(scenario_id);
            keys = {'top', 'bottom', 'left', 'right'};
            for i = 1:numel(keys)
                key = keys{i};
                lbl_name = sprintf('phase2_scenario_%d_%s_speed_label', index, key);
                field_name = sprintf('phase2_scenario_%d_%s_speed_mps', index, key);
                if ~app.has_valid_handle(lbl_name) || ~app.has_valid_handle(field_name)
                    continue;
                end
                spec = field_specs.(key);
                app.handles.(lbl_name).Text = spec.label;
                app.handles.(field_name).Enable = app.on_off(spec.editable);
                if ~spec.editable
                    app.handles.(field_name).Value = spec.value;
                end
            end
        end

        function [field_specs, note_text] = phase_boundary_control_specs(~, scenario_id)
            field_specs = struct( ...
                'top', struct('label', 'Base top wall (m/s)', 'editable', true, 'value', 0.0), ...
                'bottom', struct('label', 'Base bottom wall (m/s)', 'editable', true, 'value', 0.0), ...
                'left', struct('label', 'Left wall (fixed)', 'editable', false, 'value', 0.0), ...
                'right', struct('label', 'Right wall (fixed)', 'editable', false, 'value', 0.0));
            note_text = 'Edit the boundary speeds for this scenario. Fixed walls remain shown here for clarity.';
            switch lower(char(string(scenario_id)))
                case 'lid_driven_cavity'
                    field_specs.top = struct('label', 'Base lid speed (m/s)', 'editable', true, 'value', 0.0);
                    field_specs.bottom = struct('label', 'Bottom wall (fixed)', 'editable', false, 'value', 0.0);
                    note_text = 'Top lid is driven. Bottom, left, and right walls remain enclosed no-slip walls.';
                case 'driven_channel_flow'
                    field_specs.top = struct('label', 'Base top speed (m/s)', 'editable', true, 'value', 0.0);
                    field_specs.bottom = struct('label', 'Base bottom speed (m/s)', 'editable', true, 'value', 0.0);
                    field_specs.left = struct('label', 'Left boundary (periodic)', 'editable', false, 'value', 0.0);
                    field_specs.right = struct('label', 'Right boundary (periodic)', 'editable', false, 'value', 0.0);
                    note_text = 'Top and bottom drives are editable. Left and right boundaries stay periodic for the channel case.';
                case 'enclosed_shear_layer'
                    field_specs.top = struct('label', 'Base top speed (m/s)', 'editable', true, 'value', 0.0);
                    field_specs.bottom = struct('label', 'Base bottom speed (m/s)', 'editable', true, 'value', 0.0);
                    note_text = 'Top and bottom wall speeds drive the enclosed shear layer. Left and right walls remain enclosed no-slip walls.';
            end
        end

        function populate_phase3_scenario_row(app, parent_layout, index, scenario, defaults, colors)
            panel = uipanel(parent_layout, ...
                'Title', sprintf('Scenario %d', index), ...
                'BackgroundColor', colors.bg_panel);
