                panel.Scrollable = 'on';
            end
            panel.Layout.Row = index;
            app.handles.(sprintf('phase3_row_%d_panel', index)) = panel;

            grid = uigridlayout(panel, [1, 2]);
            grid.RowHeight = {'1x'};
            grid.ColumnWidth = {'1x', '1x'};
            grid.Padding = [4 4 4 4];
            grid.ColumnSpacing = 8;

            left = uigridlayout(grid, [2, 1]);
            left.Layout.Row = 1;
            left.Layout.Column = 1;
            left.RowHeight = {58, '1x'};
            left.ColumnWidth = {'1x'};
            left.Padding = [0 0 0 0];
            left.RowSpacing = 6;

            top = uigridlayout(left, [2, 2]);
            top.Layout.Row = 1;
            top.Layout.Column = 1;
            top.RowHeight = {18, 30};
            top.ColumnWidth = {'1x', '1x'};
            top.Padding = [0 0 0 0];
