            bc_grid.RowHeight = {26, 88, '1x'};
            bc_grid.ColumnWidth = {'1x', '1x'};
            bc_grid.Padding = [6 6 6 6];
            bc_grid.RowSpacing = 5;
            bc_grid.ColumnSpacing = 6;
            bc_note = uitextarea(bc_grid, 'Editable', 'off', 'BackgroundColor', colors.bg_input, 'FontColor', colors.fg_muted, 'Value', {''});
            bc_note.Layout.Row = 1;
            bc_note.Layout.Column = [1 2];
            app.handles.(sprintf('phase3_scenario_%d_bc_note', index)) = bc_note;
            bc_speed_grid = uigridlayout(bc_grid, [2, 4]);
            bc_speed_grid.Layout.Row = 2;
            bc_speed_grid.Layout.Column = [1 2];
            bc_speed_grid.RowHeight = {26, 26};
            bc_speed_grid.ColumnWidth = {86, '1x', 86, '1x'};
            bc_speed_grid.Padding = [0 0 0 0];
            bc_speed_grid.RowSpacing = 5;
            bc_speed_grid.ColumnSpacing = 6;
            speed_specs = { ...
                'top', 1, 1, 2, app.pick_field(scenario, {'top_speed_mps'}, 0.0); ...
                'bottom', 1, 3, 4, app.pick_field(scenario, {'bottom_speed_mps'}, 0.0); ...
                'left', 2, 1, 2, app.pick_field(scenario, {'left_speed_mps'}, 0.0); ...
                'right', 2, 3, 4, app.pick_field(scenario, {'right_speed_mps'}, 0.0)};
            for si = 1:size(speed_specs, 1)
                key = speed_specs{si, 1};
                lbl = uilabel(bc_speed_grid, 'Text', app.humanize_token(key), 'FontColor', colors.fg_text, 'HorizontalAlignment', 'right');
