            app.refresh_phase3_bc_controls(index);
            app.refresh_phase3_bathymetry_controls(index, defaults, colors);
        end

        function items = phase3_bathymetry_dropdown_items(app, defaults)
            catalog = app.pick_field_required(defaults, {'bathymetry_scenario_catalog_2d'}, struct([]));
            items = cell(1, numel(catalog));
            for i = 1:numel(catalog)
                items{i} = char(string(catalog(i).display_name));
            end
        end

        function label = phase3_bathymetry_id_to_label(app, bathymetry_id, defaults)
            entry = app.find_bathymetry_scenario_entry_by_dimension(bathymetry_id, '2d');
            label = char(string(entry.display_name));
            if nargin >= 3 && ~isempty(defaults) %#ok<INUSD>
                return;
            end
        end

        function bathymetry_id = phase3_bathymetry_label_to_id(app, label, defaults)
            catalog = app.pick_field_required(defaults, {'bathymetry_scenario_catalog_2d'}, struct([]));
            bathymetry_id = 'flat_2d';
            for i = 1:numel(catalog)
                if strcmpi(char(string(catalog(i).display_name)), char(string(label)))
                    bathymetry_id = char(string(catalog(i).id));
                    return;
                end
            end
            entry = app.find_bathymetry_scenario_entry_by_dimension(label, '2d');
            bathymetry_id = char(string(entry.id));
        end

        function entry = find_bathymetry_scenario_entry_by_dimension(app, req, dim)
            catalog = app.get_bathymetry_catalog(dim);
            token = normalize_bathymetry_scenario_token(req);
            idx = find(strcmpi(token, string({catalog.id})), 1, 'first');
            if isempty(idx)
                idx = find(strcmpi(char(string(req)), string({catalog.display_name})), 1, 'first');
            end
            if isempty(idx)
                error('UIController:UnknownBathymetryScenarioByDimension', ...
                    'Unknown %s bathymetry scenario token: %s', dim, char(string(req)));
            end
            entry = catalog(idx);
        end

        function on_phase3_row_selection_changed(app, index, defaults)
            app.refresh_phase3_bc_controls(index);
            app.refresh_phase3_bathymetry_controls(index, defaults, app.layout_cfg.colors);
            app.update_phase3_preview_row(index, defaults);
        end

        function refresh_phase3_bc_controls(app, index)
            scenario_id = app.phase2_scenario_label_to_id(app.safe_text_value( ...
                sprintf('phase3_scenario_%d_bc', index), 'Enclosed Shear Layer'));
            [field_specs, note_text] = app.phase_boundary_control_specs(scenario_id);
            keys = {'top', 'bottom', 'left', 'right'};
            for i = 1:numel(keys)
                key = keys{i};
                lbl_name = sprintf('phase3_scenario_%d_%s_speed_label', index, key);
                field_name = sprintf('phase3_scenario_%d_%s_speed_mps', index, key);
                if ~app.has_valid_handle(lbl_name) || ~app.has_valid_handle(field_name)
                    continue;
                end
                spec = field_specs.(key);
                app.handles.(lbl_name).Text = spec.label;
                app.handles.(field_name).Enable = app.on_off(spec.editable);
                if ~spec.editable
                    app.handles.(field_name).Value = spec.value;
                end
            end
            note_name = sprintf('phase3_scenario_%d_bc_note', index);
            if app.has_valid_handle(note_name)
                app.handles.(note_name).Value = cellstr(string(splitlines(string(note_text))));
            end
        end

        function refresh_phase3_bathymetry_controls(app, index, defaults, colors)
            bathy_label = app.safe_text_value(sprintf('phase3_scenario_%d_bathymetry', index), 'Flat');
            bathy_id = app.phase3_bathymetry_label_to_id(bathy_label, defaults);
            entry = app.find_bathymetry_scenario_entry_by_dimension(bathy_id, '2d');
            prefix = sprintf('phase3_scenario_%d_bathymetry', index);
            seed_state = app.pick_field(app.pick_field_required(defaults, {'phase3'}, struct()), {'scenarios'}, struct([]));
            state = struct();
            if isstruct(seed_state) && numel(seed_state) >= index && isfield(seed_state(index), 'bathymetry_state') && isstruct(seed_state(index).bathymetry_state)
                state = seed_state(index).bathymetry_state;
            end
            if isempty(fieldnames(state))
                state = app.default_bathymetry_state(entry);
            end
            host_name = sprintf('phase3_scenario_%d_bathy_host', index);
            if ~app.has_valid_handle(host_name)
                return;
            end
            app.build_phase_bathymetry_dynamic_controls(app.handles.(host_name), prefix, entry, state, colors, ...
                @(~,~) app.update_phase3_preview_row(index, defaults));
        end

        function build_phase_bathymetry_dynamic_controls(app, parent, prefix, entry, seed_state, colors, callback_fn)
            delete(parent.Children);
            if nargin < 7 || isempty(callback_fn)
                callback_fn = @(~,~) [];
            end
            flags = app.get_bathymetry_shared_flags(entry);
            specs = {};
            if flags.show_bed_slope
                specs{end + 1} = struct('id', 'bed_slope', 'label', 'Bed Slope', 'default', app.pick_field(seed_state, {'bed_slope'}, 0.03), 'limits', [-2.0 2.0], 'integer', false); %#ok<AGROW>
            end
            if flags.show_depth_offset
                specs{end + 1} = struct('id', 'depth_offset', 'label', 'Depth Offset', 'default', app.pick_field(seed_state, {'depth_offset'}, 1000.0), 'limits', [0 1e6], 'integer', false); %#ok<AGROW>
            end
            if flags.show_relief_amplitude
                specs{end + 1} = struct('id', 'relief_amplitude', 'label', 'Relief Amplitude', 'default', app.pick_field(seed_state, {'relief_amplitude'}, 180.0), 'limits', [0 1e6], 'integer', false); %#ok<AGROW>
            end
            if flags.show_resolution
                specs{end + 1} = struct('id', 'interpolation_resolution', 'label', 'Interpolation Resolution', 'default', app.pick_field(seed_state, {'interpolation_resolution'}, 96), 'limits', [24 256], 'integer', true); %#ok<AGROW>
            end
            if isfield(entry, 'dynamic_fields') && ~isempty(entry.dynamic_fields)
                for i = 1:numel(entry.dynamic_fields)
                    field = entry.dynamic_fields(i);
                    specs{end + 1} = struct( ...
                        'id', field.id, ...
                        'label', field.label, ...
                        'default', app.pick_field(seed_state, {field.id}, field.default), ...
                        'limits', field.limits, ...
                        'integer', logical(field.is_integer)); %#ok<AGROW>
                end
            end

            if isempty(specs)
                g = uigridlayout(parent, [1, 1]);
                g.Padding = [6 6 6 6];
                lbl = uilabel(g, 'Text', 'No conditional bathymetry settings are required for the selected model.', 'FontColor', colors.fg_muted);
                if isprop(lbl, 'WordWrap')
                    lbl.WordWrap = 'on';
                end
                return;
            end

            rows = max(1, ceil(numel(specs) / 2));
            g = uigridlayout(parent, [rows, 4]);
            g.RowHeight = repmat({'fit'}, 1, rows);
            g.ColumnWidth = {96, '1x', 96, '1x'};
            g.Padding = [6 6 6 6];
            g.RowSpacing = 5;
            g.ColumnSpacing = 6;
            for i = 1:numel(specs)
                spec = specs{i};
                row = ceil(i / 2);
                slot = mod(i - 1, 2);
                base_col = slot * 2 + 1;
                lbl = uilabel(g, 'Text', spec.label, 'FontColor', colors.fg_text, 'HorizontalAlignment', 'right');
                lbl.Layout.Row = row;
                lbl.Layout.Column = base_col;
                input = uieditfield(g, 'numeric', 'Value', double(spec.default), 'ValueChangedFcn', callback_fn);
                if isnumeric(spec.limits) && numel(spec.limits) == 2
                    input.Limits = double(spec.limits(:)).';
                end
                if logical(spec.integer) && isprop(input, 'RoundFractionalValues')
                    input.RoundFractionalValues = 'on';
                end
                input.Layout.Row = row;
                input.Layout.Column = base_col + 1;
                app.handles.(sprintf('%s_%s', prefix, spec.id)) = input;
            end
        end

        function state = read_phase_bathymetry_state(app, prefix, entry)
            state = app.default_bathymetry_state(entry);
            keys = fieldnames(state);
            for i = 1:numel(keys)
                handle_name = sprintf('%s_%s', prefix, keys{i});
                if app.has_valid_handle(handle_name)
                    state.(keys{i}) = double(app.handles.(handle_name).Value);
                end
            end
        end

        function on_phase3_domain_controls_changed(app)
            use_equal = logical(app.safe_checkbox_value('phase3_domain_equal_mesh', false));
            nx_value = max(2, round(app.safe_numeric_value('phase3_domain_nx', 128)));
            if use_equal && app.has_valid_handle('phase3_domain_ny')
                app.handles.phase3_domain_ny.Value = nx_value;
            end
            if app.has_valid_handle('phase3_domain_ny')
                app.handles.phase3_domain_ny.Enable = app.on_off(~use_equal);
            end
            app.update_all_phase3_previews();
        end

        function update_phase3_preview_row(app, index, defaults)
            ax_name = sprintf('phase3_scenario_%d_axes', index);
            if ~app.has_valid_handle(ax_name)
                return;
            end
            payload = app.build_phase3_preview_payload(index, defaults);
            app.render_phase3_preview_axes(app.handles.(ax_name), payload);
        end

        function update_all_phase3_previews(app)
            defaults = app.layout_cfg.ui_defaults;
            for i = 1:3
                app.update_phase3_preview_row(i, defaults);
            end
        end

        function payload = build_phase3_preview_payload(app, index, defaults)
            phase3 = app.pick_field_required(defaults, {'phase3'}, struct());
            scenario_seed = struct();
            if isfield(phase3, 'scenarios') && isstruct(phase3.scenarios) && numel(phase3.scenarios) >= index
                scenario_seed = phase3.scenarios(index);
            end

            bc_label = app.safe_text_value(sprintf('phase3_scenario_%d_bc', index), ...
                app.phase2_scenario_id_to_label(app.pick_field(scenario_seed, {'bc_id'}, 'enclosed_shear_layer')));
            scenario_id = app.phase2_scenario_label_to_id(bc_label);

            bathy_default_id = app.pick_field(scenario_seed, {'bathymetry_id'}, 'flat_2d');
            bathy_label = app.safe_text_value(sprintf('phase3_scenario_%d_bathymetry', index), ...
                app.phase3_bathymetry_id_to_label(bathy_default_id, defaults));
            bathymetry_id = app.phase3_bathymetry_label_to_id(bathy_label, defaults);
            bathymetry_entry = app.find_bathymetry_scenario_entry_by_dimension(bathymetry_id, '2d');

            Lx = max(1.0e-6, app.safe_numeric_value('phase3_domain_lx', app.pick_field(phase3, {'domain_lx'}, defaults.Lx)));
            Ly = max(1.0e-6, app.safe_numeric_value('phase3_domain_ly', app.pick_field(phase3, {'domain_ly'}, defaults.Ly)));

            bc_params = struct( ...
                'method', 'Finite Difference', ...
                'Lx', Lx, ...
                'Ly', Ly, ...
                'U_top', app.safe_numeric_value(sprintf('phase3_scenario_%d_top_speed_mps', index), app.pick_field(scenario_seed, {'top_speed_mps'}, 0.0)), ...
                'U_bottom', app.safe_numeric_value(sprintf('phase3_scenario_%d_bottom_speed_mps', index), app.pick_field(scenario_seed, {'bottom_speed_mps'}, 0.0)), ...
                'U_left', app.safe_numeric_value(sprintf('phase3_scenario_%d_left_speed_mps', index), app.pick_field(scenario_seed, {'left_speed_mps'}, 0.0)), ...
                'U_right', app.safe_numeric_value(sprintf('phase3_scenario_%d_right_speed_mps', index), app.pick_field(scenario_seed, {'right_speed_mps'}, 0.0)));
            no_slip = app.resolve_bc_display_label('dirichlet', 'no_slip');
            driven = app.resolve_bc_display_label('dirichlet', 'driven');
            switch scenario_id
                case 'lid_driven_cavity'
                    bc_params.bc_top = driven;
                    bc_params.bc_bottom = no_slip;
                    bc_params.bc_left = no_slip;
                    bc_params.bc_right = no_slip;
                case 'driven_channel_flow'
                    bc_params.bc_top = driven;
                    bc_params.bc_bottom = driven;
                    bc_params.bc_left = 'Periodic';
                    bc_params.bc_right = 'Periodic';
                otherwise
                    bc_params.bc_top = driven;
                    bc_params.bc_bottom = driven;
                    bc_params.bc_left = no_slip;
                    bc_params.bc_right = no_slip;
            end

            prefix = sprintf('phase3_scenario_%d_bathymetry', index);
            bathymetry_state = app.read_phase_bathymetry_state(prefix, bathymetry_entry);
            n = min(220, max(72, round(max([app.get_bathymetry_resolution(), 72]))));
            [X, Y] = meshgrid(linspace(-Lx / 2, Lx / 2, n), linspace(-Ly / 2, Ly / 2, n));
            bathy_params = struct( ...
                'bed_slope', double(app.pick_field(bathymetry_state, {'bed_slope'}, 0.03)), ...
                'depth_offset', double(app.pick_field(bathymetry_state, {'depth_offset'}, 1000.0)), ...
                'relief_amplitude', double(app.pick_field(bathymetry_state, {'relief_amplitude'}, 180.0)), ...
                'bathymetry_resolution', round(double(app.pick_field(bathymetry_state, {'interpolation_resolution'}, max(72, n)))), ...
                'bathymetry_custom_points', create_default_bathymetry_control_points(Lx, Ly), ...
                'bathymetry_dynamic_params', struct());
            bathy_params.z0 = bathy_params.depth_offset;
            bathy_params.amplitude = bathy_params.relief_amplitude;
            bathy_params.bathymetry_depth_offset = bathy_params.depth_offset;
            bathy_params.bathymetry_relief_amplitude = bathy_params.relief_amplitude;
            bathy_params.bathymetry_dynamic_params.(bathymetry_entry.id) = bathymetry_state;
            state_keys = fieldnames(bathymetry_state);
            for key_index = 1:numel(state_keys)
                bathy_params.(state_keys{key_index}) = bathymetry_state.(state_keys{key_index});
            end
            [B, meta] = generate_bathymetry_field(X, Y, bathymetry_entry.id, bathy_params);
            profile_x = X(1, :);
            profile_y = B(max(1, round(size(B, 1) / 2)), :);
            if isfield(meta, 'profile_x') && ~isempty(meta.profile_x)
                profile_x = double(meta.profile_x(:)).';
            end
            if isfield(meta, 'profile_y') && ~isempty(meta.profile_y)
                profile_y = double(meta.profile_y(:)).';
            end

            payload = struct( ...
                'bc_label', bc_label, ...
                'bathymetry_label', char(string(bathymetry_entry.display_name)), ...
                'bc_params', bc_params, ...
                'bathymetry_entry', bathymetry_entry, ...
                'bathymetry_state', bathymetry_state, ...
                'bathymetry_payload', struct( ...
                    'X', X, ...
                    'Y', Y, ...
                    'B', B, ...
                    'meta', meta, ...
                    'params', bathy_params, ...
                    'scenario_entry', bathymetry_entry, ...
                    'dimension', '2d', ...
                    'Lx', Lx, ...
                    'Ly', Ly, ...
                    'profile_x', double(profile_x), ...
                    'profile_y', double(profile_y)));
        end

        function render_phase3_preview_axes(app, ax, payload)
            C = app.layout_cfg.colors;
            app.render_bc_overlay_axes(ax, payload.bc_params);
            legend(ax, 'off');
            hold(ax, 'on');
            profile_x = double(payload.bathymetry_payload.profile_x(:)).';
            profile_y = double(payload.bathymetry_payload.profile_y(:)).';
            if ~isempty(profile_x) && ~isempty(profile_y)
                bed_fill_y = (-payload.bathymetry_payload.Ly / 2) * ones(size(profile_x));
                patch(ax, [profile_x, fliplr(profile_x)], [profile_y, fliplr(bed_fill_y)], ...
                    [0.20 0.35 0.48], 'FaceAlpha', 0.16, 'EdgeColor', 'none');
                plot(ax, profile_x, profile_y, 'LineWidth', 2.0, 'Color', [0.36 0.73 0.96]);
            end
            hold(ax, 'off');
            title(ax, sprintf('%s | %s', payload.bc_label, payload.bathymetry_label), ...
                'Color', C.fg_text, 'Interpreter', 'none', 'FontSize', 10);
            xlabel(ax, '');
            ylabel(ax, '');
        end

        function update_phase2_preview_row(app, index)
            ax_name = sprintf('phase2_scenario_%d_axes', index);
            if ~app.has_valid_handle(ax_name)
                return;
            end
            params = app.build_phase2_preview_params(index);
            app.render_bc_overlay_axes(app.handles.(ax_name), params);
            legend(app.handles.(ax_name), 'off');
            title(app.handles.(ax_name), '');
            xlabel(app.handles.(ax_name), '');
            ylabel(app.handles.(ax_name), '');
            grid(app.handles.(ax_name), 'off');
            box(app.handles.(ax_name), 'off');
            app.handles.(ax_name).XTick = [];
            app.handles.(ax_name).YTick = [];
        end

        function update_all_phase2_previews(app)
            for i = 1:3
                app.update_phase2_preview_row(i);
            end
        end

        function params = build_phase2_preview_params(app, index)
            scenario_name = sprintf('phase2_scenario_%d_case', index);
            top_name = sprintf('phase2_scenario_%d_top_speed_mps', index);
            bottom_name = sprintf('phase2_scenario_%d_bottom_speed_mps', index);
            left_name = sprintf('phase2_scenario_%d_left_speed_mps', index);
            right_name = sprintf('phase2_scenario_%d_right_speed_mps', index);
            scenario_id = app.phase2_scenario_label_to_id(app.safe_text_value(scenario_name, 'Enclosed Driven Cavity'));

            no_slip = app.resolve_bc_display_label('dirichlet', 'no_slip');
            driven = app.resolve_bc_display_label('dirichlet', 'driven');
            params = struct( ...
                'method', 'Finite Difference', ...
                'preview_style', 'compact_domain_only', ...
                'Lx', app.safe_numeric_value('Lx', 10), ...
                'Ly', app.safe_numeric_value('Ly', 10), ...
                'U_top', app.safe_numeric_value(top_name, 0), ...
                'U_bottom', app.safe_numeric_value(bottom_name, 0), ...
                'U_left', app.safe_numeric_value(left_name, 0), ...
                'U_right', app.safe_numeric_value(right_name, 0));

            switch scenario_id
                case 'lid_driven_cavity'
                    params.bc_top = driven;
                    params.bc_bottom = no_slip;
                    params.bc_left = no_slip;
                    params.bc_right = no_slip;
                case 'driven_channel_flow'
                    params.bc_top = driven;
                    params.bc_bottom = driven;
                    params.bc_left = 'Periodic';
                    params.bc_right = 'Periodic';
                case 'enclosed_shear_layer'
                    params.bc_top = driven;
                    params.bc_bottom = driven;
                    params.bc_left = no_slip;
                    params.bc_right = no_slip;
                otherwise
                    params.bc_top = 'Periodic';
                    params.bc_bottom = 'Periodic';
                    params.bc_left = 'Periodic';
                    params.bc_right = 'Periodic';
            end
        end

        function sync_phase3_controls_from_global(app)
            if app.has_valid_handle('phase3_domain_nx') && app.has_valid_handle('Nx')
                app.handles.phase3_domain_nx.Value = app.handles.Nx.Value;
            end
            if app.has_valid_handle('phase3_domain_ny') && app.has_valid_handle('Ny')
                app.handles.phase3_domain_ny.Value = app.handles.Ny.Value;
            end
            if app.has_valid_handle('phase3_domain_lx') && app.has_valid_handle('Lx')
                app.handles.phase3_domain_lx.Value = app.handles.Lx.Value;
            end
            if app.has_valid_handle('phase3_domain_ly') && app.has_valid_handle('Ly')
                app.handles.phase3_domain_ly.Value = app.handles.Ly.Value;
            end
            if app.has_valid_handle('phase3_domain_equal_mesh')
                app.handles.phase3_domain_equal_mesh.Value = ...
                    app.safe_numeric_value('Nx', 0) == app.safe_numeric_value('Ny', 1);
            end
            app.on_phase3_domain_controls_changed();
        end

        function apply_phase3_domain_mirror(app)
            app.on_phase3_domain_controls_changed();
        end

        function apply_phase3_bathymetry_mirror(app)
            app.update_all_phase3_previews();
        end

        function mesh_cfg = collect_mesh_convergence_settings_from_ui(app, defaults)
            mesh_cfg = defaults.mesh_convergence;
            start_nx = max(8, round(app.safe_numeric_value('phase1_mesh_start_nx', app.pick_field(mesh_cfg, {'mesh_start_nx'}, 32))));
            start_ny = max(8, round(app.safe_numeric_value('phase1_mesh_start_ny', app.pick_field(mesh_cfg, {'mesh_start_ny'}, 32))));
            final_nx = max(8, round(app.safe_numeric_value('phase1_mesh_final_nx', app.pick_field(mesh_cfg, {'mesh_final_nx'}, 768))));
            final_ny = max(8, round(app.safe_numeric_value('phase1_mesh_final_ny', app.pick_field(mesh_cfg, {'mesh_final_ny'}, 768))));
            mesh_cfg.mesh_start_equal_xy = logical(app.safe_checkbox_value('phase1_mesh_start_equal_xy', app.pick_field(mesh_cfg, {'mesh_start_equal_xy'}, true)));
            mesh_cfg.mesh_final_equal_xy = logical(app.safe_checkbox_value('phase1_mesh_final_equal_xy', app.pick_field(mesh_cfg, {'mesh_final_equal_xy'}, true)));
            mesh_cfg.mesh_start_n = max(8, round(app.safe_numeric_value('phase1_mesh_start_n', max(start_nx, start_ny))));
            mesh_cfg.mesh_start_nx = start_nx;
            mesh_cfg.mesh_start_ny = start_ny;
            mesh_cfg.mesh_final_n = max(8, round(app.safe_numeric_value('phase1_mesh_final_n', max(final_nx, final_ny))));
            mesh_cfg.mesh_final_nx = final_nx;
            mesh_cfg.mesh_final_ny = final_ny;
            mesh_cfg.mesh_level_count = max(2, round(app.safe_numeric_value('phase1_mesh_level_count', app.pick_field(mesh_cfg, {'mesh_level_count'}, 8))));
            mesh_cfg.mesh_ladder_mode = app.safe_text_value('phase1_mesh_ladder_mode', app.pick_field(mesh_cfg, {'mesh_ladder_mode'}, 'bounded'));
            mesh_cfg.mesh_powers_of_two_max_n = max(8, round(double(app.pick_field(mesh_cfg, {'mesh_powers_of_two_max_n'}, 1024))));
            mesh_cfg.convergence_tolerance = max(eps, double(app.safe_numeric_value('phase1_convergence_tolerance', app.pick_field(mesh_cfg, {'convergence_tolerance'}, 1.0))));
            mesh_cfg.ic_preset_id = app.safe_text_value('phase1_mesh_ic_preset', app.pick_field(mesh_cfg, {'ic_preset_id'}, 'elliptical_vortex'));
            mesh_cfg.ic_snapshot = app.build_mesh_convergence_ic_snapshot(mesh_cfg.ic_preset_id);
            [fd_levels, spectral_levels, ladder_meta] = app.build_phase1_mesh_levels_from_ui(mesh_cfg);
            mesh_cfg.mesh_ladder_mode = char(string(ladder_meta.mode));
            mesh_cfg.mesh_powers_of_two_max_n = double(ladder_meta.powers_of_two_max_n);
            mesh_cfg.convergence_mesh_levels_fd = fd_levels;
            mesh_cfg.convergence_mesh_levels_spectral = spectral_levels;
        end

        function phase1 = collect_phase1_settings_from_ui(app, defaults)
            phase1 = defaults.phase1;
            phase1.fd_grid_n = max(8, round(app.safe_numeric_value('phase1_fd_grid_n', app.pick_field(phase1, {'fd_grid_n'}, defaults.Nx))));
            phase1.fd_dt = max(eps, double(app.safe_numeric_value('phase1_fd_dt', app.pick_field(phase1, {'fd_dt'}, defaults.dt))));
            phase1.spectral_grid_n = max(8, round(app.safe_numeric_value('phase1_spectral_grid_n', app.pick_field(phase1, {'spectral_grid_n'}, defaults.Nx))));
            phase1.spectral_dt = max(eps, double(app.safe_numeric_value('phase1_spectral_dt', app.pick_field(phase1, {'spectral_dt'}, defaults.dt))));
            phase1.taylor_green_fd_grid_n = max(8, round(app.safe_numeric_value('phase1_tg_fd_grid_n', app.pick_field(phase1, {'taylor_green_fd_grid_n', 'fd_grid_n'}, phase1.fd_grid_n))));
            phase1.taylor_green_fd_dt = max(eps, double(app.safe_numeric_value('phase1_tg_fd_dt', app.pick_field(phase1, {'taylor_green_fd_dt', 'fd_dt'}, phase1.fd_dt))));
            phase1.taylor_green_spectral_grid_n = max(8, round(app.safe_numeric_value('phase1_tg_spectral_grid_n', app.pick_field(phase1, {'taylor_green_spectral_grid_n', 'spectral_grid_n'}, phase1.spectral_grid_n))));
            phase1.taylor_green_spectral_dt = max(eps, double(app.safe_numeric_value('phase1_tg_spectral_dt', app.pick_field(phase1, {'taylor_green_spectral_dt', 'spectral_dt'}, phase1.spectral_dt))));
            phase1.ic_study = app.pick_field(phase1, {'ic_study'}, struct());
            baseline_ic_type = app.resolve_phase1_baseline_ic_type(phase1.ic_study);
            baseline_meta = app.phase1_baseline_case_metadata(baseline_ic_type);
            phase1.ic_study.baseline_ic_type = baseline_meta.ic_type;
            phase1.ic_study.baseline_label = baseline_meta.label;
            if app.has_valid_handle('phase1_ic_study_case')
                selected_case_id = char(string(app.handles.phase1_ic_study_case.Value));
                if any(strcmpi(selected_case_id, {'baseline_stretched_single', 'baseline_elliptic_single'}))
                    selected_case_id = baseline_meta.case_id;
                end
                phase1.ic_study.selected_case_id = selected_case_id;
                case_cfg = app.resolve_phase1_ic_study_case_from_id(selected_case_id);
                if isstruct(case_cfg) && ~isempty(fieldnames(case_cfg))
                    phase1.ic_study.selected_group = char(string(app.pick_field(case_cfg, {'group_label'}, baseline_meta.group_label)));
                    phase1.ic_study.selected_preset = char(string(app.pick_field(case_cfg, {'label'}, '')));
                end
            else
                phase1.ic_study.selected_case_id = baseline_meta.case_id;
                phase1.ic_study.selected_group = baseline_meta.group_label;
                phase1.ic_study.selected_preset = baseline_meta.label;
            end
            phase1.ic_study.include_arrangement_cases = logical(app.safe_checkbox_value( ...
                'phase1_ic_study_include_arrangements', ...
                app.pick_field(phase1.ic_study, {'include_arrangement_cases'}, false)));
        end

        function baseline_ic_type = resolve_phase1_baseline_ic_type(app, cfg)
            baseline_ic_type = lower(char(string(app.pick_field(cfg, {'baseline_ic_type'}, 'stretched_gaussian'))));
            active_ic_type = '';
            if app.has_valid_handle('ic_dropdown')
                active_ic_type = app.map_ic_display_to_type(app.handles.ic_dropdown.Value);
            elseif isfield(app.config, 'ic_type') && ~isempty(app.config.ic_type)
                active_ic_type = char(string(app.config.ic_type));
            end
            if any(strcmpi(active_ic_type, {'stretched_gaussian', 'elliptical_vortex'}))
                baseline_ic_type = lower(char(string(active_ic_type)));
            end
        end

        function meta = phase1_baseline_case_metadata(~, baseline_ic_type)
            token = lower(strtrim(char(string(baseline_ic_type))));
            switch token
                case {'elliptical_vortex', 'elliptic_vortex', 'elliptic'}
                    meta = struct( ...
                        'ic_type', 'elliptical_vortex', ...
                        'case_id', 'baseline_elliptic_single', ...
                        'label', 'Elliptic', ...
                        'group_label', 'Elliptical Vortex');
                otherwise
                    meta = struct( ...
                        'ic_type', 'stretched_gaussian', ...
                        'case_id', 'baseline_stretched_single', ...
                        'label', 'Stretched Gaussian', ...
                        'group_label', 'Stretched Gaussian');
            end
        end

        function cfg = phase1_ic_study_config(app)
            defaults = create_default_parameters();
            cfg = app.pick_field(app.pick_field_required(defaults, {'phase1'}, struct()), {'ic_study'}, struct());
            current = app.pick_field(app.config, {'phase1'}, struct());
            if isstruct(current) && isfield(current, 'ic_study') && isstruct(current.ic_study)
                cfg = app.overlay_nonempty_struct_fields(cfg, current.ic_study);
            end
            baseline_meta = app.phase1_baseline_case_metadata(app.resolve_phase1_baseline_ic_type(cfg));
            cfg.baseline_ic_type = baseline_meta.ic_type;
            cfg.baseline_label = baseline_meta.label;
            if ~isfield(cfg, 'selected_case_id') || isempty(cfg.selected_case_id) || ...
                    any(strcmpi(char(string(cfg.selected_case_id)), {'baseline_stretched_single', 'baseline_elliptic_single'}))
                cfg.selected_case_id = baseline_meta.case_id;
            else
                cfg.selected_case_id = app.resolve_phase1_ic_study_case_id_from_legacy(cfg);
            end
            if ~isfield(cfg, 'selected_group') || isempty(cfg.selected_group) || ...
                    any(strcmpi(char(string(cfg.selected_group)), {'Stretched Gaussian', 'Elliptical Vortex'}))
                cfg.selected_group = baseline_meta.group_label;
            end
            if ~isfield(cfg, 'selected_preset') || isempty(cfg.selected_preset) || ...
                    any(strcmpi(char(string(cfg.selected_preset)), {'Stretched Gaussian', 'Elliptic'}))
                cfg.selected_preset = baseline_meta.label;
            end
        end

        function [labels, ids] = phase1_ic_study_case_items(app)
            cfg = app.phase1_ic_study_config();
            baseline_meta = app.phase1_baseline_case_metadata(app.pick_field(cfg, {'baseline_ic_type'}, 'stretched_gaussian'));
            labels = {char(string(app.pick_field(cfg, {'baseline_label'}, baseline_meta.label)))};
            ids = {baseline_meta.case_id};
            catalog = app.pick_field(cfg, {'catalog'}, struct([]));
            if isstruct(catalog) && ~isempty(catalog)
                labels = [labels, cellstr(string({catalog.label}))]; %#ok<AGROW>
                ids = [ids, cellstr(string({catalog.case_id}))]; %#ok<AGROW>
            end
        end

        function case_id = resolve_phase1_ic_study_case_id_from_legacy(app, cfg)
            baseline_meta = app.phase1_baseline_case_metadata(app.resolve_phase1_baseline_ic_type(cfg));
            case_id = baseline_meta.case_id;
            if nargin < 2 || ~isstruct(cfg)
                return;
            end
            selected_preset = char(string(app.pick_field(cfg, {'selected_preset'}, '')));
            catalog = app.pick_field(cfg, {'catalog'}, struct([]));
            if isstruct(catalog) && ~isempty(catalog)
                idx = find(strcmpi({catalog.label}, selected_preset), 1, 'first');
                if ~isempty(idx)
                    case_id = char(string(catalog(idx).case_id));
                end
            end
        end

        function case_cfg = resolve_phase1_ic_study_case_from_id(app, case_id)
            case_id = lower(char(string(case_id)));
            cfg = app.phase1_ic_study_config();
            if any(strcmp(case_id, {'baseline_stretched_single', 'baseline_elliptic_single'}))
                case_cfg = app.phase1_baseline_ic_study_case(cfg, case_id);
                return;
            end
            catalog = app.pick_field(cfg, {'catalog'}, struct([]));
            case_cfg = struct();
            if ~isstruct(catalog) || isempty(catalog)
                return;
            end
            idx = find(strcmpi({catalog.case_id}, case_id), 1, 'first');
            if ~isempty(idx)
                case_cfg = catalog(idx);
            end
        end

        function case_cfg = phase1_baseline_ic_study_case(app, cfg, case_id_override)
            defaults = create_default_parameters();
            if nargin < 3
                case_id_override = '';
            end
            if strcmpi(char(string(case_id_override)), 'baseline_elliptic_single')
                baseline_meta = app.phase1_baseline_case_metadata('elliptical_vortex');
            else
                baseline_meta = app.phase1_baseline_case_metadata(app.pick_field(cfg, {'baseline_ic_type'}, 'stretched_gaussian'));
            end
            if isempty(strtrim(char(string(case_id_override))))
                baseline_label = app.pick_field(cfg, {'baseline_label'}, baseline_meta.label);
            else
                baseline_label = baseline_meta.label;
            end
            center_x = double(app.pick_field(defaults, {'ic_center_x'}, 0.0));
            center_y = double(app.pick_field(defaults, {'ic_center_y'}, 0.0));
            scale = double(app.pick_field(defaults, {'ic_scale'}, 1.0));
            amplitude = double(app.pick_field(defaults, {'ic_amplitude'}, 1.0));
            stretched_dyn_defaults = app.pick_field(defaults, {'ic_dynamic_values'}, struct('stretch_x', 2.15, 'stretch_y', 0.18));
            elliptic_dyn_defaults = app.pick_field(defaults, {'reference_calibration_presets', 'elliptical_vortex', 'dynamic_overrides'}, ...
                struct('peak_vorticity', 1.0, 'sigma_x', 1.0 / sqrt(2.0 * 2.15), 'sigma_y', 1.0 / sqrt(2.0 * 0.18), 'rotation_theta', 0.0));
            if strcmpi(baseline_meta.ic_type, 'elliptical_vortex')
                runtime_overrides = struct( ...
                    'ic_scenario', char(string(baseline_label)), ...
                    'ic_coeff', [ ...
                        double(app.pick_field(elliptic_dyn_defaults, {'peak_vorticity'}, 1.0)) * scale, ...
                        double(app.pick_field(elliptic_dyn_defaults, {'sigma_x'}, 1.0 / sqrt(2.0 * 2.15))), ...
                        double(app.pick_field(elliptic_dyn_defaults, {'sigma_y'}, 1.0 / sqrt(2.0 * 0.18))), ...
                        double(app.pick_field(elliptic_dyn_defaults, {'rotation_theta'}, 0.0)), ...
                        center_x, center_y], ...
                    'ic_dynamic_values', elliptic_dyn_defaults, ...
                    'ic_center_x', center_x, ...
                    'ic_center_y', center_y, ...
                    'ic_scale', scale, ...
                    'ic_amplitude', amplitude, ...
                    'ic_count', 1, ...
                    'ic_pattern', 'single', ...
                    'ic_arrangement', 'single', ...
                    'ic_multi_vortex_experimental', false, ...
                    'ic_multi_vortex_rows', struct([]));
            else
                runtime_overrides = struct( ...
                    'ic_scenario', char(string(baseline_label)), ...
                    'ic_coeff', [ ...
                        double(app.pick_field(stretched_dyn_defaults, {'stretch_x'}, 2.15)), ...
                        double(app.pick_field(stretched_dyn_defaults, {'stretch_y'}, 0.18)), ...
                        scale * amplitude, 0.0, center_x, center_y], ...
                    'ic_dynamic_values', stretched_dyn_defaults, ...
                    'ic_center_x', center_x, ...
                    'ic_center_y', center_y, ...
                    'ic_scale', scale, ...
                    'ic_amplitude', amplitude, ...
                    'ic_count', 1, ...
                    'ic_pattern', 'single', ...
                    'ic_arrangement', 'single', ...
                    'ic_multi_vortex_experimental', false, ...
                    'ic_multi_vortex_rows', struct([]));
            end
            case_cfg = struct( ...
                'case_id', baseline_meta.case_id, ...
                'label', char(string(baseline_label)), ...
                'group_label', baseline_meta.group_label, ...
                'ic_type', baseline_meta.ic_type, ...
                'runtime_overrides', runtime_overrides);
        end

        function items = phase1_ic_study_group_items(app)
            cfg = app.phase1_ic_study_config();
            groups = app.pick_field(cfg, {'groups'}, struct([]));
            items = {};
            if isstruct(groups) && ~isempty(groups)
                items = cellstr(string({groups.label}));
            end
        end

        function items = phase1_ic_study_presets_for_group(app, group_label)
            cfg = app.phase1_ic_study_config();
            groups = app.pick_field(cfg, {'groups'}, struct([]));
            items = {};
            if ~isstruct(groups) || isempty(groups)
                return;
            end
            idx = find(strcmpi({groups.label}, char(string(group_label))), 1, 'first');
            if isempty(idx)
                return;
            end
            items = cellstr(string(groups(idx).presets));
        end

        function case_cfg = resolve_phase1_ic_study_case_from_selection(app, group_label, preset_label)
            cfg = app.phase1_ic_study_config();
            catalog = app.pick_field(cfg, {'catalog'}, struct([]));
            case_cfg = struct();
            if ~isstruct(catalog) || isempty(catalog)
                return;
            end
            preset_label = char(string(preset_label));
            group_label = char(string(group_label));
            idx = find(strcmpi({catalog.label}, preset_label), 1, 'first');
            if isempty(idx)
                idx = find(strcmpi({catalog.group_label}, group_label), 1, 'first');
            end
            if ~isempty(idx)
                case_cfg = catalog(idx);
            end
        end

        function on_phase1_ic_study_case_changed(app)
            if ~isfield(app.config, 'phase1') || ~isstruct(app.config.phase1)
                app.config.phase1 = struct();
            end
            if ~isfield(app.config.phase1, 'ic_study') || ~isstruct(app.config.phase1.ic_study)
                app.config.phase1.ic_study = struct();
            end
            if app.has_valid_handle('phase1_ic_study_case')
                selected_case_id = char(string(app.handles.phase1_ic_study_case.Value));
                app.config.phase1.ic_study.selected_case_id = selected_case_id;
                case_cfg = app.resolve_phase1_ic_study_case_from_id(selected_case_id);
                if isstruct(case_cfg) && ~isempty(fieldnames(case_cfg))
                    app.config.phase1.ic_study.selected_group = char(string(app.pick_field(case_cfg, {'group_label'}, 'Stretched Gaussian')));
                    app.config.phase1.ic_study.selected_preset = char(string(app.pick_field(case_cfg, {'label'}, '')));
                end
            end
            app.refresh_phase1_ic_study_preview();
        end

        function on_phase1_ic_study_group_changed(app)
            if ~app.has_valid_handle('phase1_ic_study_group') || ~app.has_valid_handle('phase1_ic_study_preset')
                return;
            end
            group_label = char(string(app.handles.phase1_ic_study_group.Value));
            preset_items = app.phase1_ic_study_presets_for_group(group_label);
            if isempty(preset_items)
                preset_items = {'Taylor-Green'};
            end
            current_value = char(string(app.handles.phase1_ic_study_preset.Value));
            if ~any(strcmpi(current_value, preset_items))
                current_value = char(string(preset_items{1}));
            end
            app.handles.phase1_ic_study_preset.Items = preset_items;
            app.handles.phase1_ic_study_preset.Value = current_value;
            if ~isfield(app.config, 'phase1') || ~isstruct(app.config.phase1)
                app.config.phase1 = struct();
            end
            if ~isfield(app.config.phase1, 'ic_study') || ~isstruct(app.config.phase1.ic_study)
                app.config.phase1.ic_study = struct();
            end
            app.config.phase1.ic_study.selected_group = group_label;
            app.config.phase1.ic_study.selected_preset = current_value;
            app.refresh_phase1_ic_study_preview();
        end

        function on_phase1_ic_study_preset_changed(app)
            if ~isfield(app.config, 'phase1') || ~isstruct(app.config.phase1)
                app.config.phase1 = struct();
            end
            if ~isfield(app.config.phase1, 'ic_study') || ~isstruct(app.config.phase1.ic_study)
                app.config.phase1.ic_study = struct();
            end
            if app.has_valid_handle('phase1_ic_study_group')
                app.config.phase1.ic_study.selected_group = char(string(app.handles.phase1_ic_study_group.Value));
            end
            if app.has_valid_handle('phase1_ic_study_preset')
                app.config.phase1.ic_study.selected_preset = char(string(app.handles.phase1_ic_study_preset.Value));
            end
            app.refresh_phase1_ic_study_preview();
        end

        function refresh_phase1_ic_study_preview(app)
            if ~app.has_valid_handle('phase1_ic_study_preview_axes')
                return;
            end
            ax = app.handles.phase1_ic_study_preview_axes;
            cla(ax);
            case_cfg = struct();
            if app.has_valid_handle('phase1_ic_study_case')
                case_cfg = app.resolve_phase1_ic_study_case_from_id(app.handles.phase1_ic_study_case.Value);
            elseif isfield(app.config, 'phase1') && isstruct(app.config.phase1)
                ic_cfg = app.pick_field(app.config.phase1, {'ic_study'}, struct());
                case_cfg = app.resolve_phase1_ic_study_case_from_id(app.pick_field(ic_cfg, {'selected_case_id'}, 'baseline_stretched_single'));
            end
            if ~isstruct(case_cfg) || isempty(fieldnames(case_cfg))
                title(ax, 'IC study preview unavailable', 'Color', app.layout_cfg.colors.fg_text);
                return;
            end
            payload = app.build_phase1_ic_study_preview_payload(case_cfg);
            app.render_ic_preview_axes(ax, payload, false);
        end

        function payload = build_phase1_ic_study_preview_payload(app, case_cfg)
            overrides = app.pick_field(case_cfg, {'runtime_overrides'}, struct());
            ic_type = lower(char(string(app.pick_field(case_cfg, {'ic_type'}, app.pick_field(overrides, {'ic_type'}, 'elliptical_vortex')))));
            schema = app.get_ic_schema(ic_type);
            [X, Y, Lx, Ly] = app.build_ic_preview_grid();
            shared = app.get_ic_shared_defaults();
            shared.center_x = double(app.pick_field(overrides, {'ic_center_x'}, app.pick_field(shared, {'center_x'}, 0.0)));
            shared.center_y = double(app.pick_field(overrides, {'ic_center_y'}, app.pick_field(shared, {'center_y'}, 0.0)));
            shared.scale = double(app.pick_field(overrides, {'ic_scale'}, app.pick_field(shared, {'scale'}, 1.0)));
            shared.count = max(1, round(double(app.pick_field(overrides, {'ic_count'}, app.pick_field(shared, {'count'}, 1)))));
            shared.amplitude = double(app.pick_field(overrides, {'ic_amplitude'}, app.pick_field(shared, {'amplitude'}, 1.0)));
            shared.pattern = char(string(app.pick_field(overrides, {'ic_pattern', 'ic_arrangement'}, 'single')));
            shared.arrangement = shared.pattern;
            dyn = app.default_dynamic_values(schema);
            dyn = app.merge_ic_preview_state(dyn, app.pick_field(overrides, {'ic_dynamic_values'}, struct()));
            rows = app.pick_field(overrides, {'ic_multi_vortex_rows'}, struct([]));
            used_structured_rows = false;
            if ~isempty(rows) && isfield(schema, 'supports_multi_vortex') && logical(schema.supports_multi_vortex)
                % Phase 1 case previews must render the selected case payload directly,
                % rather than depending on the global IC editor's multi-vortex state.
                rows = app.normalize_multi_vortex_rows(rows, ic_type);
                if ~isempty(rows)
                    Z = app.evaluate_multi_vortex_rows(X, Y, rows, ic_type);
                    used_structured_rows = true;
                end
            end
            if ~used_structured_rows
                ic_coeff = app.pack_ic_coeff_from_values(ic_type, schema, shared, dyn);
                Z = ICDispatcher.evaluate_catalog(X, Y, ic_type, ic_coeff);
            end
            equation_tex = char(string(app.pick_field(schema, {'equation_tex'}, '\omega(x,y)')));
            equation_tex = regexprep(equation_tex, '\\left|\\right', '');
            equation_tex = regexprep(equation_tex, '\\begin\{cases\}', '');
            equation_tex = regexprep(equation_tex, '\\end\{cases\}', '');
            equation_tex = strrep(equation_tex, '\\\\', '; ');
            show_position_marker = false;
            if isfield(schema, 'shared_flags') && isstruct(schema.shared_flags) && isfield(schema.shared_flags, 'show_position')
                show_position_marker = logical(schema.shared_flags.show_position) && ~used_structured_rows;
            end
            payload = struct( ...
                'ic_type', ic_type, ...
                'ic_display', char(string(app.pick_field(case_cfg, {'label'}, schema.display_name))), ...
                'equation_tex', equation_tex, ...
                'schema', schema, ...
                'X', X, ...
                'Y', Y, ...
                'Z', Z, ...
                'Lx', double(Lx), ...
                'Ly', double(Ly), ...
                'shared', shared, ...
                'dynamic', dyn, ...
                'show_position_marker', show_position_marker, ...
                'used_structured_rows', used_structured_rows);
        end

        function ic_snapshot = build_phase1_launch_ic_snapshot(app)
            [active_ic_type, active_schema] = app.resolve_active_ic_type();
            ic_state = app.collect_ic_state(active_schema);
            ic_snapshot = struct( ...
                'ic_type', char(string(active_ic_type)), ...
                'ic_scenario', char(string(app.pick_field(app.config, {'ic_scenario'}, 'Manual'))), ...
                'ic_coeff', double(app.build_ic_coeff_vector(active_ic_type)), ...
                'ic_dynamic_values', ic_state.ic_dynamic_values, ...
                'ic_center_x', double(ic_state.ic_center_x), ...
                'ic_center_y', double(ic_state.ic_center_y), ...
                'ic_scale', double(ic_state.ic_scale), ...
                'ic_pattern', char(string(ic_state.ic_pattern)), ...
                'ic_arrangement', char(string(ic_state.ic_arrangement)), ...
                'ic_count', max(1, round(double(ic_state.ic_count))), ...
                'ic_amplitude', double(ic_state.ic_amplitude), ...
                'ic_coeff1', double(ic_state.ic_coeff1), ...
                'ic_coeff2', double(ic_state.ic_coeff2), ...
                'ic_coeff3', double(ic_state.ic_coeff3), ...
                'ic_coeff4', double(ic_state.ic_coeff4), ...
                'ic_multi_vortex_rows', app.normalize_multi_vortex_rows( ...
                    app.pick_field(app.config, {'ic_multi_vortex_rows'}, struct([])), active_ic_type));
        end

        function [labels, ids] = mesh_convergence_ic_preset_items(~)
            labels = {'Calibrated Elliptic Gaussian', 'Taylor-Green'};
            ids = {'elliptical_vortex', 'taylor_green'};
        end

        function case_cfg = resolve_mesh_convergence_ic_case(app, preset_id)
            preset_id = lower(char(string(preset_id)));
            switch preset_id
                case {'elliptic_vortex', 'elliptic', 'elliptical'}
                    case_cfg = app.phase1_baseline_ic_study_case(struct('baseline_ic_type', 'elliptical_vortex'), 'baseline_elliptic_single');
                case 'taylor_green'
                    case_cfg = app.resolve_phase1_ic_study_case_from_id('taylor_green');
                otherwise
                    case_cfg = struct();
            end
            if ~isstruct(case_cfg) || isempty(fieldnames(case_cfg))
                case_cfg = app.phase1_baseline_ic_study_case(struct('baseline_ic_type', 'elliptical_vortex'), 'baseline_elliptic_single');
            end
        end

        function ic_snapshot = build_mesh_convergence_ic_snapshot(app, preset_id)
            case_cfg = app.resolve_mesh_convergence_ic_case(preset_id);
            overrides = app.pick_field(case_cfg, {'runtime_overrides'}, struct());
            ic_snapshot = struct('ic_type', char(string(app.pick_field(case_cfg, {'ic_type'}, 'elliptical_vortex'))));
            if isstruct(overrides) && ~isempty(fieldnames(overrides))
                ic_snapshot = merge_structs(ic_snapshot, overrides);
            end
        end

        function cfg = apply_phase1_ic_snapshot_to_config(app, cfg, ic_snapshot)
            if nargin < 3 || ~isstruct(ic_snapshot) || ~isstruct(cfg)
                return;
            end

            text_fields = {'ic_type', 'ic_scenario', 'ic_pattern', 'ic_arrangement'};
            for i = 1:numel(text_fields)
                key = text_fields{i};
                if isfield(ic_snapshot, key) && ~isempty(ic_snapshot.(key))
                    cfg.(key) = char(string(ic_snapshot.(key)));
                end
            end

            numeric_fields = {'ic_center_x', 'ic_center_y', 'ic_scale', 'ic_amplitude', ...
                'ic_coeff1', 'ic_coeff2', 'ic_coeff3', 'ic_coeff4'};
            for i = 1:numel(numeric_fields)
                key = numeric_fields{i};
                if isfield(ic_snapshot, key) && isnumeric(ic_snapshot.(key)) && isscalar(ic_snapshot.(key)) && ...
                        isfinite(ic_snapshot.(key))
                    cfg.(key) = double(ic_snapshot.(key));
                end
            end

            if isfield(ic_snapshot, 'ic_count') && isnumeric(ic_snapshot.ic_count) && isscalar(ic_snapshot.ic_count) && ...
                    isfinite(ic_snapshot.ic_count)
                cfg.ic_count = max(1, round(double(ic_snapshot.ic_count)));
            end
            if isfield(ic_snapshot, 'ic_coeff') && isnumeric(ic_snapshot.ic_coeff)
                cfg.ic_coeff = double(ic_snapshot.ic_coeff(:).');
            end
            if isfield(ic_snapshot, 'ic_dynamic_values') && isstruct(ic_snapshot.ic_dynamic_values)
                cfg.ic_dynamic_values = ic_snapshot.ic_dynamic_values;
            end
            if isfield(ic_snapshot, 'ic_multi_vortex_rows')
                cfg.ic_multi_vortex_rows = ic_snapshot.ic_multi_vortex_rows;
            end
        end

        function [fd_levels, spectral_levels, ladder_meta] = build_phase1_mesh_levels_from_ui(~, phase1)
            [fd_levels, ladder_meta] = Phase1MeshLadder(phase1);
            spectral_levels = fd_levels;
        end

        function levels = build_phase1_mesh_ladder(~, start_n, final_n, count)
            phase1 = struct( ...
                'mesh_start_equal_xy', true, ...
                'mesh_start_n', start_n, ...
                'mesh_final_equal_xy', true, ...
                'mesh_final_n', final_n, ...
                'mesh_level_count', count, ...
                'mesh_ladder_mode', 'bounded', ...
                'mesh_powers_of_two_max_n', 1024);
            levels = Phase1MeshLadder(phase1);
        end

        function phase2 = collect_phase2_settings_from_ui(app, defaults)
            phase2 = defaults.phase2;
            phase2.fd_grid_n = max(8, round(app.safe_numeric_value('phase2_fd_grid_n', app.pick_field(phase2, {'fd_grid_n'}, defaults.Nx))));
            phase2.fd_dt = max(eps, double(app.safe_numeric_value('phase2_fd_dt', app.pick_field(phase2, {'fd_dt'}, defaults.dt))));
            phase2.taylor_green_fd_grid_n = max(8, round(app.safe_numeric_value('phase2_tg_fd_grid_n', app.pick_field(phase2, {'taylor_green_fd_grid_n', 'fd_grid_n'}, phase2.fd_grid_n))));
            phase2.taylor_green_fd_dt = max(eps, double(app.safe_numeric_value('phase2_tg_fd_dt', app.pick_field(phase2, {'taylor_green_fd_dt'}, phase2.fd_dt))));
            phase2.taylor_green_honor_fixed_dt = true;
            phase2.scenarios = repmat(phase2.scenarios(1), 1, 3);
            for i = 1:3
                phase2.scenarios(i).id = app.phase2_scenario_label_to_id(app.safe_text_value(sprintf('phase2_scenario_%d_case', i), ...
                    app.phase2_scenario_id_to_label(phase2.scenarios(i).id)));
                phase2.scenarios(i).label = app.phase2_scenario_id_to_label(phase2.scenarios(i).id);
                phase2.scenarios(i).top_speed_mps = app.safe_numeric_value(sprintf('phase2_scenario_%d_top_speed_mps', i), 0.0);
                phase2.scenarios(i).bottom_speed_mps = app.safe_numeric_value(sprintf('phase2_scenario_%d_bottom_speed_mps', i), 0.0);
                phase2.scenarios(i).left_speed_mps = app.safe_numeric_value(sprintf('phase2_scenario_%d_left_speed_mps', i), 0.0);
                phase2.scenarios(i).right_speed_mps = app.safe_numeric_value(sprintf('phase2_scenario_%d_right_speed_mps', i), 0.0);
            end
        end

        function phase3 = collect_phase3_settings_from_ui(app, defaults)
            phase3 = defaults.phase3;
            phase3.domain_equal_mesh = logical(app.safe_checkbox_value('phase3_domain_equal_mesh', app.pick_field(phase3, {'domain_equal_mesh'}, false)));
            phase3.domain_nx = max(2, round(app.safe_numeric_value('phase3_domain_nx', app.pick_field(phase3, {'domain_nx'}, defaults.Nx))));
            phase3.domain_ny = max(2, round(app.safe_numeric_value('phase3_domain_ny', app.pick_field(phase3, {'domain_ny'}, defaults.Ny))));
            if logical(phase3.domain_equal_mesh)
                phase3.domain_ny = phase3.domain_nx;
            end
            phase3.domain_lx = max(1e-9, app.safe_numeric_value('phase3_domain_lx', app.pick_field(phase3, {'domain_lx'}, defaults.Lx)));
            phase3.domain_ly = max(1e-9, app.safe_numeric_value('phase3_domain_ly', app.pick_field(phase3, {'domain_ly'}, defaults.Ly)));
            if ~isfield(phase3, 'scenarios') || ~isstruct(phase3.scenarios) || isempty(phase3.scenarios)
                error('UIController:MissingPhase3ScenarioDefaults', ...
                    'create_default_parameters.phase3 must define scenario defaults.');
            end
            base_scenarios = phase3.scenarios;
            phase3.scenarios = repmat(base_scenarios(1), 1, 3);
            for i = 1:numel(phase3.scenarios)
                base = base_scenarios(min(i, numel(base_scenarios)));
                bc_id = app.phase2_scenario_label_to_id(app.safe_text_value( ...
                    sprintf('phase3_scenario_%d_bc', i), ...
                    app.phase2_scenario_id_to_label(app.pick_field(base, {'bc_id'}, 'enclosed_shear_layer'))));
                bathy_id = app.phase3_bathymetry_label_to_id(app.safe_text_value( ...
                    sprintf('phase3_scenario_%d_bathymetry', i), ...
                    app.phase3_bathymetry_id_to_label(app.pick_field(base, {'bathymetry_id'}, 'flat_2d'), defaults)), defaults);
                bathy_entry = app.find_bathymetry_scenario_entry_by_dimension(bathy_id, '2d');
                phase3.scenarios(i) = base;
                phase3.scenarios(i).bc_id = bc_id;
                phase3.scenarios(i).bc_label = app.phase2_scenario_id_to_label(bc_id);
                phase3.scenarios(i).bathymetry_id = bathy_id;
                phase3.scenarios(i).bathymetry_label = char(string(bathy_entry.display_name));
                phase3.scenarios(i).top_speed_mps = app.safe_numeric_value(sprintf('phase3_scenario_%d_top_speed_mps', i), app.pick_field(base, {'top_speed_mps'}, 0.0));
                phase3.scenarios(i).bottom_speed_mps = app.safe_numeric_value(sprintf('phase3_scenario_%d_bottom_speed_mps', i), app.pick_field(base, {'bottom_speed_mps'}, 0.0));
                phase3.scenarios(i).left_speed_mps = app.safe_numeric_value(sprintf('phase3_scenario_%d_left_speed_mps', i), app.pick_field(base, {'left_speed_mps'}, 0.0));
                phase3.scenarios(i).right_speed_mps = app.safe_numeric_value(sprintf('phase3_scenario_%d_right_speed_mps', i), app.pick_field(base, {'right_speed_mps'}, 0.0));
                phase3.scenarios(i).bathymetry_state = app.read_phase_bathymetry_state(sprintf('phase3_scenario_%d_bathymetry', i), bathy_entry);
                if strcmpi(char(string(app.pick_field(base, {'bathymetry_id'}, ''))), bathy_id)
                    phase3.scenarios(i).label = char(string(app.pick_field(base, {'label'}, phase3.scenarios(i).bathymetry_label)));
                else
                    phase3.scenarios(i).label = phase3.scenarios(i).bathymetry_label;
                end
            end
            if ~isempty(phase3.scenarios)
                phase3.bathymetry_scenario = char(string(app.pick_field(phase3.scenarios(1), {'bathymetry_id'}, 'flat_2d')));
            else
                phase3.bathymetry_scenario = 'flat_2d';
            end
            phase3.bathymetry_points_button_text = 'Phase 3 bathymetry settings are edited per scenario row.';
        end

        function txt = safe_text_value(app, handle_name, default_txt)
            txt = default_txt;
            if app.has_valid_handle(handle_name)
                txt = char(string(app.handles.(handle_name).Value));
            end
        end

        function val = safe_checkbox_value(app, handle_name, default_val)
            val = default_val;
            if app.has_valid_handle(handle_name)
                val = logical(app.handles.(handle_name).Value);
            end
        end

        function on_phase_placeholder_button(app, phase_label)
            phase_label = char(string(phase_label));
            if any(strcmpi(phase_label, {'Mesh Convergence', 'Phase 1', 'Phase 2', 'Phase 3'}))
                cfg = app.build_phase_launch_config(phase_label);
                app.launch_simulation(cfg);
                return;
            end
            msg = sprintf('%s workflow placeholder: no action is wired yet.', phase_label);
            app.append_to_terminal(msg, 'info');
            app.set_ic_preview_export_status(msg, app.layout_cfg.colors.fg_muted);
        end

        function cfg = build_phase_launch_config(app, phase_label)
            app.collect_configuration_from_ui();
            cfg = app.config;
            phase_label = char(string(phase_label));

            switch lower(strtrim(phase_label))
                case 'mesh convergence'
                    cfg.method = 'Finite Difference';
                    cfg.analysis_method = 'Finite Difference';
                    cfg.mode = 'evolution';
                    cfg.run_mode_internal = 'Evolution';
                    cfg.time_integrator = 'RK4';
                    cfg.workflow_kind = 'mesh_convergence_study';
                    cfg.phase_label = 'Mesh Convergence';
                    cfg.launch_origin = 'phase_button';
                    cfg.result_layout_kind = 'mesh_convergence_workflow';
                    cfg.phase_id = sprintf('mesh_convergence_%s_%s', ...
                        regexprep(char(string(cfg.ic_type)), '[^a-zA-Z0-9]+', '_'), ...
                        char(datetime('now', 'Format', 'yyyyMMdd_HHmmss')));
                    cfg.bc_case = 'periodic';
                    cfg.boundary_condition_case = 'periodic';
                    cfg.bc_top = 'Periodic';
                    cfg.bc_bottom = 'Periodic';
                    cfg.bc_left = 'Periodic';
                    cfg.bc_right = 'Periodic';
                    cfg.bc_top_math = 'periodic';
                    cfg.bc_bottom_math = 'periodic';
                    cfg.bc_left_math = 'periodic';
                    cfg.bc_right_math = 'periodic';
                    cfg.bc_top_physical = 'periodic';
                    cfg.bc_bottom_physical = 'periodic';
                    cfg.bc_left_physical = 'periodic';
                    cfg.bc_right_physical = 'periodic';
                    cfg.U_top = 0.0;
                    cfg.U_bottom = 0.0;
                    cfg.U_left = 0.0;
                    cfg.U_right = 0.0;
                    cfg.bathymetry_scenario = 'flat_2d';
                    cfg.bathymetry_dimension_policy = 'by_method';
                    if ~isfield(cfg, 'mesh_convergence') || ~isstruct(cfg.mesh_convergence)
                        defaults = app.initialize_default_config();
                        if ~isfield(defaults, 'mesh_convergence') || ~isstruct(defaults.mesh_convergence)
                            error('UIController:MissingMeshConvergenceDefaults', ...
                                'create_default_parameters must define mesh_convergence defaults.');
                        end
                        cfg.mesh_convergence = defaults.mesh_convergence;
                    end
                    cfg.mesh_convergence.ic_preset_id = char(string(app.pick_field(cfg.mesh_convergence, {'ic_preset_id'}, 'elliptical_vortex')));
                    cfg.mesh_convergence.ic_snapshot = app.build_mesh_convergence_ic_snapshot(cfg.mesh_convergence.ic_preset_id);
                    cfg = app.apply_phase1_ic_snapshot_to_config(cfg, cfg.mesh_convergence.ic_snapshot);
                    cfg.phase_id = sprintf('mesh_convergence_%s_%s', ...
                        regexprep(char(string(cfg.ic_type)), '[^a-zA-Z0-9]+', '_'), ...
                        char(datetime('now', 'Format', 'yyyyMMdd_HHmmss')));
                    cfg = app.normalize_workflow_launch_config(cfg);
                    cfg = app.apply_lightweight_workflow_launch_policy(cfg);
                case 'phase 1'
                    cfg.method = 'Finite Difference';
                    cfg.analysis_method = 'Finite Difference';
                    cfg.mode = 'evolution';
                    cfg.run_mode_internal = 'Evolution';
                    cfg.time_integrator = 'RK4';
                    cfg.workflow_kind = 'phase1_periodic_comparison';
                    cfg.phase_label = 'Phase 1';
                    cfg.launch_origin = 'phase_button';
                    cfg.result_layout_kind = 'phase1_workflow';
                    cfg.phase_id = sprintf('phase1_%s_%s', ...
                        regexprep(char(string(cfg.ic_type)), '[^a-zA-Z0-9]+', '_'), ...
                        char(datetime('now', 'Format', 'yyyyMMdd_HHmmss')));
                    cfg.bc_case = 'periodic';
                    cfg.boundary_condition_case = 'periodic';
                    cfg.bc_top = 'Periodic';
                    cfg.bc_bottom = 'Periodic';
                    cfg.bc_left = 'Periodic';
                    cfg.bc_right = 'Periodic';
                    cfg.bc_top_math = 'periodic';
                    cfg.bc_bottom_math = 'periodic';
                    cfg.bc_left_math = 'periodic';
                    cfg.bc_right_math = 'periodic';
                    cfg.bc_top_physical = 'periodic';
                    cfg.bc_bottom_physical = 'periodic';
                    cfg.bc_left_physical = 'periodic';
                    cfg.bc_right_physical = 'periodic';
                    cfg.U_top = 0.0;
                    cfg.U_bottom = 0.0;
                    cfg.U_left = 0.0;
                    cfg.U_right = 0.0;
                    cfg.bathymetry_scenario = 'flat_2d';
                    cfg.bathymetry_dimension_policy = 'by_method';
                    if ~isfield(cfg, 'phase1') || ~isstruct(cfg.phase1)
                        defaults = app.initialize_default_config();
                        if ~isfield(defaults, 'phase1') || ~isstruct(defaults.phase1)
                            error('UIController:MissingPhase1Defaults', ...
                                'create_default_parameters must define phase1 defaults.');
                        end
                        cfg.phase1 = defaults.phase1;
                    end
                    cfg.phase1.ic_snapshot = app.build_phase1_launch_ic_snapshot();
                    cfg = app.apply_phase1_ic_snapshot_to_config(cfg, cfg.phase1.ic_snapshot);
                    cfg = app.normalize_workflow_launch_config(cfg);
                    cfg = app.apply_lightweight_workflow_launch_policy(cfg);
                case 'phase 2'
                    cfg.method = 'Finite Difference';
                    cfg.analysis_method = 'Finite Difference';
                    cfg.mode = 'evolution';
                    cfg.run_mode_internal = 'Evolution';
                    cfg.time_integrator = 'RK4';
                    cfg.workflow_kind = 'phase2_boundary_condition_study';
                    cfg.phase_label = 'Phase 2';
                    cfg.launch_origin = 'phase_button';
                    cfg.result_layout_kind = 'phase2_workflow';
                    cfg.phase_id = sprintf('phase2_%s_%s', ...
                        regexprep(char(string(cfg.ic_type)), '[^a-zA-Z0-9]+', '_'), ...
                        char(datetime('now', 'Format', 'yyyyMMdd_HHmmss')));
                    cfg = app.normalize_workflow_launch_config(cfg);
                    cfg = app.apply_lightweight_workflow_launch_policy(cfg);
                case 'phase 3'
                    cfg.method = 'Finite Difference';
                    cfg.analysis_method = 'Finite Difference';
                    cfg.mode = 'evolution';
                    cfg.run_mode_internal = 'Evolution';
                    cfg.time_integrator = 'RK4';
                    cfg.workflow_kind = 'phase3_bathymetry_study';
                    cfg.phase_label = 'Phase 3';
                    cfg.launch_origin = 'phase_button';
                    cfg.result_layout_kind = 'phase3_workflow';
                    cfg.phase_id = sprintf('phase3_%s_%s', ...
                        regexprep(char(string(cfg.ic_type)), '[^a-zA-Z0-9]+', '_'), ...
                        char(datetime('now', 'Format', 'yyyyMMdd_HHmmss')));
                    if isfield(cfg, 'phase3') && isstruct(cfg.phase3)
                        cfg.Nx = double(app.pick_field(cfg.phase3, {'domain_nx'}, cfg.Nx));
                        cfg.Ny = double(app.pick_field(cfg.phase3, {'domain_ny'}, cfg.Ny));
                        cfg.Lx = double(app.pick_field(cfg.phase3, {'domain_lx'}, cfg.Lx));
                        cfg.Ly = double(app.pick_field(cfg.phase3, {'domain_ly'}, cfg.Ly));
                        if isfield(cfg.phase3, 'scenarios') && isstruct(cfg.phase3.scenarios) && ~isempty(cfg.phase3.scenarios)
                            cfg.bc_case = char(string(app.pick_field(cfg.phase3.scenarios(1), {'bc_id'}, 'enclosed_shear_layer')));
                            cfg.boundary_condition_case = cfg.bc_case;
                            cfg.bathymetry_scenario = char(string(app.pick_field(cfg.phase3.scenarios(1), {'bathymetry_id'}, 'flat_2d')));
                        end
                    end
                    cfg = app.normalize_workflow_launch_config(cfg);
                otherwise
                    error('UIController:UnsupportedPhaseLaunch', ...
                        'Unsupported phase launch preset "%s".', phase_label);
            end
        end

        function on_export_current_bathymetry(app)
            try
                payload = app.build_current_bathymetry_export_payload();
                default_name = sprintf('bathymetry_%s_%s.fig', ...
                    regexprep(char(string(payload.scenario_entry.id)), '[^a-zA-Z0-9_-]', '_'), ...
                    char(datetime('now', 'Format', 'yyyyMMdd_HHmmss')));
                [file, path] = uiputfile( ...
                    {'*.fig', 'MATLAB Figure (*.fig)'; ...
                     '*.mat', 'MATLAB Data (*.mat)'; ...
                     '*.csv', 'CSV Data (*.csv)'}, ...
                    'Export Current Bathymetry', default_name);
                if isequal(file, 0) || isequal(path, 0)
                    app.set_ic_preview_export_status('Bathymetry export cancelled.', app.layout_cfg.colors.fg_muted);
                    return;
                end
                output_path = fullfile(path, file);
                app.export_current_bathymetry(output_path, payload);
                app.set_ic_preview_export_status('Bathymetry exported.', app.layout_cfg.colors.accent_green);
                app.append_to_terminal(sprintf('Bathymetry export saved to: %s', output_path), 'success');
            catch ME
                app.set_ic_preview_export_status('Bathymetry export failed.', app.layout_cfg.colors.accent_red);
                app.append_to_terminal(sprintf('Bathymetry export failed: [%s] %s', ME.identifier, ME.message), 'error');
                app.show_alert_latex(ME.message, 'Bathymetry Export', 'Icon', 'error');
            end
        end

        function output_path = export_current_bathymetry(app, output_path, payload)
            if nargin < 2 || isempty(output_path)
                error('UIController:MissingBathymetryExportPath', ...
                    'A bathymetry export path is required.');
            end
            if nargin < 3 || ~isstruct(payload)
                payload = app.build_current_bathymetry_export_payload();
            end
            output_path = char(string(output_path));
            output_dir = fileparts(output_path);
            if ~isempty(output_dir) && exist(output_dir, 'dir') ~= 7
                mkdir(output_dir);
            end
            [~, ~, ext] = fileparts(output_path);
            ext = lower(char(string(ext)));
            if isempty(ext)
                output_path = [output_path, '.fig'];
                ext = '.fig';
            end

            switch ext
                case '.fig'
                    fig = figure('Visible', 'off', 'Color', [1 1 1], ...
                        'Name', sprintf('Bathymetry - %s', payload.scenario_entry.display_name), ...
                        'NumberTitle', 'off');
                    cleanup_fig = onCleanup(@() close(fig)); %#ok<NASGU>
                    ax = axes(fig);
                    app.render_bathymetry_payload_axes(ax, payload);
                    set(fig, 'Visible', 'on');
                    savefig(fig, output_path);
                case '.mat'
                    X = payload.X; %#ok<NASGU>
                    Y = payload.Y; %#ok<NASGU>
                    bathymetry = payload.B; %#ok<NASGU>
                    meta = payload.meta; %#ok<NASGU>
                    params = payload.params; %#ok<NASGU>
                    scenario_entry = payload.scenario_entry; %#ok<NASGU>
                    dimension = payload.dimension; %#ok<NASGU>
                    profile_x = payload.profile_x; %#ok<NASGU>
                    profile_y = payload.profile_y; %#ok<NASGU>
                    save(output_path, 'X', 'Y', 'bathymetry', 'meta', 'params', ...
                        'scenario_entry', 'dimension', 'profile_x', 'profile_y');
                case '.csv'
                    if strcmpi(char(string(payload.dimension)), '2d')
                        export_table = table(payload.profile_x(:), payload.profile_y(:), ...
                            'VariableNames', {'x', 'bed_elevation'});
                    else
                        export_table = table(payload.X(:), payload.Y(:), payload.B(:), ...
                            'VariableNames', {'x', 'y', 'zb'});
                    end
                    writetable(export_table, output_path);
                otherwise
                    error('UIController:UnsupportedBathymetryExportFormat', ...
                        'Bathymetry export supports .fig, .mat, and .csv files.');
            end
        end

        function cfg = normalize_workflow_launch_config(app, cfg)
            if nargin < 2 || ~isstruct(cfg)
                error('UIController:InvalidWorkflowConfig', ...
                    'normalize_workflow_launch_config requires a configuration struct.');
            end

            workflow_kind = char(string(app.pick_field(cfg, {'workflow_kind'}, '')));
            if ~any(strcmpi(workflow_kind, {'mesh_convergence_study', 'phase1_periodic_comparison', 'phase2_boundary_condition_study', 'phase3_bathymetry_study'}))
                return;
            end

            phase_cfg = struct();
            phase_field = 'phase1';
            if strcmpi(workflow_kind, 'mesh_convergence_study')
                phase_field = 'mesh_convergence';
            elseif strcmpi(workflow_kind, 'phase2_boundary_condition_study')
                phase_field = 'phase2';
            elseif strcmpi(workflow_kind, 'phase3_bathymetry_study')
                phase_field = 'phase3';
            end
            if isfield(cfg, phase_field) && isstruct(cfg.(phase_field))
                phase_cfg = cfg.(phase_field);
            else
                defaults = create_default_parameters();
                if ~isfield(defaults, phase_field) || ~isstruct(defaults.(phase_field))
                    error('UIController:MissingWorkflowDefaults', ...
                        'create_default_parameters must define %s defaults.', phase_field);
                end
                phase_cfg = defaults.(phase_field);
            end

            if ~isfield(phase_cfg, 'create_animations')
                error('UIController:MissingWorkflowAnimationDefault', ...
                    'create_default_parameters.%s must define create_animations.', phase_field);
            end
            if ~isfield(phase_cfg, 'num_plot_snapshots')
                error('UIController:MissingWorkflowSnapshotDefault', ...
                    'create_default_parameters.%s must define num_plot_snapshots.', phase_field);
            end
            if ~isfield(phase_cfg, 'resource_strategy') || isempty(phase_cfg.resource_strategy)
                phase_cfg.resource_strategy = 'throughput_first';
            end

            runtime_defaults = app.initialize_default_config();
            cfg.(phase_field) = phase_cfg;
            if ~isfield(cfg, 'resource_strategy') || isempty(cfg.resource_strategy) || ...
                    strcmpi(char(string(cfg.resource_strategy)), 'mode_adaptive')
                cfg.resource_strategy = char(string(phase_cfg.resource_strategy));
            end
            if ~isfield(cfg, 'launch_progress_only')
                cfg.launch_progress_only = logical(app.pick_field(runtime_defaults, {'launch_progress_only'}, false));
            end
            cfg.num_plot_snapshots = max(1, round(double(phase_cfg.num_plot_snapshots)));
            cfg.create_animations = logical(app.pick_field(phase_cfg, {'create_animations'}, ...
                app.pick_field(runtime_defaults, {'create_animations'}, false)));

            animation_frame_count = app.pick_field(cfg, {'animation_num_frames', 'num_animation_frames'}, ...
                app.pick_field(runtime_defaults, {'animation_num_frames', 'num_animation_frames'}, cfg.num_plot_snapshots));
            if ~(isnumeric(animation_frame_count) && isscalar(animation_frame_count) && isfinite(animation_frame_count))
                animation_frame_count = cfg.num_plot_snapshots;
            end
            cfg.animation_num_frames = max(2, round(double(animation_frame_count)));
            cfg.num_animation_frames = cfg.animation_num_frames;
            cfg.num_snapshots = max(cfg.num_plot_snapshots, cfg.animation_num_frames);

            animation_format = app.pick_field(cfg, {'animation_format'}, ...
                app.pick_field(runtime_defaults, {'animation_format'}, 'mp4+gif'));
            animation_export_format = app.pick_field(cfg, {'animation_export_format'}, ...
                app.pick_field(runtime_defaults, {'animation_export_format'}, animation_format));
            animation_export_formats = app.pick_field(cfg, {'animation_export_formats'}, ...
                app.pick_field(runtime_defaults, {'animation_export_formats'}, {'mp4', 'gif'}));
            animation_export_formats = cellstr(string(animation_export_formats));
            animation_export_formats = animation_export_formats(~cellfun(@isempty, animation_export_formats));
            if isempty(animation_export_formats)
                animation_export_formats = {'mp4', 'gif'};
            end
            cfg.animation_format = char(string(animation_format));
            cfg.animation_export_format = char(string(animation_export_format));
            cfg.animation_export_formats = animation_export_formats;
        end

        function cfg = apply_lightweight_workflow_launch_policy(app, cfg)
            if nargin < 2 || ~isstruct(cfg)
                cfg = struct();
            end
            workflow_kind = char(string(app.pick_field(cfg, {'workflow_kind'}, '')));
            if ~any(strcmpi(workflow_kind, {'mesh_convergence_study', 'phase1_periodic_comparison', 'phase2_boundary_condition_study'}))
                return;
            end

            cfg.launch_progress_only = false;
            cfg.lightweight_workflow_execution = true;
            cfg.enable_monitoring = false;
            cfg.collector_hwinfo = false;
            cfg.sustainability_auto_log = false;
            cfg.sample_interval = inf;
            if ~isfield(cfg, 'collectors') || ~isstruct(cfg.collectors)
                cfg.collectors = struct();
            end
            cfg.collectors.hwinfo = false;
            cfg.collectors.icue = false;
        end

        function tf = is_lightweight_workflow_launch(app, cfg)
            if nargin < 2 || isempty(cfg)
                cfg = app.config;
            end
            tf = logical(app.pick_field(cfg, {'lightweight_workflow_execution'}, false));
        end
        
        function browse_bathymetry_file(app)
            % Legacy import helper retained for backward-compatibility paths.
            % Method tab no longer exposes file import controls.
            [file, path] = uigetfile({'*.mat;*.xyz;*.txt;*.dat', 'Bathymetry Files'; ...
                '*.mat', 'MATLAB Files'; ...
                '*.xyz;*.txt;*.dat', 'Text Files'; ...
                '*.*', 'All Files'}, ...
                'Select Bathymetry File', ...
                pwd);
            
            if ~isequal(file, 0)
                full_path = fullfile(path, file);
                app.config.bathymetry_file = full_path;
                app.append_to_terminal(sprintf('Bathymetry file path recorded: %s', full_path), 'info');
            end
        end
    end
    
    methods
        function config = initialize_default_config(app)
            % Initialize default configuration by loading from create_default_parameters.m
            % This ensures UIController always uses the authoritative defaults
            try
                default_params = create_default_parameters();
            catch ME
                is_missing_symbol = strcmp(ME.identifier, 'MATLAB:UndefinedFunction') || ...
                    strcmp(ME.identifier, 'MATLAB:UndefinedFunctionOrVariable') || ...
                    contains(ME.message, 'Undefined function') || ...
                    contains(ME.message, 'Unrecognized function or variable');
                if ~is_missing_symbol
                    rethrow(ME);
                end
                PathSetup.attach_and_verify();
                default_params = create_default_parameters();
            end

            % Extract key parameters from defaults
            config = struct(...
                "method", default_params.analysis_method, ...
                "mode", lower(char(string(default_params.default_mode))), ...
                "Nx", default_params.Nx, ...
                "Ny", default_params.Ny, ...
                "Nz", default_params.Nz, ...
                "Lx", default_params.Lx, ...
                "Ly", default_params.Ly, ...
                "Lz", default_params.Lz, ...
                "grid_mode", char(string(default_params.grid_mode)), ...
                "equal_spacing", logical(default_params.equal_spacing), ...
                "dx", default_params.dx, ...
                "dy", default_params.dy, ...
                "is_anisotropic", logical(default_params.is_anisotropic), ...
                "delta", default_params.delta, ...
                "use_explicit_delta", default_params.use_explicit_delta, ...
                "dt", default_params.dt, ...
                "Tfinal", default_params.Tfinal, ...
                "t_final", default_params.Tfinal, ...
                "nu", default_params.nu, ...
                "fd_post_closure_edge_omega_zero", logical(default_params.fd_post_closure_edge_omega_zero), ...
                "num_snapshots", default_params.num_snapshots, ...
                "num_plot_snapshots", default_params.num_plot_snapshots, ...
                "ic_type", default_params.ic_type, ...
                "ic_coeff", default_params.ic_coeff, ...
                "ic_scenario", default_params.ic_scenario, ...
                "ic_arrangement", default_params.ic_arrangement, ...
                "ic_scale", default_params.ic_scale, ...
                "ic_count", default_params.ic_count, ...
                "ic_amplitude", default_params.ic_amplitude, ...
                "ic_center_x", default_params.ic_center_x, ...
                "ic_center_y", default_params.ic_center_y, ...
                "ic_contour_bands", logical(default_params.ic_contour_bands), ...
                "ic_pattern", default_params.ic_pattern, ...
                "ic_multi_vortex_experimental", logical(default_params.ic_multi_vortex_experimental), ...
