                "animation_export_preset", char(string(default_params.animation_export_preset)), ...
                "animation_export_width_in", double(default_params.animation_export_width_in), ...
                "animation_export_height_in", double(default_params.animation_export_height_in), ...
                "animation_export_resolution_px", double(default_params.animation_export_resolution_px), ...
                "animation_num_frames", default_params.animation_num_frames, ...
                "save_csv", logical(default_params.save_csv), ...
