                "motion_amplitude", default_params.motion_amplitude, ...
                "simulation_scenario", default_params.simulation_scenario, ...
                "simulation_scenario_catalog", default_params.simulation_scenario_catalog, ...
                "bathymetry_scenario_catalog_2d", default_params.bathymetry_scenario_catalog_2d, ...
                "bathymetry_scenario_catalog_3d", default_params.bathymetry_scenario_catalog_3d, ...
                "sustainability_auto_log", default_params.sustainability_auto_log, ...
                "sustainability", default_params.sustainability, ...
                "collectors", default_params.collectors, ...
                "collector_paths", default_params.sustainability.collector_paths, ...
                "collector_machine_profile", char(string(default_params.collector_machine_profile)), ...
                "collector_panel_profile", char(string(default_params.collector_panel_profile)), ...
                "hwinfo_control_mode", char(string(default_params.sustainability.collector_runtime.hwinfo_control_mode)), ...
                "collector_launch_root_dir", char(string(default_params.sustainability.collector_runtime.collector_launch_root_dir)), ...
                "collector_launch_csv_file", char(string(default_params.sustainability.collector_runtime.collector_launch_csv_file)), ...
                "run_mode_internal", default_params.run_mode_internal, ...
                "cpu_allocation_pct", default_params.cpu_allocation_pct, ...
                "memory_allocation_pct", default_params.memory_allocation_pct, ...
                "gpu_allocation_pct", default_params.gpu_allocation_pct, ...
                "monitor_update_hz", default_params.monitor_update_hz, ...
                "progress_update_hz", default_params.progress_update_hz, ...
                "pool_workers", default_params.pool_workers, ...
                "resource_strategy", char(string(default_params.resource_strategy)), ...
                "gpu_policy", char(string(default_params.gpu_policy)), ...
                "planner_use_host_profiles", logical(default_params.planner_use_host_profiles), ...
                "interactive_pool_workers_max", default_params.interactive_pool_workers_max, ...
                "throughput_pool_workers_min", default_params.throughput_pool_workers_min, ...
                "interactive_thread_headroom_pct", default_params.interactive_thread_headroom_pct, ...
                "gpu_min_workload_cells_steps", default_params.gpu_min_workload_cells_steps, ...
                "gpu_memory_guard_pct", default_params.gpu_memory_guard_pct, ...
                "pool_workers_max_override", default_params.pool_workers_max_override, ...
                "time_integrator", default_params.time_integrator, ...
                "use_arakawa", logical(default_params.use_arakawa), ...
                "use_gpu", logical(default_params.use_gpu), ...
                "method_config", default_params.method_config, ...
                "ic_ui_schema_version", default_params.ic_ui_schema_version, ...
                "ic_ui_catalog", default_params.ic_ui_catalog, ...
                "ic_scenario_catalog", default_params.ic_scenario_catalog, ...
                "ic_arrangement_catalog", default_params.ic_arrangement_catalog, ...
                "ic_multi_vortex_schema_version", default_params.ic_multi_vortex_schema_version, ...
                "ic_multi_vortex_defaults", default_params.ic_multi_vortex_defaults ...
            );
            config.ic_multi_vortex_rows = default_params.ic_multi_vortex_rows;
            if ~isfield(default_params, 'phase1') || ~isstruct(default_params.phase1)
                error('UIController:MissingPhase1Defaults', ...
                    'create_default_parameters must define phase1 defaults.');
            end
            if ~isfield(default_params.phase1, 'use_converged_mesh_seed')
                error('UIController:MissingPhase1Defaults', ...
                    'create_default_parameters.phase1 must define use_converged_mesh_seed.');
            end
            config.phase1 = default_params.phase1;
            config.phase1_use_converged_mesh_seed = logical(default_params.phase1.use_converged_mesh_seed);
            if ~isfield(default_params, 'mesh_convergence') || ~isstruct(default_params.mesh_convergence)
                error('UIController:MissingMeshConvergenceDefaults', ...
                    'create_default_parameters must define mesh_convergence defaults.');
            end
            config.mesh_convergence = default_params.mesh_convergence;
            if ~isfield(default_params, 'phase2') || ~isstruct(default_params.phase2)
                error('UIController:MissingPhase2Defaults', ...
                    'create_default_parameters must define phase2 defaults.');
            end
            config.phase2 = default_params.phase2;
            if ~isfield(default_params, 'phase3') || ~isstruct(default_params.phase3)
                error('UIController:MissingPhase3Defaults', ...
                    'create_default_parameters must define phase3 defaults.');
            end
            config.phase3 = default_params.phase3;

            % Boundary-condition defaults are dispatcher-driven.
            config.bc_case = 'periodic';
            config.bc_top = 'Periodic';
            config.bc_bottom = 'Periodic';
            config.bc_left = 'Periodic';
            config.bc_right = 'Periodic';
            config.bc_top_math = 'periodic';
            config.bc_bottom_math = 'periodic';
            config.bc_left_math = 'periodic';
            config.bc_right_math = 'periodic';
            config.bc_top_physical = 'periodic';
            config.bc_bottom_physical = 'periodic';
            config.bc_left_physical = 'periodic';
            config.bc_right_physical = 'periodic';
            config.U_top = 0.0;
            config.U_bottom = 0.0;
            config.U_left = 0.0;
            config.U_right = 0.0;
            config.equal_spacing = false;

            % UI runtime-only fields: prefer editable overrides in
            % `Scripts/Editable/Parameters.m` when available. Use a small
            % whitelist and dynamically copy only present fields, falling
            % back to sensible defaults otherwise. This avoids repetitive
            % isfield checks and keeps the code concise.
            try
                editable_params = create_default_parameters();
            catch ME
                is_missing_symbol = strcmp(ME.identifier, 'MATLAB:UndefinedFunction') || ...
                    strcmp(ME.identifier, 'MATLAB:UndefinedFunctionOrVariable') || ...
                    contains(ME.message, 'Undefined function') || ...
                    contains(ME.message, 'Unrecognized function or variable');
                if ~is_missing_symbol
                    rethrow(ME);
                end
                PathSetup.attach_and_verify();
                editable_params = create_default_parameters();
            end

            % Whitelist of runtime keys that the UI expects to consume.
            runtime_keys = { 'ic_pattern', 'sweep_parameter', 'sweep_values', ...
                             'simulation_scenario', 'simulation_scenario_catalog', ...
                             'bathymetry_scenario', 'bathymetry_bed_slope', ...
                             'bathymetry_depth_offset', 'bathymetry_relief_amplitude', ...
                             'bathymetry_resolution', 'bathymetry_custom_points', ...
                             'bathymetry_dynamic_params', ...
                             'bathymetry_dimension_policy', ...
                             'bathymetry_scenario_catalog_2d', 'bathymetry_scenario_catalog_3d', ...
                             'motion_enabled', 'motion_model', 'motion_amplitude', ...
                             'sustainability_auto_log', 'collectors', ...
                             'run_mode_internal', 'cpu_allocation_pct', ...
                             'memory_allocation_pct', 'gpu_allocation_pct', ...
                             'monitor_update_hz', 'progress_update_hz', ...
                             'pool_workers', 'resource_strategy', 'gpu_policy', ...
                             'planner_use_host_profiles', 'interactive_pool_workers_max', ...
                             'throughput_pool_workers_min', 'interactive_thread_headroom_pct', ...
                             'gpu_min_workload_cells_steps', 'gpu_memory_guard_pct', ...
                             'pool_workers_max_override', 'time_integrator', ...
                             'ic_scenario', 'ic_arrangement', 'ic_amplitude', 'ic_contour_bands', ...
                             'ic_multi_vortex_experimental', 'ic_multi_vortex_rows', ...
                             'ic_ui_schema_version', ...
                             'ic_ui_catalog', 'ic_scenario_catalog', 'ic_arrangement_catalog', ...
                             'ic_multi_vortex_schema_version', 'ic_multi_vortex_defaults' };

            % Apply present editable fields (do not overwrite core defaults)
            if isstruct(editable_params)
                for k = 1:numel(runtime_keys)
                    key = runtime_keys{k};
                    if isfield(editable_params, key)
                        config.(key) = editable_params.(key);
                    end
                end
            end

            % Require runtime/display defaults to be present in either
            % create_default_parameters.m or Scripts/Editable/Parameters.m.
            for k = 1:numel(runtime_keys)
                key = runtime_keys{k};
                if ~isfield(config, key)
                    error('UIController:MissingEditableParameter', ...
                        'Required runtime/display default "%s" is missing from %s and %s.', ...
                        key, ...
                        fullfile('Scripts','Infrastructure','Initialisers','create_default_parameters.m'), ...
                        fullfile('Scripts','Editable','Parameters.m'));
                end
            end

            % Record where defaults were sourced from for provenance/UI display
            config.defaults_source = struct( ...
                'summary', 'Loaded from create_default_parameters.m; UI runtime defaults prefer Scripts/Editable/Parameters.m when present', ...
                'loader', 'Scripts/Infrastructure/Initialisers/create_default_parameters.m', ...
                'editable_parameters', 'Scripts/Editable/Parameters.m', ...
                'editable_settings', 'Scripts/Editable/Settings.m');
        end
        
        function safe_stop_timer(app, field_name)
            % Stop and delete timer handles defensively without noisy warnings.
            if ~isprop(app, field_name)
                return;
            end
            t = app.(field_name);
            if isempty(t)
                app.(field_name) = [];
                return;
            end

            try
                if isvalid(t)
                    try
                        if strcmpi(char(string(t.Running)), 'on')
                            stop(t);
                        end
                    catch ME
                        UIController.warn_once('UIController:TimerStateProbeFailed', ...
                            'Timer state probe failed; attempting forced stop: %s', ME.message);
                        stop(t);
                    end
                    delete(t);
                end
            catch ME
                UIController.warn_once('UIController:TimerStopDeleteFailed', ...
                    'Timer stop/delete encountered a non-fatal error: %s', ME.message);
            end

            app.(field_name) = [];
        end

        function failure_error = resolve_async_completion_error(~, executor, fallback_error)
            failure_error = fallback_error;
            if nargin < 3 || isempty(fallback_error)
                failure_error = MException('UIController:AsyncLaunchFailed', ...
                    'Background simulation failed without a captured error.');
            end
            if isempty(executor) || ~isvalid(executor)
                return;
            end
            try
                if ~isempty(executor.terminal_failure_error)
                    failure_error = executor.terminal_failure_error;
                    return;
                end
            catch
            end
            try
                future_obj = executor.future_obj;
                if ~isempty(future_obj) && ~isempty(future_obj.Error)
                    failure_error = future_obj.Error;
                end
            catch
            end
        end

        function tf = has_valid_handle(app, field_name)
            % True when app.handles.<field_name> exists and is a live UI handle.
            tf = false;
            if ~isfield(app.handles, field_name)
                return;
            end
            h = app.handles.(field_name);
            if isempty(h)
                return;
            end
            try
                tf = isvalid(h);
            catch ME
                UIController.warn_once('UIController:IsValidHandleProbeFailed', ...
                    'isvalid() handle probe failed; falling back to ishghandle: %s', ME.message);
                try
                    tf = ishghandle(h);
                catch ME2
                    UIController.warn_once('UIController:IsHgHandleProbeFailed', ...
                        'ishghandle() fallback probe failed: %s', ME2.message);
                    tf = false;
                end
            end
        end

        function bc_val = safe_bc_value(app, handle_name, default_val)
            % Read a BC dropdown value safely, returning default if handle missing.
            if app.has_valid_handle(handle_name)
                bc_val = char(string(app.handles.(handle_name).Value));
            else
                bc_val = default_val;
            end
        end

        function val = safe_numeric_value(app, handle_name, default_val)
            % Read a numeric UI field safely, returning default if missing.
            val = default_val;
            if ~app.has_valid_handle(handle_name)
                return;
            end
            try
                val = double(app.handles.(handle_name).Value);
            catch ME
                UIController.warn_once('UIController:SafeNumericReadFailed', ...
                    'Numeric UI value read failed for "%s"; using default: %s', handle_name, ME.message);
                val = default_val;
            end
        end

        function report = audit_math_rendering(app, stage_label)
            if nargin < 2 || isempty(stage_label)
                stage_label = 'runtime';
            end
            report = struct('stage', char(string(stage_label)), 'checked', 0, 'adjusted', 0, 'issues', 0);
            if ~isstruct(app.handles)
                return;
            end

            handle_names = fieldnames(app.handles);
            for i = 1:numel(handle_names)
                name = handle_names{i};
                h = app.handles.(name);
                if isempty(h)
                    continue;
                end
                if isa(h, 'containers.Map') || isstruct(h) || isnumeric(h) || islogical(h) || ...
                        ischar(h) || isstring(h)
                    continue;
                end

                if iscell(h)
                    obj_cells = h(:);
                elseif isobject(h)
                    obj_cells = num2cell(h(:));
                else
                    continue;
                end

                for j = 1:numel(obj_cells)
                    obj = obj_cells{j};
                    if isempty(obj) || ~isobject(obj)
                        continue;
                    end
                    try
                        if ~isvalid(obj)
                            continue;
                        end
                    catch
                        continue;
                    end

                    if isa(obj, 'matlab.ui.control.UIAxes')
                        try
                            is_monitor_axis = false;
                            if isfield(app.handles, 'monitor_axes')
                                try
                                    mon_axes = app.handles.monitor_axes;
                                    if ~isempty(mon_axes)
                                        is_monitor_axis = any(arrayfun(@(h) isvalid(h) && isequal(h, obj), mon_axes));
                                    end
                                catch
                                    is_monitor_axis = false;
                                end
                            end
                            axis_labels = {obj.Title, obj.XLabel, obj.YLabel};
                            for li = 1:numel(axis_labels)
                                lbl = axis_labels{li};
                                if ~isprop(lbl, 'Interpreter')
                                    continue;
                                end
                                label_txt = '';
                                if isprop(lbl, 'String')
                                    label_txt = char(string(lbl.String));
                                end
                                current_interp = char(string(lbl.Interpreter));
                                target_interp = 'none';
                                if strcmpi(current_interp, 'latex')
                                    target_interp = 'latex';
                                elseif is_monitor_axis || app.is_math_like_text(label_txt)
                                    target_interp = 'latex';
                                end
                                if ~strcmpi(current_interp, target_interp)
                                    lbl.Interpreter = target_interp;
                                    report.adjusted = report.adjusted + 1;
                                end
                            end
                        catch
                            report.issues = report.issues + 1;
                        end
                    end

                    if isprop(obj, 'Text') && isprop(obj, 'Interpreter')
                        txt = char(string(obj.Text));
                        if ~app.is_math_like_text(txt)
                            continue;
                        end
                        report.checked = report.checked + 1;
                        try
                            if ~strcmpi(char(string(obj.Interpreter)), 'latex')
                                obj.Interpreter = 'latex';
                                report.adjusted = report.adjusted + 1;
                            end
                        catch
                            report.issues = report.issues + 1;
                        end
                    end
                end
            end

            if report.issues > 0
                app.append_to_terminal(sprintf('Math Rendering: Issues (%d adjusted, %d issues) [%s]', ...
                    report.adjusted, report.issues, report.stage), 'warning');
            else
                app.append_to_terminal(sprintf('Math Rendering: OK (%d adjusted) [%s]', ...
                    report.adjusted, report.stage), 'debug');
            end
        end

        function tf = is_math_like_text(~, txt)
            token = char(string(txt));
            if isempty(strtrim(token))
                tf = false;
                return;
            end
            token_l = lower(token);
            keyword_hits = contains(token_l, {'omega', 'psi', 'nu', 'delta', 'sigma', 'gamma', 'theta'});
            tf = contains(token, '$') || contains(token, '\') || contains(token, '^') || ...
                contains(token, '_') || any(keyword_hits);
        end

        function [display_label, math_type, physical_type] = normalize_bc_selection(app, raw_label, method_override)
            if nargin < 3
                method_override = '';
            end
            token = lower(strtrim(char(string(raw_label))));
            switch token
                case {'periodic', 'periodic (all)'}
                    math_type = 'periodic';
                    physical_type = 'periodic';
                case {'pinned (dirichlet)', 'pinned', 'pinned_dirichlet'}
                    math_type = 'dirichlet';
                    physical_type = 'pinned';
                case {'no-slip (dirichlet)', 'no-slip', 'noslip', 'dirichlet', 'stationary', ...
                        'no-slip wall (psi const)', 'no-slip wall', 'stationary wall', 'stationary wall (psi const)'}
                    math_type = 'dirichlet';
                    physical_type = 'no_slip';
                case {'no-flux (neumann)', 'no-flux', 'no_flux', 'noflux', 'neumann'}
                    math_type = 'neumann';
                    physical_type = 'no_flux';
                case {'driven (neumann)', 'driven', ...
                        'driven wall (psi const + wall speed)', 'driven wall', 'moving wall'}
                    math_type = 'dirichlet';
                    physical_type = 'driven';
                case {'open (absorbing)', 'open', 'absorbing', 'open_absorbing'}
                    math_type = 'radiation';
                    physical_type = 'open_absorbing';
                otherwise
                    error('UIController:UnknownBoundarySelection', ...
                        'Unknown boundary selection "%s".', char(string(raw_label)));
            end
            display_label = app.resolve_bc_display_label(math_type, physical_type, method_override);
        end

        function display_label = resolve_bc_display_label(app, math_type, physical_type, method_override)
            if nargin < 4
                method_override = '';
            end
            method_token = app.resolve_bc_method_token(method_override);
            switch physical_type
                case 'periodic'
                    display_label = 'Periodic';
                case 'pinned'
                    display_label = 'Pinned (Dirichlet)';
                case 'no_flux'
                    display_label = 'No-flux (Neumann)';
                case 'open_absorbing'
                    display_label = 'Open (Absorbing)';
                case 'driven'
                    display_label = 'Driven wall (psi const + wall speed)';
                otherwise
                    if strcmp(method_token, 'spectral')
                        display_label = 'Pinned (Dirichlet)';
                    elseif strcmp(method_token, 'shallow_water')
                        display_label = 'No-slip (Dirichlet)';
                    else
                        display_label = 'No-slip wall (psi const)';
                    end
            end
        end

        function method_token = resolve_bc_method_token(app, method_override)
            if nargin >= 2 && ~isempty(method_override)
                raw = char(string(method_override));
            elseif app.has_valid_handle('method_dropdown')
                raw = char(string(app.handles.method_dropdown.Value));
            elseif isfield(app.config, 'method') && ~isempty(app.config.method)
                raw = char(string(app.config.method));
            elseif isfield(app.config, 'analysis_method') && ~isempty(app.config.analysis_method)
                raw = char(string(app.config.analysis_method));
            else
                raw = 'Finite Difference';
            end

            raw = lower(strtrim(raw));
            switch raw
                case {'finite difference', 'finite_difference', 'fd'}
                    method_token = 'finite_difference';
                case {'finite volume', 'finite_volume', 'fv'}
                    method_token = 'finite_volume';
                case {'shallow water', 'shallow_water', 'swe'}
                    method_token = 'shallow_water';
                case {'spectral', 'fft', 'pseudo_spectral'}
                    method_token = 'spectral';
                otherwise
                    method_token = raw;
            end
        end

        function s = sign_or_one(~, val)
            s = sign(val);
            if s == 0
                s = 1;
            end
        end

        function apply_bc_case_to_dropdowns(app)
            % Translate the selected BC Case into individual top/bottom/left/right values
            % and refresh the domain plot. Called when bc_case dropdown changes.
            if ~app.has_valid_handle('bc_case')
                return;
            end
            case_label = char(string(app.handles.bc_case.Value));
            is_spectral = app.has_valid_handle('method_dropdown') && ...
                strcmpi(char(string(app.handles.method_dropdown.Value)), 'Spectral');
            no_slip_label = app.resolve_bc_display_label('dirichlet', 'no_slip');
            driven_label = app.resolve_bc_display_label('dirichlet', 'driven');
            pinned_label = app.resolve_bc_display_label('dirichlet', 'pinned');
            no_flux_label = app.resolve_bc_display_label('neumann', 'no_flux');
            switch case_label
                case 'Pinned Box'
                    bc_top = pinned_label; bc_bottom = pinned_label;
                    bc_left = pinned_label; bc_right = pinned_label;
                    U_top = 0.0; U_bottom = 0.0; U_left = 0.0; U_right = 0.0;
                case 'No-flux Box'
                    bc_top = no_flux_label; bc_bottom = no_flux_label;
                    bc_left = no_flux_label; bc_right = no_flux_label;
                    U_top = 0.0; U_bottom = 0.0; U_left = 0.0; U_right = 0.0;
                case 'Lid Driven Cavity'
                    bc_top = driven_label; bc_bottom = no_slip_label;
                    bc_left = no_slip_label; bc_right = no_slip_label;
                    U_top = +1.0; U_bottom = 0.0; U_left = 0.0; U_right = 0.0;
                case 'Driven Channel Flow'
                    bc_top = driven_label; bc_bottom = no_slip_label;
                    bc_left = 'Periodic'; bc_right = 'Periodic';
                    U_top = +1.0; U_bottom = 0.0; U_left = 0.0; U_right = 0.0;
                case 'Lid & Bottom Driven Cavity'
                    bc_top = driven_label; bc_bottom = driven_label;
                    bc_left = no_slip_label; bc_right = no_slip_label;
                    U_top = +1.0; U_bottom = -1.0; U_left = 0.0; U_right = 0.0;
                case 'Enclosed Shear Layer'
                    bc_top = driven_label; bc_bottom = driven_label;
                    bc_left = no_slip_label; bc_right = no_slip_label;
                    U_top = +1.0; U_bottom = -1.0; U_left = 0.0; U_right = 0.0;
                case 'Enclosed Cavity'
                    bc_top = no_slip_label; bc_bottom = no_slip_label;
                    bc_left = no_slip_label; bc_right = no_slip_label;
                    U_top = 0.0; U_bottom = 0.0; U_left = 0.0; U_right = 0.0;
                case 'Periodic (All)'
                    bc_top = 'Periodic'; bc_bottom = 'Periodic';
                    bc_left = 'Periodic'; bc_right = 'Periodic';
                    U_top = 0.0; U_bottom = 0.0; U_left = 0.0; U_right = 0.0;
                otherwise  % User Defined keeps current values
                    if is_spectral
                        bc_top = app.normalize_spectral_bc_display_label(app.safe_bc_value('bc_top', 'Periodic'));
                        bc_bottom = app.normalize_spectral_bc_display_label(app.safe_bc_value('bc_bottom', 'Periodic'));
                        bc_left = app.normalize_spectral_bc_display_label(app.safe_bc_value('bc_left', 'Periodic'));
                        bc_right = app.normalize_spectral_bc_display_label(app.safe_bc_value('bc_right', 'Periodic'));
                        U_top = 0.0; U_bottom = 0.0; U_left = 0.0; U_right = 0.0;
                    else
                        bc_top = app.safe_bc_value('bc_top', 'Periodic');
                        bc_bottom = app.safe_bc_value('bc_bottom', 'Periodic');
                        bc_left = app.safe_bc_value('bc_left', 'Periodic');
                        bc_right = app.safe_bc_value('bc_right', 'Periodic');
                        U_top = app.safe_numeric_value('U_top', 0.0);
                        U_bottom = app.safe_numeric_value('U_bottom', 0.0);
                        U_left = app.safe_numeric_value('U_left', 0.0);
                        U_right = app.safe_numeric_value('U_right', 0.0);
                    end
            end
            % Silently set individual dropdowns without triggering their callbacks
            if app.has_valid_handle('bc_top'),    app.handles.bc_top.Value    = bc_top;    end
            if app.has_valid_handle('bc_bottom'), app.handles.bc_bottom.Value = bc_bottom; end
            if app.has_valid_handle('bc_left'),   app.handles.bc_left.Value   = bc_left;   end
            if app.has_valid_handle('bc_right'),  app.handles.bc_right.Value  = bc_right;  end
            if app.has_valid_handle('U_top'),     app.handles.U_top.Value     = U_top;     end
            if app.has_valid_handle('U_bottom'),  app.handles.U_bottom.Value  = U_bottom;  end
            if app.has_valid_handle('U_left'),    app.handles.U_left.Value    = U_left;    end
            if app.has_valid_handle('U_right'),   app.handles.U_right.Value   = U_right;   end

            allow_per_side_edit = strcmp(case_label, 'User Defined');
            state = app.on_off(allow_per_side_edit);
            app.set_optional_handle_enable('bc_top', state);
            app.set_optional_handle_enable('bc_bottom', state);
            app.set_optional_handle_enable('bc_left', state);
            app.set_optional_handle_enable('bc_right', state);
            app.sync_bc_velocity_controls();
            app.update_grid_domain_plots();
        end

        function on_individual_bc_changed(app, source_name, src)
            % When a user manually changes an individual BC dropdown, switch the
            % BC Case selector to 'User Defined' and refresh the domain plot.
            if nargin < 2
                source_name = '';
            end
            if nargin < 3 %#ok<INUSD>
                src = [];
            end

            is_spectral = app.has_valid_handle('method_dropdown') && ...
                strcmpi(char(string(app.handles.method_dropdown.Value)), 'Spectral');
            if is_spectral && ~isempty(source_name) && app.has_valid_handle(source_name)
                normalized = app.normalize_spectral_bc_display_label(app.handles.(source_name).Value);
                app.handles.(source_name).Value = normalized;
                switch source_name
                    case {'bc_top', 'bc_bottom'}
                        if strcmp(source_name, 'bc_top')
                            paired_name = 'bc_bottom';
                        else
                            paired_name = 'bc_top';
                        end
                    case {'bc_left', 'bc_right'}
                        if strcmp(source_name, 'bc_left')
                            paired_name = 'bc_right';
                        else
                            paired_name = 'bc_left';
                        end
                    otherwise
                        paired_name = '';
                end
                if ~isempty(paired_name) && app.has_valid_handle(paired_name)
                    app.handles.(paired_name).Value = normalized;
                end
                if app.has_valid_handle('U_top'), app.handles.U_top.Value = 0.0; end
                if app.has_valid_handle('U_bottom'), app.handles.U_bottom.Value = 0.0; end
                if app.has_valid_handle('U_left'), app.handles.U_left.Value = 0.0; end
                if app.has_valid_handle('U_right'), app.handles.U_right.Value = 0.0; end
            end

            if app.has_valid_handle('bc_case')
                if is_spectral
                    app.handles.bc_case.Value = app.resolve_spectral_bc_case_from_current_selection();
                else
                    app.handles.bc_case.Value = 'User Defined';
                end
            end
            app.sync_bc_velocity_controls();
            app.update_grid_domain_plots();
        end

        function on_bc_velocity_changed(app)
            % Velocity edits are disabled for solver families that do not expose moving-wall semantics.
            app.update_grid_domain_plots();
        end

        function c = resolve_bc_color(~, bc_type, color_map, fallback)
            % Map a boundary-condition name to its display color.
            key = strrep(bc_type, '/', '_');
            key = matlab.lang.makeValidName(key);
            if isfield(color_map, key)
                c = color_map.(key);
            else
                c = fallback;
            end
        end

        function pattern = get_ic_pattern_value(app)
            % Arrangement is popup-driven; read from runtime config with legacy fallback.
            pattern = 'single';
            if isfield(app.config, 'ic_arrangement')
                raw = char(string(app.config.ic_arrangement));
            elseif isfield(app.config, 'ic_pattern')
                raw = char(string(app.config.ic_pattern));
            else
                raw = '';
            end
            allowed = {'single', 'circular', 'grid', 'random'};
            if any(strcmpi(raw, allowed))
                pattern = lower(raw);
            end
        end

        function n_vort = get_ic_count_value(app)
            % Return a safe positive integer vortex count when control is missing/unset.
            n_vort = 1;
            if ~app.has_valid_handle('ic_count')
                return;
            end
            try
                value = app.handles.ic_count.Value;
                if isfinite(value)
                    n_vort = max(1, round(value));
                end
            catch ME
                UIController.warn_once('UIController:ICCountReadFailed', ...
                    'IC count read failed; using default count=1: %s', ME.message);
                n_vort = 1;
            end
        end

        function items = get_multi_vortex_popup_ic_display_items(app)
            catalog = app.get_ic_ui_catalog();
            items = {};
            for i = 1:numel(catalog)
                entry = catalog(i);
                supports_popup = isfield(entry, 'supports_mixed_popup') && logical(entry.supports_mixed_popup);
                if supports_popup
                    items{end + 1} = char(string(entry.display_name)); %#ok<AGROW>
                end
            end
        end

        function rows = seed_multi_vortex_rows(app, ic_type)
            if isfield(app.config, 'ic_multi_vortex_rows') && ~isempty(app.config.ic_multi_vortex_rows)
                rows = app.normalize_multi_vortex_rows(app.config.ic_multi_vortex_rows, ic_type);
                if ~isempty(rows)
                    return;
                end
            end
            rows = app.default_multi_vortex_row(ic_type, 1);
        end

        function row = default_multi_vortex_row(app, ic_type, row_id)
            if nargin < 3 || isempty(row_id)
                row_id = 1;
            end
            normalized_type = lower(char(string(ic_type)));
            normalized_type = app.map_ic_display_to_type(normalized_type);
            if isempty(normalized_type)
                normalized_type = 'stretched_gaussian';
            end
            schema = app.get_ic_schema(normalized_type);
            row = struct( ...
                'row_id', row_id, ...
                'enabled', true, ...
                'ic_type', normalized_type, ...
                'center_x', app.safe_numeric_value('ic_center_x', 0.0), ...
                'center_y', app.safe_numeric_value('ic_center_y', 0.0), ...
                'scale', max(1.0e-6, app.safe_numeric_value('ic_scale', 1.0)), ...
                'amplitude', max(1.0e-6, app.safe_numeric_value('ic_amplitude', 1.0)), ...
                'charge', 1.0, ...
                'dynamic_values', app.default_dynamic_values(schema));
        end

        function rows = renumber_multi_vortex_rows(~, rows)
            if isempty(rows) || ~isstruct(rows)
                return;
            end
            for i = 1:numel(rows)
                rows(i).row_id = i;
            end
        end

        function rows = normalize_multi_vortex_rows(app, raw_rows, fallback_ic_type)
            if nargin < 3 || isempty(fallback_ic_type)
                fallback_ic_type = 'stretched_gaussian';
            end
            rows = struct([]);
            if isempty(raw_rows)
                return;
            end
            if isstruct(raw_rows)
                source_rows = raw_rows;
                rows = repmat(app.default_multi_vortex_row(fallback_ic_type, 1), size(source_rows));
                for i = 1:numel(source_rows)
                    seed = app.default_multi_vortex_row(fallback_ic_type, i);
                    row = source_rows(i);
                    seed_fields = fieldnames(seed);
                    for f = 1:numel(seed_fields)
                        key = seed_fields{f};
                        if isfield(row, key) && ~isempty(row.(key))
                            seed.(key) = row.(key);
                        end
                    end
                    seed.ic_type = app.map_ic_display_to_type(char(string(seed.ic_type)));
                    if isempty(seed.ic_type)
                        seed.ic_type = fallback_ic_type;
                    end
                    seed.dynamic_values = app.normalize_row_dynamic_values(seed.ic_type, seed.dynamic_values);
                    rows(i) = seed;
                end
                rows = app.renumber_multi_vortex_rows(rows);
                return;
            end

            if iscell(raw_rows)
                n_rows = size(raw_rows, 1);
                rows = repmat(app.default_multi_vortex_row(fallback_ic_type, 1), n_rows, 1);
                for i = 1:n_rows
                    row = app.default_multi_vortex_row(fallback_ic_type, i);
                    if size(raw_rows, 2) >= 1
                        row.ic_type = app.map_ic_display_to_type(char(string(raw_rows{i, 1})));
                    end
                    if size(raw_rows, 2) >= 2, row.center_x = app.cell_to_numeric(raw_rows{i, 2}, row.center_x); end
                    if size(raw_rows, 2) >= 3, row.center_y = app.cell_to_numeric(raw_rows{i, 3}, row.center_y); end
                    if size(raw_rows, 2) >= 4, row.scale = max(1.0e-6, app.cell_to_numeric(raw_rows{i, 4}, row.scale)); end
                    if size(raw_rows, 2) >= 5, row.amplitude = max(1.0e-6, app.cell_to_numeric(raw_rows{i, 5}, row.amplitude)); end
                    if size(raw_rows, 2) >= 6, row.charge = app.cell_to_numeric(raw_rows{i, 6}, row.charge); end
                    rows(i) = row;
                end
                rows = app.renumber_multi_vortex_rows(rows);
            end
        end

        function dyn = normalize_row_dynamic_values(app, ic_type, dyn)
            schema = app.get_ic_schema(ic_type);
            defaults = app.default_dynamic_values(schema);
            if ~isstruct(dyn)
                dyn = defaults;
                return;
            end
            names = fieldnames(defaults);
            for i = 1:numel(names)
                key = names{i};
                if ~isfield(dyn, key) || isempty(dyn.(key))
                    dyn.(key) = defaults.(key);
                end
            end
        end

        function data = multi_vortex_rows_to_table_data(app, rows)
            rows = app.normalize_multi_vortex_rows(rows, 'stretched_gaussian');
            n_rows = numel(rows);
            data = cell(n_rows, 7);
            for i = 1:n_rows
                data{i, 1} = logical(rows(i).enabled);
                data{i, 2} = app.map_ic_type_to_display(rows(i).ic_type);
                data{i, 3} = rows(i).center_x;
                data{i, 4} = rows(i).center_y;
                data{i, 5} = rows(i).scale;
                data{i, 6} = rows(i).amplitude;
                data{i, 7} = rows(i).charge;
            end
        end

        function rows = table_data_to_multi_vortex_rows(app, table_data, existing_rows, fallback_ic_type)
            if nargin < 4 || isempty(fallback_ic_type)
                fallback_ic_type = 'stretched_gaussian';
            end
            existing_rows = app.normalize_multi_vortex_rows(existing_rows, fallback_ic_type);
            n_rows = size(table_data, 1);
            rows = repmat(app.default_multi_vortex_row(fallback_ic_type, 1), n_rows, 1);
            has_type_column = size(table_data, 2) >= 7;
            for i = 1:n_rows
                row = app.default_multi_vortex_row(fallback_ic_type, i);
                previous_type = fallback_ic_type;
                if numel(existing_rows) >= i
                    previous_type = existing_rows(i).ic_type;
                    row.dynamic_values = existing_rows(i).dynamic_values;
                end
                row.enabled = logical(app.cell_to_numeric(table_data{i, 1}, 1.0));
                if has_type_column
                    row.ic_type = app.map_ic_display_to_type(char(string(table_data{i, 2})));
                    if isempty(row.ic_type)
                        row.ic_type = fallback_ic_type;
                    end
                    row.center_x = app.cell_to_numeric(table_data{i, 3}, row.center_x);
                    row.center_y = app.cell_to_numeric(table_data{i, 4}, row.center_y);
                    row.scale = max(1.0e-6, app.cell_to_numeric(table_data{i, 5}, row.scale));
                    row.amplitude = max(1.0e-6, app.cell_to_numeric(table_data{i, 6}, row.amplitude));
                    row.charge = app.cell_to_numeric(table_data{i, 7}, row.charge);
                else
                    row.ic_type = fallback_ic_type;
                    row.center_x = app.cell_to_numeric(table_data{i, 2}, row.center_x);
                    row.center_y = app.cell_to_numeric(table_data{i, 3}, row.center_y);
                    row.scale = max(1.0e-6, app.cell_to_numeric(table_data{i, 4}, row.scale));
                    row.amplitude = max(1.0e-6, app.cell_to_numeric(table_data{i, 5}, row.amplitude));
                    row.charge = app.cell_to_numeric(table_data{i, 6}, row.charge);
                end
                if ~strcmpi(previous_type, row.ic_type)
                    row.dynamic_values = app.default_dynamic_values(app.get_ic_schema(row.ic_type));
                else
                    row.dynamic_values = app.normalize_row_dynamic_values(row.ic_type, row.dynamic_values);
                end
                rows(i) = row;
            end
            rows = app.renumber_multi_vortex_rows(rows);
        end

        function [is_valid, message] = validate_multi_vortex_rows(app, rows, allow_mixed)
            if nargin < 3
                defaults = app.get_ic_multi_vortex_defaults();
                allow_mixed = app.pick_field(defaults, {'allow_mixed_types'}, false);
            end
            is_valid = true;
            message = 'Structured row set is valid.';
            rows = app.normalize_multi_vortex_rows(rows, 'stretched_gaussian');
            if isempty(rows)
                is_valid = false;
                message = 'At least one vortex row is required.';
                return;
            end
            enabled_rows = rows([rows.enabled]);
            if isempty(enabled_rows)
                enabled_rows = rows;
            end
            type_tokens = lower(string({enabled_rows.ic_type}));
            unique_types = unique(type_tokens);
            defaults = app.get_ic_multi_vortex_defaults();
            blocked_domain_filling = string(app.pick_field(defaults, {'blocked_domain_filling_types'}, {'taylor_green', 'random_turbulence'}));
            if any(ismember(type_tokens, blocked_domain_filling))
                is_valid = false;
                message = 'Taylor-Green and Random Turbulence are not supported in the multi-vortex editor.';
                return;
            end
            if ~allow_mixed && numel(unique_types) > 1
                is_valid = false;
                message = 'Mixed IC row types are not supported in this editor.';
                return;
            end
            for i = 1:numel(enabled_rows)
                if ~isfinite(enabled_rows(i).center_x) || ~isfinite(enabled_rows(i).center_y)
                    is_valid = false;
                    message = 'Every enabled vortex row must have finite center coordinates.';
                    return;
                end
            end
        end

        function val = cell_to_numeric(~, value, fallback)
            val = fallback;
            if isnumeric(value) && isscalar(value) && isfinite(value)
                val = double(value);
                return;
            end
            if islogical(value) && isscalar(value)
                val = double(value);
                return;
            end
            try
                cand = str2double(string(value));
                if isfinite(cand)
                    val = double(cand);
                end
            catch
                val = fallback;
            end
        end

        function set_optional_handle_enable(app, field_name, state)
            % Toggle Enable for optional controls without throwing if absent.
            if ~app.has_valid_handle(field_name)
                return;
            end
            h = app.handles.(field_name);
            if isprop(h, 'Enable')
                h.Enable = state;
            end
        end

        function set_optional_handle_property(app, field_name, prop_name, value)
            % Set arbitrary handle property when the optional control exists.
            if ~app.has_valid_handle(field_name)
                return;
            end
            h = app.handles.(field_name);
            if isprop(h, prop_name)
                h.(prop_name) = value;
            end
        end

        function append_dev_log(app, msg)
            % Developer mode was removed; keep this hook for layout tooling logs.
            app.append_to_terminal(char(string(msg)), 'debug');
        end

        function set_optional_label_text(app, field_name, value)
            % Set label text only when the handle exists and exposes Text.
            if ~app.has_valid_handle(field_name)
                return;
            end
            h = app.handles.(field_name);
            if isprop(h, 'Text')
                h.Text = char(string(value));
            end
        end

        function tf = is_live_handle(~, h)
            % True when handle-like object is valid.
            tf = false;
            if isempty(h)
                return;
            end
            try
                tf = isvalid(h);
            catch ME
                UIController.warn_once('UIController:IsLiveHandleIsValidFailed', ...
                    'isvalid() failed while probing live handle status: %s', ME.message);
                try
                    tf = ishghandle(h);
                catch ME2
                    UIController.warn_once('UIController:IsLiveHandleIshgFailed', ...
                        'ishghandle() fallback failed while probing live handle status: %s', ME2.message);
                    tf = false;
                end
            end
        end

        function enable_scrollable_if_supported(~, h)
            if isempty(h)
                return;
            end
            try
                if isprop(h, 'Scrollable')
                    h.Scrollable = 'on';
                end
            catch
            end
        end

        function enforce_container_content_margins(app, root_handle, min_padding)
            if nargin < 3 || isempty(min_padding)
                min_padding = [4 4 4 4];
            end
            if ~(isnumeric(min_padding) && numel(min_padding) == 4)
                min_padding = [4 4 4 4];
            end
            if ~app.is_live_handle(root_handle)
                return;
            end

            nodes = [root_handle; findall(root_handle)];
            for i = 1:numel(nodes)
                h = nodes(i);
                if ~app.is_live_handle(h)
                    continue;
                end
                cls = lower(class(h));
                if contains(cls, 'gridlayout') && isprop(h, 'Padding')
                    try
                        current_padding = double(h.Padding);
                    catch
                        current_padding = [0 0 0 0];
                    end
                    if numel(current_padding) ~= 4
                        current_padding = [0 0 0 0];
                    end
                    h.Padding = max(current_padding, double(min_padding));
                end
            end
        end

        function token = resolve_math_token(app, token_key, fallback)
            % Resolve canonical math token text from UI_Layout_Config.
            token = fallback;
            if ~isfield(app.layout_cfg, 'math_tokens') || ~isstruct(app.layout_cfg.math_tokens)
                return;
            end
            key = char(string(token_key));
            if isfield(app.layout_cfg.math_tokens, key)
                candidate = char(string(app.layout_cfg.math_tokens.(key)));
                if ~isempty(candidate)
                    token = candidate;
                end
            end
        end

        function lbl = create_math_label(app, parent, token_key, fallback, varargin)
            % Create label using LaTeX interpreter; fall back to plain text if unsupported.
            tex = app.resolve_math_token(token_key, fallback);
            try
                lbl = uilabel(parent, 'Text', tex, 'Interpreter', 'latex', varargin{:});
            catch ME
                UIController.warn_once('UIController:MathLabelLatexFailed', ...
                    'LaTeX label creation failed for token "%s"; using plain text: %s', token_key, ME.message);
                lbl = uilabel(parent, 'Text', fallback, varargin{:});
            end
        end

        function apply_tooltips(app)
            % Apply centralized tooltip text to all UI components.
            % Reads tooltip definitions from layout_cfg.tooltips and applies
            % them to matching handles. Safe to call at any time.
            if ~isfield(app.layout_cfg, 'tooltips') || ~isstruct(app.layout_cfg.tooltips)
                return;
            end
            tip_map = app.layout_cfg.tooltips;
            keys = fieldnames(tip_map);
            for idx = 1:numel(keys)
                key = keys{idx};
                if app.has_valid_handle(key)
                    try
                        app.handles.(key).Tooltip = char(string(tip_map.(key)));
                    catch ME
                        UIController.warn_once('UIController:TooltipApplyFailed', ...
                            'Tooltip assignment skipped for component "%s": %s', key, ME.message);
                    end
                end
            end
        end

        function info = show_alert_latex(app, message, title_txt, varargin)
            % Centralized alert helper with LaTeX-first interpreter policy.
            emit = true;
            clean_args = {};
            idx = 1;
            while idx <= numel(varargin)
                if idx < numel(varargin) && (ischar(varargin{idx}) || isstring(varargin{idx}))
                    key = lower(char(string(varargin{idx})));
                    if strcmp(key, 'emit')
                        emit = logical(varargin{idx + 1});
                        idx = idx + 2;
                        continue;
                    end
                end
                clean_args{end + 1} = varargin{idx}; %#ok<AGROW>
                if idx < numel(varargin)
                    clean_args{end + 1} = varargin{idx + 1}; %#ok<AGROW>
                end
                idx = idx + 2;
            end

            info = struct('interpreter', 'latex', 'message', char(string(message)), 'title', char(string(title_txt)));
            if ~emit
                return;
            end
            try
                uialert(app.fig, message, title_txt, 'Interpreter', 'latex', clean_args{:});
            catch ME
                UIController.warn_once('UIController:AlertLatexFailed', ...
                    'uialert LaTeX rendering failed; retrying with plain text: %s', ME.message);
                info.interpreter = 'none';
                uialert(app.fig, char(string(message)), char(string(title_txt)), clean_args{:});
            end
        end

        function choice = show_confirm_latex(app, message, title_txt, options, default_option, cancel_option, varargin)
            % Centralized confirm helper with LaTeX-first interpreter policy.
            if nargin < 5 || isempty(default_option)
                default_option = 'OK';
            end
            if nargin < 6 || isempty(cancel_option)
                cancel_option = default_option;
            end
            if nargin < 4 || isempty(options)
                options = {default_option};
            end
            emit = true;
            clean_args = {};
            idx = 1;
            while idx <= numel(varargin)
                if idx < numel(varargin) && (ischar(varargin{idx}) || isstring(varargin{idx}))
                    key = lower(char(string(varargin{idx})));
                    if strcmp(key, 'emit')
                        emit = logical(varargin{idx + 1});
                        idx = idx + 2;
                        continue;
                    end
                end
                clean_args{end + 1} = varargin{idx}; %#ok<AGROW>
                if idx < numel(varargin)
                    clean_args{end + 1} = varargin{idx + 1}; %#ok<AGROW>
                end
                idx = idx + 2;
            end

            choice = char(string(default_option));
            if ~emit
                return;
            end
            try
                choice = uiconfirm(app.fig, message, title_txt, ...
                    'Options', options, ...
                    'DefaultOption', default_option, ...
                    'CancelOption', cancel_option, ...
                    'Interpreter', 'latex', clean_args{:});
            catch ME
                UIController.warn_once('UIController:ConfirmLatexFailed', ...
                    'uiconfirm LaTeX rendering failed; retrying with plain text: %s', ME.message);
                choice = uiconfirm(app.fig, char(string(message)), char(string(title_txt)), ...
                    'Options', options, ...
                    'DefaultOption', default_option, ...
                    'CancelOption', cancel_option, clean_args{:});
            end
        end

        function update_config_subtab_titles(app, method_ok, grid_ok, time_ok, simulation_ok, convergence_ok, sustainability_ok)
            % Reflect readiness state directly in left configuration subtab titles.
            if ~isfield(app.handles, 'config_subtabs') || ~isstruct(app.handles.config_subtabs)
                return;
            end

            grid_ready = logical(grid_ok) && logical(time_ok);
            data_ready = logical(simulation_ok) && logical(sustainability_ok);
            status_map = struct( ...
                'method', logical(method_ok), ...
                'grid', grid_ready, ...
                'data', data_ready, ...
                'convergence', logical(convergence_ok));

            title_map = struct();
            if isfield(app.layout_cfg, 'config_tab') && isfield(app.layout_cfg.config_tab, 'left_subtabs') && ...
                    isfield(app.layout_cfg.config_tab.left_subtabs, 'titles')
                title_map = app.layout_cfg.config_tab.left_subtabs.titles;
            end

            keys = fieldnames(status_map);
            for idx = 1:numel(keys)
                key = keys{idx};
                if ~isfield(app.handles.config_subtabs, key)
                    continue;
                end
                tab_h = app.handles.config_subtabs.(key);
                if ~isvalid(tab_h)
                    continue;
                end

                if isfield(title_map, key)
                    base_title = char(string(title_map.(key)));
                else
                    base_title = app.humanize_token(key);
                end
                base_title = regexprep(base_title, '^\[[^\]]+\]\s*', '');
                if status_map.(key)
                    prefix = '[x]';
                else
                    prefix = '[ ]';
                end
                tab_h.Title = sprintf('%s %s', prefix, base_title);
            end
        end

        function initialize_time_video_state(app)
            % Initialize or reset in-memory triplet playback state.
            cfg = app.layout_cfg.config_tab.time_video;
            formats = cellstr(string(cfg.formats));
            streams = repmat(app.empty_time_video_stream('none'), 1, numel(formats));
            for idx = 1:numel(formats)
                fmt = char(lower(string(formats{idx})));
                streams(idx) = app.empty_time_video_stream(fmt);
                if isfield(app.handles, 'time_video_axes_map') && isstruct(app.handles.time_video_axes_map) && ...
                        isfield(app.handles.time_video_axes_map, fmt)
                    streams(idx).axes_handle = app.handles.time_video_axes_map.(fmt);
                end
                if isfield(app.handles, 'time_video_image_map') && isstruct(app.handles.time_video_image_map) && ...
                        isfield(app.handles.time_video_image_map, fmt)
                    streams(idx).image_handle = app.handles.time_video_image_map.(fmt);
                end
                if isfield(app.handles, 'time_video_status_map') && isstruct(app.handles.time_video_status_map) && ...
                        isfield(app.handles.time_video_status_map, fmt)
                    streams(idx).status_handle = app.handles.time_video_status_map.(fmt);
                end
                if isfield(app.handles, 'time_video_codec_map') && isstruct(app.handles.time_video_codec_map) && ...
                        isfield(app.handles.time_video_codec_map, fmt)
                    streams(idx).codec_handle = app.handles.time_video_codec_map.(fmt);
                end
            end

            app.time_video_state = struct( ...
                'streams', streams, ...
                'target_fps', max(1, cfg.default_fps), ...
                'is_playing', false, ...
                'loop_enabled', false, ...
                'speed_multiplier', 1.0, ...
                'last_loaded', char(datetime('now')));
        end

        function load_time_video_triplet(app, varargin)
            % Resolve latest MP4/AVI/GIF artifacts (or generate fallback) and load all panes.
            p = inputParser;
            addParameter(p, 'AutoGenerate', true, @(x) islogical(x) || isnumeric(x));
            parse(p, varargin{:});
            auto_generate = logical(p.Results.AutoGenerate);

            app.pause_time_video_triplet();
            app.initialize_time_video_state();
            paths = app.resolve_time_video_media_paths();
            if (isempty(paths.mp4) || isempty(paths.avi) || isempty(paths.gif)) && auto_generate
                generated_paths = app.generate_time_video_triplet_samples();
                if isempty(paths.mp4), paths.mp4 = generated_paths.mp4; end
                if isempty(paths.avi), paths.avi = generated_paths.avi; end
                if isempty(paths.gif), paths.gif = generated_paths.gif; end
            end

            state = app.time_video_state;
            available_count = 0;
            peak_fps = 1;
            for idx = 1:numel(state.streams)
                fmt = state.streams(idx).format;
                file_path = '';
                if isfield(paths, fmt)
                    file_path = paths.(fmt);
                end
                stream = app.read_time_video_stream(fmt, file_path);
                stream.axes_handle = state.streams(idx).axes_handle;
                stream.image_handle = state.streams(idx).image_handle;
                stream.status_handle = state.streams(idx).status_handle;
                stream.codec_handle = state.streams(idx).codec_handle;
                if stream.available
                    available_count = available_count + 1;
                    peak_fps = max(peak_fps, stream.fps);
                    stream = app.render_time_video_frame(stream, 1);
                end
                if app.is_live_handle(stream.status_handle)
                    stream.status_handle.Text = stream.status_text;
                end
                if app.is_live_handle(stream.codec_handle)
                    stream.codec_handle.Text = stream.codec_text;
                end
                state.streams(idx) = stream;
            end

            state.target_fps = max(1, min(60, peak_fps));
            state.is_playing = false;
            state.last_loaded = char(datetime('now', 'Format', 'yyyy-MM-dd HH:mm:ss'));
            app.time_video_state = state;
            app.update_time_video_status_label(sprintf('Triplet status: %d/3 formats ready', available_count));
        end

        function play_time_video_triplet(app)
            % Start synchronized playback timer for all available streams.
            if ~isstruct(app.time_video_state) || ~isfield(app.time_video_state, 'streams')
                return;
            end
            available = arrayfun(@(s) s.available, app.time_video_state.streams);
            if ~any(available)
                app.update_time_video_status_label('Triplet status: no playable formats loaded');
                return;
            end

            app.safe_stop_timer('time_video_timer');
            target_fps = app.time_video_state.target_fps;
            if ~isfinite(target_fps) || target_fps <= 0
                target_fps = 24;
            end
            target_fps = min(60, max(1, target_fps));
            period = round(max(0.001, 1 / target_fps), 3);
            app.time_video_timer = timer( ...
                'ExecutionMode', 'fixedSpacing', ...
                'Period', period, ...
                'BusyMode', 'drop', ...
                'TimerFcn', {@ui_controller_timer_on_time_video_timer_tick, app});
            start(app.time_video_timer);
            app.time_video_state.is_playing = true;

            % Update button visibility (show pause, hide play)
            if app.has_valid_handle('btn_time_video_play')
                app.handles.btn_time_video_play.Visible = 'off';
            end
            if app.has_valid_handle('btn_time_video_pause')
                app.handles.btn_time_video_pause.Visible = 'on';
            end

            app.update_time_video_status_label('Triplet status: playing');
        end

        function pause_time_video_triplet(app)
            % Pause playback without dropping loaded media frames.
            app.safe_stop_timer('time_video_timer');
            if isstruct(app.time_video_state)
                app.time_video_state.is_playing = false;
            end

            % Update button visibility (show play, hide pause)
            if app.has_valid_handle('btn_time_video_play')
                app.handles.btn_time_video_play.Visible = 'on';
            end
            if app.has_valid_handle('btn_time_video_pause')
                app.handles.btn_time_video_pause.Visible = 'off';
            end

            app.update_time_video_status_label('Triplet status: paused');
        end

        function restart_time_video_triplet(app)
            % Restart all loaded streams from frame 1.
            if ~isstruct(app.time_video_state) || ~isfield(app.time_video_state, 'streams')
                return;
            end
            was_playing = false;
            if isfield(app.time_video_state, 'is_playing')
                was_playing = app.time_video_state.is_playing;
            end
            app.pause_time_video_triplet();
            state = app.time_video_state;
            for idx = 1:numel(state.streams)
                if ~state.streams(idx).available
                    continue;
                end
                state.streams(idx).frame_index = 1;
                state.streams(idx).phase = 0;
                state.streams(idx) = app.render_time_video_frame(state.streams(idx), 1);
            end
            app.time_video_state = state;
            app.update_scrubber_position();
            app.update_time_video_status_label('Triplet status: restarted');
            if was_playing
                app.play_time_video_triplet();
            end
        end

        function toggle_time_video_playback(app)
            % Toggle between play and pause states.
            if ~isstruct(app.time_video_state)
                return;
            end
            is_playing = false;
            if isfield(app.time_video_state, 'is_playing')
                is_playing = app.time_video_state.is_playing;
            end
            if is_playing
                app.pause_time_video_triplet();
            else
                app.play_time_video_triplet();
            end
        end

        function on_time_video_loop_changed(app, loop_enabled)
            % Update loop mode in video state.
            if ~isstruct(app.time_video_state)
                return;
            end
            app.time_video_state.loop_enabled = logical(loop_enabled);
        end

        function on_time_video_speed_changed(app, speed_multiplier)
            % Update playback speed multiplier.
            if ~isstruct(app.time_video_state)
                return;
            end
            app.time_video_state.speed_multiplier = max(0.1, min(10.0, speed_multiplier));
            % Restart timer with new speed if playing
            if isfield(app.time_video_state, 'is_playing') && app.time_video_state.is_playing
                was_playing = true;
                app.pause_time_video_triplet();
                if was_playing
                    app.play_time_video_triplet();
                end
            end
        end

        function on_time_video_scrubber_moving(app, normalized_position)
            % Preview frame while scrubber is being dragged (optional, can be disabled for performance).
            % For now, just update on final position (ValueChangedFcn).
        end

        function on_time_video_scrubber_moved(app, normalized_position)
            % Jump to specific frame based on scrubber position.
            if ~isstruct(app.time_video_state) || ~isfield(app.time_video_state, 'streams')
                return;
            end
            state = app.time_video_state;
            for idx = 1:numel(state.streams)
                stream = state.streams(idx);
                if ~stream.available || stream.frame_count < 1
                    continue;
                end
                target_frame = max(1, min(stream.frame_count, round(normalized_position * (stream.frame_count - 1)) + 1));
                stream.frame_index = target_frame;
                stream.phase = 0;
                stream = app.render_time_video_frame(stream, target_frame);
                state.streams(idx) = stream;
            end
            app.time_video_state = state;
        end

        function update_scrubber_position(app)
            % Update scrubber slider to reflect current playback position.
            if ~app.has_valid_handle('slider_time_video_scrubber')
                return;
            end
            if ~isstruct(app.time_video_state) || ~isfield(app.time_video_state, 'streams')
                return;
            end
            % Use first available stream to determine position
            for idx = 1:numel(app.time_video_state.streams)
                stream = app.time_video_state.streams(idx);
                if stream.available && stream.frame_count > 1
                    normalized_pos = (stream.frame_index - 1) / (stream.frame_count - 1);
                    app.handles.slider_time_video_scrubber.Value = normalized_pos;
                    return;
                end
            end
        end

        function on_time_video_timer_tick(app)
            % Timer callback: advance each stream at its own FPS on a shared clock.
            if ~isstruct(app.time_video_state) || ~isfield(app.time_video_state, 'streams')
                return;
            end
            target_fps = max(1, app.time_video_state.target_fps);
            speed_mult = 1.0;
            if isfield(app.time_video_state, 'speed_multiplier')
                speed_mult = max(0.1, min(10.0, app.time_video_state.speed_multiplier));
            end
            loop_enabled = false;
            if isfield(app.time_video_state, 'loop_enabled')
                loop_enabled = logical(app.time_video_state.loop_enabled);
            end

            state = app.time_video_state;
            all_at_end = true;

            for idx = 1:numel(state.streams)
                stream = state.streams(idx);
                if ~stream.available || stream.frame_count < 2
                    continue;
                end

                % Apply speed multiplier to phase increment
                stream.phase = stream.phase + (stream.fps / target_fps) * speed_mult;
                advance = floor(stream.phase);
                if advance < 1
                    state.streams(idx) = stream;
                    if stream.frame_index < stream.frame_count
                        all_at_end = false;
                    end
                    continue;
                end
                stream.phase = stream.phase - advance;

                % Compute new frame index
                new_index = stream.frame_index + advance;
                if new_index > stream.frame_count
                    if loop_enabled
                        % Wrap around
                        stream.frame_index = mod(new_index - 1, stream.frame_count) + 1;
                        all_at_end = false;
                    else
                        % Clamp at end
                        stream.frame_index = stream.frame_count;
                    end
                else
                    stream.frame_index = new_index;
                    if new_index < stream.frame_count
                        all_at_end = false;
                    end
                end

                stream = app.render_time_video_frame(stream, stream.frame_index);
                state.streams(idx) = stream;
            end

            app.time_video_state = state;
            app.update_scrubber_position();

            % Stop playback if all streams reached the end and loop is disabled
            if all_at_end && ~loop_enabled
                app.pause_time_video_triplet();
            end

            drawnow limitrate nocallbacks;
        end

        function stream = render_time_video_frame(app, stream, frame_index)
            % Push selected frame to corresponding uiaxes image handle.
            if ~stream.available || isempty(stream.frames)
                return;
            end
            frame_index = max(1, min(frame_index, stream.frame_count));
            frame = stream.frames{frame_index};
            if isempty(frame)
                return;
            end

            if app.is_live_handle(stream.image_handle)
                stream.image_handle.CData = frame;
                stream.image_handle.Visible = 'on';
            elseif app.is_live_handle(stream.axes_handle)
                h_img = image(stream.axes_handle, frame);
                h_img.Visible = 'on';
                stream.image_handle = h_img;
            else
                return;
            end

            axis(stream.axes_handle, 'image');
            axis(stream.axes_handle, 'off');
            stream.frame_index = frame_index;
            if app.is_live_handle(stream.status_handle)
                stream.status_handle.Text = sprintf('%s: frame %d/%d', upper(stream.format), stream.frame_index, stream.frame_count);
            end
        end

        function latest = find_latest_file_by_ext(~, roots, ext)
            % Return newest file path for extension across root directories.
            latest = '';
            latest_datenum = -inf;
            pattern = ['*.', char(lower(string(ext)))];
            for ridx = 1:numel(roots)
                root = char(string(roots{ridx}));
                if ~isfolder(root)
                    continue;
                end
                try
                    listing = dir(fullfile(root, '**', pattern));
                catch ME
                    UIController.warn_once('UIController:RecursiveDirUnsupported', ...
                        'Recursive dir scan failed/unsupported; using flat scan fallback: %s', ME.message);
                    listing = dir(fullfile(root, pattern));
                end
                for fidx = 1:numel(listing)
                    if listing(fidx).isdir
                        continue;
                    end
                    if isfield(listing, 'folder')
                        candidate = fullfile(listing(fidx).folder, listing(fidx).name);
                    else
                        candidate = fullfile(root, listing(fidx).name);
                    end
                    if listing(fidx).datenum > latest_datenum
                        latest_datenum = listing(fidx).datenum;
                        latest = candidate;
                    end
                end
            end
        end

        function paths = resolve_time_video_media_paths(app)
            % Locate latest media artifacts for MP4/AVI/GIF.
            roots = { ...
                fullfile(pwd, 'Artifacts'), ...
                fullfile(pwd, 'Output'), ...
                fullfile(pwd, 'Outputs'), ...
                pwd};
            paths = struct( ...
                'mp4', app.find_latest_file_by_ext(roots, 'mp4'), ...
                'avi', app.find_latest_file_by_ext(roots, 'avi'), ...
                'gif', app.find_latest_file_by_ext(roots, 'gif'));
        end

        function paths = generate_time_video_triplet_samples(app)
            % Fallback generation when latest run artifacts are unavailable.
            paths = struct('mp4', '', 'avi', '', 'gif', '');
            output_dir = fullfile(pwd, 'Artifacts', 'UI', 'TimePhysicsPreview', char(datetime('now', 'Format', 'yyyyMMdd_HHmmss')));
            if ~exist(output_dir, 'dir')
                mkdir(output_dir);
            end
            try
                summary = AnimationFormatMWE('OutputDir', output_dir, 'Formats', {'mp4', 'avi', 'gif'}, ...
                    'FrameRate', app.layout_cfg.config_tab.time_video.default_fps);
                for idx = 1:numel(summary.results)
                    entry = summary.results(idx);
                    fmt = char(lower(string(entry.format)));
                    if entry.success && isfield(paths, fmt) && isfile(entry.file_path)
                        paths.(fmt) = entry.file_path;
                    end
                end
            catch ME
                app.append_to_terminal(sprintf('Triplet fallback generation failed: %s', ME.message), 'warning');
            end
        end

        function stream = read_time_video_stream(app, fmt, file_path)
            % Decode a media stream to frame cache with graceful failure semantics.
            stream = app.empty_time_video_stream(fmt);
            time_text = app.layout_cfg.ui_text.config.time;
            if isempty(file_path) || ~isfile(file_path)
                stream.status_text = sprintf(time_text.video_status_missing_pattern, upper(fmt));
                stream.codec_text = time_text.video_codec_file_missing;
                return;
            end

            cfg = app.layout_cfg.config_tab.time_video;
            max_frames = max(10, cfg.max_cached_frames);
            try
                switch lower(fmt)
                    case {'mp4', 'avi'}
                        vr = VideoReader(file_path);
                        src_fps = max(1, vr.FrameRate);
                        est_count = max(1, floor(vr.Duration * src_fps));
                        stride = max(1, ceil(est_count / max_frames));
                        frames = {};
                        src_idx = 0;
                        while hasFrame(vr)
                            frame = readFrame(vr);
                            src_idx = src_idx + 1;
                            if mod(src_idx - 1, stride) ~= 0
                                continue;
                            end
                            if ndims(frame) == 2
                                frame = repmat(frame, 1, 1, 3);
                            end
                            frames{end + 1} = frame; %#ok<AGROW>
                            if numel(frames) >= max_frames
                                break;
                            end
                        end
                        stream.frames = frames;
                        stream.fps = max(1, src_fps / stride);
                        stream.codec_text = sprintf(time_text.video_codec_videoreader_pattern, stream.fps);

                    case 'gif'
                        info = imfinfo(file_path);
                        total = numel(info);
                        stride = max(1, ceil(total / max_frames));
                        frames = {};
                        delays = zeros(1, 0);
                        for frame_idx = 1:stride:total
                            [A, map] = imread(file_path, frame_idx, 'Info', info);
                            if ndims(A) == 2
                                if ~isempty(map)
                                    rgb = ind2rgb(A, map);
                                    frame = uint8(255 * rgb);
                                else
                                    frame = repmat(uint8(A), 1, 1, 3);
                                end
                            else
                                frame = A;
                            end
                            frames{end + 1} = frame; %#ok<AGROW>
                            if isfield(info(frame_idx), 'DelayTime')
                                delays(end + 1) = info(frame_idx).DelayTime; %#ok<AGROW>
                            end
                        end
                        stream.frames = frames;
                        if isempty(delays) || ~any(delays > 0)
                            stream.fps = max(1, cfg.default_fps);
                        else
                            stream.fps = max(1, 1 / median(delays(delays > 0)));
                        end
                        stream.codec_text = sprintf(time_text.video_codec_gif_pattern, stream.fps);
                end
            catch ME
                stream.status_text = sprintf(time_text.video_status_load_failed_pattern, upper(fmt));
                stream.codec_text = sprintf(time_text.video_codec_error_pattern, ME.message);
                stream.available = false;
                stream.frames = {};
                stream.frame_count = 0;
                return;
            end

            stream.file_path = file_path;
            stream.frame_count = numel(stream.frames);
            stream.frame_index = 1;
            stream.phase = 0;
            stream.available = stream.frame_count > 0;
            if stream.available
                stream.status_text = sprintf(time_text.video_status_loaded_pattern, upper(fmt), stream.frame_count);
            else
                stream.status_text = sprintf(time_text.video_status_empty_stream_pattern, upper(fmt));
                stream.codec_text = time_text.video_codec_no_frames;
            end
        end

        function stream = empty_time_video_stream(app, fmt)
            % Construct a default stream struct.
            default_fps = 24;
            time_text = app.layout_cfg.ui_text.config.time;
            if isfield(app.layout_cfg, 'config_tab') && isfield(app.layout_cfg.config_tab, 'time_video') && ...
                    isfield(app.layout_cfg.config_tab.time_video, 'default_fps')
                default_fps = max(1, app.layout_cfg.config_tab.time_video.default_fps);
            end
            stream = struct( ...
                'format', char(fmt), ...
                'available', false, ...
                'file_path', '', ...
                'frames', {{}}, ...
                'frame_count', 0, ...
                'frame_index', 1, ...
                'fps', default_fps, ...
                'phase', 0, ...
                'axes_handle', [], ...
                'image_handle', [], ...
                'status_handle', [], ...
                'codec_handle', [], ...
                'status_text', sprintf(time_text.video_status_pending_pattern, upper(string(fmt))), ...
                'codec_text', time_text.video_codec_placeholder);
        end

        function update_time_video_status_label(app, txt)
            % Update shared playback status label if present.
            if app.has_valid_handle('time_video_status')
                app.handles.time_video_status.Text = char(string(txt));
            end
        end

        function snapshot = get_time_video_state_snapshot(app)
            % Public read-only snapshot for tests.
            snapshot = app.time_video_state;
        end

        function clear_terminal_view(app)
            T = app.layout_cfg.ui_text.terminal;
            app.terminal_log = {};
            app.terminal_type_log = {};
            if app.has_valid_handle('terminal_output')
                app.handles.terminal_output.Value = {T.cleared};
            end
        end

        function refresh_terminal_output(app)
            if ~app.has_valid_handle('terminal_output')
                return;
            end
            lines = app.terminal_display_lines();
            if isprop(app.handles.terminal_output, 'Value')
                app.handles.terminal_output.Value = lines;
            elseif isprop(app.handles.terminal_output, 'HTMLSource')
                app.handles.terminal_output.HTMLSource = app.render_terminal_html();
            end
            drawnow limitrate nocallbacks;
        end

        function lines = terminal_display_lines(app)
            if isempty(app.terminal_log)
                lines = {'[terminal] waiting for output...'};
                return;
            end
            lines = reshape(cellfun(@(s) app.sanitize_terminal_text(s), ...
                app.terminal_log(:), 'UniformOutput', false), 1, []);
        end

        function txt = sanitize_terminal_text(~, txt)
            % Keep terminal text ASCII-safe so MATLAB's UI output stream does
            % not choke on control characters, progress glyphs, or mojibake.
            txt = char(string(txt));
            replacements = {
                char(969), 'omega';
                char(968), 'psi';
                char(960), 'pi';
                char(957), 'nu';
                char(952), 'theta';
                char(945), 'alpha';
                char(916), 'Delta';
                char(215), 'x';
                char(8594), '->';
                char(8592), '<-';
                char(8593), '^';
                char(8595), 'v';
                char(8211), '-';
                char(8212), '-';
                char(8226), '-';
                char(10003), '[ok]';
                char(10007), '[x]';
                char(9608), '#';
                char(9617), '-'
                };
            for ri = 1:size(replacements, 1)
                txt = strrep(txt, replacements{ri, 1}, replacements{ri, 2});
            end
            codes = double(txt);
            keep_control = codes == 9 | codes == 10;
            codes(codes == 13 | codes == 8) = 32;
            bad = (codes < 32 & ~keep_control) | codes > 126;
            codes(bad) = double('?');
            txt = char(codes);
        end

        function html = render_terminal_html(app)
            % Render terminal log as color-coded HTML rows for the monitoring sidebar.
            T = app.layout_cfg.ui_text.terminal;
            if isempty(app.terminal_log)
                lines = string(T.waiting_html);
                html = "<html><body style='margin:0;background:#111;color:#ddd;font-family:Consolas,monospace;font-size:11px;'>" + ...
                    "<div style='padding:6px;white-space:pre-wrap;line-height:1.25;'>" + lines + "</div></body></html>";
                html = char(html);
                return;
            end

            chunks = strings(1, numel(app.terminal_log));
            for i = 1:numel(app.terminal_log)
                msg = string(app.terminal_log{i});
                msg = replace(msg, "&", "&amp;");
                msg = replace(msg, "<", "&lt;");
                msg = replace(msg, ">", "&gt;");
                msg = replace(msg, newline, "<br>");

                if i <= numel(app.terminal_type_log)
                    msg_type = char(string(app.terminal_type_log{i}));
                else
                    msg_type = 'info';
                end
                color = app.terminal_type_color(msg_type);
                chunks(i) = "<div style='color:" + color + ";'>" + msg + "</div>";
            end

            html = "<html><body style='margin:0;background:#111;color:#ddd;font-family:Consolas,monospace;font-size:11px;'>" + ...
                "<div style='padding:6px;white-space:pre-wrap;line-height:1.2;overflow:auto;'>" + ...
                strjoin(chunks, "") + ...
                "</div></body></html>";
            html = char(html);
        end

        function color = terminal_type_color(~, msg_type)
            switch lower(string(msg_type))
                case "success"
                    color = '#5CFF8A';
                case "warning"
                    color = '#FFD166';
                case "error"
                    color = '#FF6B6B';
                case "debug"
                    color = '#9AA0A6';
                otherwise
                    color = '#7CC9FF';
            end
        end

        function catalog = build_monitor_metric_catalog(app)
            % Ranked metric catalog for the 3x3 monitor (first 8 rendered as plots).
            % Source of truth: app.layout_cfg.monitor_tab.metric_catalog.
            if isfield(app.layout_cfg, 'monitor_tab') && isfield(app.layout_cfg.monitor_tab, 'metric_catalog') ...
                    && ~isempty(app.layout_cfg.monitor_tab.metric_catalog)
                catalog = app.layout_cfg.monitor_tab.metric_catalog;
                return;
            end

%            % Fallback catalog kept for resilience if config is incomplete.
%            all_methods = {'finite_difference', 'finite_volume', 'spectral'};
%            all_modes = {'evolution', 'convergence', 'sweep', 'animation', 'experimentation'};
%            conv_only = {'convergence'};
%            catalog = struct( ...
%                'id', {'iter_vs_time', 'iter_per_sec', 'runtime_vs_time', 'max_vorticity', ...
%                       'energy_proxy', 'enstrophy_proxy', 'vorticity_decay_rate', 'cpu_proxy', ...
%                       'memory_mb', 'iteration_completion', 'stability_proxy', 'convergence_residual'}, ...
%                'title', {'Iterations', 'Iterations/s', 'Runtime', 'Max $|\omega|$', ...
%                          'Energy Proxy', 'Enstrophy Proxy', 'Decay Rate', 'CPU Usage', ...
%                          'Memory Usage', 'Completion', 'Stability Proxy', 'Convergence Residual'}, ...
%                'xlabel', {'Elapsed Time', 'Elapsed Time', 'Elapsed Time', 'Elapsed Time', ...
%                           'Elapsed Time', 'Elapsed Time', 'Elapsed Time', 'Elapsed Time', ...
%                           'Elapsed Time', 'Elapsed Time', 'Elapsed Time', 'Iteration'}, ...
%                'ylabel', {'Iterations', 'Iterations/Second', 'Seconds', '$|\omega|_{max}$', ...
%                           '$E^*$', '$Z^*$', '$-d|\omega|/dt$', 'CPU Usage (%)', ...
%                           'Memory Usage (MB)', '%', 'proxy', 'residual'}, ...
%                'methods', {all_methods, all_methods, all_methods, all_methods, ...
%                            all_methods, all_methods, all_methods, all_methods, ...
%                            all_methods, all_methods, all_methods, all_methods}, ...
%                'modes', {all_modes, all_modes, all_modes, all_modes, ...
%                          all_modes, all_modes, all_modes, all_modes, ...
%                          all_modes, all_modes, all_modes, conv_only}, ...
%                'rank', num2cell([1, 2, 5, 3, 4, 6, 8, 9, 10, 11, 12, 7]));
        end

        function refresh_monitor_dashboard(app, summary, cfg)
            if ~isfield(app.handles, 'monitor_axes') || isempty(app.handles.monitor_axes)
                return;
            end
            if nargin < 3 || isempty(cfg)
                cfg = app.config;
            end
            if app.is_lightweight_workflow_launch(cfg)
                return;
            end
            cfg = app.normalize_monitor_cfg(cfg);

            monitor_series = app.resolve_monitor_series(summary, cfg);
            display_cfg = app.resolve_workflow_monitor_cfg(cfg, monitor_series);
            mem_now = monitor_series.mem_now;

            tol = NaN;
            if isfield(display_cfg, 'convergence_tol')
                tol = display_cfg.convergence_tol;
            elseif app.has_valid_handle('conv_tolerance')
                tol = app.handles.conv_tolerance.Value;
            end

            slot_count = min(numel(app.handles.monitor_axes), 8);
            selected_metric_indices = app.select_monitor_metric_indices(display_cfg, slot_count);
            app.handles.monitor_ranked_selection = selected_metric_indices;
            if ~isfield(app.handles, 'monitor_line_handles') || ...
                    numel(app.handles.monitor_line_handles) < slot_count
                app.handles.monitor_line_handles = cell(1, slot_count);
            end
            if ~isfield(app.handles, 'monitor_slot_metric_ids') || ...
                    numel(app.handles.monitor_slot_metric_ids) < slot_count
                app.handles.monitor_slot_metric_ids = repmat({''}, 1, slot_count);
            end

            for slot = 1:slot_count
                ax = app.handles.monitor_axes(slot);
                if ~isvalid(ax)
                    continue;
                end
                if slot > numel(selected_metric_indices)
                    continue;
                end
                metric = app.handles.monitor_metric_catalog(selected_metric_indices(slot));
                metric_id = char(string(metric.id));
                app.clear_monitor_dashboard_legend(ax);

                if ~app.is_monitor_metric_applicable(metric, display_cfg)
                    cache_id = ['na:' metric_id];
                    if ~strcmp(app.handles.monitor_slot_metric_ids{slot}, cache_id)
                        app.render_monitor_metric_not_applicable(ax, metric, display_cfg);
                        app.handles.monitor_slot_metric_ids{slot} = cache_id;
                        app.handles.monitor_line_handles{slot} = [];
                    end
                    continue;
                end

                [x, y] = app.monitor_metric_series(metric.id, monitor_series);
                [x, y] = app.normalize_metric_vectors(x, y);

                if strcmp(metric_id, 'vorticity_histogram')
                    cla(ax);
                    vals = monitor_series.max_omega;
                    vals = vals(isfinite(vals));
                    if isempty(vals)
                        vals = 0;
                    end
                    histogram(ax, vals, min(12, max(4, numel(vals))), ...
                        'FaceColor', app.layout_cfg.colors.accent_cyan, ...
                        'EdgeColor', app.layout_cfg.colors.bg_dark);
                    app.apply_monitor_plot_format(ax, metric);
                    app.handles.monitor_slot_metric_ids{slot} = metric_id;
                    app.handles.monitor_line_handles{slot} = struct('metric_id', metric_id, 'line', gobjects(0));
                    continue;
                end

                if strcmp(metric_id, 'environmental_impact') || strcmp(metric_id, 'resource_heatmap')
                    cla(ax);
                    env_x = app.monitor_time_vector(monitor_series);
                    [env_x, env_energy] = app.normalize_metric_vectors(env_x, ...
                        app.pick_field(monitor_series, {'environmental_energy_wh_cum'}, nan(size(env_x))));
                    env_co2 = app.rowvec(app.pick_field(monitor_series, {'environmental_co2_g_cum'}, nan(size(env_energy))));
                    env_co2 = env_co2(1:min(numel(env_co2), numel(env_energy)));
                    yyaxis(ax, 'left');
                    h_energy = plot(ax, env_x, env_energy, 'LineWidth', 1.8, 'Color', app.layout_cfg.colors.accent_green);
                    ylabel(ax, 'Energy (Wh)', 'Color', app.layout_cfg.colors.fg_text);
                    yyaxis(ax, 'right');
                    h_co2 = plot(ax, env_x(1:numel(env_co2)), env_co2, 'LineWidth', 1.8, ...
                        'Color', app.layout_cfg.colors.accent_cyan, 'LineStyle', '--');
                    ylabel(ax, 'CO2e (g)', 'Color', app.layout_cfg.colors.fg_text);
                    app.apply_monitor_plot_format(ax, metric);
                    app.apply_monitor_dashboard_legend(ax, [h_energy, h_co2], {'Energy', 'CO2e'});
                    finite_env_x = env_x(isfinite(env_x));
                    if ~isempty(finite_env_x)
                        env_x_max = max(finite_env_x);
                        if ~(isfinite(env_x_max) && env_x_max > 0)
                            env_x_max = 1;
                        end
                        xlim(ax, [0, env_x_max]);
                    end
                    app.handles.monitor_slot_metric_ids{slot} = metric_id;
                    app.handles.monitor_line_handles{slot} = struct('metric_id', metric_id, 'line', gobjects(0));
                    continue;
                end

                if strcmp(metric_id, 'run_comparison')
                    cla(ax);
                    compare_cpu = app.rowvec(app.pick_field(monitor_series, {'run_compare_power_cpu_w'}, zeros(1, 0)));
                    compare_gpu = app.rowvec(app.pick_field(monitor_series, {'run_compare_power_gpu_w'}, zeros(1, 0)));
                    compare_mem = app.rowvec(app.pick_field(monitor_series, {'run_compare_memory_proxy'}, zeros(1, 0)));
                    compare_temp = app.rowvec(app.pick_field(monitor_series, {'run_compare_temperature_c'}, zeros(1, 0)));
                    compare_labels = app.pick_field(monitor_series, {'run_compare_labels'}, cell(1, 0));
                    if isempty(compare_cpu)
                        compare_cpu = [NaN NaN];
                        compare_gpu = [NaN NaN];
                        compare_mem = [NaN NaN];
                        compare_temp = [NaN NaN];
                        compare_labels = {'Prev', 'Current'};
                    end
                    x_bar = 1:numel(compare_cpu);
                    yyaxis(ax, 'left');
                    bh = bar(ax, x_bar, [compare_cpu(:), compare_gpu(:), compare_mem(:)], 'stacked');
                    bh(1).FaceColor = app.layout_cfg.colors.accent_green;
                    bh(2).FaceColor = app.layout_cfg.colors.accent_cyan;
                    bh(3).FaceColor = app.layout_cfg.colors.accent_yellow;
                    ylabel(ax, 'Power / Proxy', 'Color', app.layout_cfg.colors.fg_text);
                    yyaxis(ax, 'right');
                    h_temp = plot(ax, x_bar, compare_temp, '-o', 'LineWidth', 1.8, ...
                        'Color', app.layout_cfg.colors.accent_blue);
                    ylabel(ax, 'CPU Temp (C)', 'Color', app.layout_cfg.colors.fg_text);
                    app.apply_monitor_plot_format(ax, metric);
                    xticks(ax, x_bar);
                    if iscell(compare_labels) && numel(compare_labels) == numel(x_bar)
                        xticklabels(ax, compare_labels);
                    else
                        xticklabels(ax, compose('Run %d', x_bar));
                    end
                    ax.XTickLabelRotation = 20;
                    app.apply_monitor_dashboard_legend(ax, [bh(:); h_temp], ...
                        {'CPU Power', 'GPU Power', 'Memory', 'CPU Temp'});
                    app.handles.monitor_slot_metric_ids{slot} = metric_id;
                    app.handles.monitor_line_handles{slot} = struct('metric_id', metric_id, 'line', gobjects(0));
                    continue;
                end

                cache = [];
                if numel(app.handles.monitor_line_handles) >= slot
                    cache = app.handles.monitor_line_handles{slot};
                end
                trace_defs = app.monitor_metric_traces(metric.id, monitor_series, x, y);
                trace_count = numel(trace_defs);
                all_trace_x = zeros(1, 0);
                all_trace_y = zeros(1, 0);
                for ti = 1:trace_count
                    all_trace_x = [all_trace_x, app.rowvec(trace_defs(ti).x)]; %#ok<AGROW>
                    all_trace_y = [all_trace_y, app.rowvec(trace_defs(ti).y)]; %#ok<AGROW>
                end
                if isempty(all_trace_x)
                    all_trace_x = x;
                end
                if isempty(all_trace_y)
                    all_trace_y = y;
                end
                convergence_workflow_active = strcmp(metric.id, 'convergence_residual') && ...
                    app.is_phase1_style_workflow_kind(app.pick_text_field(monitor_series, {'workflow_kind'}, ''));
                metric_changed = ~isstruct(cache) || ~isfield(cache, 'metric_id') || ...
                    ~strcmp(cache.metric_id, metric_id);
                line_valid = isfield(cache, 'line') && ~isempty(cache.line) && ...
                    numel(cache.line) == trace_count && all(isgraphics(cache.line(:)));
                line_missing = metric_changed || ~line_valid;

                if line_missing
                    cla(ax);
                    hold(ax, 'on');
                    ln = gobjects(1, trace_count);
                    for ti = 1:trace_count
                        trace = trace_defs(ti);
                        ln(ti) = plot(ax, trace.x, trace.y, 'LineWidth', 1.8, ...
                            'Color', trace.color, 'LineStyle', trace.line_style, ...
                            'DisplayName', trace.label);
                    end
                    hold(ax, 'off');
                    cache = struct( ...
                        'metric_id', metric_id, ...
                        'line', ln, ...
                        'tol_line', gobjects(0), ...
                        'threshold_line', gobjects(0));
                    app.apply_monitor_plot_format(ax, metric);
                    if trace_count > 1
                        app.apply_monitor_dashboard_legend(ax, ln, {trace_defs.label});
                    else
                        app.clear_monitor_dashboard_legend(ax);
                    end
                else
                    for ti = 1:trace_count
                        set(cache.line(ti), 'XData', trace_defs(ti).x, 'YData', trace_defs(ti).y);
                    end
                end

                if strcmp(metric.id, 'cpu_proxy') || strcmp(metric.id, 'iteration_completion') || ...
                        strcmp(metric.id, 'gpu_usage')
                    ytickformat(ax, '%.2f');
                end

                if strcmp(metric.id, 'convergence_residual') && isfinite(tol) && tol > 0
                    if isfield(cache, 'tol_line') && ~isempty(cache.tol_line) && ...
                            any(isgraphics(cache.tol_line(:)))
                        delete(cache.tol_line);
                    end
                    cache.tol_line = yline(ax, tol, '--', sprintf('tol=%.3f%%', tol), ...
                        'Color', app.layout_cfg.colors.accent_yellow, 'LineWidth', 1.1);
                    if isfield(cache, 'threshold_line') && ~isempty(cache.threshold_line) && ...
                            any(isgraphics(cache.threshold_line(:)))
                        delete(cache.threshold_line);
                    end
                    if convergence_workflow_active
                        cache.threshold_line = gobjects(0);
                    elseif strcmpi(app.normalize_mode_token(display_cfg.mode), 'convergence')
                        idx = find(isfinite(all_trace_y) & all_trace_y <= 1.15 * tol, 1, 'first');
                        if ~isempty(idx) && numel(all_trace_x) >= idx
                            cache.threshold_line = xline(ax, all_trace_x(idx), ':', 'near-threshold', ...
                                'Color', app.layout_cfg.colors.accent_green, 'LineWidth', 1.0);
                        end
                    end
                else
                    if isfield(cache, 'tol_line') && ~isempty(cache.tol_line) && ...
                            any(isgraphics(cache.tol_line(:)))
                        delete(cache.tol_line);
                    end
                    if isfield(cache, 'threshold_line') && ~isempty(cache.threshold_line) && ...
                            any(isgraphics(cache.threshold_line(:)))
                        delete(cache.threshold_line);
                    end
                    cache.tol_line = gobjects(0);
                    cache.threshold_line = gobjects(0);
                end

                finite_x = all_trace_x(isfinite(all_trace_x));
                if ~isempty(finite_x)
                    if app.monitor_metric_uses_runtime_seconds(metric_id)
                        [x_limits, x_ticks, tick_format] = app.monitor_runtime_axis_policy(finite_x);
                        xlim(ax, x_limits);
                        ax.XTick = x_ticks;
                        xtickformat(ax, tick_format);
                    else
                        x_min = min(finite_x);
                        x_max = max(finite_x);
                        if ~(isfinite(x_min) && isfinite(x_max)) || x_max <= x_min
                            x_max = x_min + 1;
                        end
                        xlim(ax, [x_min, x_max]);
                    end
                end
                if convergence_workflow_active
                    finite_y = all_trace_y(isfinite(all_trace_y) & all_trace_y >= 0);
                    first_residual = NaN;
                    if ~isempty(finite_y)
                        first_residual = finite_y(1);
                    end
                    upper_bound = 1.0;
                    if isfinite(first_residual) && first_residual > 0
                        upper_bound = max(first_residual * 1.15, upper_bound);
                    end
                    if isfinite(tol) && tol > 0
                        upper_bound = max(upper_bound, tol * 1.15);
                    end
                    if ~isempty(finite_y)
                        upper_bound = max(upper_bound, max(finite_y) * 1.02);
                    end
                    ylim(ax, [0, upper_bound]);
                    title(ax, 'Convergence Residual (%)');
                    xlabel(ax, 'Mesh Level');
                    ylabel(ax, '\xi (%)');
                end

                app.handles.monitor_slot_metric_ids{slot} = metric_id;
                app.handles.monitor_line_handles{slot} = cache;
            end

            conv_metric = monitor_series.conv_metric;
            app.update_monitor_numeric_table(summary, display_cfg, monitor_series, mem_now, tol, conv_metric);
        end

        function apply_monitor_dashboard_legend(app, ax, plot_handles, labels)
            %#ok<INUSD>
            app.clear_monitor_dashboard_legend(ax);
        end

        function clear_monitor_dashboard_legend(app, ax)
            if ~(isgraphics(ax) && isvalid(ax))
                return;
            end
            try
                if isprop(ax, 'Legend')
                    lgd = ax.Legend;
                    if isgraphics(lgd) && isvalid(lgd)
                        delete(lgd);
                    end
                end
            catch
            end
        end

        function update_monitor_numeric_table(app, summary, cfg, monitor_series, mem_now, tol, conv_metric)
            % Update 2-column metrics grid with key/value pairs.
            has_grid = isfield(app.handles, 'monitor_metric_labels') && ...
                ~isempty(app.handles.monitor_metric_labels);
            has_table = app.has_valid_handle('monitor_numeric_table');
            if ~has_grid && ~has_table
                return;
            end
            RT = app.layout_cfg.ui_text.monitor.runtime;

            machine = getenv('COMPUTERNAME');
            if isempty(machine); machine = getenv('HOSTNAME'); end
            if isempty(machine); machine = 'unknown'; end

            run_mode = app.pick_text_field(cfg, {'mode', 'run_mode_internal'}, '');
            norm_mode = app.normalize_mode_token(run_mode);
            run_id = '';
            max_omega_val = NaN;
            wall_time = NaN;
            if isfield(summary, 'results') && isstruct(summary.results)
                if isfield(summary.results, 'run_id'); run_id = app.to_text(summary.results.run_id, ''); end
                if isfield(summary.results, 'max_omega')
                    max_omega_val = summary.results.max_omega;
                    if ~isscalar(max_omega_val); max_omega_val = max(abs(max_omega_val), [], 'all', 'omitnan'); end
                end
                if isfield(summary.results, 'wall_time'); wall_time = summary.results.wall_time; end
            end
            if isfield(summary, 'wall_time') && isfinite(summary.wall_time); wall_time = summary.wall_time; end

            status_text = RT.status_ready;
            if isfield(summary, 'monitor_series') && isstruct(summary.monitor_series)
                if isfield(summary.monitor_series, 'status_text')
                    status_text = app.pick_text_field(summary.monitor_series, {'status_text'}, RT.status_running);
                else
                    status_text = RT.status_running;
                end
            end
            if ~isempty(strtrim(run_id)); status_text = RT.status_completed; end

            conv_mode_active = strcmpi(norm_mode, 'convergence');
            conv_tol_d = 'N/A';
            if conv_mode_active
                conv_tol_d = app.if_nan_num(tol);
            end

            iter_now = app.last_finite_from_series(monitor_series, 'iters');
            iter_rate_now = app.last_finite_from_series(monitor_series, 'iter_rate');
            cpu_now = app.last_finite_from_series(monitor_series, 'cpu_proxy');
            gpu_now = app.last_finite_from_series(monitor_series, 'gpu_series');
            cpu_temp_now = app.last_finite_from_series(monitor_series, 'cpu_temp_c');
            power_now = app.last_finite_from_series(monitor_series, 'power_w');
            energy_used_now = app.last_finite_from_series(monitor_series, 'energy_joules');
            energy_sim_now = app.last_finite_from_series(monitor_series, 'energy_proxy');
            completion_now = app.last_finite_from_series(monitor_series, 'iter_completion_pct');
            if ~isfinite(wall_time)
                wall_time = app.last_finite_from_series(monitor_series, 'elapsed_wall_time');
            end
            if ~isfinite(max_omega_val)
                max_omega_val = app.last_finite_from_series(monitor_series, 'max_omega');
            end

            worker_topology = 'adaptive';
            if isfield(monitor_series, 'worker_topology') && ~isempty(monitor_series.worker_topology)
                worker_topology = app.to_text(monitor_series.worker_topology, worker_topology);
            elseif isfield(cfg, 'pool_workers')
                if cfg.pool_workers >= 3
                    worker_topology = '3-worker split';
                elseif cfg.pool_workers == 2
                    worker_topology = '2-worker combined';
                else
                    worker_topology = '1-worker background';
                end
            end
            collector_status = app.pick_field(monitor_series, {'collector_status'}, struct());
            if isstruct(collector_status)
                hwinfo_status_txt = app.humanize_monitor_collector_status( ...
                    app.if_empty(app.pick_field(collector_status, {'hwinfo'}, ''), 'off'));
                icue_status_txt = app.humanize_monitor_collector_status( ...
                    app.if_empty(app.pick_field(collector_status, {'icue'}, ''), 'off'));
                hwinfo_transport_txt = app.pick_text_field(monitor_series, {'hwinfo_transport'}, 'none');
                if ~strcmpi(hwinfo_transport_txt, 'none')
                    collector_status_txt = sprintf('HWiNFO %s [%s] | iCUE %s', ...
                        hwinfo_status_txt, ...
                        app.humanize_monitor_transport(hwinfo_transport_txt), ...
                        icue_status_txt);
                else
                    collector_status_txt = sprintf('HWiNFO %s | iCUE %s', hwinfo_status_txt, icue_status_txt);
                end
            else
                collector_status_txt = 'HWiNFO off | iCUE off';
            end
            telemetry_source_txt = app.monitor_telemetry_source_summary(monitor_series);

            if ~isfinite(mem_now)
                mem_now = app.last_finite_from_series(monitor_series, 'memory_series');
            end

            workflow_kind = app.pick_text_field(monitor_series, {'workflow_kind'}, '');
            workflow_active = app.is_live_monitor_workflow_kind(workflow_kind);
            workflow_queue_progress = app.pick_field(monitor_series, {'workflow_overall_progress_pct'}, NaN);
            child_progress_now = app.pick_field(monitor_series, {'workflow_child_progress_pct'}, NaN);
            child_method_txt = app.pick_text_field(monitor_series, {'workflow_child_method'}, '');
            child_mode_txt = app.pick_text_field(monitor_series, {'workflow_child_mode'}, '');
            child_run_id = app.pick_text_field(monitor_series, {'workflow_child_run_id'}, '');
            child_mesh_nx = app.pick_field(monitor_series, {'workflow_child_mesh_nx'}, NaN);
            child_mesh_ny = app.pick_field(monitor_series, {'workflow_child_mesh_ny'}, NaN);
            child_iteration_now = app.pick_field(monitor_series, {'workflow_child_iteration'}, NaN);
            child_conv_metric = app.pick_field(monitor_series, {'workflow_child_conv_residual'}, NaN);
            workflow_setup_txt = app.pick_text_field(monitor_series, {'workflow_test_case_setup'}, '');
            workflow_scenario_txt = app.pick_text_field(monitor_series, {'workflow_current_scenario', 'workflow_current_job_label'}, '');
            if workflow_active
                if isfinite(child_iteration_now)
                    iter_now = child_iteration_now;
                end
                if isfinite(child_progress_now)
                    completion_now = child_progress_now;
                end
                if strlength(string(strtrim(child_run_id))) > 0
                    run_id = child_run_id;
                end
                if isfinite(child_mesh_nx) && isfinite(child_mesh_ny)
                    mesh_txt = sprintf('%dx%d', round(child_mesh_nx), round(child_mesh_ny));
                end
            end

            conv_metric_display = app.if_nan_num(conv_metric);
            if ~conv_mode_active
                conv_metric_display = 'N/A';
            elseif workflow_active && isfinite(child_conv_metric)
                conv_metric_display = app.if_nan_num(child_conv_metric);
            end
            run_baseline = app.pick_field(monitor_series, {'run_compare_baseline_iter_rate'}, NaN);
            run_delta_pct = app.pick_field(monitor_series, {'run_compare_delta_pct'}, NaN);
            nx_cfg = app.pick_field(cfg, {'Nx'}, NaN);
            ny_cfg = app.pick_field(cfg, {'Ny'}, NaN);
            sim_method_label = app.humanize_token(cfg.method);
            sim_mode_label = app.humanize_token(run_mode);
            if workflow_active
                if strlength(string(strtrim(child_method_txt))) > 0
                    sim_method_label = child_method_txt;
                end
                if strlength(string(strtrim(child_mode_txt))) > 0
                    sim_mode_label = app.humanize_token(child_mode_txt);
                end
            end
            if isfinite(nx_cfg) && isfinite(ny_cfg)
                mesh_txt = sprintf('%dx%d', round(nx_cfg), round(ny_cfg));
            else
                mesh_txt = '--';
            end
            if workflow_active && isfinite(child_mesh_nx) && isfinite(child_mesh_ny)
                mesh_txt = sprintf('%dx%d', round(child_mesh_nx), round(child_mesh_ny));
            end
            workflow_current_txt = app.describe_workflow_current_activity(monitor_series);
            if strlength(string(strtrim(workflow_current_txt))) == 0
                workflow_current_txt = app.pick_text_field(monitor_series, {'workflow_current_job_label'}, '--');
            end
            if strlength(string(strtrim(workflow_setup_txt))) == 0
                workflow_setup_txt = '--';
            end
            if strlength(string(strtrim(workflow_scenario_txt))) == 0
                workflow_scenario_txt = '--';
            end

            % Build key/value pairs for 2-column layout.
            % First 11 rows map to left column (simulation/run), second 11 to right (compute/system).
            pairs = {
                'Sim: Status', status_text;
                'Sim: Run ID', app.if_empty(run_id, '--');
                'Sim: Method', sim_method_label;
                'Sim: Mode', sim_mode_label;
                'Sim: Mesh', mesh_txt;
                'Iter: Current', app.if_nan_num_fixed(iter_now, '%.0f');
                'Iter/s', app.if_nan_num_fixed(iter_rate_now, '%6.2f');
                'Complete (%)', app.if_nan_num_fixed(completion_now, '%6.2f');
                'Max |omega|', app.if_nan_num(max_omega_val);
                'Energy (sim)', app.if_nan_num(energy_sim_now);
                'Conv metric', conv_metric_display;
                'Conv tol', conv_tol_d;
                'Run workers', worker_topology;
                'Collectors', collector_status_txt;
                'Telemetry src', telemetry_source_txt;
                'CPU (%)', app.if_nan_num_fixed(cpu_now, '%6.2f');
                'GPU (%)', app.if_nan_num_fixed(gpu_now, '%6.2f');
                'Memory (%)', app.if_nan_num_fixed(mem_now, '%8.2f');
                'CPU Temp (C)', app.if_nan_num_fixed(cpu_temp_now, '%6.2f');
                'CPU Power (W)', app.if_nan_num_fixed(power_now, '%6.2f');
                'Energy Used (J)', app.if_nan_num_fixed(energy_used_now, '%8.2f');
                'Elapsed (s)', app.if_nan_num_fixed(wall_time, '%8.2f');
                'dt (s)', app.if_nan_num_fixed(cfg.dt, '%.4f');
                'Tfinal (s)', app.if_nan_num_fixed(cfg.Tfinal, '%.2f');
                'Baseline iter/s', app.if_nan_num_fixed(run_baseline, '%6.2f');
                'Delta vs baseline (%)', app.if_nan_num_fixed(run_delta_pct, '%6.2f');
                'Machine', machine;
            };

            if workflow_active
                workflow_label = 'Queued workflow';
                if strcmpi(workflow_kind, 'mesh_convergence_study')
                    workflow_label = 'Mesh convergence workflow';
                elseif strcmpi(workflow_kind, 'phase1_periodic_comparison')
                    workflow_label = 'Phase 1 queued workflow';
                elseif strcmpi(workflow_kind, 'phase2_boundary_condition_study')
                    workflow_label = 'Phase 2 boundary-case workflow';
                elseif strcmpi(workflow_kind, 'phase3_bathymetry_study')
                    workflow_label = 'Phase 3 bathymetry workflow';
                end
                queue_rows = {
                    'Workflow', workflow_label;
                    'Workflow Phase ID', app.pick_text_field(monitor_series, {'workflow_phase_id'}, '--');
                    'Workflow Progress (%)', app.if_nan_num_fixed(workflow_queue_progress, '%6.2f');
                    'Workflow Current', workflow_current_txt;
                    'Workflow Setup', workflow_setup_txt;
                    'Workflow Scenario', workflow_scenario_txt;
                    'Workflow Status', app.pick_text_field(monitor_series, {'workflow_current_status'}, '--')
                };
                workflow_queue = app.pick_field(monitor_series, {'workflow_queue'}, struct([]));
                if isstruct(workflow_queue) && ~isempty(workflow_queue)
                    for qi = 1:numel(workflow_queue)
                        queue_rows(end + 1, :) = { ... %#ok<AGROW>
                            sprintf('Queue %d', qi), ...
                            app.describe_workflow_queue_entry(workflow_kind, workflow_queue(qi))};
                    end
                end
                pairs = [queue_rows; pairs];
            end

            if has_grid
                % Populate 2-column label grid (pairs flow column-first: left col then right col)
                n_pairs = size(pairs, 1);
                half = ceil(n_pairs / 2);
                lbl_handles = app.handles.monitor_metric_labels;
                val_handles = app.handles.monitor_metric_values;
                slot = 0;
                for row_i = 1:min(11, half)
                    % Left column
                    slot = slot + 1;
                    if slot <= numel(lbl_handles) && isvalid(lbl_handles(slot))
                        lbl_handles(slot).Text = app.to_text(pairs{row_i, 1}, '');
                        val_handles(slot).Text = app.to_text(pairs{row_i, 2}, '');
                    end
                    % Right column
                    slot = slot + 1;
                    ri = row_i + half;
                    if ri <= n_pairs && slot <= numel(lbl_handles) && isvalid(lbl_handles(slot))
                        lbl_handles(slot).Text = app.to_text(pairs{ri, 1}, '');
                        val_handles(slot).Text = app.to_text(pairs{ri, 2}, '');
                    elseif slot <= numel(lbl_handles) && isvalid(lbl_handles(slot))
                        lbl_handles(slot).Text = '';
                        val_handles(slot).Text = '';
                    end
                end
            end

            rows = cell(size(pairs, 1), 1);
            for ri = 1:size(pairs, 1)
                rows{ri} = sprintf('%s: %s', app.to_text(pairs{ri, 1}, ''), app.to_text(pairs{ri, 2}, ''));
            end
            if has_table
                app.handles.monitor_numeric_table.Data = rows;
            end
        end

        function monitor_series = resolve_monitor_series(app, summary, cfg)
            % Build monitor tile data from runtime payloads.
            % Priority order:
            %   1) summary.monitor_series live buffers (from handle_live_monitor_progress)
            %   2) summary.results scalars (dispatcher outputs)
            %   3) idle-safe vectors (NaN/constant placeholders, no synthetic dynamics)
            t = [0, max(cfg.dt, eps)];
            iters = [0, 0];
            iter_rate = [NaN, NaN];

            max_omega = [NaN, NaN];
            if isfield(summary, 'results') && isstruct(summary.results) && isfield(summary.results, 'max_omega')
                m = summary.results.max_omega;
                if ~isscalar(m)
                    m = max(abs(m), [], 'all', 'omitnan');
                end
                max_omega = [abs(m), abs(m)];
            end

            energy_proxy = [NaN, NaN];
            enstrophy_proxy = [NaN, NaN];
            cfl_adv_series = [NaN, NaN];
            cfl_diff_series = [NaN, NaN];
            cfl_terminal_series = [NaN, NaN];
            cpu_proxy = [NaN, NaN];
            gpu_series = [NaN, NaN];
            cpu_temp_c = [NaN, NaN];
            power_w = [NaN, NaN];
            cpu_voltage_v = [NaN, NaN];
            gpu_voltage_v = [NaN, NaN];
            memory_voltage_v = [NaN, NaN];
            cpu_power_w_hwinfo = [NaN, NaN];
            gpu_power_w_hwinfo = [NaN, NaN];
            memory_power_w_or_proxy = [NaN, NaN];
            system_power_w = [NaN, NaN];
            fan_rpm = [NaN, NaN];
            pump_rpm = [NaN, NaN];
            coolant_temp_c = [NaN, NaN];
            environmental_energy_wh_cum = [NaN, NaN];
            environmental_co2_g_cum = [NaN, NaN];
            energy_joules = [NaN, NaN];
            energy_rate_w = [NaN, NaN];

            mem_now = NaN;
            if ispc
                try
                    mem_info = memory;
                    mem_now = mem_info.MemUsedMATLAB / 1024^2;
                catch ME
                    UIController.warn_once('UIController:MonitorSeriesMemoryProbeFailed', ...
                        'Memory probe failed in monitor-series resolver: %s', ME.message);
                    mem_now = NaN;
                end
            end
            memory_series = [mem_now, mem_now];
            elapsed_wall_time = t;
            iter_completion = [0, 0];
            vorticity_decay_rate = [NaN, NaN];
            stability_proxy = [NaN, NaN];
            conv_x = [0, 1];
            conv_residual = [NaN, NaN];
            worker_topology = 'adaptive';
            workflow_kind = '';
            workflow_phase_id = '';
            workflow_overall_progress_pct = NaN;
            workflow_child_progress_pct = NaN;
            workflow_child_method = '';
            workflow_child_mode = '';
            workflow_child_run_id = '';
            workflow_child_mesh_nx = NaN;
            workflow_child_mesh_ny = NaN;
            workflow_child_iteration = NaN;
            workflow_child_total_iterations = NaN;
            workflow_child_conv_residual = NaN;
            workflow_child_conv_peak = NaN;
            workflow_child_dt_used = NaN;
            workflow_child_dt_cfl = NaN;
            workflow_child_dt_adv = NaN;
            workflow_child_dt_diff = NaN;
            workflow_child_cfl_adv = NaN;
            workflow_child_cfl_diff = NaN;
            workflow_child_artifact_root = '';
            workflow_child_figures_root = '';
            workflow_child_reports_root = '';
            workflow_convergence_fd_x = zeros(1, 0);
            workflow_convergence_fd_residual = zeros(1, 0);
            workflow_convergence_spectral_x = zeros(1, 0);
            workflow_convergence_spectral_residual = zeros(1, 0);
            workflow_test_case_setup = '';
            workflow_current_scenario = '';
            workflow_current_job_label = '';
            workflow_current_status = '';
            workflow_queue = struct([]);
            collector_series = app.empty_collector_series();
            collector_status = struct('matlab', 'connected', 'hwinfo', 'disabled', 'icue', 'disabled');
            coverage_domains = struct('hwinfo', {{}}, 'icue', {{}});
            preferred_source = struct();
            raw_log_paths = struct('hwinfo', '', 'icue', '');
            overlay_metrics = {'cpu_proxy', 'gpu_series', 'memory_series', 'system_power_w', 'cpu_temp_c'};
            collector_metric_catalog = struct([]);
            hwinfo_transport = 'none';
            hwinfo_status_reason = '';
            collector_panel_profile = app.pick_text_field(cfg, {'collector_panel_profile'}, ...
                app.pick_text_field(app.pick_field(cfg, {'sustainability'}, struct()), {'collector_panel_profile'}, ''));
            collector_probe_details = struct('hwinfo', struct(), 'icue', struct());

            live = struct();
            if isfield(summary, 'monitor_series') && isstruct(summary.monitor_series)
                live = summary.monitor_series;
            end
            if ~isempty(fieldnames(live))
                t = app.rowvec(app.pick_field(live, {'t', 'time'}, zeros(1, 0)));
                if isempty(t)
                    n_live = app.infer_monitor_series_length(live);
                    t = linspace(0, max(cfg.dt, eps) * max(n_live - 1, 1), max(n_live, 2));
                end
                n_live = numel(t);

                iters = app.rowvec(app.pick_field(live, {'iters', 'iterations'}, nan(1, n_live)));
                if numel(iters) ~= n_live
                    iters = nan(1, n_live);
                end

                iter_rate = app.rowvec(app.pick_field(live, {'iter_rate', 'iterations_per_second'}, nan(1, n_live)));
                if numel(iter_rate) ~= n_live
                    iter_rate = nan(1, n_live);
                end
                if ~any(isfinite(iter_rate)) && n_live >= 2
                    iter_rate = gradient(iters, t + eps);
                end

                max_omega = app.rowvec(app.pick_field(live, {'max_omega', 'max_vorticity'}, nan(1, n_live)));
                if numel(max_omega) ~= n_live
                    max_omega = nan(1, n_live);
                end

                energy_proxy = app.rowvec(app.pick_field(live, {'energy_proxy', 'kinetic_energy'}, nan(1, n_live)));
                if numel(energy_proxy) ~= n_live
                    energy_proxy = nan(1, n_live);
                end

                enstrophy_proxy = app.rowvec(app.pick_field(live, {'enstrophy_proxy', 'enstrophy'}, nan(1, n_live)));
                if numel(enstrophy_proxy) ~= n_live
                    enstrophy_proxy = nan(1, n_live);
                end

                cfl_adv_series = app.rowvec(app.pick_field(live, {'cfl_adv_series'}, nan(1, n_live)));
                if numel(cfl_adv_series) ~= n_live
                    cfl_adv_series = nan(1, n_live);
                end

                cfl_diff_series = app.rowvec(app.pick_field(live, {'cfl_diff_series'}, nan(1, n_live)));
                if numel(cfl_diff_series) ~= n_live
                    cfl_diff_series = nan(1, n_live);
                end

                cfl_terminal_series = app.rowvec(app.pick_field(live, {'cfl_terminal_series'}, nan(1, n_live)));
                if numel(cfl_terminal_series) ~= n_live
                    cfl_terminal_series = nan(1, n_live);
                end

                cpu_proxy = app.rowvec(app.pick_field(live, {'cpu_proxy', 'cpu_percent'}, nan(1, n_live)));
                if numel(cpu_proxy) ~= n_live
                    cpu_proxy = nan(1, n_live);
                end

                gpu_series = app.rowvec(app.pick_field(live, {'gpu_series', 'gpu_usage'}, nan(1, n_live)));
                if numel(gpu_series) ~= n_live
                    gpu_series = nan(1, n_live);
                end

                cpu_temp_c = app.rowvec(app.pick_field(live, {'cpu_temp_c', 'cpu_temp'}, nan(1, n_live)));
                if numel(cpu_temp_c) ~= n_live
                    cpu_temp_c = nan(1, n_live);
                end

                power_w = app.rowvec(app.pick_field(live, {'power_w', 'power_consumption', 'power_draw_w'}, nan(1, n_live)));
                if numel(power_w) ~= n_live
                    power_w = nan(1, n_live);
                end
                cpu_voltage_v = app.rowvec(app.pick_field(live, {'cpu_voltage_v'}, nan(1, n_live)));
                if numel(cpu_voltage_v) ~= n_live
                    cpu_voltage_v = nan(1, n_live);
                end
                gpu_voltage_v = app.rowvec(app.pick_field(live, {'gpu_voltage_v'}, nan(1, n_live)));
                if numel(gpu_voltage_v) ~= n_live
                    gpu_voltage_v = nan(1, n_live);
                end
                memory_voltage_v = app.rowvec(app.pick_field(live, {'memory_voltage_v'}, nan(1, n_live)));
                if numel(memory_voltage_v) ~= n_live
                    memory_voltage_v = nan(1, n_live);
                end
                cpu_power_w_hwinfo = app.rowvec(app.pick_field(live, {'cpu_power_w_hwinfo'}, nan(1, n_live)));
                if numel(cpu_power_w_hwinfo) ~= n_live
                    cpu_power_w_hwinfo = nan(1, n_live);
                end
                gpu_power_w_hwinfo = app.rowvec(app.pick_field(live, {'gpu_power_w_hwinfo'}, nan(1, n_live)));
                if numel(gpu_power_w_hwinfo) ~= n_live
                    gpu_power_w_hwinfo = nan(1, n_live);
                end
                memory_power_w_or_proxy = app.rowvec(app.pick_field(live, {'memory_power_w_or_proxy'}, nan(1, n_live)));
                if numel(memory_power_w_or_proxy) ~= n_live
                    memory_power_w_or_proxy = nan(1, n_live);
                end
                system_power_w = app.rowvec(app.pick_field(live, {'system_power_w'}, nan(1, n_live)));
                if numel(system_power_w) ~= n_live
                    system_power_w = nan(1, n_live);
                end
                fan_rpm = app.rowvec(app.pick_field(live, {'fan_rpm'}, nan(1, n_live)));
                if numel(fan_rpm) ~= n_live
                    fan_rpm = nan(1, n_live);
                end
                pump_rpm = app.rowvec(app.pick_field(live, {'pump_rpm'}, nan(1, n_live)));
                if numel(pump_rpm) ~= n_live
                    pump_rpm = nan(1, n_live);
                end
                coolant_temp_c = app.rowvec(app.pick_field(live, {'coolant_temp_c'}, nan(1, n_live)));
                if numel(coolant_temp_c) ~= n_live
                    coolant_temp_c = nan(1, n_live);
                end
                environmental_energy_wh_cum = app.rowvec(app.pick_field(live, {'environmental_energy_wh_cum'}, nan(1, n_live)));
                if numel(environmental_energy_wh_cum) ~= n_live
                    environmental_energy_wh_cum = nan(1, n_live);
                end
                environmental_co2_g_cum = app.rowvec(app.pick_field(live, {'environmental_co2_g_cum'}, nan(1, n_live)));
                if numel(environmental_co2_g_cum) ~= n_live
                    environmental_co2_g_cum = nan(1, n_live);
                end

                energy_joules = app.rowvec(app.pick_field(live, {'energy_joules', 'energy_j'}, nan(1, n_live)));
                if numel(energy_joules) ~= n_live
                    energy_joules = nan(1, n_live);
                end

                energy_rate_w = app.rowvec(app.pick_field(live, {'energy_rate_w', 'power_w'}, nan(1, n_live)));
                if numel(energy_rate_w) ~= n_live
                    energy_rate_w = nan(1, n_live);
                end

                memory_series = app.rowvec(app.pick_field(live, {'memory_series', 'memory_mb'}, nan(1, n_live)));
                if numel(memory_series) ~= n_live
                    memory_series = nan(1, n_live);
                end

                elapsed_wall_time = app.rowvec(app.pick_field(live, {'elapsed_wall_time', 'runtime_series', 'wall_time_series'}, t));
                if numel(elapsed_wall_time) ~= n_live
                    elapsed_wall_time = t;
                end

                iter_completion = app.rowvec(app.pick_field(live, {'iter_completion_pct', 'completion_pct'}, nan(1, n_live)));
                if numel(iter_completion) ~= n_live
                    iter_completion = nan(1, n_live);
                end
                if ~any(isfinite(iter_completion))
                    denom = max(max(iters), 1);
                    iter_completion = 100 * min(max(iters ./ denom, 0), 1);
                end

                vorticity_decay_rate = app.rowvec(app.pick_field(live, {'vorticity_decay_rate', 'decay_rate'}, nan(1, n_live)));
                if numel(vorticity_decay_rate) ~= n_live
                    vorticity_decay_rate = nan(1, n_live);
                end

                stability_proxy = app.rowvec(app.pick_field(live, {'stability_proxy', 'cfl_proxy'}, nan(1, n_live)));
                if numel(stability_proxy) ~= n_live
                    stability_proxy = nan(1, n_live);
                end

                conv_x = app.rowvec(app.pick_field(live, {'conv_x', 'conv_iteration'}, iters));
                if numel(conv_x) ~= n_live
                    conv_x = iters;
                end
                conv_residual = app.rowvec(app.pick_field(live, {'conv_residual', 'convergence_residual'}, nan(1, n_live)));
                if numel(conv_residual) ~= n_live
                    conv_residual = nan(1, n_live);
                end

                worker_topology = app.pick_text_field(live, {'worker_topology'}, worker_topology);
                workflow_kind = app.pick_text_field(live, {'workflow_kind'}, workflow_kind);
                workflow_phase_id = app.pick_text_field(live, {'workflow_phase_id'}, workflow_phase_id);
                workflow_overall_progress_pct = app.progress_field(live, {'workflow_overall_progress_pct'}, workflow_overall_progress_pct);
                workflow_child_progress_pct = app.progress_field(live, {'workflow_child_progress_pct'}, workflow_child_progress_pct);
