            end

            if ~any(isfinite(energy_rate_w)) && numel(energy_joules) >= 2
                energy_rate_w = gradient(energy_joules, elapsed_wall_time + eps);
            end
            if ~any(isfinite(vorticity_decay_rate)) && numel(max_omega) >= 2
                vorticity_decay_rate = max(0, -gradient(abs(max_omega), t + eps));
            end
            if ~any(isfinite(stability_proxy))
                stability_proxy = 1 ./ (1 + abs(vorticity_decay_rate));
            end

