        function cfg_out = resolve_workflow_monitor_cfg(app, cfg, monitor_series)
            cfg_out = cfg;
            if ~isstruct(monitor_series)
                return;
            end
            workflow_kind = app.pick_text_field(monitor_series, {'workflow_kind'}, '');
            if ~app.is_live_monitor_workflow_kind(workflow_kind)
                return;
            end

            child_method = app.pick_text_field(monitor_series, {'workflow_child_method'}, '');
            child_mode = app.pick_text_field(monitor_series, {'workflow_child_mode'}, '');
            child_nx = app.progress_field(monitor_series, {'workflow_child_mesh_nx'}, NaN);
            child_ny = app.progress_field(monitor_series, {'workflow_child_mesh_ny'}, NaN);

            if strlength(string(strtrim(child_method))) > 0
                cfg_out.method = child_method;
                cfg_out.analysis_method = child_method;
            end
            if strlength(string(strtrim(child_mode))) > 0
                cfg_out.mode = child_mode;
                cfg_out.run_mode_internal = app.humanize_token(child_mode);
            end
            if isfinite(child_nx)
                cfg_out.Nx = child_nx;
            end
            if isfinite(child_ny)
                cfg_out.Ny = child_ny;
            end
        end

