        function value = pick_field(~, s, keys, fallback)
            value = fallback;
            for i = 1:numel(keys)
                key = keys{i};
                if isfield(s, key)
                    value = s.(key);
                    return;
                end
            end
        end

        function value = pick_text_field(app, s, keys, fallback)
            if nargin < 4
                fallback = '';
            end
            value = app.to_text(app.pick_field(s, keys, fallback), fallback);
        end

        function text = to_text(app, value, fallback)
            if nargin < 3
                fallback = '';
            end

            fallback_text = '';
            try
                fallback_text = char(string(fallback));
            catch
                fallback_text = '';
            end
            text = fallback_text;

            if nargin < 2 || isempty(value)
                return;
            end

            candidate = value;
            if iscell(candidate)
                if isempty(candidate) || ~isscalar(candidate)
                    return;
                end
                text = app.to_text(candidate{1}, fallback_text);
                return;
            end

            if ischar(candidate)
                text = char(candidate);
            elseif isstring(candidate)
                if ~isempty(candidate)
                    text = char(candidate(1));
                end
            elseif isnumeric(candidate) || islogical(candidate)
                if isscalar(candidate)
                    text = char(string(candidate));
                end
            elseif isstruct(candidate)
                if isscalar(candidate)
                    preferred_keys = {'label', 'name', 'text', 'value', 'status_text', 'status', ...
                        'mode', 'phase', 'stage_name', 'job_label', 'job_key', 'workflow_kind', ...
                        'id', 'token', 'kind', 'run_id', 'study_id'};
                    resolved = false;
                    for i = 1:numel(preferred_keys)
                        key = preferred_keys{i};
                        if isfield(candidate, key) && ~isempty(candidate.(key))
                            text = app.to_text(candidate.(key), fallback_text);
                            resolved = true;
                            break;
                        end
                    end
                    if ~resolved
                        field_names = fieldnames(candidate);
                        max_fields = min(numel(field_names), 4);
                        parts = cell(1, 0);
                        for i = 1:max_fields
                            key = field_names{i};
                            value_text = app.to_text(candidate.(key), '');
                            if strlength(string(strtrim(value_text))) > 0
                                parts{end + 1} = sprintf('%s=%s', key, value_text); %#ok<AGROW>
                            elseif isnumeric(candidate.(key)) || islogical(candidate.(key))
                                dims = size(candidate.(key));
                                parts{end + 1} = sprintf('%s=[%s %s]', key, class(candidate.(key)), mat2str(dims)); %#ok<AGROW>
                            elseif isstruct(candidate.(key))
                                nested_fields = fieldnames(candidate.(key));
                                nested_preview = strjoin(nested_fields(1:min(numel(nested_fields), 3)), ',');
                                if numel(nested_fields) > 3
                                    nested_preview = sprintf('%s,+%d', nested_preview, numel(nested_fields) - 3);
                                end
                                parts{end + 1} = sprintf('%s={%s}', key, nested_preview); %#ok<AGROW>
                            else
                                parts{end + 1} = sprintf('%s=[%s]', key, class(candidate.(key))); %#ok<AGROW>
                            end
                        end
                        if numel(field_names) > max_fields
                            parts{end + 1} = sprintf('+%d fields', numel(field_names) - max_fields); %#ok<AGROW>
                        end
                        if ~isempty(parts)
                            text = strjoin(parts, ' | ');
                        end
                    end
                end
            else
                try
                    if isscalar(candidate)
                        text = char(string(candidate));
                    end
                catch
                    text = fallback_text;
                end
            end

            if isempty(text)
                text = fallback_text;
            end
        end

        function tf = are_live_handles(app, varargin)
            tf = true;
            for i = 1:numel(varargin)
                if ~app.is_live_handle(varargin{i})
                    tf = false;
                    return;
                end
            end
        end

        function value = pick_field_required(~, s, keys, ~)
            % Strict default lookup for create_default_parameters()-sourced UI defaults.
            % Signature intentionally accepts a legacy "fallback" arg so call sites can
            % be migrated mechanically while enforcing fail-fast behavior.
            for i = 1:numel(keys)
                key = keys{i};
                if isfield(s, key)
                    value = s.(key);
                    return;
                end
            end
            error('UIController:MissingDefaultField', ...
                'Required default field missing from create_default_parameters(): %s', ...
                strjoin(keys, ', '));
        end

        function v = rowvec(~, value)
            if ~isnumeric(value)
                v = zeros(1, 0);
                return;
            end
            v = reshape(double(value), 1, []);
        end

        function selected = select_monitor_metric_indices(app, cfg, slot_count)
            if nargin < 4 || isempty(slot_count)
                slot_count = 8;
            end
            catalog = app.handles.monitor_metric_catalog;
            if isempty(catalog)
                selected = 1:min(slot_count, 0);
                return;
            end

            applicable = find(arrayfun(@(m) app.is_monitor_metric_applicable(m, cfg), catalog));
            if isempty(applicable)
                applicable = 1:numel(catalog);
            end
            [~, order] = sort([catalog(applicable).rank], 'ascend');
            selected = applicable(order);

            if numel(selected) < slot_count
                remaining = setdiff(1:numel(catalog), selected, 'stable');
                if ~isempty(remaining)
                    [~, rem_order] = sort([catalog(remaining).rank], 'ascend');
                    selected = [selected, remaining(rem_order)]; %#ok<AGROW>
                end
            end
            selected = selected(1:min(slot_count, numel(selected)));
        end

        function [x, y] = monitor_metric_series(app, metric_id, monitor_series)
            time_x = app.monitor_time_vector(monitor_series);
            switch metric_id
                case 'iter_vs_time'
                    x = time_x; y = monitor_series.iters;
                case 'iter_per_sec'
                    x = time_x; y = monitor_series.iter_rate;
                case 'runtime_vs_time'
                    x = time_x; y = monitor_series.elapsed_wall_time;
                case 'max_vorticity'
                    x = time_x; y = monitor_series.max_omega;
                case 'energy_proxy'
                    x = time_x; y = monitor_series.energy_proxy;
                case 'enstrophy_proxy'
                    x = time_x; y = monitor_series.enstrophy_proxy;
                case 'kinetic_energy_live'
                    x = time_x; y = monitor_series.energy_proxy;
                case 'enstrophy_live'
                    x = time_x; y = monitor_series.enstrophy_proxy;
                case 'vorticity_decay_rate'
                    x = time_x; y = monitor_series.vorticity_decay_rate;
                case 'cpu_proxy'
                    x = time_x; y = monitor_series.cpu_proxy;
                case 'gpu_usage'
                    x = time_x; y = monitor_series.gpu_series;
                case {'memory_usage', 'memory_mb'}
                    x = time_x; y = monitor_series.memory_series;
                case {'power_overlay', 'cpu_temperature'}
                    x = time_x; y = monitor_series.cpu_power_w_hwinfo;
                case 'power_usage'
                    x = time_x; y = monitor_series.power_w;
                case {'voltage_overlay', 'energy_usage'}
                    x = time_x; y = monitor_series.cpu_voltage_v;
                case 'vorticity_histogram'
                    x = time_x; y = monitor_series.max_omega;
                case {'environmental_impact', 'resource_heatmap'}
                    x = time_x; y = monitor_series.environmental_energy_wh_cum;
                case 'run_comparison'
                    y = app.pick_field(monitor_series, {'run_compare_power_cpu_w'}, zeros(1, 0));
                    x = 1:numel(y);
                case 'cfl_overlay'
                    x = time_x;
                    y = monitor_series.cfl_terminal_series;
                case 'iteration_completion'
                    x = time_x; y = monitor_series.iter_completion_pct;
                case 'stability_proxy'
                    x = time_x; y = monitor_series.stability_proxy;
                case 'convergence_residual'
                    x = monitor_series.conv_x; y = monitor_series.conv_residual;
                otherwise
                    x = time_x; y = nan(size(time_x));
            end
        end

        function traces = monitor_metric_traces(app, metric_id, monitor_series, x_fallback, y_fallback)
            if nargin < 4
                x_fallback = app.monitor_time_vector(monitor_series);
            end
            if nargin < 5
                y_fallback = nan(size(x_fallback));
            end

            switch char(string(metric_id))
                case 'cpu_proxy'
                    traces = app.monitor_collector_source_traces( ...
                        x_fallback, monitor_series, 'cpu_proxy', {'hwinfo', 'matlab', 'icue'});
                    if ~isempty(traces)
                        return;
                    end
                case 'gpu_usage'
                    traces = app.monitor_collector_source_traces( ...
                        x_fallback, monitor_series, 'gpu_series', {'hwinfo', 'matlab', 'icue'});
                    if ~isempty(traces)
                        return;
                    end
                case {'memory_usage', 'memory_mb'}
                    traces = app.monitor_collector_source_traces( ...
                        x_fallback, monitor_series, 'memory_series', {'hwinfo', 'matlab'});
                    if ~isempty(traces)
                        return;
                    end
                case 'power_usage'
                    traces = app.monitor_collector_source_traces( ...
                        x_fallback, monitor_series, 'power_w', {'hwinfo', 'icue', 'matlab'});
                    if ~isempty(traces)
                        return;
                    end
                case 'convergence_residual'
                    traces = app.phase1_convergence_traces(monitor_series);
                    if ~isempty(traces)
                        return;
                    end
                case 'cfl_overlay'
                    traces = app.monitor_cfl_traces(x_fallback, monitor_series);
                    if ~isempty(traces)
                        return;
                    end
                case {'voltage_overlay', 'energy_usage'}
                    traces = app.monitor_overlay_traces(x_fallback, monitor_series, { ...
                        struct('field', 'cpu_voltage_v', 'label', 'CPU Voltage', 'color', app.layout_cfg.colors.accent_green, 'line_style', '-'), ...
                        struct('field', 'gpu_voltage_v', 'label', 'GPU Voltage', 'color', app.layout_cfg.colors.accent_cyan, 'line_style', '--'), ...
                        struct('field', 'memory_voltage_v', 'label', 'Memory Voltage', 'color', app.layout_cfg.colors.accent_yellow, 'line_style', ':')});
                    if ~isempty(traces)
                        return;
                    end
                case {'power_overlay', 'cpu_temperature'}
                    memory_label = 'Memory Power';
                    if app.pick_field(monitor_series, {'memory_power_is_proxy'}, false)
                        memory_label = 'Memory Demand Proxy';
                    end
                    traces = app.monitor_overlay_traces(x_fallback, monitor_series, { ...
                        struct('field', 'cpu_power_w_hwinfo', 'label', 'CPU Power', 'color', app.layout_cfg.colors.accent_green, 'line_style', '-'), ...
                        struct('field', 'gpu_power_w_hwinfo', 'label', 'GPU Power', 'color', app.layout_cfg.colors.accent_cyan, 'line_style', '--'), ...
                        struct('field', 'memory_power_w_or_proxy', 'label', memory_label, 'color', app.layout_cfg.colors.accent_yellow, 'line_style', ':')});
                    if ~isempty(traces)
                        return;
                    end
            end

            traces = struct('x', {x_fallback}, 'y', {y_fallback}, ...
                'label', {''}, 'color', {app.layout_cfg.colors.accent_cyan}, ...
                'line_style', {'-'});
        end

        function traces = monitor_collector_source_traces(app, x_values, monitor_series, metric_key, source_order)
            traces = struct('x', {}, 'y', {}, 'label', {}, 'color', {}, 'line_style', {});
            for i = 1:numel(source_order)
                source = source_order{i};
                values = app.collector_metric_vector(monitor_series, source, metric_key);
                [trace_x, trace_y] = app.normalize_metric_vectors(x_values, values);
                if ~any(isfinite(trace_y))
                    continue;
                end
                [color, line_style] = app.collector_source_style(source);
                traces(end + 1) = struct( ... %#ok<AGROW>
                    'x', trace_x, ...
                    'y', trace_y, ...
                    'label', app.collector_source_display_label(source), ...
                    'color', color, ...
                    'line_style', line_style);
            end
        end

        function traces = monitor_cfl_traces(app, x_values, monitor_series)
            traces = struct('x', {}, 'y', {}, 'label', {}, 'color', {}, 'line_style', {});
            specs = { ...
                struct('field', 'cfl_adv_series', 'label', 'CFLa', 'color', app.layout_cfg.colors.accent_green, 'line_style', '-'), ...
                struct('field', 'cfl_diff_series', 'label', 'CFLd', 'color', app.layout_cfg.colors.accent_cyan, 'line_style', '--')};
            for i = 1:numel(specs)
                values = app.rowvec(app.pick_field(monitor_series, {specs{i}.field}, zeros(1, 0)));
                [trace_x, trace_y] = app.normalize_metric_vectors(x_values, values);
                if ~any(isfinite(trace_y))
                    continue;
                end
                traces(end + 1) = struct( ... %#ok<AGROW>
                    'x', trace_x, ...
                    'y', trace_y, ...
                    'label', specs{i}.label, ...
                    'color', specs{i}.color, ...
                    'line_style', specs{i}.line_style);
            end
            if ~isempty(traces)
                return;
            end

            fallback_values = app.rowvec(app.pick_field(monitor_series, {'cfl_terminal_series'}, zeros(1, 0)));
            [trace_x, trace_y] = app.normalize_metric_vectors(x_values, fallback_values);
            if any(isfinite(trace_y))
                traces = struct('x', {trace_x}, 'y', {trace_y}, ...
                    'label', {'CFL'}, 'color', {app.layout_cfg.colors.accent_yellow}, ...
                    'line_style', {'-'});
            end
        end

        function values = collector_metric_vector(~, monitor_series, source, metric_key)
            values = zeros(1, 0);
            if strcmpi(char(string(source)), 'normalized')
                if isfield(monitor_series, metric_key) && isnumeric(monitor_series.(metric_key))
                    values = reshape(double(monitor_series.(metric_key)), 1, []);
                    if any(isfinite(values))
                        return;
                    end
                end
                fallback_sources = {'hwinfo', 'icue', 'matlab'};
                for i = 1:numel(fallback_sources)
                    if ~isfield(monitor_series, 'collector_series') || ~isstruct(monitor_series.collector_series)
                        break;
                    end
                    if ~isfield(monitor_series.collector_series, fallback_sources{i}) || ...
                            ~isstruct(monitor_series.collector_series.(fallback_sources{i})) || ...
                            ~isfield(monitor_series.collector_series.(fallback_sources{i}), metric_key)
                        continue;
                    end
                    candidate = monitor_series.collector_series.(fallback_sources{i}).(metric_key);
                    if isnumeric(candidate) && any(isfinite(candidate))
                        values = reshape(double(candidate), 1, []);
                        return;
                    end
                end
                return;
            end
            if ~isfield(monitor_series, 'collector_series') || ~isstruct(monitor_series.collector_series)
                return;
            end
            if ~isfield(monitor_series.collector_series, source) || ~isstruct(monitor_series.collector_series.(source))
                return;
            end
            source_struct = monitor_series.collector_series.(source);
            if ~isfield(source_struct, metric_key) || ~isnumeric(source_struct.(metric_key))
                return;
            end
            values = reshape(double(source_struct.(metric_key)), 1, []);
        end

        function [color, line_style] = collector_source_style(app, source)
            style = ExternalCollectorDispatcher.source_plot_style(source);
            color = style.rgb;
            line_style = style.line_style;
        end

        function [x, y] = normalize_metric_vectors(app, x_raw, y_raw)
            x = app.rowvec(x_raw);
            y = app.rowvec(y_raw);
            n = min(numel(x), numel(y));
            if n < 1
                x = [0, 1];
                y = [nan, nan];
                return;
            end
            x = x(1:n);
            y = y(1:n);
            if n == 1
                x0 = x(1);
                y0 = y(1);
                if ~isfinite(x0)
                    x = [0, 1];
                    y = [y0, y0];
                    return;
                end
                if abs(x0) > 1e9
                    delta = 1.0;
                else
                    delta = max(1.0e-3, max(abs(x0), 1.0) * 1.0e-3);
                end
                x = [x0, x0 + delta];
                y = [y0, y0];
            end
        end

        function traces = phase1_convergence_traces(app, monitor_series)
            traces = struct('x', {}, 'y', {}, 'label', {}, 'color', {}, 'line_style', {});
            workflow_kind = app.pick_text_field(monitor_series, {'workflow_kind'}, '');
            if ~app.is_phase1_style_workflow_kind(workflow_kind)
                return;
            end
            trace_specs = { ...
                struct('x_field', 'workflow_convergence_fd_x', ...
                    'y_field', 'workflow_convergence_fd_residual', ...
                    'label', 'FD', ...
                    'color', app.layout_cfg.colors.accent_green, ...
                    'line_style', '-'), ...
                struct('x_field', 'workflow_convergence_spectral_x', ...
                    'y_field', 'workflow_convergence_spectral_residual', ...
                    'label', 'Spectral', ...
                    'color', app.layout_cfg.colors.accent_cyan, ...
                    'line_style', '--')};
            for i = 1:numel(trace_specs)
                x_values = app.rowvec(app.pick_field(monitor_series, {trace_specs{i}.x_field}, zeros(1, 0)));
                y_values = app.rowvec(app.pick_field(monitor_series, {trace_specs{i}.y_field}, zeros(1, 0)));
                [trace_x, trace_y] = app.normalize_metric_vectors(x_values, y_values);
                if ~any(isfinite(trace_y))
                    continue;
                end
                traces(end + 1) = struct( ... %#ok<AGROW>
                    'x', trace_x, ...
                    'y', trace_y, ...
                    'label', trace_specs{i}.label, ...
                    'color', trace_specs{i}.color, ...
                    'line_style', trace_specs{i}.line_style);
            end
        end

        function x = monitor_time_vector(app, monitor_series)
            x = app.monitor_elapsed_seconds( ...
                app.rowvec(app.pick_field(monitor_series, {'elapsed_wall_time'}, zeros(1, 0))));
            if ~isempty(x) && any(isfinite(x))
                return;
            end
            x = app.monitor_elapsed_seconds( ...
                app.rowvec(app.pick_field(monitor_series, {'wall_clock_time'}, zeros(1, 0))));
            if ~isempty(x) && any(isfinite(x))
                return;
            end
            x = app.monitor_elapsed_seconds( ...
                app.rowvec(app.pick_field(monitor_series, {'t', 'time'}, zeros(1, 0))));
        end

        function x = monitor_elapsed_seconds(~, values)
            x = reshape(double(values), 1, []);
            if isempty(x)
                return;
            end
            finite_idx = find(isfinite(x), 1, 'first');
            if isempty(finite_idx)
                return;
            end
            x = x - x(finite_idx);
            x(~isfinite(x)) = NaN;
            x = max(x, 0);
        end

        function tf = monitor_metric_uses_runtime_seconds(~, metric_id)
            tf = ~any(strcmp(char(string(metric_id)), {'run_comparison', 'convergence_residual', 'vorticity_histogram'}));
        end

        function [x_limits, x_ticks, tick_format] = monitor_runtime_axis_policy(app, x_values)
            finite_x = double(x_values(isfinite(x_values)));
            if isempty(finite_x)
                x_limits = [0, 1];
                x_ticks = 0:0.2:1;
                tick_format = '%.2f';
                return;
            end

            x_max = max([finite_x(:); 0]);
            if ~(isfinite(x_max) && x_max > 0)
                step = 0.2;
                upper = 1;
            else
                target_tick_count = 6;
                raw_step = x_max / max(target_tick_count - 1, 1);
                step = app.nice_axis_step(raw_step);
                upper = step * ceil(x_max / step);
                if abs(upper - x_max) < max(step * 1e-6, eps(step))
                    upper = upper + step;
                end
            end

            upper = max(upper, step);
            x_limits = [0, upper];
            x_ticks = 0:step:upper;
            tick_format = app.runtime_axis_tick_format(step);
        end

        function step = nice_axis_step(~, raw_step)
            raw_step = max(double(raw_step), eps);
            exponent = floor(log10(raw_step));
            fraction = raw_step / (10 ^ exponent);
            if fraction <= 1
                nice_fraction = 1;
            elseif fraction <= 2
                nice_fraction = 2;
            elseif fraction <= 5
                nice_fraction = 5;
            else
                nice_fraction = 10;
            end
            step = nice_fraction * (10 ^ exponent);
        end

        function tick_format = runtime_axis_tick_format(~, step)
            step = abs(double(step));
            if step >= 10
                tick_format = '%.0f';
            elseif step >= 1
                tick_format = '%.1f';
            elseif step >= 0.1
                tick_format = '%.2f';
            else
                tick_format = '%.3f';
            end
        end

        function traces = monitor_overlay_traces(app, x_values, monitor_series, trace_specs)
            traces = struct('x', {}, 'y', {}, 'label', {}, 'color', {}, 'line_style', {});
            for i = 1:numel(trace_specs)
                values = app.rowvec(app.pick_field(monitor_series, {trace_specs{i}.field}, zeros(1, 0)));
                [trace_x, trace_y] = app.normalize_metric_vectors(x_values, values);
                if ~any(isfinite(trace_y))
                    continue;
                end
                traces(end + 1) = struct( ... %#ok<AGROW>
                    'x', trace_x, ...
                    'y', trace_y, ...
                    'label', trace_specs{i}.label, ...
                    'color', trace_specs{i}.color, ...
                    'line_style', trace_specs{i}.line_style);
            end
        end

        function apply_wall_clock_ticks(~, ax, x_values)
            x = reshape(double(x_values), 1, []);
            x = x(isfinite(x) & x > 1e9);
            if isempty(x)
                return;
            end
            ticks = ax.XTick;
            if isempty(ticks)
                return;
            end
            tick_dt = datetime(ticks, 'ConvertFrom', 'posixtime', 'TimeZone', 'local');
            ax.XTickLabel = cellstr(string(tick_dt, 'HH:mm:ss'));
        end

        function apply_monitor_plot_format(app, ax, metric)
            app.style_axes(ax);
            ax.PlotBoxAspectRatio = [1 1 1];
            ax.PlotBoxAspectRatioMode = 'manual';
            grid(ax, 'on');

            fig = ancestor(ax, 'figure');
            if ~isempty(fig) && isprop(fig, 'CurrentAxes')
                try
                    fig.CurrentAxes = ax;
                catch ME
                    UIController.warn_once('UIController:SetCurrentAxesFailed', ...
                        'Could not set CurrentAxes during monitor formatting: %s', ME.message);
                end
            end

            title_interp = app.pick_metric_interpreter(metric.title);
            x_interp = app.pick_metric_interpreter(metric.xlabel);
            y_interp = app.pick_metric_interpreter(metric.ylabel);
            ResultsPlotDispatcher.apply_axes(ax, ...
                struct( ...
                    'xlabel', metric.xlabel, ...
                    'ylabel', metric.ylabel, ...
                    'title', metric.title, ...
                    'x_interpreter', x_interp, ...
                    'y_interpreter', y_interp, ...
                    'title_interpreter', title_interp), ...
                ResultsPlotDispatcher.defaults(), ResultsPlotDispatcher.default_colors());

            % Enforce per-axis labels directly so dynamic tile assignment remains deterministic.
            title(ax, metric.title, 'Color', app.layout_cfg.colors.fg_text, 'FontSize', 16, 'FontWeight', 'bold', 'Interpreter', title_interp);
            xlabel(ax, metric.xlabel, 'Color', app.layout_cfg.colors.fg_text, 'FontSize', 12, 'Interpreter', x_interp);
            ylabel(ax, metric.ylabel, 'Color', app.layout_cfg.colors.fg_text, 'FontSize', 12, 'Interpreter', y_interp);
            ax.Color = app.layout_cfg.colors.bg_dark;
            ax.XColor = app.layout_cfg.colors.fg_text;
            ax.YColor = app.layout_cfg.colors.fg_text;
            ax.GridColor = app.layout_cfg.colors.accent_gray;
            ax.GridAlpha = 0.3;
            ax.FontSize = 11;
            % Note: FontColor not available for UIAxes - use XColor/YColor instead
            % Apply 2 decimal-place tick formatting to all monitor plots
            ytickformat(ax, '%.2f');
            xtickformat(ax, '%.2f');

            % Monitor tiles intentionally suppress legend labels (single trace per tile).
        end

        function interp = pick_metric_interpreter(app, txt)
            % Safe interpreter policy for monitor labels.
            % Use latex only for explicit math strings and avoid syntax warnings
            % for plain text labels containing characters like "%".
            token = char(string(txt));
            if isempty(token)
                interp = 'none';
                return;
            end
            if contains(token, '%')
                interp = 'none';
                return;
            end
            if app.is_math_like_text(token)
                interp = 'latex';
            else
                interp = 'none';
            end
        end

        function value = last_finite_from_series(app, monitor_series, field_name)
            value = NaN;
            if ~isstruct(monitor_series) || ~isfield(monitor_series, field_name)
                return;
            end
            vec = app.rowvec(monitor_series.(field_name));
            finite_idx = find(isfinite(vec), 1, 'last');
            if ~isempty(finite_idx)
                value = vec(finite_idx);
            end
        end

        function out = resolve_monitor_run_comparison(app, iter_rate_series)
            % Build simple run-comparison vectors for dashboard bars/table rows.
            out = struct( ...
                'labels', {cell(1, 0)}, ...
                'iter_rate', zeros(1, 0), ...
                'baseline_iter_rate', NaN, ...
                'delta_pct', NaN);

            prev_rates = zeros(1, 0);
            prev_labels = cell(1, 0);
            if ~isempty(app.session_figures)
                start_idx = max(1, numel(app.session_figures) - 4);
                for run_idx = start_idx:numel(app.session_figures)
                    entry = app.session_figures(run_idx);
                    if ~isfield(entry, 'monitor_series') || ~isstruct(entry.monitor_series)
                        continue;
                    end
                    rate_val = app.last_finite_from_series(entry.monitor_series, 'iter_rate');
                    if isfinite(rate_val)
                        prev_rates(end + 1) = rate_val; %#ok<AGROW>
                        prev_labels{end + 1} = sprintf('Run %d', run_idx); %#ok<AGROW>
                    end
                end
            end

            current_rate = NaN;
            if isnumeric(iter_rate_series)
                finite_curr = iter_rate_series(isfinite(iter_rate_series));
                if ~isempty(finite_curr)
                    current_rate = finite_curr(end);
                end
            end

            labels = prev_labels;
            values = prev_rates;
            if isfinite(current_rate)
                labels{end + 1} = 'Current'; %#ok<AGROW>
                values(end + 1) = current_rate; %#ok<AGROW>
            end

            out.labels = labels;
            out.iter_rate = values;
            if ~isempty(prev_rates)
                out.baseline_iter_rate = mean(prev_rates, 'omitnan');
                if isfinite(current_rate) && isfinite(out.baseline_iter_rate) && abs(out.baseline_iter_rate) > eps
                    out.delta_pct = 100 * (current_rate - out.baseline_iter_rate) / out.baseline_iter_rate;
                end
            end
        end

        function values = resolve_monitor_wall_clock_series(app, live, monitor_series)
            n = numel(app.rowvec(app.pick_field(monitor_series, {'elapsed_wall_time', 't'}, zeros(1, 0))));
            values = app.rowvec(app.pick_field(live, {'wall_clock_time'}, nan(1, n)));
            if numel(values) ~= n
                values = nan(1, n);
            end
            if any(values > 1e9)
                return;
            end
            values = app.rowvec(app.pick_field(monitor_series, {'elapsed_wall_time', 't'}, zeros(1, n)));
        end

        function summary_txt = monitor_telemetry_source_summary(app, monitor_series)
            source_specs = { ...
                struct('label', 'CPU', 'preferred_key', 'cpu', 'metric_key', 'cpu_proxy', 'source_order', {{'hwinfo', 'matlab', 'icue'}}), ...
                struct('label', 'GPU', 'preferred_key', 'gpu', 'metric_key', 'gpu_series', 'source_order', {{'hwinfo', 'matlab', 'icue'}}), ...
                struct('label', 'Mem', 'preferred_key', 'memory', 'metric_key', 'memory_series', 'source_order', {{'hwinfo', 'matlab'}}), ...
                struct('label', 'Power', 'preferred_key', 'power', 'metric_key', 'power_w', 'source_order', {{'hwinfo', 'icue', 'matlab'}})};
            labels = strings(1, numel(source_specs));
            for i = 1:numel(source_specs)
                labels(i) = string(app.describe_monitor_metric_source( ...
                    monitor_series, source_specs{i}.preferred_key, source_specs{i}.metric_key, source_specs{i}.source_order));
            end
            nonempty_labels = labels(strlength(strtrim(labels)) > 0 & labels ~= "--");
            if isempty(nonempty_labels)
                summary_txt = '--';
                return;
            end
            if all(labels == labels(1))
                summary_txt = sprintf('CPU/GPU/Mem/Power -> %s', char(labels(1)));
                return;
            end
            parts = strings(1, 0);
            for i = 1:numel(source_specs)
                if labels(i) == "--"
                    continue;
                end
                parts(end + 1) = string(sprintf('%s %s', source_specs{i}.label, labels(i))); %#ok<AGROW>
            end
            if isempty(parts)
                summary_txt = '--';
                return;
            end
            summary_txt = char(strjoin(parts, ' | '));
        end

        function label = describe_monitor_metric_source(app, monitor_series, preferred_key, metric_key, source_order)
            label = "--";
            source = app.infer_monitor_metric_source(monitor_series, preferred_key, metric_key, source_order);
            switch lower(app.to_text(source, ''))
                case 'hwinfo'
                    transport = app.pick_text_field(monitor_series, {'hwinfo_transport'}, 'none');
                    if strcmpi(transport, 'none') || isempty(strtrim(transport))
                        label = 'HWiNFO';
                    else
                        label = sprintf('HWiNFO [%s]', app.humanize_monitor_transport(transport));
                    end
                case 'matlab'
                    label = 'MATLAB';
                case 'icue'
                    label = 'iCUE';
            end
        end

        function label = collector_source_display_label(app, source)
            switch lower(app.to_text(source, ''))
                case 'hwinfo'
                    label = 'HWiNFO';
                case 'matlab'
                    label = 'MATLAB';
                case 'icue'
                    label = 'iCUE';
                otherwise
                    label = app.to_text(source, '--');
            end
        end

        function text = humanize_monitor_collector_status(app, value)
            token = lower(strtrim(app.to_text(value, '')));
            switch token
                case 'shared_memory_connected'
                    text = 'shared memory connected';
                case 'csv_fallback'
                    text = 'csv fallback';
                case 'csv_target_mismatch'
                    text = 'target mismatch';
                case 'shared_memory_disabled'
                    text = 'shared memory disabled';
                case 'shared_memory_expired'
                    text = 'shared memory expired';
                case 'connected'
                    text = 'connected';
                case 'disabled'
                    text = 'disabled';
                case 'off'
                    text = 'off';
                otherwise
                    if isempty(strtrim(token))
                        text = '--';
                    else
                        text = strrep(token, '_', ' ');
                    end
            end
        end

        function text = humanize_monitor_transport(app, value)
            token = lower(strtrim(app.to_text(value, '')));
            switch token
                case 'shared_memory'
                    text = 'shared memory';
                case 'csv'
                    text = 'csv';
                case 'auto'
                    text = 'auto';
                otherwise
                    if isempty(strtrim(token))
                        text = '--';
                    else
                        text = strrep(token, '_', ' ');
                    end
            end
        end

        function source = infer_monitor_metric_source(app, monitor_series, preferred_key, metric_key, source_order)
            source = '';
            preferred = app.pick_field(monitor_series, {'preferred_source'}, struct());
            if isstruct(preferred) && isfield(preferred, preferred_key)
                candidate = lower(app.to_text(preferred.(preferred_key), ''));
                if any(strcmp(candidate, source_order))
                    source = candidate;
                    return;
                end
            end
            for i = 1:numel(source_order)
                values = app.collector_metric_vector(monitor_series, source_order{i}, metric_key);
                if any(isfinite(values))
                    source = source_order{i};
                    return;
                end
            end
        end

        function values = preferred_monitor_series(app, monitor_series, metric_key, fallback_field, source_order)
            if nargin < 6 || isempty(source_order)
                source_order = {'hwinfo', 'matlab', 'icue'};
            end
            base = zeros(1, 0);
            base = app.rowvec(app.pick_field(monitor_series, {metric_key}, base));
            if nargin >= 4 && ~isempty(fallback_field)
                fallback_values = app.rowvec(app.pick_field(monitor_series, {fallback_field}, zeros(1, 0)));
                if isempty(base)
                    base = fallback_values;
                elseif ~isempty(fallback_values)
                    n = max(numel(base), numel(fallback_values));
                    base(end + 1:n) = nan;
                    fallback_values(end + 1:n) = nan;
                    replace_mask = ~isfinite(base) & isfinite(fallback_values);
                    base(replace_mask) = fallback_values(replace_mask);
                end
            end
            n = max([numel(base), numel(app.rowvec(app.pick_field(monitor_series, {'t'}, zeros(1, 0)))), 2]);
            if isempty(base)
                base = nan(1, n);
            elseif numel(base) < n
                base(end + 1:n) = nan;
            else
                base = base(1:n);
            end
            values = base;
            for i = 1:numel(source_order)
                candidate = app.collector_metric_vector(monitor_series, source_order{i}, metric_key);
                if isempty(candidate) || ~any(isfinite(candidate))
                    continue;
                end
                candidate = app.rowvec(candidate);
                if numel(candidate) < n
                    candidate(end + 1:n) = nan;
                else
                    candidate = candidate(1:n);
                end
                values = candidate;
                return;
            end
        end

        function n = infer_monitor_series_length(app, live)
            n = 0;
            if ~isstruct(live)
                n = 2;
                return;
            end
            live_fields = fieldnames(live);
            for i = 1:numel(live_fields)
                value = live.(live_fields{i});
                if isnumeric(value) && ~isempty(value) && ~isscalar(value)
                    n = max(n, numel(app.rowvec(value)));
                end
            end
            if isfield(live, 'collector_series') && isstruct(live.collector_series)
                sources = fieldnames(live.collector_series);
                for si = 1:numel(sources)
                    source_struct = live.collector_series.(sources{si});
                    if ~isstruct(source_struct)
                        continue;
                    end
                    metric_fields = fieldnames(source_struct);
                    for mi = 1:numel(metric_fields)
                        value = source_struct.(metric_fields{mi});
                        if isnumeric(value) && ~isempty(value) && ~isscalar(value)
                            n = max(n, numel(app.rowvec(value)));
                        end
                    end
                end
            end
            if n <= 0
                n = 2;
            end
        end

        function [values, is_proxy] = resolve_monitor_memory_power_series(app, monitor_series)
            values = app.preferred_monitor_series(monitor_series, 'memory_power_w_or_proxy', '', {'hwinfo'});
            direct_values = app.collector_metric_vector(monitor_series, 'hwinfo', 'memory_power_w_or_proxy');
            is_proxy = true;
            if any(isfinite(direct_values))
                catalog = app.pick_field(monitor_series, {'collector_metric_catalog'}, struct([]));
                if isstruct(catalog)
                    for i = 1:numel(catalog)
                        item = catalog(i);
                        if strcmpi(char(string(app.pick_field(item, {'source'}, ''))), 'hwinfo') && ...
                                strcmpi(char(string(app.pick_field(item, {'metric_key'}, ''))), 'memory_power_w_or_proxy')
                            unit_txt = lower(char(string(app.pick_field(item, {'unit'}, ''))));
                            is_proxy = ~contains(unit_txt, 'w');
                            return;
                        end
                    end
                end
                is_proxy = false;
            end
        end

        function [energy_wh, co2_g] = resolve_monitor_environmental_impact(app, monitor_series)
            time_s = app.rowvec(app.pick_field(monitor_series, {'elapsed_wall_time', 't'}, zeros(1, 0)));
            energy_wh = nan(size(time_s));
            co2_g = nan(size(time_s));
            if isempty(time_s)
                return;
            end
            existing_energy = app.rowvec(app.pick_field(monitor_series, {'environmental_energy_wh_cum'}, zeros(1, 0)));
            existing_co2 = app.rowvec(app.pick_field(monitor_series, {'environmental_co2_g_cum'}, zeros(1, 0)));
            if any(isfinite(existing_energy))
                existing_energy(end + 1:numel(time_s)) = nan;
                energy_wh = existing_energy(1:numel(time_s));
            end
            if any(isfinite(existing_co2))
                existing_co2(end + 1:numel(time_s)) = nan;
                co2_g = existing_co2(1:numel(time_s));
            end
            if any(isfinite(energy_wh)) && any(isfinite(co2_g))
                return;
            end
            env_model = ExternalCollectorDispatcher.resolve_environmental_model_public(monitor_series);
            source_power = reshape(double(ExternalCollectorDispatcher.resolve_environmental_power_vector_public(monitor_series, env_model)), 1, []);
            n = min(numel(time_s), numel(source_power));
            if n <= 0
                return;
            end
            time_s = time_s(1:n);
            source_power = source_power(1:n);
            energy_wh = zeros(1, n);
            for i = 2:n
                dt_h = max(time_s(i) - time_s(i - 1), 0) / 3600;
                p_prev = max(source_power(i - 1), 0);
                p_now = max(source_power(i), 0);
                if ~(isfinite(dt_h) && isfinite(p_prev) && isfinite(p_now))
                    energy_wh(i) = energy_wh(i - 1);
                    continue;
                end
                energy_wh(i) = energy_wh(i - 1) + 0.5 * (p_prev + p_now) * dt_h;
            end
            co2_g = ExternalCollectorDispatcher.environmental_factor_g_per_wh_public(env_model) * energy_wh;
        end

        function out = resolve_monitor_power_comparison(app, current_monitor_series)
            out = struct('labels', {cell(1, 0)}, 'cpu_power', zeros(1, 0), ...
                'gpu_power', zeros(1, 0), 'memory_power', zeros(1, 0), 'temperature_c', zeros(1, 0));
            labels = cell(1, 0);
            cpu_vals = zeros(1, 0);
            gpu_vals = zeros(1, 0);
            mem_vals = zeros(1, 0);
            temp_vals = zeros(1, 0);
            entries = app.collector_popup_session_entries();
            for i = 1:numel(entries)
                if ~isfield(entries(i), 'monitor_series') || ~isstruct(entries(i).monitor_series)
                    continue;
                end
                entry_series = entries(i).monitor_series;
                labels{end + 1} = sprintf('Run %d', i); %#ok<AGROW>
                cpu_vals(end + 1) = app.mean_finite_from_series(entry_series, 'cpu_power_w_hwinfo'); %#ok<AGROW>
                gpu_vals(end + 1) = app.mean_finite_from_series(entry_series, 'gpu_power_w_hwinfo'); %#ok<AGROW>
                mem_vals(end + 1) = app.mean_finite_from_series(entry_series, 'memory_power_w_or_proxy'); %#ok<AGROW>
                temp_vals(end + 1) = app.mean_finite_from_series(entry_series, 'cpu_temp_c'); %#ok<AGROW>
            end
            labels{end + 1} = 'Current'; %#ok<AGROW>
            cpu_vals(end + 1) = app.mean_finite_from_series(current_monitor_series, 'cpu_power_w_hwinfo'); %#ok<AGROW>
            gpu_vals(end + 1) = app.mean_finite_from_series(current_monitor_series, 'gpu_power_w_hwinfo'); %#ok<AGROW>
            mem_vals(end + 1) = app.mean_finite_from_series(current_monitor_series, 'memory_power_w_or_proxy'); %#ok<AGROW>
            temp_vals(end + 1) = app.mean_finite_from_series(current_monitor_series, 'cpu_temp_c'); %#ok<AGROW>
            out.labels = labels;
            out.cpu_power = cpu_vals;
            out.gpu_power = gpu_vals;
            out.memory_power = mem_vals;
            out.temperature_c = temp_vals;
        end

        function value = mean_finite_from_series(app, monitor_series, field_name)
            value = NaN;
            if ~isstruct(monitor_series) || ~isfield(monitor_series, field_name)
                return;
            end
            vec = app.rowvec(monitor_series.(field_name));
            vec = vec(isfinite(vec));
            if ~isempty(vec)
                value = mean(vec, 'omitnan');
            end
        end

        function tf = is_monitor_metric_applicable(app, metric, cfg)
            method_token = app.normalize_method_token(cfg.method);
            mode_token = app.normalize_mode_token(cfg.mode);
            tf = any(strcmpi(metric.methods, method_token)) && any(strcmpi(metric.modes, mode_token));
        end

        function render_monitor_metric_not_applicable(app, ax, metric, cfg)
            T = app.layout_cfg.ui_text.monitor_metric_na;
            cla(ax);
            xlim(ax, [0 1]);
            ylim(ax, [0 1]);
            ax.XTick = [];
            ax.YTick = [];
            ax.Box = 'on';
            grid(ax, 'off');

            msg_1 = T.msg_1;
            msg_2 = sprintf('%s / %s', app.humanize_token(cfg.method), app.humanize_token(cfg.mode));
            text(ax, 0.5, 0.58, msg_1, 'HorizontalAlignment', 'center', ...
                'Color', app.layout_cfg.colors.accent_yellow, 'FontSize', 11, 'FontWeight', 'bold');
            text(ax, 0.5, 0.42, msg_2, 'HorizontalAlignment', 'center', ...
                'Color', app.layout_cfg.colors.fg_muted, 'FontSize', 9);

            title_text = sprintf('%s%s', metric.title, T.title_suffix);
            title_interp = app.pick_metric_interpreter(title_text);
            title(ax, title_text, 'Color', app.layout_cfg.colors.fg_text, ...
                'FontSize', 10, 'Interpreter', title_interp);
            xlabel(ax, '', 'Interpreter', 'none');
            ylabel(ax, '', 'Interpreter', 'none');
        end

        function cfg = normalize_monitor_cfg(app, cfg)
            % Normalize monitor config aliases to avoid missing-field warnings.
            if nargin < 2 || isempty(cfg) || ~isstruct(cfg)
                cfg = struct();
            end

            if ~isfield(cfg, 'Tfinal')
                if isfield(cfg, 't_final')
                    cfg.Tfinal = cfg.t_final;
                elseif app.has_valid_handle('t_final')
                    cfg.Tfinal = app.handles.t_final.Value;
                else
                    cfg.Tfinal = 10;
                end
            end
            if ~isfield(cfg, 'dt')
                if app.has_valid_handle('dt')
                    cfg.dt = app.handles.dt.Value;
                else
                    cfg.dt = 0.01;
                end
            end
            if ~isfield(cfg, 'mode')
                if app.has_valid_handle('mode_dropdown')
                    cfg.mode = lower(char(string(app.handles.mode_dropdown.Value)));
                else
                    cfg.mode = 'evolution';
                end
            end
            if ~isfield(cfg, 'method')
                if app.has_valid_handle('method_dropdown')
                    cfg.method = char(string(app.handles.method_dropdown.Value));
                else
                    cfg.method = 'finite_difference';
                end
            end
            if ~isfield(cfg, 'Nx') && app.has_valid_handle('Nx')
                cfg.Nx = app.handles.Nx.Value;
            end
            if ~isfield(cfg, 'Ny') && app.has_valid_handle('Ny')
                cfg.Ny = app.handles.Ny.Value;
            end
            if ~isfield(cfg, 'Lx') && app.has_valid_handle('Lx')
                cfg.Lx = app.handles.Lx.Value;
            end
            if ~isfield(cfg, 'Ly') && app.has_valid_handle('Ly')
                cfg.Ly = app.handles.Ly.Value;
            end
            if ~isfield(cfg, 'convergence_N_max') && app.has_valid_handle('conv_N_max')
                cfg.convergence_N_max = app.handles.conv_N_max.Value;
            end
            if ~isfield(cfg, 'convergence_tol') && app.has_valid_handle('conv_tolerance')
                cfg.convergence_tol = app.handles.conv_tolerance.Value;
            end
        end

        function token = normalize_method_token(~, method_value)
            token = lower(char(string(method_value)));
            token = strtrim(token);
            token = strrep(token, '-', '_');
            token = strrep(token, ' ', '_');
            switch token
                case {'fd', 'finite_difference'}
                    token = 'finite_difference';
                case {'fv', 'finite_volume'}
                    token = 'finite_volume';
                case {'spectral', 'spectral_method'}
                    token = 'spectral';
            end
        end

        function token = normalize_convergence_criterion_token(~, criterion_value)
            token = lower(char(string(criterion_value)));
            token = strtrim(token);
            token = strrep(token, '-', '_');
            token = strrep(token, ' ', '_');
            switch token
                case {'', 'l2_relative', 'l2_absolute', 'linf_relative', 'max_vorticity', ...
                        'energy_dissipation', 'auto_physical', 'relative_change', ...
                        'successive_relative_change', 'successive_vorticity_error', ...
                        'successive_vorticity_relative_l2'}
                    token = 'successive_vorticity_relative_l2';
                otherwise
                    token = 'successive_vorticity_relative_l2';
            end
        end

        function token = normalize_mode_token(app, mode_value)
            token = lower(app.to_text(mode_value, ''));
            token = strtrim(token);
            token = strrep(token, '-', '_');
            token = strrep(token, ' ', '_');
            switch token
                case {'parametersweep', 'parameter_sweep'}
                    token = 'sweep';
                case 'experimentation'
                    token = 'sweep';
            end
        end

        function out = if_nan_num(~, value)
            if isnumeric(value) && isscalar(value) && isfinite(value)
                out = sprintf('%.4g', value);
            else
                out = '--';
            end
        end

        function out = if_nan_num_fixed(~, value, pattern)
            if nargin < 3 || isempty(pattern)
                pattern = '%.2f';
            end
            if isnumeric(value) && isscalar(value) && isfinite(value)
                out = sprintf(pattern, double(value));
            else
                out = '--';
            end
        end

        function out = if_nan_percent_fixed(~, value, pattern)
            if nargin < 3 || isempty(pattern)
                pattern = '%.3f%%';
            end
            if isnumeric(value) && isscalar(value) && isfinite(value)
                out = sprintf(pattern, double(value));
            else
                out = '--';
            end
        end

        function line = monitor_metric_line(~, category, label, value, unit)
            value_txt = char(string(value));
            unit_txt = strtrim(char(string(unit)));
            if isempty(unit_txt) || strcmp(unit_txt, '-') || strcmp(value_txt, '--') || strcmpi(value_txt, 'N/A')
                value_with_unit = value_txt;
            else
                value_with_unit = sprintf('%s %s', value_txt, unit_txt);
            end
            line = sprintf('[%s] %s: %s', char(string(category)), char(string(label)), value_with_unit);
        end

        function out = if_empty(app, txt, fallback)
            if nargin < 3
                fallback = '--';
            end
            t = app.to_text(txt, '');
            if isempty(strtrim(t))
                out = app.to_text(fallback, '--');
            else
                out = t;
            end
        end

        function out = humanize_token(app, value)
            token = app.to_text(value, '');
            token = strrep(token, '_', ' ');
            token = strtrim(lower(token));
            parts = strsplit(token, ' ');
            for i = 1:numel(parts)
                if isempty(parts{i})
                    continue;
                end
                parts{i}(1) = upper(parts{i}(1));
            end
            out = strjoin(parts, ' ');
        end
        
        function validate_all_layouts(app)
            % Validate all layouts in UI (check for errors)
            app.append_dev_log('Running layout validation...');
            
            issues = {};
            
            % Check for leftover Position usage
            issues = app.check_position_usage_recursive(app.fig, issues);
            
            % Check for invalid row/col indices
            % (TODO: implement full validation)
            
            if isempty(issues)
                app.append_dev_log('Validation passed: No issues found');
                app.append_to_terminal('Layout validation PASSED', 'success');
            else
                for i = 1:length(issues)
                    app.append_dev_log(sprintf('Issue: %s', issues{i}));
                end
                app.append_to_terminal(sprintf('Layout validation found %d issue(s)', length(issues)), 'warning');
            end
        end
        
        function issues = check_position_usage_recursive(app, obj, issues)
            % Recursively check for Position property usage
            if ~ishghandle(obj)
                return;
            end
            
            try
                if isprop(obj, 'Units') && strcmp(obj.Units, 'normalized') && isprop(obj, 'Position')
                    % Check if Position is being used (non-default)
                    % Skip tab group (allowed for now)
                    if ~isa(obj, 'matlab.ui.container.TabGroup')
                        issues{end+1} = sprintf('%s uses Position (should use grid layout)', class(obj));
                    end
                end
            catch ME
                UIController.warn_once('UIController:LayoutValidationProbeFailed', ...
                    'Layout validation skipped a component due to metadata read failure: %s', ME.message);
            end
            
            % Recurse
            try
                children = obj.Children;
                for i = 1:length(children)
                    issues = app.check_position_usage_recursive(children(i), issues);
                end
            catch ME
                UIController.warn_once('UIController:LayoutValidationRecurseFailed', ...
                    'Layout validation recursion skipped inaccessible children: %s', ME.message);
            end
        end
        
        function dump_ui_map(app)
            % Dump UI component map to console and inspector log
            app.append_dev_log('Dumping UI map to console...');
            fprintf('\n===== UI COMPONENT MAP =====\n');
            app.dump_component_tree_recursive(app.fig, 0);
            fprintf('===== END UI MAP =====\n\n');
            app.append_dev_log('ÃƒÂ¢Ã…â€œÃ¢â‚¬Å“ UI map dumped to console');
        end
        
        function dump_component_tree_recursive(~, obj, depth)
            % Recursively dump component tree
            if ~ishghandle(obj)
                return;
            end
            
            indent = repmat('  ', 1, depth);
            comp_type = class(obj);
            
            % Get layout info if available
            layout_info = '';
            try
                if isprop(obj, 'Layout') && isprop(obj.Layout, 'Row')
                    layout_info = sprintf(' [Row=%s, Col=%s]', ...
                        mat2str(obj.Layout.Row), mat2str(obj.Layout.Column));
                end
            catch ME
                UIController.warn_once('UIController:DumpTreeLayoutReadFailed', ...
                    'UI map dump skipped layout metadata for a component: %s', ME.message);
            end
            
            % Get tag if available
            tag_info = '';
            try
                if isprop(obj, 'Tag') && ~isempty(obj.Tag)
                    tag_info = sprintf(' (Tag: %s)', obj.Tag);
                end
            catch ME
                UIController.warn_once('UIController:DumpTreeTagReadFailed', ...
                    'UI map dump skipped Tag metadata for a component: %s', ME.message);
            end
            
            fprintf('%s- %s%s%s\n', indent, comp_type, layout_info, tag_info);
            
            % Recurse
            try
                children = obj.Children;
                for i = 1:length(children)
                    dump_component_tree_recursive([], children(i), depth + 1);
                end
            catch ME
                UIController.warn_once('UIController:DumpTreeRecurseFailed', ...
                    'UI map dump recursion skipped inaccessible children: %s', ME.message);
            end
        end
        
