            app.append_to_terminal('Layout reset not yet implemented', 'warning');
            % TODO: Full implementation would recreate UI from LayoutCfg
        end

    end

    methods (Access = private)
        % ===== UI LAYOUT CONFIGURATION =====
        % Embedded from UI_Layout_Config.m - centralized layout configuration
        function cfg = UI_Layout_Config_Internal(app)
            % UI_LAYOUT_CONFIG - Centralized layout configuration for UIController
            %
            % Purpose:
            %   Single source of truth for all UI layout parameters
            %   Editing layout = edit this method only
            %
            % Returns:
            %   cfg - struct with layout configuration
            %
            % Usage:
            %   cfg = app.UI_Layout_Config();
            %   main_grid = uigridlayout(parent, cfg.main_grid.rows_cols);
            %   main_grid.ColumnWidth = cfg.main_grid.col_widths;
            %
            % Constraints:
            %   - All sizes must be valid MATLAB layout specs
            %   - Row/column indices must match component placement map

            % ===== ROOT FIGURE GRID =====
            % Top-level grid: tab content only (menu/title row removed).
            cfg.root_grid.rows_cols    = [1, 1];
            cfg.root_grid.row_heights  = {'1x'};
            cfg.root_grid.col_widths   = {'1x'};              % Single full-width column
            cfg.root_grid.padding      = [5 5 5 5];           % [top, bottom, left, right] in pixels
            cfg.root_grid.row_spacing  = 0;                   % Vertical spacing between rows
            cfg.root_grid.col_spacing  = 5;                   % Horizontal spacing (single column, minimal)

            % ===== TAB GROUP GRID =====
            % Tab group fills the root grid.
            cfg.tab_group.parent_row   = 1;                   % Row containing tabs
            cfg.tab_group.parent_col   = 1;                   % Column containing tabs
            cfg.tab_group.order        = {'config', 'monitoring', 'results', 'report'};  % Tab creation order

            % ===== STANDARD COMPONENT SIZES =====
            % Defines preferred heights for all UI element types (in pixels)
            cfg.sizes.button_height        = 32;              % Standard button height
            cfg.sizes.dropdown_height      = 28;              % Dropdown/combobox height
            cfg.sizes.edit_height          = 28;              % Single-line edit field
            cfg.sizes.label_height         = 20;              % Text label height
            cfg.sizes.checkbox_height      = 24;              % Checkbox control height
            cfg.sizes.textarea_height      = 78;              % Multi-line text area height
            cfg.sizes.panel_title_padding  = 10;              % Padding around panel titles
            cfg.sizes.form_row_height      = 28;              % Standard form row height
            cfg.sizes.form_row_tall        = 36;              % Tall form row (e.g., multi-line content)
            cfg.sizes.design_width         = 1366;            % Baseline compact-first resolution width
            cfg.sizes.design_height        = 768;             % Baseline compact-first resolution height
            cfg.sizes.min_scale            = 0.78;            % Lower clamp for responsive downscaling
            cfg.sizes.max_scale            = 1.12;            % Upper clamp for responsive upscaling

            % ===== STANDARD HEIGHT ALIASES =====
            % Mirror sizes struct for easier reference in layout configs (cfg.heights.*)
            cfg.heights.button          = cfg.sizes.button_height;
            cfg.heights.dropdown        = cfg.sizes.dropdown_height;
            cfg.heights.edit            = cfg.sizes.edit_height;
            cfg.heights.label           = cfg.sizes.label_height;
            cfg.heights.checkbox        = cfg.sizes.checkbox_height;
            cfg.heights.textarea        = cfg.sizes.textarea_height;
            cfg.heights.form_row        = cfg.sizes.form_row_height;
            cfg.heights.form_row_tall   = cfg.sizes.form_row_tall;

            % ===== CONFIG TAB =====
            % Configuration tab: balanced 2-column layout for settings + IC editing.
            cfg.config_tab.root.rows_cols      = [1, 2];      % Single row, 2 columns
            cfg.config_tab.root.col_widths     = {'1x', '1x'};  % Equal-width left/right columns
            cfg.config_tab.root.row_heights    = {'1x'};      % Single flexible row
            cfg.config_tab.root.padding        = [6 6 6 6];   % Inner padding all sides
            cfg.config_tab.root.row_spacing    = 10;          % Row spacing (not used: 1 row)
            cfg.config_tab.root.col_spacing    = 8;           % Column spacing between left/right

            % Left column: tabbed sections to reduce crowding.
            cfg.config_tab.left.rows_cols      = [1, 1];
            cfg.config_tab.left.row_heights    = {'1x'};
            cfg.config_tab.left.padding        = [6 6 6 6];
            cfg.config_tab.left.row_spacing    = 4;
            cfg.config_tab.left_subtabs = struct( ...
                'root', struct( ...
                    'rows_cols', [1, 1], ...
                    'row_heights', {'1x'}, ...
                    'col_widths', {'1x'}, ...
                    'padding', [0 0 0 0], ...
                    'row_spacing', 0, ...
                    'col_spacing', 0), ...
                'order', {{'phase', 'method', 'grid', 'data', 'convergence'}}, ...
                'titles', struct( ...
                    'method', 'Method and Mode', ...
                    'grid', 'Boundary Conditions and Domain Settings', ...
                    'data', 'Data Collection', ...
                    'convergence', 'Mesh Settings', ...
                    'phase', 'Phase Settings'));

            % Right column: 3 stacked panels (buttons, IC config, IC preview) - buttons snug at top
            cfg.config_tab.right.rows_cols     = [3, 1];      % 3 rows, 1 column
