            cfg.colors.accent_gray    = [0.60 0.60 0.60];  % Disabled/inactive state
        end

        function tab_layout = build_tab_layout_groups(app, cfg)
            % build_tab_layout_groups - Group layout controls per tab for easier editing.
            %
            % Field order inside each tab group:
            %   tab_name -> grid -> sections -> sub_tabs -> plots
            %
            % This is an editor-facing organization layer and keeps legacy fields intact
            % (`cfg.config_tab`, `cfg.monitor_tab`, `cfg.results_tab`) for compatibility.

            tab_layout = struct();

            tab_layout.config = struct( ...
                'tab_name', cfg.text.tabs.config, ...
                'grid', cfg.config_tab.root, ...
                'sections', struct( ...
                    'left_column', cfg.config_tab.left, ...
                    'left_subtabs', cfg.config_tab.left_subtabs, ...
                    'right_column', cfg.config_tab.right, ...
                    'method', cfg.config_tab.method_grid, ...
                    'grid', cfg.config_tab.grid_grid, ...
                    'time', cfg.config_tab.sim_grid, ...
                    'time_video', cfg.config_tab.time_video, ...
                    'simulation', cfg.config_tab.sim_grid, ...
                    'convergence', cfg.config_tab.conv_grid, ...
                    'sustainability', cfg.config_tab.sus_grid, ...
                    'initial_condition', cfg.config_tab.ic_grid), ...
                'sub_tabs', cfg.config_tab.left_subtabs.titles, ...
                'plots', struct(), ...
                'coords', cfg.coords.config);

            tab_layout.monitoring = struct( ...
                'tab_name', cfg.text.tabs.monitoring, ...
                'grid', cfg.monitor_tab.root, ...
                'sections', struct( ...
                    'dashboard_grid', cfg.monitor_tab.left, ...
                    'sidebar', cfg.monitor_tab.sidebar), ...
                'sub_tabs', struct(), ...
                'plots', struct( ...
                    'plot_grid_rows', cfg.monitor_tab.plot_grid_rows, ...
                    'plot_grid_cols', cfg.monitor_tab.plot_grid_cols, ...
                    'plot_tile_count', cfg.monitor_tab.plot_tile_count, ...
                    'numeric_tile_index', cfg.monitor_tab.numeric_tile_index, ...
                    'live_update', cfg.monitor_tab.live_update), ...
                'coords', cfg.coords.monitor);

            results_figure_area = struct();
            if isfield(cfg.results_tab, 'main')
                results_figure_area = cfg.results_tab.main;
            elseif isfield(cfg.results_tab, 'fig_grid')
                results_figure_area = cfg.results_tab.fig_grid;
            end

            tab_layout.results = struct( ...
                'tab_name', cfg.text.tabs.results, ...
                'grid', cfg.results_tab.root, ...
                'sections', struct( ...
                    'figure_area', results_figure_area, ...
                    'control_row', cfg.results_tab.controls), ...
                'sub_tabs', struct('default_preview', 'Preview'), ...
                'plots', struct(), ...
                'coords', cfg.coords.results);
        end

        function manifest = build_layout_manifest(app, cfg)
            % build_layout_manifest - Flat major-component map for sandbox rendering.
            % Creates a comprehensive index of all UI regions for debugging/visualization
            manifest = struct( ...
                'id', {}, ...
                'region', {}, ...
                'coords', {}, ...
                'title', {}, ...
                'description', {});

            % Configuration tab entries
            manifest(end + 1) = app.make_entry('config_left', 'Configuration', cfg.coords.config.left, ...
                'Configuration Left Column', 'Method/grid/time/simulation/convergence/phase settings stacks');
            manifest(end + 1) = app.make_entry('config_right', 'Configuration', cfg.coords.config.right, ...
                'Configuration Right Column', 'Action buttons, initial condition, and preview stacks');
            manifest(end + 1) = app.make_entry('config_method', 'Configuration', cfg.coords.config.panel_method, ...
                cfg.text.config_panels.method, 'Method and run-mode selector panel');
            manifest(end + 1) = app.make_entry('config_grid', 'Configuration', cfg.coords.config.panel_grid, ...
                cfg.text.config_panels.grid, 'Grid size and spatial-domain panel');
            manifest(end + 1) = app.make_entry('config_time', 'Configuration', cfg.coords.config.panel_time, ...
                cfg.text.config_panels.time, 'Time-step and viscosity panel');
            manifest(end + 1) = app.make_entry('config_sim', 'Configuration', cfg.coords.config.panel_sim, ...
                cfg.text.config_panels.simulation, 'Output/save/animation panel');
            manifest(end + 1) = app.make_entry('config_conv', 'Configuration', cfg.coords.config.panel_conv, ...
                cfg.text.config_panels.convergence, 'Convergence controls panel');
            manifest(end + 1) = app.make_entry('config_sus', 'Configuration', cfg.coords.config.panel_sus, ...
                cfg.text.config_panels.sustainability, 'Sustainability collectors and monitoring panel');
            manifest(end + 1) = app.make_entry('config_phase', 'Configuration', cfg.coords.config.panel_phase, ...
                cfg.text.config_panels.phase, 'Phase workflow presets and per-phase settings panel');
            manifest(end + 1) = app.make_entry('config_buttons', 'Configuration', cfg.coords.config.panel_buttons, ...
                'Action Buttons', 'Launch control row');
            % Right column entries (buttons, IC setup, IC preview)
            manifest(end + 1) = app.make_entry('config_ic', 'Configuration', cfg.coords.config.panel_ic, ...
                cfg.text.config_panels.ic, 'Initial condition parameter panel');
            manifest(end + 1) = app.make_entry('config_preview', 'Configuration', cfg.coords.config.panel_preview, ...
                cfg.text.config_panels.preview, 'Initial condition visualization panel');

            % Live Monitor tab entries
            manifest(end + 1) = app.make_entry('monitor_left', 'Live Monitor', cfg.coords.monitor.left_panel, ...
                cfg.text.monitor_panels.dashboard, '8 plot tiles plus 1 numeric metrics tile');
            manifest(end + 1) = app.make_entry('monitor_sidebar', 'Live Monitor', cfg.coords.monitor.terminal_panel, ...
                cfg.text.monitor_panels.sidebar, 'Terminal log, run status, collector probes');

            % Results tab entries
            manifest(end + 1) = app.make_entry('results_figures', 'Results and Figures', cfg.coords.results.panel_fig, ...
                cfg.text.results_panels.figures, 'Generated figure browser and display');
            manifest(end + 1) = app.make_entry('results_metrics', 'Results and Figures', cfg.coords.results.panel_metrics, ...
                cfg.text.results_panels.metrics, 'Metrics summary readout');
        end

        function entry = make_entry(~, id, region, coords, title_txt, description_txt)
            % Helper function to create manifest entry struct
            entry = struct( ...
                'id', id, ...
                'region', region, ...
                'coords', coords, ...
                'title', title_txt, ...
                'description', description_txt);
        end

        function defaults = resolve_ui_defaults_from_factory(app, cfg)
            % Build UI seed defaults from create_default_parameters() so
            % defaults are defined in one place only.
            try
                base = create_default_parameters();
            catch ME
                if ~UIController.is_missing_symbol_error(ME)
                    rethrow(ME);
                end
                UIController.attach_project_paths_from_ui();
                base = create_default_parameters();
            end

            defaults = struct();
            defaults.method = char(string(app.pick_field_required(base, {'analysis_method'}, 'Finite Difference')));
            defaults.mode = app.normalize_mode_display(char(string(app.pick_field_required(base, {'default_mode', 'run_mode_internal', 'mode'}, 'Evolution'))));
            defaults.simulation_scenario = char(string(app.pick_field_required(base, {'simulation_scenario'}, 'Manual')));
            defaults.simulation_scenario_catalog = app.pick_field_required(base, {'simulation_scenario_catalog'}, struct([]));
            defaults.bathymetry_scenario = char(string(app.pick_field_required(base, {'bathymetry_scenario'}, 'flat_2d')));
            defaults.bathymetry_bed_slope = double(app.pick_field_required(base, {'bathymetry_bed_slope'}, 0.03));
            defaults.bathymetry_depth_offset = double(app.pick_field_required(base, {'bathymetry_depth_offset'}, 1000.0));
            defaults.bathymetry_relief_amplitude = double(app.pick_field_required(base, {'bathymetry_relief_amplitude'}, 180.0));
            defaults.bathymetry_resolution = round(double(app.pick_field_required(base, {'bathymetry_resolution'}, 96)));
            defaults.bathymetry_custom_points = app.pick_field_required(base, {'bathymetry_custom_points'}, struct([]));
            defaults.bathymetry_dynamic_params = app.pick_field_required(base, {'bathymetry_dynamic_params'}, struct());
