        function ui_options = resolve_ic_ui_options_from_defaults(app, ui_options, defaults)
            if nargin < 3 || ~isstruct(defaults)
                return;
            end
            if isfield(defaults, 'ic_ui_catalog') && ~isempty(defaults.ic_ui_catalog)
                ui_options.ic_type_items = cell(1, numel(defaults.ic_ui_catalog));
                for i = 1:numel(defaults.ic_ui_catalog)
                    ui_options.ic_type_items{i} = defaults.ic_ui_catalog(i).display_name;
                end
            end
            if isfield(defaults, 'ic_scenario_catalog') && ~isempty(defaults.ic_scenario_catalog)
                ui_options.ic_scenario_items = cell(1, numel(defaults.ic_scenario_catalog));
                for i = 1:numel(defaults.ic_scenario_catalog)
                    ui_options.ic_scenario_items{i} = defaults.ic_scenario_catalog(i).scenario_name;
                end
            end
            if isfield(defaults, 'ic_arrangement_catalog') && ~isempty(defaults.ic_arrangement_catalog)
                ui_options.ic_arrangement_items = cell(1, numel(defaults.ic_arrangement_catalog));
                for i = 1:numel(defaults.ic_arrangement_catalog)
                    ui_options.ic_arrangement_items{i} = defaults.ic_arrangement_catalog(i).id;
                end
                ui_options.ic_pattern_items = ui_options.ic_arrangement_items;
            end
            if isfield(defaults, 'simulation_scenario_catalog') && ~isempty(defaults.simulation_scenario_catalog)
                ui_options.simulation_scenario_items = cell(1, numel(defaults.simulation_scenario_catalog));
                for i = 1:numel(defaults.simulation_scenario_catalog)
                    ui_options.simulation_scenario_items{i} = defaults.simulation_scenario_catalog(i).scenario_name;
                end
            else
                ui_options.simulation_scenario_items = {'Manual'};
            end
            if isfield(defaults, 'bathymetry_scenario_catalog_2d') && ~isempty(defaults.bathymetry_scenario_catalog_2d)
                ui_options.bathymetry_scenario_items_2d = cell(1, numel(defaults.bathymetry_scenario_catalog_2d));
                for i = 1:numel(defaults.bathymetry_scenario_catalog_2d)
                    ui_options.bathymetry_scenario_items_2d{i} = defaults.bathymetry_scenario_catalog_2d(i).id;
                end
            else
                ui_options.bathymetry_scenario_items_2d = {'flat_2d'};
            end
            if isfield(defaults, 'bathymetry_scenario_catalog_3d') && ~isempty(defaults.bathymetry_scenario_catalog_3d)
                ui_options.bathymetry_scenario_items_3d = cell(1, numel(defaults.bathymetry_scenario_catalog_3d));
                for i = 1:numel(defaults.bathymetry_scenario_catalog_3d)
                    ui_options.bathymetry_scenario_items_3d{i} = defaults.bathymetry_scenario_catalog_3d(i).id;
                end
            else
                ui_options.bathymetry_scenario_items_3d = {'flat_3d'};
            end
        end

        function display_name = map_ic_type_to_display(~, ic_type)
            token = lower(strtrim(char(string(ic_type))));
            switch token
                case 'no_initial_condition'
                    display_name = 'No Initial Condition';
                case 'stretched_gaussian'
                    display_name = 'Stretched Gaussian';
                case {'vortex_blob', 'vortex_blob_gaussian'}
                    display_name = 'Vortex Blob';
                case 'vortex_pair'
                    display_name = 'Vortex Pair';
                case 'multi_vortex'
                    display_name = 'Multi-Vortex';
                case 'lamb_oseen'
                    display_name = 'Lamb-Oseen';
                case 'rankine'
                    display_name = 'Rankine';
                case 'lamb_dipole'
                    display_name = 'Lamb Dipole';
                case 'taylor_green'
                    display_name = 'Taylor-Green';
                case 'random_turbulence'
                    display_name = 'Random Turbulence';
                case 'elliptical_vortex'
                    display_name = 'Elliptical Vortex';
                otherwise
                    display_name = 'Stretched Gaussian';
            end
        end

        function mode_name = normalize_mode_display(~, token)
            mode_name = 'Evolution';
            key = lower(strtrim(char(string(token))));
            switch key
                case {'evolution', 'solve'}
                    mode_name = 'Evolution';
                case 'convergence'
                    mode_name = 'Convergence';
                case {'parameter sweep', 'parametersweep', 'sweep'}
                    mode_name = 'Parameter Sweep';
                case 'animation'
                    mode_name = 'Animation';
            end
        end

        function value = coeff_or(~, coeffs, idx, fallback)
            value = fallback;
            if numel(coeffs) >= idx && isfinite(coeffs(idx))
                value = coeffs(idx);
            end
        end

        function ic_type = map_ic_display_to_type(~, display_name)
            % Map UI display names to internal ic_type values
            % This ensures the display names are human-friendly while
            % the actual ic_type values match the initialise_omega switch cases
            display_name = char(string(display_name));

            switch display_name
                case {'No Initial Condition', 'no_initial_condition'}
                    ic_type = 'no_initial_condition';
                case {'Stretched Gaussian', 'stretched_gaussian'}
                    ic_type = 'stretched_gaussian';
                case {'Vortex Blob', 'Vortex Blob Gaussian', 'vortex_blob', 'vortex_blob_gaussian'}
                    ic_type = 'vortex_blob_gaussian';
                case {'Vortex Pair', 'vortex_pair'}
                    ic_type = 'vortex_pair';
                case {'Multi-Vortex', 'multi_vortex'}
                    ic_type = 'multi_vortex';
                case {'Lamb-Oseen', 'lamb_oseen'}
                    ic_type = 'lamb_oseen';
                case {'Rankine', 'rankine'}
                    ic_type = 'rankine';
                case {'Lamb Dipole', 'lamb_dipole'}
                    ic_type = 'lamb_dipole';
                case {'Taylor-Green', 'taylor_green'}
                    ic_type = 'taylor_green';
                case {'Random Turbulence', 'random_turbulence'}
                    ic_type = 'random_turbulence';
                case {'Elliptical Vortex', 'elliptical_vortex'}
                    ic_type = 'elliptical_vortex';
                otherwise
                    % Fallback: try to use display_name directly if it's a valid ic_type
                    ic_type = lower(display_name);
            end
        end
    end

    methods (Static, Access = private)

        function tf = is_missing_symbol_error(ME)
            % True when failure likely comes from missing path entries.
            tf = strcmp(ME.identifier, 'MATLAB:UndefinedFunction') || ...
                 strcmp(ME.identifier, 'MATLAB:UndefinedFunctionOrVariable') || ...
                 contains(ME.message, 'Undefined function') || ...
                 contains(ME.message, 'Unrecognized function or variable');
        end

        function attach_project_paths_from_ui()
            % Bootstrap Scripts/ and invoke PathSetup from UIController's location.
            if exist('PathSetup', 'class') ~= 8
                ui_dir      = fileparts(mfilename('fullpath'));  % Scripts/UI
                scripts_dir = fileparts(ui_dir);                % Scripts
                addpath(genpath(scripts_dir));
                utilities_dir = fullfile(fileparts(scripts_dir), 'utilities');
                if exist(utilities_dir, 'dir') == 7
                    addpath(utilities_dir);
                end
            end
            PathSetup.attach_and_verify();
        end

        function warn_once(identifier, message, varargin)
            % Emit a warning only once per identifier to avoid UI log spam.
            persistent emitted_ids;
            if isempty(emitted_ids)
                emitted_ids = containers.Map('KeyType', 'char', 'ValueType', 'logical');
            end

            id = char(string(identifier));
            if isKey(emitted_ids, id)
                return;
            end
            emitted_ids(id) = true;

            SafeConsoleIO.warning(id, message, varargin{:});
        end

        function safe_close_figure(fig_handle)
            if isempty(fig_handle)
                return;
            end
            try
                if isgraphics(fig_handle, 'figure')
                    close(fig_handle);
                end
            catch
            end
        end

        function safe_delete_file(path_str)
            if ~(ischar(path_str) || isstring(path_str))
                return;
            end
            file_path = char(string(path_str));
            if isempty(file_path) || exist(file_path, 'file') ~= 2
                return;
            end
            try
                delete(file_path);
            catch
            end
        end

        function layout_kind = resolve_result_layout_kind_static(summary, results, run_cfg)
            layout_kind = '';

            if isstruct(run_cfg) && isfield(run_cfg, 'result_layout_kind') && ~isempty(run_cfg.result_layout_kind)
                layout_kind = char(string(run_cfg.result_layout_kind));
                return;
            end
            if isstruct(results) && isfield(results, 'result_layout_kind') && ~isempty(results.result_layout_kind)
                layout_kind = char(string(results.result_layout_kind));
                return;
            end
            if isstruct(summary) && isfield(summary, 'result_layout_kind') && ~isempty(summary.result_layout_kind)
                layout_kind = char(string(summary.result_layout_kind));
                return;
            end
            if isstruct(results) && isfield(results, 'workflow_manifest') && isstruct(results.workflow_manifest) && ...
                    isfield(results.workflow_manifest, 'result_layout_kind') && ~isempty(results.workflow_manifest.result_layout_kind)
                layout_kind = char(string(results.workflow_manifest.result_layout_kind));
                return;
            end
            if isstruct(summary) && isfield(summary, 'workflow_manifest') && isstruct(summary.workflow_manifest) && ...
                    isfield(summary.workflow_manifest, 'result_layout_kind') && ~isempty(summary.workflow_manifest.result_layout_kind)
                layout_kind = char(string(summary.workflow_manifest.result_layout_kind));
                return;
            end

            launch_origin = '';
            phase_label = '';
            if isstruct(run_cfg)
                if isfield(run_cfg, 'launch_origin') && ~isempty(run_cfg.launch_origin)
                    launch_origin = char(string(run_cfg.launch_origin));
                end
                if isfield(run_cfg, 'phase_label') && ~isempty(run_cfg.phase_label)
                    phase_label = char(string(run_cfg.phase_label));
                end
            end
            if isempty(launch_origin) && isstruct(results) && isfield(results, 'launch_origin') && ~isempty(results.launch_origin)
                launch_origin = char(string(results.launch_origin));
            end
            if isempty(launch_origin) && isstruct(summary) && isfield(summary, 'launch_origin') && ~isempty(summary.launch_origin)
                launch_origin = char(string(summary.launch_origin));
            end
            if isempty(phase_label) && isstruct(results) && isfield(results, 'phase_label') && ~isempty(results.phase_label)
                phase_label = char(string(results.phase_label));
            end
            if isempty(phase_label) && isstruct(summary) && isfield(summary, 'phase_label') && ~isempty(summary.phase_label)
                phase_label = char(string(summary.phase_label));
            end

            if strcmpi(launch_origin, 'phase_button') && strcmpi(strtrim(phase_label), 'Mesh Convergence')
                layout_kind = 'mesh_convergence_workflow';
                return;
            end
            if strcmpi(launch_origin, 'phase_button') && strcmpi(strtrim(phase_label), 'Phase 1')
                layout_kind = 'phase1_workflow';
                return;
            end
            if strcmpi(launch_origin, 'phase_button') && strcmpi(strtrim(phase_label), 'Phase 2')
                layout_kind = 'phase2_workflow';
                return;
            end
            if strcmpi(launch_origin, 'phase_button') && strcmpi(strtrim(phase_label), 'Phase 3')
                layout_kind = 'phase3_workflow';
                return;
            end

            if isstruct(results) && isfield(results, 'workflow_kind') && ...
                    strcmpi(char(string(results.workflow_kind)), 'mesh_convergence_study')
                layout_kind = 'mesh_convergence_workflow';
                return;
            end
            if isstruct(results) && isfield(results, 'workflow_kind') && ...
                    strcmpi(char(string(results.workflow_kind)), 'phase1_periodic_comparison')
                layout_kind = 'phase1_workflow';
                return;
            end
            if isstruct(results) && isfield(results, 'workflow_kind') && ...
                    strcmpi(char(string(results.workflow_kind)), 'phase2_boundary_condition_study')
                layout_kind = 'phase2_workflow';
                return;
            end
            if isstruct(results) && isfield(results, 'workflow_kind') && ...
                    strcmpi(char(string(results.workflow_kind)), 'phase3_bathymetry_study')
                layout_kind = 'phase3_workflow';
                return;
            end
            if isstruct(run_cfg) && isfield(run_cfg, 'workflow_kind') && ...
                    strcmpi(char(string(run_cfg.workflow_kind)), 'mesh_convergence_study')
                layout_kind = 'mesh_convergence_workflow';
                return;
            end
            if isstruct(run_cfg) && isfield(run_cfg, 'workflow_kind') && ...
                    strcmpi(char(string(run_cfg.workflow_kind)), 'phase1_periodic_comparison')
                layout_kind = 'phase1_workflow';
                return;
            end
            if isstruct(run_cfg) && isfield(run_cfg, 'workflow_kind') && ...
                    strcmpi(char(string(run_cfg.workflow_kind)), 'phase2_boundary_condition_study')
                layout_kind = 'phase2_workflow';
                return;
            end
            if isstruct(run_cfg) && isfield(run_cfg, 'workflow_kind') && ...
                    strcmpi(char(string(run_cfg.workflow_kind)), 'phase3_bathymetry_study')
                layout_kind = 'phase3_workflow';
                return;
            end
            if isstruct(summary) && isfield(summary, 'workflow_kind') && ...
                    strcmpi(char(string(summary.workflow_kind)), 'mesh_convergence_study')
                layout_kind = 'mesh_convergence_workflow';
                return;
            end
            if isstruct(summary) && isfield(summary, 'workflow_kind') && ...
                    strcmpi(char(string(summary.workflow_kind)), 'phase1_periodic_comparison')
                layout_kind = 'phase1_workflow';
                return;
            end
            if isstruct(summary) && isfield(summary, 'workflow_kind') && ...
                    strcmpi(char(string(summary.workflow_kind)), 'phase2_boundary_condition_study')
                layout_kind = 'phase2_workflow';
                return;
            end
            if isstruct(summary) && isfield(summary, 'workflow_kind') && ...
                    strcmpi(char(string(summary.workflow_kind)), 'phase3_bathymetry_study')
                layout_kind = 'phase3_workflow';
            end
        end

    end
end

function local_close_phase1_export_figure(fig)
    if isempty(fig)
        return;
    end
    try
        if isgraphics(fig, 'figure')
            close(fig);
        end
    catch
    end
end

function ui_controller_timer_poll_active_executor_completion(~, ~, app)
    if isempty(app)
        return;
    end
    try
        if isvalid(app)
            app.poll_active_executor_completion();
        end
    catch ME
        UIController.warn_once('UIController:ExecutorCompletionTimerFailed', ...
            'Executor completion timer callback failed: %s', ME.message);
    end
end

